CREATE FUNCTION [dbo].[AccLedger_OtherAccounts_F] (@AccNo AS VARCHAR(255),@VchrNo AS VARCHAR(255))
RETURNS VARCHAR(1000) AS

BEGIN
DECLARE @ReturnStr AS VARCHAR(1000)
SET @ReturnStr=''
DECLARE @Temp AS VARCHAR(255)
DECLARE Abc CURSOR FOR SELECT AccTitle FROM Vouchers INNER JOIN Accounts ON Vouchers.AccNo=Accounts.AccNo WHERE VchrNo=@VchrNo AND Accounts.AccNo<>@AccNo
OPEN Abc

FETCH NEXT FROM Abc into @Temp
WHILE @@Fetch_Status=0
	BEGIN
		SET @ReturnStr=@ReturnStr + @Temp + ','
		FETCH NEXT FROM Abc Into @Temp
	END
	IF LEN(@ReturnStr)>0
		SET @ReturnStr = LEFT(@ReturnStr,LEN(@ReturnStr)-1)
CLOSE Abc
DEALLOCATE Abc

RETURN @ReturnStr

END




