GO
SET QUOTED_IDENTIFIER ON
GO


CREATE FUNCTION [dbo].[CartonsForProductionOrder_F] (@OrderNo AS VARCHAR(50),@ItemCode AS VARCHAR(50))
RETURNS Varchar(4000) AS

BEGIN
DECLARE @ReturnString As Varchar(4000)
SET @ReturnString=''
DECLARE @CartonNo AS INT,@Qty AS INT
DECLARE Abc CURSOR FOR SELECT CartonNo,SUM(Qty) AS Qty FROM VDispatchListDetail_Adv WITH (NOLOCK)
	WHERE OrderNo=@OrderNo AND ItemCode=@ItemCode
	GROUP BY CartonNo

OPEN Abc

FETCH NEXT FROM Abc INTO @CartonNo,@Qty
WHILE @@Fetch_Status=0
	BEGIN
		SET @ReturnString=@ReturnString + CAST(@CartonNo AS VARCHAR(10)) + '(' + CAST(@Qty AS VARCHAR(10)) + ')' + CHAR(13) + CHAR(10)
		FETCH NEXT FROM Abc INTO @CartonNo,@Qty
	END
	IF LEN(@ReturnString)>0
		SET @ReturnString = LEFT(@ReturnString,Len(@ReturnString)-2)
CLOSE Abc
DEALLOCATE Abc

RETURN @ReturnString

END



