GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE FUNCTION [dbo].[F_AuthQtyForIss] (@ItemCode As Varchar(50),@LotNo As Int=null,@OrderNo As Varchar(50)=null,@ProcessID As Int=null,@VendID As Int=null)
RETURNS Int AS
Begin
Declare @RetVal As Int

		If @VendID = null

			Set @RetVal=(SELECT     SUM(RcvdQty+Wastage+LostQty) AS Quantity
			FROM         VVendRcvdItems
			WHERE     (ReqAuth = 1) AND (ItemCode=@ItemCode)
			GROUP BY ItemCode)
		Else
			Set @RetVal=(SELECT     SUM(RcvdQty+Wastage+LostQty) AS Quantity
			FROM         VVendRcvdItems
			WHERE     (ReqAuth = 1) AND (ItemCode=@ItemCode)  and (VendID=@VendID)
			GROUP BY ItemCode)

	Return IsNull(@RetVal,0)
End













