CREATE FUNCTION [dbo].[F_AuthQtyForRcv] (@ItemCode As Varchar(50),@ProcessID As Int=null)
RETURNS Int AS
Begin
Declare @RetVal As Int

	Set @RetVal=(SELECT SUM(IssQty) AS Quantity
	FROM         VendIssued INNER JOIN VendIssdDetail ON VendIssued.EntryID=VendIssdDetail.RefID
	WHERE     (ReqAuth = 1) AND (ItemCode=@ItemCode)  AND (ProcessID=@ProcessID)
	GROUP BY ItemCode,ProcessID)

Return IsNull(@RetVal,0)
End






















