/****** Object:  UserDefinedFunction [dbo].[F_CheckHoliday]    Script Date: 6/29/2026 4:49:59 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE FUNCTION [dbo].[F_CheckHoliday] (@DT as DateTime,@StartDT as DateTime,@EndDT as DateTime)

RETURNS DateTime

Begin
Declare @HDay as DateTime

Declare Holiday Cursor
	For Select DT From Holidays Where DT Between @StartDT and @EndDT Order By DT
Open Holiday
Fetch Next From Holiday Into @HDay

If DateName(dw,@DT)='Sunday'
Set @DT=DateAdd(Day,1,@DT)

While @@Fetch_Status=0
	Begin
		If @DT=@HDay
			Begin
				Set @DT=DateAdd(Day,1,@DT)
				If DateName(dw,@DT)='Sunday'
					Set @DT=DateAdd(Day,1,@DT)
			End
		Fetch Next From Holiday Into @HDay
	End
Close Holiday
Deallocate Holiday
Return
@DT
End























