CREATE FUNCTION [dbo].[F_CustomInvoiceOrderDates] (@CustomInvoice as Varchar(50))
RETURNS Varchar(1000) AS

Begin
Declare @Orders As Varchar(1000)
Set @Orders=''
Declare @Temp As DateTime
Declare @Temp1 As Varchar(255)
Declare Abc Cursor For Select Distinct OrderNo,DT From VrptCustomInvoiceDetail Where CustomInvoice=@CustomInvoice
Open Abc

Fetch Next From Abc Into @Temp1,@Temp
While @@Fetch_Status=0
	Begin
		Set @Orders=@Orders + ',' + Cast(Convert(Varchar(50),@Temp,5)  As Varchar(15))
		Fetch Next From Abc Into @Temp1,@Temp
	End

	Set @Orders = Right(@Orders,Len(@orders)-1)
Close Abc
Deallocate Abc

Return @Orders

End















