CREATE FUNCTION [dbo].[F_IssQty] (@OrderNo As Varchar(50),@ItemCode as Varchar(50),@ProcessID AS INT)
RETURNS INT AS
	Begin
		Declare @TotIss as int
		Set @TotIss=0

		SELECT     @TotIss=Sum(dbo.VendIssdDetail.IssQty)
		FROM         dbo.VendIssued INNER JOIN
			dbo.VendIssdDetail ON dbo.VendIssued.EntryID = dbo.VendIssdDetail.RefID
		Where OrderNo=@OrderNo AND ItemCode=@ItemCode and ProcessID=@ProcessID--dbo.F_ItemsTopProcID(@ItemCode)

		Return (IsNull(@TotIss,0))

	End
