/****** Object:  UserDefinedFunction [dbo].[F_NoOfDays]    Script Date: 6/29/2026 4:49:59 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO

--Resources Deductions
CREATE FUNCTION [dbo].[F_NoOfDays] (
@FirstDT Datetime,@SecondDT as DateTime) RETURNS int
Begin
	Declare @TotDays as int

	If Month(@FirstDT)<>Month(@SecondDT)
		Set @TotDays=Day(@SecondDT)
	Else
		Set @TotDays=DateDiff(dd,@FirstDT,@SecondDT)+1

	Return @TotDays
End







