CREATE FUNCTION [dbo].[F_OrderAmt] (@OrderNo as Varchar(50),@POrder as Bit=0)
RETURNS float(8) AS
Begin
Declare @TotAmt as Float(8)

If @POrder=1
	Set @TotAmt=(Select Sum(Qty*Price) From RMPOrderItems Where OrderNo=@OrderNo)
Else
	Set @TotAmt=(Select Sum(Qty*Price) From FOrderItems Where OrderNo=@OrderNo)


Return @TotAmt
End






