CREATE FUNCTION [dbo].[F_ProcQtyToIssue] (@OrderNo as varchar(50)=null)

RETURNS @TempTable TABLE (OrderNo nvarchar(50),ItemCode Varchar(50),ProcessID int,IssQty int,LotNo int)

	Begin
		Declare @EntryID as int
		set @EntryID=0
		If @OrderNo is null
			Insert @TempTable Select OrderNo,CompItemCode,ProcessID,RemQty,Null as LotNo From VFItemsTopProcID Where (RemQty>0)
		Else
			Insert @TempTable Select OrderNo,CompItemCode,ProcessID,RemQty ,Null as LotNo From VFItemsTopProcID Where (OrderNo=@OrderNo) and (RemQty>0)

		  --Insert Into @TempTable Select  isnull(@OrderNo,OrderNo) as OrderNo,ItemCode,T1.NextProcessID,IssuableQty From VVendRcvdItems as T1 Where T1.OrderNo=@OrderNo or @OrderNo is null
		  Insert Into @TempTable Select  isnull(@OrderNo,OrderNo) as OrderNo,ItemCode,T1.NextProcessID,Qty,Null as LotNo From VTotalRcvd as T1 Where T1.OrderNo=@OrderNo or @OrderNo is null

		  --Insert Into @TempTable Select  LotNo as OrderNo,ItemCode,T1.NextProcessID,Qty,LotNo From VTotalRcvdLots as T1
		Return
	End
















































