CREATE FUNCTION [dbo].[F_ProcQtyToIssue1] (@OrderNo as varchar(50))

RETURNS @TempTable TABLE (OrderNo nvarchar(50),ItemCode Varchar(50),ProcessID int,IssQty int)

Begin


			Declare @ItemCode as int

			Declare @OrdQty as int
			Set @OrdQty=(Select Sum(Qty) From FOrderItems Where OrderNo=@orderNo and ItemCode=@ItemCode)

			Insert @TempTable Select @OrderNo as OrderNo,ItemCode,ProcessID,Qty-IssQty From VFItemsTopProcID Where OrderNo=@OrderNo

			Insert Into @TempTable Select @OrderNo as OrderNo,@ItemCode as ItemCode,T1.NextProcessID,dbo.F_QtyToIssue(@OrderNo,@ItemCode,T1.NextProcessID) From VendRecievedItems as T1 Where T1.OrderNo=@OrderNo and T1.ItemCode=@ItemCode


		Return
End








