CREATE FUNCTION [dbo].[F_ProformaAmt] (@PInvoice as Varchar(50))
RETURNS float(8) AS
BEGIN
RETURN
(SELECT SUM(Qty*Price) FROM FProformaOrders LEFT OUTER JOIN
	(SELECT PInvoice,SUM(ChargesAmt) AS ChargesAmt FROM FPInvoiceOtherCharges GROUP BY PInvoice) TabOCs ON FProformaOrders.PInvoice=TabOCs.PInvoice
	WHERE FProformaOrders.PInvoice=@PInvoice)
END

