CREATE FUNCTION [dbo].[F_ProformaInternalOrders] (@PInvoice as Varchar(50))
RETURNS Varchar(1000) AS

Begin
Declare @Orders As Varchar(1000)
Set @Orders=''
Declare @Temp As Varchar(255)
Declare Abc Cursor For Select Distinct InternalRefNo From VFProformaOrders1 Where PInvoice=@PInvoice
Open Abc

Fetch Next From Abc Into @Temp
While @@Fetch_Status=0
	Begin
		Set @Orders=@Orders + ',' + @Temp
		Fetch Next From Abc Into @Temp
	End
	IF LEN(@Orders)>0
		Set @Orders = Right(@Orders,Len(@orders)-1)
Close Abc
Deallocate Abc

Return @Orders

End













