CREATE FUNCTION [dbo].[F_ToAppend] (@CustCode as varchar(30),@CustCountry as varchar(50))

/*RETURNS Table AS  Return

(SELECT @CustCode as CustCode,@CustCountry as Country, ItemID AS CompItemID, Unit, ItemID, ItemName as [Description], FOB, ExWorks,CnFAir, CnFSea, CIFAir, CIFSea,CnIAir,CnISea,
	FixedPackingUnit as PackingMode,ItemName AS CustomDescription, FOB AS CustomFOB, ExWorks As CustomExWorks ,CnFAir AS CustomCnFAir, CnFSea AS CustomCnFSea, CIFSea AS CustomCIFSea,
	CIFAir AS CustomCIFAir,CnIAir As CustomCnIAir,CnISea As CustomCnISea,' ' As EAN,ItemColor,FOBTop, ExWorksTop, CnFAirTop, CnFSeaTop, CIFAirTop, CIFSeaTop, CnIAirTop, CnISeaTop
FROM Items Where ItemID Not In(Select ItemID From FCustomerCatalog Where CustCode=@CustCode and Country=@CustCountry))*/

RETURNS @TempTable TABLE (CustCode VARCHAR(255),Country VARCHAR(255),CompItemID VARCHAR(255),Unit VARCHAR(50),ItemID VARCHAR(255),Description VARCHAR(1000),FOB REAL,ExWorks REAL,CnFAir REAL,CnFSea REAL,CIFAir REAL,CIFSea REAL,CnIAir REAL,CnISea REAL,
				PackingMode INT,CustomDescription VARCHAR(1000), CustomFOB REAL, CustomExWorks REAL ,CustomCnFAir REAL, CustomCnFSea REAL, CustomCIFSea REAL,
				CustomCIFAir REAL,CustomCnIAir REAL,CustomCnISea REAL,EAN VARCHAR(255),ItemColor VARCHAR(255),FOBTop REAL, ExWorksTop REAL, CnFAirTop REAL, CnFSeaTop REAL, CIFAirTop REAL, CIFSeaTop REAL, CnIAirTop REAL, CnISeaTop REAL)

BEGIN

DECLARE @Discount AS REAL
SELECT @Discount=MAXDiscount FROM ForeignCustomers WHERE CustCode=@CustCode AND Country=@CustCountry
IF ISNULL(@Discount,0)<>0
	SET @Discount=@Discount/100

INSERT INTO @TempTable
SELECT @CustCode AS CustCode,@CustCountry AS Country, ItemID AS CompItemID, Unit, ItemID, ItemName, ROUND(FOB-(FOB*@Discount),4), ROUND(ExWorks-(ExWorks*@Discount),4),ROUND(CnFAir-(CnFAir*@Discount),4), ROUND(CnFSea-(CnFSea*@Discount),4), ROUND(CIFAir-(CIFAir*@Discount),4), ROUND(CIFSea-(CIFSea*@Discount),4),
	ROUND(CnIAir-(CnIAir*@Discount),4),ROUND(CnISea-(CnISea*@Discount),4),FixedPackingUnit as PackingMode,ItemName, ROUND(FOB-(FOB*@Discount),4), ROUND(ExWorks-(ExWorks*@Discount),4) ,ROUND(CnFAir -(CnFAir*@Discount),4), ROUND(CnFSea -(CnFSea*@Discount),4), ROUND(CIFSea -(CIFSea*@Discount),4),
	ROUND(CIFAir -(CIFAir*@Discount),4),ROUND(CnIAir -(CnIAir*@Discount),4),ROUND(CnISea -(CnISea*@Discount),4),' ',ItemColor,ROUND(FOBTop -(FOBTop*@Discount),4), ROUND(ExWorksTop -(ExWorksTop*@Discount),4), ROUND(CnFAirTop -(CnFAirTop*@Discount),4), ROUND(CnFSeaTop -(CnFSeaTop*@Discount),4), ROUND(CIFAirTop -(CIFAirTop*@Discount),4),
	ROUND(CIFSeaTop -(CIFSeaTop*@Discount),4), ROUND(CnIAirTop -(CnIAirTop*@Discount),4), ROUND(CnISeaTop -(CnISeaTop*@Discount),4)
FROM Items WHERE ItemID NOT IN(SELECT CompItemID FROM FCustomerCatalog WHERE CustCode=@CustCode AND Country=@CustCountry)



RETURN
END


