BEGIN

DECLARE @Discount AS REAL
SET @Discount=0

INSERT INTO @TempTable
SELECT @Vend_AccNo,ItemID,Unit,ItemID,ItemName, ROUND(FOB-(FOB*@Discount),4), ROUND(ExWorks-(ExWorks*@Discount),4),ROUND(CnFAir-(CnFAir*@Discount),4), ROUND(CnFSea-(CnFSea*@Discount),4), ROUND(CIFAir-(CIFAir*@Discount),4), ROUND(CIFSea-(CIFSea*@Discount),4),
	ROUND(CnIAir-(CnIAir*@Discount),4),ROUND(CnISea-(CnISea*@Discount),4),FixedPackingUnit as PackingMode,ItemName, ROUND(FOB-(FOB*@Discount),4), ROUND(ExWorks-(ExWorks*@Discount),4) ,ROUND(CnFAir -(CnFAir*@Discount),4), ROUND(CnFSea -(CnFSea*@Discount),4), ROUND(CIFSea -(CIFSea*@Discount),4),
	ROUND(CIFAir -(CIFAir*@Discount),4),ROUND(CnIAir -(CnIAir*@Discount),4),ROUND(CnISea -(CnISea*@Discount),4),' ',ItemColor,ROUND(FOBTop -(FOBTop*@Discount),4), ROUND(ExWorksTop -(ExWorksTop*@Discount),4), ROUND(CnFAirTop -(CnFAirTop*@Discount),4), ROUND(CnFSeaTop -(CnFSeaTop*@Discount),4), ROUND(CIFAirTop -(CIFAirTop*@Discount),4),
	ROUND(CIFSeaTop -(CIFSeaTop*@Discount),4), ROUND(CnIAirTop -(CnIAirTop*@Discount),4), ROUND(CnISeaTop -(CnISeaTop*@Discount),4)
FROM Items WHERE ItemID NOT IN(SELECT ItemID FROM Vendor_Catalog WHERE Vend_AccNo=@Vend_AccNo)



RETURN
