CREATE FUNCTION [dbo].[F_TotalSundays] (@FirstDate as DateTime,@SecondDate as DateTime)
RETURNS Int
Begin
Declare @TotSuns as int
Declare @TotDays as int
Declare @DaysToFirstSun as int
Set @TotDays=DateDiff(day,@FirstDate,@SecondDate)
Set @DaysToFirstSun=(8-DAY(@FirstDate)/7)

If @DaysToFirstSun>@TotDays
	Set @TotSuns=0
Else
	Set @TotSuns=(@TotDays-@DaysToFirstSun)/7+1
Return
@TotSuns



/*	set @Per=isnull((Select PerIncrease From PercentageRanges Where @Qty Between QtyFrom and QtyTo),2)
	Return
	((@Qty*@Per/100)+@Qty) */
End



















