CREATE FUNCTION [dbo].[FHoldedSalaries](@ParDate datetime)
RETURNS @retTABLE TABLE(EmpID VARCHAR(50),HoldAmt INT)
BEGIN
	DECLARE @myDT dateTIME
	SET @myDT=DATEADD(m,-1,@ParDate)
	INSERT INTO @retTABLE SELECT EmpID, HoldAmt
	FROM EmpHoldSalary
	WHERE (month(dt) = Month(@myDT) AND year(DT) = Year(@myDT) )

	RETURN
END



