CREATE FUNCTION  [dbo].[FOverTime](@ParDate datetime)

RETURNS @TempTable TABLE (EmpID VARCHAR(50),OverTimeHours REAL,SAOverTimeHours REAL,LateComingHrs_Adjusted REAL,OTHrs_Actual REAL,LateComingHrs_Actual REAL,Food_Allowance INT)

BEGIN

DECLARE @TempTable_Working TABLE(EmpID VARCHAR(50),DT DATETIME,OTHrs REAL,LateHrs REAL,Food_Allowance_Rate INT)
DECLARE @TempTable_Late TABLE(EmpID VARCHAR(50),DT DATETIME,LateHrs REAL)

INSERT INTO @TempTable_Late(EmpId,DT,LateHrs)
	SELECT EmpID,DT,LateComingHrs FROM dbo.LateComingHrs_Datewise_Fn(@ParDate)

INSERT INTO @TempTable_Working(EmpID,DT,OTHrs,Food_Allowance_Rate)
	SELECT EmpTimes.EmpID,DT, SUM((PayableHrs)) AS OTHrs--SUM(FLOOR(PayableHrs)) AS OTHrs
		,Employees.EmpLunchAmt
FROM EmpTimes
INNER JOIN Employees ON EmpTimes.EmpID=Employees.EmpID
--WHERE (MONTH(EmpTimes.DT) = MONTH(@ParDate) AND YEAR(EmpTimes.DT) = YEAR(@ParDate) AND EmpTimes.DT <=@ParDATE ) AND OverTime=1 AND PayableHrs>=1
-- IF ANY EMPLOYEE MARK OVERTIME 10 MINTUES IT SHOULD COME IN SALARY
WHERE (MONTH(EmpTimes.DT) = MONTH(@ParDate) AND YEAR(EmpTimes.DT) = YEAR(@ParDate) AND EmpTimes.DT <=@ParDATE ) AND OverTime=1 AND (DateName(WeekDay,DT)<>'Sunday')  --AND PayableHrs>=1
AND DT NOT IN (SELECT DT FROM Holidays)
GROUP BY EmpTimes.EmpID,EmpTimes.DT,Employees.EmpLunchAmt
HAVING SUM(PayableHrs)>0.4833	--29 Mins.

--UNION

--SELECT EmpID,DT,SUM(FLOOR(OTHrs)) AS OTHrs FROM EmpOTHrs WHERE MONTH(DT)=MONTH(@ParDate) AND YEAR(DT)=YEAR(@ParDate) GROUP BY EmpID,DT
--- NEED TO PAY ALL OTS
--SELECT EmpID,DT,SUM((OTHrs)) AS OTHrs FROM EmpOTHrs WHERE MONTH(DT)=MONTH(@ParDate) AND YEAR(DT)=YEAR(@ParDate) AND (DateName(WeekDay,DT)<>'Sunday')  GROUP BY EmpID,DT

UNION

--SELECT EmpTimes.EmpID,EmpTimes.DT,SUM(FLOOR(PayableHrs)) AS OTHrs FROM EmpTimes INNER JOIN Employees ON EmpTimes.EmpID=Employees.EmpID
--- NEED TO PAY ALL OTS
SELECT EmpTimes.EmpID,EmpTimes.DT,SUM((PayableHrs)) AS OTHrs,Employees.EmpLunchAmt FROM EmpTimes INNER JOIN Employees ON EmpTimes.EmpID=Employees.EmpID
WHERE Employees.Designation<>'Security Guard' AND  MONTH(DT)=MONTH(@ParDate) AND YEAR(DT)=YEAR(@ParDate) AND EmpTimes.DT<=@ParDate
	--AND (DateName(WeekDay,DT)='Sunday' OR DT IN(SELECT DT FROM Holidays)) GROUP BY EmpTimes.EmpID,EmpTimes.DT
	AND (DateName(WeekDay,DT)<>'Sunday' AND DT IN(SELECT DT FROM Holidays)) GROUP BY EmpTimes.EmpID,EmpTimes.DT,Employees.EmpLunchAmt

UPDATE @TempTable_Working SET LateHrs=T1.LateHrs FROM @TempTable_Working T2
	LEFT JOIN @TempTable_Late T1 ON T2.EmpID=T1.EmpID AND T2.DT=T1.DT

/*INSERT INTO @TempTable(EmpID,OverTimeHours,LateComingHrs_Adjusted,OTHrs_Actual)
	SELECT EmpID,SUM(OTHrs-ISNULL(LateHrs,0)),SUM(LateHrs),SUM(OTHrs) FROM @TempTable_Working GROUP BY EmpID*/
/*INSERT INTO @TempTable(EmpID,OverTimeHours,LateComingHrs_Adjusted,OTHrs_Actual)
	SELECT EmpID
		--,SUM(CASE WHEN OTHrs>ISNULL(LateHrs,0) THEN (OTHrs-ISNULL(LateHrs,0)) ELSE 0 END)
		,CASE WHEN SUM(OTHrs)-SUM(LateHrs)>0 THEN SUM(OTHrs)-SUM(LateHrs) ELSE 0 END
		,SUM(LateHrs),SUM(OTHrs) FROM @TempTable_Working GROUP BY EmpID*/

INSERT INTO @TempTable(EmpID,OverTimeHours,LateComingHrs_Actual,OTHrs_Actual,Food_Allowance)
	SELECT EmpID,SUM(OTHrs),0,SUM(OTHrs),SUM(CASE WHEN OTHrs BETWEEN 3 AND 3.99 THEN Food_Allowance_Rate ELSE 0 END) AS Food_Allowance FROM @TempTable_Working GROUP BY EmpID

UPDATE TMain SET LateComingHrs_Actual=T1.LateHrs FROM @TempTable TMain INNER JOIN (SELECT EmpID,SUM(LateHrs) AS LateHrs FROM @TempTable_Late GROUP BY EmpID) T1 ON TMain.EmpID=T1.EmpID
UPDATE @TempTable SET LateComingHrs_Actual=0 WHERE LateComingHrs_Actual IS NULL

UPDATE TMain SET OverTimeHours=CASE WHEN OverTimeHours>LateComingHrs_Actual THEN OverTimeHours-LateComingHrs_Actual ELSE 0 END FROM @TempTable TMain
UPDATE TMain SET LateComingHrs_Adjusted=OTHrs_Actual-OverTimeHours FROM @TempTable TMain


UPDATE @TempTable SET SAOverTimeHours=OverTimeHours,LateComingHrs_Adjusted=(OTHrs_Actual-OverTimeHours)

RETURN

END
