CREATE FUNCTION  [dbo].[FSandwichLeaves](@ParDate DateTime)
RETURNS @ReturnTable TABLE (EmpID Varchar(50),SPAbsentDays REAL)
AS
BEGIN

DECLARE @DTFrom AS DATETIME,@DTTo AS DATETIME

SET @DTFrom=DATEADD(dd,-day(@ParDate)+1,@ParDate)
SET @DTTo=@ParDate
--SET @DTTo=DATEADD(dd,-day(@ParDate),DateAdd(mm,1,@ParDate))
DECLARE @TempDT AS DATETIME
SET @TempDT=@DTFrom

DECLARE  @myDT  TABLE(DT  DATETIME,DTEarly DATETIME,DTLater DATETIME,Weightage INT,DTToCheck DATETIME)
DECLARE @Dates TABLE(DT DATETIME)

DECLARE @Count AS INT
DECLARE @LastDT AS DATETIME,@NextDT AS DATETIME,@PrevNextDT AS DATETIME
DECLARE @DTEarly1 AS DATETIME
WHILE @TempDT<=@DTTO
	BEGIN
		IF dbo.IsWorkingDay(@TempDT)=0
			BEGIN
				SET @LastDT=dbo.GetLastWorkingDate(@TempDT)

				SET @DTEarly1= DATEADD(dd,-1,@LastDT)
				IF dbo.IsWorkingDay(@DTEarly1)=0
					SET @DTEarly1=@LastDT

				SET @NextDT=dbo.GetNextWorkingDate(@TempDT)
				INSERT INTO @myDT(DT,DTEarly,DTLater,Weightage,DTToCheck) VALUES(@TempDT,@LastDT,@NextDT,DATEDIFF(dd,@LastDT,@NextDT)-1,@LastDT)

				IF @LastDT<>@DTEarly1
					INSERT INTO @myDT(DT,DTEarly,DTLater,Weightage,DTToCheck) VALUES(@TempDT,@DTEarly1,@NextDT,DATEDIFF(dd,@LastDT,@NextDT)-1,@LastDT)

				SET @PrevNextDT=@NextDT
				SET @TempDT=@NextDT
			END
		ELSE
			BEGIN
				SET @TempDT=DateAdd(dd,1,@TempDT)
			END

	END

DECLARE @EmpAbsDays TABLE(EmpID VARCHAR(50),AbsentDT DATETIME,Weightage Real)
DECLARE @EmpAbsDays1 TABLE(EmpID VARCHAR(50),AbsentDT DATETIME,Weightage Real)
DECLARE myCursor CURSOR FOR SELECT EmpID,JoinDate,DiscontinuedOn FROM Employees
DECLARE @EmpID AS VARCHAR(50),@JoinDT AS DATETIME,@DiscontinuedOn AS DATETIME
Open myCursor

FETCH NEXT FROM myCursor INTO @EmpID,@JoinDT,@DiscontinuedOn
WHILE @@Fetch_Status=0
	BEGIN
		--Add Sandwich Leaves Where Day Before & After Holiday[s] Or Sunday is Absent.
		/*INSERT INTO @EmpAbsDays SELECT @EmpID,DT,Weightage FROM @myDT WHERE DTEarly NOT IN(SELECT EmpTimes.DT FROM EmpTimes INNER JOIN @myDT myDT ON EmpTimes.DT=myDT.DTEarly WHERE EmpID=@EmpID)
			AND DTEarly NOT IN(SELECT AttendanceSheet.DT FROM AttendanceSheet INNER JOIN @myDT myDT ON AttendanceSheet.DT=myDT.DTEarly WHERE EmpID=@EmpID AND Attendance IN(2))
			AND DTEarly>=@JoinDT AND (DTEarly<@DiscontinuedOn OR @DiscontinuedOn IS NULL)


			AND DTLater NOT IN(SELECT EmpTimes.DT FROM EmpTimes INNER JOIN @myDT myDT ON EmpTimes.DT=myDT.DTLater WHERE EmpID=@EmpID)
			AND DTLater>=@JoinDT AND (DTLater<@DiscontinuedOn OR @DiscontinuedOn IS NULL)
			AND DTLater NOT IN(SELECT AttendanceSheet.DT FROM AttendanceSheet INNER JOIN @myDT myDT ON AttendanceSheet.DT=myDT.DTLater WHERE EmpID=@EmpID AND Attendance IN(2))*/
		--Add Sandwich Leaves Where Day After Holiday[s] Or Sunday is Absent.And Day before is Not Absent.. Add Half.
		/*INSERT INTO @EmpAbsDays SELECT @EmpID,DT,Weightage/2.00 FROM @myDT WHERE (DTEarly IN(SELECT EmpTimes.DT FROM EmpTimes INNER JOIN @myDT myDT ON EmpTimes.DT=myDT.DTEarly WHERE EmpID=@EmpID)
			OR DTEarly IN(SELECT AttendanceSheet.DT FROM AttendanceSheet INNER JOIN @myDT myDT ON AttendanceSheet.DT=myDT.DTEarly WHERE EmpID=@EmpID AND Attendance IN(2)))
			AND DTEarly>=@JoinDT AND (DTEarly<@DiscontinuedOn OR @DiscontinuedOn IS NULL)
			AND DTLater NOT IN(SELECT EmpTimes.DT FROM EmpTimes INNER JOIN @myDT myDT ON EmpTimes.DT=myDT.DTLater WHERE EmpID=@EmpID)
			AND DTLater>=@JoinDT AND (DTLater<@DiscontinuedOn OR @DiscontinuedOn IS NULL)
			AND DTLater NOT IN(SELECT AttendanceSheet.DT FROM AttendanceSheet INNER JOIN @myDT myDT ON AttendanceSheet.DT=myDT.DTLater WHERE EmpID=@EmpID AND Attendance IN(2))*/
		--Add Sandwich Leaves Where Day Before Holiday[s] Or Sunday is Absent.And Day After is Not Absent.. Add Half.
		INSERT INTO @EmpAbsDays SELECT @EmpID,DT,Weightage/2.00 FROM @myDT WHERE (DTEarly NOT IN(SELECT EmpTimes.DT FROM EmpTimes INNER JOIN @myDT myDT ON EmpTimes.DT=myDT.DTEarly WHERE EmpID=@EmpID)
			AND DTEarly NOT IN(SELECT AttendanceSheet.DT FROM AttendanceSheet INNER JOIN @myDT myDT ON AttendanceSheet.DT=myDT.DTEarly WHERE EmpID=@EmpID AND Attendance IN(2))
			AND DTEarly>=@JoinDT AND (DTEarly<@DiscontinuedOn OR @DiscontinuedOn IS NULL))
			AND (DTToCheck NOT IN(SELECT EmpTimes.DT FROM EmpTimes INNER JOIN @myDT myDT ON EmpTimes.DT=myDT.DTEarly WHERE EmpID=@EmpID)
			AND DTToCheck NOT IN(SELECT AttendanceSheet.DT FROM AttendanceSheet INNER JOIN @myDT myDT ON AttendanceSheet.DT=myDT.DTEarly WHERE EmpID=@EmpID AND Attendance IN(2))
			AND DTToCheck>=@JoinDT AND (DTEarly<@DiscontinuedOn OR @DiscontinuedOn IS NULL))

		/*INSERT INTO @EmpAbsDays SELECT @EmpID,DT,Weightage/2.00 FROM @myDT WHERE DTEarly NOT IN(SELECT EmpTimes.DT FROM EmpTimes INNER JOIN @myDT myDT ON EmpTimes.DT=myDT.DTEarly WHERE EmpID=@EmpID)
			AND DTEarly NOT IN(SELECT AttendanceSheet.DT FROM AttendanceSheet INNER JOIN @myDT myDT ON AttendanceSheet.DT=myDT.DTEarly WHERE EmpID=@EmpID AND Attendance IN(2))
			AND DTEarly>=@JoinDT AND (DTEarly<@DiscontinuedOn OR @DiscontinuedOn IS NULL)*/
			/*AND (DTLater IN(SELECT EmpTimes.DT FROM EmpTimes INNER JOIN @myDT myDT ON EmpTimes.DT=myDT.DTLater WHERE EmpID=@EmpID)
			OR DTLater IN(SELECT AttendanceSheet.DT FROM AttendanceSheet INNER JOIN @myDT myDT ON AttendanceSheet.DT=myDT.DTLater WHERE EmpID=@EmpID AND Attendance IN(2)))
			AND DTLater>=@JoinDT AND (DTLater<@DiscontinuedOn OR @DiscontinuedOn IS NULL)*/


		FETCH NEXT FROM myCursor INTO @EmpID,@JoinDT,@DiscontinuedOn
	END

CLOSE myCursor
DEALLOCATE myCursor

--SELECT * FROM @myDT
--SELECT * FROM @EmpAbsDays
INSERT INTO @EmpAbsDays1 SELECT * FROM @EmpAbsDays
INSERT @ReturnTable SELECT  EmpID,SUM(EmpAbsDays.Weightage) FROM @EmpAbsDays1 EmpAbsDays GROUP BY EmpID--INNER JOIN @myDT myDT ON AbsentDT BETWEEN DTEarly AND DTLater GROUP BY EmpID

RETURN

END











