CREATE FUNCTION  [dbo].[FSandwichLeaves_Frgz](@ParDate DateTime)
RETURNS @ReturnTable TABLE (EmpID Varchar(50),SPAbsentDays REAL)
AS
BEGIN

DECLARE @DTFrom AS DATETIME,@DTTo AS DATETIME

SET @DTFrom=DATEADD(dd,-day(@ParDate)+1,@ParDate)
SET @DTTo=@ParDate
--SET @DTTo=DATEADD(dd,-day(@ParDate),DateAdd(mm,1,@ParDate))
DECLARE @TempDT AS DATETIME
SET @TempDT=@DTFrom

DECLARE  @myDTTemp  TABLE(DT  DATETIME,Weightage INT,CheckDT DATETIME,DTToCheck DATETIME,DTToCheckNext DATETIME)
DECLARE  @myDT  TABLE(DT  DATETIME,Weightage INT,CheckDT DATETIME,DTToCheck DATETIME,DTToCheckNext DATETIME)

DECLARE @Dates TABLE(DT DATETIME)

DECLARE @Count AS INT
DECLARE @LastDT AS DATETIME,@NextDT AS DATETIME,@PrevNextDT AS DATETIME
DECLARE @LastDT1 AS DATETIME,@NextDT1 AS DATETIME
DECLARE @DTEarly1 AS DATETIME
DECLARE @DaysDiff AS INT,@iCounter AS INT
SET @iCounter=0
DECLARE @myPrevDT AS DATETIME,@myNextDT AS DATETIME,@myDTToCheck AS DATETIME
WHILE @TempDT<=@DTTO
	BEGIN
		IF dbo.IsWorkingDay(@TempDT)=0
			BEGIN
				SET @LastDT=dbo.GetLastWorkingDate(@TempDT)
				SET @LastDT1=DateAdd(d,-1,@LastDT)

				SET @NextDT=dbo.GetNextWorkingDate(@TempDT)
				SET @NextDT1=DateAdd(d,1,@NextDT)

				INSERT INTO @myDTTemp(DT,Weightage,CheckDT,DTToCheck,DTToCheckNext) VALUES(@LastDT,DATEDIFF(dd,@LastDT,@NextDT)-1,@TempDT,@LastDT,@NextDT)
				--For Day Before...
				--IF dbo.IsWorkingDay(@LastDT1)=1
				--	INSERT INTO @myDTTemp(DT,Weightage,CheckDT,DTToCheck) VALUES(@LastDT1,DATEDIFF(dd,@LastDT,@NextDT)-1,@TempDT,@LastDT)

				--INSERT INTO @myDTTemp(DT,Weightage,CheckDT,DTToCheck) VALUES(@NextDT,DATEDIFF(dd,@LastDT,@NextDT)-1,@TempDT,@NextDT)
				--For Day After...
				--IF dbo.IsWorkingDay(@NextDT1)=1
				--	INSERT INTO @myDTTemp(DT,Weightage,CheckDT,DTToCheck) VALUES(@NextDT1,DATEDIFF(dd,@LastDT,@NextDT)-1,@TempDT,@NextDT)

				SET @TempDT=DATEADD(dd,1,@NextDT)
			END
		ELSE
			BEGIN
				SET @TempDT=DateAdd(dd,1,@TempDT)
			END

	END

INSERT INTO @myDT SELECT DISTINCT * FROM @myDTTemp

DECLARE myCursor CURSOR FOR SELECT EmpID,JoinDate,DiscontinuedOn FROM Employees
DECLARE @EmpID AS VARCHAR(50),@JoinDT AS DATETIME,@DiscontinuedOn AS DATETIME

DECLARE @EmpAbsDays TABLE(EmpID VARCHAR(50),AbsentDT DATETIME,Weightage Real,CheckDT DATETIME,WeightageDT Real)
DECLARE @EmpAbsDays1 TABLE(EmpID VARCHAR(50),AbsentDT DATETIME,Weightage Real)
Open myCursor

FETCH NEXT FROM myCursor INTO @EmpID,@JoinDT,@DiscontinuedOn
WHILE @@Fetch_Status=0
	BEGIN

		/*INSERT INTO @EmpAbsDays SELECT @EmpID,DT,0.5,CheckDT,Weightage FROM @myDT WHERE (DT NOT IN(SELECT EmpTimes.DT FROM EmpTimes INNER JOIN @myDT myDT ON EmpTimes.DT=myDT.DT WHERE EmpID=@EmpID)
			AND DTToCheck NOT IN(SELECT EmpTimes.DT FROM EmpTimes INNER JOIN @myDT myDT ON EmpTimes.DT=myDT.DT WHERE EmpID=@EmpID)
			AND DT NOT IN(SELECT AttendanceSheet.DT FROM AttendanceSheet INNER JOIN @myDT myDT ON AttendanceSheet.DT=myDT.DT WHERE EmpID=@EmpID AND Attendance IN(2))
			AND DTToCheck NOT IN(SELECT AttendanceSheet.DT FROM AttendanceSheet INNER JOIN @myDT myDT ON AttendanceSheet.DT=myDT.DT WHERE EmpID=@EmpID AND Attendance IN(2))
			AND DT>=@JoinDT AND (DT<@DiscontinuedOn OR @DiscontinuedOn IS NULL))*/

		INSERT INTO @EmpAbsDays SELECT @EmpID,DT,1,CheckDT,Weightage FROM @myDT WHERE
			((DTToCheck NOT IN(SELECT EmpTimes.DT FROM EmpTimes INNER JOIN @myDT myDT ON EmpTimes.DT=myDT.DT WHERE EmpID=@EmpID)
			AND DTToCheck NOT IN(SELECT AttendanceSheet.DT FROM AttendanceSheet INNER JOIN @myDT myDT ON AttendanceSheet.DT=myDT.DT WHERE EmpID=@EmpID AND Attendance IN(2)))
			OR
			(DTToCheckNext NOT IN(SELECT EmpTimes.DT FROM EmpTimes INNER JOIN @myDT myDT ON EmpTimes.DT=myDT.DTToCheckNext WHERE EmpID=@EmpID)
			AND DTToCheckNext NOT IN(SELECT AttendanceSheet.DT FROM AttendanceSheet INNER JOIN @myDT myDT ON AttendanceSheet.DT=myDT.DTToCheckNext WHERE EmpID=@EmpID AND Attendance IN(2))))
			AND (DTToCheck>=@JoinDT AND (DTToCheckNext<@DiscontinuedOn OR @DiscontinuedOn IS NULL))

		FETCH NEXT FROM myCursor INTO @EmpID,@JoinDT,@DiscontinuedOn
	END

CLOSE myCursor
DEALLOCATE myCursor

INSERT @ReturnTable SELECT EmpID,SUM(Weightage) FROM (SELECT EmpID,CheckDT,WeightageDT,CASE WHEN SUM(Weightage)>WeightageDT THEN WeightageDT ELSE SUM(Weightage) END AS Weightage FROM @EmpAbsDays GROUP BY EmpID,CheckDT,WeightageDT) T1 GROUP BY EmpID

RETURN

END
