SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE FUNCTION  [dbo].[FShortLeaves] (@ParDate  as datetime,@EmpID as VarChar(50))
RETURNS Varchar(500) As
Begin
	Declare @From VARCHAR(255)
	Declare @To  VARCHAR(255)
	Declare @FinalStr  VARCHAR(500)
	Declare @CL As Real,@SL As Real,@AL As Real,@CPL As Real,@LWP As Real,@ML As Real,@SAL As Real
	Declare @LeaveType As Varchar(40)
	SET @LeaveType=''
	Set @FinalStr = ''
	Declare cur cursor
	FOR SELECT  CL,SL,AL,CPL,LWP,ML,SAL,[From],[To] FROM Leaves
	WHERE DT = @ParDate AND EmpID=@EmpID AND [Full]=0
	Open Cur
	FETCH NEXT FROM Cur INTO @CL,@SL,@AL,@CPL,@LWP,@ML,@SAL,@From,@To
	If @CL Is NOT NULL
		SET @LeaveType='Casual '
	Else If @SL IS NOT NULL
		SET @LeaveType='Sick '
	Else If @AL IS NOT NULL
		SET @LeaveType='Annual '
	Else If @CPL IS NOT NULL
		SET @LeaveType='CPL '
	Else If @LWP IS NOT NULL
		SET @LeaveType='LWP '
	Else If @ML IS NOT NULL
		SET @LeaveType='ML '
	Else If @SAL IS NOT NULL
		SET @LeaveType='SAL '
	Set @FinalStr =  @LeaveType + '(' + @From  + ' To ' + @To + ')'
	FETCH NEXT FROM Cur INTO @CL,@SL,@AL,@CPL,@LWP,@ML,@SAL,@From,@To

	while @@FETCH_STATUS=0
		BEGIN
			If @CL Is NOT NULL
				SET @LeaveType='Casual '
			Else If @SL IS NOT NULL
				SET @LeaveType='Sick '
			Else If @AL IS NOT NULL
				SET @LeaveType='Annual '
			Else If @CPL IS NOT NULL
				SET @LeaveType='CPL '
			Else If @LWP IS NOT NULL
				SET @LeaveType='LWP '
			Else If @ML IS NOT NULL
				SET @LeaveType='ML '
			Else If @SAL IS NOT NULL
				SET @LeaveType='SAL '
			Set @FinalStr = @FinalStr + ',' + @LeaveType + '(' + @From  + ' To ' + @To + ')'
			FETCH NEXT FROM Cur INTO @CL,@SL,@AL,@CPL,@LWP,@ML,@SAL,@From,@To
		END
	Return @FinalStr
End





