CREATE FUNCTION [dbo].[FTotalSundays](@DTFrom as datetime,@DTTo as datetime)
RETURNS int AS
BEGIN
	DECLARE @FirstDay As Int,@StartDay As Int
	DECLARE @FirstSunday As Int,@TotSuns As Int
	DECLARE @iDay AS Int,@i AS Int
	Set @iDay = Day(@DtTo)
	Set @FirstDay = DatePart(WeekDay,@DTFrom)

	Set @StartDay = Day(@DTFrom)

	If @FirstDay<>1--@StartDay <> @FirstDay
		Set @FirstSunday = (8 - @FirstDay) --@StartDay + (8 - @FirstDay)
	Else
		Set @FirstSunday = 0


	Set @TotSuns = 0
	Set @DTFrom=DateAdd(day,@FirstSunday,@DTFrom)
/*	If IsDate(Cast(Month(@DTFrom) As Varchar) + '/' + Cast(@FirstSunday As Varchar) + '/' + Cast(Year(@DTFrom) As Varchar))=0
		Set @DTFrom=Cast(Month(@DTFrom)+1 As Varchar) + '/' + Cast(@FirstSunday As Varchar) + '/' + Cast(Year(@DTFrom) As Varchar)
	Else
		Set @DTFrom=Cast(Month(@DTFrom) As Varchar) + '/' + Cast(@FirstSunday As Varchar) + '/' + Cast(Year(@DTFrom) As Varchar)
*/
	While @DTFrom<=@DTTo
		Begin

			Set @TotSuns=@TotSuns+1
			Set @i=@i+7
			Set @DTFrom=DateAdd(d,7,@DTFrom)
		End



Return @TotSuns
END







