CREATE FUNCTION [dbo].[GetAllLots_F] (@LotNo AS VARCHAR(50))

RETURNS @TempTable TABLE (RefLotNo VARCHAR(50),LotNo VARCHAR(50))


	BEGIN

		DECLARE @TempLotNo AS VARCHAR(50),@TempLotNo1 AS VARCHAR(50)
		SET @TempLotNo=@LotNo
		INSERT INTO @TempTable VALUES(@LotNo,@TempLotNo)
		WHILE @TempLotNo IS NOT NULL
			BEGIN
				SET @TempLotNo1=NULL
				SELECT @TempLotNo1=VendRcvdDetail1.LotNo FROM VendRcvdDetail
				INNER JOIN LotTransferDetails ON LotTransferDetails.VRD_To_RefID=VendRcvdDetail.EntryID
				INNER JOIN VendRcvdDetail VendRcvdDetail1 ON VendRcvdDetail1.EntryID=LotTransferDetails.VRD_From_RefID
				WHERE VendRcvdDetail.LotNo=@TempLotNo AND Type=1
				IF @TempLotNo1 IS NOT NULL
					INSERT INTO @TempTable VALUES(@LotNo,@TempLotNo1)
				SET @TempLotNo=@TempLotNo1
			END

		RETURN
	END




