CREATE FUNCTION [dbo].[GetAllRepairLots_F] (@LotNo AS VARCHAR(50))
RETURNS VARCHAR(1000) AS

BEGIN
DECLARE @ReturnStr AS VARCHAR(1000)
SET @ReturnStr=''
DECLARE @Temp AS VARCHAR(255)
DECLARE Abc CURSOR FOR SELECT DISTINCT VendIssdDetail.LotNo FROM VendIssdDetail
				INNER JOIN VendReWorkIssuanceDetail ON VendReWorkIssuanceDetail.VID_RefID=VendIssdDetail.EntryID
				INNER JOIN VendRcvdDetailReWorkDetail ON VendReWorkIssuanceDetail.VRDRWD_RefID=VendRcvdDetailReWorkDetail.EntryID
				INNER JOIN VendRcvdDetail ON VendRcvdDetailReWorkDetail.VRD_RefID=VendRcvdDetail.EntryID
				WHERE VendRcvdDetail.LotNo=@LotNo
OPEN Abc

FETCH NEXT FROM Abc into @Temp
WHILE @@Fetch_Status=0
	BEGIN
		SET @ReturnStr=@ReturnStr + @Temp + ','
		FETCH NEXT FROM Abc Into @Temp
	END
	IF LEN(@ReturnStr)>0
		SET @ReturnStr = LEFT(@ReturnStr,LEN(@ReturnStr)-1)
CLOSE Abc
DEALLOCATE Abc

RETURN @ReturnStr

END






