GO
SET QUOTED_IDENTIFIER ON
GO

CREATE FUNCTION [dbo].[GetBalance] (@AccNo As Varchar(50),@DT As DateTime,@CurrentDT As DateTime)
	RETURNS Money As
	Begin
		SET @DT=CAST(CONVERT(varchar(50),@DT,6) AS DATETIME)
		SET @CurrentDT=CAST(CONVERT(varchar(50),@CurrentDT,1) AS DATETIME)
		DECLARE @MaxDT As DateTime
		DECLARE @TransAmt As Money,@Balance As Money
		SET @TransAmt=0
		SELECT @MaxDT=Max(VDate) From Vouchers Where AccNo=@AccNo
		IF @MaxDT Is NULL
			SET @MaxDT=@CurrentDT

		IF @DT<@MaxDT
			Select @Balance=Balance,@TransAmt=Credit-Debit From Vouchers Where SNo=(Select Max(SNo) From Vouchers Where VDate<=@DT AND AccNo=@AccNo)
		Else
			Select @Balance=Balance From Accounts Where AccNo=@AccNo

		IF @Balance Is NULL
			Select @Balance=OpenBal From Accounts Where AccNo=@AccNo

		RETURN @Balance
	End







