		FETCH NEXT FROM Abc INTO @LotNo,@RcvdQty
	END
	IF LEN(@ReturnString)>0
		SET @ReturnString = LEFT(@ReturnString,Len(@ReturnString)-1)
CLOSE Abc
DEALLOCATE Abc

