SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE FUNCTION [dbo].[IsWorkingDay] (@DT As DateTime)
	RETURNS Bit As
	Begin
		DECLARE @ReturnVal Bit
		DECLARE @iCount as TinyInt
		SELECT @iCount=Count(DT) From Holidays Where DT=@DT
		IF @iCount=0
			BEGIN
				IF DateName(Weekday,@DT)='Sunday'
					SET @ReturnVal=0
				ELSE
					SET @ReturnVal=1
			END
		Else
			SET @ReturnVal=0
		RETURN @ReturnVal
	End
GO
