/****** Object:  UserDefinedFunction [dbo].[OverTime_Datewise_Fn]    Script Date: 6/29/2026 4:49:59 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE FUNCTION  [dbo].[OverTime_Datewise_Fn](@ParDate DATETIME,@EmpID VARCHAR(50))

RETURNS @TempTable_Working TABLE(EmpID VARCHAR(50),DT DATETIME,OTHrs REAL,LateHrs REAL)

BEGIN

DECLARE @TempTable_Late TABLE(EmpID VARCHAR(50),DT DATETIME,LateHrs REAL)
INSERT INTO @TempTable_Late(EmpId,DT,LateHrs)
	SELECT EmpID,DT,LateComingHrs FROM dbo.LateComingHrs_Datewise_Fn(@ParDate)

DECLARE @TempTable_OT TABLE(EmpID VARCHAR(50),DT DATETIME,OTHrs REAL)

INSERT INTO @TempTable_OT(EmpID,DT,OTHrs)
	SELECT EmpTimes.EmpID,DT, SUM(ROUND(PayableHrs,2)) AS OTHrs
FROM EmpTimes
WHERE (MONTH(EmpTimes.DT) = MONTH(@ParDate) AND YEAR(EmpTimes.DT) = YEAR(@ParDate) AND EmpTimes.DT <=@ParDATE ) AND OverTime=1 AND PayableHrs>=1
AND NOT (DateName(WeekDay,DT)='Sunday'	OR DT IN(SELECT DT FROM Holidays))
GROUP BY EmpTimes.EmpID,EmpTimes.DT

UNION

SELECT EmpID,DT,SUM(FLOOR(OTHrs)) AS OTHrs FROM EmpOTHrs WHERE MONTH(DT)=MONTH(@ParDate) AND YEAR(DT)=YEAR(@ParDate) GROUP BY EmpID,DT

UNION

SELECT EmpTimes.EmpID,EmpTimes.DT,SUM(ROUND(PayableHrs,2)) AS OTHrs FROM EmpTimes INNER JOIN Employees ON EmpTimes.EmpID=Employees.EmpID
WHERE Employees.Designation<>'Security Guard' AND  MONTH(DT)=MONTH(@ParDate) AND YEAR(DT)=YEAR(@ParDate) AND EmpTimes.DT<=@ParDate
	AND (DateName(WeekDay,DT)='Sunday'	OR DT IN(SELECT DT FROM Holidays)) GROUP BY EmpTimes.EmpID,EmpTimes.DT

/*UPDATE @TempTable_Working SET LateHrs=T1.LateHrs FROM @TempTable_Working T2
	LEFT JOIN @TempTable_Late T1 ON T2.EmpID=T1.EmpID AND T2.DT=T1.DT*/

INSERT INTO @TempTable_Working(EmpID,DT,OTHrs,LateHrs)
	SELECT EmpID,DT,SUM(OTHrs),SUM(LateHrs) FROM (
	SELECT EmpID,DT,OTHrs,0 AS LateHrs FROM @TempTable_OT
	UNION
	SELECT EmpID,DT,0,LateHrs FROM @TempTable_Late) T1 GROUP BY EmpID,DT

UPDATE @TempTable_Working SET LateHrs=CASE WHEN OTHrs>T1.LateHrs THEN 0 ELSE T1.LateHrs-OTHrs END FROM @TempTable_Working T2
	LEFT JOIN @TempTable_Late T1 ON T2.EmpID=T1.EmpID AND T2.DT=T1.DT

RETURN
END
GO
