DECLARE Abc CURSOR FOR SELECT IssQty FROM VVendIssdDetail_Simple WITH (NOLOCK) INNER JOIN
	(SELECT MIN(EntryID) AS MINEntryID FROM dbo.VVendIssdDetail_Simple WITH (NOLOCK) WHERE OrderNo=@OrderNo AND ItemCode=@ItemCode AND ProcessID IN(172,212) GROUP BY OrderNo,ItemCode,ProcessID) T1 ON VVendIssdDetail_Simple.EntryID=T1.MINEntryID

OPEN Abc

FETCH NEXT FROM Abc INTO @Qty
WHILE @@Fetch_Status=0
	BEGIN
		SET @ReturnString=@ReturnString + @Qty + CHAR(13) + CHAR(10)
		FETCH NEXT FROM Abc INTO @Qty
	END
	IF LEN(@ReturnString)>0
		SET @ReturnString = LEFT(@ReturnString,Len(@ReturnString)-2)
CLOSE Abc
DEALLOCATE Abc

RETURN @ReturnString

End























