/****** Object:  UserDefinedFunction [dbo].[ProcessesForProductionOrder_F]    Script Date: 6/29/2026 4:49:59 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO



CREATE FUNCTION [dbo].[ProcessesForProductionOrder_F] (@OrderNo AS VARCHAR(50),@ItemCode AS VARCHAR(50))
RETURNS Varchar(1000) AS

BEGIN
DECLARE @ReturnString As Varchar(1000)
SET @ReturnString=''
DECLARE @ProcessName AS VARCHAR(255),@RcvdQty As INT,@DT AS DATETIME
DECLARE Abc CURSOR FOR SELECT DT,Description,RcvdQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0) AS RcvdQty FROM VendRcvdDetail WITH (NOLOCK) INNER JOIN VendReceived WITH (NOLOCK) ON VendReceived.EntryID=VendRcvdDetail.RefID INNER JOIN Processes ON VendReceived.ProcessID=Processes.ProcessID
	INNER JOIN (SELECT MAX(EntryID) AS MAXEntryID FROM VendRcvdDetail WITH (NOLOCK) GROUP BY LotNo) T1 ON VendRcvdDetail.EntryID=T1.MAXEntryID
	WHERE OrderNo=@OrderNo AND ItemCode=@ItemCode ORDER BY LotNo
OPEN Abc

FETCH NEXT FROM Abc INTO @DT,@ProcessName,@RcvdQty
WHILE @@Fetch_Status=0
	BEGIN
		SET @ReturnString=@ReturnString + @ProcessName + ' (' + CONVERT(VARCHAR(50),@DT,5) + ') ('  + CAST(@RcvdQty AS VARCHAR(10)) + ')' + CHAR(13)
		FETCH NEXT FROM Abc INTO @DT,@ProcessName,@RcvdQty
	END
	IF LEN(@ReturnString)>0
		SET @ReturnString = LEFT(@ReturnString,Len(@ReturnString)-1)
CLOSE Abc
DEALLOCATE Abc

RETURN @ReturnString

End
























