/****** Object:  UserDefinedFunction [dbo].[RepairLot_OriginalLots_F]    Script Date: 6/29/2026 4:49:59 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE FUNCTION [dbo].[RepairLot_OriginalLots_F] (@ForLotNo AS VARCHAR(50))
RETURNS VARCHAR(4000) AS

BEGIN
DECLARE @ReturnString As Varchar(4000)
SET @ReturnString=''
DECLARE @LotNo AS VARCHAR(255),@Qty AS INT
DECLARE @PolishingMaker AS VARCHAR(255),@OriginatorMaker AS VARCHAR(255)
DECLARE Abc CURSOR FOR SELECT VendRcvdDetail.LotNo,VendReWorkIssuanceDetail.Qty,
	VLotWithFirstProcessOfIssuance.VenderName AS OriginatorMaker,VLotWithPolishingMaker.VenderName AS PolishingMaker FROM VendReWorkIssuanceDetail
	INNER JOIN VendRcvdDetailReWorkDetail ON VendReWorkIssuanceDetail.VRDRWD_RefID=VendRcvdDetailReWorkDetail.EntryID
	INNER JOIN VendRcvdDetail ON VendRcvdDetailReWorkDetail.VRD_RefID=VendRcvdDetail.EntryID
	INNER JOIN VendIssdDetail ON VendReWorkIssuanceDetail.VID_RefID=VendIssdDetail.EntryID
	LEFT OUTER JOIN VLotWithFirstProcessOfIssuance ON VendRcvdDetail.LotNo=VLotWithFirstProcessOfIssuance.LotNo
	LEFT OUTER JOIN VLotWithPolishingMaker ON VendRcvdDetail.LotNo=VLotWithPolishingMaker.LotNo
	WHERE VendIssdDetail.LotNo=@ForLotNo

OPEN Abc

FETCH NEXT FROM Abc INTO @LotNo,@Qty,@OriginatorMaker,@PolishingMaker
WHILE @@Fetch_Status=0
	BEGIN
		SET @ReturnString=@ReturnString + @LotNo + ' (' + CAST(@Qty AS VARCHAR(50)) + ')' +  ' Originator=' + ISNULL(@OriginatorMaker,'') + ' Polisher=' + ISNULL(@PolishingMaker,'') + CHAR(13) + CHAR(10)
		FETCH NEXT FROM Abc INTO @LotNo,@Qty,@OriginatorMaker,@PolishingMaker
	END
	IF LEN(@ReturnString)>0
		SET @ReturnString = LEFT(@ReturnString,Len(@ReturnString)-2)
CLOSE Abc
DEALLOCATE Abc

RETURN @ReturnString

END


























