CREATE FUNCTION [dbo].[VendReceived_Employees_F] (@EntryID INT)
RETURNS VARCHAR(1000) AS

BEGIN
DECLARE @ReturnStr AS VARCHAR(1000)
SET @ReturnStr=''
DECLARE @Temp AS VARCHAR(255)
DECLARE Abc CURSOR FOR SELECT Name FROM VendReceived INNER JOIN VendReceived_Employees ON VendReceived.EntryID=VendReceived_Employees.VR_RefID INNER JOIN Employees ON VendReceived_Employees.EmpID=Employees.EmpID WHERE VendReceived.EntryID=@EntryID
OPEN Abc

FETCH NEXT FROM Abc into @Temp
WHILE @@Fetch_Status=0
	BEGIN
		SET @ReturnStr=@ReturnStr + @Temp + ','
		FETCH NEXT FROM Abc Into @Temp
	END
	IF LEN(@ReturnStr)>0
		SET @ReturnStr = LEFT(@ReturnStr,LEN(@ReturnStr)-1)
CLOSE Abc
DEALLOCATE Abc

RETURN @ReturnStr

END







