/****** Object:  View [dbo].[VCustomInvoiceAmt]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO



CREATE VIEW [dbo].[VCustomInvoiceAmt]
AS
SELECT     Tab1.CustomInvoice, Tab1.TotalAmt + ISNULL(Tab2.OtherChargesAmt, 0) AS TotalAmt, Tab1.TotalCustomAmt+ISNULL(Tab2.OtherChargesAmtCustom,0) AS TotalCustomAmt,TotalQty
FROM         (SELECT     dbo.CustomInvoice.CustomInvoice, SUM(dbo.CustomInvoiceItems.Qty * dbo.CustomInvoiceItems.Price) AS TotalAmt,
                                              SUM(dbo.CustomInvoiceItems.Qty *  (dbo.CustomInvoiceItems.CustomPrice)) AS TotalCustomAmt,SUM(Qty) AS TotalQty
                       FROM          dbo.CustomInvoice INNER JOIN
                                              dbo.CustomInvoiceItems ON dbo.CustomInvoice.CustomInvoice = dbo.CustomInvoiceItems.CustomInvoice
                       GROUP BY dbo.CustomInvoice.CustomInvoice) Tab1 LEFT OUTER JOIN
                          (SELECT     CustomInvoice, SUM(ChargesAmt) AS OtherChargesAmt,SUM(ChargesAmt) AS OtherChargesAmtCustom
                            FROM          CustomInvoiceOtherCharges
                            GROUP BY CustomInvoice) Tab2 ON Tab1.CustomInvoice = Tab2.CustomInvoice
GO
