SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE VIEW [dbo].[VCustomInvoiceList]
AS
SELECT        dbo.ForeignCustomers.Curr, dbo.CustomInvoice.CustomInvoice, dbo.CustomInvoice.DT, dbo.ForeignCustomers.CustCode, dbo.ForeignCustomers.Country,
                         dbo.VCustomInvoiceAmt.TotalAmt, ISNULL(PackingTable.PackingCount, 0) AS PackingInfo, dbo.CustomInvoice.ShippingMode,
                         dbo.VCustomInvoiceAmt.TotalCustomAmt, dbo.CustomInvoice.GatePassDT, dbo.CustomInvoice.DTMaturity, dbo.CustomInvoice.SampleInvoice
						 ,dbo.F_CustomInvoiceOrders(CustomInvoice.CustomInvoice) AS InvoiceOrders
						 ,dbo.F_CustomInvoiceInternalOrders(CustomInvoice.CustomInvoice) AS InvoiceInternalOrders
						 ,dbo.Invoice_DispatchListNos_Fn(CustomInvoice.CustomInvoice) AS DispatchListNos
FROM            dbo.ForeignCustomers INNER JOIN
                         dbo.CustomInvoice ON dbo.ForeignCustomers.CustCode = dbo.CustomInvoice.CustCode AND
                         dbo.ForeignCustomers.Country = dbo.CustomInvoice.Country INNER JOIN
                         dbo.VCustomInvoiceAmt ON dbo.CustomInvoice.CustomInvoice = dbo.VCustomInvoiceAmt.CustomInvoice LEFT OUTER JOIN
                             (SELECT        CustomInvoice, COUNT(*) AS PackingCount
                                FROM            dbo.CustomPList
                                GROUP BY CustomInvoice) AS PackingTable ON dbo.CustomInvoice.CustomInvoice = PackingTable.CustomInvoice




GO
