CREATE VIEW [dbo].[VCustomInvoice]
AS
SELECT        dbo.CustomInvoice.CustomInvoice, dbo.CustomInvoice.DT, dbo.CustomInvoice.CustCode, dbo.CustomInvoice.Country, dbo.CustomInvoice.ShippingMode, dbo.CustomInvoice.AWBNo, dbo.CustomInvoice.AWBNoDT,
                         dbo.CustomInvoice.FormE, dbo.CustomInvoice.FormEDT, dbo.CustomInvoice.TradeTerms, dbo.CustomInvoice.GrossWeight, dbo.CustomInvoice.PaymentTerms, dbo.CustomInvoice.LCNo, dbo.CustomInvoice.LCDate,
                         dbo.CustomInvoice.TransShipment, dbo.CustomInvoice.PartialShipment, dbo.CustomInvoice.Packaging, dbo.CustomInvoice.ShippingAgentID, dbo.CustomInvoice.InsuranceAgentID, dbo.CustomInvoice.LoadPortID,
                         dbo.CustomInvoice.DisPortID, dbo.CustomInvoice.OurBankID, dbo.CustomInvoice.DeclarationsBalls, dbo.CustomInvoice.DeclarationsGarments, dbo.CustomInvoice.DeclarationsGloves, dbo.CustomInvoice.Consignee,
                         dbo.CustomInvoice.ComInvDT, dbo.CustomInvoice.Vessel, dbo.CustomInvoice.ComDeclarationsBalls, dbo.CustomInvoice.ComDeclarationsGarments, dbo.CustomInvoice.ComDeclarationsGloves, dbo.CustomInvoice.ComNotify,
                         dbo.CustomInvoice.ComConsignee, dbo.CustomInvoice.ComPayTerms, dbo.CustomInvoice.ComAgainst, dbo.CustomInvoice.ComDrawnUnder, dbo.CustomInvoice.ComSpecial, dbo.CustomInvoice.ManDischarge,
                         dbo.CustomInvoice.ManDeclaration, dbo.CustomInvoice.ContainerNo, dbo.CustomInvoice.Warehouse, dbo.CustomInvoice.Gate, dbo.CustomInvoice.DTETA, dbo.CustomInvoice.SRONo, dbo.CustomInvoice.CustCurrency,
                         dbo.CustomInvoice.InvoiceFeedingDT, dbo.CustomInvoice.CompanyRefID, dbo.CustomInvoice.SealNo, dbo.CustomInvoice.InvoiceOf, dbo.CustomInvoice.GatePassNo, dbo.CustomInvoice.GatePassDT,
                         dbo.CustomInvoice.DTREDescription, dbo.CustomInvoice.DTMaturity, dbo.CustomInvoice.NoSRO, dbo.CustomInvoice.CIFTradeTerms, dbo.ForeignCustomers.Name, dbo.ForeignCustomers.Address,
                         VPorts_2.CountryName AS LoadCountry, VPorts_2.CityID AS LoadCityID, VPorts_2.City AS LoadCity, VPorts_2.Port AS LoadPort, VPorts_1.CountryName AS DisCountry, VPorts_1.CityID AS DisCityID, VPorts_1.City AS DisCity,
                         VPorts_1.Port AS DisPort, dbo.CustomInvoiceItems.EntryID, dbo.CustomInvoiceItems.RefID, dbo.CustomInvoiceItems.Qty, dbo.CustomInvoiceItems.Price, dbo.CustomInvoiceItems.CustomPrice, dbo.BankList.Bank,
                         dbo.InsuranceAgents.Name AS InsuranceAgentsName, dbo.ShippingAgents.Name AS ShippingAgentsName, dbo.FProformaOrders.PInvoice, dbo.FOrderItems.OrderNo, dbo.FOrderItems.ItemCode, dbo.Items.ItemName,
                         dbo.Items.Unit, dbo.FProformaOrders.InvQty, dbo.ForeignCustomers.Curr, dbo.ForeignCustomers.Cont1name, dbo.ForeignCustomers.cont1phone, dbo.Items.ItemSize, dbo.FCustomerCatalog.ItemID AS CustItemID,
                         dbo.CustomInvoiceItems.RebateRate, dbo.FCustomerOrders.DeliveryDT, dbo.BankList.Address AS BankAddress, dbo.FProformaOrders.OrderEntryID, dbo.Items.CustomDescription AS ItemCustomName,
                         dbo.Companies.CompanyName, dbo.FOrderItems.CompItemCode, dbo.CustomInvoiceItems.DTRENo, dbo.Companies.ExportRegNo AS ExportNo, dbo.FOrderItems.DeliveryDT AS DeliveryDTItem,
                         dbo.FCustomerOrders.DT AS OrderDT, dbo.VTotalCartons.TotalCartons, dbo.CustomInvoice.SampleInvoice, dbo.CustomInvoice.FreeSamples, dbo.CustomInvoice.InvoiceDescription, dbo.CustomInvoice.CustomDT,
                         dbo.FCustomerOrders.InternalRefNo, dbo.Items.GroupID, dbo.CustomInvoice.GDNo, dbo.CustomInvoice.InvoiceTo
FROM            dbo.FCustomerCatalog INNER JOIN
                         dbo.CustomInvoice INNER JOIN
                         dbo.CustomInvoiceItems ON dbo.CustomInvoice.CustomInvoice = dbo.CustomInvoiceItems.CustomInvoice INNER JOIN
                         dbo.ForeignCustomers ON dbo.CustomInvoice.CustCode = dbo.ForeignCustomers.CustCode AND dbo.CustomInvoice.Country = dbo.ForeignCustomers.Country INNER JOIN
                         dbo.FProformaOrders ON dbo.CustomInvoiceItems.RefID = dbo.FProformaOrders.EntryID INNER JOIN
                         dbo.FOrderItems ON dbo.FProformaOrders.OrderEntryID = dbo.FOrderItems.ID ON dbo.FCustomerCatalog.CustCode = dbo.ForeignCustomers.CustCode AND dbo.FCustomerCatalog.Country = dbo.ForeignCustomers.Country AND
                         dbo.FCustomerCatalog.CompItemID = dbo.FOrderItems.CompItemCode INNER JOIN
                         dbo.FCustomerOrders ON dbo.ForeignCustomers.CustCode = dbo.FCustomerOrders.CustCode AND dbo.ForeignCustomers.Country = dbo.FCustomerOrders.Country AND
                         dbo.FOrderItems.OrderNo = dbo.FCustomerOrders.OrderNo INNER JOIN
                         dbo.ItemCatagories INNER JOIN
                         dbo.Items ON dbo.ItemCatagories.CatID = dbo.Items.CatID ON dbo.FOrderItems.CompItemCode = dbo.Items.ItemID INNER JOIN
                         dbo.Companies ON dbo.CustomInvoice.CompanyRefID = dbo.Companies.EntryID LEFT OUTER JOIN
                         dbo.VTotalCartons ON dbo.CustomInvoice.CustomInvoice = dbo.VTotalCartons.CustomInvoice LEFT OUTER JOIN
                         dbo.ShippingAgents ON dbo.CustomInvoice.ShippingAgentID = dbo.ShippingAgents.EntryID LEFT OUTER JOIN
                         dbo.InsuranceAgents ON dbo.CustomInvoice.InsuranceAgentID = dbo.InsuranceAgents.EntryID LEFT OUTER JOIN
                         dbo.BankList ON dbo.CustomInvoice.OurBankID = dbo.BankList.BankID LEFT OUTER JOIN
                         dbo.VPorts AS VPorts_2 ON dbo.CustomInvoice.LoadPortID = VPorts_2.PortID LEFT OUTER JOIN
                         dbo.VPorts AS VPorts_1 ON dbo.CustomInvoice.DisPortID = VPorts_1.PortID
GO
