CREATE VIEW [dbo].[VEE]
AS
SELECT        dbo.CustomInvoice.FormE, dbo.CustomInvoice.CustCode, dbo.CustomInvoice.Country, dbo.FCustPayments.CustomInvoice, dbo.CustomInvoice.DT,
                         dbo.ForeignCustomers.Curr, dbo.FCustPayments.AmountEE * dbo.FCustPayments.ExchRate AS PAmount, dbo.FCustPayments.AmountEE AS FAmount,
                         dbo.FCustPayments.DT AS RealisationDate, dbo.FCustPayments.AmountEE AS TotalCommercialAmt, dbo.FCustPayments.FDBCNo, dbo.CustomInvoice.OurBankID,
                         dbo.FCustPayments.BankID, dbo.CustomInvoice.CompanyRefID, dbo.CustomInvoice.InvoiceOf, dbo.Companies.CompanyName, dbo.FCustPayments.Description,
                         dbo.FCustPayments.ExchRate, dbo.CustomInvoice.AWBNoDT, dbo.VCustomInvoiceOrderForEE.OrderNo, dbo.VCustomInvoiceOrderForEE.OrderDT,
                         dbo.Companies.ExportRegNo, dbo.Companies.NTNNo, dbo.FCustPayments.EntryID, dbo.FCustPayments.BankNoForEE, dbo.FCustPayments.PageNoForEE,
                         dbo.FCustPayments.ItemNoForEE, dbo.FCustPayments.AmountEE, dbo.FCustPayments.AmtRcvd, dbo.FCustPayments.HideEntry
FROM            dbo.FCustPayments INNER JOIN
                         dbo.CustomInvoice ON dbo.FCustPayments.CustomInvoice = dbo.CustomInvoice.CustomInvoice INNER JOIN
                         dbo.ForeignCustomers ON dbo.CustomInvoice.CustCode = dbo.ForeignCustomers.CustCode AND
                         dbo.CustomInvoice.Country = dbo.ForeignCustomers.Country INNER JOIN
                         dbo.VCustomInvoiceAmt ON dbo.CustomInvoice.CustomInvoice = dbo.VCustomInvoiceAmt.CustomInvoice INNER JOIN
                         dbo.Companies ON dbo.CustomInvoice.CompanyRefID = dbo.Companies.EntryID INNER JOIN
                         dbo.VCustomInvoiceOrderForEE ON dbo.CustomInvoice.CustomInvoice = dbo.VCustomInvoiceOrderForEE.CustomInvoice
WHERE        (dbo.FCustPayments.CustomPayment = 1)

GO
/****** Object:  UserDefinedFunction [dbo].[F_EmpMinSalary]    Script Date: 6/29/2026 4:50:00 PM ******/
