GO


CREATE FUNCTION  [dbo].[F_EmpMinSalary] ()
RETURNS Table  AS
Return(

	SELECT EmpID,MinimumSalary,Case When StartingSalary<MinimumSalary Then MinimumSalary Else StartingSalary END As EmpMinSalary FROM  Employees CROSS JOIN PayrollSettings
)

GO
