CREATE VIEW [dbo].[VEmp]
AS
SELECT        dbo.Departments.deptid, dbo.Departments.name AS DeptName, dbo.Employees.empid, dbo.Employees.name, dbo.Employees.fname, dbo.Employees.dob, dbo.Employees.Religion, dbo.Employees.Age, dbo.Employees.sex,
                         dbo.Employees.Address, dbo.Employees.NIC, dbo.Employees.NTN, dbo.Employees.Phone1, dbo.Employees.Phone2, dbo.EmpSettings.AbsAllowed, dbo.EmpSettings.TimeAllowed, dbo.EmpSettings.NTimes,
                         dbo.EmpSettings.OverTime, dbo.Employees.StartingSalary, dbo.Employees.Salary, dbo.Employees.PProfit, dbo.Employees.Active, dbo.Employees.EmpType, dbo.Employees.DiscontinuedOn, dbo.Employees.JoinDate,
                         dbo.Employees.Bonus, dbo.Employees.Designation, dbo.Employees.Rel, dbo.Employees.Status, dbo.Employees.Transport, dbo.EmpSettings.EnterTime, dbo.EmpSettings.ExitTime, dbo.EmpSettings.BGHoliday,
                         dbo.EmpSettings.AGHoliday, dbo.EmpSettings.BPHoliday, dbo.EmpSettings.APHoliday, REPLACE(dbo.EmpSettings.EmpID, dbo.Departments.deptid + '-', dbo.Departments.Dept_ID + '-') AS Emp_ID, dbo.EmpSettings.LunchTime,
                         dbo.Employees.EmergencyName, dbo.Employees.EmergencyFName, dbo.Employees.EmergencyPhone1, dbo.Employees.EmergencyPhone2, dbo.Employees.EmergencyAddress, dbo.Employees.BloodGroup,
                         dbo.Employees.OTByQty, dbo.Employees.MinQty, dbo.Employees.UnionFund, dbo.Employees.Lunch, dbo.Employees.social, dbo.Employees.oldage, dbo.Employees.SocialNo, dbo.Employees.OldAgeNo,
                         dbo.Employees.InsurableDT, dbo.Employees.ArmyRetired, dbo.Employees.EmpAccNo, dbo.Employees.BankPymt, dbo.Departments.TempDept, dbo.Employees.EmployeeID, dbo.Employees.EmpPic,
                         dbo.Employees.PerPieceRate, dbo.Employees.Rate, F_EmpMinSalary.EmpMinSalary, dbo.Employees.EmpIDOld, dbo.Employees.ProbationPeriod, dbo.EmpSettings.EmpAttCat_RefID, dbo.Employees.ExemptSettings,
                         dbo.Employees.TempEmp, dbo.Employees.intGuarantorId, dbo.Employees.FixAllowance
FROM            dbo.EmpSettings RIGHT OUTER JOIN
                         dbo.Employees LEFT OUTER JOIN
                         dbo.F_EmpMinSalary() AS F_EmpMinSalary ON dbo.Employees.empid = F_EmpMinSalary.EmpID ON dbo.EmpSettings.EmpID = dbo.Employees.empid RIGHT OUTER JOIN
                         dbo.Departments ON dbo.Employees.deptid = dbo.Departments.deptid
