CREATE VIEW [dbo].[VItemInitialProcess]
AS
SELECT     dbo.VItemProcesses.*
FROM         dbo.VItemProcesses INNER JOIN
                          (SELECT     Tab1.ItemID, ProcessID
                             FROM         (SELECT     ItemID, MIN(SNo) MinSNo
                                                     FROM         ItemProcesses
                                                     GROUP BY ItemID) Tab1 INNER JOIN
                                                       (SELECT     ItemID, SNo, ProcessID
                                                          FROM         ItemProcesses) Tab2 ON Tab1.ItemID = Tab2.ItemID AND Tab1.MinSNo = Tab2.SNo) TabInner ON
                      dbo.VItemProcesses.IsExist = TabInner.ItemID AND dbo.VItemProcesses.ProcessID = TabInner.ProcessID
GO
