CREATE VIEW [dbo].[VFCustOrders]
AS
SELECT     dbo.FCustomerOrders.OrderNo, dbo.FCustomerOrders.TradeTerms, dbo.FCustomerOrders.PartialShipment, dbo.FCustomerOrders.PaymentTerms,
                      dbo.FCustomerOrders.CustCode, dbo.FCustomerOrders.Country, dbo.FCustomerOrders.TransShipment, dbo.FCustomerOrders.Packaging,
                      dbo.FCustomerOrders.DeliveryDT, dbo.FOrderItems.ItemCode, dbo.FCustomerCatalog.Unit, dbo.FCustomerCatalog.Description, dbo.FOrderItems.Price,
                      dbo.FOrderItems.Qty, dbo.FOrderItems.CompItemCode, dbo.FOrderItems.Qty - ISNULL(TProforma.ProformaUsedQty, 0) AS InvQty, dbo.FOrderItems.ID AS OrderItemID,
                      dbo.ForeignCustomers.AccNo, dbo.FCustomerOrders.DT, dbo.FOrderItems.CustomPrice, dbo.FCustomerOrders.InternalRefNo,
                      dbo.FOrderItems.DeliveryDT AS DeliveryDTItem, dbo.FOrderItems.Stamps AS StampsItem, dbo.FOrderItems.Quality AS QualityItem
FROM         dbo.FCustomerOrders INNER JOIN
                      dbo.FOrderItems ON dbo.FCustomerOrders.OrderNo = dbo.FOrderItems.OrderNo INNER JOIN
                      dbo.FCustomerCatalog ON dbo.FCustomerOrders.CustCode = dbo.FCustomerCatalog.CustCode AND
                      dbo.FCustomerOrders.Country = dbo.FCustomerCatalog.Country AND dbo.FOrderItems.CompItemCode = dbo.FCustomerCatalog.CompItemID INNER JOIN
                      dbo.ForeignCustomers ON dbo.FCustomerOrders.CustCode = dbo.ForeignCustomers.CustCode AND
                      dbo.FCustomerOrders.Country = dbo.ForeignCustomers.Country LEFT OUTER JOIN
                          (SELECT     OrderEntryID, SUM(Qty) AS ProformaUsedQty
                             FROM         FProformaOrders
                             GROUP BY OrderEntryID) TProforma ON dbo.FOrderItems.ID = TProforma.OrderEntryID

