CREATE VIEW [dbo].[VStockOrderOpening]
AS
SELECT dbo.StockOrderOpening.EntryID, dbo.StockOrderOpening.ItemID, dbo.StockOrderOpening.ProcessID, dbo.StockOrderOpening.Qty, dbo.StockOrderOpening.Location, dbo.StockOrderOpening.UserName, dbo.StockOrderOpening.MachineName, dbo.StockOrderOpening.DTEntry, dbo.Items.ItemName, dbo.Items.Unit, dbo.Items.Type, dbo.Items.ItemSize, dbo.Items.SizeUnit,
         dbo.Processes.Description, dbo.StockOrderOpening.Remarks, dbo.VStoreShelfs.ShelfNo, dbo.VStoreShelfs.RackNo, dbo.VStoreShelfs.StoreName, dbo.VStoreShelfs.Store_RefID, dbo.StockOrderOpening.Shelf_RefID, ISNULL(TSOO.QtyIssd_SOO, 0) AS IssdQty, ISNULL(TTransfer.SplitQty, 0) AS SplityQty, dbo.StockOrderOpening.LotNo_Manual,
         dbo.StockOrderOpening.BatchNo_Manual, ISNULL(TSOO.QtyIssd_SOO, 0) AS QtyIssd_SOO, dbo.StockOrderOpening.Mill_Certificate_No, dbo.VStoreShelfs.R1
FROM  dbo.StockOrderOpening INNER JOIN
         dbo.Items ON dbo.StockOrderOpening.ItemID = dbo.Items.ItemID INNER JOIN
         dbo.Processes ON dbo.StockOrderOpening.ProcessID = dbo.Processes.ProcessID INNER JOIN
         dbo.VStoreShelfs ON dbo.StockOrderOpening.Shelf_RefID = dbo.VStoreShelfs.EntryID LEFT OUTER JOIN
             (SELECT Opening_RefID, SUM(IssQty) AS IssdQty
            FROM  dbo.vendRcvdDetail
            GROUP BY Opening_RefID) AS T1 ON dbo.StockOrderOpening.EntryID = T1.Opening_RefID LEFT OUTER JOIN
             (SELECT SOO_RefID, SUM(SplitQty) AS SplitQty
            FROM  dbo.LotTransferDetails
            WHERE (Type = 2) AND (Qty = SplitQty) AND (SOO_RefID IS NOT NULL)
            GROUP BY SOO_RefID) AS TTransfer ON dbo.StockOrderOpening.EntryID = TTransfer.SOO_RefID LEFT OUTER JOIN
             (SELECT SOO_RefID, SUM(QtyIssd) AS QtyIssd_SOO
            FROM  dbo.StockOrderOpening_Issuance
            GROUP BY SOO_RefID) AS TSOO ON dbo.StockOrderOpening.EntryID = TSOO.SOO_RefID
GO
/****** Object:  View [dbo].[VItemSFStock]    Script Date: 6/29/2026 4:50:00 PM ******/
