GO

CREATE VIEW [dbo].[VItemSFStock]
AS
SELECT dbo.VStockOrderOpening.ItemID, SUM(dbo.VStockOrderOpening.Qty - dbo.VStockOrderOpening.IssdQty) AS Qty, dbo.VStockOrderOpening.StoreName, dbo.VStockOrderOpening.ShelfNo, dbo.VStockOrderOpening.RackNo, dbo.VStockOrderOpening.Shelf_RefID, dbo.VStockOrderOpening.Store_RefID
FROM  dbo.VStockOrderOpening LEFT OUTER JOIN
             (SELECT Opening_RefID
            FROM  dbo.vendRcvdDetail
            GROUP BY Opening_RefID) AS T1 ON T1.Opening_RefID = dbo.VStockOrderOpening.EntryID
WHERE (dbo.VStockOrderOpening.Qty > dbo.VStockOrderOpening.IssdQty)
GROUP BY dbo.VStockOrderOpening.ItemID, dbo.VStockOrderOpening.StoreName, dbo.VStockOrderOpening.ShelfNo, dbo.VStockOrderOpening.RackNo, dbo.VStockOrderOpening.Shelf_RefID, dbo.VStockOrderOpening.Store_RefID
GO
