GO
SET QUOTED_IDENTIFIER ON
GO


CREATE VIEW [dbo].[VItemWithStocks]
AS
SELECT     dbo.Items.ItemID, TFinished.TotalFinishedStock, TSFStock.TotalSFStock
FROM         dbo.Items LEFT OUTER JOIN
                          (SELECT     ItemID, SUM(NetQty) AS TotalFinishedStock
                            FROM          dbo.VItemsWithShelfWiseStock WHERE NetQty>0
                            GROUP BY ItemID) AS TFinished ON dbo.Items.ItemID = TFinished.ItemID LEFT OUTER JOIN
                          (SELECT     ItemID, SUM(Qty) AS TotalSFStock
                            FROM          dbo.VItemSFStock
                            GROUP BY ItemID) AS TSFStock ON dbo.Items.ItemID = TSFStock.ItemID

GO
