CREATE VIEW [dbo].[VMaterialLocationWiseBalances]
AS
SELECT     dbo.VStoreShelfs.Store_RefID, dbo.VStoreShelfs.StoreName, dbo.VStoreShelfs.RackNo, dbo.VStoreShelfs.Rack_RefID, dbo.VStoreShelfs.ShelfNo, TabMat.Shelf_RefID, TabMat.ShelfQty, TabMat.MaterialID, dbo.RM.RMID, TabMat.SheetsQty, dbo.RM.RMName,
                  dbo.RM.Unit, dbo.RM.RMID1, dbo.RM.RMSize, dbo.RM.SizeUnit, dbo.RM.QtyInStock, dbo.RM.Pic, dbo.RM.RM_Maker_Description
FROM        dbo.VStoreShelfs INNER JOIN
                      (SELECT     Shelf_RefID, MaterialID, ROUND(SUM(QtyPlaced - QtyIssued), 2) AS ShelfQty, SUM(SheetsPlaced - ISNULL(SheetsIssued, 0)) AS SheetsQty
                       FROM        dbo.VMaterialLocationWiseStatus
                       WHERE     (QtyPlaced - QtyIssued > 0)
                       GROUP BY Shelf_RefID, MaterialID) AS TabMat ON dbo.VStoreShelfs.EntryID = TabMat.Shelf_RefID INNER JOIN
                  dbo.RM ON TabMat.MaterialID = dbo.RM.RMID1
GO
/****** Object:  View [dbo].[VCustomInvoiceAmtRcvd]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
