CREATE VIEW [dbo].[VCustomInvoiceAmtRcvd]
AS
SELECT        CustomInvoice, SUM(TotalAmtRcvd) AS TotalAmtRcvd, SUM(CASE WHEN EntryType IN (1, 0) THEN TotalAmtRcvd ELSE 0 END) AS TotalCustomAmtRcvd,
                         SUM(CASE WHEN EntryType = 1 THEN TotalAmtRcvd ELSE 0 END) AS TotalDebitAmount, SUM(TotalAmtRcvd) AS TotalCommercialAmtRcvd
FROM            (SELECT        CustomInvoice, SUM(AmtRcvd) AS TotalAmtRcvd, 0 AS EntryType
                           FROM            dbo.FCustPayments
                           GROUP BY CustomInvoice
                           UNION
                           SELECT        CustomInvoice, SUM(Amount) AS TotalAmtRcvd, 1 AS EntryType
                           FROM            dbo.FCustAdvancePaymentsAdjusted
                           GROUP BY CustomInvoice) AS TblDervd
GROUP BY CustomInvoice

GO
