CREATE VIEW [dbo].[VItemSFStock_WIthProcessName]
AS
SELECT        dbo.VStockOrderOpening.ItemID, SUM(dbo.VStockOrderOpening.Qty - dbo.VStockOrderOpening.IssdQty) AS Qty, dbo.VStockOrderOpening.StoreName, dbo.VStockOrderOpening.ShelfNo, dbo.VStockOrderOpening.RackNo,
                         dbo.VStockOrderOpening.Shelf_RefID, dbo.VStockOrderOpening.Store_RefID, dbo.VStockOrderOpening.Description
