CREATE VIEW [dbo].[VMakerBalances]
AS
SELECT     dbo.VMakers.VendID, dbo.VMakers.VendID1, dbo.VMakers.VenderName, dbo.VMakers.Active, ISNULL(T1.Balance, 0) AS Balance, ISNULL(dbo.VMakers.MakerCapacity,
                      0) AS MakerCapacity
FROM         dbo.VMakers LEFT OUTER JOIN
                          (SELECT     dbo.VendIssued.VendID, SUM(dbo.VendIssdDetail.IssQty - dbo.VendIssdDetail.RcvdQty) AS Balance
                            FROM          dbo.VendIssued INNER JOIN
                                                   dbo.VendIssdDetail ON dbo.VendIssued.EntryID = dbo.VendIssdDetail.RefID
                            WHERE      (dbo.VendIssued.MasterPONo IS NOT NULL) AND (dbo.VendIssdDetail.IssQty > dbo.VendIssdDetail.RcvdQty) AND (dbo.VendIssued.Closed = 0)
                            GROUP BY dbo.VendIssued.VendID) AS T1 ON dbo.VMakers.VendID = T1.VendID

