CREATE VIEW [dbo].[VEmpDailyEntries]
AS
SELECT     EmpID, DT, MIN(EntryID) AS FirstEntryID, SUM(entryID) - (CASE WHEN COUNT(EntryID) = 3 THEN MAX(EntryID) ELSE 0 END) - MIN(EntryID)
                      AS SecondEntryID, CASE WHEN COUNT(EntryID) = 3 THEN MAX(EntryID) ELSE NULL END AS OverTimeEntryID, COUNT(EntryID) AS TotalEntries
FROM         dbo.EmpTimes
GROUP BY EmpID, DT



