CREATE VIEW [dbo].[VFOrderItemswithShippedQty]
AS
SELECT        ISNULL(Shipped.TotalShipped, 0) AS ShippedQty, dbo.FOrderItems.ID, dbo.FOrderItems.OrderNo, dbo.FOrderItems.ItemCode, dbo.FOrderItems.CompItemCode, dbo.FOrderItems.Price, dbo.FOrderItems.CustomPrice,
                         dbo.FOrderItems.InvQty, dbo.FOrderItems.Qty, Shipped.LastShipmentDate, dbo.F_OrderProformas(dbo.FOrderItems.OrderNo, dbo.FOrderItems.CompItemCode) AS Proformas, dbo.FCustomerOrders.CustCode,
                         dbo.FOrderItems.DeliveryDT, dbo.FOrderItems.DeliveryStatus, dbo.FCustomerOrders.DT, dbo.FOrderItems.Remarks, dbo.FCustomerOrders.InternalRefNo, dbo.FCustomerOrders.DeliveryDT AS OrderDeliveryDT,
                         dbo.VCurrencyExchangeRates.ExchRate, dbo.Items.PriceForCost
FROM            dbo.FCustomerOrders INNER JOIN
                         dbo.FOrderItems ON dbo.FCustomerOrders.OrderNo = dbo.FOrderItems.OrderNo INNER JOIN
                         dbo.ForeignCustomers ON dbo.FCustomerOrders.CustCode = dbo.ForeignCustomers.CustCode AND dbo.FCustomerOrders.Country = dbo.ForeignCustomers.Country INNER JOIN
                         dbo.Items ON dbo.FOrderItems.CompItemCode = dbo.Items.ItemID LEFT OUTER JOIN
                         dbo.VCurrencyExchangeRates ON dbo.ForeignCustomers.Curr = dbo.VCurrencyExchangeRates.Currency LEFT OUTER JOIN
                             (SELECT        dbo.FProformaOrders.OrderEntryID, SUM(ISNULL(dbo.CustomInvoiceItems.Qty, 0)) AS TotalShipped, MAX(dbo.CustomInvoice.GatePassDT) AS LastShipmentDate
                               FROM            dbo.CustomInvoiceItems INNER JOIN
                                                         dbo.CustomInvoice ON dbo.CustomInvoiceItems.CustomInvoice = dbo.CustomInvoice.CustomInvoice INNER JOIN
                                                         dbo.FProformaOrders ON dbo.CustomInvoiceItems.RefID = dbo.FProformaOrders.EntryID
                               WHERE        (dbo.CustomInvoice.GatePassDT IS NOT NULL)
                               GROUP BY dbo.FProformaOrders.OrderEntryID) AS Shipped ON dbo.FOrderItems.ID = Shipped.OrderEntryID
GO
