CREATE VIEW [dbo].[VFOrderItems]
AS
SELECT     dbo.FCustomerOrders.CustCode, dbo.FCustomerOrders.Country, dbo.FCustomerOrders.OrderNo, dbo.FCustomerOrders.InternalRefNo, dbo.FOrderItems.CompItemCode, dbo.FOrderItems.DeliveryDT, dbo.FOrderItems.Qty, T1.ShippedQty,
                  dbo.FOrderItems.DeliveryStatus, dbo.Items.ItemName, dbo.FOrderItems.ID, dbo.FCustomerOrders.DT, dbo.FOrderItems.ItemCode, dbo.ItemGroups.Description, dbo.FCustomerOrders.Packaging, dbo.FCustomerOrders.DeliveryDT AS OrderDeliveryDT,
                  dbo.FCustomerOrders.Quality, dbo.FOrderItems.Quality AS ItemQuality, dbo.Items.GroupID, dbo.FOrderItems.Remarks, dbo.FOrderItems.SortNo, dbo.FOrderItems.Price, dbo.FOrderItems.Item_Finishing_Type, dbo.FCustomerOrders.Packaging_Weight,
                  dbo.FCustomerOrders.OrderRevisionDT
FROM        dbo.FCustomerOrders INNER JOIN
                  dbo.FOrderItems ON dbo.FCustomerOrders.OrderNo = dbo.FOrderItems.OrderNo INNER JOIN
                      (SELECT     ID, SUM(ShippedQty) AS ShippedQty
                       FROM        dbo.VFOrderItemswithShippedQty
                       GROUP BY ID) AS T1 ON dbo.FOrderItems.ID = T1.ID INNER JOIN
                  dbo.Items ON dbo.FOrderItems.CompItemCode = dbo.Items.ItemID LEFT OUTER JOIN
                  dbo.ItemGroups ON dbo.Items.GroupID = dbo.ItemGroups.ID
