                      dbo.VendIssdDetail.Repair_RefID, dbo.VendIssdDetail.Rcvd_RefID, dbo.VendIssdDetail.VID_EmpID, dbo.VendIssued.MasterPONo, dbo.VendIssued.DT,
                      dbo.Makers.VendID1, dbo.Makers.VenderName, dbo.VendIssued.VendID
