CREATE VIEW [dbo].[VVendIssdDetail_Simple_WithFollowup]
AS
SELECT     dbo.VVendIssdDetail_Simple.ProcessID, dbo.VVendIssdDetail_Simple.EntryID, dbo.VVendIssdDetail_Simple.RefID, dbo.VVendIssdDetail_Simple.RecieptID, dbo.VVendIssdDetail_Simple.ItemCode,
                      dbo.VVendIssdDetail_Simple.Rate, dbo.VVendIssdDetail_Simple.IssQty, dbo.VVendIssdDetail_Simple.RcvdQty, dbo.VVendIssdDetail_Simple.LotNo, dbo.VVendIssdDetail_Simple.ReqAuth,
                      dbo.VVendIssdDetail_Simple.OrderNo, dbo.VVendIssdDetail_Simple.RcvProcessID, dbo.VVendIssdDetail_Simple.ReturnDT, dbo.VVendIssdDetail_Simple.Priority,
                      dbo.VVendIssdDetail_Simple.SpecialInstructions, dbo.VVendIssdDetail_Simple.IPODL_RefID, dbo.VVendIssdDetail_Simple.ProcessOrderIssuanceDT,
                      dbo.VVendIssdDetail_Simple.ProcessOrderRcvingDT, dbo.VVendIssdDetail_Simple.ReWorkLot, dbo.VVendIssdDetail_Simple.Repair_RefID, dbo.VVendIssdDetail_Simple.Rcvd_RefID,
                      dbo.VVendIssdDetail_Simple.VID_EmpID, dbo.VVendIssdDetail_Simple.MasterPONo, dbo.VVendIssdDetail_Simple.DT, dbo.VVendIssdDetail_Simple.VendID1,
                      dbo.VVendIssdDetail_Simple.VenderName, dbo.VVendIssdDetail_Simple.VendID, TFollowup1.Remarks_1, TFollowup2.Remarks_2, TFollowup3.Remarks_3
FROM         dbo.VVendIssdDetail_Simple LEFT OUTER JOIN
                          (SELECT     dbo.VendIssdDetail_ReturnDTs.VIS_RefID, dbo.FollowUpData.Remarks AS Remarks_1
                            FROM          dbo.FollowUpData INNER JOIN
                                                   dbo.VendIssdDetail_ReturnDTs ON dbo.FollowUpData.VIDRDTS_RefID = dbo.VendIssdDetail_ReturnDTs.EntryID
                            WHERE      (dbo.FollowUpData.FollowUp = '(F1)')) AS TFollowup1 ON dbo.VVendIssdDetail_Simple.EntryID = TFollowup1.VIS_RefID LEFT OUTER JOIN
                          (SELECT     VendIssdDetail_ReturnDTs_2.VIS_RefID, FollowUpData_2.Remarks AS Remarks_2
                            FROM          dbo.FollowUpData AS FollowUpData_2 INNER JOIN
                                                   dbo.VendIssdDetail_ReturnDTs AS VendIssdDetail_ReturnDTs_2 ON FollowUpData_2.VIDRDTS_RefID = VendIssdDetail_ReturnDTs_2.EntryID
                            WHERE      (FollowUpData_2.FollowUp = '(F2)')) AS TFollowup2 ON dbo.VVendIssdDetail_Simple.EntryID = TFollowup2.VIS_RefID LEFT OUTER JOIN
                          (SELECT     VendIssdDetail_ReturnDTs_1.VIS_RefID, FollowUpData_1.Remarks AS Remarks_3
                            FROM          dbo.FollowUpData AS FollowUpData_1 INNER JOIN
                                                   dbo.VendIssdDetail_ReturnDTs AS VendIssdDetail_ReturnDTs_1 ON FollowUpData_1.VIDRDTS_RefID = VendIssdDetail_ReturnDTs_1.EntryID
                            WHERE      (FollowUpData_1.FollowUp = '(F3)')) AS TFollowup3 ON dbo.VVendIssdDetail_Simple.EntryID = TFollowup3.VIS_RefID

GO
