CREATE VIEW [dbo].[VUnshippedOrderItemList]
AS
SELECT OrderNo, CompItemCode, SUM(Qty) AS OrderQty, SUM(ISNULL(ShippedQty, 0)) AS ShippedQty, MAX(LastShipmentDate) AS LastShipmentDate, CustCode, DT, MAX(Remarks) AS Remarks, MAX(DeliveryDT) AS DeliveryDT, MAX(Price) AS Price, MAX(PriceForCost) AS PriceForCost
FROM  dbo.VFOrderItemswithShippedQty
GROUP BY OrderNo, CompItemCode, CustCode, DT
HAVING (SUM(Qty) > SUM(ISNULL(ShippedQty, 0))) AND (OrderNo NOT IN
             (SELECT OrderNo
            FROM  dbo.FCustomerFinalOrders))
			AND (OrderNo NOT IN ('Stock-Order', 'Stock-OrderIss'))
			--AND (dbo.VFOrderItemswithShippedQty.CustCode NOT IN('STOCK','PARTS'))
