CREATE VIEW [dbo].[VFProformas]
AS
SELECT        dbo.FProformaOrders.EntryID, dbo.FProformaOrders.PInvoice, dbo.FProformaOrders.OrderEntryID, dbo.FProformaOrders.Qty,
                         dbo.FProformaOrders.Qty - ISNULL(CII.CIIQty, 0) AS InvQty, dbo.FPInvoice.CustCode, dbo.FPInvoice.Country, dbo.FOrderItems.ItemCode, dbo.FOrderItems.OrderNo,
                         dbo.Items.ItemName, dbo.FPInvoice.TradeTerms, dbo.FPInvoice.PartialShipment, dbo.FPInvoice.TransShipment, dbo.FPInvoice.PaymentTerms,
                         dbo.FPInvoice.packaging, dbo.FPInvoice.DeliveryDT, dbo.FCustomerOrders.DT, dbo.FOrderItems.ID AS OrderItemID, dbo.Items.Unit, dbo.Items.ItemSize,
                         dbo.FPInvoice.CompanyRefID, dbo.FPInvoice.ShippingAgent, dbo.FPInvoice.SMethod, dbo.FPInvoice.InvoiceOf, dbo.FPInvoice.OurBankID,
                         dbo.FCustomerCatalog.PackingMode, dbo.FOrderItems.CompItemCode, dbo.BankList.Bank, dbo.SROs.CRebate AS RebateRate, dbo.FProformaOrders.Price,
                         dbo.FProformaOrders.CustomPrice, dbo.FOrderItems.DeliveryDT AS DeliveryDTItem, dbo.FCustomerOrders.InternalRefNo, dbo.Items.ItemID,
                         dbo.FCustomerOrders.OrderType
FROM            dbo.FPInvoice INNER JOIN
                         dbo.FProformaOrders ON dbo.FPInvoice.PInvoice = dbo.FProformaOrders.PInvoice INNER JOIN
                         dbo.FOrderItems ON dbo.FProformaOrders.OrderEntryID = dbo.FOrderItems.ID INNER JOIN
                         dbo.FCustomerOrders ON dbo.FOrderItems.OrderNo = dbo.FCustomerOrders.OrderNo INNER JOIN
                         dbo.Items ON dbo.FOrderItems.CompItemCode = dbo.Items.ItemID INNER JOIN
                         dbo.FCustomerCatalog ON dbo.FPInvoice.CustCode = dbo.FCustomerCatalog.CustCode AND dbo.FPInvoice.Country = dbo.FCustomerCatalog.Country AND
                         dbo.FOrderItems.CompItemCode = dbo.FCustomerCatalog.CompItemID INNER JOIN
                         dbo.ItemCatagories ON dbo.Items.CatID = dbo.ItemCatagories.CatID LEFT OUTER JOIN
                         dbo.SROs ON dbo.ItemCatagories.SRONo = dbo.SROs.EntryID LEFT OUTER JOIN
                         dbo.BankList ON dbo.FPInvoice.OurBankID = dbo.BankList.BankID LEFT OUTER JOIN
                             (SELECT        RefID, SUM(Qty) AS CIIQty
                                FROM            dbo.CustomInvoiceItems
                                GROUP BY RefID) AS CII ON dbo.FProformaOrders.EntryID = CII.RefID
WHERE        (dbo.FOrderItems.OrderNo IN
                             (SELECT        OrderNo
                                FROM            dbo.VUnshippedOrderList))

GO
