SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VVendor_Orders_List]
AS
SELECT dbo.Vendor_Orders.OrderNo, dbo.Vendor_Orders.DT, dbo.Vendor_Orders.Vend_AccNo, '' AS Country, dbo.F_OrderAmt(dbo.Vendor_Orders.OrderNo, 0) AS OrderAmt, '' AS Curr, dbo.VVendor_Orders_TotalQty.TotalInvQty, dbo.VVendor_Orders_TotalQty.TotalOrderQty, dbo.Vendor_Orders.DeliveryDT, dbo.Vendor_Orders.CompanyRefID, dbo.Companies.CompanyName,
         dbo.VUnshippedOrderList.OrderNo AS UnshippedOrderNo, TotalShipped.TotalShippedQty, 0 AS ExchRate, dbo.Vendor_Orders.InternalRefNo, ROUND(dbo.VVendor_Orders_TotalQty.TotalWeight, 2) AS TotalWeight, TotalShipped.TotalShippedAmt, ISNULL(dbo.Vendor_Orders_Final.Cancelled, 0) AS Cancelled, TotalQuantities.TotalArticles, dbo.Vendor_Orders_Final.Remarks,
         TotalShipped.ShippedItemCount, TotalShipped.ShippedItemQty, TotalShipped.PartiallyShippedItemCount, TotalShipped.PartiallyShippedItemQty, TotalShipped.TotalBalanceQty, dbo.Vendor_Orders.OrderType, T1.TotalPlannedQty, dbo.Vendor_Orders.OrderPlanApproved, dbo.VVenders.AccTitle
FROM  dbo.Vendor_Orders INNER JOIN
         dbo.VVenders ON dbo.Vendor_Orders.Vend_AccNo = dbo.VVenders.AccNo INNER JOIN
         dbo.VVendor_Orders_TotalQty ON dbo.Vendor_Orders.OrderNo = dbo.VVendor_Orders_TotalQty.OrderNo INNER JOIN
         dbo.Companies ON dbo.Vendor_Orders.CompanyRefID = dbo.Companies.EntryID LEFT OUTER JOIN
         dbo.VUnshippedOrderList ON dbo.Vendor_Orders.OrderNo = dbo.VUnshippedOrderList.OrderNo INNER JOIN
             (SELECT OrderNo, SUM(Qty) AS TotalOrderQty, COUNT(*) AS TotalArticles
            FROM  dbo.Vendor_Orders_Items
            GROUP BY OrderNo) AS TotalQuantities ON dbo.Vendor_Orders.OrderNo = TotalQuantities.OrderNo LEFT OUTER JOIN
         dbo.Vendor_Orders_Final ON dbo.Vendor_Orders.OrderNo = dbo.Vendor_Orders_Final.OrderNo LEFT OUTER JOIN
             (SELECT OrderNo, SUM(ShippedQty) AS TotalShippedQty, SUM(ShippedQty * Price) AS TotalShippedAmt, SUM(CASE WHEN ShippedQty >= Qty THEN 1 ELSE 0 END) AS ShippedItemCount, SUM(CASE WHEN ShippedQty >= Qty THEN ShippedQty ELSE 0 END) AS ShippedItemQty, SUM(CASE WHEN ShippedQty > 0 AND ShippedQty < Qty THEN 1 ELSE 0 END)
                     AS PartiallyShippedItemCount, SUM(CASE WHEN ShippedQty > 0 AND ShippedQty < Qty THEN ShippedQty ELSE 0 END) AS PartiallyShippedItemQty, SUM(CASE WHEN ShippedQty >= Qty THEN 0 ELSE Qty - ShippedQty END) AS TotalBalanceQty
            FROM  dbo.VFOrderItemswithShippedQty
            WHERE (CompItemCode IN
                         (SELECT ItemID
                        FROM  dbo.Items))
            GROUP BY OrderNo) AS TotalShipped ON dbo.Vendor_Orders.OrderNo = TotalShipped.OrderNo LEFT OUTER JOIN
             (SELECT OrderNo, SUM(Qty) AS TotalPlannedQty
            FROM  dbo.OrderPlanningDetails
            GROUP BY OrderNo) AS T1 ON dbo.Vendor_Orders.OrderNo = T1.OrderNo
GO
