CREATE VIEW [dbo].[VVendor_Orders_Items]
AS
SELECT dbo.Vendor_Orders_Items.ID, dbo.Vendor_Orders_Items.ItemID_Vendor AS ItemCode, dbo.Vendor_Orders_Items.Price, dbo.Vendor_Orders_Items.Qty, dbo.Vendor_Orders_Items.Qty - ISNULL(TProforma.ProformaUsedQty, 0) AS InvQty, dbo.Items.ItemName, dbo.Vendor_Catalog.Description, dbo.Vendor_Catalog.ItemID, dbo.Vendor_Catalog.ItemID AS CompItemID, '' AS Curr,
         dbo.Vendor_Catalog.Unit, dbo.VVenders.AccTitle, dbo.VVenders.Address, dbo.Vendor_Orders_Items.CustomPrice, dbo.Items.CustomDescription, dbo.Items.ItemSize, dbo.Items.SizeUnit, dbo.SteelTypes.SteelType, dbo.SteelGages.Gage, dbo.Items.ItemColor, dbo.Vendor_Catalog.BarcodeNo, dbo.Vendor_Catalog.PackingMode, dbo.Items.MasterCartonL, dbo.Items.MasterCartonW,
         dbo.Items.MasterCartonH, dbo.Items.SmallCartonL, dbo.Items.SmallCartonW, dbo.Items.SmallCartonH, dbo.Items.PolyBag, dbo.Vendor_Catalog.SpecialInstructions, dbo.Vendor_Catalog.StampInstructions, dbo.Vendor_Catalog.PackingInstructions, dbo.Items.Unit AS UnitItems, dbo.Vendor_Catalog.ItemColor AS CustomerColor, ISNULL(Shipped.TotalShipped, 0) AS ShippedQty,
         dbo.Items.ItemNameUrdu, dbo.Items.InHand, dbo.Vendor_Orders_Items.SortNo, dbo.ItemCatagories.MaxLotSize, dbo.Vendor_Orders_Items.DeliveryDT AS DeliveryDTItem, dbo.Vendor_Orders_Items.Stamps AS StampsItem, dbo.Vendor_Orders_Items.Quality AS QualityItem, dbo.Items.FinQuality, dbo.Items.Type, dbo.Vendor_Orders_Items.DeliveryStatus, dbo.Vendor_Catalog.OCR,
         dbo.Vendor_Orders_Items.ItemID AS CompItemCode, dbo.ItemGroups.Description AS GroupDescription, dbo.Vendor_Orders.OrderNo, dbo.Vendor_Orders.DT, dbo.Vendor_Orders.TradeTerms, dbo.Vendor_Orders.Vend_AccNo, '' AS Country, dbo.Vendor_Orders.PartialShipment, dbo.Vendor_Orders.PaymentTerms, dbo.Vendor_Orders.TransShipment,
         dbo.Vendor_Orders.Packaging, dbo.Vendor_Orders.DeliveryDT, dbo.Vendor_Orders.BatchNo, dbo.Vendor_Orders.CompanyRefID, dbo.Vendor_Orders.StampDT, dbo.Vendor_Orders.Quality, dbo.Vendor_Orders.InternalRefNo, dbo.Vendor_Orders.OrderRcvdVia, dbo.Vendor_Orders_Items.Remarks, dbo.Vendor_Orders.OrderType, dbo.Items.GroupID, T1.VOI_RefID,
         dbo.FCustomerFinalOrders.Cancelled, dbo.Items.MasterCartonSmallBoxes, dbo.Items.SmallBoxPcs, dbo.Items.FinishedWeight, dbo.Vendor_Orders.OrderRevisionNo, dbo.Vendor_Orders.OrderRevisionDT, dbo.Vendor_Orders_Items.Item_Edited, dbo.Vendor_Orders.ShippingMode, dbo.Vendor_Orders_Items.Weight, dbo.Vendor_Orders_Items.Item_Finishing_Type,
         dbo.Item_Finishing_Type.Item_Finishing_Type_Text
FROM  dbo.Vendor_Orders INNER JOIN
         dbo.Vendor_Orders_Items ON dbo.Vendor_Orders.OrderNo = dbo.Vendor_Orders_Items.OrderNo INNER JOIN
         dbo.Vendor_Catalog ON dbo.Vendor_Orders.Vend_AccNo = dbo.Vendor_Catalog.Vend_AccNo AND dbo.Vendor_Orders_Items.ItemID = dbo.Vendor_Catalog.ItemID INNER JOIN
         dbo.Items ON dbo.Vendor_Catalog.ItemID = dbo.Items.ItemID INNER JOIN
         dbo.VVenders ON dbo.Vendor_Orders.Vend_AccNo = dbo.VVenders.AccNo INNER JOIN
         dbo.ItemCatagories ON dbo.Items.CatID = dbo.ItemCatagories.CatID INNER JOIN
         dbo.ItemGroups ON dbo.Items.GroupID = dbo.ItemGroups.ID LEFT OUTER JOIN
         dbo.Item_Finishing_Type ON dbo.Vendor_Orders_Items.Item_Finishing_Type = dbo.Item_Finishing_Type.EntryID LEFT OUTER JOIN
         dbo.FCustomerFinalOrders ON dbo.Vendor_Orders.OrderNo = dbo.FCustomerFinalOrders.OrderNo LEFT OUTER JOIN
         dbo.SteelGages ON dbo.Items.Gage = dbo.SteelGages.GageID LEFT OUTER JOIN
         dbo.SteelTypes ON dbo.Items.SteelUsed = dbo.SteelTypes.SteelID LEFT OUTER JOIN
             (SELECT VOI_RefID
            FROM  dbo.Vendor_Orders_Items_PDF
            GROUP BY VOI_RefID) AS T1 ON dbo.Vendor_Orders_Items.ID = T1.VOI_RefID LEFT OUTER JOIN
             (SELECT OrderEntryID, SUM(Qty) AS ProformaUsedQty
            FROM  dbo.FProformaOrders
            GROUP BY OrderEntryID) AS TProforma ON dbo.Vendor_Orders_Items.ID = TProforma.OrderEntryID LEFT OUTER JOIN
             (SELECT FProformaOrders_1.OrderEntryID, SUM(ISNULL(dbo.CustomInvoiceItems.Qty, 0)) AS TotalShipped
            FROM  dbo.CustomInvoiceItems INNER JOIN
                     dbo.CustomInvoice ON dbo.CustomInvoiceItems.CustomInvoice = dbo.CustomInvoice.CustomInvoice INNER JOIN
                     dbo.FProformaOrders AS FProformaOrders_1 ON dbo.CustomInvoiceItems.RefID = FProformaOrders_1.EntryID
            WHERE (dbo.CustomInvoice.GatePassDT IS NOT NULL)
            GROUP BY FProformaOrders_1.OrderEntryID) AS Shipped ON dbo.Vendor_Orders_Items.ID = Shipped.OrderEntryID
GO
