CREATE VIEW [dbo].[VSalaryLedgerEx]
AS
SELECT        TOP (100) PERCENT TabInner1.PrevSal, dbo.VEmp.deptid, dbo.VEmp.DeptName, dbo.VEmp.name, dbo.VEmp.fname, dbo.VEmp.dob, dbo.VEmp.JoinDate, dbo.VEmp.TempDept, dbo.VEmp.Designation, dbo.VEmp.Active,
                         T1_1.EntryID, T1_1.Salary, T1_1.SalaryExt, T1_1.DT, T1_1.Description, T1_1.UserName, T1_1.MachineName, T1_1.EntryDT, T1_1.PreviousSalary, T1_1.PrevEntryID, dbo.VEmp.empid, dbo.VEmp.FixAllowance
FROM            (SELECT        EntryID, EmpID, Salary, SalaryExt, DT, Description, UserName, MachineName, EntryDT, PreviousSalary,
                                                        (SELECT        MAX(EntryID) AS Expr1
                                                          FROM            dbo.SalaryLedger AS T1
                                                          WHERE        (EmpID = dbo.SalaryLedger.EmpID) AND (EntryID < dbo.SalaryLedger.EntryID)) AS PrevEntryID
                          FROM            dbo.SalaryLedger) AS T1_1 RIGHT OUTER JOIN
                         dbo.VEmp ON T1_1.EmpID = dbo.VEmp.empid LEFT OUTER JOIN
                             (SELECT        EntryID, Salary AS PrevSal
                               FROM            dbo.SalaryLedger AS SalaryLedger_1) AS TabInner1 ON TabInner1.EntryID = T1_1.PrevEntryID
ORDER BY T1_1.DT
GO
