CREATE VIEW [dbo].[VCustomInvoiceItems]
AS
SELECT        dbo.ForeignCustomers.Name, dbo.ForeignCustomers.Address, dbo.CustomInvoiceItems.EntryID, dbo.CustomInvoiceItems.RefID, dbo.CustomInvoiceItems.Qty, dbo.CustomInvoiceItems.Price,
                         dbo.CustomInvoiceItems.CustomPrice, dbo.FProformaOrders.PInvoice, dbo.FOrderItems.OrderNo, dbo.FOrderItems.ItemCode, dbo.Items.ItemName, dbo.Items.Unit, dbo.FProformaOrders.InvQty, dbo.ForeignCustomers.Curr,
                         dbo.ForeignCustomers.Cont1name, dbo.ForeignCustomers.cont1phone, dbo.Items.ItemSize, dbo.FCustomerCatalog.ItemID AS CustItemID, dbo.CustomInvoiceItems.RebateRate, dbo.FCustomerOrders.DeliveryDT,
                         dbo.FProformaOrders.OrderEntryID, dbo.Items.CustomDescription AS ItemCustomName, dbo.FOrderItems.CompItemCode, dbo.CustomInvoiceItems.DTRENo, dbo.CustomInvoiceItems.CustomInvoice,
                         dbo.CustomInvoiceItems.ItemForLabTest, dbo.CustomInvoiceItems.BatchNo, dbo.FOrderItems.DeliveryDT AS DeliveryDTItem, dbo.CustomInvoice.AWBNoDT, dbo.Items.ItemID, dbo.FProformaOrders.ItemDescription
FROM            dbo.FCustomerCatalog INNER JOIN
                         dbo.CustomInvoice INNER JOIN
                         dbo.CustomInvoiceItems ON dbo.CustomInvoice.CustomInvoice = dbo.CustomInvoiceItems.CustomInvoice INNER JOIN
                         dbo.ForeignCustomers ON dbo.CustomInvoice.CustCode = dbo.ForeignCustomers.CustCode AND dbo.CustomInvoice.Country = dbo.ForeignCustomers.Country INNER JOIN
                         dbo.FProformaOrders ON dbo.CustomInvoiceItems.RefID = dbo.FProformaOrders.EntryID INNER JOIN
                         dbo.FOrderItems ON dbo.FProformaOrders.OrderEntryID = dbo.FOrderItems.ID ON dbo.FCustomerCatalog.CustCode = dbo.ForeignCustomers.CustCode AND dbo.FCustomerCatalog.Country = dbo.ForeignCustomers.Country AND
                         dbo.FCustomerCatalog.CompItemID = dbo.FOrderItems.CompItemCode INNER JOIN
                         dbo.FCustomerOrders ON dbo.ForeignCustomers.CustCode = dbo.FCustomerOrders.CustCode AND dbo.ForeignCustomers.Country = dbo.FCustomerOrders.Country AND
                         dbo.FOrderItems.OrderNo = dbo.FCustomerOrders.OrderNo INNER JOIN
                         dbo.ItemCatagories INNER JOIN
                         dbo.Items ON dbo.ItemCatagories.CatID = dbo.Items.CatID ON dbo.FOrderItems.CompItemCode = dbo.Items.ItemID
GO
