                  VPorts_1.CountryName AS DisCountry, VPorts_1.CityID AS DisCityID, VPorts_1.City AS DisCity, VPorts_1.PortID AS DisPortID, VPorts_1.Port AS DisPort, dbo.ForeignCustomers.Cont1name, dbo.ForeignCustomers.DTFormat,
                  dbo.ShippingAgents.Name AS ShippingAgentName, dbo.InsuranceAgents.Name AS InsuranceAgentName, dbo.ForeignCustomers.FakeAddress, dbo.ExportPackageLocknHide.CoveringLetterL, dbo.ExportPackageLocknHide.CoveringLetterH,
                  dbo.ExportPackageLocknHide.InvoiceL, dbo.ExportPackageLocknHide.InvoiceH, dbo.ExportPackageLocknHide.PackingListL, dbo.ExportPackageLocknHide.PackingListH, dbo.ExportPackageLocknHide.ShippingL, dbo.ExportPackageLocknHide.ShippingH,
                  dbo.ExportPackageLocknHide.PackingLabelsL, dbo.ExportPackageLocknHide.PackingLabelsH, dbo.ExportPackageLocknHide.FormEL, dbo.ExportPackageLocknHide.FormEH, dbo.ExportPackageLocknHide.ValuationFormL,
                  dbo.ExportPackageLocknHide.ValuationFormH, dbo.ExportPackageLocknHide.CCoveringLetterL, dbo.ExportPackageLocknHide.CCoveringLetterH, dbo.ExportPackageLocknHide.CInvoiceL, dbo.ExportPackageLocknHide.CInvoiceH,
                  dbo.ExportPackageLocknHide.CPackingListL, dbo.ExportPackageLocknHide.CPackingListH, dbo.ExportPackageLocknHide.CInspectionL, dbo.ExportPackageLocknHide.CInspectionH, dbo.ExportPackageLocknHide.GSPL, dbo.ExportPackageLocknHide.GSPH,
                  dbo.BankList.Bank, dbo.Companies.CompanyName, dbo.CustomInvoice.CustomInvoice, dbo.CustomInvoice.DT, dbo.CustomInvoice.CustCode, dbo.CustomInvoice.Country, dbo.CustomInvoice.ShippingMode, dbo.CustomInvoice.AWBNo,
                  dbo.CustomInvoice.AWBNoDT, dbo.CustomInvoice.FormE, dbo.CustomInvoice.FormEDT, dbo.CustomInvoice.TradeTerms, dbo.CustomInvoice.GrossWeight, dbo.CustomInvoice.PaymentTerms, dbo.CustomInvoice.LCNo, dbo.CustomInvoice.TransShipment,
                  dbo.CustomInvoice.Packaging, dbo.CustomInvoice.ShippingAgentID, dbo.CustomInvoice.PartialShipment, dbo.CustomInvoice.InsuranceAgentID, dbo.CustomInvoice.OurBankID, dbo.CustomInvoice.DeclarationsBalls, dbo.CustomInvoice.DeclarationsGarments,
                  dbo.CustomInvoice.DeclarationsGloves, dbo.CustomInvoice.Consignee, dbo.CustomInvoice.ComInvDT, dbo.CustomInvoice.Vessel, dbo.CustomInvoice.ComDeclarationsBalls, dbo.CustomInvoice.ComDeclarationsGarments,
                  dbo.CustomInvoice.ComDeclarationsGloves, dbo.CustomInvoice.ComNotify, dbo.CustomInvoice.ComConsignee, dbo.CustomInvoice.ComPayTerms, dbo.CustomInvoice.ComAgainst, dbo.CustomInvoice.ComDrawnUnder, dbo.CustomInvoice.ComSpecial,
                  dbo.CustomInvoice.ManDischarge, dbo.CustomInvoice.ManDeclaration, dbo.CustomInvoice.ContainerNo, dbo.CustomInvoice.Warehouse, dbo.CustomInvoice.Gate, dbo.CustomInvoice.DTETA, dbo.CustomInvoice.SRONo, dbo.CustomInvoice.CustCurrency,
                  dbo.CustomInvoice.InvoiceFeedingDT, dbo.CustomInvoice.CompanyRefID, ROUND(dbo.VCustomInvoiceAmt.TotalCustomAmt - ISNULL(dbo.VCustomInvoiceAmtRcvd.TotalCustomAmtRcvd, 0), 0) AS TotalCustomAmtToRcv, dbo.VCustomInvoiceAmt.TotalCustomAmt,
                  dbo.VCustomInvoiceAmtRcvd.TotalCustomAmtRcvd, dbo.CustomInvoice.InvoiceOf, dbo.VCustomInvoiceAmt.TotalAmt AS TotalCommercialAmt, ISNULL(dbo.VCustomInvoiceAmtRcvd.TotalCommercialAmtRcvd, 0) AS TotalCommercialAmtRcvd,
                  ROUND(dbo.VCustomInvoiceAmt.TotalAmt - ISNULL(dbo.VCustomInvoiceAmtRcvd.TotalCommercialAmtRcvd, 0), 0) AS TotalCommercialAmtToRcv, dbo.CustomInvoice.LCDate, dbo.BankList.Branch, dbo.BankList.City, dbo.Companies.Address AS CompanyAddress,
                  dbo.Companies.PhoneNo, dbo.Companies.FaxNo, dbo.Companies.EFax, dbo.Companies.Email, dbo.Companies.NTNNo, dbo.Companies.OriginalAddress, dbo.Companies.SalesTaxNo, dbo.Companies.Internet, dbo.Companies.Email1, dbo.Companies.PhoneNo1,
                  dbo.CustomInvoiceDTREs_F(dbo.CustomInvoice.CustomInvoice) AS DTREs, dbo.VCustomInvoiceAmt.TotalQty, dbo.CustomInvoiceAuthorization.AmtInPakRs, dbo.CustomInvoiceAuthorization.ExchRate, dbo.CustomInvoice.DTMaturity, dbo.CustomInvoice.NoSRO,
                  dbo.CustomInvoice.CIFTradeTerms, dbo.CustomInvoice.SampleInvoice, dbo.ForeignCustomers.ShowCustomerRef, dbo.CustomInvoice.FreeSamples, dbo.BankList.Manager AS IBAN, dbo.VCustomInvoiceList.InvoiceOrders,
                  dbo.VCustomInvoiceList.InvoiceInternalOrders, dbo.CustomInvoice.GDNo, dbo.CustomInvoice.InvoiceTo, dbo.CustomInvoice.CustomDT, dbo.CustomInvoice.InvoiceDescription, dbo.CustomInvoice.SealNo, dbo.CustomInvoice.GatePassNo,
                  dbo.CustomInvoice.GatePassDT, dbo.CustomInvoice.DTREDescription
