                  dbo.VCustomInvoiceAmt RIGHT OUTER JOIN
                  dbo.Companies INNER JOIN
                  dbo.ForeignCustomers INNER JOIN
                  dbo.CustomInvoice ON dbo.ForeignCustomers.CustCode = dbo.CustomInvoice.CustCode AND dbo.ForeignCustomers.Country = dbo.CustomInvoice.Country ON dbo.Companies.EntryID = dbo.CustomInvoice.CompanyRefID LEFT OUTER JOIN
                  dbo.CustomInvoiceAuthorization ON dbo.CustomInvoice.CustomInvoice = dbo.CustomInvoiceAuthorization.CustomInvoice ON dbo.VCustomInvoiceAmt.CustomInvoice = dbo.CustomInvoice.CustomInvoice LEFT OUTER JOIN
                  dbo.VCustomInvoiceAmtRcvd ON dbo.CustomInvoice.CustomInvoice = dbo.VCustomInvoiceAmtRcvd.CustomInvoice LEFT OUTER JOIN
                  dbo.BankList ON dbo.CustomInvoice.OurBankID = dbo.BankList.BankID ON dbo.ShippingAgents.EntryID = dbo.CustomInvoice.ShippingAgentID LEFT OUTER JOIN
                  dbo.InsuranceAgents ON dbo.CustomInvoice.InsuranceAgentID = dbo.InsuranceAgents.EntryID LEFT OUTER JOIN
                  dbo.VPorts AS VPorts_2 ON dbo.CustomInvoice.LoadPortID = VPorts_2.PortID LEFT OUTER JOIN
                  dbo.VPorts AS VPorts_1 ON dbo.CustomInvoice.DisPortID = VPorts_1.PortID LEFT OUTER JOIN
                  dbo.ExportPackageLocknHide ON dbo.CustomInvoice.CustomInvoice = dbo.ExportPackageLocknHide.CustomInvoice LEFT OUTER JOIN
                  dbo.VCustomInvoiceList ON dbo.CustomInvoice.CustomInvoice = dbo.VCustomInvoiceList.CustomInvoice
GO
