CREATE VIEW [dbo].[VRawMaterialIssuance]
AS
SELECT     dbo.RawMaterialIssuance.IssNo, dbo.RawMaterialIssuance.DT, dbo.RawMaterialIssuance.IssdToEmpID, dbo.RawMaterialIssuance.AuthorizedByEmpID, dbo.RawMaterialIssuanceDetail.Price, dbo.RawMaterialIssuanceDetail.Qty,
                  dbo.RawMaterialIssuanceDetail.RMID1, dbo.RM.RMID, dbo.RM.GroupID, dbo.RM.RMName, dbo.RM.Unit, dbo.RM.RMSize, dbo.RM.SizeUnit, dbo.Processes.Description, dbo.VendIssued.VendID, dbo.RawMaterialIssuanceDetail.VchrNo,
                  dbo.RawMaterialIssuanceDetail.EntryID, dbo.RawMaterialIssuance.EntryID AS MasterEntryID, dbo.VendIssued.ItemID, dbo.Makers.VendID AS Makers_VendID
				  ,dbo.VendIssued.MasterPONo
				  ,dbo.Makers.AccNo
FROM        dbo.Processes RIGHT OUTER JOIN
                  dbo.Makers RIGHT OUTER JOIN
                  dbo.VendIssued ON dbo.Makers.VendID = dbo.VendIssued.VendID ON dbo.Processes.ProcessID = dbo.VendIssued.ProcessID RIGHT OUTER JOIN
                  dbo.RM INNER JOIN
                  dbo.RawMaterialIssuance INNER JOIN
                  dbo.RawMaterialIssuanceDetail ON dbo.RawMaterialIssuance.IssNo = dbo.RawMaterialIssuanceDetail.IssNo ON dbo.RM.RMID1 = dbo.RawMaterialIssuanceDetail.RMID1 ON dbo.VendIssued.EntryID = dbo.RawMaterialIssuance.VI_RefID
