CREATE VIEW [dbo].[VRebate]
AS
SELECT     dbo.Rebate.EntryID, dbo.Rebate.CustomInvoice, dbo.Rebate.DT, dbo.Rebate.ExchRate, dbo.Rebate.AmtRealized, dbo.Rebate.InPak, dbo.Rebate.LessFreight,
                      dbo.Rebate.LessInsurance, dbo.Rebate.NetFOB, dbo.Rebate.NetRebate, dbo.Rebate.RecDT, dbo.Rebate.Paid, dbo.Rebate.Applied, dbo.Rebate.AppDT,
                      dbo.Rebate.CustomNo, dbo.Rebate.CustomDT, dbo.Rebate.Commodity, dbo.VRebateSRO.LessFreight AS SROFreight,
                      dbo.VRebateSRO.LessInsurance AS SROInsurance, dbo.VRebateSRO.NetTotal AS SROTotal, dbo.VRebateSRO.SRONo, dbo.VRebateSRO.CRebate,
                      dbo.VRebateSRO.STax, dbo.VRebateSRO.EDuty, dbo.VRebateSRO.CompleteNo, dbo.ForeignCustomers.Curr, dbo.ForeignCustomers.CustCode,
                      dbo.ForeignCustomers.Country, dbo.VRebateSRO.SRODT, dbo.CustomInvoice.DT AS CustomInvoiceDT,
                      dbo.VRebateSRO.NetTotal / 100 * dbo.VRebateSRO.STax AS TotalSTax, dbo.VRebateSRO.NetTotal / 100 * dbo.VRebateSRO.EDuty AS TotalEDuty,
                      dbo.VRebateSRO.NetTotal / 100 * dbo.VRebateSRO.CRebate AS TotalRebate, dbo.CustomInvoice.FormEDT, dbo.VRebateSRO.Percentage, dbo.CustomInvoice.FormE,
                      dbo.CustomInvoice.AWBNo, dbo.CustomInvoice.AWBNoDT, dbo.Rebate.Vessel, dbo.Rebate.PayTerms, dbo.Rebate.FBankCharges, dbo.VCustomInvoiceAmt.TotalAmt,
                      dbo.VCustomInvoiceAmt.TotalCustomAmt, dbo.VCustomInvoiceAmtRcvd.TotalCustomAmtRcvd, dbo.VCustomInvoiceAmtRcvd.TotalCommercialAmtRcvd,
                      dbo.Companies.CompanyName, dbo.CustomInvoice.InvoiceOf, dbo.Companies.PhoneNo1, dbo.Companies.FaxNo, dbo.Companies.EFax, dbo.Companies.Email1,
                      dbo.Companies.Internet, dbo.Companies.NTNNo, dbo.Companies.SalesTaxNo, dbo.Companies.Address, dbo.Rebate.BGExpenses, dbo.Rebate.DTREExpenses,
                      dbo.Rebate.ReturnGoodsValue, dbo.VRebateSRO.BGExp, dbo.VRebateSRO.DTREExp, dbo.VRebateSRO.ReturnGoodsValue AS SROReturnGoodsValue
FROM         dbo.CustomInvoice INNER JOIN
                      dbo.Rebate INNER JOIN
                      dbo.VRebateSRO ON dbo.Rebate.CustomInvoice = dbo.VRebateSRO.CustomInvoice ON dbo.CustomInvoice.CustomInvoice = dbo.Rebate.CustomInvoice INNER JOIN
                      dbo.VCustomInvoiceAmt ON dbo.Rebate.CustomInvoice = dbo.VCustomInvoiceAmt.CustomInvoice INNER JOIN
                      dbo.VCustomInvoiceAmtRcvd ON dbo.Rebate.CustomInvoice = dbo.VCustomInvoiceAmtRcvd.CustomInvoice INNER JOIN
                      dbo.ForeignCustomers ON dbo.CustomInvoice.CustCode = dbo.ForeignCustomers.CustCode AND
                      dbo.CustomInvoice.Country = dbo.ForeignCustomers.Country INNER JOIN
                      dbo.Companies ON dbo.CustomInvoice.CompanyRefID = dbo.Companies.EntryID

GO
