/****** Object:  View [dbo].[VVendRcvdDetail]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VVendRcvdDetail]
AS
SELECT dbo.VendReceived.DT, dbo.VendReceived.VendID, dbo.vendRcvdDetail.RcvdQty - dbo.vendRcvdDetail.Wastage - ISNULL(dbo.vendRcvdDetail.RcvRepairQty, 0) - dbo.vendRcvdDetail.IssQty AS IssuableQty, dbo.VendReceived.UserID, dbo.VItems1.CompleteItemName AS ItemDescription, dbo.VendReceived.Issuance_RefID, dbo.VendReceived.ProcessID AS MainProcessID,
         dbo.VendAssItems.Unit, dbo.VItems1.ForgingWeight, CASE WHEN VendAssItems.UNIT = 'Kgs' THEN (RcvdWeight - ((RcvdWeight / dbo.VendRcvdDetail.RcvdQty) * (Wastage + LostQty))) * VendIssdDetail.Rate ELSE VendIssdDetail.Rate * (dbo.VendRcvdDetail.RcvdQty - Wastage - LostQty) END AS RcvdValue,
         (CASE WHEN dbo.VendRcvdDetail.RcvdQty = 0 THEN 0 ELSE RcvdWeight / dbo.VendRcvdDetail.RcvdQty END) * dbo.vendRcvdDetail.LostQty AS LostQtyWeight, (CASE WHEN dbo.VendRcvdDetail.RcvdQty = 0 THEN 0 ELSE RcvdWeight / dbo.VendRcvdDetail.RcvdQty END) * dbo.vendRcvdDetail.Wastage AS WasteQtyWeight, dbo.VendIssdDetail.Rate AS IssRate,
         CAST(CONVERT(VARCHAR(50), dbo.VendReceived.DT, 6) AS DATETIME) AS OnlyDT, dbo.Processes.BillingProcessID, dbo.Makers.VenderName, dbo.Processes.Code, dbo.Processes.Description, dbo.VItems1.ItemName, dbo.VItems1.ItemSize, dbo.VItems1.SizeUnit, dbo.VItems1.TipSize, dbo.VendIssued.RecieptID AS MainRecieptID, dbo.VendReceived.EmpID,
         dbo.Employees.name + ' ' + dbo.Employees.Rel + ' ' + dbo.Employees.fname AS EmployeeName, dbo.ItemProcesses.SNO AS ItemSNo, ItemBillingProcess.SNO AS BillingProcessSNo, dbo.VendReceived.EntryID AS ReceivedEntryID, dbo.vendRcvdDetail.EntryID, dbo.vendRcvdDetail.RefID, dbo.vendRcvdDetail.ItemCode, dbo.vendRcvdDetail.RecieptID, dbo.vendRcvdDetail.RcvdQty,
         dbo.vendRcvdDetail.Wastage, dbo.vendRcvdDetail.Rate, dbo.vendRcvdDetail.LotNo, dbo.vendRcvdDetail.ReqAuth, dbo.vendRcvdDetail.RcvRepairQty, dbo.vendRcvdDetail.IssRepairQty, dbo.vendRcvdDetail.NextProcessID, dbo.vendRcvdDetail.LostQty, dbo.vendRcvdDetail.OrderNo, dbo.vendRcvdDetail.CountedBy, dbo.vendRcvdDetail.Issue_RefID, dbo.vendRcvdDetail.ProcessID,
         dbo.vendRcvdDetail.RcvdWeight, dbo.vendRcvdDetail.RepairAmt, dbo.vendRcvdDetail.Opening_RefID, dbo.vendRcvdDetail.ReWorkQty, dbo.vendRcvdDetail.ReWorkLot, dbo.vendRcvdDetail.Repair_RefID, dbo.vendRcvdDetail.Insp_EmpID, dbo.vendRcvdDetail.Audited, dbo.vendRcvdDetail.IssQty, dbo.VendAssItems.Rate AS VAIRate,
         dbo.vendRcvdDetail.Not_Available_For_Billing
FROM  dbo.VendReceived INNER JOIN
         dbo.vendRcvdDetail ON dbo.VendReceived.EntryID = dbo.vendRcvdDetail.RefID INNER JOIN
         dbo.VItems1 ON dbo.vendRcvdDetail.ItemCode = dbo.VItems1.ItemID LEFT OUTER JOIN
         dbo.VendAssItems ON dbo.vendRcvdDetail.ItemCode = dbo.VendAssItems.ItemID AND dbo.VendReceived.VendID = dbo.VendAssItems.VendID AND dbo.vendRcvdDetail.ProcessID = dbo.VendAssItems.ProcessID INNER JOIN
         dbo.VendIssdDetail ON dbo.VendIssdDetail.EntryID = dbo.vendRcvdDetail.Issue_RefID INNER JOIN
         dbo.Processes ON dbo.vendRcvdDetail.ProcessID = dbo.Processes.ProcessID LEFT OUTER JOIN
         dbo.ItemProcesses ON dbo.vendRcvdDetail.ItemCode = dbo.ItemProcesses.ItemID AND dbo.vendRcvdDetail.ProcessID = dbo.ItemProcesses.ProcessID LEFT OUTER JOIN
         dbo.ItemProcesses AS ItemBillingProcess ON dbo.Processes.BillingProcessID = ItemBillingProcess.ProcessID AND dbo.vendRcvdDetail.ItemCode = ItemBillingProcess.ItemID INNER JOIN
         dbo.Makers ON dbo.VendReceived.VendID = dbo.Makers.VendID INNER JOIN
         dbo.VendIssued ON dbo.VendIssdDetail.RefID = dbo.VendIssued.EntryID LEFT OUTER JOIN
         dbo.Employees ON dbo.VendReceived.EmpID = dbo.Employees.empid LEFT OUTER JOIN
             (SELECT VRD_From_RefID, SUM(SplitQty) AS SplitQtyForRcvdQty
            FROM  dbo.LotTransferDetails
            GROUP BY VRD_From_RefID) AS TSplitQtyForRcvdQty ON dbo.vendRcvdDetail.EntryID = TSplitQtyForRcvdQty.VRD_From_RefID
GO
