CREATE VIEW [dbo].[VDispatchListToExport]
AS
SELECT        TMain.RefID AS DispatchListNo, TMain.OrderNo, TMain.ItemCode, TMain.DispatchQty, ISNULL(T1.InvQty, 0) AS InvQty
FROM            (SELECT        dbo.DispatchListDetails_Adv.RefID, dbo.VendRcvdDetail.OrderNo, dbo.VendRcvdDetail.ItemCode, SUM(dbo.DispatchListDetail_VRD.Qty)
                                                    AS DispatchQty
                           FROM            dbo.DispatchListDetail_VRD INNER JOIN
                                                    dbo.VendRcvdDetail ON dbo.DispatchListDetail_VRD.VRD_RefID = dbo.VendRcvdDetail.EntryID INNER JOIN
                                                    dbo.DispatchListDetails_Adv ON dbo.DispatchListDetails_Adv.EntryID = dbo.DispatchListDetail_VRD.DLD_RefID
                           GROUP BY dbo.VendRcvdDetail.OrderNo, dbo.VendRcvdDetail.ItemCode, dbo.DispatchListDetails_Adv.RefID) AS TMain LEFT OUTER JOIN
                             (SELECT        OrderNo, ItemID, SUM(InvQty) AS InvQty
                                FROM            dbo.VFProformas
                                WHERE        (InvQty > 0)
                                GROUP BY OrderNo, ItemID) AS T1 ON TMain.OrderNo = T1.OrderNo AND TMain.ItemCode = T1.ItemID

