CREATE VIEW [dbo].[VMakerAdvancesLedger_Short]
AS
SELECT        dbo.VVendersAndMakers.VendID, T1.EntryID, T1.AccNo, T1.DT, T1.Description, T1.Amount, T1.AccVoucherNo
FROM            (SELECT        EntryID, AccNo, DT, Description, Amount, AccVoucherNo
                          FROM            dbo.MakerAdvancesShort
                          UNION
                          SELECT        dbo.MakerPostedBills_STDeductions.EntryID, dbo.MakerPostedBills_STDeductions.AccNo, dbo.MakerPostedBills.DT, 'Deduction in Bill' AS Description, - dbo.MakerPostedBills_STDeductions.Amount AS Amount,
                                                   dbo.MakerPostedBills.VchrNo
                          FROM            dbo.MakerPostedBills_STDeductions INNER JOIN
                                                   dbo.MakerPostedBills ON dbo.MakerPostedBills.EntryID = dbo.MakerPostedBills_STDeductions.MPB_RefID
                          UNION
                          SELECT        MakerPostedBills_STDeductions_2.EntryID, MakerPostedBills_STDeductions_2.AccNo, dbo.MakerLoanTransfer.DT, dbo.MakerLoanTransfer.Description, - MakerPostedBills_STDeductions_2.Amount AS Amount,
                                                   '' AS VchrNo
                          FROM            dbo.MakerPostedBills_STDeductions AS MakerPostedBills_STDeductions_2 INNER JOIN
                                                   dbo.MakerLoanTransfer ON dbo.MakerLoanTransfer.EntryID = MakerPostedBills_STDeductions_2.MLT_RefID
                          UNION
                          SELECT        EntryID, AccNo, DT, 'Deduction in Bill' AS Description, - STDeduction AS Amount, VchrNo
                          FROM            dbo.VenderPostedBills
                          UNION
                          SELECT        MakerPostedBills_STDeductions_1.EntryID, MakerPostedBills_STDeductions_1.AccNo, dbo.MakerLoanClearance_Manual.DT, 'Deduction in Bill' AS Description,
                                                   - MakerPostedBills_STDeductions_1.Amount AS Amount, dbo.MakerLoanClearance_Manual.VchrNo
                          FROM            dbo.MakerPostedBills_STDeductions AS MakerPostedBills_STDeductions_1 INNER JOIN
                                                   dbo.MakerLoanClearance_Manual ON dbo.MakerLoanClearance_Manual.MPB_STD_EntryID = MakerPostedBills_STDeductions_1.EntryID) AS T1 INNER JOIN
                         dbo.VVendersAndMakers ON T1.AccNo = dbo.VVendersAndMakers.AccNo
