GO

CREATE VIEW [dbo].[VInvForRebate]
AS
SELECT     dbo.CustomInvoice.CustomInvoice, dbo.CustomInvoice.DT, dbo.CustomInvoice.CustCode, dbo.CustomInvoice.Country, dbo.CustomInvoice.AWBNo,
                      dbo.CustomInvoice.AWBNoDT, dbo.CustomInvoice.FormE, dbo.CustomInvoice.FormEDT, dbo.VCustomInvoiceAmt.TotalAmt AS TotalCommercialAmt,
                      ISNULL(dbo.VCustomInvoiceAmtRcvd.TotalCommercialAmtRcvd, 0) AS TotalCommercialAmtRcvd,
                      ROUND(dbo.VCustomInvoiceAmt.TotalAmt - ISNULL(dbo.VCustomInvoiceAmtRcvd.TotalCommercialAmtRcvd, 0), 0) AS CommercialAmtToRcv,
                      dbo.VCustomInvoiceAmt.TotalCustomAmt, ISNULL(dbo.VCustomInvoiceAmtRcvd.TotalCustomAmtRcvd, 0) AS TotalCustomAmtRcvd,
                      ROUND(dbo.VCustomInvoiceAmt.TotalCustomAmt - ISNULL(dbo.VCustomInvoiceAmtRcvd.TotalCustomAmtRcvd, 0), 0) AS CustomAmtToRcv,
                      dbo.CustomInvoice.PaymentTerms, dbo.ForeignCustomers.PaymentDays, dbo.ForeignCustomers.Curr, dbo.CustomInvoice.FreeSamples,
                      dbo.CustomInvoice.GatePassNo
FROM         dbo.CustomInvoice INNER JOIN
                      dbo.VCustomInvoiceAmt ON dbo.CustomInvoice.CustomInvoice = dbo.VCustomInvoiceAmt.CustomInvoice LEFT OUTER JOIN
                      dbo.VCustomInvoiceAmtRcvd ON dbo.CustomInvoice.CustomInvoice = dbo.VCustomInvoiceAmtRcvd.CustomInvoice INNER JOIN
                      dbo.ForeignCustomers ON dbo.CustomInvoice.CustCode = dbo.ForeignCustomers.CustCode AND dbo.CustomInvoice.Country = dbo.ForeignCustomers.Country
WHERE     (dbo.CustomInvoice.FreeSamples = 0)

GO
