CREATE VIEW [dbo].[VPaymentsRcvd]
AS
SELECT     TOP 100 PERCENT dbo.CustomInvoice.CustomInvoice, dbo.FCustPayments.DT, dbo.FCustPayments.Description, dbo.CustomInvoice.CustCode,
                      dbo.CustomInvoice.Country, '' AS Orders, '' AS Proformas, '' AS FormE, dbo.FCustPayments.FDBCNo, dbo.FCustPayments.DT AS FDBCDT,
                      1 AS EntryType, dbo.FCustPayments.EntryID, dbo.FCustPayments.BankID, dbo.BankList.Bank, dbo.BankList.Branch, '' AS AccNo,
                      dbo.FCustPayments.CustomPayment, dbo.FCustPayments.AdvEntryID, dbo.CustomInvoice.DT AS InvoiceDT,
                      dbo.FCustPayments.AmtRcvd AS TotalCommercialAmt, 0 AS TotalCommercialAmtRcvd, 0 AS CommercialAmtToRcv, 0 AS TotalCustomAmt,
                      0 AS TotalCustomAmtRcvd, 0 AS CustomAmtToRcv, dbo.FCustPayments.PRCVchrNo, dbo.FCustPayments.ExchRate,AWBNoDT,CustomInvoice.PaymentTerms,PaymentDays,Curr,0 AS FreeSamples,'MyGPNo' AS GatePassNo
FROM         dbo.FCustPayments INNER JOIN
                      dbo.CustomInvoice ON dbo.FCustPayments.CustomInvoice = dbo.CustomInvoice.CustomInvoice INNER JOIN
                      dbo.BankList ON dbo.FCustPayments.BankID = dbo.BankList.BankID
		INNER JOIN ForeignCustomers ON CustomInvoice.CustCode=ForeignCustomers.CustCode AND CustomInvoice.Country=ForeignCustomers.Country



