CREATE VIEW [dbo].[VCustomInvoice1]
AS
SELECT     dbo.CustomInvoice.*, dbo.ForeignCustomers.Name AS Name, dbo.ForeignCustomers.Address AS Address, VPorts_2.CountryName AS LoadCountry,
                      VPorts_2.CityID AS LoadCityID, VPorts_2.City AS LoadCity, VPorts_2.Port AS LoadPort, VPorts_1.CountryName AS DisCountry, VPorts_1.CityID AS DisCityID,
                      VPorts_1.City AS DisCity, VPorts_1.Port AS DisPort, dbo.BankList.Bank AS Bank, dbo.InsuranceAgents.Name AS InsuranceAgentsName,
                      dbo.ShippingAgents.Name AS ShippingAgentsName, dbo.ForeignCustomers.Curr AS Curr, dbo.ForeignCustomers.Cont1name AS Cont1Name,
                      dbo.ForeignCustomers.cont1phone AS Cont1Phone, dbo.Company.ExportNo AS ExportNo, dbo.VTotalCartons.TotalCartons AS TotalCartons,
                      dbo.VTotalCartons.TotalQty AS TotalQty, '123' AS NICNo
FROM         dbo.VTotalCartons RIGHT OUTER JOIN
                      dbo.CustomInvoice INNER JOIN
                      dbo.ForeignCustomers ON dbo.CustomInvoice.CustCode = dbo.ForeignCustomers.CustCode AND dbo.CustomInvoice.Country = dbo.ForeignCustomers.Country ON
                      dbo.VTotalCartons.CustomInvoice = dbo.CustomInvoice.CustomInvoice LEFT OUTER JOIN
                      dbo.ShippingAgents ON dbo.CustomInvoice.ShippingAgentID = dbo.ShippingAgents.EntryID LEFT OUTER JOIN
                      dbo.InsuranceAgents ON dbo.CustomInvoice.InsuranceAgentID = dbo.InsuranceAgents.EntryID LEFT OUTER JOIN
                      dbo.BankList ON dbo.CustomInvoice.OurBankID = dbo.BankList.BankID LEFT OUTER JOIN
                      dbo.VPorts VPorts_2 ON dbo.CustomInvoice.LoadPortID = VPorts_2.PortID LEFT OUTER JOIN
                      dbo.VPorts VPorts_1 ON dbo.CustomInvoice.DisPortID = VPorts_1.PortID CROSS JOIN
                      dbo.Company

