CREATE VIEW [dbo].[VrptFormE]
AS
SELECT     dbo.VTotalCartons.TotalCartons, dbo.VTotalCartons.TotalQty, dbo.VCustomInvoice1.CustomInvoice, dbo.VCustomInvoice1.DT, dbo.VCustomInvoice1.CustCode,
                      dbo.VCustomInvoice1.Country, dbo.VCustomInvoice1.AWBNo, dbo.VCustomInvoice1.AWBNoDT, dbo.VCustomInvoice1.FormE, dbo.VCustomInvoice1.FormEDT,
                      dbo.VCustomInvoice1.TradeTerms, dbo.VCustomInvoice1.PaymentTerms, dbo.VCustomInvoice1.LoadCountry, dbo.VCustomInvoice1.LoadCity,
                      dbo.VCustomInvoice1.LoadPort, dbo.VCustomInvoice1.DisCountry, dbo.VCustomInvoice1.DisCity, dbo.VCustomInvoice1.DisPort, dbo.VCustomInvoice1.Address,
                      dbo.VCustomInvoice1.Consignee, dbo.EForm.Qty, dbo.EForm.TermsOfSale, dbo.EForm.ShippingMode, dbo.EForm.ShipPort, dbo.EForm.LandCustom,
                      dbo.VCustomInvoice1.ManDischarge, dbo.Companies.NICNo, dbo.Companies.IssDT, dbo.Companies.Address AS CompanyAddress, dbo.Companies.CompanyName,
                      dbo.Companies.NTNNo, dbo.VCustomInvoice1.InvoiceOf, dbo.Companies.ExportRegNo, dbo.Companies.ExportRegNoDT, dbo.VCustomInvoiceAmt.TotalCustomAmt,
