CREATE VIEW [dbo].[VRM]
AS
SELECT     ISNULL(dbo.VRMAvgRate.AvgRate, 0) AS AvgRate, dbo.RMGroups.Description AS GroupName, dbo.RMGroups.GrpColor AS GroupColor, dbo.RM.RMID, dbo.RM.GroupID, dbo.RM.RMID1, dbo.RM.RMName, dbo.RM.Unit, dbo.RM.RMSize, dbo.RM.SizeUnit,
                  dbo.RM.Rate, dbo.RM.RMUsage, dbo.RM.AssetAccNo, dbo.RM.SaleAccNo, dbo.RM.SRTAccNo, dbo.RM.InActive, dbo.RM.ReorderPoint, dbo.RM.MinLevel, dbo.RM.MaxLevel, dbo.RM.OpeningStock, dbo.RM.Description, dbo.RM.MaterialCode,
                  dbo.RM.TechnicalDrawing, dbo.RM.Pic, dbo.RM.AnnealingStock, dbo.RM.MachiningStock, dbo.RM.UrduName, ISNULL(Tab1.QtyInStock, 0) AS QtyInStock, dbo.RM.RequiresMaleGrinding, dbo.RM.MaleGrindingStock,
                  dbo.RMGroupIDsForForging.Group_ID AS ForgingGroupID, Tab1.SheetsInStock, dbo.RM.Returnable, dbo.RM.Sampling, dbo.RM.MakerRate
				  ,dbo.RM.Weight_Length,dbo.RM.RM_Maker_Description
FROM        dbo.RM LEFT OUTER JOIN
                  dbo.RMGroupIDsForForging ON dbo.RM.GroupID = dbo.RMGroupIDsForForging.Group_ID LEFT OUTER JOIN
                  dbo.RMGroups ON dbo.RM.GroupID = dbo.RMGroups.ID LEFT OUTER JOIN
                  dbo.VRMAvgRate ON dbo.RM.RMID = dbo.VRMAvgRate.RMID LEFT OUTER JOIN
                      (SELECT     MaterialID, SUM(QtyPlaced - QtyIssued) AS QtyInStock, SUM(ISNULL(SheetsPlaced, 0) - ISNULL(SheetsIssued, 0)) AS SheetsInStock
                       FROM        dbo.VMaterialLocationWiseStatus
                       GROUP BY MaterialID) AS Tab1 ON dbo.RM.RMID1 = Tab1.MaterialID
