FROM            dbo.VRM
UNION
SELECT        0 AS RMID, ItemID, ItemName, Unit, CAST(1 AS BIT) AS CCItem, 0 AS GroupID, ItemSize, 0 AS Rate, '' AS RMUsage, SizeUnit, TipSize, 0 AS RequiresMaleGrinding, 0 AS ForgingGroupID, Sample,ItemNameUrdu AS RMUrduName
FROM            Items

