SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VMaterialsForPlacement]
AS
SELECT        dbo.VendRcvd.VendID, dbo.VendRcvdDetailPO.RcvID, dbo.VendRcvdDetailPO.MaterialID, dbo.VRMAndItemsUnioned.RMName, dbo.VRMAndItemsUnioned.Unit, dbo.VendRcvdDetailPO.EntryID,
                         ISNULL(TabPlaced.QtyPlaced, 0) AS QtyPlaced, dbo.VVendersAndMakers.AccTitle, dbo.VendRcvd.RcvDate, ISNULL(dbo.VendRcvdDetailPO.QtyRcvd, 0) - ISNULL(TabRej.QtyRejected, 0)
                         + dbo.VendRcvdDetailPO.ExtraQtyRcvd AS QtyPassed, dbo.VendOrderDetail.Qty * dbo.VendOrderDetail.Rate AS Rate, dbo.VendRcvdDetailPO.PORefNo, dbo.VRMAndItemsUnioned.RMID1,
                         dbo.VendRcvdDetailPO.Sheets - ISNULL(TabRej.SheetsRejected, 0) AS Sheets, ISNULL(TabPlaced.SheetsPlaced, 0) AS SheetsPlaced, TabRej.QtyRejected, TabRej.SheetsRejected,
                         dbo.VRMAndItemsUnioned.Sample, dbo.VendOrderDetail.CCItem, dbo.RcvItemsSimpleDetail.EntryID AS RISD_EntryID
FROM            dbo.VendRcvd INNER JOIN
                         dbo.VendRcvdDetailPO ON dbo.VendRcvd.RcvID = dbo.VendRcvdDetailPO.RcvID INNER JOIN
                         dbo.VRMAndItemsUnioned ON dbo.VendRcvdDetailPO.MaterialID = dbo.VRMAndItemsUnioned.RMID1 INNER JOIN
                         dbo.VendOrderDetail ON dbo.VendRcvdDetailPO.PORefNo = dbo.VendOrderDetail.OrderNo AND dbo.VendRcvdDetailPO.MaterialID = dbo.VendOrderDetail.RMID AND
                         dbo.VRMAndItemsUnioned.CCItem = dbo.VendOrderDetail.CCItem INNER JOIN
                         dbo.VendOrders ON dbo.VendOrderDetail.OrderNo = dbo.VendOrders.OrderNo INNER JOIN
                         dbo.VVendersAndMakers ON dbo.VendRcvd.VendID = dbo.VVendersAndMakers.AccNo LEFT OUTER JOIN
                         dbo.RcvItemsSimpleDetail ON dbo.VendRcvdDetailPO.EntryID = dbo.RcvItemsSimpleDetail.VRDPO_RefID LEFT OUTER JOIN
                             (SELECT        Rcvd_RefID, SUM(QtyPlaced) AS QtyPlaced, SUM(SheetsPlaced) AS SheetsPlaced
                               FROM            dbo.MaterialLocationwiseStatus
                               GROUP BY Rcvd_RefID) AS TabPlaced ON dbo.VendRcvdDetailPO.EntryID = TabPlaced.Rcvd_RefID LEFT OUTER JOIN
                             (SELECT        VRDPO_RefID, SUM(QtyRejected) AS QtyRejected, SUM(SheetsRejected) AS SheetsRejected
                               FROM            dbo.VendRcvdDetailPO_Rejection_Detail
                               GROUP BY VRDPO_RefID) AS TabRej ON dbo.VendRcvdDetailPO.EntryID = TabRej.VRDPO_RefID
WHERE        (dbo.VendRcvd.RcvID NOT IN
                             (SELECT        RcvID
                               FROM            dbo.RcvIDsToIgnoreForPlacement))

GO
