CREATE VIEW [dbo].[VVendIssRepair2]
AS
SELECT     dbo.VendRcvdDetail.ItemCode, dbo.VOwnRepairVenders.VendID, SUM(dbo.VendRcvdDetail.RcvRepairQty - dbo.VendRcvdDetail.IssRepairQty)
                      AS RepairQty
FROM         dbo.VendRcvdDetail INNER JOIN
                      dbo.VVendIssRepair3 ON dbo.VendRcvdDetail.RecieptID = dbo.VVendIssRepair3.RecieptID LEFT OUTER JOIN
                      dbo.VOwnRepairVenders ON dbo.VVendIssRepair3.VendID = dbo.VOwnRepairVenders.VendID
WHERE     (dbo.VendRcvdDetail.RcvRepairQty IS NOT NULL)
GROUP BY dbo.VendRcvdDetail.ItemCode, dbo.VOwnRepairVenders.VendID
HAVING      (SUM(dbo.VendRcvdDetail.RcvRepairQty - dbo.VendRcvdDetail.IssRepairQty) > 0)

