                      Employees_2.name AS EmpName, Employees_1.name AS AuthByName, dbo.VRM.ForgingGroupID AS ForgingGroupID,
                      dbo.VRM.RequiresMaleGrinding AS RequiresMaleGrinding, dbo.VVendersAndMakers.AccTitle AS AccTitle, dbo.VIssued.RMID1, dbo.VIssued.Qty, dbo.VIssued.InHand,
                      dbo.VIssued.StoreName, dbo.VIssued.Price, dbo.VIssued.ChildEntryID, dbo.VIssued.Sheets, dbo.VIssued.EntryID, dbo.VIssued.IssNo, dbo.VIssued.DT,
                      dbo.VIssued.EntryDT, dbo.VIssued.UserName, dbo.VIssued.ComputerName, dbo.VIssued.VI_RefID, dbo.VIssued.IssdToEmpID, dbo.VIssued.AuthorizedByEmpID,
                      dbo.VIssued.VchrNo, dbo.VIssued.VO_OrderNo, dbo.VIssued.Remarks
