CREATE VIEW [dbo].[VVendOrders]
AS
SELECT     dbo.VendOrders.OrderNo, dbo.VendOrders.DT, dbo.VendOrders.VendID, dbo.VendOrders.AttnPerson, dbo.VendOrders.PaymentTerms, dbo.VendOrders.Department,
                      dbo.VendOrders.DeliveryDT, dbo.VendOrders.Remarks, dbo.VendOrders.ReqNo, dbo.VendOrders.VeryUrgent, dbo.VendOrders.Final, dbo.VendOrderDetail.Rate,
                      dbo.VendOrderDetail.Qty, dbo.VRMAndItemsUnioned.GroupID, dbo.VRMAndItemsUnioned.RMID1, dbo.VRMAndItemsUnioned.RMName,
                      dbo.VRMAndItemsUnioned.Unit, dbo.VRMAndItemsUnioned.RMSize, dbo.VRMAndItemsUnioned.SizeUnit, dbo.VRMAndItemsUnioned.Rate AS RMRate,
                      dbo.VRMAndItemsUnioned.RMUsage, dbo.VendOrders.EntryID, dbo.VVendersAndMakers.AccTitle, dbo.VendOrderDetail.EntryID AS VendOrderDetailEntryID,
                      dbo.VendOrders.IssuanceType, dbo.VendOrders.RunningPONo, dbo.VendOrders.Ref, dbo.VendOrders.Payments, dbo.VendOrders.Shipment,
                      dbo.VendOrders.Instructions, dbo.VendOrders.Notes, dbo.VendOrders.Currency, dbo.VendOrders.SampleProvided, dbo.VendOrders.SampleProvidedDescription,
                      dbo.VendOrders.DrawingProvided, dbo.VendOrders.DrawingProvidedDescription, dbo.VendOrders.SteelProvided, dbo.VendOrders.SteelProvidedDescription,
                      dbo.RMGroupsForTwoUnits.OtherUnit, dbo.RMGroupsForTwoUnits.EntryID AS OtherUnitEntryID, dbo.VendOrders.POType, dbo.VendOrderDetail.CCItem,
                      dbo.LastRMPOQty_F(dbo.VendOrderDetail.EntryID, dbo.VendOrderDetail.RMID, dbo.VendOrders.VendID) AS LastRate, dbo.VendOrders.CustomerPONo,
                      dbo.VendOrders.SteelType_RefID, T1.VOD_RefID, dbo.VendOrders.SampleOrder,dbo.VendOrders.Order_Collection_By
                      ,dbo.VendorderDetail.ItemRemarks
FROM         dbo.VendOrders INNER JOIN
                      dbo.VendOrderDetail ON dbo.VendOrders.OrderNo = dbo.VendOrderDetail.OrderNo INNER JOIN
                      dbo.VRMAndItemsUnioned ON dbo.VendOrderDetail.RMID = dbo.VRMAndItemsUnioned.RMID1 AND
                      dbo.VendOrderDetail.CCItem = dbo.VRMAndItemsUnioned.CCItem INNER JOIN
                      dbo.VVendersAndMakers ON dbo.VendOrders.VendID = dbo.VVendersAndMakers.AccNo LEFT OUTER JOIN
                      dbo.RMGroupsForTwoUnits ON dbo.VRMAndItemsUnioned.GroupID = dbo.RMGroupsForTwoUnits.RMG_RefID LEFT OUTER JOIN
                          (SELECT     VOD_RefID
                             FROM         dbo.VendOrderDetail_PDF
                             GROUP BY VOD_RefID) AS T1 ON dbo.VendOrderDetail.EntryID = T1.VOD_RefID

