/****** Object:  View [dbo].[VStockLedger]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VStockLedger]
AS
SELECT        TransactionID, TransactionDate, MaterialID, Description, Reference, Quantity, TransactionType, Rate, UserName, RecieptID, IssuanceType, POIssuance, Sheets
FROM            (SELECT        IssNo AS TransactionID, DT AS TransactionDate, RMID1 AS MaterialID, 'Issued to ' + IssdToEmpID AS Description, CASE WHEN VO_OrderNo <> '' THEN AccTitle ELSE CASE WHEN ISNULL(IssdToEmpID, '')
                                                    = '' THEN VenderName ELSE EmpName END END AS Reference, - Qty AS Quantity, 0 AS TransactionType, 0 AS Rate, UserName, CASE WHEN VI_RefID = 0 THEN VO_OrderNo ELSE RecieptID END AS RecieptID,
                                                    CASE WHEN ForgingGroupID IS NOT NULL THEN CASE WHEN RequiresMaleGrinding = 1 THEN 3 ELSE 2 END ELSE 0 END AS IssuanceType, 0 AS POIssuance, Sheets
                          FROM            dbo.VMaterialIssued
                          UNION ALL
                          SELECT        RcvID, RcvDate AS TransactionDate, MaterialID, Description, Name, NetQtyRcvd, TransactionType, Rate, StoreRcvdUserName AS UserName, OrderNo AS RecieptID, IssuanceType, 0 AS POIssuance, Sheets
                          FROM            dbo.VStockRcvd
                          UNION ALL
                          SELECT        OrderNo, DT AS TransactionDate, RMID1 AS MaterialID, 'PO Issuance @ ' + CASE IssuanceType WHEN 1 THEN 'Annealing' WHEN 2 THEN 'Machining' WHEN 3 THEN 'Male Grinding' END AS Expr1, AccTitle,
                                                   - Qty AS Expr2, 0 AS TransactionType, Rate, '' AS UserName, OrderNo AS RecieptID, IssuanceType, 1 AS POIssuance, 0 AS Sheets
                          FROM            dbo.VVendOrders
                          WHERE        (IssuanceType <> 0)
                          UNION ALL
                          SELECT        OrderNo, DT AS TransactionDate, MaterialID, 'Rejection ' AS Description, AccTitle, - QtyRejected AS Qty, 0 AS TransactionType, Rate, UserName, RcvID, 0 AS IssuanceType, 0 AS POIssuance, SheetsRejected
                          FROM            dbo.VVendRcvdDetailPO_Rejection_Detail) AS StockLedger
GO
