CREATE VIEW [dbo].[VCombinedOrderReportItemwise]
AS
SELECT     dbo.FCustomerOrders.CustCode, dbo.FCustomerOrders.Country, dbo.FCustomerOrders.OrderNo, dbo.Items.ItemID, dbo.Items.ItemName,
                      dbo.ItemGroups.Description AS GroupName, FOrderItems.DeliveryDT, FOrderItems.ItemCode, TShipped.CustomInvoice, TShipped.ShippedQty, TShipped.AWBNoDT,
                      FOrderItems.OrderQty, dbo.FCustomerOrders.DT, dbo.Items.GroupID
FROM         dbo.FCustomerOrders INNER JOIN
                          (SELECT     OrderNo, CompItemCode, ItemCode, DeliveryDT, SUM(Qty) AS OrderQty
                             FROM         dbo.FOrderItems
                             GROUP BY OrderNo, CompItemCode, ItemCode, DeliveryDT) FOrderItems ON dbo.FCustomerOrders.OrderNo = FOrderItems.OrderNo INNER JOIN
                      dbo.Items ON FOrderItems.CompItemCode = dbo.Items.ItemID INNER JOIN
                      dbo.ItemGroups ON dbo.Items.GroupID = dbo.ItemGroups.ID INNER JOIN
                      dbo.VUnshippedOrderList ON dbo.FCustomerOrders.OrderNo = dbo.VUnshippedOrderList.OrderNo LEFT OUTER JOIN
                          (SELECT     CustomInvoice, AWBNoDT, OrderNo, CompItemCode, DeliveryDTItem, SUM(Qty) AS ShippedQty
                             FROM         dbo.VCustomInvoiceItems
                             GROUP BY CustomInvoice, AWBNoDT, OrderNo, CompItemCode, DeliveryDTItem) TShipped ON FOrderItems.OrderNo = TShipped.OrderNo AND
                      FOrderItems.CompItemCode = TShipped.CompItemCode AND FOrderItems.DeliveryDT = TShipped.DeliveryDTItem

