CREATE VIEW [dbo].[VCommercialInvoice]
AS
SELECT     dbo.FOrderItems.ID, dbo.FOrderItems.ItemCode, dbo.FOrderItems.Price, dbo.FOrderItems.Qty, dbo.FOrderItems.InvQty, dbo.ForeignCustomers.Curr,
                      dbo.ForeignCustomers.Name, dbo.ForeignCustomers.Address, VPorts_2.CountryName AS LoadCountry, VPorts_2.CityID AS LoadCityID,
                      VPorts_2.City AS LoadCity, VPorts_2.PortID AS LoadPortID, VPorts_2.Port AS LoadPort, VPorts_1.CountryName AS DisCountry,
                      VPorts_1.CityID AS DisCityID, VPorts_1.City AS DisCity, VPorts_1.PortID AS DisPortID, VPorts_1.Port AS DisPort, dbo.FPInvoice.PInvoice,
                      dbo.FPInvoice.DT, dbo.FPInvoice.CustCode, dbo.FPInvoice.Country, dbo.FPInvoice.SMethod, dbo.FPInvoice.TradeTerms,
                      dbo.FPInvoice.PaymentTerms, dbo.FPInvoice.BankID, dbo.FPInvoice.PartialShipment, dbo.FPInvoice.TransShipment, dbo.FPInvoice.packaging,
                      dbo.FPInvoice.DeliveryDT, dbo.FOrderItems.OrderNo, dbo.ForeignCustomers.Cont1name, dbo.ForeignCustomers.DTFormat,
                      dbo.FCustBanks.BankName, dbo.FCustBanks.Address1, dbo.F_ProformaAmt(dbo.FPInvoice.PInvoice) AS TotAmt,
                      dbo.F_CustomAmt(dbo.FPInvoice.PInvoice) AS TotCustomAmt, dbo.FPInvoice.Marks, dbo.FPInvoice.Measurement, dbo.FPInvoice.SpecialInstr,
                      dbo.FPInvoice.GrossW, dbo.FPInvoice.NetW, dbo.FPInvoice.Goods, dbo.FPInvoice.ShippingAgent AS ShippingAgentID,
                      dbo.FPInvoice.InsuranceAgent AS InsuranceAgentID, dbo.FPInvoice.LCNo, dbo.F_ProformaOrders(dbo.FPInvoice.PInvoice) AS ProformaOrders,
                      dbo.F_ProformaOrderDates(dbo.FPInvoice.PInvoice) AS ProformaOrderDates, dbo.FOrderItems.CustomPrice, dbo.FProformaOrders.Qty AS ProformaQty,
                      dbo.FPInvoice.BatchNo, dbo.FPInvoice.Declarations, dbo.FPInvoice.PInvoiceID, dbo.ForeignCustomers.FakeAddress, dbo.CustomInvoice.FormE,
                      dbo.CustomInvoice.AWBNo, dbo.CustomInvoice.AWBNoDT, dbo.F_PerIncrease(dbo.FProformaOrders.Qty) - dbo.FProformaOrders.Qty AS FreeStock,
                      dbo.CustomInvoice.Vessel, dbo.CustomInvoice.DT AS CustomInvoiceDT, dbo.FCustBanks.Address2,
                      dbo.CustomInvoice.Declarations AS CustomDeclarations, dbo.CustomInvoice.CommercialDeclarations
FROM         dbo.FProformaOrders INNER JOIN
                      dbo.FPInvoice ON dbo.FProformaOrders.PInvoice = dbo.FPInvoice.PInvoice INNER JOIN
                      dbo.FOrderItems ON dbo.FProformaOrders.OrderEntryID = dbo.FOrderItems.ID INNER JOIN
                      dbo.ForeignCustomers ON dbo.FPInvoice.CustCode = dbo.ForeignCustomers.CustCode AND
                      dbo.FPInvoice.Country = dbo.ForeignCustomers.Country INNER JOIN
                      dbo.CustomInvoice ON dbo.FPInvoice.PInvoice = dbo.CustomInvoice.CustomInvoice LEFT OUTER JOIN
                      dbo.FCustBanks ON dbo.FPInvoice.BankID = dbo.FCustBanks.BankID LEFT OUTER JOIN
                      dbo.VPorts VPorts_1 ON dbo.FPInvoice.DischargePort = VPorts_1.PortID LEFT OUTER JOIN
                      dbo.VPorts VPorts_2 ON dbo.FPInvoice.LoadPort = VPorts_2.PortID

GO
/****** Object:  UserDefinedFunction [dbo].[LateComingHrs_Datewise_Fn]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO


CREATE Function [dbo].[LateComingHrs_Datewise_Fn] (@DT DATETIME) RETURNS TABLE
AS
RETURN
(
--SELECT T1.EmpID,DT, DATEDIFF(n,EnterTime,InTime)/60.00 AS LateComingHrs FROM VEmpSettings
--INNER JOIN (
--SELECT EmpID,DT,InTime FROM EmpTimes
--INNER JOIN (SELECT MIN(EmpTimes.EntryID) AS EntryID FROM EmpTimes LEFT JOIN Leaves ON EmpTimes.EmpID=Leaves.EmpID AND EmpTimes.DT=Leaves.DT WHERE (MONTH(EmpTimes.DT) = MONTH(@DT) AND YEAR(EmpTimes.DT) = YEAR(@DT) AND EmpTimes.DT <=@DT) AND Leaves.EmpID IS NULL GROUP BY EmpTimes.EmpID,EmpTimes.DT) TInner ON EmpTimes.EntryID=TInner.EntryID) T1 ON VEmpSettings.EmpID=T1.EmpID

--WHERE (MONTH(DT)=MONTH(@DT) AND YEAR(DT) = YEAR(@DT) AND DT <=@DT)

--AND DATEDIFF(n,DateAdd(n,CAST(LateDeductionAfter AS INT),EnterTime),InTime)>0
--AND VEmpSettings.LateDeduction=1

SELECT T1.EmpID,DT, DATEDIFF(n,EnterTime,InTime)/60.00 AS LateComingHrs FROM VEmpSettings
INNER JOIN (
SELECT EmpID,DT,InTime FROM EmpTimes
INNER JOIN (SELECT MIN(EmpTimes.EntryID) AS EntryID FROM EmpTimes LEFT JOIN Leaves ON EmpTimes.EmpID=Leaves.EmpID AND EmpTimes.DT=Leaves.DT WHERE (MONTH(EmpTimes.DT) = MONTH(@DT) AND YEAR(EmpTimes.DT) = YEAR(@DT) AND EmpTimes.DT <=@DT) AND Leaves.EmpID IS NULL GROUP BY EmpTimes.EmpID,EmpTimes.DT) TInner ON EmpTimes.EntryID=TInner.EntryID) T1 ON VEmpSettings.EmpID=T1.EmpID

WHERE (MONTH(DT)=MONTH(@DT) AND YEAR(DT) = YEAR(@DT) AND DT <=@DT)
AND DT NOT IN (SELECT DT FROM Holidays) AND (DateName(WeekDay,DT)<>'Sunday')

AND DATEDIFF(n,DateAdd(n,CAST(LateDeductionAfter AS INT),EnterTime),InTime)>0
AND VEmpSettings.LateDeduction=1)

GO
/****** Object:  UserDefinedFunction [dbo].[FHrsWorked]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO




CREATE FUNCTION [dbo].[FHrsWorked](@ParDate DATETIME)
RETURNS TABLE AS
RETURN(
SELECT EmpID, ROUND(SUM(CASE WHEN PayableHrs>8 THEN 8 ELSE ROUND(PayableHrs,6) END),6)  AS HrsWorked
FROM (SELECT VEmpTimes2.EmpID,VEmpTimes2.DT
	--,CASE WHEN DATENAME(WEEKDAY,VEmpTimes2.DT)='Saturday' THEN 8-ISNULL(TLate.LateComingHrs,0) ELSE PayableHrs END AS PayableHrs
	,PayableHrs
	FROM VEmpTimes2
	LEFT JOIN dbo.LateComingHrs_Datewise_Fn(@ParDate) AS TLate ON VEmpTimes2.EmpID=TLate.EmpID AND VEmpTimes2.DT=TLate.DT
	LEFT JOIN Holidays ON VempTimes2.DT=Holidays.DT
		WHERE (MONTH(VEmpTimes2.DT) = MONTH(@ParDate) AND YEAR(VEmpTimes2.DT) = YEAR(@ParDate) AND VEmpTimes2.DT<=@ParDATE )
		AND DATENAME(WEEKDAY,VEmpTimes2.DT)<>'Sunday'
		AND Holidays.DT IS NULL
		--AND VEmpTimes2.DT NOT IN(SELECT DT FROM Holidays)
		) T1
		GROUP BY EmpID)
GO
