CREATE VIEW [dbo].[VrptProformas]
AS
SELECT     dbo.FOrderItems.ID, dbo.FOrderItems.ItemCode, dbo.FProformaOrders.Price, dbo.FOrderItems.Qty, dbo.FOrderItems.InvQty, dbo.Items.ItemName, dbo.FCustomerCatalog.Description, dbo.FCustomerCatalog.ItemID, dbo.FCustomerCatalog.CompItemID,
                  dbo.ForeignCustomers.Curr, dbo.FCustomerCatalog.Unit, dbo.ForeignCustomers.Name, dbo.ForeignCustomers.Address, VPorts_2.CountryName AS LoadCountry, VPorts_2.CityID AS LoadCityID, VPorts_2.City AS LoadCity, VPorts_2.PortID AS LoadPortID,
                  VPorts_2.Port AS LoadPort, VPorts_1.CountryName AS DisCountry, VPorts_1.CityID AS DisCityID, VPorts_1.City AS DisCity, VPorts_1.PortID AS DisPortID, VPorts_1.Port AS DisPort, dbo.FPInvoice.PInvoice, dbo.FPInvoice.DT, dbo.FPInvoice.CustCode,
                  dbo.FPInvoice.Country, dbo.FPInvoice.SMethod, dbo.FPInvoice.TradeTerms, dbo.FPInvoice.PaymentTerms, dbo.FPInvoice.BankID, dbo.FPInvoice.PartialShipment, dbo.FPInvoice.TransShipment, dbo.FPInvoice.packaging,
                  dbo.FPInvoice.DeliveryDT AS ProformaDeliveryDT, dbo.FOrderItems.OrderNo, dbo.ForeignCustomers.Cont1name, dbo.ForeignCustomers.DTFormat, dbo.FCustBanks.BankName, dbo.FCustBanks.Address1, dbo.FCustomerCatalog.PackingMode,
                  dbo.F_ProformaAmt(dbo.FPInvoice.PInvoice) AS TotAmt, dbo.F_CustomAmt(dbo.FPInvoice.PInvoice) AS TotCustomAmt, dbo.FPInvoice.Marks, dbo.FPInvoice.Measurement, dbo.FPInvoice.SpecialInstr, dbo.FPInvoice.GrossW, dbo.FPInvoice.NetW, dbo.FPInvoice.Goods,
                  dbo.ShippingAgents.Name AS ShippingAgentName, dbo.InsuranceAgents.Name AS InsuranceAgentName, dbo.FPInvoice.ShippingAgent AS ShippingAgentID, dbo.FPInvoice.InsuranceAgent AS InsuranceAgentID, dbo.FPInvoice.LCNo,
                  dbo.F_ProformaOrders(dbo.FPInvoice.PInvoice) AS ProformaOrders, dbo.F_ProformaOrderDates(dbo.FPInvoice.PInvoice) AS ProformaOrderDates, dbo.VItems1.CompleteItemName, dbo.FProformaOrders.CustomPrice, dbo.FProformaOrders.Qty AS ProformaQty,
                  dbo.FPInvoice.BatchNo, dbo.ForeignCustomers.FakeAddress, dbo.CustomInvoice.FormE, dbo.CustomInvoice.AWBNoDT, dbo.F_PerIncrease(dbo.FProformaOrders.Qty) - dbo.FProformaOrders.Qty AS FreeStock, dbo.CustomInvoice.Vessel,
                  dbo.ItemCatagories.Description AS ItemCatagory, dbo.CustomInvoice.DT AS CustomInvoiceDT, dbo.FCustBanks.Address2, dbo.ItemCatagories.SRONo, dbo.FPInvoice.OurBankID, dbo.FCustomerOrders.DeliveryDT, dbo.FPInvoice.InvoiceOf,
                  dbo.FCustomerOrders.DT AS OrderDate, dbo.Items.ItemSize, dbo.Items.ItemColor, dbo.Items.SizeUnit, dbo.Companies.CompanyName, dbo.FProformaOrders.EntryID, dbo.ItemCatagories.HSCode, dbo.Items.Type, dbo.FCustBanks.BankCountry,
                  dbo.FCustomerCatalog.StampInstructions, dbo.FCustomerCatalog.SpecialInstructions, dbo.FCustomerCatalog.PackingInstructions, dbo.FCustomerCatalog.ItemColor AS CustomerItemColor, dbo.FCustomerCatalog.BarcodeNo, dbo.ForeignCustomers.AgentName,
                  dbo.Items.ItemPic, dbo.Items.FinishedWeight, dbo.BankList.Remittance, dbo.FPInvoice.Packages, dbo.FPInvoice.ShippingAddress, dbo.FPInvoice.DeliveryDetail, dbo.BankList.AccNo, dbo.ForeignCustomers.City AS CustomerCity, dbo.FOrderItems.SortNo,
                  dbo.ForeignCustomers.ShowCustomerRef, dbo.FOrderItems.DeliveryDT AS DeliveryDTItem, dbo.FPInvoice.Notes1, dbo.FPInvoice.Notes2, dbo.FProformaOrders.Item_Highlight, dbo.FProformaOrders.ItemDescription, dbo.FPInvoice.DiscountPer,
                  dbo.FPInvoice.DiscountAmount, dbo.FPInvoice.Insurance_Freight_Amount, dbo.FPInvoice.Insurance_Freight_Amount_II, dbo.FPInvoice.Discount_Description, dbo.FPInvoice.Insurance_Description, dbo.FPInvoice.Insurance_Description_II,
                  dbo.FPInvoice.CIF_Description, dbo.FPInvoice.Total_Description, dbo.FCustomerOrders.OrderRcvdVia, dbo.FOrderItems.Remarks, dbo.FOrderItems.Item_Finishing_Type, dbo.Item_Finishing_Type.Item_Finishing_Type_Text, dbo.FPInvoice.CompanyRefID,
                  dbo.Company.Address AS CompAddress, dbo.Company.FDANo, dbo.FOrderItems.IW_OrderNo, dbo.FOrderItems.IW_BatchNo, dbo.FOrderItems.DeliveryDT AS ItemDeliveryDT, dbo.Items.FDAListingNo, dbo.Items.FDAProductCode, dbo.SROs.SroNo AS SRNo,
                  dbo.SROs.CompleteNo AS CompleteSRONo, dbo.SROs.Description AS SRODesccription, dbo.BankList.Branch, dbo.BankList.City, dbo.BankList.Address AS BankAddress, dbo.BankList.Bank, dbo.BankList.Manager AS IBANNo, dbo.BankList.Remittance AS SwiftCode,
                  dbo.ForeignCustomers.Fax2 AS VatNo, dbo.ForeignCustomers.Fax3 AS EORINo, dbo.FPInvoice.Declarations, dbo.ForeignCustomers.FC_Note_I, dbo.ForeignCustomers.FC_Note_II, dbo.FPInvoice.InvoiceTo, dbo.FOrderItems.Weight, dbo.FOrderItems.Stamps,
                  dbo.FCustomerOrders.InternalRefNo AS InternalOrderNo, TItemDeliveryDT.ItemDeliveryDT AS ItemDeliveryDT_Max, dbo.ForeignCustomers.cont1phone, dbo.CustomInvoice.AWBNo, dbo.ForeignCustomers.Stamps AS Expr1, dbo.Items.MakerDescription,
                  dbo.CustomInvoice.ShippingMode, dbo.Company.CompanyName AS Expr2
FROM        dbo.Items INNER JOIN
                  dbo.FCustomerCatalog ON dbo.Items.ItemID = dbo.FCustomerCatalog.CompItemID INNER JOIN
                  dbo.FPInvoice ON dbo.FCustomerCatalog.CustCode = dbo.FPInvoice.CustCode AND dbo.FCustomerCatalog.Country = dbo.FPInvoice.Country INNER JOIN
                  dbo.FProformaOrders ON dbo.FPInvoice.PInvoice = dbo.FProformaOrders.PInvoice INNER JOIN
                  dbo.FOrderItems ON dbo.FProformaOrders.OrderEntryID = dbo.FOrderItems.ID AND dbo.FCustomerCatalog.CompItemID = dbo.FOrderItems.CompItemCode INNER JOIN
                  dbo.ForeignCustomers ON dbo.FPInvoice.CustCode = dbo.ForeignCustomers.CustCode AND dbo.FPInvoice.Country = dbo.ForeignCustomers.Country INNER JOIN
                  dbo.ItemCatagories ON dbo.Items.CatID = dbo.ItemCatagories.CatID INNER JOIN
                  dbo.FCustomerOrders ON dbo.FOrderItems.OrderNo = dbo.FCustomerOrders.OrderNo AND dbo.ForeignCustomers.CustCode = dbo.FCustomerOrders.CustCode AND dbo.ForeignCustomers.Country = dbo.FCustomerOrders.Country INNER JOIN
                  dbo.Companies ON dbo.FPInvoice.CompanyRefID = dbo.Companies.EntryID INNER JOIN
                  dbo.VItems1 ON dbo.FCustomerCatalog.CompItemID = dbo.VItems1.ItemID LEFT OUTER JOIN
                  dbo.Item_Finishing_Type ON dbo.FOrderItems.Item_Finishing_Type = dbo.Item_Finishing_Type.EntryID LEFT OUTER JOIN
                  dbo.BankList ON dbo.FPInvoice.OurBankID = dbo.BankList.BankID LEFT OUTER JOIN
                  dbo.CustomInvoice ON dbo.FPInvoice.PInvoice = dbo.CustomInvoice.CustomInvoice LEFT OUTER JOIN
                  dbo.InsuranceAgents ON dbo.FPInvoice.InsuranceAgent = dbo.InsuranceAgents.EntryID LEFT OUTER JOIN
                  dbo.ShippingAgents ON dbo.FPInvoice.ShippingAgent = dbo.ShippingAgents.EntryID LEFT OUTER JOIN
                  dbo.FCustBanks ON dbo.FPInvoice.BankID = dbo.FCustBanks.BankID LEFT OUTER JOIN
                  dbo.VPorts AS VPorts_1 ON dbo.FPInvoice.DischargePort = VPorts_1.PortID LEFT OUTER JOIN
                  dbo.VPorts AS VPorts_2 ON dbo.FPInvoice.LoadPort = VPorts_2.PortID LEFT OUTER JOIN
                  dbo.Company ON dbo.Companies.CompanyName = dbo.Company.CompanyName LEFT OUTER JOIN
                  dbo.SROs ON dbo.ItemCatagories.SRONo = dbo.SROs.EntryID LEFT OUTER JOIN
                      (SELECT     OrderNo, MAX(DeliveryDT) AS ItemDeliveryDT
                       FROM        dbo.FOrderItems AS FOrderItems_1
                       GROUP BY OrderNo) AS TItemDeliveryDT ON dbo.FCustomerOrders.OrderNo = TItemDeliveryDT.OrderNo
GO
