CREATE VIEW [dbo].[VProformaItems]
AS
SELECT     dbo.FPInvoice.PInvoice, dbo.FOrderItems.OrderNo, dbo.FOrderItems.ItemCode, dbo.FOrderItems.ID, dbo.FProformaOrders.Qty,
                      dbo.FCustomerOrders.DeliveryDT, ISNULL(dbo.DHRDetail.ExtraPer, 0) AS ExtraPer
FROM         dbo.FPInvoice INNER JOIN
                      dbo.FProformaOrders ON dbo.FPInvoice.PInvoice = dbo.FProformaOrders.PInvoice INNER JOIN
                      dbo.FOrderItems ON dbo.FProformaOrders.OrderEntryID = dbo.FOrderItems.ID INNER JOIN
                      dbo.FCustomerOrders ON dbo.FOrderItems.OrderNo = dbo.FCustomerOrders.OrderNo LEFT OUTER JOIN
                      dbo.DHRDetail ON dbo.FPInvoice.PInvoice = dbo.DHRDetail.PInvoice AND dbo.FOrderItems.ItemCode = dbo.DHRDetail.ItemCode AND
                      dbo.FOrderItems.OrderNo = dbo.DHRDetail.OrderNo

