/****** Object:  View [dbo].[VFOrderSteelWeight1]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VFOrderSteelWeight1]
AS
SELECT     TOP 100 PERCENT dbo.VProformaItems.PInvoice, SUM((dbo.VProformaItems.Qty + dbo.VProformaItems.ExtraPer) * dbo.Items.ForgingWeight)
                      / 1000 AS TotalWeight, dbo.Items.SteelUsed
FROM         dbo.VProformaItems INNER JOIN
                      dbo.Items ON dbo.VProformaItems.ItemCode = dbo.Items.ItemID
WHERE     (dbo.VProformaItems.ItemCode <> '000000')
GROUP BY dbo.VProformaItems.PInvoice, dbo.Items.SteelUsed
ORDER BY dbo.VProformaItems.PInvoice

