CREATE VIEW [dbo].[VrptSales]
AS
SELECT     dbo.rptSales.*,
                          (SELECT     SUM(Period1 + Period2 + Period3 + Period4 + Period5 + Period6 + Period7 + Period8 + Period9 + Period10 + Period11 + Period12)
                            FROM          rptSales INNER JOIN VAccountGroupsForExpenseReport ON rptSales.Customer=VAccountGroupsForExpenseReport.AccNo WHERE Type=1) AS TotalIncome,
                          (SELECT     SUM(Period1 + Period2 + Period3 + Period4 + Period5 + Period6 + Period7 + Period8 + Period9 + Period10 + Period11 + Period12)
                            FROM          rptSales INNER JOIN VAccountGroupsForExpenseReport ON rptSales.Customer=VAccountGroupsForExpenseReport.AccNo WHERE Type=0) AS TotalExpense,
 dbo.rptSalesPrevious.Period1 AS Period1Prev, dbo.rptSalesPrevious.Period2 AS Period2Prev,
                      dbo.rptSalesPrevious.Period3 AS Period3Prev, dbo.rptSalesPrevious.Period4 AS Period4Prev, dbo.rptSalesPrevious.Period5 AS Period5Prev,
                      dbo.rptSalesPrevious.Period6 AS Period6Prev, dbo.rptSalesPrevious.Period7 AS Period7Prev, dbo.rptSalesPrevious.Period8 AS Period8Prev,
                      dbo.rptSalesPrevious.Period9 AS Period9Prev, dbo.rptSalesPrevious.Period10 AS Period10Prev, dbo.rptSalesPrevious.Period11 AS Period11Prev,
                      dbo.rptSalesPrevious.Period12 AS Period12Prev,
                          (SELECT     SUM(Period1 + Period2 + Period3 + Period4 + Period5 + Period6 + Period7 + Period8 + Period9 + Period10 + Period11 + Period12)
                            FROM          rptSalesPrevious INNER JOIN VAccountGroupsForExpenseReport ON rptSalesPrevious.Customer=VAccountGroupsForExpenseReport.AccNo WHERE Type=1) AS TotalPrevIncome,
                          (SELECT     SUM(Period1 + Period2 + Period3 + Period4 + Period5 + Period6 + Period7 + Period8 + Period9 + Period10 + Period11 + Period12)
                            FROM          rptSalesPrevious INNER JOIN VAccountGroupsForExpenseReport ON rptSalesPrevious.Customer=VAccountGroupsForExpenseReport.AccNo WHERE Type=0) AS TotalPrevExpense
FROM         dbo.rptSales INNER JOIN
                      dbo.rptSalesPrevious ON dbo.rptSales.Customer = dbo.rptSalesPrevious.Customer AND dbo.rptSales.RefID = dbo.rptSalesPrevious.RefID




