/****** Object:  UserDefinedFunction [dbo].[FLateComingHrs_DateWise]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE Function [dbo].[FLateComingHrs_DateWise] (@ParDate DATETIME) RETURNS TABLE
AS
RETURN
(SELECT T1.EmpID, SUM(DATEDIFF(n,EnterTime,InTime)/60.00) AS LateComingHrs FROM VEmpSettings
INNER JOIN (
SELECT EmpID,DT,InTime FROM EmpTimes
INNER JOIN (SELECT MIN(EmpTimes.EntryID) AS EntryID FROM EmpTimes LEFT JOIN Leaves ON EmpTimes.EmpID=Leaves.EmpID AND EmpTimes.DT=Leaves.DT WHERE (EmpTimes.DT=@ParDATE) AND Leaves.EmpID IS NULL GROUP BY EmpTimes.EmpID,EmpTimes.DT) TInner ON EmpTimes.EntryID=TInner.EntryID) T1 ON VEmpSettings.EmpID=T1.EmpID
WHERE (DT=@ParDATE)

AND DATEDIFF(n,DateAdd(n,CAST(LateDeductionAfter AS INT),EnterTime),InTime)>0
GROUP BY T1.EmpID)
GO
