CREATE VIEW [dbo].[VFOrderSteelWeightEP1]
AS
SELECT     TOP 100 PERCENT dbo.VProformaItems.PInvoice, SUM(dbo.VProformaItems.Qty * dbo.Items.ForgingWeight) / 1000 AS TotalWeight,
                      SUM((dbo.VProformaItems.Qty + dbo.DHRDetail.ExtraPer) * dbo.Items.ForgingWeight) / 1000 AS TotalWeightEP, dbo.Items.SteelUsed
FROM         dbo.VProformaItems INNER JOIN
                      dbo.DHRDetail ON dbo.VProformaItems.PInvoice = dbo.DHRDetail.PInvoice AND dbo.VProformaItems.ItemCode = dbo.DHRDetail.ItemCode AND
                      dbo.VProformaItems.OrderNo = dbo.DHRDetail.OrderNo INNER JOIN
                      dbo.Items ON dbo.DHRDetail.ItemCode = dbo.Items.ItemID
GROUP BY dbo.VProformaItems.PInvoice, dbo.Items.SteelUsed
ORDER BY dbo.VProformaItems.PInvoice

