CREATE VIEW [dbo].[VFSteelPurchOrdGageWise1]
AS
SELECT     dbo.FPInvoice.PInvoice, SUM(dbo.Items.ForgingWeight * dbo.FProformaOrders.Qty) / 1000 AS TotalWeight,
                      SUM(dbo.Items.ForgingWeight * (dbo.FProformaOrders.Qty + dbo.DHRDetail.ExtraPer)) / 1000 AS TotalWeightEP, dbo.Items.SteelUsed,
                      dbo.Items.Gage
FROM         dbo.Items INNER JOIN
                      dbo.FOrderItems ON dbo.Items.ItemID = dbo.FOrderItems.CompItemCode INNER JOIN
                      dbo.FPInvoice INNER JOIN
                      dbo.FProformaOrders ON dbo.FPInvoice.PInvoice = dbo.FProformaOrders.PInvoice ON
                      dbo.FOrderItems.ID = dbo.FProformaOrders.OrderEntryID LEFT OUTER JOIN
                      dbo.DHRDetail ON dbo.FOrderItems.OrderNo = dbo.DHRDetail.OrderNo AND dbo.FOrderItems.CompItemCode = dbo.DHRDetail.ItemCode AND
                      dbo.FPInvoice.PInvoice = dbo.DHRDetail.PInvoice
GROUP BY dbo.FPInvoice.PInvoice, dbo.Items.SteelUsed, dbo.Items.Gage

