CREATE VIEW [dbo].[VVenderRcvs]
AS
SELECT        dbo.VendRcvd.RcvID, dbo.VendRcvd.RcvDate, dbo.VendRcvd.VendID, dbo.VendRcvd.Description, dbo.VendRcvd.Discount, dbo.VendRcvd.StockUpdated,
                         dbo.VendRcvd.PostingDate, dbo.VendRcvd.RunningRcvNo, RcvDetail.Checked, RcvDetail.TotalQty, RcvDetail.PORefNo, dbo.VVendersAndMakers.AccTitle AS Name,
                         dbo.VVendersAndMakers.AccTitle AS VenderName, CASE RcvDetail.Checked WHEN 1 THEN 'Inspection Complete' ELSE 'Inspection Pending' END AS Status,
                         RcvDetail.SampleOrder, RcvDetail.Value, TRej.TotalQtyRejected
FROM            dbo.VendRcvd INNER JOIN
                         dbo.VVendersAndMakers ON dbo.VendRcvd.VendID = dbo.VVendersAndMakers.AccNo INNER JOIN
                             (SELECT        dbo.VendRcvdDetailPO.RcvID, dbo.VendRcvdDetailPO.PORefNo, dbo.VendRcvdDetailPO.Checked, dbo.VendOrders.SampleOrder,
                                                         SUM(dbo.VendRcvdDetailPO.QtyRcvd) AS TotalQty, SUM(dbo.VendRcvdDetailPO.QtyRcvd * dbo.VendRcvdDetailPO.Rate) AS Value
                                FROM            dbo.VendRcvdDetailPO LEFT OUTER JOIN
                                                         dbo.VendOrders ON dbo.VendRcvdDetailPO.PORefNo = dbo.VendOrders.OrderNo
                                GROUP BY dbo.VendRcvdDetailPO.RcvID, dbo.VendRcvdDetailPO.PORefNo, dbo.VendRcvdDetailPO.Checked, dbo.VendOrders.SampleOrder) AS RcvDetail ON
                         dbo.VendRcvd.RcvID = RcvDetail.RcvID LEFT OUTER JOIN
                             (SELECT        RcvID, SUM(QtyRejected) AS TotalQtyRejected
                                FROM            dbo.VVendRcvdDetailPO_Rejection_Detail
                                GROUP BY RcvID) AS TRej ON dbo.VendRcvd.RcvID = TRej.RcvID

