SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VEmpLeaves]
AS
SELECT     dbo.Employees.name, dbo.Employees.Rel, dbo.Employees.fname, dbo.Employees.Designation, dbo.Leaves.EmpID, dbo.Leaves.DT, dbo.Leaves.CL, dbo.Leaves.SL, dbo.Leaves.AL,
                      dbo.Leaves.CPL, dbo.Leaves.LWP, dbo.Leaves.ML, dbo.Leaves.SAL, dbo.Leaves.TML, dbo.AttendanceSheet.Attendance, dbo.Leaves.AuthPerson,
                      CASE WHEN Attendance = 4 THEN 0.50 ELSE 1.00 END AS Leave,
                      CASE WHEN CL = 1 THEN 'Casual Leave' ELSE CASE WHEN SL = 1 THEN 'Sick Leave' ELSE CASE WHEN AL = 1 THEN 'Annual Leave' ELSE CASE WHEN LWP = 1 THEN 'Leave Without Pay' ELSE CASE
                       WHEN SAL = 1 THEN 'Special Approved Leave' ELSE CASE WHEN TML = 1 THEN 'Three Months Leave' ELSE 'Other Leave' END END END END END END AS LeaveType
FROM         dbo.Leaves INNER JOIN
                      dbo.Employees ON dbo.Leaves.EmpID = dbo.Employees.empid LEFT OUTER JOIN
                      dbo.AttendanceSheet ON dbo.Leaves.EmpID = dbo.AttendanceSheet.EmpID AND dbo.Leaves.DT = dbo.AttendanceSheet.DT

GO
/****** Object:  UserDefinedFunction [dbo].[FLeaves]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO
CREATE FUNCTION  [dbo].[FLeaves] (@ParDate  as datetime
)
RETURNS Table  AS
Return(
SELECT     EmpID,SUM(ISNULL(CL,0))+SUM(ISNULL(SL,0))+SUM(ISNULL(AL,0))+SUM(ISNULL(CPL,0))+SUM(ISNULL(LWP,0))+SUM(ISNULL(ML,0))+SUM(ISNULL(SAL,0)) As Leaves
	,SUM(CASE WHEN CL=1 THEN 1 ELSE 0 END) as CasualLeaves,SUM(SL) as SickLeaves,SUM(AL) as AnnualLeaves,
	     SUM(CPL) as CompensatoryLeaves,SUM(LWP) as WPLeaves,SUM(ML) as MaternityLeaves,SUM(SAL) As SAL,SUM(Case Attendance when 2 then 1 else 0 end) as ApprovedLeaves
	     ,SUM(CASE WHEN ISNULL(CL,0)+ISNULL(SL,0)+ISNULL(CPL,0)+ISNULL(SAL,0)=0.5 THEN 0.5 ELSE 0 END) AS HalfLeaves
	     ,SUM(CASE WHEN CL=1 THEN 1 ELSE 0 END) AS HL
FROM         VEmpLeaves
WHERE	(month(dt) = Month(@ParDate) AND year(DT) = Year(@ParDate) AND DT <=@ParDATE )
GROUP BY EmpID)
GO
/****** Object:  View [dbo].[VMakerBilling_WastageToDeduct]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VMakerBilling_WastageToDeduct]
AS
SELECT     TOP 100 PERCENT dbo.VVendRcvdDetail.VendID, dbo.VVendRcvdDetail.EntryID, dbo.VVendRcvdDetail.Issuance_RefID, dbo.VVendRcvdDetail.OrderNo,
                      dbo.VVendRcvdDetail.LotNo, dbo.VVendRcvdDetail.RecieptID, TMasters.MasterPONo, TBillProc.Wastage, dbo.VVendRcvdDetail.IssRate,
                      dbo.VVendRcvdDetail.ItemCode, dbo.VVendRcvdDetail.DT, dbo.Items.CatID
FROM         dbo.VVendRcvdDetail INNER JOIN
                      dbo.Items ON dbo.VVendRcvdDetail.ItemCode = dbo.Items.ItemID LEFT OUTER JOIN
                          (SELECT     LotNo, MIN(EntryID) AS MinEntryID
                            FROM          VendRcvdDetail
                            GROUP BY LotNo) TMinLot ON dbo.VVendRcvdDetail.LotNo = TMinLot.LotNo LEFT OUTER JOIN
                          (SELECT     VendIssued.EntryID AS MainIssuanceEntryID, VendRcvdDetail.EntryID, MasterPONo, VendIssued.RecieptID
                            FROM          VendIssued INNER JOIN
                                                   VendIssdDetail ON VendIssdDetail.RefID = VendIssued.EntryID INNER JOIN
                                                   VendRcvdDetail ON VendRcvdDetail.Issue_RefID = VendIssdDetail.EntryID) TMasters ON TMinLot.MinEntryID = TMasters.EntryID LEFT OUTER JOIN
                          (SELECT     LotNo, ProcessID, MAX(DT) AS LotClearDT, SUM(Wastage) AS Wastage
                            FROM          (SELECT     LotNo, VendRcvdDetail.ProcessID, DT, Wastage
                                                    FROM          VendRcvdDetail INNER JOIN
                                                                           VendReceived ON VendReceived.EntryID = VendRcvdDetail.RefID
                                                    WHERE      ReqAuth = 0 AND Wastage > 0 AND DT <= '7/7/11'
                                                    UNION ALL
                                                    SELECT     VendRcvdDetail1.LotNo, VendRcvdDetail.ProcessID, DT, VendRcvdDetail.Wastage
                                                    FROM         VendRcvdDetail INNER JOIN
                                                                          VendReceived ON VendReceived.EntryID = VendRcvdDetail.RefID INNER JOIN
                                                                          LotTransferDetails ON VendRcvdDetail.EntryID = VRD_To_RefID INNER JOIN
                                                                          VendRcvdDetail VendRcvdDetail1 ON VRD_From_RefID = VendRcvdDetail1.EntryID
                                                    WHERE     VendRcvdDetail.ReqAuth = 0 AND Type = 1 AND VendRcvdDetail.Wastage > 0 AND DT <= '7/7/11') TBilling
                            GROUP BY LotNo, ProcessID) TBillProc ON dbo.VVendRcvdDetail.BillingProcessID = TBillProc.ProcessID AND
                      dbo.VVendRcvdDetail.LotNo = TBillProc.LotNo
WHERE     (ISNULL(TBillProc.Wastage, 0) > 0) AND (dbo.VVendRcvdDetail.EntryID NOT IN
                          (SELECT     VRD_RefID
                            FROM          MakerPostedBillsDetail_Receivings)) AND (dbo.VVendRcvdDetail.EntryID NOT IN
                          (SELECT     MBD_RefID
                            FROM          MakerPostedBills_Wastage))
ORDER BY dbo.VVendRcvdDetail.EntryID

GO
