CREATE FUNCTION [dbo].[F_VendWorkDone] (
@ParDate Datetime) RETURNS Table AS
Return(

SELECT     VendID, SUM(Qty * Rate) AS Total
FROM         dbo.VVenderWorkDone1
WHERE (month(dt) = Month(@ParDate) AND year(DT) = Year(@ParDate) AND Convert(varchar,DT,1) <=@ParDATE)
AND IsNull(RcvingRepair,0)=0
GROUP BY VendID)
