                         dbo.vendRcvdDetail ON dbo.VendIssdDetail.EntryID = dbo.vendRcvdDetail.Issue_RefID INNER JOIN
                             (SELECT        MIN(EntryID) AS MinEntryID
                                FROM            dbo.VendIssdDetail AS VendIssdDetail_1
                                GROUP BY LotNo) AS T1 ON dbo.VendIssdDetail.EntryID = T1.MinEntryID
WHERE        (dbo.vendRcvdDetail.EntryID NOT IN
                             (SELECT        VRD_To_RefID
                                FROM            dbo.LotTransferDetails))
