CREATE VIEW [dbo].[VVendIssdDetail]
AS
SELECT        dbo.VendIssued.VendID, dbo.VendIssued.DT, dbo.VendIssued.UserID, dbo.VendIssued.ProcessID, dbo.VendIssdDetail.EntryID, dbo.VendIssdDetail.RefID,
                         dbo.VendIssdDetail.RecieptID, dbo.VendIssdDetail.ItemCode, dbo.VendIssdDetail.Rate, dbo.VendIssdDetail.IssQty, dbo.VendIssdDetail.RcvdQty,
                         dbo.VendIssdDetail.LotNo, dbo.VendIssdDetail.ReqAuth, dbo.Makers.VenderName, dbo.Makers.VendID1, dbo.VendIssdDetail.OrderNo,
                         dbo.VendIssdDetail.RcvProcessID, dbo.VendIssdDetail.Rcvd_RefID, dbo.Makers.AccNo, dbo.VendIssdDetail.ReWorkLot, dbo.VendIssdDetail.Repair_RefID,
                         dbo.VendIssued.RecieptID AS MainRecieptID, dbo.Processes.Description, dbo.Processes.Code, dbo.ItemProcesses.SNO, dbo.Items.ItemName,
                         dbo.FCustomerOrders.CustCode, dbo.Items.GroupID, dbo.VendIssued.Closed, dbo.VendIssdDetail.ReturnDT, dbo.FCustomerOrders.InternalRefNo,
                         dbo.VendIssued.MasterPONo
FROM            dbo.VendIssued INNER JOIN
                         dbo.VendIssdDetail ON dbo.VendIssued.EntryID = dbo.VendIssdDetail.RefID INNER JOIN
                         dbo.Processes ON dbo.VendIssued.ProcessID = dbo.Processes.ProcessID INNER JOIN
                         dbo.ItemProcesses ON dbo.VendIssued.ProcessID = dbo.ItemProcesses.ProcessID AND dbo.VendIssdDetail.ItemCode = dbo.ItemProcesses.ItemID INNER JOIN
                         dbo.Items ON dbo.ItemProcesses.ItemID = dbo.Items.ItemID LEFT OUTER JOIN
                         dbo.StockOrderOpening_Issuance ON dbo.VendIssdDetail.EntryID = dbo.StockOrderOpening_Issuance.VID_RefID LEFT OUTER JOIN
                         dbo.FCustomerOrders ON dbo.VendIssdDetail.OrderNo = dbo.FCustomerOrders.OrderNo LEFT OUTER JOIN
                         dbo.Makers ON dbo.VendIssued.VendID = dbo.Makers.VendID

