/****** Object:  View [dbo].[VRunningLots]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE VIEW [dbo].[VRunningLots]
AS
SELECT     TOP (100) PERCENT T1.ItemCode, T1.LotNo, T1.CustCode, T1.OrderNo, T1.Description, T1.Qty, T1.ProcessID, T1.VendID, T1.ReWorkLot, T1.DT, dbo.VLotWithFirstProcessOfIssuance.Description AS ProcessFrom, dbo.VLotWithR2InDate.DT AS R2InDT,
                  dbo.StockOrderOpening_Issuance.EntryID AS SOO_ISS_EntryID, dbo.VItemPolishingProcessSNo.PolishingItemSNo, dbo.ItemProcesses.SNO
FROM        (SELECT     ItemCode, LotNo, CustCode, OrderNo, Description, IssQty - RcvdQty AS Qty, ProcessID, VendID, ReWorkLot, DT
                   FROM        dbo.VVendIssdDetail
                   WHERE     (LotNo <> '0') AND (IssQty - RcvdQty > 0) AND (EntryID NOT IN
                                         (SELECT     Issue_RefID
                                          FROM        dbo.vendRcvdDetail))
                   UNION
                   SELECT     ItemCode, LotNo, CustCode, OrderNo, Description, RcvdQty - IssQty - ISNULL(Wastage, 0) - ISNULL(ReWorkQty, 0) AS Qty, ProcessID, VendID, ReWorkLot, DT
                   FROM        dbo.VVendRcvdDetail_Simple
                   WHERE     (LotNo <> '0') AND (RcvdQty - IssQty - ISNULL(Wastage, 0) - ISNULL(ReWorkQty, 0) > 0) AND (EntryID NOT IN
                                         (SELECT     Rcvd_RefID
                                          FROM        dbo.VendIssdDetail
                                          WHERE     (Rcvd_RefID IS NOT NULL))) AND (ISNULL(Opening_RefID, 0) = 0)) AS T1 LEFT OUTER JOIN
                  dbo.VLotWithR2InDate ON T1.LotNo = dbo.VLotWithR2InDate.LotNo LEFT OUTER JOIN
                  dbo.VLotWithFirstProcessOfIssuance ON T1.LotNo = dbo.VLotWithFirstProcessOfIssuance.LotNo LEFT OUTER JOIN
                  dbo.StockOrderOpening_Issuance ON dbo.VLotWithFirstProcessOfIssuance.EntryID = dbo.StockOrderOpening_Issuance.VID_RefID LEFT OUTER JOIN
                  dbo.VItemPolishingProcessSNo ON T1.ItemCode = dbo.VItemPolishingProcessSNo.ItemCode LEFT OUTER JOIN
                  dbo.ItemProcesses ON T1.ItemCode = dbo.ItemProcesses.ItemID AND dbo.ItemProcesses.ProcessID = T1.ProcessID
WHERE     (T1.LotNo NOT IN
                      (SELECT     LotNo
                       FROM        dbo.Lots_Closed))
ORDER BY T1.ProcessID
GO
