CREATE VIEW [dbo].[VShippingInstructions]
AS
SELECT     dbo.ShippingInstructions.GoodsDesc, dbo.ShippingInstructions.GWeight, dbo.ShippingInstructions.Measurement,
                      dbo.ShippingInstructions.MarksnNumbers, dbo.ShippingInstructions.NonKind, dbo.ShippingInstructions.Encloseres,
                      dbo.ShippingInstructions.SpecialInstructions, dbo.ShippingAgents.Name, dbo.ShippingAgents.Address AS AgentAddress,
                      dbo.VrptCustomInvoice.CustCode, dbo.VrptCustomInvoice.Country, dbo.VrptCustomInvoice.Address, dbo.VrptCustomInvoice.Curr,
                      dbo.VrptCustomInvoice.LoadPort, dbo.VrptCustomInvoice.DisPort, dbo.VrptCustomInvoice.DT, dbo.VrptCustomInvoice.TradeTerms,
                      dbo.CustomInvoice.AWBNo, dbo.CustomInvoice.AWBNoDT, dbo.CustomInvoice.FormE, dbo.CustomInvoice.FormEDT, dbo.VTotalCartons.TotalCartons,
                      dbo.VrptCustomInvoice.Name AS CustName, dbo.VrptCustomInvoice.Address AS CustAddress, dbo.VrptCustomInvoice.ShippingL,
                      dbo.VrptCustomInvoice.ShippingH, dbo.VCustomInvoiceOrders.CustomInvoiceOrders, dbo.VCustomInvoiceAmt.TotalCustomAmt,
                      dbo.ShippingInstructions.CustomInvoice
FROM         dbo.ShippingInstructions INNER JOIN
                      dbo.VrptCustomInvoice ON dbo.ShippingInstructions.CustomInvoice = dbo.VrptCustomInvoice.CustomInvoice INNER JOIN
                      dbo.CustomInvoice ON dbo.ShippingInstructions.CustomInvoice = dbo.CustomInvoice.CustomInvoice INNER JOIN
                      dbo.VCustomInvoiceOrders ON dbo.CustomInvoice.CustomInvoice = dbo.VCustomInvoiceOrders.CustomInvoice INNER JOIN
                      dbo.VCustomInvoiceAmt ON dbo.CustomInvoice.CustomInvoice = dbo.VCustomInvoiceAmt.CustomInvoice LEFT OUTER JOIN
                      dbo.VTotalCartons ON dbo.ShippingInstructions.CustomInvoice = dbo.VTotalCartons.CustomInvoice LEFT OUTER JOIN
                      dbo.ShippingAgents ON dbo.VrptCustomInvoice.ShippingAgentID = dbo.ShippingAgents.EntryID

