CREATE FUNCTION [dbo].[FLongCurrent] (@ParDate as DateTime)
RETURNS Table AS
return(SELECT     EmpID, SUM(isnull(Amount,0)) AS LongAmount
FROM         dbo.Advances Where ISNULL(DeductionStartDT,DT)<=@ParDate and Type=1
GROUP BY EmpID)


