CREATE FUNCTION [dbo].[FLongDeduct2] (@ParDate as DateTime)
RETURNS Table AS
return(SELECT     EmpID, SUM(isnull(AmtClrd,0)) AS ClsAmt
FROM         dbo.AmtCleared Where dt<=@ParDate
