/****** Object:  UserDefinedFunction [dbo].[FLongDeduct3]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO
CREATE FUNCTION [dbo].[FLongDeduct3] ()
RETURNS Table AS
Return(SELECT EmpID, DAmount
FROM Advances Where EntryID In (Select Max(EntryID) From Advances Where Type=1 Group By EmpID)
)
GO
/****** Object:  UserDefinedFunction [dbo].[FLongDeduct]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE FUNCTION [dbo].[FLongDeduct](@ParDate as DateTime)
RETURNS Table AS
Return(
	SELECT     Ded1.*, Ded2.ClsAmt AS ClsAmt,Ded3.LongAmount as CurrentLong,Ded4.DAmount As DedAmt
	FROM         FLongDeduct1(@ParDate) Ded1 LEFT OUTER JOIN
             FLongDeduct2(@ParDate) Ded2 ON Ded1.EmpID =Ded2.EmpID
	LEFT OUTER JOIN
             FLongCurrent(@ParDate) Ded3 ON Ded1.EmpID =Ded3.EmpID
	LEFT OUTER JOIN
	FLongDeduct3() Ded4 ON Ded1.EmpID=Ded4.EmpID
)


GO
