GO

CREATE VIEW [dbo].[VVendOrdersToRcv]
AS
SELECT        dbo.VVendOrders.OrderNo, dbo.VVendOrders.DT, dbo.VVendOrders.VendID, dbo.VVendOrders.AttnPerson, dbo.VVendOrders.PaymentTerms,
                         dbo.VVendOrders.Department, dbo.VVendOrders.DeliveryDT, dbo.VVendOrders.Remarks, dbo.VVendOrders.ReqNo, dbo.VVendOrders.VeryUrgent,
                         dbo.VVendOrders.Final, dbo.VVendOrders.Rate, dbo.VVendOrders.Qty, dbo.VVendOrders.GroupID, dbo.VVendOrders.RMID1, dbo.VVendOrders.RMName,
                         dbo.VVendOrders.Unit, dbo.VVendOrders.RMSize, dbo.VVendOrders.SizeUnit, dbo.VVendOrders.RMRate, dbo.VVendOrders.RMUsage, dbo.VVendOrders.EntryID,
                         dbo.VVendOrders.AccTitle, dbo.VVendOrders.VendOrderDetailEntryID, dbo.VVendOrders.IssuanceType, dbo.VVendOrders.RunningPONo, dbo.VVendOrders.Ref,
                         dbo.VVendOrders.Payments, dbo.VVendOrders.Shipment, dbo.VVendOrders.Instructions, dbo.VVendOrders.Notes, dbo.VVendOrders.Currency,
                         dbo.VVendOrders.SampleProvided, dbo.VVendOrders.SampleProvidedDescription, dbo.VVendOrders.DrawingProvided,
                         dbo.VVendOrders.DrawingProvidedDescription, dbo.VVendOrders.SteelProvided, dbo.VVendOrders.SteelProvidedDescription, dbo.VVendOrders.OtherUnit,
                         dbo.VVendOrders.OtherUnitEntryID, dbo.VVendOrders.POType, dbo.VVendOrders.CCItem, dbo.VVendOrders.LastRate, dbo.VVendOrders.CustomerPONo,
                         dbo.VVendOrders.SteelType_RefID, dbo.VVendOrders.VOD_RefID, ISNULL(VOrdRcvd.TotalQtyRcvd, 0) AS QtyRcvd, ISNULL(dbo.VVendOrders.Qty, 0)
                         - ISNULL(VOrdRcvd.TotalQtyRcvd, 0) AS QtyToRcv, dbo.VVendOrders.OrderNo AS PONo, dbo.VVendOrders.RMID1 AS MaterialID,
                         dbo.VVendOrders.RMName AS MaterialName, dbo.VVendOrders.Qty AS QtyOrdered, dbo.VVendOrders.SampleOrder
FROM            dbo.VVendOrders LEFT OUTER JOIN
                             (SELECT        dbo.VendRcvdDetailPO.PORefNo, dbo.VendRcvdDetailPO.MaterialID, SUM(ISNULL(dbo.VendRcvdDetailPO.QtyRcvd, 0)
                                                         + ISNULL(dbo.VendRcvdDetailPO.ExtraQtyRcvd, 0) - ISNULL(dbo.VendRcvdDetailPO.QtyReturned, 0)
                                                         - ISNULL(dbo.VVendRcvdDetailPO_TotalRejection.QtyRejected, 0)) AS TotalQtyRcvd
                                FROM            dbo.VendRcvdDetailPO LEFT OUTER JOIN
                                                         dbo.VVendRcvdDetailPO_TotalRejection ON dbo.VendRcvdDetailPO.EntryID = dbo.VVendRcvdDetailPO_TotalRejection.VRDPO_RefID
                                GROUP BY dbo.VendRcvdDetailPO.PORefNo, dbo.VendRcvdDetailPO.MaterialID) AS VOrdRcvd ON dbo.VVendOrders.OrderNo = VOrdRcvd.PORefNo AND
                         dbo.VVendOrders.RMID1 = VOrdRcvd.MaterialID
WHERE        (ISNULL(dbo.VVendOrders.Qty, 0) - ISNULL(VOrdRcvd.TotalQtyRcvd, 0) > 0) AND (dbo.VVendOrders.Final = 0) OR
                         (dbo.VVendOrders.SampleOrder = 1)

GO
