CREATE VIEW [dbo].[VScholorships]
AS
SELECT     dbo.VEmp.*, dbo.ScholorShips.SType AS SType, dbo.ScholorShips.StartDT AS StartDT, dbo.ScholorShips.DT, dbo.ScholorShips.EntryID,
                      CASE SType WHEN 0 THEN 'PRIMARY' WHEN 1 THEN 'Middle' WHEN 2 THEN 'High' ELSE '' END AS ScholorshipType, dbo.ScholorShips.Qty AS Qty,
                      dbo.ScholorShips.Qty * CASE SType WHEN 0 THEN 100 WHEN 1 THEN 150 WHEN 2 THEN 200 ELSE 0 END AS Amount
FROM         dbo.VEmp INNER JOIN
                      dbo.ScholorShips ON dbo.VEmp.empid = dbo.ScholorShips.EmpID
WHERE     (dbo.VEmp.deptid <> 'VDRS')
