CREATE VIEW [dbo].[VCustomInvoiceDetail_From_PList]
AS
SELECT     dbo.FOrderItems.ID, dbo.FOrderItems.ItemCode, dbo.FCustomerCatalog.Description, dbo.FCustomerCatalog.ItemID, dbo.FCustomerCatalog.CompItemID,
                      dbo.ForeignCustomers.Curr, dbo.FCustomerCatalog.Unit, dbo.ForeignCustomers.Name, dbo.ForeignCustomers.Address, dbo.FOrderItems.OrderNo,
                      dbo.ForeignCustomers.Cont1name, dbo.ForeignCustomers.DTFormat, dbo.FCustomerCatalog.PackingMode, dbo.VItems1.CompleteItemName,
                      dbo.FProformaOrders.Qty AS ProformaQty, dbo.ForeignCustomers.FakeAddress, dbo.ItemCatagories.Description AS ItemCatagory, dbo.ItemCatagories.SRONo,
                      dbo.FCustomerOrders.DeliveryDT, dbo.FProformaOrders.EntryID, dbo.FCustomerOrders.DT, dbo.VItems1.ItemGroup, dbo.CustomInvoice.CustomInvoice,
                      dbo.VInvoiceDataFromPackingList.EntryID AS CustomInvoiceItemsEntryID, dbo.VInvoiceDataFromPackingList.Qty, dbo.VInvoiceDataFromPackingList.Price,
                      dbo.VInvoiceDataFromPackingList.CustomPrice, dbo.VItems1.CatID, dbo.VItems1.ItemName, dbo.VItems1.CustomDescription, dbo.VItems1.FinishedWeight,
                      dbo.VItems1.ItemSize, dbo.VItems1.SizeUnit, dbo.VItems1.Unit AS ItemUnit, dbo.VItems1.ItemColor, dbo.CustomInvoice.Consignee,
                      dbo.FCustomerCatalog.ItemColor AS CustomerItemColor, dbo.VItems1.Type, dbo.VInvoiceDataFromPackingList.DTRENo, dbo.CustomInvoice.DTREDescription,
                      dbo.VInvoiceDataFromPackingList.BatchNo, dbo.VItems1.FDAListingNo, dbo.VItems1.FDAProductCode, dbo.CustomInvoice.GrossWeight,
                      dbo.BatchNosFromPackingListForInvoice_F(dbo.VInvoiceDataFromPackingList.EntryID) AS Batches, dbo.CustomInvoice.ComDrawnUnder,
                      dbo.CustomInvoice.ComSpecial, dbo.FCustomerOrders.InternalRefNo, dbo.FProformaOrders.ItemDescription, dbo.VInvoiceDataFromPackingList.LotNo,
                      dbo.Lots_List.Batch_No, dbo.Lots_List.Mill_Certificate_No, dbo.VItems1.SFDA_Name, dbo.VItems1.SFDA_No, dbo.VItems1.SFDA_Listing,
                      dbo.FOrderItems.Item_Finishing_Type, dbo.Item_Finishing_Type.Item_Finishing_Type_Text, dbo.FOrderItems.Qty - ISNULL(TShipped.ShippedQty, 0)
                      AS Order_Balance_Qty, dbo.FCustomerCatalog.MDMA, dbo.FCustomerCatalog.SFDA_Listing_No, dbo.FCustomerCatalog.MD_Group,
					  Item_Finishing_Type.Item_Finishing_Type_Text AS FinshingType,FOrderItems.Stamps,FOrderItems.IW_BatchNo,
					  FOrderItems.IW_OrderNo,ItemCatagories.HSCode,FOrderItems.Remarks,FOrderItems.Quality AS Finshing,
					  CustomInvoice.InvoiceDescription,ForeignCustomers.FC_Note_I,ForeignCustomers.FC_Note_II,ISNULL(dbo.F_CustomInvoice_HSCodes(CustomInvoice.CustomInvoice),'') AS HSCode_For_Invoice
FROM         dbo.VItems1 INNER JOIN
                      dbo.VInvoiceDataFromPackingList INNER JOIN
                      dbo.ForeignCustomers INNER JOIN
                      dbo.FProformaOrders INNER JOIN
                      dbo.FOrderItems ON dbo.FProformaOrders.OrderEntryID = dbo.FOrderItems.ID INNER JOIN
                      dbo.FCustomerOrders ON dbo.FOrderItems.OrderNo = dbo.FCustomerOrders.OrderNo ON dbo.ForeignCustomers.CustCode = dbo.FCustomerOrders.CustCode AND
                      dbo.ForeignCustomers.Country = dbo.FCustomerOrders.Country INNER JOIN
                      dbo.CustomInvoice INNER JOIN
                      dbo.FCustomerCatalog ON dbo.CustomInvoice.CustCode = dbo.FCustomerCatalog.CustCode AND dbo.CustomInvoice.Country = dbo.FCustomerCatalog.Country ON
                      dbo.ForeignCustomers.CustCode = dbo.CustomInvoice.CustCode AND dbo.ForeignCustomers.Country = dbo.CustomInvoice.Country ON
                      dbo.VInvoiceDataFromPackingList.RefID = dbo.FProformaOrders.EntryID AND
                      dbo.VInvoiceDataFromPackingList.CustomInvoice = dbo.CustomInvoice.CustomInvoice ON dbo.VItems1.ItemID = dbo.FOrderItems.CompItemCode AND
                      dbo.VItems1.ItemID = dbo.FCustomerCatalog.CompItemID INNER JOIN
                      dbo.ItemCatagories ON dbo.VItems1.CatID = dbo.ItemCatagories.CatID LEFT OUTER JOIN
                      dbo.Item_Finishing_Type ON dbo.FOrderItems.Item_Finishing_Type = dbo.Item_Finishing_Type.EntryID LEFT OUTER JOIN
                      dbo.Lots_List ON dbo.VInvoiceDataFromPackingList.LotNo = dbo.Lots_List.LotNo LEFT OUTER JOIN
                          (SELECT     FProformaOrders_1.OrderEntryID, SUM(dbo.CustomPList.Qty) AS ShippedQty
                            FROM          dbo.CustomInvoiceItems INNER JOIN
                                                   dbo.CustomPList ON dbo.CustomInvoiceItems.EntryID = dbo.CustomPList.OrderItemID INNER JOIN
                                                   dbo.FProformaOrders AS FProformaOrders_1 ON dbo.CustomInvoiceItems.RefID = FProformaOrders_1.EntryID
                            GROUP BY FProformaOrders_1.OrderEntryID) AS TShipped ON dbo.FOrderItems.ID = TShipped.OrderEntryID



GO
