CREATE VIEW [dbo].[VItemOpenPOs]
AS
SELECT     dbo.VendIssued.EntryID, dbo.Makers.VendID1, dbo.Makers.VenderName, dbo.VendIssued.RecieptID, dbo.VendIssued.MasterPONo, dbo.VendIssdDetail.OrderNo,
                      dbo.VendIssdDetail_ReturnDTs.IssQty + CASE WHEN ISNULL(IssRcvBalance, 0) < 0 THEN ABS(ISNULL(IssRcvBalance, 0))
                      ELSE 0 END + ISNULL(dbo.VendIssdDetail_MoreDetails.Wastage_Return, 0) - dbo.VendIssdDetail_ReturnDTs.RcvQty AS Qty,
                      dbo.VendIssdDetail_ReturnDTs.ReturnDT, dbo.VendIssdDetail.ItemCode, dbo.VendIssdDetail.EntryID AS VID_EntryID, dbo.VendIssdDetail.Rate
FROM         dbo.VendIssued INNER JOIN
                      dbo.VendIssdDetail ON dbo.VendIssued.EntryID = dbo.VendIssdDetail.RefID INNER JOIN
                      dbo.VendIssdDetail_ReturnDTs ON dbo.VendIssdDetail.EntryID = dbo.VendIssdDetail_ReturnDTs.VIS_RefID INNER JOIN
                      dbo.Makers ON dbo.VendIssued.VendID = dbo.Makers.VendID LEFT OUTER JOIN
                      dbo.VendIssdDetail_MoreDetails ON dbo.VendIssdDetail.EntryID = dbo.VendIssdDetail_MoreDetails.VID_RefID AND
                      dbo.VendIssdDetail_ReturnDTs.RcvQty < dbo.VendIssdDetail_ReturnDTs.IssQty + CASE WHEN ISNULL(IssRcvBalance, 0) < 0 THEN ABS(ISNULL(IssRcvBalance, 0))
                      ELSE 0 END + ISNULL(dbo.VendIssdDetail_MoreDetails.Wastage_Return, 0)
WHERE     (dbo.VendIssued.Closed = 0) AND (dbo.VendIssdDetail.LotNo = '0')

GO
