CREATE VIEW [dbo].[VVendIssdDetailWithValue]
AS
SELECT     dbo.VendIssued.EntryID AS MainEntryID, dbo.VendIssued.RecieptID AS MainRecieptID, dbo.VendIssued.DT, dbo.VendIssdDetail.EntryID, dbo.VendIssued.VendID, dbo.VendIssdDetail.RefID, dbo.VendIssdDetail.RecieptID, dbo.VendIssdDetail.ItemCode,
                  dbo.VendIssdDetail.Rate, dbo.VendIssdDetail.IssQty, dbo.VendIssdDetail.RcvdQty, dbo.VendIssdDetail.LotNo, dbo.VendIssdDetail.ReqAuth, dbo.VendIssdDetail.OrderNo, dbo.VendIssdDetail.RcvProcessID, dbo.VendIssdDetail.ReturnDT, dbo.VendIssdDetail.Priority,
                  dbo.VendIssdDetail.SpecialInstructions, dbo.VendIssued.VchrNo, dbo.Items.ForgingWeight, CASE WHEN VendAssItems.Unit = 'Kgs' THEN ((ForgingWeight * VendIssdDetail.IssQty) / 1000)
                  * VendIssdDetail.Rate ELSE VendIssdDetail.IssQty * VendIssdDetail.Rate END AS IssValue, CASE WHEN VendAssItems.Unit = 'Kgs' THEN ((ForgingWeight * (VendIssdDetail.IssQty - VendIssdDetail.RcvdQty)) / 1000)
                  * VendIssdDetail.Rate ELSE (VendIssdDetail.IssQty - VendIssdDetail.RcvdQty) * VendIssdDetail.Rate END AS BalanceValue, dbo.VendIssdDetail.ReWorkLot, dbo.VendIssdDetail.Repair_RefID, dbo.VendReceived.DT AS RcvDT,
                  dbo.vendRcvdDetail.RcvdQty AS RcvRcvdQty, dbo.Items.MakerDescription1, dbo.Items.ItemNameUrdu
FROM        dbo.VendIssdDetail INNER JOIN
                  dbo.VendIssued ON dbo.VendIssdDetail.RefID = dbo.VendIssued.EntryID LEFT OUTER JOIN
                  dbo.VendAssItems ON dbo.VendIssued.VendID = dbo.VendAssItems.VendID AND dbo.VendIssdDetail.ItemCode = dbo.VendAssItems.ItemID AND dbo.VendIssued.ProcessID = dbo.VendAssItems.ProcessID INNER JOIN
                  dbo.Items ON dbo.VendIssued.ItemID = dbo.Items.ItemID LEFT OUTER JOIN
                  dbo.vendRcvdDetail ON dbo.VendIssdDetail.EntryID = dbo.vendRcvdDetail.Issue_RefID LEFT OUTER JOIN
                  dbo.VendReceived ON dbo.vendRcvdDetail.RefID = dbo.VendReceived.EntryID
GO
