CREATE VIEW [dbo].[VMakerIssItems]
AS
SELECT     dbo.VendIssued.DT, dbo.VendIssued.VendID, VendIssdDetail.IssQty - VendIssdDetail.RcvdQty AS RemQty, dbo.Makers.VenderName, dbo.VendIssued.ProcessID,
                      dbo.VendIssued.UserID, dbo.VItems1.ItemID AS CompItemCode, dbo.VItems1.CompleteItemName AS Itemdescription, dbo.VendIssued.RecieptID AS MainRecieptID,
                      CAST(CONVERT(Varchar(10), dbo.VendIssued.DT, 1) AS DATETIME) AS OnlyDT, dbo.VendIssued.EntryID AS MainEntryID, dbo.VItems1.ItemName, dbo.Makers.VendID1,
                      dbo.Processes.Description AS ProcessName, VendIssdDetail.EntryID, VendIssdDetail.RefID, VendIssdDetail.RecieptID, VendIssdDetail.ItemCode,
                      VendIssdDetail.Rate, VendIssdDetail.IssQty, VendIssdDetail.RcvdQty, VendIssdDetail.LotNo, VendIssdDetail.ReqAuth, VendIssdDetail.OrderNo,
                      VendIssdDetail.RcvProcessID, VendIssdDetail.ReturnDT, VendIssdDetail.Priority, VendIssdDetail.SpecialInstructions, VendIssdDetail.ForgingWeight,
                      VendIssdDetail.IssValue, dbo.VendAssItems.Unit, ISNULL(TabRcvd.UnAuthRcvdQty, 0) AS UnAuthRcvdQty, dbo.VItems1.ItemNameUrdu, dbo.VItems1.ItemSize,
                      dbo.VItems1.SizeUnit, dbo.VItems1.Type, dbo.VItems1.ItemColor, dbo.VendIssued.MaximumRcvingsAgainstPO, dbo.VendIssued.ExcessQtyPercentage,
                      VendIssdDetail.ReWorkLot, VendIssdDetail.Repair_RefID, dbo.VendIssdDetail_MoreDetails.Wastage_Return, dbo.VendIssdDetail_MoreDetails.IssRcvBalance
FROM         dbo.VVendIssdDetailWithValue VendIssdDetail INNER JOIN
                      dbo.VendIssued ON VendIssdDetail.RefID = dbo.VendIssued.EntryID INNER JOIN
                      dbo.VItems1 ON VendIssdDetail.ItemCode = dbo.VItems1.ItemID INNER JOIN
                      dbo.Processes ON dbo.VendIssued.ProcessID = dbo.Processes.ProcessID LEFT OUTER JOIN
                      dbo.VendIssdDetail_MoreDetails ON VendIssdDetail.EntryID = dbo.VendIssdDetail_MoreDetails.VID_RefID LEFT OUTER JOIN
                      dbo.VendAssItems ON dbo.VendIssued.VendID = dbo.VendAssItems.VendID AND dbo.VendIssued.ProcessID = dbo.VendAssItems.ProcessID AND
                      VendIssdDetail.ItemCode = dbo.VendAssItems.ItemID LEFT OUTER JOIN
                      dbo.Makers ON dbo.VendIssued.VendID = dbo.Makers.VendID LEFT OUTER JOIN
                          (SELECT     Issue_RefID, SUM(RcvdQty) AS UnAuthRcvdQty
                            FROM          VendRcvdDetail
                            WHERE      ReqAuth = 1
                            GROUP BY Issue_RefID) TabRcvd ON VendIssdDetail.EntryID = TabRcvd.Issue_RefID

GO
