CREATE VIEW [dbo].[VPurchaseCalendarReturnDates]
AS
SELECT     dbo.VendIssued.VendID, dbo.VendIssued.MasterPONo, dbo.VendIssdDetail_ReturnDTs.IssQty, dbo.VendIssdDetail_ReturnDTs.RcvQty,
                      dbo.VendIssdDetail_ReturnDTs.ReturnDT, dbo.VendIssdDetail.ItemCode, dbo.Makers.VendID1, dbo.Items.GroupID, dbo.FCustomerOrders.CustCode,
                      dbo.DateLookup.DateFull, dbo.DateLookup.FullYear, dbo.DateLookup.WeekNumber, dbo.DateLookup.MonthDay, dbo.DateLookup.MonthNumber,
                      dbo.VendIssdDetail_ReturnDTs.EntryID AS EntryIDReturnDTs, dbo.VendIssued.RecieptID, dbo.VendIssued.SpecialInstructions, dbo.FCustomerOrders.InternalRefNo,
                      dbo.Makers.VenderName,FCustomerCatalog.ItemID AS CustItemCode
FROM         dbo.VendIssued INNER JOIN
                      dbo.VendIssdDetail ON dbo.VendIssued.EntryID = dbo.VendIssdDetail.RefID INNER JOIN
                      dbo.Makers ON dbo.VendIssued.VendID = dbo.Makers.VendID INNER JOIN
                      dbo.FCustomerOrders ON dbo.VendIssdDetail.OrderNo = dbo.FCustomerOrders.OrderNo INNER JOIN
                      dbo.VendIssdDetail_ReturnDTs ON dbo.VendIssdDetail.EntryID = dbo.VendIssdDetail_ReturnDTs.VIS_RefID INNER JOIN
                      dbo.Items ON dbo.VendIssdDetail.ItemCode = dbo.Items.ItemID INNER JOIN
                      dbo.DateLookup ON dbo.VendIssdDetail_ReturnDTs.ReturnDT = dbo.DateLookup.DateFull INNER JOIN
	FCustomerCatalog ON FCustomerOrders.CustCode=FCustomerCatalog.CustCode AND FCustomerOrders.Country=FCustomerCatalog.Country AND VendIssdDetail.ItemCode=FCustomerCatalog.CompItemID
WHERE     (dbo.VendIssued.Closed = 0) AND (dbo.FCustomerOrders.CustCode <> 'Stock') AND (dbo.VendIssued.MasterPONo IS NOT NULL)



