CREATE VIEW [dbo].[VPurchaseCalendar]
AS
SELECT T1.* FROM (
SELECT        VendID, MasterPONo, IssQty, RcvQty, ReturnDT, ItemCode, VendID1, GroupID, CustCode, DateFull, FullYear, WeekNumber, MonthDay, MonthNumber, '(D)' AS Prefix,
                         EntryIDReturnDTs, ReturnDT AS ActualReturnDT,Followup,RecieptID,SpecialInstructions,InternalRefNo,VenderName,CustItemCode
FROM            VPurchaseCalendarReturnDates LEFT OUTER JOIN FollowUpData ON EntryIDReturnDTs=VIDRDTS_RefID AND FollowUpData.FollowUp='(D)'
UNION ALL
(SELECT        VendID, MasterPONo, IssQty, RcvQty, CASE WHEN WeekDayName = 'Sunday' THEN DATEADD(day, 1, FollowupDate1) ELSE FollowupDate1 END AS ReturnDT, ItemCode, VendID1,
                           GroupID, CustCode, DateFull, FullYear, WeekNumber, MonthDay, MonthNumber, '(F1)' AS Prefix, EntryIDReturnDTs, ReturnDT AS ActualReturnDT,Followup,RecieptID,SpecialInstructions,InternalRefNo,VenderName,CustItemCode
 FROM            VVendIssuedWithReturnDTs INNER JOIN
                           DateLookup ON DateLookup.DateFull = FollowupDate1 LEFT OUTER JOIN FollowUpData ON EntryIDReturnDTs=VIDRDTS_RefID AND FollowUpData.FollowUp='(F1)'
UNION ALL
SELECT        VendID, MasterPONo, IssQty, RcvQty, CASE WHEN WeekDayName = 'Sunday' THEN DATEADD(day, 1, FollowupDate2) ELSE FollowupDate2 END AS ReturnDT, ItemCode, VendID1,
                         GroupID, CustCode, DateFull, FullYear, WeekNumber, MonthDay, MonthNumber, '(F2)' AS Prefix, EntryIDReturnDTs, ReturnDT AS ActualReturnDT,Followup,RecieptID,SpecialInstructions,InternalRefNo,VenderName,CustItemCode
FROM            VVendIssuedWithReturnDTs INNER JOIN
                         DateLookup ON DateLookup.DateFull = FollowupDate2 LEFT OUTER JOIN FollowUpData ON EntryIDReturnDTs=VIDRDTS_RefID AND FollowUpData.FollowUp='(F2)'
UNION ALL
SELECT        VendID, MasterPONo, IssQty, RcvQty, CASE WHEN WeekDayName = 'Sunday' THEN DATEADD(day, 1, FollowupDate3) ELSE FollowupDate3 END AS ReturnDT, ItemCode, VendID1,
                         GroupID, CustCode, DateFull, FullYear, WeekNumber, MonthDay, MonthNumber, '(F3)' AS Prefix, EntryIDReturnDTs, ReturnDT AS ActualReturnDT,Followup,RecieptID,SpecialInstructions,InternalRefNo,VenderName,CustItemCode
FROM            VVendIssuedWithReturnDTs INNER JOIN
                         DateLookup ON DateLookup.DateFull = FollowupDate3 LEFT OUTER JOIN FollowUpData ON EntryIDReturnDTs=VIDRDTS_RefID AND FollowUpData.FollowUp='(F3)')) T1

