CREATE VIEW [dbo].[VCalcRebate1]
AS
SELECT     dbo.CustomInvoiceItems.CustomInvoice, dbo.CustomInvoiceItems.RebateRate AS SRORate,
                      SUM(dbo.CustomInvoiceItems.CustomPrice * dbo.CustomInvoiceItems.Qty) AS TotalAmount, dbo.VCustomInvoiceAmt.TotalCustomAmt AS TotalInvoiceAmt,
                      dbo.SROs.SroNo
FROM         dbo.Items INNER JOIN
                      dbo.FProformaOrders INNER JOIN
                      dbo.FOrderItems ON dbo.FProformaOrders.OrderEntryID = dbo.FOrderItems.ID ON dbo.Items.ItemID = dbo.FOrderItems.CompItemCode INNER JOIN
                      dbo.CustomInvoiceItems ON dbo.FProformaOrders.EntryID = dbo.CustomInvoiceItems.RefID INNER JOIN
                      dbo.VCustomInvoiceAmt ON dbo.CustomInvoiceItems.CustomInvoice = dbo.VCustomInvoiceAmt.CustomInvoice INNER JOIN
                      dbo.ItemCatagories ON dbo.Items.CatID = dbo.ItemCatagories.CatID INNER JOIN
                      dbo.SROs ON dbo.ItemCatagories.SRONo = dbo.SROs.EntryID
WHERE     (ISNULL(dbo.SROs.CRebate, 0) > 0)
GROUP BY dbo.CustomInvoiceItems.CustomInvoice, dbo.SROs.SroNo, dbo.CustomInvoiceItems.RebateRate, dbo.VCustomInvoiceAmt.TotalCustomAmt, dbo.SROs.SroNo

