CREATE VIEW [dbo].[VTotalRcvdLots]
AS
SELECT     LotNo, ItemCode, NextProcessID, RecieptID, SUM(RcvdQty - IssQty) AS Qty
FROM         dbo.VendRcvdDetail
WHERE     (LotNo IS NOT NULL) AND (ISNULL(ReqAuth, 0) = 0) AND (RecieptID NOT IN
                          (SELECT     RecieptID
                            FROM          dbo.VVendIssdDetail
                            WHERE      (ReqAuth = 1)
                            GROUP BY LotNo, ItemCode, ProcessID, RecieptID))
GROUP BY LotNo, ItemCode, NextProcessID, RecieptID
HAVING      (SUM(RcvdQty - IssQty) > 0)

