CREATE VIEW [dbo].[VMakerPerformance]
AS
SELECT     dbo.VendIssued.DT, dbo.VendIssdDetail.IssQty, CAST(CONVERT(VARCHAR(50), TRcv.RcvDate, 6) AS DATETIME) AS RcvDate, TRcv.RcvdQty,
                      dbo.VendIssdDetail.ReturnDT, dbo.VendIssdDetail.ItemCode, dbo.VendIssued.VendID, dbo.Makers.VenderName, dbo.Makers.VendID1, TRcv.RcvCount,
                      dbo.VendIssdDetail.EntryID
FROM         dbo.VendIssued INNER JOIN
                      dbo.VendIssdDetail ON dbo.VendIssued.EntryID = dbo.VendIssdDetail.RefID INNER JOIN
                      dbo.Makers ON dbo.VendIssued.VendID = dbo.Makers.VendID LEFT OUTER JOIN
                          (SELECT     dbo.vendRcvdDetail.Issue_RefID, COUNT(DISTINCT dbo.vendRcvdDetail.ItemCode) AS RcvCount, MAX(dbo.VendReceived.DT) AS RcvDate,
                                                   SUM(dbo.vendRcvdDetail.RcvdQty) AS RcvdQty
                            FROM          dbo.vendRcvdDetail INNER JOIN
                                                   dbo.VendReceived ON dbo.VendReceived.EntryID = dbo.vendRcvdDetail.RefID
                            GROUP BY dbo.vendRcvdDetail.Issue_RefID) AS TRcv ON dbo.VendIssdDetail.EntryID = TRcv.Issue_RefID
WHERE     (dbo.VendIssued.ProcessID IN (2, 5, 6, 11, 12, 13, 14, 16, 18, 19, 20, 23, 24, 29, 30, 31, 32)) AND (dbo.VendIssued.VendID NOT IN (653))
GO
/****** Object:  View [dbo].[VMakerPerformanceEx]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VMakerPerformanceEx]
AS
SELECT     T1.*, dbo.Makers.VenderName, T2.TotalItemCount, T2.TotalOnTime
FROM         (SELECT     T1.VendID, CAST(CAST(MONTH(DT) AS VARCHAR(2)) + '/01/' + CAST(YEAR(DT) AS VARCHAR(4)) AS DATETIME) AS DT, SUM(Issqty) AS IssdQty,
                                              SUM(RcvdQty) AS RcvdQty, SUM(CASE WHEN T1.OnTime = 1 THEN RcvdQty ELSE 0 END) AS OnTimeQty,
                                              SUM(CASE WHEN T1.OnTime = 0 THEN RcvdQty ELSE 0 END) AS DelayedQty, COUNT(ItemCode) AS ItemCount, SUM(Days) AS Days, SUM(T1.OnTime)
                                              AS OnTime
                       FROM          (SELECT     *, CASE WHEN RcvDate <= ReturnDT THEN 1 ELSE 0 END AS OnTime, DATEDIFF(d, ReturnDT, RcvDate) AS Days
                                               FROM          VMakerPerformance) T1
                       GROUP BY T1.VendID, CAST(CAST(MONTH(DT) AS VARCHAR(2)) + '/01/' + CAST(YEAR(DT) AS VARCHAR(4)) AS DATETIME)) T1 INNER JOIN
                      dbo.Makers ON T1.VendID = dbo.Makers.VendID LEFT OUTER JOIN
                          (SELECT     VendID, COUNT(ItemCode) AS TotalItemCount, SUM(OnTime) AS TotalOnTime
                            FROM          (SELECT     *, CASE WHEN RcvDate <= ReturnDT THEN 1 ELSE 0 END AS OnTime, DATEDIFF(d, ReturnDT, RcvDate) AS Days
                                                    FROM          VMakerPerformance) TInner
                            GROUP BY VendID) T2 ON T1.VendID = T2.VendID

GO
