                         dbo.VendIssdDetail.LotNo, dbo.Items.CatID, dbo.Processes.Description, dbo.VendReceived.VendID AS FromVendID, dbo.MakerRepair.DeductFromBilling, dbo.MakerRepair.EmpID, dbo.vendRcvdDetail.RcvdQty,
