CREATE VIEW [dbo].[VEmpLeaveBalance]
AS
SELECT     dbo.VEmp.*, dbo.AnnualLeaves.Casual - ISNULL(VLeaveBalance.TotalCL, 0) AS CLBalance, dbo.AnnualLeaves.Sick - ISNULL(VLeaveBalance.TotalSL,
                      0) AS SLBalance, dbo.AnnualLeaves.Annual - ISNULL(VLeaveBalance.TotalAL, 0) AS ALBalance,
                      dbo.AnnualLeaves.Compensatory - ISNULL(VLeaveBalance.TotalCPL, 0) AS CPLBalance,
                      dbo.AnnualLeaves.Maternity - ISNULL(VLeaveBalance.TotalML, 0) AS MLBalance
FROM         (SELECT     dbo.Leaves.EmpID, COUNT(dbo.Leaves.CL) AS TotalCL, COUNT(dbo.Leaves.SL) AS TotalSL, COUNT(dbo.Leaves.CPL) AS TotalCPL,
                                              COUNT(dbo.Leaves.AL) AS TotalAL, COUNT(dbo.Leaves.ML) AS TotalML
                       FROM          dbo.Leaves CROSS JOIN
                                              dbo.AnnualLeaves
                       GROUP BY dbo.Leaves.EmpID) VLeaveBalance RIGHT OUTER JOIN
                      dbo.VEmp ON dbo.VEmp.empid = VLeaveBalance.EmpID CROSS JOIN
                      dbo.AnnualLeaves


