                      dbo.InternalProductionOrderDetail.CompItemCode, dbo.InternalProductionOrderDetail.SpecialInstructions, dbo.InternalProductionOrderDetailLots.EntryID,
                      dbo.InternalProductionOrderDetailLots.LotQty, dbo.InternalProductionOrderDetailLots.PrintDone, dbo.InternalProductionOrderDetail.Qty,
                      dbo.VItemInitialProcess.Fix_Maker_RefID, dbo.Makers.VenderName, dbo.VItemInitialProcess.ProcessID, dbo.VendAssItems.Rate, dbo.Items.ItemName,
                      dbo.Items.ItemSize, dbo.Items.SizeUnit, dbo.Items.TipSize, dbo.Items.InHand, dbo.InternalProductionOrderDetail.ReservedQty, dbo.VItemInitialProcess.Operation,
