/****** Object:  View [dbo].[VItemsWithShelfWiseStock_Customerwise]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE VIEW [dbo].[VItemsWithShelfWiseStock_Customerwise]
AS
SELECT     dbo.VStoreShelfs.StoreName, dbo.VStoreShelfs.RackNo, dbo.VStoreShelfs.ShelfNo, T1.ItemID, T1.RcvdQty - ISNULL(T1.IssdQty, 0) AS NetQty, T1.Shelf_RefID, T2.Remarks, dbo.VStoreShelfs.Store_RefID, T1.CustCode, T2.CustCode AS Expr1
FROM        dbo.VStoreShelfs INNER JOIN
                      (SELECT     ItemID, Shelf_RefID, CustCode, SUM(RcvdQty) AS RcvdQty, SUM(IssdQty) AS IssdQty
                       FROM        (SELECT     dbo.RcvItemsSimpleDetail.ItemID, dbo.RcvItemsSimple.CustCode, dbo.RcvItemsSimpleDetail_Placement.Shelf_RefID, SUM(dbo.RcvItemsSimpleDetail_Placement.RcvdQty) AS RcvdQty, 0 AS IssdQty
                                          FROM        dbo.RcvItemsSimpleDetail_Placement INNER JOIN
                                                            dbo.RcvItemsSimpleDetail ON dbo.RcvItemsSimpleDetail_Placement.RISD_RefID = dbo.RcvItemsSimpleDetail.EntryID INNER JOIN
                                                            dbo.RcvItemsSimple ON dbo.RcvItemsSimple.RcvNo = dbo.RcvItemsSimpleDetail.RcvNo
                                          GROUP BY dbo.RcvItemsSimpleDetail.ItemID, dbo.RcvItemsSimple.CustCode, dbo.RcvItemsSimpleDetail_Placement.Shelf_RefID
                                          UNION ALL
                                          SELECT     dbo.IssItemsSimpleDetail.ItemID, dbo.IssItemsSimple.CustCode, dbo.IssItemsSimpleDetail_More.Shelf_RefID, 0 AS RcvdQty, SUM(dbo.IssItemsSimpleDetail_More.IssdQty) AS IssdQty
                                          FROM        dbo.IssItemsSimpleDetail INNER JOIN
                                                            dbo.IssItemsSimpleDetail_More ON dbo.IssItemsSimpleDetail.EntryID = dbo.IssItemsSimpleDetail_More.IISD_RefID INNER JOIN
                                                            dbo.IssItemsSimple ON dbo.IssItemsSimple.IssNo = dbo.IssItemsSimpleDetail.IssNo
                                          GROUP BY dbo.IssItemsSimpleDetail.ItemID, dbo.IssItemsSimple.CustCode, dbo.IssItemsSimpleDetail_More.Shelf_RefID) AS TInner1
                       GROUP BY ItemID, CustCode, Shelf_RefID) AS T1 ON dbo.VStoreShelfs.EntryID = T1.Shelf_RefID LEFT OUTER JOIN
                      (SELECT     dbo.VRcvitemsSimpleDetail_Placement.ItemID, dbo.VRcvitemsSimpleDetail_Placement.CustCode, dbo.VRcvitemsSimpleDetail_Placement.Shelf_RefID, dbo.VRcvitemsSimpleDetail_Placement.Remarks
                       FROM        dbo.VRcvitemsSimpleDetail_Placement INNER JOIN
                                             (SELECT     MAX(EntryID) AS MaxEntryID
                                              FROM        dbo.VRcvitemsSimpleDetail_Placement AS VRcvitemsSimpleDetail_Placement_1
                                              GROUP BY ItemID, CustCode, Shelf_RefID) AS TMax ON dbo.VRcvitemsSimpleDetail_Placement.EntryID = TMax.MaxEntryID) AS T2 ON T1.CustCode = T2.CustCode AND T1.ItemID = T2.ItemID AND T1.Shelf_RefID = T2.Shelf_RefID
GO
