CREATE VIEW [dbo].[VrptOrders_ForProduction]
AS
SELECT        TFOrderItems.ItemCode, TFOrderItems.Qty, dbo.VItems_WithFinishedStock.ItemName, dbo.FCustomerCatalog.Description, dbo.FCustomerCatalog.ItemID, dbo.VItems_WithFinishedStock.ItemID AS CompItemID,
                         dbo.ForeignCustomers.Curr, dbo.FCustomerCatalog.Unit, dbo.ForeignCustomers.Name, dbo.ForeignCustomers.Address, dbo.VItems_WithFinishedStock.CustomDescription,
                         dbo.VItems_WithFinishedStock.ItemSize, dbo.VItems_WithFinishedStock.SizeUnit, dbo.SteelTypes.SteelType, dbo.SteelGages.Gage, dbo.VItems_WithFinishedStock.ItemColor, dbo.FCustomerCatalog.BarcodeNo,
                         dbo.FCustomerCatalog.PackingMode, dbo.VItems_WithFinishedStock.MasterCartonL, dbo.VItems_WithFinishedStock.MasterCartonW, dbo.VItems_WithFinishedStock.MasterCartonH,
                         dbo.VItems_WithFinishedStock.SmallCartonL, dbo.VItems_WithFinishedStock.SmallCartonW, dbo.VItems_WithFinishedStock.SmallCartonH, dbo.VItems_WithFinishedStock.PolyBag,
                         dbo.FCustomerCatalog.SpecialInstructions, dbo.FCustomerCatalog.StampInstructions, dbo.FCustomerCatalog.PackingInstructions, dbo.VItems_WithFinishedStock.Unit AS UnitItems,
                         dbo.FCustomerCatalog.ItemColor AS CustomerColor, dbo.VItems_WithFinishedStock.ItemNameUrdu, dbo.VItems_WithFinishedStock.InHand, dbo.ItemCatagories.MaxLotSize,
                         dbo.VItems_WithFinishedStock.FinQuality, dbo.VItems_WithFinishedStock.Type, dbo.FCustomerCatalog.OCR, TShipped.ShippedQty, dbo.FCustomerOrders.OrderNo, dbo.FCustomerOrders.DT,
                         dbo.FCustomerOrders.TradeTerms, dbo.FCustomerOrders.CustCode, dbo.FCustomerOrders.Country, dbo.FCustomerOrders.PartialShipment, dbo.FCustomerOrders.PaymentTerms,
                         dbo.FCustomerOrders.TransShipment, dbo.FCustomerOrders.Packaging, dbo.FCustomerOrders.DeliveryDT, dbo.FCustomerOrders.BatchNo, dbo.FCustomerOrders.CompanyRefID, dbo.FCustomerOrders.StampDT,
                         dbo.FCustomerOrders.Quality, dbo.FCustomerOrders.InternalRefNo, dbo.FCustomerOrders.OrderRcvdVia, dbo.FCustomerOrders.OrderType, TFOrderItems.SetItem, TFOrderItems.OrderItemID,
                         TFOrderItems.CustomerItemCode, TFOrderItems.CompItemCode, dbo.FCustomerOrders.DeliveryDT AS OrderDeliveryDT, TFOrderItems.ItemQuality, TFOrderItems.Remarks, TFOrderItems.DeliveryStatus,
                         TSCW.InHand_CustomerWise
FROM            dbo.FCustomerOrders INNER JOIN
                             (SELECT        dbo.FOrderItems.OrderNo, dbo.FOrderItems.ItemCode, dbo.FOrderItems.CompItemCode, 0 AS SetItem, dbo.FOrderItems.CompItemCode AS OrderItemID, SUM(dbo.FOrderItems.Qty) AS Qty,
                                                         dbo.FOrderItems.ItemCode AS CustomerItemCode, dbo.FOrderItems.Quality AS ItemQuality, dbo.FOrderItems.Remarks, dbo.FOrderItems.DeliveryStatus
                               FROM            dbo.FOrderItems INNER JOIN
                                                         dbo.Items ON dbo.Items.ItemID = dbo.FOrderItems.CompItemCode
                               WHERE        (dbo.Items.ItemType <> 2)
                               GROUP BY dbo.FOrderItems.OrderNo, dbo.FOrderItems.ItemCode, dbo.FOrderItems.CompItemCode, dbo.FOrderItems.Quality, dbo.FOrderItems.Remarks, dbo.FOrderItems.DeliveryStatus
                               UNION ALL
                               SELECT        FOrderItems_1.OrderNo, dbo.ItemsSets.Set_ItemID, dbo.ItemsSets.Set_ItemID AS Expr1, 1 AS SetItem, FOrderItems_1.CompItemCode AS OrderItemID, SUM(FOrderItems_1.Qty * dbo.ItemsSets.Qty)
                                                        AS Qty, FOrderItems_1.ItemCode AS CustomerItemCode, FOrderItems_1.Quality, FOrderItems_1.Remarks, FOrderItems_1.DeliveryStatus
                               FROM            dbo.FOrderItems AS FOrderItems_1 INNER JOIN
                                                        dbo.Items AS Items_1 ON FOrderItems_1.CompItemCode = Items_1.ItemID INNER JOIN
                                                        dbo.ItemsSets ON dbo.ItemsSets.ItemID = Items_1.ItemID
                               WHERE        (Items_1.ItemType = 2)
                               GROUP BY FOrderItems_1.OrderNo, dbo.ItemsSets.Set_ItemID, FOrderItems_1.CompItemCode, FOrderItems_1.ItemCode, FOrderItems_1.Quality, FOrderItems_1.Remarks, FOrderItems_1.DeliveryStatus)
                         AS TFOrderItems ON dbo.FCustomerOrders.OrderNo = TFOrderItems.OrderNo INNER JOIN
                         dbo.FCustomerCatalog ON dbo.FCustomerOrders.CustCode = dbo.FCustomerCatalog.CustCode AND dbo.FCustomerOrders.Country = dbo.FCustomerCatalog.Country AND
                         TFOrderItems.OrderItemID = dbo.FCustomerCatalog.CompItemID INNER JOIN
                         dbo.VItems_WithFinishedStock ON TFOrderItems.CompItemCode = dbo.VItems_WithFinishedStock.ItemID INNER JOIN
                         dbo.ForeignCustomers ON dbo.FCustomerOrders.CustCode = dbo.ForeignCustomers.CustCode AND dbo.FCustomerOrders.Country = dbo.ForeignCustomers.Country INNER JOIN
                         dbo.ItemCatagories ON dbo.VItems_WithFinishedStock.CatID = dbo.ItemCatagories.CatID LEFT OUTER JOIN
                         dbo.SteelGages ON dbo.VItems_WithFinishedStock.Gage = dbo.SteelGages.GageID LEFT OUTER JOIN
                         dbo.SteelTypes ON dbo.VItems_WithFinishedStock.SteelUsed = dbo.SteelTypes.SteelID LEFT OUTER JOIN
                             (SELECT        OrderNo, CompItemCode, SUM(ShippedQty) AS ShippedQty
                               FROM            dbo.VFOrderItemswithShippedQty
                               GROUP BY OrderNo, CompItemCode) AS TShipped ON TFOrderItems.OrderNo = TShipped.OrderNo AND TFOrderItems.CompItemCode = TShipped.CompItemCode LEFT OUTER JOIN
                             (SELECT        CustCode, ItemID, SUM(NetQty) AS InHand_CustomerWise
                               FROM            dbo.VItemsWithShelfWiseStock_Customerwise
                               GROUP BY CustCode, ItemID) AS TSCW ON dbo.FCustomerOrders.CustCode = TSCW.CustCode AND TFOrderItems.CompItemCode = TSCW.ItemID

GO
/****** Object:  View [dbo].[VFOrderItemPTC_Repair]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*LEFT OUTER JOIN (SELECT LotNo AS FromLotNo,ProcessID FROM LotTransferDetails INNER JOIN VendRcvdDetail ON VRD_To_RefID=VendRcvdDetail.EntryID) TSplit1 ON TSplit1.VRD_*/
CREATE VIEW [dbo].[VFOrderItemPTC_Repair]
AS
SELECT     TFOrderItems.OrderNo, TFOrderItems.ItemCode, TFOrderItems.Qty, dbo.FCustomerOrders.CustCode, dbo.FCustomerOrders.Country, dbo.FCustomerOrders.DT, dbo.Items.ItemName, dbo.Items.ItemSize, dbo.Items.SizeUnit, dbo.Items.Type,
                  dbo.FCustomerOrders.Packaging, dbo.FCustomerOrders.DeliveryDT, dbo.RepairTypeProcesses.SeqNo AS SNO, dbo.RepairTypeProcesses.ProcessID, dbo.Processes.Description, Tab1.RcvdQty, Tab2.LotNo, Tab1.VendID, dbo.Makers.VenderName, Tab1.RcvDT,
                  TabIss.IssDT, TabMin.MinProcessID, Tab1.Wastage, Tab1.PassQty, dbo.Employees.empid, dbo.Employees.name, Tab1.ReWorkQty, TFOrderItems.CompItemCode, dbo.Processes.Code, dbo.Processes.ProcessNameUrdu, dbo.Items.ItemNameUrdu,
                  EmpRcv.name AS RcvEmpName, Tab1.Rate, TMasterPO.MasterPONo, TSteelBatch.SteelBatchNo, TForgeBatch.ForgeBatchNo, TSFRemarks.SFRemarks, TSplit.SplitQty, ISNULL(TSplit.Type, TSplitFrom.SplitTypeFrom) AS SplitType, TSplit.ToOrderNo, TSplit.ToLotNo,
                  TSplitFrom.FromOrderNo, TSplitFrom.FromLotNo, TSplitFrom.SplitQtyFrom, dbo.RepairLot_OriginalLots_F(Tab2.LotNo) AS RepairGeneratedFrom, dbo.RepairTypes.RepairType, TLastRcv.LotLastEntryID, Tab_TTRF.TTRFQty, Tab1.ReceivedEntryID,
                  dbo.VendReceived_Employees_F(Tab1.ReceivedEntryID) AS Employees, dbo.FCustomerOrders.InternalRefNo, dbo.Items.Additional_Detail
FROM        (SELECT     OrderNo, ItemCode, CompItemID AS CompItemCode, SUM(Qty) AS Qty
                   FROM        dbo.VrptOrders_ForProduction
                   GROUP BY OrderNo, ItemCode, CompItemID) AS TFOrderItems INNER JOIN
                  dbo.Items ON TFOrderItems.CompItemCode = dbo.Items.ItemID INNER JOIN
                  dbo.FCustomerOrders ON TFOrderItems.OrderNo = dbo.FCustomerOrders.OrderNo LEFT OUTER JOIN
                      (SELECT DISTINCT OrderNo, ItemCode, LotNo, Repair_RefID
                       FROM        dbo.vendRcvdDetail) AS Tab2 ON TFOrderItems.OrderNo = Tab2.OrderNo AND TFOrderItems.CompItemCode = Tab2.ItemCode INNER JOIN
                  dbo.RepairTypeProcesses ON dbo.RepairTypeProcesses.Repair_RefID = Tab2.Repair_RefID INNER JOIN
                  dbo.Processes ON dbo.RepairTypeProcesses.ProcessID = dbo.Processes.ProcessID INNER JOIN
                  dbo.RepairTypes ON Tab2.Repair_RefID = dbo.RepairTypes.EntryID LEFT OUTER JOIN
                      (SELECT     VendRcvdDetail_2.ProcessID, VendRcvdDetail_2.LotNo, VendRcvdDetail_2.Rate, dbo.VendReceived.EmpID, VendRcvdDetail_2.RcvdQty, CASE WHEN ReqAuth = 1 THEN 0 ELSE RcvdQty END AS PassQty, dbo.VendReceived.VendID,
                                         dbo.VendReceived.DT AS RcvDT, VendRcvdDetail_2.Wastage, VendRcvdDetail_2.ReWorkQty, dbo.VendReceived.EntryID AS ReceivedEntryID
                       FROM        dbo.vendRcvdDetail AS VendRcvdDetail_2 INNER JOIN
                                         dbo.VendReceived ON dbo.VendReceived.EntryID = VendRcvdDetail_2.RefID) AS Tab1 ON Tab2.LotNo = Tab1.LotNo AND dbo.RepairTypeProcesses.ProcessID = Tab1.ProcessID LEFT OUTER JOIN
                      (SELECT     dbo.VendIssued.ProcessID, dbo.VendIssdDetail.LotNo, dbo.VendIssdDetail_MoreDetails.EmpID, dbo.VendIssdDetail.Repair_RefID, MIN(dbo.VendIssued.DT) AS IssDT
                       FROM        dbo.VendIssued INNER JOIN
                                         dbo.VendIssdDetail ON dbo.VendIssued.EntryID = dbo.VendIssdDetail.RefID LEFT OUTER JOIN
                                         dbo.VendIssdDetail_MoreDetails ON dbo.VendIssdDetail.EntryID = dbo.VendIssdDetail_MoreDetails.VID_RefID
                       GROUP BY dbo.VendIssued.ProcessID, dbo.VendIssdDetail.LotNo, dbo.VendIssdDetail_MoreDetails.EmpID, dbo.VendIssdDetail.Repair_RefID) AS TabIss ON Tab2.LotNo = TabIss.LotNo AND
                  dbo.RepairTypeProcesses.ProcessID = TabIss.ProcessID LEFT OUTER JOIN
                      (SELECT     VendRcvdDetail_1.LotNo, MIN(VendReceived_1.ProcessID) AS MinProcessID
                       FROM        dbo.VendReceived AS VendReceived_1 INNER JOIN
                                         dbo.vendRcvdDetail AS VendRcvdDetail_1 ON VendReceived_1.EntryID = VendRcvdDetail_1.RefID
                       GROUP BY VendRcvdDetail_1.LotNo) AS TabMin ON Tab2.LotNo = TabMin.LotNo LEFT OUTER JOIN
                  dbo.Makers ON Tab1.VendID = dbo.Makers.VendID LEFT OUTER JOIN
                  dbo.Employees ON TabIss.EmpID = dbo.Employees.empid LEFT OUTER JOIN
                  dbo.Employees AS EmpRcv ON Tab1.EmpID = EmpRcv.empid LEFT OUTER JOIN
                      (SELECT     TNest1.LotNo, VendIssued_1.EntryID, VendIssued_1.MasterPONo
                       FROM        dbo.VendIssued AS VendIssued_1 INNER JOIN
                                         dbo.VendIssdDetail AS VendIssdDetail_1 ON VendIssued_1.EntryID = VendIssdDetail_1.RefID INNER JOIN
                                             (SELECT     LotNo, MIN(Issue_RefID) AS Issue_RefID
                                              FROM        dbo.vendRcvdDetail AS vendRcvdDetail_8
                                              GROUP BY LotNo) AS TNest1 ON TNest1.Issue_RefID = VendIssdDetail_1.EntryID) AS TMasterPO ON Tab1.LotNo = TMasterPO.LotNo LEFT OUTER JOIN
                      (SELECT     dbo.RawMaterialIssuance.VI_RefID, MAX(dbo.RawMaterialIssuanceDetail.PORefNo) AS SteelBatchNo
                       FROM        dbo.RawMaterialIssuance INNER JOIN
                                         dbo.RawMaterialIssuanceDetail ON dbo.RawMaterialIssuance.IssNo = dbo.RawMaterialIssuanceDetail.IssNo INNER JOIN
                                         dbo.RM ON dbo.RawMaterialIssuanceDetail.RMID1 = dbo.RM.RMID1
                       WHERE     (dbo.RM.GroupID = 20)
                       GROUP BY dbo.RawMaterialIssuance.VI_RefID) AS TSteelBatch ON TMasterPO.EntryID = TSteelBatch.VI_RefID LEFT OUTER JOIN
                      (SELECT     RawMaterialIssuance_1.VI_RefID, MAX(RawMaterialIssuanceDetail_1.PORefNo) AS ForgeBatchNo
                       FROM        dbo.RawMaterialIssuance AS RawMaterialIssuance_1 INNER JOIN
                                         dbo.RawMaterialIssuanceDetail AS RawMaterialIssuanceDetail_1 ON RawMaterialIssuance_1.IssNo = RawMaterialIssuanceDetail_1.IssNo INNER JOIN
                                         dbo.RM AS RM_1 ON RawMaterialIssuanceDetail_1.RMID1 = RM_1.RMID1
                       WHERE     (RM_1.GroupID IN (25, 27, 28, 29, 30))
                       GROUP BY RawMaterialIssuance_1.VI_RefID) AS TForgeBatch ON TMasterPO.EntryID = TForgeBatch.VI_RefID LEFT OUTER JOIN
                      (SELECT     vendRcvdDetail_7.ProcessID, vendRcvdDetail_7.LotNo, dbo.StockOrderOpening.Remarks AS SFRemarks
                       FROM        dbo.StockOrderOpening INNER JOIN
                                         dbo.StockOrderOpening_Issuance ON dbo.StockOrderOpening.EntryID = dbo.StockOrderOpening_Issuance.SOO_RefID INNER JOIN
                                         dbo.vendRcvdDetail AS vendRcvdDetail_7 ON dbo.StockOrderOpening_Issuance.VID_RefID = vendRcvdDetail_7.Issue_RefID) AS TSFRemarks ON Tab2.LotNo = TSFRemarks.LotNo AND Tab1.ProcessID = TSFRemarks.ProcessID LEFT OUTER JOIN
                      (SELECT     vendRcvdDetail_6.LotNo, vendRcvdDetail_6.ProcessID, dbo.LotTransferDetails.SplitQty, dbo.LotTransferDetails.Type, dbo.LotTransferDetails.ToOrderNo, VendRcvdDetail_1.LotNo AS ToLotNo
                       FROM        dbo.LotTransferDetails INNER JOIN
                                         dbo.vendRcvdDetail AS vendRcvdDetail_6 ON dbo.LotTransferDetails.VRD_From_RefID = vendRcvdDetail_6.EntryID INNER JOIN
                                         dbo.vendRcvdDetail AS VendRcvdDetail_1 ON dbo.LotTransferDetails.VRD_To_RefID = VendRcvdDetail_1.EntryID) AS TSplit ON Tab2.LotNo = TSplit.LotNo AND Tab1.ProcessID = TSplit.ProcessID LEFT OUTER JOIN
                      (SELECT     vendRcvdDetail_5.LotNo AS FromLotNo, vendRcvdDetail_5.ProcessID, LotTransferDetails_1.SplitQty AS SplitQtyFrom, LotTransferDetails_1.Type AS SplitTypeFrom, LotTransferDetails_1.FromOrderNo, VendRcvdDetail_1.LotNo
                       FROM        dbo.LotTransferDetails AS LotTransferDetails_1 INNER JOIN
                                         dbo.vendRcvdDetail AS vendRcvdDetail_5 ON LotTransferDetails_1.VRD_From_RefID = vendRcvdDetail_5.EntryID INNER JOIN
                                         dbo.vendRcvdDetail AS VendRcvdDetail_1 ON LotTransferDetails_1.VRD_To_RefID = VendRcvdDetail_1.EntryID) AS TSplitFrom ON Tab2.LotNo = TSplitFrom.LotNo AND Tab1.ProcessID = TSplitFrom.ProcessID LEFT OUTER JOIN
                      (SELECT     LotNo, MAX(EntryID) AS LotLastEntryID
                       FROM        dbo.vendRcvdDetail AS vendRcvdDetail_4
                       GROUP BY LotNo) AS TLastRcv ON Tab2.LotNo = TLastRcv.LotNo LEFT OUTER JOIN
                      (SELECT     vendRcvdDetail_3.ProcessID, vendRcvdDetail_3.LotNo, SUM(dbo.TransferredToReadyFinishLotsDetail.Qty) AS TTRFQty
                       FROM        dbo.TransferredToReadyFinishLotsDetail INNER JOIN
                                         dbo.vendRcvdDetail AS vendRcvdDetail_3 ON dbo.TransferredToReadyFinishLotsDetail.VRD_RefID = vendRcvdDetail_3.EntryID
                       GROUP BY vendRcvdDetail_3.ProcessID, vendRcvdDetail_3.LotNo) AS Tab_TTRF ON Tab1.ProcessID = Tab_TTRF.ProcessID AND Tab2.LotNo = Tab_TTRF.LotNo
GO
