CREATE VIEW [dbo].[VFOrderTotalQty]
AS
SELECT     OrderNo, SUM(Qty) AS TotalOrderQty, SUM(InvQty) AS TotalInvQty,SUM(dbo.FOrderItems.Qty*Items.FinishedWeight) AS TotalWeight
FROM         dbo.FOrderItems INNER JOIN Items ON FOrderItems.CompItemCode=Items.ItemID
GROUP BY OrderNo

GO
/****** Object:  View [dbo].[VFOrderList]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE VIEW [dbo].[VFOrderList]
AS
SELECT     dbo.FCustomerOrders.OrderNo, dbo.FCustomerOrders.DT, dbo.FCustomerOrders.CustCode, dbo.FCustomerOrders.Country, dbo.F_OrderAmt(dbo.FCustomerOrders.OrderNo, 0) AS OrderAmt,
                      dbo.ForeignCustomers.Curr, dbo.VFOrderTotalQty.TotalInvQty, dbo.VFOrderTotalQty.TotalOrderQty, dbo.FCustomerOrders.DeliveryDT, dbo.FCustomerOrders.CompanyRefID,
                      dbo.Companies.CompanyName, dbo.VUnshippedOrderList.OrderNo AS UnshippedOrderNo, TotalShipped.TotalShippedQty, dbo.VCurrencyExchangeRates.ExchRate,
                      dbo.FCustomerOrders.InternalRefNo, ROUND(dbo.VFOrderTotalQty.TotalWeight, 2) AS TotalWeight, TotalShipped.TotalShippedAmt, ISNULL(dbo.FCustomerFinalOrders.Cancelled, 0) AS Cancelled,
                      TotalQuantities.TotalArticles, dbo.FCustomerFinalOrders.Remarks, TotalShipped.ShippedItemCount, TotalShipped.ShippedItemQty, TotalShipped.PartiallyShippedItemCount,
                      TotalShipped.PartiallyShippedItemQty, TotalShipped.TotalBalanceQty, dbo.FCustomerOrders.OrderType, T1.TotalPlannedQty, dbo.FCustomerOrders.OrderPlanApproved
                      ,dbo.ForeignCustomers.LateOrderAlerts
FROM         dbo.FCustomerOrders INNER JOIN
                      dbo.ForeignCustomers ON dbo.FCustomerOrders.CustCode = dbo.ForeignCustomers.CustCode AND dbo.FCustomerOrders.Country = dbo.ForeignCustomers.Country INNER JOIN
                      dbo.VFOrderTotalQty ON dbo.FCustomerOrders.OrderNo = dbo.VFOrderTotalQty.OrderNo INNER JOIN
                      dbo.Companies ON dbo.FCustomerOrders.CompanyRefID = dbo.Companies.EntryID LEFT OUTER JOIN
                      dbo.VUnshippedOrderList ON dbo.FCustomerOrders.OrderNo = dbo.VUnshippedOrderList.OrderNo INNER JOIN
                          (SELECT     OrderNo, SUM(Qty) AS TotalOrderQty, COUNT(*) AS TotalArticles
                            FROM          dbo.FOrderItems
                            GROUP BY OrderNo) AS TotalQuantities ON dbo.FCustomerOrders.OrderNo = TotalQuantities.OrderNo LEFT OUTER JOIN
                      dbo.FCustomerFinalOrders ON dbo.FCustomerOrders.OrderNo = dbo.FCustomerFinalOrders.OrderNo LEFT OUTER JOIN
                          (SELECT     OrderNo, SUM(ShippedQty) AS TotalShippedQty, SUM(ShippedQty * Price) AS TotalShippedAmt, SUM(CASE WHEN ShippedQty >= Qty THEN 1 ELSE 0 END) AS ShippedItemCount,
                                                   SUM(CASE WHEN ShippedQty >= Qty THEN ShippedQty ELSE 0 END) AS ShippedItemQty, SUM(CASE WHEN ShippedQty > 0 AND ShippedQty < Qty THEN 1 ELSE 0 END)
                                                   AS PartiallyShippedItemCount, SUM(CASE WHEN ShippedQty > 0 AND ShippedQty < Qty THEN ShippedQty ELSE 0 END) AS PartiallyShippedItemQty,
                                                   SUM(CASE WHEN ShippedQty >= Qty THEN 0 ELSE Qty - ShippedQty END) AS TotalBalanceQty
                            FROM          dbo.VFOrderItemswithShippedQty
                            WHERE      (CompItemCode IN
                                                       (SELECT     ItemID
                                                         FROM          dbo.Items))
                            GROUP BY OrderNo) AS TotalShipped ON dbo.FCustomerOrders.OrderNo = TotalShipped.OrderNo LEFT OUTER JOIN
                      dbo.VCurrencyExchangeRates ON dbo.ForeignCustomers.Curr = dbo.VCurrencyExchangeRates.Currency LEFT OUTER JOIN
                          (SELECT     OrderNo, SUM(Qty) AS TotalPlannedQty
                            FROM          dbo.OrderPlanningDetails
                            GROUP BY OrderNo) AS T1 ON dbo.FCustomerOrders.OrderNo = T1.OrderNo

GO
/****** Object:  View [dbo].[VProductionStatusForProductionOrder]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VProductionStatusForProductionOrder]
AS
SELECT     FOrderItems.OrderNo, FOrderItems.ItemCode,TabProc1.Qty AS FiledStock,TabProc2.Qty AS BTStock,TabProc3.Qty AS TemperStock,TabProc4.Qty AS BCStock,TabProc5.Qty AS FittingStock,TabProc6.Qty AS PolishingStock
,TabProc7.Qty AS EPStock,TabProc8.Qty AS EBStock,TabProc9.Qty AS SBStock,TabProc10.Qty AS SettingStock,TabProc11.Qty AS FPStock,TabProc12.Qty AS UCStock,TabProc13.Qty AS PackingStock
,TabProc14.Qty AS ReadyFinishStock,TabProc15.Qty AS SemiFinishedStock
,TabIssFiled.Qty AS FieldIss,TabIssRF.Qty AS RFIss,TabIssSF.Qty AS SFIss,TabVends.VendID
FROM         dbo.FOrderItems
LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode FROM VVendIssdDetail GROUP BY VendID,OrderNo,ItemCode) TabVends ON FOrderItems.OrderNo=TabVends.OrderNo AND FOrderItems.ItemCode=TabVends.ItemCode

LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(RcvdQty-IssQty) AS Qty FROM VVendRcvdDetail WHERE ProcessID=1 GROUP BY VendID,OrderNo,ItemCode) TabProc1 ON TabProc1.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabProc1.OrderNo
LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(RcvdQty-IssQty) AS Qty FROM VVendRcvdDetail WHERE ProcessID=2 GROUP BY VendID,OrderNo,ItemCode) TabProc2 ON TabProc2.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabProc2.OrderNo
LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(RcvdQty-IssQty) AS Qty FROM VVendRcvdDetail WHERE ProcessID=3 GROUP BY VendID,OrderNo,ItemCode) TabProc3 ON TabProc3.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabProc3.OrderNo
LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(RcvdQty-IssQty) AS Qty FROM VVendRcvdDetail WHERE ProcessID=4 GROUP BY VendID,OrderNo,ItemCode) TabProc4 ON TabProc4.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabProc4.OrderNo
LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(RcvdQty-IssQty) AS Qty FROM VVendRcvdDetail WHERE ProcessID=5 GROUP BY VendID,OrderNo,ItemCode) TabProc5 ON TabProc5.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabProc5.OrderNo
LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(RcvdQty-IssQty) AS Qty FROM VVendRcvdDetail WHERE ProcessID=6 GROUP BY VendID,OrderNo,ItemCode) TabProc6 ON TabProc6.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabProc6.OrderNo
LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(RcvdQty-IssQty) AS Qty FROM VVendRcvdDetail WHERE ProcessID=7 GROUP BY VendID,OrderNo,ItemCode) TabProc7 ON TabProc7.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabProc7.OrderNo
LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(RcvdQty-IssQty) AS Qty FROM VVendRcvdDetail WHERE ProcessID=8 GROUP BY VendID,OrderNo,ItemCode) TabProc8 ON TabProc8.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabProc8.OrderNo
LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(RcvdQty-IssQty) AS Qty FROM VVendRcvdDetail WHERE ProcessID=9 GROUP BY VendID,OrderNo,ItemCode) TabProc9 ON TabProc9.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabProc9.OrderNo
LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(RcvdQty-IssQty) AS Qty FROM VVendRcvdDetail WHERE ProcessID=10 GROUP BY VendID,OrderNo,ItemCode) TabProc10 ON TabProc10.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabProc10.OrderNo
LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(RcvdQty-IssQty) AS Qty FROM VVendRcvdDetail WHERE ProcessID=11 GROUP BY VendID,OrderNo,ItemCode) TabProc11 ON TabProc11.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabProc11.OrderNo
LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(RcvdQty-IssQty) AS Qty FROM VVendRcvdDetail WHERE ProcessID=12 GROUP BY VendID,OrderNo,ItemCode) TabProc12 ON TabProc12.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabProc12.OrderNo
LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(RcvdQty-IssQty) AS Qty FROM VVendRcvdDetail WHERE ProcessID=13 GROUP BY VendID,OrderNo,ItemCode) TabProc13 ON TabProc13.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabProc13.OrderNo
LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(RcvdQty-IssQty) AS Qty FROM VVendRcvdDetail WHERE ProcessID=27 GROUP BY VendID,OrderNo,ItemCode) TabProc14 ON TabProc14.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabProc14.OrderNo
LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(RcvdQty-IssQty) AS Qty FROM VVendRcvdDetail WHERE ProcessID=28 GROUP BY VendID,OrderNo,ItemCode) TabProc15 ON TabProc15.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabProc15.OrderNo

LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(IssQty-RcvdQty) AS Qty FROM VVendIssdDetail WHERE ProcessID=1 GROUP BY VendID,OrderNo,ItemCode) TabIssFiled ON TabIssFiled.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabIssFiled.OrderNo
LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(IssQty-RcvdQty) AS Qty FROM VVendIssdDetail WHERE ProcessID=27 GROUP BY VendID,OrderNo,ItemCode) TabIssRF ON TabIssRF.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabIssRF.OrderNo
LEFT OUTER JOIN (SELECT VendID,OrderNo,ItemCode,SUM(IssQty-RcvdQty) AS Qty FROM VVendIssdDetail WHERE ProcessID=28 GROUP BY VendID,OrderNo,ItemCode) TabIssSF ON TabIssSF.VendID=TabVends.VendID AND FOrderItems.OrderNo=TabIssSF.OrderNo



