CREATE VIEW [dbo].[VFPInvoice]
AS
SELECT        dbo.ForeignCustomers.Curr, dbo.ForeignCustomers.Name, dbo.ForeignCustomers.Address, VPorts_2.CountryName AS LoadCountry, VPorts_2.CityID AS LoadCityID, VPorts_2.City AS LoadCity, VPorts_2.PortID AS LoadPortID,
                         VPorts_2.Port AS LoadPort, VPorts_1.CountryName AS DisCountry, VPorts_1.CityID AS DisCityID, VPorts_1.City AS DisCity, VPorts_1.PortID AS DisPortID, VPorts_1.Port AS DisPort, dbo.FPInvoice.PInvoice, dbo.FPInvoice.DT,
                         dbo.FPInvoice.CustCode, dbo.FPInvoice.Country, dbo.FPInvoice.SMethod, dbo.FPInvoice.TradeTerms, dbo.FPInvoice.PaymentTerms, dbo.FPInvoice.BankID, dbo.FPInvoice.PartialShipment, dbo.FPInvoice.TransShipment,
                         dbo.FPInvoice.packaging, dbo.FPInvoice.DeliveryDT AS ProformaDeliveryDT, dbo.ForeignCustomers.Cont1name, dbo.ForeignCustomers.DTFormat, dbo.FCustBanks.BankName, dbo.FCustBanks.Address1, dbo.FPInvoice.Marks,
                         dbo.FPInvoice.Measurement, dbo.FPInvoice.SpecialInstr, dbo.FPInvoice.GrossW, dbo.FPInvoice.NetW, dbo.FPInvoice.Goods, dbo.ShippingAgents.Name AS ShippingAgentName,
                         dbo.InsuranceAgents.Name AS InsuranceAgentName, dbo.FPInvoice.ShippingAgent AS ShippingAgentID, dbo.FPInvoice.InsuranceAgent AS InsuranceAgentID, dbo.FPInvoice.LCNo, dbo.FPInvoice.BatchNo,
                         dbo.FPInvoice.Declarations, dbo.FPInvoice.PInvoiceID, dbo.ForeignCustomers.FakeAddress, dbo.FCustBanks.Address2, dbo.FPInvoice.OurBankID, dbo.BankList.Bank, dbo.FPInvoice.CompanyRefID,
                         dbo.Companies.CompanyName, dbo.FPInvoice.InvoiceOf, dbo.FPInvoice.DeliveryDetail, dbo.FPInvoice.Packages, dbo.FPInvoice.ShippingAddress, dbo.FPInvoice.Notes1, dbo.FPInvoice.Notes2, dbo.FPInvoice.DiscountPer,
                         dbo.FPInvoice.DiscountAmount, dbo.FPInvoice.Insurance_Freight_Amount, dbo.FPInvoice.Insurance_Freight_Amount_II, dbo.FPInvoice.Discount_Description, dbo.FPInvoice.Insurance_Description,
                         dbo.FPInvoice.Insurance_Description_II, dbo.FPInvoice.CIF_Description, dbo.FPInvoice.Total_Description,dbo.FPInvoice.InvoiceTo
FROM            dbo.Companies INNER JOIN
                         dbo.ForeignCustomers INNER JOIN
                         dbo.FPInvoice ON dbo.ForeignCustomers.CustCode = dbo.FPInvoice.CustCode AND dbo.ForeignCustomers.Country = dbo.FPInvoice.Country ON dbo.Companies.EntryID = dbo.FPInvoice.CompanyRefID LEFT OUTER JOIN
                         dbo.BankList ON dbo.FPInvoice.OurBankID = dbo.BankList.BankID LEFT OUTER JOIN
                         dbo.InsuranceAgents ON dbo.FPInvoice.InsuranceAgent = dbo.InsuranceAgents.EntryID LEFT OUTER JOIN
                         dbo.ShippingAgents ON dbo.FPInvoice.ShippingAgent = dbo.ShippingAgents.EntryID LEFT OUTER JOIN
                         dbo.FCustBanks ON dbo.FPInvoice.BankID = dbo.FCustBanks.BankID LEFT OUTER JOIN
                         dbo.VPorts AS VPorts_1 ON dbo.FPInvoice.DischargePort = VPorts_1.PortID LEFT OUTER JOIN
                         dbo.VPorts AS VPorts_2 ON dbo.FPInvoice.LoadPort = VPorts_2.PortID
GO
