CREATE VIEW [dbo].[VLotsWithMasterPONo]
AS
SELECT        dbo.vendRcvdDetail.LotNo, dbo.VendIssued.MasterPONo, dbo.Makers.VenderName, dbo.Makers.VendID1, dbo.VendIssdDetail.Batch_No, dbo.VendIssued.DT AS MasterPODT
FROM            dbo.vendRcvdDetail INNER JOIN
                         dbo.VendIssdDetail ON dbo.vendRcvdDetail.Issue_RefID = dbo.VendIssdDetail.EntryID INNER JOIN
                         dbo.VendIssued ON dbo.VendIssdDetail.RefID = dbo.VendIssued.EntryID INNER JOIN
                         dbo.Makers ON dbo.VendIssued.VendID = dbo.Makers.VendID
WHERE        (dbo.vendRcvdDetail.EntryID IN
                             (SELECT        MIN(EntryID) AS Expr1
                                FROM            dbo.vendRcvdDetail AS vendRcvdDetail_1
                                GROUP BY LotNo))
