CREATE VIEW [dbo].[VVendOrdersList]
AS
SELECT        dbo.VendOrders.DT, dbo.VendOrders.VendID, dbo.VVendersAndMakers.AccTitle, dbo.VendOrders.AttnPerson, dbo.VendOrders.PaymentTerms,
                         dbo.VendOrders.Department, dbo.VendOrders.DeliveryDT, dbo.VendOrders.Remarks, dbo.VendOrders.OrderNo, dbo.VendOrders.ReqNo, dbo.VendOrders.Final,
                         dbo.VendOrders.RunningPONo, dbo.VendOrders.IssuanceType, dbo.VendOrders.PDFAttachment, T1.TotalQtyOrdered, dbo.VendOrders.SampleOrder,
                         T2.OrderNo AS RcvableOrderNo, TRcvs.TotalQtyRcvd
FROM            dbo.VendOrders LEFT OUTER JOIN
                         dbo.VVendersAndMakers ON dbo.VendOrders.VendID = dbo.VVendersAndMakers.AccNo LEFT OUTER JOIN
                             (SELECT        OrderNo, SUM(Qty) AS TotalQtyOrdered
                                FROM            dbo.VendOrderDetail
                                GROUP BY OrderNo) AS T1 ON dbo.VendOrders.OrderNo = T1.OrderNo LEFT OUTER JOIN
                             (SELECT        PORefNo, SUM(QtyRcvd) AS TotalQtyRcvd
                                FROM            dbo.VendRcvdDetailPO
                                GROUP BY PORefNo) AS TRcvs ON dbo.VendOrders.OrderNo = TRcvs.PORefNo LEFT OUTER JOIN
                             (SELECT DISTINCT OrderNo
                                FROM            dbo.VVendOrdersToRcv AS VVendOrdersToRcv_1) AS T2 ON dbo.VendOrders.OrderNo = T2.OrderNo

