CREATE VIEW [dbo].[VRunningLots_Simple_Ex]
AS
SELECT     T1.ItemCode, T1.LotNo, T1.OrderNo, T1.Description, T1.Qty, T1.ProcessID, T1.VendID, T1.ReWorkLot, dbo.VLotWithR2InDate.DT AS R2InDT,
                      dbo.VItemPolishingProcessSNo.PolishingItemSNo, dbo.ItemProcesses.SNO, T1.DT
FROM         (SELECT     ItemCode, LotNo, OrderNo, Description, IssQty - RcvdQty AS Qty, ProcessID, VendID, ReWorkLot, DT
                        FROM         dbo.VVendIssdDetail
                        WHERE     (LotNo <> '0') AND (IssQty - RcvdQty > 0) AND (EntryID NOT IN
                                                  (SELECT     Issue_RefID
                                                     FROM         dbo.VendRcvdDetail))
                        UNION
                        SELECT     ItemCode, LotNo, OrderNo, Description, RcvdQty - IssQty - ISNULL(Wastage, 0) AS Qty, ProcessID, VendID, ReWorkLot, DT
                        FROM         dbo.VVendRcvdDetail_Simple
                        WHERE     (LotNo <> '0') AND (RcvdQty - IssQty - ISNULL(Wastage, 0) > 0) AND (EntryID NOT IN
                                                  (SELECT     Rcvd_RefID
                                                     FROM         dbo.VendIssdDetail
                                                     WHERE     (Rcvd_RefID IS NOT NULL))) AND (ISNULL(Opening_RefID, 0) = 0)) AS T1 LEFT OUTER JOIN
                      dbo.VLotWithR2InDate ON T1.LotNo = dbo.VLotWithR2InDate.LotNo LEFT OUTER JOIN
                      dbo.VItemPolishingProcessSNo ON T1.ItemCode = dbo.VItemPolishingProcessSNo.ItemCode LEFT OUTER JOIN
                      dbo.ItemProcesses ON T1.ItemCode = dbo.ItemProcesses.ItemID AND dbo.ItemProcesses.ProcessID = T1.ProcessID

