CREATE VIEW [dbo].[VProformaDetail]
AS
SELECT        dbo.FOrderItems.ID, dbo.FOrderItems.ItemCode, dbo.FProformaOrders.Price, dbo.FOrderItems.Qty, dbo.FOrderItems.InvQty, dbo.Items.ItemName, dbo.FCustomerCatalog.Description, dbo.FCustomerCatalog.ItemID,
                         dbo.FCustomerCatalog.CompItemID, dbo.ForeignCustomers.Curr, dbo.FCustomerCatalog.Unit, dbo.ForeignCustomers.Name, dbo.ForeignCustomers.Address, dbo.FOrderItems.OrderNo, dbo.ForeignCustomers.Cont1name,
                         dbo.ForeignCustomers.DTFormat, dbo.FCustomerCatalog.PackingMode, dbo.VItems1.CompleteItemName, dbo.FProformaOrders.CustomPrice, dbo.FProformaOrders.Qty AS ProformaQty, dbo.ForeignCustomers.FakeAddress,
                         dbo.ItemCatagories.Description AS ItemCatagory, dbo.ItemCatagories.SRONo, dbo.FPInvoice.PInvoice, dbo.FPInvoice.BatchNo, dbo.FCustomerOrders.DeliveryDT, dbo.Items.CatID, dbo.FProformaOrders.EntryID,
                         dbo.FCustomerOrders.DT, dbo.VItems1.ItemGroup, dbo.FProformaOrders.InvQty AS CustomInvQty, dbo.FOrderItems.DeliveryDT AS DeliveryDTItem, dbo.FOrderItems.Stamps AS StampsItem,
                         dbo.FOrderItems.Quality AS QualityItem, dbo.FProformaOrders.Item_Highlight,dbo.FProformaOrders.ItemDescription
FROM            dbo.FCustomerOrders INNER JOIN
                         dbo.FOrderItems ON dbo.FCustomerOrders.OrderNo = dbo.FOrderItems.OrderNo INNER JOIN
                         dbo.Items INNER JOIN
                         dbo.FCustomerCatalog ON dbo.Items.ItemID = dbo.FCustomerCatalog.CompItemID INNER JOIN
                         dbo.FPInvoice ON dbo.FCustomerCatalog.CustCode = dbo.FPInvoice.CustCode AND dbo.FCustomerCatalog.Country = dbo.FPInvoice.Country INNER JOIN
                         dbo.FProformaOrders ON dbo.FPInvoice.PInvoice = dbo.FProformaOrders.PInvoice INNER JOIN
                         dbo.ForeignCustomers ON dbo.FPInvoice.CustCode = dbo.ForeignCustomers.CustCode AND dbo.FPInvoice.Country = dbo.ForeignCustomers.Country INNER JOIN
                         dbo.ItemCatagories ON dbo.Items.CatID = dbo.ItemCatagories.CatID ON dbo.FCustomerOrders.CustCode = dbo.ForeignCustomers.CustCode AND dbo.FCustomerOrders.Country = dbo.ForeignCustomers.Country AND
                         dbo.FOrderItems.ID = dbo.FProformaOrders.OrderEntryID AND dbo.FOrderItems.CompItemCode = dbo.FCustomerCatalog.CompItemID INNER JOIN
                         dbo.VItems1 ON dbo.FOrderItems.CompItemCode = dbo.VItems1.ItemID
