/****** Object:  View [dbo].[VSemiFinish_Shelf_Lot_Batch_Wise_Stock]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VSemiFinish_Shelf_Lot_Batch_Wise_Stock]
AS
SELECT        dbo.VStoreShelfs.StoreName, dbo.VStoreShelfs.RackNo, dbo.VStoreShelfs.ShelfNo, T1.ItemID, T1.RcvdQty - ISNULL(T1.IssdQty, 0) AS NetQty, T1.Shelf_RefID, T2.Remarks, dbo.VStoreShelfs.Store_RefID, T1.LotNo_Manual,
                         T1.BatchNo_Manual
FROM            dbo.VStoreShelfs INNER JOIN
                             (SELECT        ItemID, Shelf_RefID, SUM(RcvdQty) AS RcvdQty, SUM(IssdQty) AS IssdQty, LotNo_Manual, BatchNo_Manual
                                FROM            (SELECT        dbo.RcvItemsSimpleDetail.ItemID, dbo.RcvItemsSimpleDetail_Placement.Shelf_RefID, SUM(dbo.RcvItemsSimpleDetail_Placement.RcvdQty) AS RcvdQty, 0 AS IssdQty,
                                                                                    dbo.RcvItemsSimpleDetail.LotNo_Manual, dbo.RcvItemsSimpleDetail.BatchNo_Manual
                                                           FROM            dbo.RcvItemsSimpleDetail_Placement INNER JOIN
                                                                                    dbo.RcvItemsSimpleDetail ON dbo.RcvItemsSimpleDetail_Placement.RISD_RefID = dbo.RcvItemsSimpleDetail.EntryID
                                                           GROUP BY dbo.RcvItemsSimpleDetail.ItemID, dbo.RcvItemsSimpleDetail_Placement.Shelf_RefID, dbo.RcvItemsSimpleDetail.LotNo_Manual, dbo.RcvItemsSimpleDetail.BatchNo_Manual
                                                           UNION ALL
                                                           SELECT        dbo.IssItemsSimpleDetail.ItemID, dbo.IssItemsSimpleDetail_More.Shelf_RefID, 0 AS RcvdQty, SUM(dbo.IssItemsSimpleDetail_More.IssdQty) AS IssdQty, dbo.IssItemsSimpleDetail.LotNo_Manual,
                                                                                    dbo.IssItemsSimpleDetail.BatchNo_Manual
                                                           FROM            dbo.IssItemsSimpleDetail INNER JOIN
                                                                                    dbo.IssItemsSimpleDetail_More ON dbo.IssItemsSimpleDetail.EntryID = dbo.IssItemsSimpleDetail_More.IISD_RefID
                                                           GROUP BY dbo.IssItemsSimpleDetail.ItemID, dbo.IssItemsSimpleDetail_More.Shelf_RefID, dbo.IssItemsSimpleDetail.LotNo_Manual, dbo.IssItemsSimpleDetail.BatchNo_Manual) AS TInner1
                                GROUP BY ItemID, Shelf_RefID, LotNo_Manual, BatchNo_Manual) AS T1 ON dbo.VStoreShelfs.EntryID = T1.Shelf_RefID LEFT OUTER JOIN
                             (SELECT        dbo.VRcvitemsSimpleDetail_Placement.ItemID, dbo.VRcvitemsSimpleDetail_Placement.Shelf_RefID, dbo.VRcvitemsSimpleDetail_Placement.Remarks
                                FROM            dbo.VRcvitemsSimpleDetail_Placement INNER JOIN
                                                             (SELECT        MAX(EntryID) AS MaxEntryID
                                                                FROM            dbo.VRcvitemsSimpleDetail_Placement AS VRcvitemsSimpleDetail_Placement_1
                                                                GROUP BY ItemID, Shelf_RefID) AS TMax ON dbo.VRcvitemsSimpleDetail_Placement.EntryID = TMax.MaxEntryID) AS T2 ON T1.ItemID = T2.ItemID AND T1.Shelf_RefID = T2.Shelf_RefID
