CREATE VIEW [dbo].[VItemsWithLocationwiseStock]
AS
SELECT     dbo.Items.CatID, dbo.Items.ItemID, TabRcvd.Location, ISNULL(TabRcvd.RcvdQty, 0) AS RcvdQty, ISNULL(TabIssd.IssdQty, 0) AS IssdQty,
                      ISNULL(TabRcvd.RcvdQty, 0) - ISNULL(TabIssd.IssdQty, 0) AS NetQty
FROM         dbo.Items INNER JOIN
                          (SELECT     ItemID, Location, SUM(Qty) AS RcvdQty
                             FROM         RcvItemsSimpleDetail
                             GROUP BY ItemID, Location) TabRcvd ON dbo.Items.ItemID = TabRcvd.ItemID LEFT OUTER JOIN
                          (SELECT     ItemID, Location, SUM(Qty) AS IssdQty
                             FROM         IssItemsSimpleDetail
                             GROUP BY ItemID, Location) TabIssd ON TabRcvd.ItemID = TabIssd.ItemID AND TabRcvd.Location = TabIssd.Location

