CREATE VIEW [dbo].[VItemsWithLocationwiseStock_Rackwise]
AS
SELECT     TOP 100 PERCENT *, LEFT(Location, 4) + SUBSTRING(Location, 5, CHARINDEX('-', Location, 5) - 5) AS Rack
FROM         dbo.VItemsWithLocationwiseStock
WHERE     (Location <> '') AND (LEN(Location) - LEN(REPLACE(Location, '-', '')) > 1)
ORDER BY ItemID

