CREATE VIEW [dbo].[VSSEmployees]
AS
SELECT     dbo.VEmp.*, SalaryLedger.Salary AS JoiningSalary,
CASE WHEN DATEDIFF(dd, dbo.VEmp.JoinDate, dbo.VCurDT.CurDT) > ProbationPeriod+6 THEN 'Permanent' ELSE 'Temporary' END AS EmpStatus,
CASE WHEN DATEDIFF(dd, dbo.VEmp.JoinDate, dbo.VCurDT.CurDT) > ProbationPeriod+6 THEN 1 ELSE 0 END AS Permanent
--+5 Added in ProbationPeriod to Cover for 31 Days of a month as Settings for Probation are 0,30,60,90,120,150 and 180.
FROM dbo.VEmp INNER JOIN
                      dbo.VCurDT ON DATEDIFF(yy, dbo.VEmp.dob, dbo.VCurDT.CurDT) > 0 INNER JOIN
                          (SELECT     EmpID, Salary
                            FROM          dbo.SalaryLedger
                            WHERE      Description = 'Starting Salary On Joining' AND Salary <= 5000) SalaryLedger ON
                      dbo.VEmp.empid = SalaryLedger.EmpID COLLATE SQL_Latin1_General_CP1_CI_AS

GO
