CREATE VIEW [dbo].[vEmpLedger]
AS
SELECT        dbo.VEmp.deptid, dbo.VEmp.DeptName, dbo.VEmp.empid, dbo.VEmp.name, dbo.VEmp.fname, dbo.VEmp.dob, dbo.VEmp.Religion, dbo.VEmp.Age, dbo.VEmp.sex, dbo.VEmp.Address, dbo.VEmp.NIC, dbo.VEmp.NTN,
                         dbo.VEmp.Phone1, dbo.VEmp.Phone2, dbo.VEmp.AbsAllowed, dbo.VEmp.TimeAllowed, dbo.VEmp.NTimes, dbo.VEmp.OverTime, dbo.VEmp.StartingSalary, dbo.VEmp.Salary, dbo.VEmp.PProfit, dbo.VEmp.Active,
                         dbo.VEmp.EmpType, dbo.VEmp.DiscontinuedOn, dbo.VEmp.JoinDate, dbo.VEmp.Bonus, dbo.VEmp.Designation, dbo.VEmp.Rel, dbo.VEmp.Status, dbo.VEmp.Transport, dbo.VEmp.EnterTime, dbo.VEmp.ExitTime,
                         dbo.VEmp.BGHoliday, dbo.VEmp.AGHoliday, dbo.VEmp.BPHoliday, dbo.VEmp.APHoliday, dbo.VEmp.Emp_ID, dbo.VEmp.LunchTime, dbo.VEmp.EmergencyName, dbo.VEmp.EmergencyFName, dbo.VEmp.EmergencyPhone1,
                         dbo.VEmp.EmergencyPhone2, dbo.VEmp.EmergencyAddress, dbo.VEmp.BloodGroup, dbo.VEmp.OTByQty, dbo.VEmp.MinQty, dbo.VEmp.UnionFund, dbo.VEmp.Lunch, dbo.VEmp.social, dbo.VEmp.oldage, dbo.VEmp.SocialNo,
                         dbo.VEmp.OldAgeNo, dbo.VEmp.InsurableDT, dbo.VEmp.ArmyRetired, dbo.VEmp.EmpAccNo, dbo.VEmp.BankPymt, dbo.VEmp.TempDept, dbo.VEmp.EmployeeID, dbo.VEmp.EmpPic, dbo.VEmp.PerPieceRate, dbo.VEmp.Rate,
                         dbo.VEmp.EmpMinSalary, dbo.VEmp.EmpIDOld, dbo.VEmp.ProbationPeriod, dbo.VEmp.EmpAttCat_RefID, dbo.VEmp.ExemptSettings, dbo.VEmp.TempEmp, dbo.VEmp.intGuarantorId, dbo.VEmp.FixAllowance,
                         dbo.AttendanceSheet.DT, dbo.AttendanceSheet.Attendance, dbo.AttendanceSheet.LateHours, DAY(dbo.AttendanceSheet.DT) AS AttDay, dbo.AttendanceSheet.ExtraHrs, dbo.VShortTermByDate.ShortTerm,
                         dbo.VLongTermByDate.LongTerm, ISNULL(dbo.Leaves.CL, 0) AS CL, ISNULL(dbo.Leaves.SL, 0) AS SL, ISNULL(dbo.Leaves.AL, 0) AS AL, ISNULL(dbo.Leaves.CPL, 0) AS CPL, ISNULL(dbo.Leaves.LWP, 0) AS LWP,
                         ISNULL(dbo.Leaves.ML, 0) AS ML, ISNULL(dbo.Leaves.SAL, 0) AS SAL, TabOTOther.OTHrsOther
FROM            dbo.AttendanceSheet LEFT OUTER JOIN
                         dbo.Leaves ON dbo.AttendanceSheet.EmpID = dbo.Leaves.EmpID AND dbo.AttendanceSheet.DT = dbo.Leaves.DT RIGHT OUTER JOIN
                         dbo.VEmp ON dbo.AttendanceSheet.EmpID = dbo.VEmp.empid LEFT OUTER JOIN
                         dbo.OverTime ON dbo.AttendanceSheet.DT = dbo.OverTime.DT AND dbo.AttendanceSheet.EmpID = dbo.OverTime.EmpID LEFT OUTER JOIN
                         dbo.VShortTermByDate ON dbo.AttendanceSheet.EmpID = dbo.VShortTermByDate.EmpID AND dbo.AttendanceSheet.DT = dbo.VShortTermByDate.DT LEFT OUTER JOIN
                         dbo.VLongTermByDate ON dbo.AttendanceSheet.EmpID = dbo.VLongTermByDate.EmpID AND dbo.AttendanceSheet.DT = dbo.VLongTermByDate.DT LEFT OUTER JOIN
                             (SELECT        EmpID, DT, SUM(OTHrs) AS OTHrsOther
                               FROM            dbo.EmpOTHrs
                               GROUP BY EmpID, DT) AS TabOTOther ON dbo.AttendanceSheet.EmpID = TabOTOther.EmpID AND dbo.AttendanceSheet.DT = TabOTOther.DT
