                      dbo.VendRcvdDetail.IssRepairQty, dbo.VendRcvdDetail.IssQty, dbo.VendRcvdDetail.NextProcessID, dbo.VendRcvdDetail.LostQty, dbo.VendRcvdDetail.OrderNo,
                      dbo.VendRcvdDetail.CountedBy, dbo.VendRcvdDetail.Issue_RefID, dbo.VendRcvdDetail.ProcessID, dbo.VendRcvdDetail.RcvdWeight, dbo.VendRcvdDetail.RepairAmt,
