CREATE VIEW [dbo].[VVendRcvdDetailWastageDetail_RejectionStore]
AS
SELECT        dbo.VendRcvdDetailWastageDetail.EntryID, dbo.VendRcvdDetailWastageDetail.VRD_RefID, dbo.VendRcvdDetailWastageDetail.Wastage_RefID, dbo.VendRcvdDetailWastageDetail.Qty, dbo.VendReceived.VendID,
                         dbo.VendRcvdDetail.ItemCode, dbo.VendRcvdDetail.OrderNo, dbo.VendRcvdDetail.Rate, dbo.Makers.VendID1, dbo.Makers.VenderName, dbo.Items.ItemName, dbo.WastageTypes.WastageType, dbo.VendRcvdDetail.LotNo,
                         CAST(CONVERT(Varchar(50), dbo.VendReceived.DT, 6) AS DATETIME) AS OnlyDT, dbo.WastageTypes.WastageName, dbo.VendRcvdDetail.Opening_RefID, dbo.Items.GroupID, dbo.VendRcvdDetail.ProcessID,
                         dbo.VendIssued.MasterPONo, dbo.VendRcvdDetail.ReWorkQty, dbo.VendRcvdDetail.ReWorkLot, dbo.VendRcvdDetail.Wastage, dbo.FCustomerOrders.CustCode, dbo.Items.CatID, dbo.VendReceived.DT,
                         dbo.Processes.Description, Makers_1.VendID AS ChargeTo_VendID, Makers_1.VendID1 AS ChargeTo_VendID1, Makers_1.VenderName AS ChargeTo_VenderName, dbo.VendRcvdDetailWastageDetail.HandlingBy,
                         ISNULL(TRcv.TotalReceived, 0) AS TotalReceived, ISNULL(TRcv.TotalLost, 0) AS TotalLost, dbo.VendRcvdDetail.RecieptID
FROM            dbo.VendRcvdDetailWastageDetail INNER JOIN
                         dbo.VendRcvdDetail ON dbo.VendRcvdDetailWastageDetail.VRD_RefID = dbo.VendRcvdDetail.EntryID INNER JOIN
                         dbo.VendReceived ON dbo.VendRcvdDetail.RefID = dbo.VendReceived.EntryID INNER JOIN
                         dbo.Makers ON dbo.VendReceived.VendID = dbo.Makers.VendID INNER JOIN
                         dbo.Items ON dbo.VendRcvdDetail.ItemCode = dbo.Items.ItemID INNER JOIN
                         dbo.WastageTypes ON dbo.VendRcvdDetailWastageDetail.Wastage_RefID = dbo.WastageTypes.EntryID INNER JOIN
                         dbo.VendIssued ON dbo.VendReceived.Issuance_RefID = dbo.VendIssued.EntryID INNER JOIN
                         dbo.FCustomerOrders ON dbo.VendRcvdDetail.OrderNo = dbo.FCustomerOrders.OrderNo INNER JOIN
                         dbo.Processes ON dbo.VendRcvdDetail.ProcessID = dbo.Processes.ProcessID LEFT OUTER JOIN
                         dbo.Makers AS Makers_1 ON dbo.VendRcvdDetailWastageDetail.VendID = Makers_1.VendID LEFT OUTER JOIN
                             (SELECT        VRDWD_RefID, SUM(QtyRcvd) AS TotalReceived, SUM(QtyLost) AS TotalLost
                               FROM            dbo.Rejection_Receiving
                               GROUP BY VRDWD_RefID) AS TRcv ON dbo.VendRcvdDetailWastageDetail.EntryID = TRcv.VRDWD_RefID
