                         1 AS EntryType, dbo.Rejection_Receiving.EntryID AS ChildEntryID, T1.LotNo, T1.ItemCode, T1.ItemName, dbo.Rejection_Receiving.QtyRcvd, dbo.Rejection_Receiving.QtyLost, dbo.Rejection_Receiving.Remarks, '' AS Location,
                         dbo.Rejection_Receiving.QtyRcvd AS Qty, dbo.VStoreShelfs.ShelfNo, dbo.VStoreShelfs.RackNo, dbo.VStoreShelfs.StoreName, ISNULL(TIssd.TotalIssued, 0) AS TotalIssued, dbo.Rejection_Receiving.Shelf_RefID,
                         dbo.VStoreShelfs.Rack_RefID
FROM            dbo.Rejection_Receiving INNER JOIN
                         dbo.VVendRcvdDetailWastageDetail_RejectionStore AS T1 ON dbo.Rejection_Receiving.VRDWD_RefID = T1.EntryID INNER JOIN
                         dbo.VStoreShelfs ON dbo.Rejection_Receiving.Shelf_RefID = dbo.VStoreShelfs.EntryID LEFT OUTER JOIN
                             (SELECT        R_R_RefID, SUM(Qty) AS TotalIssued
                               FROM            dbo.Rejection_Issuance_Detail
                               GROUP BY R_R_RefID) AS TIssd ON dbo.Rejection_Receiving.EntryID = TIssd.R_R_RefID

