/****** Object:  View [dbo].[VItemsWithShelfWiseStock_Sample]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VItemsWithShelfWiseStock_Sample]
AS
SELECT        dbo.VStoreShelfs.StoreName, dbo.VStoreShelfs.RackNo, dbo.VStoreShelfs.ShelfNo, T1.Sample_Type, T1.ItemID, T1.RcvdQty - ISNULL(T1.IssdQty, 0) AS NetQty, T1.Shelf_RefID,
                         dbo.VStoreShelfs.Store_RefID
FROM            dbo.VStoreShelfs INNER JOIN
                             (SELECT        ItemID, Shelf_RefID, Sample_Type, SUM(RcvdQty) AS RcvdQty, SUM(IssdQty) AS IssdQty
                               FROM            (SELECT        dbo.RcvItemsSimpleDetail.ItemID, dbo.RcvItemsSimpleDetail_Placement.Shelf_RefID, dbo.RcvItemsSimpleDetail.Sample_Type, SUM(dbo.RcvItemsSimpleDetail_Placement.RcvdQty)
                                                                                   AS RcvdQty, 0 AS IssdQty
                                                         FROM            dbo.RcvItemsSimpleDetail_Placement INNER JOIN
                                                                                   dbo.RcvItemsSimpleDetail ON dbo.RcvItemsSimpleDetail_Placement.RISD_RefID = dbo.RcvItemsSimpleDetail.EntryID INNER JOIN
                                                                                   dbo.RcvItemsSimple ON dbo.RcvItemsSimple.RcvNo = dbo.RcvItemsSimpleDetail.RcvNo
                                                         WHERE        (dbo.RcvItemsSimple.Sample = 1)
                                                         GROUP BY dbo.RcvItemsSimpleDetail.ItemID, dbo.RcvItemsSimpleDetail_Placement.Shelf_RefID, dbo.RcvItemsSimpleDetail.Sample_Type
                                                         UNION ALL
                                                         SELECT        dbo.IssItemsSimpleDetail.ItemID, dbo.IssItemsSimpleDetail_More.Shelf_RefID, dbo.IssItemsSimpleDetail.Sample_Type, 0 AS RcvdQty, SUM(dbo.IssItemsSimpleDetail_More.IssdQty)
                                                                                  AS IssdQty
                                                         FROM            dbo.IssItemsSimpleDetail INNER JOIN
                                                                                  dbo.IssItemsSimpleDetail_More ON dbo.IssItemsSimpleDetail.EntryID = dbo.IssItemsSimpleDetail_More.IISD_RefID INNER JOIN
                                                                                  dbo.IssItemsSimple ON dbo.IssItemsSimple.IssNo = dbo.IssItemsSimpleDetail.IssNo
                                                         WHERE        (dbo.IssItemsSimple.SampleIssuance = 1)
                                                         GROUP BY dbo.IssItemsSimpleDetail.ItemID, dbo.IssItemsSimpleDetail_More.Shelf_RefID, dbo.IssItemsSimpleDetail.Sample_Type) AS TInner1
                               GROUP BY ItemID, Shelf_RefID, Sample_Type) AS T1 ON dbo.VStoreShelfs.EntryID = T1.Shelf_RefID

GO
/****** Object:  UserDefinedFunction [dbo].[FLateComingHrs]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE Function [dbo].[FLateComingHrs] (@ParDate DATETIME) RETURNS TABLE
AS
RETURN
(SELECT T1.EmpID, SUM(DATEDIFF(n,EnterTime,InTime)/60.00) AS LateComingHrs FROM VEmpSettings
INNER JOIN (
SELECT EmpID,DT,InTime FROM EmpTimes
INNER JOIN (SELECT MIN(EmpTimes.EntryID) AS EntryID FROM EmpTimes LEFT JOIN Leaves ON EmpTimes.EmpID=Leaves.EmpID AND EmpTimes.DT=Leaves.DT WHERE (MONTH(EmpTimes.DT) = MONTH(@ParDate) AND YEAR(EmpTimes.DT) = YEAR(@ParDate) AND EmpTimes.DT <=@ParDATE) AND Leaves.EmpID IS NULL GROUP BY EmpTimes.EmpID,EmpTimes.DT) TInner ON EmpTimes.EntryID=TInner.EntryID) T1 ON VEmpSettings.EmpID=T1.EmpID
WHERE (MONTH(DT)=MONTH(@ParDate) AND YEAR(DT) = YEAR(@ParDate) AND DT <=@ParDATE)

AND DATEDIFF(n,DateAdd(n,CAST(LateDeductionAfter AS INT),EnterTime),InTime)>0
GROUP BY T1.EmpID)
GO
