CREATE VIEW [dbo].[VFOrdItemsTotIssued]
AS
SELECT     dbo.VFOrdItemsTotOutStock.ItemCode, SUM(dbo.VFOrdItemsTotInStock.TotInStock) AS TotInStock, SUM(dbo.VFOrdItemsTotOutStock.TotOutStock)
                      AS TotOutStock, SUM(dbo.VFOrdItemsTotWastage.TotalWastage) AS TotalWastage, SUM(dbo.VFOrdItemsTotInStock.TotInStock)
                      + SUM(dbo.VFOrdItemsTotOutStock.TotOutStock) + SUM(dbo.VFOrdItemsTotWastage.TotalWastage) + SUM(dbo.VFOrdItemsTotWastage.TotRepairQty)
                      AS TotalIssued
FROM         dbo.VFOrdItemsTotInStock LEFT OUTER JOIN
                      dbo.VFOrdItemsTotWastage ON dbo.VFOrdItemsTotInStock.ItemCode = dbo.VFOrdItemsTotWastage.ItemCode FULL OUTER JOIN
                      dbo.VFOrdItemsTotOutStock ON dbo.VFOrdItemsTotInStock.ItemCode = dbo.VFOrdItemsTotOutStock.ItemCode
GROUP BY dbo.VFOrdItemsTotOutStock.ItemCode

