/****** Object:  View [dbo].[VFOrderItemPTC]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*LEFT OUTER JOIN (SELECT LotNo AS FromLotNo,ProcessID FROM LotTransferDetails INNER JOIN VendRcvdDetail ON VRD_To_RefID=VendRcvdDetail.EntryID) TSplit1 ON TSplit1.VRD_*/
CREATE VIEW [dbo].[VFOrderItemPTC]
AS
SELECT     TFOrderItems.OrderNo, TFOrderItems.ItemCode, TFOrderItems.Qty, dbo.FCustomerOrders.CustCode, dbo.FCustomerOrders.Country, dbo.FCustomerOrders.DT, dbo.Items.ItemName, dbo.Items.ItemSize, dbo.Items.SizeUnit, dbo.Items.Type,
                  dbo.FCustomerOrders.Packaging, dbo.FCustomerOrders.DeliveryDT, dbo.ItemProcesses.SNO, dbo.ItemProcesses.ProcessID, dbo.Processes.Description, Tab1.RcvdQty, Tab2.LotNo, Tab1.VendID, dbo.Makers.VenderName, Tab1.RcvDT, TabIss.IssDT,
                  TabMin.MinProcessID, Tab1.Wastage, Tab1.PassQty, dbo.Employees.empid, dbo.Employees.name, Tab1.ReWorkQty, TFOrderItems.CompItemCode, dbo.Processes.Code, dbo.Processes.ProcessNameUrdu, dbo.Items.ItemNameUrdu,
                  EmpRcv.name AS RcvEmpName, Tab1.Rate, TMasterPO.MasterPONo, TSteelBatch.SteelBatchNo, TForgeBatch.ForgeBatchNo, TSFRemarks.SFRemarks, TSplit.SplitQty, ISNULL(TSplit.Type, TSplitFrom.SplitTypeFrom) AS SplitType, TSplit.ToOrderNo, TSplit.ToLotNo,
                  TSplitFrom.FromOrderNo, TSplitFrom.FromLotNo, TSplitFrom.SplitQtyFrom, TSplit.FromItemCode, TSplit.ToItemCode, TMasterPO.RecieptID, TIssFromSF.LotNo AS IssSFLotNo, TIssFromSF.IssSFRemarks, TIssFromSF.IssSFQty, TLastRcv.LotLastEntryID,
                  dbo.VFOrderItemsWithShippedQtyItemCodeWise.ShippedQty, ISNULL(dbo.VLotWithPolishingMaker.VenderName, '') AS FromLotPolisher, ISNULL(dbo.VLotWithFirstProcessOfIssuance.VenderName, '') AS FromLotOriginator, Tab1.RcvTemperValue,
                  TabIss.IssSpecialInstructions, dbo.FCustomerOrders.InternalRefNo, dbo.ProcessGroups.PGReference, Tab1.ReceivedEntryID, dbo.VendReceived_Employees_F(Tab1.ReceivedEntryID) AS Employees, TFOrderItems.Quality, dbo.GetAllRepairLots_F(Tab2.LotNo)
                  AS RepairLots, TSplit.LotTransferRemarks, TSplitFrom.LotTransferRemarks AS LotTransferRemarksFrom, Tab1.UserName, Tab1.MachineName, dbo.Makers.CompanyName, dbo.FCustomerOrders.Quality AS Expr1, dbo.FCustomerOrders.TradeTerms,
                  dbo.FCustomerOrders.StampDT, dbo.FCustomerOrders.OrderType, dbo.FCustomerOrders.ShippingMode, dbo.FCustomerOrders.OrderRevisionNo, dbo.FCustomerOrders.Packaging_Weight, dbo.FCustomerOrders.OrderRevisionDT, dbo.Items.FinQuality,
                  dbo.Items.SteelUsed, dbo.Items.Gage, dbo.Processes.AuthRequired, dbo.Items.CustomDescription, dbo.Items.ItemID, dbo.Items.PackingInstructions, dbo.Items.ItemUsage
FROM        (SELECT     OrderNo, ItemCode, CompItemID AS CompItemCode, Quality, SUM(Qty) AS Qty
                   FROM        dbo.VrptOrders_ForProduction
                   GROUP BY OrderNo, ItemCode, CompItemID, Quality) AS TFOrderItems LEFT OUTER JOIN
                  dbo.VFOrderItemsWithShippedQtyItemCodeWise ON TFOrderItems.OrderNo = dbo.VFOrderItemsWithShippedQtyItemCodeWise.OrderNo AND TFOrderItems.CompItemCode = dbo.VFOrderItemsWithShippedQtyItemCodeWise.CompItemCode INNER JOIN
                  dbo.Items ON TFOrderItems.CompItemCode = dbo.Items.ItemID INNER JOIN
                  dbo.ItemProcesses ON dbo.Items.ItemID = dbo.ItemProcesses.ItemID INNER JOIN
                  dbo.FCustomerOrders ON TFOrderItems.OrderNo = dbo.FCustomerOrders.OrderNo INNER JOIN
                  dbo.Processes ON dbo.ItemProcesses.ProcessID = dbo.Processes.ProcessID LEFT OUTER JOIN
                  dbo.ItemProcessGroups ON dbo.Items.ItemID = dbo.ItemProcessGroups.ItemID LEFT OUTER JOIN
                  dbo.ProcessGroups ON dbo.ItemProcessGroups.PG_RefID = dbo.ProcessGroups.EntryID LEFT OUTER JOIN
                      (SELECT DISTINCT OrderNo, ItemCode, LotNo
                       FROM        dbo.vendRcvdDetail) AS Tab2 ON TFOrderItems.OrderNo = Tab2.OrderNo AND TFOrderItems.CompItemCode = Tab2.ItemCode LEFT OUTER JOIN
                      (SELECT     VendRcvdDetail_2.ProcessID, VendRcvdDetail_2.LotNo, VendRcvdDetail_2.Rate, dbo.VendReceived.EmpID, dbo.VendReceived.TemperValue AS RcvTemperValue, VendRcvdDetail_2.RcvdQty,
                                         CASE WHEN ReqAuth = 1 THEN 0 ELSE RcvdQty END AS PassQty, dbo.VendReceived.VendID, dbo.VendReceived.DT AS RcvDT, VendRcvdDetail_2.Wastage, VendRcvdDetail_2.ReWorkQty, dbo.VendReceived.EntryID AS ReceivedEntryID,
                                         dbo.VendReceived.UserName, dbo.VendReceived.MachineName
                       FROM        dbo.vendRcvdDetail AS VendRcvdDetail_2 INNER JOIN
                                         dbo.VendReceived ON dbo.VendReceived.EntryID = VendRcvdDetail_2.RefID) AS Tab1 ON Tab2.LotNo = Tab1.LotNo AND dbo.ItemProcesses.ProcessID = Tab1.ProcessID LEFT OUTER JOIN
                      (SELECT     dbo.VendIssued.ProcessID, dbo.VendIssdDetail.LotNo, dbo.VendIssdDetail_MoreDetails.EmpID, dbo.VendIssued.SpecialInstructions AS IssSpecialInstructions, MIN(dbo.VendIssued.DT) AS IssDT
                       FROM        dbo.VendIssued INNER JOIN
                                         dbo.VendIssdDetail ON dbo.VendIssued.EntryID = dbo.VendIssdDetail.RefID LEFT OUTER JOIN
                                         dbo.VendIssdDetail_MoreDetails ON dbo.VendIssdDetail.EntryID = dbo.VendIssdDetail_MoreDetails.VID_RefID
                       GROUP BY dbo.VendIssued.ProcessID, dbo.VendIssdDetail.LotNo, dbo.VendIssdDetail_MoreDetails.EmpID, dbo.VendIssued.SpecialInstructions) AS TabIss ON Tab2.LotNo = TabIss.LotNo AND dbo.ItemProcesses.ProcessID = TabIss.ProcessID LEFT OUTER JOIN
                      (SELECT     VendRcvdDetail_1.LotNo, MIN(VendReceived_1.ProcessID) AS MinProcessID
                       FROM        dbo.VendReceived AS VendReceived_1 INNER JOIN
                                         dbo.vendRcvdDetail AS VendRcvdDetail_1 ON VendReceived_1.EntryID = VendRcvdDetail_1.RefID
                       GROUP BY VendRcvdDetail_1.LotNo) AS TabMin ON Tab2.LotNo = TabMin.LotNo LEFT OUTER JOIN
                  dbo.Makers ON Tab1.VendID = dbo.Makers.VendID LEFT OUTER JOIN
                  dbo.Employees ON TabIss.EmpID = dbo.Employees.empid LEFT OUTER JOIN
                  dbo.Employees AS EmpRcv ON Tab1.EmpID = EmpRcv.empid LEFT OUTER JOIN
                      (SELECT     TNest1.LotNo, VendIssued_2.EntryID, VendIssued_2.MasterPONo, VendIssued_2.RecieptID
                       FROM        dbo.VendIssued AS VendIssued_2 INNER JOIN
                                         dbo.VendIssdDetail AS VendIssdDetail_2 ON VendIssued_2.EntryID = VendIssdDetail_2.RefID INNER JOIN
                                             (SELECT     LotNo, MIN(Issue_RefID) AS Issue_RefID
                                              FROM        dbo.vendRcvdDetail AS VendRcvdDetail_7
                                              GROUP BY LotNo) AS TNest1 ON TNest1.Issue_RefID = VendIssdDetail_2.EntryID) AS TMasterPO ON Tab2.LotNo = TMasterPO.LotNo LEFT OUTER JOIN
                      (SELECT     dbo.RawMaterialIssuance.VI_RefID, MAX(dbo.RawMaterialIssuanceDetail.PORefNo) AS SteelBatchNo
                       FROM        dbo.RawMaterialIssuance INNER JOIN
                                         dbo.RawMaterialIssuanceDetail ON dbo.RawMaterialIssuance.IssNo = dbo.RawMaterialIssuanceDetail.IssNo INNER JOIN
                                         dbo.RM ON dbo.RawMaterialIssuanceDetail.RMID1 = dbo.RM.RMID1
                       WHERE     (dbo.RM.GroupID = 20)
                       GROUP BY dbo.RawMaterialIssuance.VI_RefID) AS TSteelBatch ON TMasterPO.EntryID = TSteelBatch.VI_RefID LEFT OUTER JOIN
                      (SELECT     RawMaterialIssuance_1.VI_RefID, MAX(RawMaterialIssuanceDetail_1.PORefNo) AS ForgeBatchNo
                       FROM        dbo.RawMaterialIssuance AS RawMaterialIssuance_1 INNER JOIN
                                         dbo.RawMaterialIssuanceDetail AS RawMaterialIssuanceDetail_1 ON RawMaterialIssuance_1.IssNo = RawMaterialIssuanceDetail_1.IssNo INNER JOIN
                                         dbo.RM AS RM_1 ON RawMaterialIssuanceDetail_1.RMID1 = RM_1.RMID1
                       WHERE     (RM_1.GroupID IN (25, 27, 28, 29, 30))
                       GROUP BY RawMaterialIssuance_1.VI_RefID) AS TForgeBatch ON TMasterPO.EntryID = TForgeBatch.VI_RefID LEFT OUTER JOIN
                      (SELECT     VendRcvdDetail_6.ProcessID, VendRcvdDetail_6.LotNo, '' AS SFRemarks
                       FROM        dbo.vendRcvdDetail AS VendRcvdDetail_6 INNER JOIN
                                             (SELECT     VID_RefID
                                              FROM        dbo.StockOrderOpening_Issuance
                                              GROUP BY VID_RefID) AS TSOO_I ON TSOO_I.VID_RefID = VendRcvdDetail_6.Issue_RefID) AS TSFRemarks ON Tab2.LotNo = TSFRemarks.LotNo AND Tab1.ProcessID = TSFRemarks.ProcessID LEFT OUTER JOIN
                      (SELECT     VendRcvdDetail_5.LotNo, VendRcvdDetail_5.ProcessID, dbo.LotTransferDetails.SplitQty, dbo.LotTransferDetails.Type, dbo.LotTransferDetails.ToOrderNo, VendRcvdDetail_1.LotNo AS ToLotNo, dbo.LotTransferDetails.FromItemCode,
                                         dbo.LotTransferDetails.ToItemCode, dbo.LotTransferDetails.LotTransferRemarks
                       FROM        dbo.LotTransferDetails INNER JOIN
                                         dbo.vendRcvdDetail AS VendRcvdDetail_5 ON dbo.LotTransferDetails.VRD_From_RefID = VendRcvdDetail_5.EntryID INNER JOIN
                                         dbo.vendRcvdDetail AS VendRcvdDetail_1 ON dbo.LotTransferDetails.VRD_To_RefID = VendRcvdDetail_1.EntryID) AS TSplit ON Tab2.LotNo = TSplit.LotNo AND Tab1.ProcessID = TSplit.ProcessID LEFT OUTER JOIN
                      (SELECT     VendRcvdDetail_4.LotNo AS FromLotNo, VendRcvdDetail_4.ProcessID, LotTransferDetails_1.SplitQty AS SplitQtyFrom, LotTransferDetails_1.Type AS SplitTypeFrom, LotTransferDetails_1.FromOrderNo, VendRcvdDetail_1.LotNo,
                                         LotTransferDetails_1.LotTransferRemarks
                       FROM        dbo.LotTransferDetails AS LotTransferDetails_1 INNER JOIN
                                         dbo.vendRcvdDetail AS VendRcvdDetail_4 ON LotTransferDetails_1.VRD_From_RefID = VendRcvdDetail_4.EntryID INNER JOIN
                                         dbo.vendRcvdDetail AS VendRcvdDetail_1 ON LotTransferDetails_1.VRD_To_RefID = VendRcvdDetail_1.EntryID) AS TSplitFrom ON Tab2.LotNo = TSplitFrom.LotNo AND Tab1.ProcessID = TSplitFrom.ProcessID LEFT OUTER JOIN
                      (SELECT     VendIssued_1.ProcessID, VendIssdDetail_1.LotNo, '' AS IssSFRemarks, VendIssdDetail_1.IssQty AS IssSFQty
                       FROM        dbo.VendIssdDetail AS VendIssdDetail_1 INNER JOIN
                                             (SELECT     VID_RefID
                                              FROM        dbo.StockOrderOpening_Issuance AS StockOrderOpening_Issuance_1
                                              GROUP BY VID_RefID) AS TSOO_I_1 ON VendIssdDetail_1.EntryID = TSOO_I_1.VID_RefID INNER JOIN
                                         dbo.VendIssued AS VendIssued_1 ON VendIssdDetail_1.RefID = VendIssued_1.EntryID) AS TIssFromSF ON Tab2.LotNo = TIssFromSF.LotNo AND Tab1.ProcessID = TIssFromSF.ProcessID LEFT OUTER JOIN
                      (SELECT     LotNo, MAX(EntryID) AS LotLastEntryID
                       FROM        dbo.vendRcvdDetail AS VendRcvdDetail_3
                       GROUP BY LotNo) AS TLastRcv ON Tab2.LotNo = TLastRcv.LotNo LEFT OUTER JOIN
                  dbo.VLotWithPolishingMaker ON TSplitFrom.FromLotNo = dbo.VLotWithPolishingMaker.LotNo LEFT OUTER JOIN
                  dbo.VLotWithFirstProcessOfIssuance ON TSplitFrom.FromLotNo = dbo.VLotWithFirstProcessOfIssuance.LotNo
GO
