CREATE VIEW [dbo].[VVendLedger1]
AS
SELECT     Table1.RecieptID, Table1.DT, Table1.VendID, Table1.ItemCode,
                      Table1.ProcessID, Table1.IssQty, Table1.RcvdQty, 0 AS Wastage, Table1.VenderName,Table1.VendID1
