                       dbo.FSteelPurchaseOrder.ExtraPer, dbo.TestLabs.Address AS LabAddress, dbo.SteelVendors.Address AS VendAddress,
                      dbo.FSteelPurchaseOrder.PurchOrdNo, dbo.FSteelPurchaseOrder.DT, dbo.FSteelPurchaseOrder.MillBatchNo, dbo.FSteelPurchaseOrder.PInvoice,
                      dbo.VFProformaList.CustCode, dbo.VFProformaList.Country, dbo.FSteelPurchaseOrder.RecDT, dbo.FSteelPurchaseOrder.Hidden
FROM         dbo.SteelVendors INNER JOIN
                      dbo.FSteelPurchaseOrder INNER JOIN
                      dbo.TestLabs ON dbo.FSteelPurchaseOrder.LabID = dbo.TestLabs.ID ON dbo.SteelVendors.ID = dbo.FSteelPurchaseOrder.VendID INNER JOIN
                      dbo.VFProformaList ON dbo.FSteelPurchaseOrder.PInvoice = dbo.VFProformaList.PInvoice

