/****** Object:  View [dbo].[VVendReceivingList_Simple]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE VIEW [dbo].[VVendReceivingList_Simple]
AS
SELECT        dbo.VendReceived.EntryID, dbo.VendReceived.VendID, dbo.VendReceived.DT, dbo.VendReceived.UserID, dbo.VendReceived.ProcessID, dbo.VendRcvdDetail.RecieptID, dbo.VendRcvdDetail.ItemCode,
                         dbo.VendRcvdDetail.RcvdQty, dbo.VendRcvdDetail.Wastage, dbo.VendRcvdDetail.LostQty, dbo.Makers.VenderName, dbo.Makers.VendID1, CAST(CONVERT(Varchar(10), dbo.VendReceived.DT, 1) AS DATETIME) AS OnlyDT,
                         dbo.VendRcvdDetail.ReqAuth, dbo.VendReceived.Issuance_RefID, dbo.Processes.Description, dbo.ItemProcesses.Scanning, dbo.VendRcvdDetail.LotNo, dbo.VendRcvdDetail.NextProcessID, dbo.VendRcvdDetail.IssQty,
                         dbo.VendRcvdDetail.EntryID AS VRD_EntryID, dbo.VendRcvdDetail.Opening_RefID, dbo.Items.CatID, dbo.VendRcvdDetail.OrderNo, dbo.VendIssued.MasterPONo, dbo.VendRcvdDetail.ReWorkLot, FOrderItems.CompItemCode,
                         dbo.VendRcvdDetail.ReWorkQty, dbo.FCustomerOrders.CustCode, dbo.Items.ItemName, dbo.Items.ItemSize, dbo.Items.SizeUnit, dbo.Items.Type, dbo.Items.GroupID, dbo.ItemGroups.Description AS ItemGroup,
                         dbo.VendReceived.EmpID, dbo.Employees.name AS EmpName, T1.VRD_From_RefID, dbo.VendIssued.DT AS IssDT, dbo.VendIssdDetail.IssQty AS Issuance_IssQty, dbo.VendIssdDetail.RcvdQty AS Issuance_RcvdQty,
                         TDL.VRD_RefID, dbo.VendIssdDetail.ReturnDT, dbo.MakerPostedBillsDetail_Receivings.EntryID AS MPB_D_EntryID, dbo.MakerPostedBills.BillNo, dbo.VendRcvdDetail.Rate AS RcvRate, dbo.VendIssdDetail.Rate,
                         dbo.VendReceived.UserName, TBilling.BillingQty
FROM            dbo.VendReceived INNER JOIN
                         dbo.VendRcvdDetail ON dbo.VendReceived.EntryID = dbo.VendRcvdDetail.RefID INNER JOIN
                         dbo.Makers ON dbo.VendReceived.VendID = dbo.Makers.VendID INNER JOIN
                         dbo.Processes ON dbo.VendReceived.ProcessID = dbo.Processes.ProcessID INNER JOIN
                         dbo.Items ON dbo.VendRcvdDetail.ItemCode = dbo.Items.ItemID LEFT OUTER JOIN
                         dbo.MakerPostedBillsDetail_Receivings INNER JOIN
                         dbo.MakerPostedBills ON dbo.MakerPostedBillsDetail_Receivings.MPB_RefID = dbo.MakerPostedBills.EntryID ON dbo.VendRcvdDetail.EntryID = dbo.MakerPostedBillsDetail_Receivings.VRD_RefID LEFT OUTER JOIN
                         dbo.VendIssued INNER JOIN
                         dbo.VendIssdDetail ON dbo.VendIssued.EntryID = dbo.VendIssdDetail.RefID ON dbo.VendRcvdDetail.Issue_RefID = dbo.VendIssdDetail.EntryID LEFT OUTER JOIN
                         dbo.ItemGroups ON dbo.Items.GroupID = dbo.ItemGroups.ID LEFT OUTER JOIN
                         dbo.Employees ON dbo.VendReceived.EmpID = dbo.Employees.empid LEFT OUTER JOIN
                         dbo.FCustomerOrders INNER JOIN
                         dbo.VFOrderItems_Grouped AS FOrderItems ON dbo.FCustomerOrders.OrderNo = FOrderItems.OrderNo ON dbo.VendRcvdDetail.OrderNo = FOrderItems.OrderNo AND
                         dbo.VendRcvdDetail.ItemCode = FOrderItems.CompItemCode LEFT OUTER JOIN
                         dbo.ItemProcesses ON dbo.Processes.ProcessID = dbo.ItemProcesses.ProcessID AND dbo.VendRcvdDetail.ItemCode = dbo.ItemProcesses.ItemID AND
                         dbo.VendReceived.ProcessID = dbo.ItemProcesses.ProcessID LEFT OUTER JOIN
                             (SELECT        VRD_From_RefID
                                FROM            dbo.LotTransferDetails
                                WHERE        (Type = 1)
                                GROUP BY VRD_From_RefID) AS T1 ON dbo.VendRcvdDetail.EntryID = T1.VRD_From_RefID LEFT OUTER JOIN
                             (SELECT        VRD_RefID
                                FROM            dbo.DispatchListDetail_VRD
                                GROUP BY VRD_RefID) AS TDL ON dbo.VendRcvdDetail.EntryID = TDL.VRD_RefID LEFT OUTER JOIN
                             (SELECT        LotNo, ProcessID, RcvdQty - ISNULL(ReWorkQty, 0) - Wastage AS BillingQty
                                FROM            dbo.VendRcvdDetail AS VendRcvdDetail_1) AS TBilling ON dbo.Processes.BillingProcessID = TBilling.ProcessID AND dbo.VendRcvdDetail.LotNo = TBilling.LotNo
GO
