CREATE VIEW [dbo].[VVendRcvdDetailPO]
AS
SELECT     dbo.VendRcvdDetailPO.RcvID, dbo.VendRcvdDetailPO.PORefNo, dbo.VendRcvdDetailPO.MaterialID, dbo.VendRcvdDetailPO.QtyRcvd,
                      dbo.VendRcvdDetailPO.QtyReturned, dbo.VendRcvdDetailPO.Rate, dbo.VendRcvdDetailPO.Checked, dbo.VendRcvdDetailPO.WORef,
                      dbo.VendRcvdDetailPO.StoreName, dbo.VendRcvdDetailPO.ExtraQtyRcvd, dbo.VendRcvd.VendID, dbo.VendOrders.IssuanceType, dbo.VendOrders.DT,
                      dbo.VendRcvd.RcvDate, dbo.VendRcvdDetailPO.EntryID, dbo.VRMAndItemsUnioned.RMName, dbo.VRMAndItemsUnioned.RMSize, dbo.VVendersAndMakers.AccTitle,
                      dbo.VRMAndItemsUnioned.GroupID, dbo.VVendRcvdDetailPO_TotalRejection.QtyRejected, dbo.VVendRcvdDetailPO_TotalRejection.SheetsRejected,
                      dbo.VRMAndItemsUnioned.RMID1, dbo.VVendersAndMakers.AccNo, dbo.VendOrders.SampleOrder
FROM         dbo.VendRcvdDetailPO INNER JOIN
                      dbo.VendOrders ON dbo.VendRcvdDetailPO.PORefNo = dbo.VendOrders.OrderNo INNER JOIN
                      dbo.VendRcvd ON dbo.VendRcvdDetailPO.RcvID = dbo.VendRcvd.RcvID INNER JOIN
                      dbo.VVendersAndMakers ON dbo.VendOrders.VendID = dbo.VVendersAndMakers.AccNo INNER JOIN
                      dbo.VendOrderDetail ON dbo.VendOrders.OrderNo = dbo.VendOrderDetail.OrderNo AND dbo.VendRcvdDetailPO.MaterialID = dbo.VendOrderDetail.RMID INNER JOIN
                      dbo.VRMAndItemsUnioned ON dbo.VendOrderDetail.RMID = dbo.VRMAndItemsUnioned.RMID1 AND
                      dbo.VendOrderDetail.CCItem = dbo.VRMAndItemsUnioned.CCItem LEFT OUTER JOIN
                      dbo.VVendRcvdDetailPO_TotalRejection ON dbo.VendRcvdDetailPO.EntryID = dbo.VVendRcvdDetailPO_TotalRejection.VRDPO_RefID

