CREATE VIEW [dbo].[VMakerPostedBillsDetail]
AS
SELECT     dbo.VendIssued.RecieptID, dbo.VendIssued.VchrNo, Tab1.[Value], Tab2.RcvdValue, Tab2.WasteValue,TempLoan
FROM         dbo.VendIssued LEFT OUTER JOIN
                          (SELECT     RefID, SUM(IssValue) AS Value
                             FROM         VVendIssdDetailWithValue
                             GROUP BY RefID) Tab1 ON dbo.VendIssued.EntryID = Tab1.RefID LEFT OUTER JOIN
                          (SELECT     Issuance_RefID, SUM(RcvdValue) AS RcvdValue, SUM(WasteQtyWeight * IssRate) AS WasteValue
                             FROM         VVendRcvdDetail
                             GROUP BY Issuance_RefID) Tab2 ON dbo.VendIssued.EntryID = Tab2.Issuance_RefID
LEFT OUTER JOIN (SELECT Issuance_RefID,SUM(Amount) AS TempLoan FROM MakerTemporaryLoans GROUP BY Issuance_RefID ) Tab3 ON VendIssued.EntryID=Tab3.Issuance_RefID




