CREATE VIEW [dbo].[VPrintInnerLabels]
AS
SELECT DispatchListDetail_Inners.EntryID, DispatchListDetail_Inners.RefID, DispatchListDetail_Inners.Qty, DispatchListDetail_Inners.InnerNo, DispatchListDetail_Inners.CartonNo, dbo.DispatchListDetails_Adv.ItemCode, dbo.Items.ItemID, dbo.Items.ItemName, dbo.Items.FDAProductCode, dbo.Items.FDAListingNo, dbo.DispatchListDetails_Adv.EntryID AS EntryID_Adv,
         dbo.LotNoForInnerLable_F(DispatchListDetail_Inners.EntryID, 0) AS Lots, dbo.Lot_State_For_Inner_Labels_F(DispatchListDetail_Inners.EntryID, 0) AS Lot_Process,
		 DispatchList.EntryID AS DL_EntryID,DispatchList.CustCode,DispatchList.Country,VDispatchListToExport.OrderNo AS Orders,
		 FOrderitems.IW_BatchNo,FOrderitems.IW_OrderNo,FOrderitems.OrderNo,FCustomerOrders.InternalRefNo AS InternalOrderNo,
		 FOrderitems.Item_Finishing_Type,FOrderitems.Stamps,FOrderitems.Remarks,FOrderitems.Qty AS OrderItemQty,
		 Item_Finishing_Type.Item_Finishing_Type_Text
FROM  dbo.DispatchListDetail_Inners AS DispatchListDetail_Inners INNER JOIN
         dbo.DispatchListDetails_Adv ON DispatchListDetail_Inners.RefID = dbo.DispatchListDetails_Adv.EntryID INNER JOIN
         dbo.Items ON dbo.DispatchListDetails_Adv.ItemCode = dbo.Items.ItemID
		 INNER JOIN DispatchList ON DispatchListDetails_Adv.RefID=DispatchList.EntryID

		 LEFT JOIN VDispatchListToExport ON DispatchListDetails_Adv.ItemCode=VDispatchListToExport.ItemCode
		 AND DispatchList.EntryID=VDispatchListToExport.DispatchListNo

		 LEFT JOIN FOrderitems ON VDispatchListToExport.OrderNo=FOrderitems.OrderNo AND
		 VDispatchListToExport.ItemCode=FOrderitems.CompItemCode
		 INNER JOIN FCustomerOrders ON FOrderitems.OrderNo=FCustomerOrders.OrderNo
		 LEFT JOIN Item_Finishing_Type ON FOrderitems.Item_Finishing_Type=Item_Finishing_Type.EntryID



