CREATE VIEW [dbo].[VVendIssdDetail_MakerDashboard]
AS
SELECT     dbo.VVendIssdDetail.VendID, dbo.VVendIssdDetail.DT, dbo.VVendIssdDetail.UserID, dbo.VVendIssdDetail.ProcessID, dbo.VVendIssdDetail.EntryID,
                      dbo.VVendIssdDetail.RefID, dbo.VVendIssdDetail.RecieptID, dbo.VVendIssdDetail.ItemCode, dbo.VVendIssdDetail.Rate, dbo.VVendIssdDetail.IssQty,
                      dbo.VVendIssdDetail.RcvdQty, dbo.VVendIssdDetail.LotNo, dbo.VVendIssdDetail.ReqAuth, dbo.VVendIssdDetail.VenderName, dbo.VVendIssdDetail.VendID1,
                      dbo.VVendIssdDetail.OrderNo, dbo.VVendIssdDetail.RcvProcessID, dbo.VVendIssdDetail.Rcvd_RefID, dbo.VVendIssdDetail.AccNo, dbo.VVendIssdDetail.ReWorkLot,
                      dbo.VVendIssdDetail.Repair_RefID, dbo.VVendIssdDetail.MainRecieptID, dbo.VVendIssdDetail.Description, dbo.VVendIssdDetail.Code, dbo.VVendIssdDetail.SNO,
                      dbo.VVendIssdDetail.ItemName, dbo.VVendIssdDetail.CustCode, dbo.VVendIssdDetail.GroupID, dbo.VVendIssdDetail.Closed, T1.RcvDT,
                      dbo.VVendIssdDetail.InternalRefNo
FROM         dbo.VVendIssdDetail LEFT OUTER JOIN
                          (SELECT     dbo.VendRcvdDetail.Issue_RefID, MAX(dbo.VendReceived.DT) AS RcvDT
                             FROM         dbo.VendReceived INNER JOIN
                                                   dbo.VendRcvdDetail ON dbo.VendReceived.EntryID = dbo.VendRcvdDetail.RefID
                             GROUP BY dbo.VendRcvdDetail.Issue_RefID) AS T1 ON dbo.VVendIssdDetail.EntryID = T1.Issue_RefID

