CREATE VIEW [dbo].[VVenderPostedBillsList]
AS
SELECT        dbo.VenderPostedBills.EntryID, dbo.VenderPostedBills.AccNo, dbo.VenderPostedBills.UserName, dbo.VenderPostedBills.MachineName,
                         dbo.VenderPostedBills.DTEntry, dbo.VenderPostedBills.BillNo, dbo.VenderPostedBills.DT, dbo.VVendersAndMakers.AccTitle, T1.TotalBillAmount,
                         T2.TotalDedAmount, dbo.VenderPostedBills.VchrNo, dbo.VenderPostedBills.SampleBilling
FROM            dbo.VenderPostedBills INNER JOIN
                         dbo.VVendersAndMakers ON dbo.VenderPostedBills.AccNo = dbo.VVendersAndMakers.AccNo LEFT OUTER JOIN
                             (SELECT        dbo.VenderPostedBillsDetail.RefID, SUM(dbo.VendRcvdDetailPO.QtyRcvd * dbo.VendRcvdDetailPO.Rate) AS TotalBillAmount
                                FROM            dbo.VenderPostedBillsDetail INNER JOIN
                                                         dbo.VendRcvdDetailPO ON dbo.VenderPostedBillsDetail.VRDPO_RefID = dbo.VendRcvdDetailPO.EntryID
                                GROUP BY dbo.VenderPostedBillsDetail.RefID) AS T1 ON dbo.VenderPostedBills.EntryID = T1.RefID LEFT OUTER JOIN
                             (SELECT        dbo.VenderPostedBillsIssuanceDetails.RefID, SUM(dbo.RawMaterialIssuanceDetail.Qty * dbo.RawMaterialIssuanceDetail.Price)
                                                         AS TotalDedAmount
                                FROM            dbo.VenderPostedBillsIssuanceDetails INNER JOIN
                                                         dbo.RawMaterialIssuanceDetail ON dbo.VenderPostedBillsIssuanceDetails.VRMID_RefID = dbo.RawMaterialIssuanceDetail.EntryID
                                GROUP BY dbo.VenderPostedBillsIssuanceDetails.RefID) AS T2 ON dbo.VenderPostedBills.EntryID = T2.RefID

GO
