CREATE VIEW [dbo].[VrptOrders_GroupedItems]
AS
SELECT     TFOrderItems.ItemCode AS ItemCode, TFOrderItems.Qty AS Qty, dbo.Items.ItemName AS ItemName, dbo.FCustomerCatalog.Description AS Description,
                      dbo.FCustomerCatalog.ItemID AS ItemID, dbo.FCustomerCatalog.CompItemID AS CompItemID, dbo.ForeignCustomers.Curr AS Curr, dbo.FCustomerCatalog.Unit AS Unit,
                      dbo.ForeignCustomers.Name AS Name, dbo.ForeignCustomers.Address AS Address, dbo.Items.CustomDescription AS CustomDescription,
                      dbo.Items.ItemSize AS ItemSize, dbo.Items.SizeUnit AS SizeUnit, dbo.SteelTypes.SteelType AS SteelType, dbo.SteelGages.Gage AS Gage,
                      dbo.Items.ItemColor AS ItemColor, dbo.FCustomerCatalog.BarcodeNo AS BarcodeNo, dbo.FCustomerCatalog.PackingMode AS PackingMode,
                      dbo.Items.MasterCartonL AS MasterCartonL, dbo.Items.MasterCartonW AS MasterCartonW, dbo.Items.MasterCartonH AS MasterCartonH,
                      dbo.Items.SmallCartonL AS SmallCartonL, dbo.Items.SmallCartonW AS SmallCartonW, dbo.Items.SmallCartonH AS SmallCartonH, dbo.Items.PolyBag AS PolyBag,
                      dbo.FCustomerCatalog.SpecialInstructions AS SpecialInstructions, dbo.FCustomerCatalog.StampInstructions AS StampInstructions,
                      dbo.FCustomerCatalog.PackingInstructions AS PackingInstructions, dbo.Items.Unit AS UnitItems, dbo.FCustomerCatalog.ItemColor AS CustomerColor,
                      dbo.Items.ItemNameUrdu AS ItemNameUrdu, dbo.Items.InHand AS InHand, dbo.ItemCatagories.MaxLotSize AS MaxLotSize, dbo.Items.FinQuality AS FinQuality,
                      dbo.Items.Type AS Type, dbo.FCustomerCatalog.OCR AS OCR, TShipped.ShippedQty AS ShippedQty, dbo.FCustomerOrders.OrderNo, dbo.FCustomerOrders.DT,
                      dbo.FCustomerOrders.TradeTerms, dbo.FCustomerOrders.CustCode, dbo.FCustomerOrders.Country, dbo.FCustomerOrders.PartialShipment,
                      dbo.FCustomerOrders.PaymentTerms, dbo.FCustomerOrders.TransShipment, dbo.FCustomerOrders.Packaging, dbo.FCustomerOrders.DeliveryDT,
                      dbo.FCustomerOrders.BatchNo, dbo.FCustomerOrders.CompanyRefID, dbo.FCustomerOrders.StampDT, dbo.FCustomerOrders.Quality,
                      dbo.FCustomerOrders.InternalRefNo, dbo.FCustomerOrders.OrderRcvdVia, dbo.FCustomerOrders.OrderType
FROM         dbo.FCustomerOrders INNER JOIN
                          (SELECT     OrderNo, ItemCode, CompItemCode, SUM(Qty) AS Qty
                             FROM         FOrderItems
                             GROUP BY OrderNo, ItemCode, CompItemCode) TFOrderItems ON dbo.FCustomerOrders.OrderNo = TFOrderItems.OrderNo INNER JOIN
                      dbo.FCustomerCatalog ON dbo.FCustomerOrders.CustCode = dbo.FCustomerCatalog.CustCode AND
                      dbo.FCustomerOrders.Country = dbo.FCustomerCatalog.Country AND TFOrderItems.CompItemCode = dbo.FCustomerCatalog.CompItemID INNER JOIN
                      dbo.Items ON dbo.FCustomerCatalog.CompItemID = dbo.Items.ItemID INNER JOIN
                      dbo.ForeignCustomers ON dbo.FCustomerOrders.CustCode = dbo.ForeignCustomers.CustCode AND
                      dbo.FCustomerOrders.Country = dbo.ForeignCustomers.Country INNER JOIN
                      dbo.ItemCatagories ON dbo.Items.CatID = dbo.ItemCatagories.CatID LEFT OUTER JOIN
                      dbo.SteelGages ON dbo.Items.Gage = dbo.SteelGages.GageID LEFT OUTER JOIN
                      dbo.SteelTypes ON dbo.Items.SteelUsed = dbo.SteelTypes.SteelID LEFT OUTER JOIN
                          (SELECT     OrderNo, CompItemCode, SUM(ShippedQty) AS ShippedQty
                             FROM         VFOrderItemswithShippedQty
                             GROUP BY OrderNo, CompItemCode) TShipped ON TFOrderItems.OrderNo = TShipped.OrderNo AND
                      TFOrderItems.CompItemCode = TShipped.CompItemCode



GO
