SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VVendRcvItemsrpt]
AS
SELECT     dbo.Makers.VendID1 AS VendID1, dbo.Makers.VenderName AS VenderName, dbo.Processes.Description AS Process, ISNULL(dbo.Items.ItemName, '')
                      + ' ' + ISNULL(dbo.Items.ItemSize, '') + ' ' + ISNULL(dbo.Items.SizeUnit, '') + ' ' + ISNULL(dbo.Items.Type, '') + ' ' + ISNULL(dbo.Items.FinQuality, '') AS CompItemDesc,
                      dbo.VendRcvAuthdetail.UserID AS AuthUserID, dbo.Processes.Supervisor AS Supervisor, dbo.VendRcvAuthdetail.DT AS AuthDT,
                      dbo.VendIssued.RecieptID AS IssRecieptID, dbo.VVendRcvdItems.DT, dbo.VVendRcvdItems.VendID, dbo.VVendRcvdItems.IssuableQty, dbo.VVendRcvdItems.UserID,
                      dbo.VVendRcvdItems.ItemDescription, dbo.VVendRcvdItems.Issuance_RefID, dbo.VVendRcvdItems.Unit, dbo.VVendRcvdItems.EntryID, dbo.VVendRcvdItems.RefID,
                      dbo.VVendRcvdItems.ItemCode, dbo.VVendRcvdItems.RecieptID, dbo.VVendRcvdItems.RcvdQty, dbo.VVendRcvdItems.Wastage, dbo.VVendRcvdItems.Rate,
                      dbo.VVendRcvdItems.LotNo, dbo.VVendRcvdItems.ReqAuth, dbo.VVendRcvdItems.RcvRepairQty, dbo.VVendRcvdItems.IssRepairQty, dbo.VVendRcvdItems.IssQty,
                      dbo.VVendRcvdItems.NextProcessID, dbo.VVendRcvdItems.LostQty, dbo.VVendRcvdItems.OrderNo, dbo.VVendRcvdItems.CountedBy,
                      dbo.VVendRcvdItems.Issue_RefID, dbo.VVendRcvdItems.ProcessID, dbo.VVendRcvdItems.RcvdWeight, dbo.VVendRcvdItems.RepairAmt,
                      dbo.VVendRcvdItems.Opening_RefID, dbo.VVendRcvdItems.ReWorkQty, dbo.VVendRcvdItems.ReWorkLot, dbo.VVendRcvdItems.Repair_RefID
FROM         dbo.Makers RIGHT OUTER JOIN
                      dbo.VVendRcvdItems INNER JOIN
                      dbo.Processes ON dbo.VVendRcvdItems.ProcessID = dbo.Processes.ProcessID INNER JOIN
                      dbo.Items ON dbo.VVendRcvdItems.ItemCode = dbo.Items.ItemID INNER JOIN
                      dbo.VendIssued ON dbo.VVendRcvdItems.Issuance_RefID = dbo.VendIssued.EntryID ON dbo.Makers.VendID = dbo.VVendRcvdItems.VendID LEFT OUTER JOIN
                      dbo.VendRcvAuthdetail ON dbo.VVendRcvdItems.EntryID = dbo.VendRcvAuthdetail.RcvID

