                      dbo.ShortTermAdvanceClearance.Type, dbo.ShortTermAdvanceClearance.EmpIDTo
FROM         dbo.ShortTermAdvanceClearance LEFT OUTER JOIN
                          (SELECT     SAC_RefID, SUM(ShortTermAdvanceClearanceDetail.Amount) AS Amount
