CREATE VIEW [dbo].[VShortTermLoanLedger]
AS
SELECT EmpID,DT,ActualAmountTaken AS Amount,AccVoucherNo,0 AS ClearedAmt,Description,DeductionStartDT FROM Advances WHERE Type=0 AND ActualAmountTaken>0

UNION ALL

SELECT EmpID,DT,0 AS Amount,'' AS AccVoucherNo,ShortTerm AS ClearedAmt,'Deduction from ' + RIGHT(CONVERT(varchar(50),DT,6),6) + ' Salary' AS Description,DT AS DeductionStartDT FROM MonthlySalaries

UNION ALL

SELECT EmpID,DT,0 AS Amount,'' AS AccVoucherNo,Amount AS ClearedAmt,Remarks AS Description,DT AS DeductionStartDT FROM VShortTermAdvanceClearanceSummary


UNION ALL

SELECT EmpID,ShortTermToLongTermConversions.DT,0 AS Amount,'' AS AccVoucherNo,Advances.Amount AS ClearedAmt, 'Converted To LongTerm' AS Description,ShortTermToLongTermConversions.DT AS DeductionStartDT FROM ShortTermToLongTermConversions INNER JOIN Advances ON ShortTermToLongTermConversions.Advances_RefID=Advances.EntryID


GO
