CREATE FUNCTION [dbo].[F_VendLongDeduct1](@ParDate as Datetime)
RETURNS Table  AS
Return(
/*SELECT     VendID, SUM(isnull(DAmount,0)) AS DedAmt, SUM(isnull(Amount,0)) AS TotAmt
FROM         dbo.VenderAdvances
WHERE     (Type = 1) and Convert(varchar,DT,1)<= @ParDate
GROUP BY VendID*/
Select Tab1.VendID,Tab1.TotAmt,Tab2.DAmount As DedAmt From
(SELECT     VendID, SUM(isnull(Amount,0)) AS TotAmt
FROM         dbo.VenderAdvances
WHERE     (Type = 1)
GROUP BY VendID) Tab1 INNER JOIN (Select VendID,DAmount From VenderAdvances Where Type=1
AND EntryID In(Select Max(EntryID) From VenderAdvances
 WHERe type=1 Group By VendID)) Tab2 ON Tab1.VendID=Tab2.VendID
)










