CREATE FUNCTION [dbo].[F_VendLongDeduct2] (@ParDate as DateTime)
RETURNS Table AS
return(SELECT     VendID, SUM(isnull(LTAmt,0)) AS ClsAmt
FROM         dbo.VendMonthlyPayments Where Convert(varchar,DT,1)<@ParDate AND AdvSalary=0
GROUP BY VendID)
