CREATE FUNCTION [dbo].[F_VendLongDeduct](@ParDate as DateTime)
RETURNS Table AS
Return(
	SELECT     Ded1.*, Ded2.ClsAmt AS ClsAmt
	FROM         F_VendLongDeduct1(@ParDate) Ded1 LEFT OUTER JOIN
             F_VendLongDeduct2(@ParDate) Ded2 ON Ded1.VendID=Ded2.VendID
)

GO
