                      dbo.InternalProductionOrderDetail.CompItemCode, dbo.InternalProductionOrderDetail.SpecialInstructions, dbo.InternalProductionOrderDetailLots.EntryID,
                      dbo.InternalProductionOrderDetailLots.LotQty, dbo.InternalProductionOrderDetailLots.PrintDone, dbo.InternalProductionOrderDetail.Qty,
