CREATE VIEW [dbo].[VCustomerQuotations]
AS
SELECT     dbo.CustomerQuotations.QuotationNo, dbo.CustomerQuotations.DT, dbo.CustomerQuotations.CustCode, dbo.CustomerQuotations.Country,
                      dbo.CustomerQuotations.TradeTerms, dbo.CustomerQuotations.CompanyRefID, dbo.CustomerQuotationsItems.EntryID,
                      dbo.CustomerQuotationsItems.ItemCode, dbo.CustomerQuotationsItems.Qty, dbo.CustomerQuotationsItems.Price, dbo.Items.ItemName, dbo.Items.Unit,
                      dbo.ForeignCustomers.Curr, dbo.CustomerQuotations.Validity, dbo.CustomerQuotations.PaymentTerms, dbo.CustomerQuotations.ShipVia,
                      dbo.CustomerQuotations.Packing, dbo.CustomerQuotations.DeliveryTime, dbo.CustomerQuotations.BankID, dbo.BankList.Remittance,
                      dbo.BankList.Bank, dbo.ForeignCustomers.Address, dbo.ForeignCustomers.FakeAddress, dbo.VFCustomerCatalog.ItemID,
                      dbo.CustomerQuotations.UserName, dbo.CustomerQuotations.MachineName, dbo.CustomerQuotations.DTEntry, dbo.ForeignCustomers.Name,
                      dbo.CustomerQuotations.CustomerRef, dbo.CustomerQuotations.Remarks, dbo.CustomerQuotationsItems.DeliveryDT, dbo.BankList.Branch,
                      dbo.BankList.City, dbo.BankList.AccNo, dbo.VFCustomerCatalog.CompItemID, dbo.CustomerQuotations.Department,
                      dbo.CustomerQuotations.AttentionPerson, dbo.CustomerQuotations.SwiftCode, dbo.CustomerQuotationsItems.QualityType,
                      dbo.ForeignCustomers.City AS CustomerCity, dbo.CustomerQuotations.GrossWeight, dbo.CustomerQuotations.NetWeight,
                      dbo.CustomerQuotations.NoOfPackages, dbo.CustomerQuotations.RevisionHistory, dbo.Items.FinishedWeight, dbo.CustomerQuotations.Destination,
                      dbo.VFCustomerCatalog.Description, dbo.Items.ItemSize, dbo.Items.SizeUnit
FROM         dbo.CustomerQuotations INNER JOIN
                      dbo.CustomerQuotationsItems ON dbo.CustomerQuotations.QuotationNo = dbo.CustomerQuotationsItems.QuotationNo INNER JOIN
                      dbo.Items ON dbo.CustomerQuotationsItems.ItemCode = dbo.Items.ItemID INNER JOIN
                      dbo.ForeignCustomers ON dbo.CustomerQuotations.CustCode = dbo.ForeignCustomers.CustCode AND
                      dbo.CustomerQuotations.Country = dbo.ForeignCustomers.Country INNER JOIN
                      dbo.VFCustomerCatalog ON dbo.CustomerQuotations.CustCode = dbo.VFCustomerCatalog.CustCode AND
                      dbo.CustomerQuotations.Country = dbo.VFCustomerCatalog.Country AND dbo.Items.ItemID = dbo.VFCustomerCatalog.CompItemID LEFT OUTER JOIN
                      dbo.BankList ON dbo.CustomerQuotations.BankID = dbo.BankList.BankID
