CREATE VIEW [dbo].[VChqBookLedger]
AS
SELECT        dbo.ChqList.ChqBookNo, dbo.ChqList.ChqNo, dbo.ChqList.Issued, dbo.VChqLedger.SNo, dbo.VChqLedger.CDate, dbo.VChqLedger.AccNo, dbo.VChqLedger.Amount, dbo.VChqLedger.BankID, dbo.VChqLedger.chequeType,
                         dbo.VChqLedger.chequeDate, dbo.VChqLedger.Posted, dbo.VChqLedger.Payment, dbo.VChqLedger.AccTitle, dbo.VChqLedger.Bank, dbo.VChqLedger.Branch, dbo.VChqLedger.Bounced, dbo.VChqLedger.Description,
                         dbo.Cheque.Description AS DeleteDescription, dbo.Cheque.Payee, dbo.Cheque.ClearanceDT, dbo.ChqBooks.AccNo AS BankAccNo
						 ,dbo.VChqLedger.VDate,dbo.VChqLedger.Vouchers_SNo,dbo.VChqLedger.Handed_Over_To
FROM            dbo.ChqList INNER JOIN
                         dbo.ChqBooks ON dbo.ChqList.ChqBookNo = dbo.ChqBooks.ChqBookNo LEFT OUTER JOIN
                         dbo.Cheque ON dbo.ChqList.ChqBookNo = dbo.Cheque.ChqBookNo AND dbo.ChqList.ChqNo = dbo.Cheque.chequeno LEFT OUTER JOIN
                         dbo.VChqLedger ON dbo.ChqList.ChqBookNo = dbo.VChqLedger.ChqBookNo AND dbo.ChqList.ChqNo = dbo.VChqLedger.chequeno
GO
