CREATE VIEW [dbo].[VrptOrders_ForProduction_Reports]
AS
SELECT TFOrderItems.ItemCode, TFOrderItems.Qty, dbo.VItems_WithFinishedStock.ItemName, dbo.FCustomerCatalog.Description, dbo.FCustomerCatalog.ItemID, dbo.VItems_WithFinishedStock.ItemID AS CompItemID, dbo.ForeignCustomers.Curr, dbo.FCustomerCatalog.Unit, dbo.ForeignCustomers.Name, dbo.ForeignCustomers.Address,
         dbo.VItems_WithFinishedStock.CustomDescription, dbo.VItems_WithFinishedStock.ItemSize, dbo.VItems_WithFinishedStock.SizeUnit, dbo.SteelTypes.SteelType, dbo.SteelGages.Gage, dbo.VItems_WithFinishedStock.ItemColor, dbo.FCustomerCatalog.BarcodeNo, dbo.FCustomerCatalog.PackingMode, dbo.VItems_WithFinishedStock.MasterCartonL,
         dbo.VItems_WithFinishedStock.MasterCartonW, dbo.VItems_WithFinishedStock.MasterCartonH, dbo.VItems_WithFinishedStock.SmallCartonL, dbo.VItems_WithFinishedStock.SmallCartonW, dbo.VItems_WithFinishedStock.SmallCartonH, dbo.VItems_WithFinishedStock.PolyBag, dbo.FCustomerCatalog.SpecialInstructions, dbo.FCustomerCatalog.StampInstructions,
         dbo.FCustomerCatalog.PackingInstructions, dbo.VItems_WithFinishedStock.Unit AS UnitItems, dbo.FCustomerCatalog.ItemColor AS CustomerColor, dbo.VItems_WithFinishedStock.ItemNameUrdu, dbo.VItems_WithFinishedStock.InHand, dbo.ItemCatagories.MaxLotSize, dbo.VItems_WithFinishedStock.FinQuality, dbo.VItems_WithFinishedStock.Type, dbo.FCustomerCatalog.OCR,
         TShipped.ShippedQty, dbo.FCustomerOrders.OrderNo, dbo.FCustomerOrders.DT, dbo.FCustomerOrders.TradeTerms, dbo.FCustomerOrders.CustCode, dbo.FCustomerOrders.Country, dbo.FCustomerOrders.PartialShipment, dbo.FCustomerOrders.PaymentTerms, dbo.FCustomerOrders.TransShipment, dbo.FCustomerOrders.Packaging, dbo.FCustomerOrders.DeliveryDT,
         dbo.FCustomerOrders.BatchNo, dbo.FCustomerOrders.CompanyRefID, dbo.FCustomerOrders.StampDT, dbo.FCustomerOrders.Quality, dbo.FCustomerOrders.InternalRefNo, dbo.FCustomerOrders.OrderRcvdVia, dbo.FCustomerOrders.OrderType, TFOrderItems.SetItem, TFOrderItems.OrderItemID, TFOrderItems.CustomerItemCode, TFOrderItems.CompItemCode,
         dbo.FCustomerOrders.DeliveryDT AS OrderDeliveryDT, TFOrderItems.ItemQuality, TFOrderItems.Remarks, TFOrderItems.DeliveryStatus, TSCW.InHand_CustomerWise, TFOrderItems.Item_Finishing_Type, dbo.Item_Finishing_Type.Item_Finishing_Type_Text
FROM  dbo.FCustomerOrders INNER JOIN
             (SELECT dbo.FOrderItems.OrderNo, dbo.FOrderItems.ItemCode, dbo.FOrderItems.CompItemCode, 0 AS SetItem, dbo.FOrderItems.CompItemCode AS OrderItemID, SUM(dbo.FOrderItems.Qty) AS Qty, dbo.FOrderItems.ItemCode AS CustomerItemCode, dbo.FOrderItems.Quality AS ItemQuality, dbo.FOrderItems.Remarks, dbo.FOrderItems.DeliveryStatus,
                     dbo.FOrderItems.Item_Finishing_Type
            FROM  dbo.FOrderItems INNER JOIN
                     dbo.Items ON dbo.Items.ItemID = dbo.FOrderItems.CompItemCode
            WHERE (dbo.Items.ItemType <> 2)
            GROUP BY dbo.FOrderItems.OrderNo, dbo.FOrderItems.ItemCode, dbo.FOrderItems.CompItemCode, dbo.FOrderItems.Quality, dbo.FOrderItems.Remarks, dbo.FOrderItems.DeliveryStatus, dbo.FOrderItems.Item_Finishing_Type
            UNION ALL
            SELECT FOrderItems_1.OrderNo, dbo.ItemsSets.Set_ItemID, dbo.ItemsSets.Set_ItemID AS Expr1, 1 AS SetItem, FOrderItems_1.CompItemCode AS OrderItemID, SUM(FOrderItems_1.Qty * dbo.ItemsSets.Qty) AS Qty, FOrderItems_1.ItemCode AS CustomerItemCode, FOrderItems_1.Quality, FOrderItems_1.Remarks, FOrderItems_1.DeliveryStatus,
                     FOrderItems_1.Item_Finishing_Type
            FROM  dbo.FOrderItems AS FOrderItems_1 INNER JOIN
                     dbo.Items AS Items_1 ON FOrderItems_1.CompItemCode = Items_1.ItemID INNER JOIN
                     dbo.ItemsSets ON dbo.ItemsSets.ItemID = Items_1.ItemID
            WHERE (Items_1.ItemType = 2)
            GROUP BY FOrderItems_1.OrderNo, dbo.ItemsSets.Set_ItemID, FOrderItems_1.CompItemCode, FOrderItems_1.ItemCode, FOrderItems_1.Quality, FOrderItems_1.Remarks, FOrderItems_1.DeliveryStatus, FOrderItems_1.Item_Finishing_Type) AS TFOrderItems ON dbo.FCustomerOrders.OrderNo = TFOrderItems.OrderNo INNER JOIN
         dbo.FCustomerCatalog ON dbo.FCustomerOrders.CustCode = dbo.FCustomerCatalog.CustCode AND dbo.FCustomerOrders.Country = dbo.FCustomerCatalog.Country AND TFOrderItems.OrderItemID = dbo.FCustomerCatalog.CompItemID INNER JOIN
         dbo.VItems_WithFinishedStock ON TFOrderItems.CompItemCode = dbo.VItems_WithFinishedStock.ItemID INNER JOIN
         dbo.ForeignCustomers ON dbo.FCustomerOrders.CustCode = dbo.ForeignCustomers.CustCode AND dbo.FCustomerOrders.Country = dbo.ForeignCustomers.Country INNER JOIN
         dbo.ItemCatagories ON dbo.VItems_WithFinishedStock.CatID = dbo.ItemCatagories.CatID LEFT OUTER JOIN
         dbo.SteelGages ON dbo.VItems_WithFinishedStock.Gage = dbo.SteelGages.GageID LEFT OUTER JOIN
         dbo.SteelTypes ON dbo.VItems_WithFinishedStock.SteelUsed = dbo.SteelTypes.SteelID LEFT OUTER JOIN
             (SELECT OrderNo, CompItemCode, SUM(ShippedQty) AS ShippedQty
            FROM  dbo.VFOrderItemswithShippedQty
            GROUP BY OrderNo, CompItemCode) AS TShipped ON TFOrderItems.OrderNo = TShipped.OrderNo AND TFOrderItems.CompItemCode = TShipped.CompItemCode LEFT OUTER JOIN
             (SELECT CustCode, ItemID, SUM(NetQty) AS InHand_CustomerWise
            FROM  dbo.VItemsWithShelfWiseStock_Customerwise
            GROUP BY CustCode, ItemID) AS TSCW ON dbo.FCustomerOrders.CustCode = TSCW.CustCode AND TFOrderItems.CompItemCode = TSCW.ItemID LEFT OUTER JOIN
         dbo.Item_Finishing_Type ON TFOrderItems.Item_Finishing_Type = dbo.Item_Finishing_Type.EntryID
GO
