/****** Object:  UserDefinedFunction [dbo].[FSundayOTHrs]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE FUNCTION [dbo].[FSundayOTHrs](@ParDate datetime)
RETURNS TABLE AS
RETURN(
SELECT EmpID--, SUM(CASE WHEN PayableHrs>8 THEN 8 ELSE ROUND(PayableHrs,1) END) AS SundayOTHrs
	--, SUM(ROUND(PayableHrs,2)+ROUND(OTHrs,2)) AS SundayOTHrs
	--CHANGE BY ZEESHAN TO LESS LATE HOURS FROM SUNDAY WORKING HOURS AFTER USER REQUIREMENT
	,SUM((ROUND(PayableHrs,2)+ROUND(OTHrs,2))) AS SundayOTHrs,SUM(ROUND(VEmpTimes2.LateHours,2)) AS LateHOurs
FROM VEmpTimes2
WHERE (MONTH(dt) = MONTH(@ParDate) AND YEAR(DT) = YEAR(@ParDate) AND DT <=@ParDATE )
AND (DATENAME(WEEKDAY,DT)='Sunday' OR DT IN(SELECT DT FROM Holidays))
GROUP BY EmpID)





GO
