                      dbo.VFOrderSteelWeight1.TotalWeight + dbo.VFOrderSteelWeight1.TotalWeight * (dbo.FSteelPurchaseOrder.ExtraPer / 100) AS RealWeight
FROM         dbo.FSteelPurchaseOrder INNER JOIN
                      dbo.VFSteelOrdRealWeight ON dbo.FSteelPurchaseOrder.PInvoice = dbo.VFSteelOrdRealWeight.PInvoice RIGHT OUTER JOIN
                      dbo.VFOrderSteelWeight1 INNER JOIN
                      dbo.SteelTypes ON dbo.VFOrderSteelWeight1.SteelUsed = dbo.SteelTypes.SteelID ON
                      dbo.VFSteelOrdRealWeight.PInvoice = dbo.VFOrderSteelWeight1.PInvoice AND
