CREATE VIEW [dbo].[VCVs]
AS
SELECT     dbo.CVs.EntryID, dbo.CVs.CVID, dbo.CVs.Name, dbo.CVs.Rel, dbo.CVs.FName, dbo.CVs.DOB, dbo.CVs.Religion, dbo.CVs.MaritalStatus, dbo.CVs.Sex, dbo.CVs.Address,
                      dbo.CVs.NIC, dbo.CVs.Phone1, dbo.CVs.Area, dbo.CVs.Cell, dbo.CVs.PerAddress, dbo.CVs.Pic, dbo.CVs.UserName, dbo.CVs.MachineName, dbo.CVs.EntryDT,
                      dbo.CVs.SelectionType, dbo.CVs.InterviewDT, dbo.CVs.InterviewBy, dbo.CVs.Remarks, dbo.VCVLastAcademicQualifications.Diploma, TTotalExp.TotalExperience,
                      dbo.VCVLastReference.strFullName, dbo.VCVLastReference.Guarantor_RefID
FROM         dbo.CVs LEFT OUTER JOIN
                      dbo.VCVLastReference ON dbo.CVs.CVID = dbo.VCVLastReference.CVID LEFT OUTER JOIN
                      dbo.VCVLastAcademicQualifications ON dbo.CVs.CVID = dbo.VCVLastAcademicQualifications.CVID LEFT OUTER JOIN
                          (SELECT     CVID, SUM(Experience) AS TotalExperience
                            FROM          CVExperience
                            GROUP BY CVID) TTotalExp ON dbo.CVs.CVID = TTotalExp.CVID


