CREATE FUNCTION  [dbo].[F_EmpTimes] (@DT as datetime)
RETURNS Table  AS
Return(
SELECT     TOP 100 PERCENT
	dbo.Employees.empid,
	   dbo.Employees.deptid, dbo.Employees.name, dbo.Employees.fname, dbo.Employees.Rel,dbo.Employees.Active
	,EmpTimes.DT,EmpTimes.InTime,EmpTimes.OutTime,EmpTimes.EntryID,EmpTimes.Hrs
FROM         dbo.Employees
LEFT OUTER JOIN (Select EmpID,DT, InTime, OutTime, EntryID, Hrs From EmpTimes Where DT=@DT ) EmpTimes
ON  EmpTimes.EmpID=dbo.Employees.EmpID
WHERE Active=1
ORDER BY dbo.Employees.EmpID, EmpTimes.EntryID
)


