CREATE FUNCTION [dbo].[F_ExpensesPrevious](@StartDate datetime,@EndDate DateTime)
RETURNS Table  AS
RETURN(
SELECT b.SortID,b.Period,b.AccNo,a.Amount FROM (SELECT rptSalePeriodsPrevious.*,Accounts.AccNo FROM Accounts CROSS JOIN rptSalePeriodsPrevious
	--WHERE LEFT(AccNo,3)='42-' OR LEFT(AccNo,3)='43-' OR Left(AccNo,7)='41-006-' OR Left(AccNo,7)='24-004-' OR Left(AccNo,7)='41-001-') b
	WHERE CAST(LEFT(AccNo,2) AS INT)>=31) b
LEFT OUTER JOIN
(SELECT Vouchers.AccNo,LEFT(DATENAME(m,VDate),3) + '-' + RIGHT(DATENAME(YEAR,VDate),2) AS Period,SUM(CASE Type WHEN 0 THEN ABS(Debit-Credit) WHEN 1 THEN  ABS(Credit-Debit) END) AS Amount FROM Vouchers
	INNER JOIN AccountGroupsForExpenseReport ON Vouchers.AccNo=AccountGroupsForExpenseReport.AccNo
	INNER JOIN GroupsForExpenseReport ON GroupsForExpenseReport.EntryID=AccountGroupsForExpenseReport.AccGroup_RefID
	WHERE VDate Between @StartDate AND @EndDate AND CAST(LEFT(Vouchers.AccNo,2) AS INT)>=31
GROUP BY Vouchers.AccNo,LEFT(DATENAME(m,VDate),3) + '-' + RIGHT(DATENAME(YEAR,VDate),2))  a ON a.Period=b.Period AND a.AccNo=b.AccNo)








