CREATE FUNCTION [dbo].[F_VendPlantBill] (
@ParDate Datetime) RETURNS Table AS
Return(



SELECT     dbo.VendReceived.VendID, SUM(dbo.VenderLedger.Qty * dbo.VenderLedger.Rate) AS TotAmt
FROM         dbo.VendReceived INNER JOIN
                      dbo.VenderLedger ON dbo.VendReceived.EntryID = dbo.VenderLedger.RefID AND dbo.VendReceived.VendID <> dbo.VenderLedger.VendID INNER JOIN
                      dbo.Venders ON dbo.VendReceived.VendID = dbo.Venders.VendID AND dbo.VenderLedger.VendID = dbo.Venders.Planter
		Where Month(VendReceived.DT)=Month(@ParDate) AND Year(VendReceived.DT)=Year(@ParDate) AND Convert(varchar,DT,1) <=@ParDATE
GROUP BY dbo.VendReceived.VendID)

