CREATE FUNCTION [dbo].[F_VendResDed] (
@ParDate Datetime,@TotMonDays as int) RETURNS Table AS
Return(
/*SELECT     VendID, Sum((Rate/@TotMonDays)*dbo.F_NoOfDays(AssDT,IsNull(UnAssDT,@ParDate))) AS TotalResDeduction
FROM         dbo.VendAssResources
WHERE (month(AssDT) = Month(@ParDate) AND year(AssDT) = Year(@ParDate)) Or (UnAssDT Is Null) Or
