CREATE FUNCTION [dbo].[FOverTimeDinnerCount](@ParDate DATETIME)
RETURNS TABLE AS
RETURN(
SELECT EmpID,SUM(CASE WHEN OTHrs>=4.5 THEN 1 ELSE 0 END) AS DinnerCount FROM
(SELECT EmpID, DT,SUM(PayableHrs) As OTHrs
FROM EmpTimes
WHERE (month(dt) = Month(@ParDate) AND year(DT) = Year(@ParDate) AND DT <=@ParDATE )  AND (OverTime=1 OR DATENAME(WEEKDAY,DT)='Sunday')
GROUP BY EmpID,DT) T1 GROUP BY EmpID)

