/****** Object:  UserDefinedFunction [dbo].[GetItem_Previous_Next_ProcessID_TblFn]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE FUNCTION [dbo].[GetItem_Previous_Next_ProcessID_TblFn](@ProcessID INT)

RETURNS TABLE
AS
RETURN
(
	SELECT T1.* FROM (
		SELECT ItemID
			,LAG(ProcessID) OVER(PARTITION BY ItemID ORDER BY SNo) AS Previous_ProcessID
			,ProcessID AS Current_ProcessID
			,LEAD(ProcessID) OVER(PARTITION BY ItemID ORDER BY SNo) AS Next_ProcessID
		FROM ItemProcesses --WHERE ProcessID=@ProcessID
		) T1 WHERE Current_ProcessID=@ProcessID
)
GO
