CREATE VIEW [dbo].[VA]
AS
SELECT     dbo.VenderLedger.*, dbo.VendReceived.DT AS Expr1, dbo.VendRcvdDetail.RecieptID AS Expr2
FROM         dbo.VenderLedger INNER JOIN
                      dbo.VendReceived ON dbo.VenderLedger.RefID = dbo.VendReceived.EntryID INNER JOIN
