/****** Object:  View [dbo].[VBalSheet]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VBalSheet]
AS
SELECT DISTINCT (SELECT     SUM(Amount)
                                          FROM         BalSheet
                                          WHERE     Type = 11) AS FixedAssets,
                          (SELECT     SUM(Amount)
                            FROM          BalSheet
                            WHERE      Type IN (12)) AS LongTermInvestments,
                          (SELECT     SUM(Amount)
                            FROM          BalSheet
                            WHERE      Type IN (13)) AS LongTermLoans,
                          (SELECT     SUM(Amount)
                            FROM          BalSheet
                            WHERE      Type IN (14)) AS LongTermDeposits,
                          (SELECT     SUM(Amount)
                            FROM          BalSheet
                            WHERE      Type = 15) AS CurrentAssets,
                          (SELECT     SUM(Amount)
                            FROM          BalSheet
                            WHERE      Type = 21) AS Capital,
                          (SELECT     SUM(Amount)
                            FROM          BalSheet
                            WHERE      Type = 22) AS LongTermLiabilities,
                          (SELECT     SUM(Amount)
                            FROM          BalSheet
                            WHERE      Type = 24) AS CurrentLiabilities,
                          (SELECT     SUM(Amount)
                            FROM          BalSheet
                            WHERE      Type IN (31, 32, 33)) +
                          (SELECT     SUM(Amount)
                            FROM          BalSheet
                            WHERE      Type IN (41, 42, 43, 44)) AS NetIncome
FROM         dbo.BalSheet

GO
