                         dbo.DispatchListDetail_Inners.InnerNo, dbo.DispatchListDetail_Inners.Qty AS InnerQty, dbo.CustomPList.Qty AS CustomPListQty,
                         dbo.DispatchListDetail_VRD.Qty AS DLD_VRD_Qty
FROM            dbo.CustomPList INNER JOIN
