                         dbo.CustomPList_DispatchListDetail ON dbo.CustomPList.ID = dbo.CustomPList_DispatchListDetail.CustomPList_RefID AND
                         dbo.FOrderItems.CompItemCode = dbo.CustomPList_DispatchListDetail.ItemCode AND
                         dbo.CustomPList.CartonFrom = dbo.CustomPList_DispatchListDetail.CartonNo INNER JOIN
                         dbo.DispatchListDetails_Adv ON dbo.CustomPList_DispatchListDetail.DP_RefID = dbo.DispatchListDetails_Adv.RefID AND
                         dbo.CustomPList_DispatchListDetail.ItemCode = dbo.DispatchListDetails_Adv.ItemCode INNER JOIN
                         dbo.DispatchListDetail_Inners ON dbo.DispatchListDetails_Adv.EntryID = dbo.DispatchListDetail_Inners.RefID AND
                         dbo.DispatchListDetail_Inners.CartonNo = dbo.CustomPList_DispatchListDetail.CartonNo INNER JOIN
                         dbo.DispatchListDetail_VRD ON dbo.DispatchListDetail_VRD.DLDC_RefID = dbo.DispatchListDetail_Inners.EntryID INNER JOIN
                         dbo.VendRcvdDetail ON dbo.DispatchListDetail_VRD.VRD_RefID = dbo.VendRcvdDetail.EntryID

