/****** Object:  View [dbo].[VEmpProductivityReport_Production]    Script Date: 6/29/2026 4:50:00 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VEmpProductivityReport_Production]
AS
SELECT     dbo.Employees.empid, dbo.Employees.name, dbo.vendRcvdDetail.ItemCode, dbo.Items.ItemName, dbo.Processes.Description, ROUND(dbo.vendRcvdDetail.RcvdQty / TCount.EmpCount, 0) AS RcvdQty, 0 AS Type, CAST(CONVERT(VARCHAR(50),
                  dbo.VendReceived.DT, 6) AS DATETIME) AS DTOnly, dbo.vendRcvdDetail.LotNo, dbo.Departments.name AS Dname, TEmpTarget.Qty, dbo.VendReceived.OverTime, dbo.Employees.deptid, TEmpTargetOT.OTQty, TRegularGroupTargets.Qty AS GroupTargetQtyRegular,
                  TOTGroupTargets.Qty AS GroupTargetQtyOverTime, TOTGroupTargets.GroupAvgOT, TRegularGroupTargets.GroupAvgRegular, dbo.ItemGroups.Description AS ItemGroupDesc, dbo.Processes.ProcessNameUrdu, dbo.Processes.Description AS ProcessName,
                  dbo.Processes.SNO, dbo.ProcessGroups.GroupName, dbo.ProcessGroupsProcesses.Hub_Name, dbo.ProcessGroupsProcesses.Scanning, dbo.ProcessGroupsProcesses.SeqNo, dbo.vendRcvdDetail.OrderNo, dbo.vendRcvdDetail.RcvdQty AS Expr1,
                  dbo.vendRcvdDetail.Wastage, dbo.vendRcvdDetail.ReWorkQty, dbo.VendReceived.UserName, dbo.VendReceived.MachineName, dbo.Employees.EmpPic, dbo.Employees.Designation, dbo.Employees.JoinDate, dbo.Employees.Active, dbo.vendRcvdDetail.RecieptID,
                  dbo.vendRcvdDetail.RefID, dbo.vendRcvdDetail.EntryID, dbo.VendReceived.EntryID AS Expr3,
				  dbo.VendReceived.ProcessID, dbo.VendReceived.DT, dbo.Employees.fname, dbo.vendRcvdDetail.CountedBy,
				  dbo.vendRcvdDetail.Insp_EmpID,
                  dbo.vendRcvdDetail.Audited,Emp_Ins.name AS Ins_EmpName,Emp_Ins.fname AS Ins_fname
FROM        dbo.VendReceived INNER JOIN
                  dbo.VendReceived_Employees ON dbo.VendReceived.EntryID = dbo.VendReceived_Employees.VR_RefID INNER JOIN
                  dbo.Employees ON dbo.VendReceived_Employees.EmpID = dbo.Employees.empid INNER JOIN
                  dbo.vendRcvdDetail ON dbo.VendReceived.EntryID = dbo.vendRcvdDetail.RefID INNER JOIN
                  dbo.Items ON dbo.vendRcvdDetail.ItemCode = dbo.Items.ItemID INNER JOIN
                  dbo.ItemGroups ON dbo.Items.GroupID = dbo.ItemGroups.ID INNER JOIN
                  dbo.Processes ON dbo.VendReceived.ProcessID = dbo.Processes.ProcessID INNER JOIN
                  dbo.ItemProcesses ON dbo.Items.ItemID = dbo.ItemProcesses.ItemID AND dbo.Processes.ProcessID = dbo.ItemProcesses.ProcessID LEFT OUTER JOIN
                  dbo.ItemProcessGroups ON dbo.Items.ItemID = dbo.ItemProcessGroups.ItemID LEFT OUTER JOIN
                  dbo.ProcessGroups ON dbo.ItemProcessGroups.PG_RefID = dbo.ProcessGroups.EntryID LEFT OUTER JOIN
                  dbo.ProcessGroupsProcesses ON dbo.ProcessGroups.EntryID = dbo.ProcessGroupsProcesses.Group_RefID AND dbo.ItemProcesses.ProcessID = dbo.ProcessGroupsProcesses.Process_RefID INNER JOIN
                  dbo.Departments ON dbo.Employees.deptid = dbo.Departments.deptid LEFT OUTER JOIN
                      (SELECT     EmpID, ProcessID, GroupID, Qty
                       FROM        dbo.EmpDailyTargets
                       WHERE     (OverTime = 0)) AS TEmpTarget ON dbo.Processes.ProcessID = TEmpTarget.ProcessID AND dbo.Items.GroupID = TEmpTarget.GroupID AND dbo.Employees.empid = TEmpTarget.EmpID LEFT OUTER JOIN
                      (SELECT     EmpID, ProcessID, GroupID, Qty AS OTQty
                       FROM        dbo.EmpDailyTargets AS EmpDailyTargets_1
                       WHERE     (OverTime = 1)) AS TEmpTargetOT ON dbo.Processes.ProcessID = TEmpTargetOT.ProcessID AND dbo.Items.GroupID = TEmpTargetOT.GroupID AND dbo.Employees.empid = TEmpTargetOT.EmpID LEFT OUTER JOIN
                      (SELECT     VR_RefID, COUNT(VR_RefID) AS EmpCount
                       FROM        dbo.VendReceived_Employees AS VendReceived_Employees_1
                       GROUP BY VR_RefID) AS TCount ON dbo.VendReceived.EntryID = TCount.VR_RefID LEFT OUTER JOIN
                      (SELECT     EmpID, SUM(Qty) AS Qty, AVG(Qty) AS GroupAvgRegular
                       FROM        dbo.EmpDailyTargets AS EmpDailyTargets_Group
                       WHERE     (OverTime = 0)
                       GROUP BY EmpID) AS TRegularGroupTargets ON dbo.Employees.empid = TRegularGroupTargets.EmpID LEFT OUTER JOIN
                      (SELECT     EmpID, SUM(Qty) AS Qty, AVG(Qty) AS GroupAvgOT
                       FROM        dbo.EmpDailyTargets AS EmpDailyTargets_GroupOT
                       WHERE     (OverTime = 1)
                       GROUP BY EmpID) AS TOTGroupTargets ON dbo.Employees.empid = TOTGroupTargets.EmpID
					LEFT JOIN Employees Emp_Ins ON vendRcvdDetail.Insp_EmpID=Emp_Ins.empid

GO
