CREATE VIEW [dbo].[VFixedAssets]
AS
SELECT     dbo.FixedAssets.EntryID, dbo.FixedAssets.AssetID, dbo.FixedAssets.Description, dbo.FixedAssets.AcquiredDT, dbo.FixedAssets.Location, dbo.FixedAssets.ModelNo,
                      dbo.FixedAssets.SerialNo, dbo.FixedAssets.Manufacturer, dbo.FixedAssets.Notes, dbo.FixedAssets.DeptID, dbo.FixedAssets.Status, dbo.FixedAssets.VendAccNo,
                      dbo.FixedAssets.PlacedInServiceDT, dbo.FixedAssets.AcquisitionCost, dbo.FixedAssets.RetirementDT, dbo.FixedAssets.AccumAccNo,
                      dbo.FixedAssets.DepriciationAccNo, dbo.FixedAssets.DepriciationMethodID, dbo.FixedAssets.Convention, dbo.FixedAssets.AdjustedCost,
                      dbo.FixedAssets.SalvageValue, dbo.FixedAssets.DepriciationBeginMonth, dbo.FixedAssets.LifeInYears, dbo.Departments.name,
                      dbo.Accounts.AccTitle AS VenderAccTitle, Accounts_2.AccTitle AS AccumAccTitle, Accounts_1.AccTitle AS DepriciationAccTitle,
                      dbo.DepriciationMethods.DepriciationMethod, dbo.FixedAssets.InActive, dbo.FixedAssets.MasterFA_RefID,
                      dbo.FixedAssets_Master.Description AS FixedAssets_MasterDescription, dbo.FixedAssets.AssetPic, dbo.FixedAssets.RequiresCalibration,
                      dbo.FixedAssets.CalibrationFrequency
FROM         dbo.FixedAssets INNER JOIN
                      dbo.Departments ON dbo.FixedAssets.DeptID = dbo.Departments.deptid INNER JOIN
