                      dbo.FixedAssets_Master ON dbo.FixedAssets.MasterFA_RefID = dbo.FixedAssets_Master.EntryID LEFT OUTER JOIN
                      dbo.Accounts AS Accounts_2 ON dbo.FixedAssets.AccumAccNo = Accounts_2.AccNo LEFT OUTER JOIN
                      dbo.Accounts AS Accounts_1 ON dbo.FixedAssets.DepriciationAccNo = Accounts_1.AccNo LEFT OUTER JOIN
                      dbo.Accounts ON dbo.FixedAssets.VendAccNo = dbo.Accounts.AccNo

