CREATE VIEW [dbo].[VFOrderItemQty]
AS
SELECT     dbo.FOrderItems.OrderNo, dbo.FOrderItems.CompItemCode, dbo.FCustomerOrders.CustCode, dbo.Items.ItemName,
                      CASE FCustomerOrders.CustCode WHEN 'HICO' THEN 0 ELSE (dbo.F_PerIncrease(dbo.FOrderItems.Qty) - dbo.FOrderItems.Qty) END AS FreeStock,
                      dbo.FOrderItems.Qty, dbo.FCustomerCatalog.PackingMode
FROM         dbo.FOrderItems INNER JOIN
                      dbo.FCustomerOrders ON dbo.FOrderItems.OrderNo = dbo.FCustomerOrders.OrderNo INNER JOIN
                      dbo.Items ON dbo.FOrderItems.CompItemCode = dbo.Items.ItemID INNER JOIN
                      dbo.FCustomerCatalog ON dbo.FCustomerOrders.CustCode = dbo.FCustomerCatalog.CustCode AND
                      dbo.FCustomerOrders.Country = dbo.FCustomerCatalog.Country AND dbo.FOrderItems.CompItemCode = dbo.FCustomerCatalog.CompItemID
