CREATE VIEW [dbo].[VFOrdItemsProcTotInStock1]
AS
SELECT     dbo.VendRcvdDetail.ItemCode, dbo.VendReceived.ProcessID, SUM(dbo.VendRcvdDetail.RcvdQty - dbo.VendRcvdDetail.IssQty) AS ProcTotInStock,
                      SUM(dbo.VendRcvdDetail.Wastage) AS TotWastage, SUM(dbo.VendRcvdDetail.LostQty) AS TotLost
FROM         dbo.VendRcvdDetail INNER JOIN
                      dbo.VendReceived ON dbo.VendRcvdDetail.RefID = dbo.VendReceived.EntryID
WHERE     (dbo.VendRcvdDetail.ReqAuth <> 1)
GROUP BY dbo.VendRcvdDetail.ItemCode, dbo.VendReceived.ProcessID
HAVING      (SUM(dbo.VendRcvdDetail.RcvdQty - dbo.VendRcvdDetail.IssQty) > 0)

GO
