SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VInvoiceBalChecker]
AS
SELECT     dbo.CustomInvoice.CustomInvoice, dbo.CustomInvoice.TotalCustomAmtToRcv,
                      dbo.CustomInvoice.TotalCustomAmt - dbo.CustomInvoice.TotalCustomAmtToRcv AS CustomToTest, Custom.CustomTest,
                      dbo.CustomInvoice.TotalCommercialAmtToRcv,
                      dbo.CustomInvoice.TotalCommercialAmt - dbo.CustomInvoice.TotalCommercialAmtToRcv AS ComToTest, Com.ComTest
FROM         dbo.CustomInvoice LEFT OUTER JOIN
                          (SELECT     PInvoice, SUM(AmtRcvd) AS ComTest
                            FROM          FCustPayments
                            WHERE      CustomPayment = 0
                            GROUP BY PInvoice) Com ON dbo.CustomInvoice.CustomInvoice = Com.PInvoice LEFT OUTER JOIN
                          (SELECT     PInvoice, SUM(AmtRcvd) AS CustomTest
                            FROM          FCustPayments
                            WHERE      CustomPayment = 1
                            GROUP BY PInvoice) Custom ON dbo.CustomInvoice.CustomInvoice = Custom.PInvoice

GO
