/****** Object:  View [dbo].[VLotWithLastProcessOfIssuance]    Script Date: 6/29/2026 4:50:01 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VLotWithLastProcessOfIssuance]
AS
SELECT     dbo.VendIssdDetail.LotNo, dbo.VendIssued.ProcessID, dbo.Processes.Description, dbo.VendIssdDetail.IssQty, T1.RcvdQty, T1.Wastage, T1.ReWorkQty,
                      dbo.VendIssued.DT, T2.TotalWastage, T2.TotalReWorkQty,TotalSplitQty
FROM         dbo.VendIssdDetail INNER JOIN
                      dbo.VendIssued ON dbo.VendIssdDetail.RefID = dbo.VendIssued.EntryID INNER JOIN
                      dbo.Processes ON dbo.VendIssued.ProcessID = dbo.Processes.ProcessID LEFT OUTER JOIN
                          (SELECT     Issue_RefID, SUM(RcvdQty) AS RcvdQty, SUM(Wastage) AS Wastage, SUM(ReWorkQty) AS ReWorkQty
                             FROM         dbo.VendRcvdDetail
                             GROUP BY Issue_RefID) T1 ON dbo.VendIssdDetail.EntryID = T1.Issue_RefID LEFT OUTER JOIN
                          (SELECT     LotNo, SUM(Wastage) AS TotalWastage, SUM(ReWorkQty) AS TotalReWorkQty
                             FROM         dbo.VendRcvdDetail
                             GROUP BY LotNo) T2 ON dbo.VendIssdDetail.LotNo = T2.LotNo LEFT OUTER JOIN
		(SELECT LotNo,SUM(SplitQty) AS TotalSplitQty FROM LotTransferDetails INNER JOIN VendRcvdDetail ON LotTransferDetails.VRD_From_RefID=VendRcvdDetail.EntryID WHERE Type=1 GROUP BY LotNo) T3
			ON VendIssdDetail.LotNo=T3.LotNo

WHERE     (dbo.VendIssdDetail.EntryID IN
                          (SELECT     MAX(EntryID)
                             FROM         VendIssdDetail
                             GROUP BY LotNo))


GO
/****** Object:  View [dbo].[VMakerAdvancesDeduction]    Script Date: 6/29/2026 4:50:01 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE VIEW [dbo].[VMakerAdvancesDeduction]
AS
SELECT     dbo.Accounts.AccNo, dbo.Accounts.AccTitle, ISNULL(TabTaken.TotalAmountTaken, 0) AS TotalAmountTaken, ISNULL(TabCleared.TotalAmountCleared,0) AS TotalAmountCleared, ISNULL(TabDeduction.DAmount, 0) AS DeductionAmount,
	CASE WHEN ISNULL(TabTaken.TotalAmountTaken, 0)-ISNULL(TabCleared.TotalAmountCleared, 0)>ISNULL(TabDeduction.DAmount, 0) THEN ISNULL(TabDeduction.DAmount, 0)
		ELSE ISNULL(TabTaken.TotalAmountTaken, 0)-ISNULL(TabCleared.TotalAmountCleared, 0) END AS ActualDeductionAmount
FROM         dbo.Accounts LEFT OUTER JOIN
                          (SELECT     AccNo, SUM(Amount) AS TotalAmountTaken, MAX(EntryID) AS LastEntryID
                             FROM         MakerAdvances WHERE Type=1
                             GROUP BY AccNo) TabTaken ON dbo.Accounts.AccNo = TabTaken.AccNo LEFT OUTER JOIN
                          (SELECT     AccNo, SUM(AmtClrd) AS TotalAmountCleared
                             FROM         MakerAmtCleared
                             GROUP BY AccNo) TabCleared ON dbo.Accounts.AccNo = TabCleared.AccNo LEFT OUTER JOIN
                      dbo.MakerAdvances TabDeduction ON dbo.Accounts.AccNo = TabDeduction.AccNo AND TabTaken.LastEntryID = TabDeduction.EntryID




GO
