CREATE VIEW [dbo].[VMakerLongTermDeductions]
AS
SELECT     Makers.VendID, Makers.VenderName, ISNULL(TabTaken.TotalAmountTaken, 0) AS TotalAmountTaken, ISNULL(TabCleared.TotalAmountCleared,0) AS TotalAmountCleared, ISNULL(TabDeduction.DAmount, 0) AS DeductionAmount,
	CASE WHEN ISNULL(TabTaken.TotalAmountTaken, 0)-ISNULL(TabCleared.TotalAmountCleared, 0)>ISNULL(TabDeduction.DAmount, 0) THEN ISNULL(TabDeduction.DAmount, 0)
		ELSE ISNULL(TabTaken.TotalAmountTaken, 0)-ISNULL(TabCleared.TotalAmountCleared, 0) END AS ActualDeductionAmount
FROM         Makers LEFT OUTER JOIN
                          (SELECT     MakerID, SUM(Amount) AS TotalAmountTaken, MAX(EntryID) AS LastEntryID
                             FROM         MakerAdvances WHERE Type=1
                             GROUP BY MakerID) TabTaken ON Makers.VendID = TabTaken.MakerID LEFT OUTER JOIN
                          (SELECT     MakerID, SUM(AmtCleared) AS TotalAmountCleared
                             FROM         MakerAmtCleared
                             GROUP BY MakerID) TabCleared ON Makers.VendID = TabCleared.MakerID LEFT OUTER JOIN
                      dbo.MakerAdvances TabDeduction ON Makers.VendID = TabDeduction.MakerID AND TabTaken.LastEntryID = TabDeduction.EntryID




GO
