CREATE VIEW [dbo].[VMakerPostedBills]
AS
SELECT     dbo.Vouchers.VchrNo, dbo.Vouchers.Debit, dbo.Vouchers.balance, Tab1.VendID, dbo.Makers.VendID1, dbo.Makers.VenderName, dbo.MakerPostedBills.BillNo,
                      dbo.MakerPostedBills.EntryID, dbo.MakerPostedBills.DT
FROM         dbo.Vouchers INNER JOIN
                          (SELECT     VendID, VchrNo
                            FROM          VendIssued
                            GROUP BY VendID, VchrNo) Tab1 ON dbo.Vouchers.VchrNo = Tab1.VchrNo INNER JOIN
                      dbo.Makers ON Tab1.VendID = dbo.Makers.VendID INNER JOIN
                      dbo.MakerPostedBills ON dbo.Vouchers.VchrNo = dbo.MakerPostedBills.VchrNo
WHERE     (dbo.Vouchers.Debit > 0)

