/****** Object:  View [dbo].[VMakerPostedBillsList]    Script Date: 6/29/2026 4:50:01 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE VIEW [dbo].[VMakerPostedBillsList]
AS
SELECT dbo.MakerPostedBills.EntryID, dbo.MakerPostedBills.VendID, dbo.MakerPostedBills.DT, dbo.MakerPostedBills.UserName, dbo.MakerPostedBills.MachineName, dbo.MakerPostedBills.DTEntry, dbo.MakerPostedBills.BillNo, dbo.MakerPostedBills.TempAdvance, dbo.MakerPostedBills.STDeduction, dbo.MakerPostedBills.LTDeduction, dbo.MakerPostedBills.ManualBillNo,
         Makers_1.VenderName, dbo.MakerPostedBills.VchrNo, dbo.MakerPostedBills.ManualDedAmt, dbo.MakerPostedBills.RepairAmt, dbo.MakerPostedBills.WastageAmt, dbo.MakerPostedBills.MaterialDedAmt, dbo.MakerPostedBills.DTFrom, dbo.MakerPostedBills.DTTo, TBill.TotalQty, TBill.TotalValue, dbo.MakerPostedBills.Posted, dbo.MakerPostedBills.DebitAccNo,
         dbo.MakerPostedBills.AmountToPost, Makers_1.VendID1, Makers_1.AccNo, dbo.MakerPostedBills.URPTax, dbo.MakerPostedBills.URPVchrNo, dbo.MakerPostedBills.Payment_VchrNo, (TBill.TotalValue - ISNULL(dbo.MakerPostedBills.MaterialDedAmt, 0) - ISNULL(dbo.MakerPostedBills.ManualDedAmt, 0) - ISNULL(dbo.MakerPostedBills.RepairAmt, 0)
         - ISNULL(dbo.MakerPostedBills.WastageAmt, 0) - ISNULL(dbo.MakerPostedBills.STDeduction, 0) - ISNULL(dbo.MakerPostedBills.LTDeduction, 0) + ISNULL(dbo.MakerPostedBills.Material_Return_Amount, 0) + ISNULL(dbo.MakerPostedBills.Manual_Billing_Amount, 0) - ISNULL(dbo.MakerPostedBills.Manual_Billing_Amount_Deduction, 0)
         - ISNULL(dbo.MakerPostedBills.Services_To_Maker, 0)) - ISNULL(dbo.MakerPostedBills.NoOfStations, 0) * ISNULL(dbo.MakerPostedBills.StationRate, 0) AS NetPayable, dbo.MakerPostedBills.NoOfStations, dbo.MakerPostedBills.StationRate, TPayments.TotalPaidAmount, dbo.MakerPostedBills.Material_Return_Amount, dbo.MakerPostedBills.Manual_Billing_Amount,
         dbo.MakerPostedBills.Manual_Billing_Amount_Deduction, dbo.MakerPostedBills.Services_To_Maker
FROM  dbo.MakerPostedBills INNER JOIN
         dbo.Makers AS Makers_1 ON Makers_1.VendID = dbo.MakerPostedBills.VendID LEFT OUTER JOIN
             (SELECT MPB_RefID, SUM(Qty) AS TotalQty, SUM(Qty * Rate) AS TotalValue
            FROM  dbo.MakerPostedBillsDetail_Receivings
            GROUP BY MPB_RefID) AS TBill ON dbo.MakerPostedBills.EntryID = TBill.MPB_RefID LEFT OUTER JOIN
            (
				SELECT MPB_RefID,SUM(PaidAmt) AS TotalPaidAmount FROM
				(
					SELECT MPB_RefID,PaidAmt FROM  dbo.MakerPostedBills_Payments
					UNION
					SELECT MakerPostedBills.EntryID,Amount AS TotalPaidAmount FROM MakerPostedBills
						INNER JOIN Vouchers ON MakerPostedBills.VchrNo=Vouchers.VchrNo
						INNER JOIN VoucherDetail ON Vouchers.SNo=VoucherDetail.SNo
				) TInner GROUP BY MPB_RefID
			/*SELECT MakerPostedBills.EntryID,SUM(Amount) AS TotalPaidAmount FROM MakerPostedBills
				INNER JOIN Vouchers ON MakerPostedBills.VchrNo=Vouchers.VchrNo
				INNER JOIN VoucherDetail ON Vouchers.SNo=VoucherDetail.SNo*/
			--GROUP BY MakerPostedBills.EntryID
			) AS TPayments ON dbo.MakerPostedBills.EntryID = TPayments.MPB_RefID
GO
