CREATE VIEW [dbo].[VPLS]
AS
SELECT DISTINCT (SELECT     isnull(SUM(Amount), 0)
                                          FROM         PLS
                                          WHERE     Type = 31 AND Parent = 0) AS TT31,
                          (SELECT     isnull(SUM(Amount), 0)
                            FROM          PLS
                            WHERE      Type = 33 AND Parent = 0) AS TT33,
                          (SELECT     isnull(SUM(Amount), 0)
                            FROM          PLS
                            WHERE      Type = 41 AND Parent = 0) AS TT41,
                          (SELECT     isnull(SUM(Amount), 0)
                            FROM          PLS
                            WHERE      Type = 42 AND Parent = 0) AS TT42,
                          (SELECT     isnull(SUM(Amount), 0)
                            FROM          PLS
                            WHERE      Type = 43 AND Parent = 0) AS TT43,
                          (SELECT     isnull(SUM(Amount), 0)
                            FROM          PLS
                            WHERE      Type = 44 AND Parent = 0) AS TT44
FROM         dbo.PLS

