CREATE VIEW [dbo].[VPrintEmpLedger]
AS
SELECT dbo.PrintEmpLedger.EntryID, dbo.PrintEmpLedger.DT, dbo.PrintEmpLedger.Status, dbo.PrintEmpLedger.InTime, dbo.PrintEmpLedger.OutTime, dbo.PrintEmpLedger.SecondInTime, dbo.PrintEmpLedger.SecondOutTime, dbo.PrintEmpLedger.OTInTime, dbo.PrintEmpLedger.OTOutTime, dbo.PrintEmpLedger.Hrs, dbo.PrintEmpLedger.LateHours, dbo.PrintEmpLedger.OverTime,
         dbo.PrintEmpLedger.ShortLeave, dbo.PrintEmpLedger.EmpID, dbo.PrintEmpLedger.PayableHrs, dbo.PrintEmpLedger.OTHrsOther, dbo.PrintEmpLedger.OTHrs, dbo.PrintEmpLedger.LateHrs, dbo.Holidays.Description, dbo.PrintEmpLedger.LateHrs_Original,
		 (CASE WHEN ISNULL(Holidays.Description,'')='' THEN 0 ELSE 1 END) AS Holiday,
		 (CASE WHEN (DateName(WeekDay,PrintEmpLedger.DT)='Sunday') THEN 1 ELSE 0 END ) AS IsSunday,

		 (CASE WHEN ((CASE WHEN ISNULL(Holidays.Description,'')='' THEN 0 ELSE 1 END)=1) OR (CASE WHEN (DateName(WeekDay,PrintEmpLedger.DT)='Sunday') THEN 1 ELSE 0 END )=1 THEN
			0
		 ELSE
			LateHrs_Original
		 END) AS LateHours_Ac

FROM  dbo.PrintEmpLedger LEFT OUTER JOIN
         dbo.Holidays ON dbo.PrintEmpLedger.DT = dbo.Holidays.DT


