CREATE VIEW [dbo].[VProductionExportCost]
AS
SELECT     dbo.FCustomerOrders.OrderNo, dbo.FCustomerOrders.DT, dbo.FCustomerOrders.TradeTerms, dbo.FCustomerOrders.CustCode, dbo.FCustomerOrders.Country,
                      dbo.FOrderItems.CompItemCode, dbo.FOrderItems.Qty, dbo.FOrderItems.Price, dbo.Items.ItemName, dbo.Items.Unit, dbo.Items.Type, dbo.Items.ItemSize,
                      dbo.Items.SizeUnit, T1.Rate, dbo.ForeignCustomers.Curr,PriceForCost,Production,IssQty
FROM         dbo.FCustomerOrders INNER JOIN
                      dbo.FOrderItems ON dbo.FCustomerOrders.OrderNo = dbo.FOrderItems.OrderNo INNER JOIN
                      dbo.Items ON dbo.FOrderItems.CompItemCode = dbo.Items.ItemID INNER JOIN
                      dbo.ForeignCustomers ON dbo.FCustomerOrders.CustCode = dbo.ForeignCustomers.CustCode AND
                      dbo.FCustomerOrders.Country = dbo.ForeignCustomers.Country LEFT OUTER JOIN
                          (SELECT     OrderNo, ItemCode,IssQty,Rate,1 AS Production FROM VendIssdDetail WHERE Rcvd_RefID=0 AND EntryID IN(SELECT MIN(EntryID) FROM VendIssdDetail GROUP BY OrderNo, ItemCode)
		UNION ALL
		SELECT OrderNo,ItemID,SUM(Qty) AS IssQty,0 AS Rate,0 AS Production FROM StockOrderAdjustments GROUP BY OrderNo,ItemID
		) T1 ON dbo.FOrderItems.OrderNo = T1.OrderNo AND dbo.FOrderItems.CompItemCode = T1.ItemCode

GO
/****** Object:  View [dbo].[VR2OutLookReport]    Script Date: 6/29/2026 4:50:01 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VR2OutLookReport]
AS
SELECT     ItemCode, ProcessID, SUM(Qty) AS Qty
FROM         (SELECT     dbo.VendIssdDetail.ItemCode, dbo.VendIssued.ProcessID, SUM(dbo.VendIssdDetail.IssQty - dbo.VendIssdDetail.RcvdQty) AS Qty
                        FROM         dbo.VendIssued INNER JOIN
                                              dbo.VendIssdDetail ON dbo.VendIssued.EntryID = dbo.VendIssdDetail.RefID
                        WHERE     (dbo.VendIssdDetail.IssQty > dbo.VendIssdDetail.RcvdQty)
                        GROUP BY dbo.VendIssdDetail.ItemCode, dbo.VendIssued.ProcessID
                        UNION ALL
                        SELECT     ItemCode, NextProcessID AS ProcessID, SUM(RcvdQty - Wastage - ISNULL(ReWorkQty, 0) - IssQty) AS Qty
                        FROM         dbo.VendRcvdDetail
                        WHERE     (RcvdQty - Wastage - ISNULL(ReWorkQty, 0) - IssQty > 0) AND (NextProcessID IS NOT NULL)
                        GROUP BY ItemCode, NextProcessID) AS TInner
GROUP BY ItemCode, ProcessID

GO
