SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VRMStatusStorewise]
AS
SELECT        dbo.RM.RMID, dbo.RM.RMID1, dbo.RM.Unit, dbo.RM.RMName, TabOpening.StoreName, ISNULL(TabRcvd.RcvdQty, 0) AS RcvdQty, ISNULL(TabIssd.IssdQty, 0) AS IssdQty, ISNULL(TabOpening.OpeningBalance, 0)
                         + ISNULL(TabRcvd.RcvdQty, 0) - ISNULL(TabIssd.IssdQty, 0) AS NetQty, TabOpening.OpeningBalance, TabOpening.EntryID, dbo.RM.Rate
FROM            dbo.RM INNER JOIN
                             (SELECT        EntryID, StoreName, RMID, OpeningBalance
                               FROM            dbo.RMStorewiseOpeningStocks) AS TabOpening ON dbo.RM.RMID = TabOpening.RMID LEFT OUTER JOIN
                             (SELECT        MaterialID, StoreName, SUM(QtyRcvd + ISNULL(ExtraQtyRcvd, 0)) AS RcvdQty
                               FROM            dbo.VendRcvdDetailPO
                               GROUP BY MaterialID, StoreName) AS TabRcvd ON dbo.RM.RMID1 = TabRcvd.MaterialID AND TabOpening.StoreName = TabRcvd.StoreName LEFT OUTER JOIN
                             (SELECT        RMID1, StoreName, SUM(Qty) AS IssdQty
                               FROM            dbo.RawMaterialIssuanceDetail
                               GROUP BY RMID1, StoreName) AS TabIssd ON dbo.RM.RMID1 = TabIssd.RMID1 AND TabRcvd.StoreName = TabIssd.StoreName
WHERE        (ISNULL(TabOpening.OpeningBalance, 0) + ISNULL(TabRcvd.RcvdQty, 0) - ISNULL(TabIssd.IssdQty, 0) > 0)
GO
