CREATE VIEW [dbo].[VTotalRcvdProd]
AS
SELECT     dbo.VendRcvdDetail.ItemCode, dbo.VendReceived.ProcessID, dbo.VendRcvdDetail.NextProcessID,
                      SUM(dbo.VendRcvdDetail.RcvdQty - dbo.VendRcvdDetail.IssQty - dbo.VendRcvdDetail.LostQty - dbo.VendRcvdDetail.Wastage)
                      --- dbo.F_AuthQtyForRcv(dbo.VendRcvdDetail.ItemCode, dbo.VendRcvdDetail.NextProcessID)
	AS Qty, dbo.VendRcvdDetail.OrderNo
FROM         dbo.VendRcvdDetail INNER JOIN
                      dbo.VendReceived ON dbo.VendRcvdDetail.RefID = dbo.VendReceived.EntryID
WHERE     (dbo.VendRcvdDetail.RcvdQty - dbo.VendRcvdDetail.IssQty > 0) AND (dbo.VendRcvdDetail.ReqAuth = 0)
GROUP BY dbo.VendRcvdDetail.ItemCode, dbo.VendReceived.ProcessID, dbo.VendRcvdDetail.NextProcessID, dbo.VendRcvdDetail.OrderNo




GO
