CREATE VIEW [dbo].[VTotalRcvdProdNew]
AS
SELECT     dbo.VendRcvdDetail.ItemCode, dbo.VendReceived.ProcessID, dbo.VendRcvdDetail.NextProcessID,
                      SUM(dbo.VendRcvdDetail.RcvdQty - dbo.VendRcvdDetail.IssQty - dbo.VendRcvdDetail.LostQty - dbo.VendRcvdDetail.Wastage - ISNULL(dbo.VendRcvdDetail.ReWorkQty,
                       0)) - dbo.F_AuthQtyForRcv(dbo.VendRcvdDetail.ItemCode, dbo.VendRcvdDetail.NextProcessID) AS Qty, dbo.VendRcvdDetail.OrderNo, dbo.VendReceived.VendID,
                      dbo.VendRcvdDetail.EntryID, dbo.VendRcvdDetail.LotNo
FROM         dbo.VendRcvdDetail INNER JOIN
                      dbo.VendReceived ON dbo.VendRcvdDetail.RefID = dbo.VendReceived.EntryID
WHERE     (dbo.VendRcvdDetail.RcvdQty - dbo.VendRcvdDetail.IssQty > 0) AND (dbo.VendRcvdDetail.ReqAuth = 0)
GROUP BY dbo.VendRcvdDetail.ItemCode, dbo.VendReceived.ProcessID, dbo.VendRcvdDetail.NextProcessID, dbo.VendRcvdDetail.OrderNo, dbo.VendReceived.VendID,
                      dbo.VendRcvdDetail.EntryID, dbo.VendRcvdDetail.LotNo

