CREATE PROCEDURE [dbo].[AddBankAccounts_SP] (@UserName Varchar(255),@ComputerName Varchar(255)) AS

DECLARE @BankID As INT
DECLARE @BankName As Varchar(255)
DECLARE @BankAccount As Varchar(255)
DECLARE @AccName As Varchar(255)
DECLARE @AccNo As Varchar(255)
DECLARE TempTable CURSOR
FOR Select BankID,Bank,AccNo From BankList Order By BankID
OPEN TempTable
FETCH NEXT FROM TempTable into @BankID,@BankName,@BankAccount

WHILE @@FETCH_STATUS = 0
	BEGIN
		SET @AccName=LEFT(@BankName,CHARINDEX(' ',@BankName)) + ' ' + @BankAccount
		SET @AccNo=PakSmith_AWM.dbo.GetNextAccno(@AccName,'15','15-002',0)
		INSERT INTO Accounts(AccNo,AccTitle,SubAccOf,Type,openbal,opendate,Balance,UserName,ComputerName) Values(@AccNo,@AccName,'15-002','15',0,getDate(),0,@UserName,@ComputerName)
		INSERT INTO BankAccounts(BankID,AccNo,Type,BankAccNo,DefaultBank,AllowOD) VALUES(@BankID,@AccNo,'15',@BankAccount,0,0)
		FETCH NEXT FROM TempTable into @BankID,@BankName,@BankAccount

	END

	CLOSE TempTable
	DEALLOCATE TempTable
GO
/****** Object:  StoredProcedure [dbo].[AddBatchNosToInvoice]    Script Date: 6/29/2026 4:50:02 PM ******/
