CREATE PROCEDURE [dbo].[AddBatchNosToInvoice] (@CustomInvoice AS VARCHAR(50)) AS
BEGIN

	DECLARE @myCursor CURSOR
	SET @myCursor=CURSOR FORWARD_ONLY FOR SELECT CustomInvoiceItems.EntryID,CompItemCode,BatchNo FROM CustomInvoiceItems
	INNER JOIN FProformaOrders ON FProformaOrders.EntryID=CustomInvoiceItems.RefID
	INNER JOIN FOrderItems ON FProformaOrders.OrderEntryID=FOrderItems.ID
	WHERE CustomInvoice=@CustomInvoice ORDER BY CompItemCode


	DECLARE @EntryID AS INT,@ItemID AS VARCHAR(255),@PrevItemID AS VARCHAR(255)
	DECLARE @BatchNoSaved AS VARCHAR(50)
	SET @PrevItemID=''
	OPEN @myCursor
	FETCH NEXT FROM @myCursor INTO @EntryID,@ItemID,@BatchNoSaved
	DECLARE @iCounter AS INT,@BatchNo AS VARCHAR(50)


	DECLARE @No AS INT,@Month AS INT,@myDT AS DATETIME
	WHILE @@FETCH_STATUS = 0
		BEGIN
			IF @PrevItemID<>@ItemID
				BEGIN
					IF ISNULL(@BatchNoSaved,'')<>''
						SET @BatchNo=@BatchNoSaved
					ELSE
						BEGIN
							SELECT @No=ROUND(((999 - 1 -1) * RAND() + 1), 0)
							SELECT @Month=ROUND(((12 - 1 -1) * RAND() + 1), 0)
							SET @myDT=DATEADD(m,-@Month,getDate())
							SET @BatchNo=CAST(@No AS VARCHAR(50)) + '/' + REPLACE(RIGHT(CONVERT(varchar(50),@myDT,3),5),'/','')
						END
				END

			UPDATE CustomInvoiceItems SET BatchNo=@BatchNo WHERE EntryID=@EntryID
			SET @PrevItemID=@ItemID
			FETCH NEXT FROM @myCursor INTO @EntryID,@ItemID,@BatchNoSaved
		END

END
CLOSE @myCursor
DEALLOCATE @myCursor
GO
