CREATE PROCEDURE [dbo].[AddForeignCustomerAccounts_SP] (@UserName Varchar(255),@ComputerName Varchar(255)) AS

DECLARE @CustCode As Varchar(255)
DECLARE @AccName As Varchar(255)
DECLARE @AccNo As Varchar(255)
DECLARE TempTable CURSOR
FOR Select CustCode,Name From ForeignCustomers Order By CustCode
OPEN TempTable
FETCH NEXT FROM TempTable into @CustCode,@AccName

WHILE @@FETCH_STATUS = 0
	BEGIN
		SET @AccNo=PakSmith_AWM.dbo.GetNextAccno(@CustCode,'15','15-003',0)
		INSERT INTO Accounts(AccNo,AccTitle,SubAccOf,Type,openbal,opendate,Balance,UserName,ComputerName) Values(@AccNo,@CustCode,'15-003','15',0,getDate(),0,@UserName,@ComputerName)
		UPDATE ForeignCustomers SET AccNo=@AccNo WHERE CustCode=@CustCode
		FETCH NEXT FROM TempTable into @CustCode,@AccName

	END

	CLOSE TempTable
	DEALLOCATE TempTable
GO
