CREATE PROCEDURE [dbo].[ArticlewiseWIP_SP](@ItemID AS VARCHAR(50),@Options AS TinyInt=0,@ProcessID AS INT=0,@DTFrom DATETIME,@DTTo DATETIME)
AS
BEGIN
IF @Options=0 --Processwise
	SELECT Items.ItemID,Processes.ProcessID,Processes.Description,TabIssd.IssQty,TabRcvd.RcvdQty,TabRcvd.ReIssQty FROM Items INNER JOIN ItemProcesses
	ON Items.ItemID=ItemProcesses.ItemID INNER JOIN Processes ON ItemProcesses.ProcessID=Processes.ProcessID
	LEFT OUTER JOIN
	(SELECT ItemCode,ProcessID,SUM(IssQty) AS IssQty FROM VVendIssdDetail WHERE ItemCode=@ItemID AND VVendIssdDetail.DT BETWEEN @DTFrom AND @DTTo GROUP BY ItemCode,ProcessID) TabIssd ON
	ItemProcesses.ItemID=TabIssd.ItemCode AND ItemProcesses.ProcessID=TabIssd.ProcessID
	LEFT OUTER JOIN
	(SELECT ItemCode,ProcessID,SUM(RcvdQty) AS RcvdQty,SUM(IssQty) AS ReIssQty FROM VVendRcvdDetail WHERE ItemCode=@ItemID AND VVendRcvdDetail.DT BETWEEN @DTFrom AND @DTTo GROUP BY ItemCode,ProcessID) TabRcvd ON
	ItemProcesses.ItemID=TabRcvd.ItemCode AND ItemProcesses.ProcessID=TabRcvd.ProcessID
	WHERE Items.ItemID=@ItemID ORDER BY ItemProcesses.SNo
ELSE IF @Options=1 --Orderwise ; Makerwise
	SELECT VendID1,OrderNo,Items.ItemID,ItemProcesses.ProcessID,TabIssd.IssQty,TabIssd.RcvdQty FROM Items INNER JOIN ItemProcesses ON Items.ItemID=ItemProcesses.ItemID
	LEFT OUTER JOIN
	(SELECT VendID,OrderNo,ItemCode,ProcessID,SUM(IssQty) AS IssQty,SUM(RcvdQty) AS RcvdQty FROM VVendIssdDetail WHERE VVendIssdDetail.DT BETWEEN @DTFrom AND @DTTo GROUP BY VendID,OrderNo,ItemCode,ProcessID) TabIssd ON
	ItemProcesses.ItemID=TabIssd.ItemCode AND ItemProcesses.ProcessID=TabIssd.ProcessID
	INNER JOIN Makers ON TabIssd.VendID=Makers.VendID
	WHERE Items.ItemID=@ItemID AND ItemProcesses.ProcessID=@ProcessID ORDER BY OrderNo
ELSE IF @Options=2 --Issuance # wise
	SELECT RecieptID,VendID1,TabIssd.OrderNo,Items.ItemID,ItemProcesses.ProcessID,TabIssd.IssQty,TabIssd.RcvdQty,InternalRefNo FROM Items INNER JOIN ItemProcesses ON Items.ItemID=ItemProcesses.ItemID
	LEFT OUTER JOIN
	(SELECT MainRecieptID AS RecieptID,VendID,OrderNo,ItemCode,ProcessID,IssQty,RcvdQty FROM VVendIssdDetail WHERE VVendIssdDetail.DT BETWEEN @DTFrom AND @DTTo) TabIssd ON
	ItemProcesses.ItemID=TabIssd.ItemCode AND ItemProcesses.ProcessID=TabIssd.ProcessID
	INNER JOIN Makers ON TabIssd.VendID=Makers.VendID
	INNER JOIN FCustomerOrders ON TabIssd.OrderNo=FCustomerOrders.OrderNo
	WHERE Items.ItemID=@ItemID AND ItemProcesses.ProcessID=@ProcessID ORDER BY TabIssd.OrderNo
END
GO
