CREATE PROCEDURE [dbo].[BalanceSheet_SP]
	-- Add the parameters for the stored procedure here
	(@DTTo AS DATETIME)
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	/*DECLARE @SNos TABLE(SNo INT)
	INSERT INTO @SNos(SNo) SELECT MAX(Sno) FROM VLedger WHERE VDATE<=@DTTo AND LEFT(dbo.Vouchers.AccNo,2) IN('11','12','13','14','15','21','22','23','24') GROUP BY AccNo*/
	SELECT Accounts.AccNo,AccTitle,Head,SubAccOf,Parent,Code,ISNULL(T1.TheBalance, dbo.Accounts.openbal) AS ClosingBalance FROM Accounts
		INNER JOIN Heads ON Accounts.Type=Heads.Code

		LEFT OUTER JOIN
		(SELECT Accno, Balance  AS TheBalance FROM dbo.Vouchers WHERE SNo IN (SELECT MAX(Sno) FROM VLedger WHERE VDATE<=@DTTo AND LEFT(VLedger.AccNo,2) IN('11','12','13','14','15','21','22','23','24') GROUP BY AccNo)) T1
		ON Accounts.AccNo=T1.AccNo

		WHERE LEFT(Accounts.AccNo,2) IN('11','12','13','14','15','21','22','23','24')
END
GO
