CREATE PROCEDURE [dbo].[CashBookReport_SP] (@DTFrom AS DATETIME,@DTTo AS DATETIME) AS

BEGIN

SET @DTFrom=CAST(CONVERT(VARCHAR(50),@DTFrom,6) AS DATETIME)
SET @DTTo=CAST(CONVERT(VARCHAR(50),@DTTo,6) AS DATETIME)

DECLARE @CashMasterAccount AS VARCHAR(255)
SELECT @CashMasterAccount=DataValue FROM GeneralData WHERE DataName='CashInHandParent'

DECLARE @OpeningBalance AS INT,@AccNo AS VARCHAR(255),@ClosingBalance AS INT
SET @OpeningBalance=0
SET @ClosingBalance=0

DECLARE @myCursor CURSOR
SET @myCursor=CURSOR FORWARD_ONLY FOR SELECT AccNo FROM Accounts WHERE SubAccOf=@CashmasterAccount
OPEN @myCursor
FETCH NEXT FROM @myCursor INTO @AccNo
WHILE @@FETCH_STATUS = 0
	BEGIN
		SET @OpeningBalance=@OpeningBalance+ISNULL(dbo.GetBalance(@AccNo,DATEADD(d,-1,@DTFrom),getDate()),0)
		SET @ClosingBalance=@ClosingBalance+ISNULL(dbo.GetBalance(@AccNo,@DTTo,getDate()),0)
		FETCH NEXT FROM @myCursor INTO @AccNo
	END
CLOSE @myCursor
DEALLOCATE @myCursor

SELECT     SNo, VDate, Vouchers.VchrNo, Accounts.Accno, Description, Vouchers.Debit AS Credit, Vouchers.Credit AS Debit, Vouchers.balance, DpstSlip, CSNo,Accounts.AccTitle,TCash.Balance AS CashBalance,TCash.Debit AS CashDebit,TCash.Credit AS CashCredit,@OpeningBalance AS OpeningBalance,@ClosingBalance AS ClosingBalance
FROM         dbo.Vouchers INNER JOIN Accounts ON Vouchers.AccNo=Accounts.AccNo
LEFT OUTER JOIN(SELECT VchrNo,Debit,Credit,Vouchers.Balance FROM Vouchers INNER JOIN Accounts ON Vouchers.AccNo=Accounts.AccNo WHERE VDate BETWEEN @DTFrom AND @DTTo AND Accounts.SubAccOf=@CashMasterAccount) TCash ON Vouchers.VchrNo=TCash.VchrNo
WHERE     Vouchers.VchrNo IN
                          (SELECT     VchrNo
                             FROM         Vouchers INNER JOIN Accounts ON Vouchers.AccNo=Accounts.AccNo
                             WHERE     Accounts.SubAccOf=@CashMasterAccount AND (LEFT(VchrNo, 3) IN ('CPV', 'CRV','BPV')))  AND (Accounts.SubAccOf<>@CashMasterAccount)
	AND VDate BETWEEN @DTFrom AND @DTTo


END
GO
