CREATE PROCEDURE [dbo].[CustomerComparison_SP] (@CustCode AS VARCHAR(50),@CompareCustomers AS VARCHAR(4000)) AS

BEGIN
SET ANSI_WARNINGS OFF
DECLARE @myQuery AS VARCHAR(4000)


		CREATE TABLE #Customers (CustCode VARCHAR(50))

		IF @CompareCustomers='0'
			SET @myQuery='INSERT INTO #Customers(CustCode) SELECT DISTINCT CustCode FROM ForeignCustomers'
		ELSE
			SET @myQuery='INSERT INTO #Customers(CustCode) SELECT DISTINCT  CustCode FROM ForeignCustomers WHERE CustCode IN(' + @CompareCustomers +')'
		EXEC(@myQuery)

		CREATE TABLE #ReturnTBL (ItemCode VARCHAR(255),Common TINYINT)

		INSERT INTO #ReturnTBL(ItemCode,Common)
			SELECT DISTINCT CompItemCode,1 FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
				WHERE CustCode=@CustCode AND CompItemCode IN(SELECT CompItemCode FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
											INNER JOIN #Customers ON FCustomerOrders.CustCode=#Customers.CustCode)

		INSERT INTO #ReturnTBL(ItemCode,Common)
			SELECT DISTINCT CompItemCode,0 FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
				WHERE CustCode=@CustCode AND CompItemCode NOT IN(SELECT CompItemCode FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
											INNER JOIN #Customers ON FCustomerOrders.CustCode=#Customers.CustCode)

		INSERT INTO #ReturnTBL(ItemCode,Common)
			SELECT DISTINCT CompItemCode,0 FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
				WHERE CustCode IN(SELECT CustCode FROM #Customers)
				AND CompItemCode NOT IN(SELECT CompItemCode FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo WHERE CustCode=@CustCode)
				AND CompItemCode NOT IN(SELECT ItemCode FROM #ReturnTBL)

			SELECT * FROM #ReturnTBL


SET ANSI_WARNINGS ON
END
GO
