CREATE PROCEDURE [dbo].[CustomerRecommendations_SP] (@CustCode AS VARCHAR(50)='') AS

BEGIN

SET ANSI_WARNINGS OFF

CREATE TABLE #myTBL (CustCode VARCHAR(50),ItemID VARCHAR(255))

CREATE TABLE #ReturnTBL (CustCode VARCHAR(50),ItemID VARCHAR(255))

INSERT INTO #myTBL(CustCode,ItemID)
	SELECT CustCode,CompItemCode FROM FCustomerOrders INNER JOIN FOrderItems ON FCustomerOrders.OrderNo=FOrderItems.OrderNo WHERE DT<=DATEADD(day,90,getDate())


IF @CustCode=''

	SELECT CustCode,Items.ItemID,ItemName FROM #myTBL INNER JOIN Items ON #myTBL.ItemID=Items.ItemID
		WHERE CustCode+Items.ItemID NOT IN(SELECT CustCode+CompItemCode FROM FCustomerOrders INNER JOIN FOrderItems ON FCustomerOrders.OrderNo=FOrderItems.OrderNo WHERE DT>DATEADD(day,90,getDate()))

ELSE
	SELECT CustCode,Items.ItemID,ItemName FROM #myTBL INNER JOIN Items ON #myTBL.ItemID=Items.ItemID
		WHERE CustCode+Items.ItemID NOT IN(SELECT CustCode+CompItemCode FROM FCustomerOrders INNER JOIN FOrderItems ON FCustomerOrders.OrderNo=FOrderItems.OrderNo WHERE DT>DATEADD(day,90,getDate()))
		AND CustCode=@CustCode

SET ANSI_WARNINGS ON

END
