SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [dbo].[CustomerStats_ValueWise_SP](@DTFrom DATETIME,@DTTo DATETIME,@CustCode VARCHAR(4000)='')
AS
BEGIN

SET @DTFrom=CAST(CONVERT(VARCHAR(50),@DTFrom,6) AS DATETIME)
SET @DTTo=CAST(CONVERT(VARCHAR(50),@DTTo,6) AS DATETIME)

CREATE TABLE #Customers(CustCode VARCHAR(50))

DECLARE @myQuery AS VARCHAR(1000)
IF @CustCode=''
	SET @myQuery='INSERT INTO #Customers(CustCode) SELECT CustCode FROM ForeignCustomers'
ELSE
	SET @myQuery='INSERT INTO #Customers(CustCode) SELECT CustCode FROM ForeignCustomers WHERE CustCode IN(' + @CustCode +')'

EXEC(@myQuery)

DELETE FROM #Customers WHERE CustCode='Stock'

CREATE TABLE #myTBL(CustCode VARCHAR(255),ExchRate REAL,TotalPendingValue INT,TotalPendingValuePK INT,TotalSalesValue INT,TotalSalesValuePK INT,TotalOpenPOValue INT,TotalRcvingNoBilling INT,TotalRcvingBilling INT)



INSERT INTO #myTBL(CustCode)
	SELECT CustCode FROM ForeignCustomers


UPDATE #myTBL SET #myTBL.ExchRate=T1.ExchRate,#myTBL.TotalPendingValue=T1.TotalPendingValue,#myTBL.TotalPendingValuePK=(T1.TotalPendingValue*T1.ExchRate)
	 FROM #myTBL TMain INNER JOIN (SELECT CustCode,ExchRate,SUM(OrderAmt-TotalShippedAmt) AS TotalPendingValue FROM VFOrderList WHERE OrderNo IN(SELECT OrderNo FROM VUnshippedOrderList) GROUP BY CustCode,ExchRate) T1 ON TMain.CustCode=T1.CustCode

UPDATE #myTBL SET #myTBL.TotalSalesValue=T1.TotalSalesValue,#myTBL.TotalSalesValuePK=(T1.TotalSalesValue*TMain.ExchRate)
	 FROM #myTBL TMain INNER JOIN (SELECT CustCode,SUM(Qty*Price) AS TotalSalesValue FROM VCustomInvoice WHERE DT BETWEEN @DTFrom AND @DTTo GROUP BY CustCode) T1 ON TMain.CustCode=T1.CustCode

UPDATE #myTBL SET #myTBL.TotalOpenPOValue=T1.TotalOpenPOValue
	 FROM #myTBL TMain INNER JOIN (SELECT CustCode,SUM(Qty*Rate) AS TotalOpenPOValue FROM VItemOpenPOs INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=VItemOpenPOs.OrderNo GROUP BY CustCode) T1 ON TMain.CustCode=T1.CustCode

UPDATE #myTBL SET #myTBL.TotalRcvingNoBilling=T1.TotalRcvingNoBilling
	 FROM #myTBL TMain INNER JOIN (SELECT CustCode,SUM(VendRcvdDetail.RcvdQty*VendIssdDetail.Rate) AS TotalRcvingNoBilling FROM VendRcvdDetail
									INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=VendRcvdDetail.OrderNo
									INNER JOIN VendIssdDetail ON VendRcvdDetail.Issue_RefID=VendIssdDetail.EntryID
										WHERE VendRcvdDetail.EntryID NOT IN(SELECT VRD_RefID FROM MakerPostedBillsDetail_Receivings)  GROUP BY CustCode) T1 ON TMain.CustCode=T1.CustCode

UPDATE #myTBL SET #myTBL.TotalRcvingBilling=T1.TotalRcvingBilling
	 FROM #myTBL TMain INNER JOIN (SELECT CustCode,SUM(VendRcvdDetail.RcvdQty*VendIssdDetail.Rate) AS TotalRcvingBilling FROM VendRcvdDetail
									INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=VendRcvdDetail.OrderNo
									INNER JOIN VendIssdDetail ON VendRcvdDetail.Issue_RefID=VendIssdDetail.EntryID
									INNER JOIN MakerPostedBillsDetail_Receivings oN VendRcvdDetail.EntryID=MakerPostedBillsDetail_Receivings.VRD_RefID
									INNER JOIN MakerPostedBills ON MakerPostedBillsDetail_Receivings.MPB_RefID=MakerPostedBills.EntryID
									WHERE MakerPostedBills.DT BETWEEN @DTFrom AND @DTTo GROUP BY CustCode) T1 ON TMain.CustCode=T1.CustCode


SELECT #myTBL.* FROM #myTBL INNER JOIN #Customers ON #myTBL.CustCode=#Customers.CustCode

END
GO
/****** Object:  StoredProcedure [dbo].[CustomerYearWiseDemandSupply_SP]    Script Date: 6/29/2026 4:50:02 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE PROCEDURE [dbo].[CustomerYearWiseDemandSupply_SP] (@DTFrom AS DATETIME,@DTTo AS DATETIME) AS

DECLARE @myReturnTBLOrders TABLE(CustCode VARCHAR(50),OrderYear INT,OrderNos INT,OrderValue INT,OrderPcs INT)
DECLARE @myReturnTBLExport TABLE(CustCode VARCHAR(50),OrderYear INT,ExportNos INT,ExportValue INT,ExportPcs INT)

DECLARE @myReturnTBL TABLE(CustCode VARCHAR(50),OrderYear INT,OrderNos INT,OrderValue INT,OrderPcs INT,ExportNos INT,ExportValue INT,ExportPcs INT)
--DECLARE @YearsTBL TABLE(myYear INT)

--INSERT INTO @YearsTBL(myYear) SELECT DISTINCT FullYear FROM DateLookup WHERE DateFull BETWEEN @DTFrom AND @DTTo

INSERT INTO @myReturnTBLOrders(CustCode,OrderYear,OrderNos,OrderValue,OrderPcs)
	SELECT CustCode,YEAR(DT) AS myYear,COUNT(DISTINCT FCustomerOrders.OrderNO),SUM(Qty*Price),SUM(Qty)  FROM FCustomerOrders INNER JOIN FOrderItems ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
	WHERE DT BETWEEN @DTFrom AND @DTTo AND OrderType='Customer Order'
	GROUP BY CustCode,YEAR(DT)


CREATE TABLE #TempTBL(CustCode VARCHAR(255),CustomInvoice VARCHAR(255),OrderYear INT,ExportNos INT,ExportValue INT,ExportPcs INT)

INSERT INTO #TempTBL(CustCode,CustomInvoice,OrderYear,ExportNos,ExportValue,ExportPcs)
	SELECT CustCode,CustomInvoice,YEAR(DT),COUNT(DISTINCT OrderNo) AS ExportNos,SUM(Qty*Price),SUM(Qty) FROM VCustomInvoice WHERE DT BETWEEN @DTFrom AND @DTTo AND ISNULL(GatePassNo,'')<>''
	GROUP BY CustCode,CustomInvoice,YEAR(DT)

UPDATE #TempTBL SET ExportValue=ExportValue+ISNULL(OtherCharges,0) FROM #TempTBL T1 INNER JOIN VCustomInvoiceOtherChargesTotal ON T1.CustomInvoice=VCustomInvoiceOtherChargesTotal.CustomInvoice
INSERT INTO @myReturnTBLExport(CustCode,OrderYear,ExportNos,ExportValue,ExportPcs)
	SELECT CustCode,OrderYear,ExportNos,ExportValue,ExportPcs FROM #TempTBL
/*INSERT INTO @myReturnTBLExport(CustCode,OrderYear,ExportNos,ExportValue,ExportPcs)
	SELECT CustCode,OrderYear,ExportNos,ExportValue,ExportPCs FROM (
	SELECT CustCode,VCustomInvoice.CustomInvoice,YEAR(DT) AS OrderYear,COUNT(DISTINCT OrderNo) AS ExportNos,SUM(Qty*Price)+ISNULL(VCustomInvoiceOtherChargesTotal.OtherCharges,0) AS ExportValue,SUM(Qty) AS ExportPCs FROM VCustomInvoice
		LEFT OUTER JOIN VCustomInvoiceOtherChargesTotal ON VCustomInvoice.CustomInvoice=VCustomInvoiceOtherChargesTotal.CustomInvoice
	WHERE DT BETWEEN @DTFrom AND @DTTo GROUP BY CustCode,VCustomInvoice.CustomInvoice,YEAR(DT),OtherCharges) TMain
	GROUP BY CustCode,OrderYear*/


INSERT INTO @myReturnTBL(CustCode,OrderYear,OrderNos,OrderValue,OrderPCs,ExportNos,ExportValue,ExportPcs)
	SELECT CustCode,OrderYear,SUM(OrderNos),SUM(OrderValue),SUM(OrderPcs),SUM(ExportNos),SUM(ExportValue),SUM(ExportPcs) FROM
	(SELECT CustCode,OrderYear,OrderNos,OrderValue,OrderPcs,0 AS ExportNos,0 AS ExportValue,0 AS ExportPcs FROM @myReturnTBLOrders
	UNION
	SELECT CustCode,OrderYear,0,0,0,ExportNos,ExportValue,ExportPcs FROM @myReturnTBLExport) T1 GROUP BY CustCode,OrderYear

SELECT * FROM @myReturnTBL
