--HAVING DATEDIFF(day,MAX(DT),GetDate())>@iDays
CREATE PROCEDURE [dbo].[DeadStockReport_SP] (@Stores VARCHAR(4000)='',@iDays AS INT) AS

BEGIN

	CREATE TABLE #Stores(StoreID INT)

	DECLARE @myQuery AS VARCHAR(1000)
	IF @Stores=''
		SET @myQuery='INSERT INTO #Stores(StoreID) SELECT EntryID FROM Stores'
	ELSE
		SET @myQuery='INSERT INTO #Stores(StoreID) SELECT EntryID FROM Stores WHERE EntryID IN(' + @Stores +')'
	EXEC(@myQuery)
	SELECT Items.ItemID,Items.ItemName,ISNULL(T1.StoreQty,0) AS StoreQty,StoreName,ISNULL(SFStockQty,0) AS SFStockQty FROM Items
		LEFT OUTER JOIN
		(SELECT ItemID,StoreName,SUM(NetQty) AS StoreQty FROM VItemsWithShelfWiseStock INNER JOIN #Stores ON VItemsWithShelfWiseStock.Store_RefID=#Stores.StoreID GROUP BY ItemID,StoreName HAVING SUM(NetQty)>0) T1 ON Items.ItemID=T1.ItemID
		LEFT OUTER JOIN
		(SELECT ItemID,SUM(Qty-IssdQty) AS SFStockQty FROM VStockOrderOpening INNER JOIN #Stores ON VStockOrderOpening.Store_RefID=#Stores.StoreID  WHERE Qty>IssdQty GROUP BY ItemID) TSF ON Items.ItemID=TSF.ItemID

		LEFT OUTER JOIN (SELECT CompItemCode,MAX(DT) AS LastOrderDT FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
										GROUP BY CompItemCode) T2 ON Items.ItemID=T2.CompItemCode
		WHERE (DATEDIFF(d,LastOrderDT,getDate())>@iDays OR LastOrderDT IS NULL)
		AND ISNULL(T1.StoreQty,0)+ISNULL(TSF.SFStockQty,0)>0
END


GO
