CREATE PROCEDURE [dbo].[Delivery_Performance_PurchaserWise_SP](@DTFrom DATETIME,@DTTo DATETIME,@VendID INT=0,@Purchaser VARCHAR(50)='')

AS
	BEGIN
		-- SET NOCOUNT ON added to prevent extra result sets from
		-- interfering with SELECT statements.
		SET NOCOUNT ON;


		SELECT MasterPONo,VenderName,TInner.DT,TargetDT,TInner.CustCode,Iss_Items,Iss_Qty,Rcv_Items,Rcv_Qty,OnTime,VID_EmpID,VEmp.Name AS Purchaser,LastRcvDT,FCustomerOrders.OrderNo,FCustomerOrders.InternalRefNo FROM (
		SELECT MasterPONo,VendID,DT,VID_EmpID,CustCode,OrderNo,MAX(LastRcvDT) AS LastRcvDT,MAX(ReturnDT) AS TargetDT,COUNT(*) AS Iss_Items,SUM(IssQty) AS Iss_Qty,SUM(CASE WHEN RcvdQty>0 THEN 1 ELSE 0 END) AS Rcv_Items,SUM(RcvdQty) AS Rcv_Qty,SUM(OnTime) AS OnTime
		FROM (
		SELECT VendIssued.MasterPONo,VendIssued.VendID,VendIssued.DT,VendIssdDetail.ReturnDT,FCustomerOrders.CustCode,FCustomerOrders.OrderNo,
		VendIssdDetail.IssQty,VendIssdDetail.RcvdQty,VendIssdDetail.VID_EmpID,CASE WHEN (ReturnDT<LastRcvDT) THEN 1 ELSE 0 END AS OnTime,LastRcvDT FROM VendIssued
		INNER JOIN VendIssdDetail ON VendIssued.EntryID=VendIssdDetail.RefID
		INNER JOIN FCustomerOrders ON VendIssdDetail.OrderNo=FCustomerOrders.OrderNo
		LEFT JOIN (SELECT VendRcvdDetail.Issue_RefID,MAX(VendReceived.DT) AS LastRcvDT FROM VendRcvdDetail
					INNER JOIN VendReceived ON VendRcvdDetail.RefID=VendReceived.EntryID
					GROUP BY VendRcvdDetail.Issue_RefID) TRcv ON VendIssdDetail.EntrYID=TRcv.Issue_RefID WHERE VendIssdDetail.ReturnDT BETWEEN @DTFrom AND @DTTo) T1
					GROUP BY MasterPONo,VendID,DT,VID_EmpID,CustCode,OrderNo) TInner INNER JOIN Makers ON TInner.VendID=Makers.VendID INNER JOIN VEmp ON TInner.VID_EmpID=VEmp.EmpID
		INNER JOIN FCustomerOrders ON TInner.OrderNo=FCustomerOrders.OrderNo
		AND (TInner.VendID=@VendID OR @VendID=0)
		AND (VID_EmpID=@Purchaser OR @Purchaser='')


	END

GO
