CREATE PROCEDURE [dbo].[DeliveryPreformanceReport_SP] (@DTFrom AS DATETIME,@DTTo AS DATETIME) AS

BEGIN

	SELECT TOrders.OrderNo,TOrders.TotalItems,TOrders.TotalQty,TotalShippedQty,TotalShippedItems,LastShipmentDate,ISNULL(TInner.DeliveryDT,FCustomerOrders.DeliveryDT)  AS DeliveryDT,CASE WHEN VUnshippedOrderList.OrderNo IS NULL THEN 1 ELSE  0 END AS Shipped,FCustomerOrders.DT AS OrderDT,InternalRefNo,CustCode,TotalValue FROM (
	SELECT FCustomerOrders.OrderNo,COUNT(ItemCode) AS TotalItems,SUM(Qty) AS TotalQty,SUM(Qty*Price) AS TotalValue FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,ISNULL(OriginalDelivery,DeliveryDT) AS DeliveryDT FROM VFCustomerOrders_ShippingDates
				WHERE EntryID IN(SELECT MAX(EntryID) FROM FCustomerOrders_ShippingDates GROUP BY OrderNo)) TInner ON FCustomerOrders.OrderNo=TInner.OrderNo
	WHERE ISNULL(TInner.DeliveryDT,FCustomerOrders.DeliveryDT)  BETWEEN @DTFrom AND @DTTo
	GROUP BY FCustomerOrders.OrderNo) TOrders  INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=TOrders.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,ISNULL(OriginalDelivery,DeliveryDT) AS DeliveryDT FROM VFCustomerOrders_ShippingDates
				WHERE EntryID IN(SELECT MAX(EntryID) FROM FCustomerOrders_ShippingDates GROUP BY OrderNo)) TInner ON FCustomerOrders.OrderNo=TInner.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,SUM(ShippedQty) AS TotalShippedQty,COUNT(ItemCode) AS TotalShippedItems ,MAX(LastShipmentDate) AS LastShipmentDate FROM VFOrderItemsWithShippedQty GROUP BY OrderNo) TShipped
	ON TOrders.OrderNo=TShipped.OrderNo LEFT OUTER JOIN VUnshippedOrderList ON FCustomerOrders.OrderNo=VUnshippedOrderList.OrderNo
	WHERE FCustomerOrders.CustCode NOT IN('Stock','PHF') AND FCustomerOrders.OrderNo NOT IN(SELECT OrderNo FROM FCustomerFInalOrders WHERE Cancelled IN(1,2))
END
GO
