CREATE PROCEDURE [dbo].[DemandAndSupply_SP] (@DTFrom AS DATETIME,@DTTo AS DATETIME) AS

BEGIN

	DECLARE @DTFrom1 AS DATETIME,@DTTo1 AS DATETIME
	DECLARE @DTFrom2 AS DATETIME,@DTTo2 AS DATETIME
	DECLARE @DTFrom3 AS DATETIME,@DTTo3 AS DATETIME
	DECLARE @DTFrom4 AS DATETIME,@DTTo4 AS DATETIME
	DECLARE @DTFrom5 AS DATETIME,@DTTo5 AS DATETIME
	DECLARE @DTFrom6 AS DATETIME,@DTTo6 AS DATETIME
	DECLARE @DTFrom7 AS DATETIME,@DTTo7 AS DATETIME
	DECLARE @DTFrom8 AS DATETIME,@DTTo8 AS DATETIME
	DECLARE @DTFrom9 AS DATETIME,@DTTo9 AS DATETIME
	DECLARE @DTFrom10 AS DATETIME,@DTTo10 AS DATETIME
	DECLARE @DTFrom11 AS DATETIME,@DTTo11 AS DATETIME
	DECLARE @DTFrom12 AS DATETIME,@DTTo12 AS DATETIME


	SET @DTFrom1=@DTFrom;SET @DTFrom2=DateAdd(m,1,@DTFrom);SET @DTFrom3=DateAdd(m,2,@DTFrom);SET @DTFrom4=DateAdd(m,3,@DTFrom)
	SET @DTFrom5=DateAdd(m,4,@DTFrom);SET @DTFrom6=DateAdd(m,5,@DTFrom);SET @DTFrom7=DateAdd(m,6,@DTFrom);SET @DTFrom8=DateAdd(m,7,@DTFrom)
	SET @DTFrom9=DateAdd(m,8,@DTFrom);SET @DTFrom10=DateAdd(m,9,@DTFrom);SET @DTFrom11=DateAdd(m,10,@DTFrom);SET @DTFrom12=DateAdd(m,11,@DTFrom)

	SET @DTTo1=DateAdd(d,-1,DateAdd(m,1,@DTFrom1));SET @DTTo2=DateAdd(d,-1,DateAdd(m,1,@DTFrom2));SET @DTTo3=DateAdd(d,-1,DateAdd(m,1,@DTFrom3))
	SET @DTTo4=DateAdd(d,-1,DateAdd(m,1,@DTFrom4));SET @DTTo5=DateAdd(d,-1,DateAdd(m,1,@DTFrom5));SET @DTTo6=DateAdd(d,-1,DateAdd(m,1,@DTFrom6))
	SET @DTTo7=DateAdd(d,-1,DateAdd(m,1,@DTFrom7));SET @DTTo8=DateAdd(d,-1,DateAdd(m,1,@DTFrom8));SET @DTTo9=DateAdd(d,-1,DateAdd(m,1,@DTFrom9))
	SET @DTTo10=DateAdd(d,-1,DateAdd(m,1,@DTFrom10));SET @DTTo11=DateAdd(d,-1,DateAdd(m,1,@DTFrom11));SET @DTTo12=DateAdd(d,-1,DateAdd(m,1,@DTFrom12))

	CREATE TABLE #Dates(myDTFrom DATETIME,myDTTo DATETIME)
	INSERT INTO 	#Dates(myDTFrom,myDTTo) VALUES(@DTFrom1,@DTTo1)
	INSERT INTO 	#Dates(myDTFrom,myDTTo) VALUES(@DTFrom2,@DTTo2)
	INSERT INTO 	#Dates(myDTFrom,myDTTo) VALUES(@DTFrom3,@DTTo3)
	INSERT INTO 	#Dates(myDTFrom,myDTTo) VALUES(@DTFrom4,@DTTo4)
	INSERT INTO 	#Dates(myDTFrom,myDTTo) VALUES(@DTFrom5,@DTTo5)
	INSERT INTO 	#Dates(myDTFrom,myDTTo) VALUES(@DTFrom6,@DTTo6)
	INSERT INTO 	#Dates(myDTFrom,myDTTo) VALUES(@DTFrom7,@DTTo7)
	INSERT INTO 	#Dates(myDTFrom,myDTTo) VALUES(@DTFrom8,@DTTo8)
	INSERT INTO 	#Dates(myDTFrom,myDTTo) VALUES(@DTFrom9,@DTTo9)
	INSERT INTO 	#Dates(myDTFrom,myDTTo) VALUES(@DTFrom10,@DTTo10)
	INSERT INTO 	#Dates(myDTFrom,myDTTo) VALUES(@DTFrom11,@DTTo11)
	INSERT INTO 	#Dates(myDTFrom,myDTTo) VALUES(@DTFrom12,@DTTo12)

	CREATE TABLE #ResultSet(DT DATETIME,NoOfOrders INT,OrderQty INT,OrderAmt INT,OrderAmtPK INT,NoOfShipments INT,ShippedQty INT,ShippedAmt INT,ShippedAmtPK INT)

	INSERT INTO #ResultSet(DT) SELECT myDTFrom FROM #Dates

	UPDATE #ResultSet SET #ResultSet.NoOfOrders=T1.NoOfOrders,#ResultSet.OrderQty=T1.OrderQty,#ResultSet.OrderAmt=T1.OrderAmt
		FROM #ResultSet INNER JOIN (SELECT myDTFrom,COUNT(DISTINCT FCustomerOrders.OrderNo) AS NoOfOrders,SUM(Qty) AS OrderQty,SUM(Qty*Price) AS OrderAmt FROM FCustomerOrders INNER JOIN FOrderItems ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
					INNER JOIN #Dates ON FCustomerOrders.DT BETWEEN #Dates.myDTFrom AND #Dates.myDTTo AND FCustomerOrders.CustCode NOT IN('Stock','PHF') AND FCustomerOrders.OrderNo NOT IN(SELECT OrderNo FROM FCustomerFInalOrders WHERE Cancelled IN(1,2)) GROUP BY myDTFrom) T1 ON #ResultSet.DT=T1.myDTFrom

	UPDATE #ResultSet SET #ResultSet.NoOfShipments=T1.NoOfShipments,#ResultSet.ShippedQty=T1.ShippedQty,#ResultSet.ShippedAmt=T1.ShippedAmt
		FROM #ResultSet INNER JOIN (SELECT myDTFrom,COUNT(DISTINCT CustomInvoice.CustomInvoice) AS NoOfShipments,SUM(Qty) AS ShippedQty,SUM(Qty*Price) AS ShippedAmt FROM CustomInvoice INNER JOIN CustomInvoiceItems ON CustomInvoice.CustomInvoice=CustomInvoiceitems.CustomInvoice
					INNER JOIN #Dates ON CustomInvoice.DT BETWEEN #Dates.myDTFrom AND #Dates.myDTTo WHERE ISNULL(RTRIM(LTRIM(GatePassNo)),'')<>'' GROUP BY myDTFrom) T1 ON #ResultSet.DT=T1.myDTFrom

	SELECT * FROM #ResultSet
	/*SELECT TOrders.OrderNo,TOrders.TotalItems,TOrders.TotalQty,TotalShippedQty,TotalShippedItems,LastShipmentDate,ISNULL(TInner.DeliveryDT,FCustomerOrders.DeliveryDT)  AS DeliveryDT,CASE WHEN VUnshippedOrderList.OrderNo IS NULL THEN 1 ELSE  0 END AS Shipped,FCustomerOrders.DT AS OrderDT,InternalRefNo,CustCode,TotalValue FROM (
	SELECT FCustomerOrders.OrderNo,COUNT(ItemCode) AS TotalItems,SUM(Qty) AS TotalQty,SUM(Qty*Price) AS TotalValue FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,ISNULL(OriginalDelivery,DeliveryDT) AS DeliveryDT FROM VFCustomerOrders_ShippingDates
				WHERE EntryID IN(SELECT MAX(EntryID) FROM FCustomerOrders_ShippingDates GROUP BY OrderNo)) TInner ON FCustomerOrders.OrderNo=TInner.OrderNo
	WHERE ISNULL(TInner.DeliveryDT,FCustomerOrders.DeliveryDT)  BETWEEN @DTFrom AND @DTTo
	GROUP BY FCustomerOrders.OrderNo) TOrders  INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=TOrders.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,ISNULL(OriginalDelivery,DeliveryDT) AS DeliveryDT FROM VFCustomerOrders_ShippingDates
				WHERE EntryID IN(SELECT MAX(EntryID) FROM FCustomerOrders_ShippingDates GROUP BY OrderNo)) TInner ON FCustomerOrders.OrderNo=TInner.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,SUM(ShippedQty) AS TotalShippedQty,COUNT(ItemCode) AS TotalShippedItems ,MAX(LastShipmentDate) AS LastShipmentDate FROM VFOrderItemsWithShippedQty GROUP BY OrderNo) TShipped
	ON TOrders.OrderNo=TShipped.OrderNo LEFT OUTER JOIN VUnshippedOrderList ON FCustomerOrders.OrderNo=VUnshippedOrderList.OrderNo
	WHERE FCustomerOrders.CustCode NOT IN('Stock','PHF') AND FCustomerOrders.OrderNo NOT IN(SELECT OrderNo FROM FCustomerFInalOrders WHERE Cancelled IN(1,2))*/
END
GO
