CREATE PROCEDURE [dbo].[DemandsReceivedReport_FourMonthWise_SP] (@DTFrom AS DATETIME,@DTTo AS DATETIME,@CustCode AS VARCHAR(4000)='',@ItemGroup AS VARCHAR(4000)='') AS

BEGIN
		SET ANSI_WARNINGS OFF
		DECLARE @myQuery AS VARCHAR(4000)

		CREATE TABLE #Customers(CustCode VARCHAR(50))
		CREATE TABLE #ItemGroups(GroupID INT)

		DECLARE @Processes AS VARCHAR(1000)
		IF @CustCode=''
			SET @myQuery='INSERT INTO #Customers(CustCode) SELECT CustCode FROM ForeignCustomers'
		ELSE
			SET @myQuery='INSERT INTO #Customers(CustCode) SELECT CustCode FROM ForeignCustomers WHERE CustCode IN(' + @CustCode +')'
		EXEC(@myQuery)

		IF @ItemGroup=''
			SET @myQuery='INSERT INTO #ItemGroups(GroupID) SELECT ID FROM ItemGroups'
		ELSE
			SET @myQuery='INSERT INTO #ItemGroups(GroupID) SELECT ID FROM ItemGroups WHERE ID IN(' + @ItemGroup + ')'

		EXEC(@myQuery)

		DECLARE  @DTFrom1 AS DATETIME,@DTTo1 AS DATETIME
		DECLARE  @DTFrom2 AS DATETIME,@DTTo2 AS DATETIME
		DECLARE  @DTFrom3 AS DATETIME,@DTTo3 AS DATETIME

		SET @DTFrom1=@DTFrom
		SET @DTTo1=DATEADD(month,4,@DTFrom1)-1

		SET @DTFrom2=@DTTo1+1
		SET @DTTo2=DATEADD(month,4,@DTFrom2)-1

		SET @DTFrom3=@DTTo2+1
		SET @DTTo3=DATEADD(month,4,@DTFrom3)-1

	SELECT T1.CustCode,ItemID,ItemName,Items.GroupID,ItemGroups.Description,Period1Hits,Period1Qty,Period2Hits,Period2Qty,Period3Hits,Period3Qty FROM Items
		INNER JOIN (SELECT #Customers.CustCode,CompItemCode FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
					INNER JOIN #Customers ON FCustomerOrders.CustCode=#Customers.CustCode WHERE DT BETWEEN @DTFrom AND @DTTo GROUP BY #Customers.CustCode,CompitemCode) T1 ON Items.ItemID=T1.CompItemCode
		LEFT OUTER JOIN(SELECT #Customers.CustCode,CompItemCode,SUM(Qty) AS Period1Qty,COUNT(DISTINCT CompItemCode) AS Period1Hits FROM FOrderItems
					INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo INNER JOIN #Customers ON FCustomerOrders.CustCode=#Customers.CustCode WHERE DT BETWEEN @DTFrom1 AND @DTTo1 GROUP BY #Customers.CustCode,CompitemCode) TPeriod1 ON T1.CustCode=TPeriod1.CustCode AND T1.CompItemCode=TPeriod1.CompItemCode
		LEFT OUTER JOIN(SELECT #Customers.CustCode,CompItemCode,SUM(Qty) AS Period2Qty,COUNT(DISTINCT CompItemCode) AS Period2Hits FROM FOrderItems
					INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo INNER JOIN #Customers ON FCustomerOrders.CustCode=#Customers.CustCode WHERE DT BETWEEN @DTFrom2 AND @DTTo2 GROUP BY #Customers.CustCode,CompitemCode) TPeriod2 ON T1.CustCode=TPeriod2.CustCode AND T1.CompItemCode=TPeriod2.CompItemCode
		LEFT OUTER JOIN(SELECT #Customers.CustCode,CompItemCode,SUM(Qty) AS Period3Qty,COUNT(DISTINCT CompItemCode) AS Period3Hits FROM FOrderItems
					INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo INNER JOIN #Customers ON FCustomerOrders.CustCode=#Customers.CustCode WHERE DT BETWEEN @DTFrom3 AND @DTTo3 GROUP BY #Customers.CustCode,CompitemCode) TPeriod3 ON T1.CustCode=TPeriod3.CustCode AND T1.CompItemCode=TPeriod3.CompItemCode

		INNER JOIN #ItemGroups ON Items.GroupID=#ItemGroups.GroupID INNER JOIN ItemGroups ON Items.GroupID=ItemGroups.ID

SET ANSI_WARNINGS ON
END
GO
