CREATE PROCEDURE [dbo].[EmployeeLoanBalanceReport_SP] (@DT AS DATETIME,@InActive AS BIT) AS
SET @DT=CAST(CONVERT(VARCHAR(50),@DT,6) AS DATETIME)

SELECT     ISNULL(LT.LongTermBalance, 0) AS LongTermBalance, dbo.VEmp.deptid, dbo.VEmp.DeptName, dbo.VEmp.empid, dbo.VEmp.name, dbo.VEmp.fname, dbo.VEmp.dob,
                      dbo.VEmp.Religion, dbo.VEmp.Age, dbo.VEmp.sex, dbo.VEmp.Address, dbo.VEmp.NIC, dbo.VEmp.NTN, dbo.VEmp.Phone1, dbo.VEmp.Phone2, dbo.VEmp.AbsAllowed,
                      dbo.VEmp.TimeAllowed, dbo.VEmp.NTimes, dbo.VEmp.OverTime, dbo.VEmp.StartingSalary, dbo.VEmp.Salary, dbo.VEmp.PProfit, dbo.VEmp.Active,
                      dbo.VEmp.EmpType, dbo.VEmp.DiscontinuedOn, dbo.VEmp.JoinDate, dbo.VEmp.Bonus, dbo.VEmp.Designation, dbo.VEmp.Rel, dbo.VEmp.Status, dbo.VEmp.Transport,
                      dbo.VEmp.EnterTime, dbo.VEmp.ExitTime, dbo.VEmp.BGHoliday, dbo.VEmp.AGHoliday, dbo.VEmp.BPHoliday, dbo.VEmp.APHoliday, dbo.VEmp.Emp_ID,
                      dbo.VEmp.LunchTime, dbo.VEmp.EmergencyName, dbo.VEmp.EmergencyFName, dbo.VEmp.EmergencyPhone1, dbo.VEmp.EmergencyPhone2,
                      dbo.VEmp.EmergencyAddress, dbo.VEmp.BloodGroup, dbo.VEmp.OTByQty, dbo.VEmp.MinQty, dbo.VEmp.UnionFund, dbo.VEmp.Lunch, dbo.VEmp.social,
                      dbo.VEmp.oldage, dbo.VEmp.SocialNo, dbo.VEmp.OldAgeNo, dbo.VEmp.InsurableDT, dbo.VEmp.ArmyRetired, dbo.VEmp.EmpAccNo, dbo.VEmp.BankPymt,
                      dbo.VEmp.TempDept, dbo.VEmp.EmployeeID, dbo.VEmp.EmpPic, dbo.VEmp.PerPieceRate, dbo.VEmp.Rate, dbo.VEmp.EmpMinSalary, dbo.VEmp.EmpIDOld,
                      dbo.VEmp.ProbationPeriod, dbo.VEmp.EmpAttCat_RefID, dbo.VEmp.ExemptSettings, dbo.VEmp.TempEmp, dbo.VEmp.intGuarantorId,STLoan,strFullName,strAddress,LTLoanDed
FROM         dbo.VEmp LEFT OUTER JOIN GuarantorList_Imported ON VEmp.intGuarantorId=GuarantorList_Imported.intGuarantorId
LEFT OUTER JOIN
                          (SELECT     EmpID, SUM(amount) AS LongTermBalance
                            FROM          VLongTermLoans WHERE DT<=@DT
                            GROUP BY EmpID) LT ON dbo.VEmp.empid = LT.EmpID
		--LEFT OUTER JOIN (SELECT EmpID,SUM(Amount) AS STLoan FROM Advances WHERE MONTH(DT)=MONTH(@DT) AND YEAR(DT)=YEAR(@DT) GROUP BY EmpID) TShortTerm ON VEmp.EmpID=TShortTerm.EmpID
		LEFT OUTER JOIN (SELECT EmpID,SUM(Amount) AS STLoan FROM Advances WHERE DT<=@DT AND Cleared=0 AND Type=0 GROUP BY EmpID) TShortTerm ON VEmp.EmpID=TShortTerm.EmpID
		LEFT OUTER JOIN (SELECT EmpID,DAmount AS LTLoanDed FROM Advances WHERE EntryID IN(SELECT MAX(EntryID) FROM Advances WHERE Type=1 GROUP BY EmpID)) TMonthlyDed ON VEmp.EmpID=TMonthlyDed.EmpID
	WHERE (Active=0 OR @InActive=0)

GO
