-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[Employees_Targets_Report_SP](@DTFrom DATETIME,@DTTo DATETIME)

AS
BEGIN

	SET NOCOUNT ON;

	SELECT T2.*,EmpDailyTargets.Qty AS TargetQty FROM EmpDailyTargets INNER JOIN (
	SELECT T1.EmpID,VEmp.Name,VEmp.Designation,VEmp.DeptName,T1.ProcessID,T1.GroupID,T1.RcvdQty
	,ItemGroups.Description AS ItemGroup,Processes.Description AS Process,T1.OverTime
	FROM (
	SELECT EmpID,ProcessID,GroupID,OverTime,SUM(RcvdQty) AS RcvdQty
			--,SUM(CASE WHEN OverTime=0 THEN RcvdQty ELSE 0 END) AS RcvdQty
			--,SUM(CASE WHEN OverTime=1 THEN RcvdQty ELSE 0 END) AS RcvdQty_OverTime

	FROM VVendRcvdDetail_Simple INNER JOIN VendReceived_Employees ON VendReceived_Employees.VR_RefID=VVendRcvdDetail_Simple.RefID
	WHERE VVendRcvdDetail_Simple.DT BETWEEN @DTFrom AND @DTTo
	GROUP BY EmpID,ProcessID,GroupID,OverTime) T1
	INNER JOIN VEmp ON T1.EmpID=VEmp.EmpID
	INNER JOIN ItemGroups ON ItemGroups.ID=T1.GroupID
	INNER JOIN Processes ON T1.ProcessID=Processes.ProcessID) T2 ON
	T2.EmpID=EmpDailyTargets.EmpID AND T2.GroupID=EmpDailyTargets.GroupID AND T2.ProcessID=EmpDailyTargets.ProcessID AND T2.OverTime=EmpDailyTargets.OverTime

END
GO
