CREATE PROCEDURE [dbo].[EmpOverTimeSheet_SP] @DTFrom DateTime,@DTTo DateTime,@EmpID AS VARCHAR(50)='',@DeptID AS VARCHAR(50)=''
AS

BEGIN

	SELECT VEmp.EmpID,Name,Rel,FName,StartingSalary,DeptName,DeptID,Designation,Active,Tab2.TotalOTHrs,Tab2.TotalExcessHrs FROM VEmp
		INNER JOIN (SELECT EmpID,SUM(PayableHrs) AS TotalOTHrs,0 AS TotalExcessHrs FROM EmpTimes WHERE OverTime=1 AND DT BETWEEN @DTFrom AND @DTTo GROUP BY EmpID) Tab2
	 ON VEmp.EmpID=Tab2.EmpID

	 WHERE (VEmp.deptid=@DeptID OR @DeptID='') AND (VEmp.EmpID=@EmpID OR @EmpID='')
	 ORDER BY VEmp.EmpID
END

GO
