CREATE PROCEDURE [dbo].[EmpYearlyDaysReport_SP] (@DTFrom DATETIME,@DTTo DATETIME) AS

SET @DTFrom=CONVERT(varchar(50),@DTFrom,6)
SET @DTTo=CONVERT(varchar(50),@DTTo,6)

DECLARE @DTFrom1 AS DATETIME,@DTTo1 AS DATETIME
DECLARE @DTFrom2 AS DATETIME,@DTTo2 AS DATETIME
DECLARE @DTFrom3 AS DATETIME,@DTTo3 AS DATETIME
DECLARE @DTFrom4 AS DATETIME,@DTTo4 AS DATETIME
DECLARE @DTFrom5 AS DATETIME,@DTTo5 AS DATETIME
DECLARE @DTFrom6 AS DATETIME,@DTTo6 AS DATETIME
DECLARE @DTFrom7 AS DATETIME,@DTTo7 AS DATETIME
DECLARE @DTFrom8 AS DATETIME,@DTTo8 AS DATETIME
DECLARE @DTFrom9 AS DATETIME,@DTTo9 AS DATETIME
DECLARE @DTFrom10 AS DATETIME,@DTTo10 AS DATETIME
DECLARE @DTFrom11 AS DATETIME,@DTTo11 AS DATETIME
DECLARE @DTFrom12 AS DATETIME,@DTTo12 AS DATETIME

SET @DTFrom1=@DTFrom;SET @DTFrom2=DateAdd(m,1,@DTFrom);SET @DTFrom3=DateAdd(m,2,@DTFrom);SET @DTFrom4=DateAdd(m,3,@DTFrom)
SET @DTFrom5=DateAdd(m,4,@DTFrom);SET @DTFrom6=DateAdd(m,5,@DTFrom);SET @DTFrom7=DateAdd(m,6,@DTFrom);SET @DTFrom8=DateAdd(m,7,@DTFrom)
SET @DTFrom9=DateAdd(m,8,@DTFrom);SET @DTFrom10=DateAdd(m,9,@DTFrom);SET @DTFrom11=DateAdd(m,10,@DTFrom);SET @DTFrom12=DateAdd(m,11,@DTFrom)

SET @DTTo1=DateAdd(d,-1,DateAdd(m,1,@DTFrom1));SET @DTTo2=DateAdd(d,-1,DateAdd(m,1,@DTFrom2));SET @DTTo3=DateAdd(d,-1,DateAdd(m,1,@DTFrom3))
SET @DTTo4=DateAdd(d,-1,DateAdd(m,1,@DTFrom4));SET @DTTo5=DateAdd(d,-1,DateAdd(m,1,@DTFrom5));SET @DTTo6=DateAdd(d,-1,DateAdd(m,1,@DTFrom6))
SET @DTTo7=DateAdd(d,-1,DateAdd(m,1,@DTFrom7));SET @DTTo8=DateAdd(d,-1,DateAdd(m,1,@DTFrom8));SET @DTTo9=DateAdd(d,-1,DateAdd(m,1,@DTFrom9))
SET @DTTo10=DateAdd(d,-1,DateAdd(m,1,@DTFrom10));SET @DTTo11=DateAdd(d,-1,DateAdd(m,1,@DTFrom11));SET @DTTo12=DateAdd(d,-1,DateAdd(m,1,@DTFrom12))

DECLARE @myReturnTBL TABLE(EmpID VARCHAR(50),Month1TD REAL,Month2TD REAL,Month3TD REAL,Month4TD REAL,Month5TD REAL,Month6TD REAL,Month7TD REAL,Month8TD REAL,Month9TD REAL,Month10TD REAL,Month11TD REAL,Month12TD REAL
											,Month1P REAL,Month2P REAL,Month3P REAL,Month4P REAL,Month5P REAL,Month6P REAL,Month7P REAL,Month8P REAL,Month9P REAL,Month10P REAL,Month11P REAL,Month12P REAL
											,Month1L REAL,Month2L REAL,Month3L REAL,Month4L REAL,Month5L REAL,Month6L REAL,Month7L REAL,Month8L REAL,Month9L REAL,Month10L REAL,Month11L REAL,Month12L REAL
											,Month1S REAL,Month2S REAL,Month3S REAL,Month4S REAL,Month5S REAL,Month6S REAL,Month7S REAL,Month8S REAL,Month9S REAL,Month10S REAL,Month11S REAL,Month12S REAL
											,Month1A REAL,Month2A REAL,Month3A REAL,Month4A REAL,Month5A REAL,Month6A REAL,Month7A REAL,Month8A REAL,Month9A REAL,Month10A REAL,Month11A REAL,Month12A REAL
											)

INSERT INTO @myReturnTBL (EmpID) SELECT DISTINCT EmpID FROM MonthlySalaries WHERE DT BETWEEN @DTFrom AND @DTTo

UPDATE @myReturnTBL SET Month1TD=TCalc.TotalDays,Month1P=TotalPresents,Month1L=TotalLeaves,Month1S=ISNULL(TotalLeaves,0)+ISNULL(TotalPresents,0)
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,Day(DT) AS TotalDays,PresentDays AS TotalPresents,LeaveDays AS TotalLeaves FROM MonthlySalaries WHERE DT BETWEEN @DTFrom1 AND @DTTo1) TCalc  ON myReturnTBL.EmpID=TCalc.EmpID

UPDATE @myReturnTBL SET Month2TD=TCalc.TotalDays,Month2P=TotalPresents,Month2L=TotalLeaves,Month2S=ISNULL(TotalLeaves,0)+ISNULL(TotalPresents,0)
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,Day(DT) AS TotalDays,PresentDays AS TotalPresents,LeaveDays AS TotalLeaves FROM MonthlySalaries WHERE DT BETWEEN @DTFrom2 AND @DTTo2) TCalc  ON myReturnTBL.EmpID=TCalc.EmpID

UPDATE @myReturnTBL SET Month3TD=TCalc.TotalDays,Month3P=TotalPresents,Month3L=TotalLeaves,Month3S=ISNULL(TotalLeaves,0)+ISNULL(TotalPresents,0)
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,Day(DT) AS TotalDays,PresentDays AS TotalPresents,LeaveDays AS TotalLeaves FROM MonthlySalaries WHERE DT BETWEEN @DTFrom3 AND @DTTo3) TCalc  ON myReturnTBL.EmpID=TCalc.EmpID

UPDATE @myReturnTBL SET Month4TD=TCalc.TotalDays,Month4P=TotalPresents,Month4L=TotalLeaves,Month4S=ISNULL(TotalLeaves,0)+ISNULL(TotalPresents,0)
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,Day(DT) AS TotalDays,PresentDays AS TotalPresents,LeaveDays AS TotalLeaves FROM MonthlySalaries WHERE DT BETWEEN @DTFrom4 AND @DTTo4) TCalc  ON myReturnTBL.EmpID=TCalc.EmpID

UPDATE @myReturnTBL SET Month5TD=TCalc.TotalDays,Month5P=TotalPresents,Month5L=TotalLeaves,Month5S=ISNULL(TotalLeaves,0)+ISNULL(TotalPresents,0)
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,Day(DT) AS TotalDays,PresentDays AS TotalPresents,LeaveDays AS TotalLeaves FROM MonthlySalaries WHERE DT BETWEEN @DTFrom5 AND @DTTo5) TCalc  ON myReturnTBL.EmpID=TCalc.EmpID

UPDATE @myReturnTBL SET Month6TD=TCalc.TotalDays,Month6P=TotalPresents,Month6L=TotalLeaves,Month6S=ISNULL(TotalLeaves,0)+ISNULL(TotalPresents,0)
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,Day(DT) AS TotalDays,PresentDays AS TotalPresents,LeaveDays AS TotalLeaves FROM MonthlySalaries WHERE DT BETWEEN @DTFrom6 AND @DTTo6) TCalc  ON myReturnTBL.EmpID=TCalc.EmpID

UPDATE @myReturnTBL SET Month7TD=TCalc.TotalDays,Month7P=TotalPresents,Month7L=TotalLeaves,Month7S=ISNULL(TotalLeaves,0)+ISNULL(TotalPresents,0)
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,Day(DT) AS TotalDays,PresentDays AS TotalPresents,LeaveDays AS TotalLeaves FROM MonthlySalaries WHERE DT BETWEEN @DTFrom7 AND @DTTo7) TCalc  ON myReturnTBL.EmpID=TCalc.EmpID

UPDATE @myReturnTBL SET Month8TD=TCalc.TotalDays,Month8P=TotalPresents,Month8L=TotalLeaves,Month8S=ISNULL(TotalLeaves,0)+ISNULL(TotalPresents,0)
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,Day(DT) AS TotalDays,PresentDays AS TotalPresents,LeaveDays AS TotalLeaves FROM MonthlySalaries WHERE DT BETWEEN @DTFrom8 AND @DTTo8) TCalc  ON myReturnTBL.EmpID=TCalc.EmpID

UPDATE @myReturnTBL SET Month9TD=TCalc.TotalDays,Month9P=TotalPresents,Month9L=TotalLeaves,Month9S=ISNULL(TotalLeaves,0)+ISNULL(TotalPresents,0)
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,Day(DT) AS TotalDays,PresentDays AS TotalPresents,LeaveDays AS TotalLeaves FROM MonthlySalaries WHERE DT BETWEEN @DTFrom9 AND @DTTo9) TCalc  ON myReturnTBL.EmpID=TCalc.EmpID

UPDATE @myReturnTBL SET Month10TD=TCalc.TotalDays,Month10P=TotalPresents,Month10L=TotalLeaves,Month10S=ISNULL(TotalLeaves,0)+ISNULL(TotalPresents,0)
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,Day(DT) AS TotalDays,PresentDays AS TotalPresents,LeaveDays AS TotalLeaves FROM MonthlySalaries WHERE DT BETWEEN @DTFrom10 AND @DTTo10) TCalc  ON myReturnTBL.EmpID=TCalc.EmpID

UPDATE @myReturnTBL SET Month11TD=TCalc.TotalDays,Month11P=TotalPresents,Month11L=TotalLeaves,Month11S=ISNULL(TotalLeaves,0)+ISNULL(TotalPresents,0)
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,Day(DT) AS TotalDays,PresentDays AS TotalPresents,LeaveDays AS TotalLeaves FROM MonthlySalaries WHERE DT BETWEEN @DTFrom11 AND @DTTo11) TCalc  ON myReturnTBL.EmpID=TCalc.EmpID

UPDATE @myReturnTBL SET Month12TD=TCalc.TotalDays,Month12P=TotalPresents,Month12L=TotalLeaves,Month12S=ISNULL(TotalLeaves,0)+ISNULL(TotalPresents,0)
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,Day(DT) AS TotalDays,PresentDays AS TotalPresents,LeaveDays AS TotalLeaves FROM MonthlySalaries WHERE DT BETWEEN @DTFrom12 AND @DTTo12) TCalc  ON myReturnTBL.EmpID=TCalc.EmpID

--We can add Salaries of each month from monthly salaries to get the exact rates here...

UPDATE @myReturnTBL SET Month1A=Month1TD-Month1S,Month2A=Month2TD-Month2S,Month3A=Month3TD-Month3S,Month4A=Month4TD-Month4S
						,Month5A=Month5TD-Month5S,Month6A=Month6TD-Month6S,Month7A=Month7TD-Month7S,Month8A=Month8TD-Month8S
						,Month9A=Month9TD-Month9S,Month10A=Month10TD-Month10S,Month11A=Month11TD-Month11S,Month12A=Month12TD-Month12S

SELECT VEmp.Name,Rel,FName,JoinDate,VEmp.DeptID,DeptName,StartingSalary,myReturnTBL.*

	FROM VEmp
	INNER JOIN @myReturnTBL myReturnTBL ON VEmp.EmpID=myReturnTBL.EmpID
GO
