CREATE PROCEDURE [dbo].[ExportPreformanceReport_SP] (@DTFrom AS DATETIME,@DTTo AS DATETIME,@ItemGroup AS INT=0,@CatID AS VARCHAR(50)='',@AdditionalGroup AS INT=0,@Customers AS VARCHAR(50)='') AS

BEGIN

SET ANSI_WARNINGS OFF

SET @DTFrom=CAST(CONVERT(VARCHAR(50),@DTFrom,6) AS DATETIME)
SET @DTTo=CAST(CONVERT(VARCHAR(50),@DTTo,6) AS DATETIME)

CREATE TABLE #myTBL (ItemID VARCHAR(255),Qty INT,Hits INT,Stock INT)

INSERT INTO #myTBL(ItemID,Qty,Hits)
	SELECT CompItemCode,SUM(CustomInvoiceItems.Qty),COUNT(CustomInvoiceItems.RefID) FROM CustomInvoiceItems INNER JOIN CustomInvoice ON CustomInvoice.CustomInvoice=CustomInvoiceItems.CustomInvoice
		INNER JOIN FProformaOrders ON CustomInvoiceItems.RefID=FProformaOrders.EntryID INNER JOIN FOrderItems ON FProformaOrders.OrderEntryID=FOrderItems.ID
		WHERE DT BETWEEN @DTFrom AND @DTTo AND (CustCode=@Customers OR @Customers='')
		GROUP BY CompItemCode

IF @ItemGroup<>0
	DELETE FROM #myTBL WHERE ItemID NOT IN(SELECT ItemID FROM Items WHERE GroupID=@ItemGroup)

IF @CatID<>''
	DELETE FROM #myTBL WHERE ItemID NOT IN(SELECT ItemID FROM Items WHERE CatID=@CatID)

IF @AdditionalGroup<>0
	DELETE FROM #myTBL WHERE ItemID NOT IN(SELECT ItemID FROM Items WHERE MainGroupID=@AdditionalGroup)


UPDATE #myTBL SET Stock=T1.NetQty FROM #myTBL INNER JOIN (SELECT ItemID,SUM(NetQty) AS NetQty FROM VItemsWithLocationwiseStock GROUP  BY ItemID) T1 ON #myTBL.ItemID=T1.ItemID

SELECT VItems.ItemID,Vitems.ItemName,Category,MainGroupName,ItemGroup,Qty,Stock,Hits FROM #myTBL INNER JOIN VItems ON #myTBL.ItemID=VItems.ItemID
SET ANSI_WARNINGS ON

END
GO
