-- =============================================
-- Author:		<Asim Arif>
-- Create date: <31-10-12>
-- Description:	<Budget vs. Actual>
-- =============================================
CREATE PROCEDURE [dbo].[FinancialBudgeting_SP](@DT AS DATETIME)

AS
BEGIN

	SET NOCOUNT ON;
	CREATE TABLE #myTBL (AccGroup_RefID VARCHAR(255),CurrentMonthActualAmt INT,PrevMonthActualAmt INT,CurrentMonthBudgetAmt INT,PrevMonthBudgetAmt INT)

	DECLARE @myUpdateQry AS VARCHAR(1000)

	DECLARE @DTPrev AS DATETIME
	SET @DTPrev=DATEADD(m,-1,@DT)
	INSERT INTO #myTBL(AccGroup_RefID) SELECT EntryID FROM GroupsForExpenseReport

	SET @myUpdateQry='UPDATE #myTBL SET CurrentMonthActualAmt=Value FROM #myTBL myTBL INNER JOIN (SELECT AccGroup_RefID,SUM(Debit-Credit) AS Value FROM AccountGroupsForExpenseReport INNER JOIN Vouchers ON Vouchers.AccNo=AccountGroupsForExpenseReport.AccNo WHERE MONTH(VDate)=' + CAST(MONTH(@DT) AS VARCHAR(50)) + ' AND YEAR(VDate)=' + CAST(YEAR(@DT) AS VARCHAR(50)) + ' GROUP BY AccGroup_RefID) TInner ON myTBL.AccGroup_RefID=TInner.AccGroup_RefID'
	EXEC(@myUpdateQry)

	SET @myUpdateQry='UPDATE #myTBL SET PrevMonthActualAmt=Value FROM #myTBL myTBL INNER JOIN (SELECT AccGroup_RefID,SUM(Debit-Credit) AS Value FROM AccountGroupsForExpenseReport INNER JOIN Vouchers ON Vouchers.AccNo=AccountGroupsForExpenseReport.AccNo WHERE MONTH(VDate)=' + CAST(MONTH(@DTPrev) AS VARCHAR(50)) + ' AND YEAR(VDate)=' + CAST(YEAR(@DTPrev) AS VARCHAR(50)) + ' GROUP BY AccGroup_RefID) TInner ON myTBL.AccGroup_RefID=TInner.AccGroup_RefID'
	EXEC(@myUpdateQry)

	DECLARE @Month AS INT,@YEAR AS INT,@FinYear AS VARCHAR(255)
	DECLARE @PrevMonth AS INT,@PrevYEAR AS INT,@PrevFinYear AS VARCHAR(255)

	SET @Month=MONTH(@DT)
	SET @YEAR=YEAR(@DT)

	SET @PrevMonth=MONTH(@DTPrev)
	SET @PrevYEAR=YEAR(@DTPrev)

	IF @Month>6
		SET @FinYear=CAST(@YEAR AS VARCHAR(10)) + ' - ' + CAST((@YEAR+1) AS VARCHAR(10))
	ELSE
		SET @FinYear=CAST((@YEAR-1) AS VARCHAR(10)) + ' - ' + CAST((@YEAR) AS VARCHAR(10))

	IF @PrevMonth>6
		SET @PrevFinYear=CAST(@PrevYEAR AS VARCHAR(10)) + ' - ' + CAST((@PrevYEAR+1) AS VARCHAR(10))
	ELSE
		SET @PrevFinYear=CAST((@PrevYEAR-1) AS VARCHAR(10)) + ' - ' + CAST((@PrevYEAR) AS VARCHAR(10))

	DECLARE @MonthField AS VARCHAR(50),@PrevMonthField AS VARCHAR(50)
	IF @Month=1
		BEGIN
			SET @MonthField='Month_January'
			SET @PrevMonthField='Month_December'
		END
	ELSE IF @Month=2
		BEGIN
			SET @MonthField='Month_February'
			SET @PrevMonthField='Month_January'
		END
	ELSE IF @Month=3
		BEGIN
			SET @MonthField='Month_March'
			SET @PrevMonthField='Month_February'
		END
	ELSE IF @Month=4
		BEGIN
			SET @MonthField='Month_April'
			SET @PrevMonthField='Month_March'
		END
	ELSE IF @Month=5
		BEGIN
			SET @MonthField='Month_May'
			SET @PrevMonthField='Month_April'
		END
	ELSE IF @Month=6
		BEGIN
			SET @MonthField='Month_June'
			SET @PrevMonthField='Month_May'
		END
	ELSE IF @Month=7
		BEGIN
			SET @MonthField='Month_July'
			SET @PrevMonthField='Month_June'
		END
	ELSE IF @Month=8
		BEGIN
			SET @MonthField='Month_August'
			SET @PrevMonthField='Month_July'
		END
	ELSE IF @Month=9
		BEGIN
			SET @MonthField='Month_September'
			SET @PrevMonthField='Month_August'
		END
	ELSE IF @Month=10
		BEGIN
			SET @MonthField='Month_October'
			SET @PrevMonthField='Month_September'
		END
	ELSE IF @Month=11
		BEGIN
			SET @MonthField='Month_November'
			SET @PrevMonthField='Month_October'
		END
	ELSE IF @Month=12
		BEGIN
			SET @MonthField='Month_December'
			SET @PrevMonthField='Month_November'
		END


	SET @myUpdateQry='UPDATE #myTBL SET CurrentMonthBudgetAmt='+@MonthField+' FROM #myTBL myTBL INNER JOIN FinancialBudgeting_GroupWise ON FinancialBudgeting_GroupWise.GFER_RefID=myTBL.AccGroup_RefID WHERE FinancialBudgeting_GroupWise.FinancialYear=''' + @FinYear + ''''
	EXEC(@myUpdateQry)

	SET @myUpdateQry='UPDATE #myTBL SET PrevMonthBudgetAmt='+@PrevMonthField+' FROM #myTBL myTBL INNER JOIN FinancialBudgeting_GroupWise ON FinancialBudgeting_GroupWise.GFER_RefID=myTBL.AccGroup_RefID WHERE FinancialBudgeting_GroupWise.FinancialYear=''' + @PrevFinYear + ''''
	EXEC(@myUpdateQry)
	--SELECT @FinYear,@PrevFinYear,@DT,@DTPrev
END

SELECT #myTBL.*,GroupName FROM #myTBL INNER JOIN GroupsForExpenseReport ON #myTBL.AccGroup_RefID=GroupsForExpenseReport.EntryID
	ORDER BY GroupsForExpenseReport.EntryID


GO
