CREATE PROCEDURE [dbo].[FinishItemLedger_SP](@ItemID AS VARCHAR(255),@DTFrom AS DATETIME,@DTTo AS DATETIME) AS

BEGIN

	DECLARE @OpeningBalance AS INT,@TotalRcvd AS INT,@TotalIssd AS INT

	SELECT @TotalRcvd=SUM(Qty) FROM RcvItemsSimple INNER JOIN RcvItemsSimpleDetail ON RcvItemsSimple.RcvNo=RcvItemsSimpleDetail.RcvNo WHERE ItemID=@ItemID AND DT<@DTFrom
	SELECT @TotalIssd=SUM(Qty) FROM IssItemsSimple INNER JOIN IssItemsSimpleDetail ON IssItemsSimple.IssNo=IssItemsSimpleDetail.IssNo WHERE ItemID=@ItemID AND DT<@DTFrom

	SET @OpeningBalance=ISNULL(@TotalRcvd,0)-ISNULL(@TotalIssd,0)

	SELECT T1.*,Items.ItemID,Items.ItemName,CustCode,InternalRefNo,Unit,@OpeningBalance AS OpeningBalance
	,VStoreShelfs.StoreName + '(' + VStoreShelfs.RackNo + ') (' + VStoreShelfs.ShelfNo + ')' AS Location
	,Lots_List.Lot_Remarks,Items.ItemPic
	FROM Items
	LEFT OUTER JOIN(
	SELECT CAST(CONVERT(VARCHAR(50),DT,6) AS DATETIME) AS DT,RcvItemsSimple.RcvNo,RcvdBy,RcvdFrom,RcvItemsSimpleDetail_Placement.RcvdQty AS QtyIn,0 AS QtyOut,1 AS EntryType,RcvItemsSimpleDetail.Remarks,RcvItemsSimpleDetail.OrderNo,LotNo_Manual,BatchNo_Manual,Shelf_RefID FROM RcvItemsSimple
		INNER JOIN RcvItemsSimpleDetail ON RcvItemsSimple.RcvNo=RcvItemsSimpleDetail.RcvNo
		INNER JOIN RcvItemsSimpleDetail_Placement ON RcvItemsSimpleDetail.EntryID=RcvItemsSimpleDetail_Placement.RISD_RefID


		WHERE CAST(CONVERT(VARCHAR(50),DT,6) AS DATETIME) BETWEEN @DTFrom AND @DTTo AND ItemID=@ItemID

	UNION ALL

	SELECT CAST(CONVERT(VARCHAR(50),DT,6) AS DATETIME) AS DT,IssItemsSimple.IssNo,AttnPerson,Department,0 AS QtyIn,
	IssItemsSimpleDetail_More.IssdQty AS QtyOut,0 AS EntryType,IssItemsSimpleDetail.Remarks,IssItemsSimpleDetail.OrderNo,LotNo_Manual,BatchNo_Manual,Shelf_RefID FROM IssItemsSimple
		INNER JOIN IssItemsSimpleDetail ON IssItemsSimple.IssNo=IssItemsSimpleDetail.IssNo
		INNER JOIN IssItemsSimpleDetail_More ON IssItemsSimpleDetail.EntryID=IssItemsSimpleDetail_More.IISD_RefID
		WHERE CAST(CONVERT(VARCHAR(50),DT,6) AS DATETIME) BETWEEN @DTFrom AND @DTTo AND ItemID=@ItemID) T1 ON Items.ItemID=@ItemID

	LEFT OUTER JOIN VStoreShelfs ON T1.Shelf_RefID=VStoreShelfs.EntryID
	LEFT OUTER JOIN FCustomerOrders ON T1.OrderNo=FCustomerOrders.OrderNo
	LEFT OUTER JOIN Lots_List ON T1.LotNo_Manual=Lots_List.LotNo
	WHERE Items.ItemID=@ItemID ORDER BY T1.DT,EntryType DESC

END
GO
/****** Object:  StoredProcedure [dbo].[GetAllTableSizes]    Script Date: 6/29/2026 4:50:02 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[GetAllTableSizes]
AS
/*
    Obtains spaced used data for ALL user tables in the database
*/
DECLARE @TableName VARCHAR(100)    --For storing values in the cursor

--Cursor to get the name of all user tables from the sysobjects listing
DECLARE tableCursor CURSOR
FOR
select [name]
from dbo.sysobjects
where  OBJECTPROPERTY(id, N'IsUserTable') = 1
FOR READ ONLY

--A procedure level temp table to store the results
CREATE TABLE #TempTable
(
    tableName varchar(100),
    numberofRows varchar(100),
    reservedSize varchar(50),
    dataSize varchar(50),
    indexSize varchar(50),
    unusedSize varchar(50)
)

--Open the cursor
OPEN tableCursor

--Get the first table name from the cursor
FETCH NEXT FROM tableCursor INTO @TableName

--Loop until the cursor was not able to fetch
WHILE (@@Fetch_Status >= 0)
BEGIN
    --Dump the results of the sp_spaceused query to the temp table
    INSERT  #TempTable
        EXEC sp_spaceused @TableName

    --Get the next table name
    FETCH NEXT FROM tableCursor INTO @TableName
END

--Get rid of the cursor
CLOSE tableCursor
DEALLOCATE tableCursor

--Select all records so we can use the reults
SELECT *
FROM #TempTable

--Final cleanup!
DROP TABLE #TempTable

GO
