CREATE PROCEDURE [dbo].[GetLeaveBalances] (@EmpID AS Varchar(50),@DT As DateTime) As


Declare @FinalDT As DateTime
Set @FinalDT=DateAdd(m,1,@DT)

Declare @StartDT As SmallDateTime

/*IF Month(@DT)<7
	Set @StartDT='7/1/' + Cast(Year(@DT)-1 As Varchar)
Else
	Set @StartDT='7/1/' + Cast(Year(@DT) As Varchar)*/
SET @StartDT='1/1/' + Cast(Year(@DT) As Varchar)

Begin


	SELECT Employees.EmpID,CL_E,SL_E,AL_E,CPL_E,LWP_E,ML_E,SAL_E,HL_E,CL,SL,AL,CPL,LWP,ML,SAL,HL FROM Employees LEFT OUTER JOIN
		(SELECT EmpID,SUM(ISNULL(CASE WHEN CL=1 THEN 1 ELSE 0 END,0)) AS CL_E,Sum(IsNull(SL,0)) As SL_E,Sum(Isnull(AL,0)) As AL_E,Sum(IsNull(CPL,0)) As CPL_E,Sum(IsNull(LWP,0)) As LWP_E,Sum(IsNull(ML,0)) As ML_E,Sum(IsNull(SAL,0)) As SAL_E,SUM(ISNULL(CASE WHEN CL=0.5 THEN 1 ELSE 0 END,0)) AS HL_E From Leaves
		WHERE EmpID=@EmpID AND DT<@DT AND (DT Between @StartDT AND @DT) AND NOT (Month(DT)=Month(@DT) AND Year(DT)=Year(@DT))  Group By EmpID) Tab1 ON Employees.EmpID=Tab1.EmpID LEFT OUTER JOIN
		(Select EmpID,Sum(IsNull(CASE WHEN CL=1 THEN 1 ELSE 0 END,0)) As CL,Sum(IsNull(SL,0)) As SL,Sum(Isnull(AL,0)) As AL,Sum(IsNull(CPL,0)) As CPL,Sum(IsNull(LWP,0)) As LWP,Sum(IsNull(ML,0)) As ML,Sum(IsNull(SAL,0)) As SAL,SUM(ISNULL(CASE WHEN CL=0.5 THEN 1 ELSE 0 END,0)) AS HL From Leaves
		Where EmpID=@EmpID AND Month(DT)=Month(@DT) AND Year(DT)=Year(@DT) Group By EmpID) Tab2 ON Employees.EmpID=Tab2.EmpID WHERE Employees.EmpID=@EmpID



End



GO
