-- =============================================
-- Author:		<Asim Arif (AWM Systems)>
-- Create date: <21-Sep-2011>
-- Description:	<Income Statement>
-- =============================================
CREATE PROCEDURE [dbo].[IncomeStatement_SP]
	-- Add the parameters for the stored procedure here
	(@DTFrom AS DATETIME,@DTTo AS DATETIME)
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	SELECT Accounts.AccNo,Accounts.AccTitle,Amount,Head,Accounts.SubAccOf,Accounts.Parent,Code,AccSub.AccTitle AS SubAccTitle FROM Accounts
		INNER JOIN Heads ON Accounts.Type=Heads.Code
		LEFT OUTER JOIN Accounts AccSub ON Accounts.SubAccOf=AccSub.AccNo
		INNER JOIN (SELECT AccNo,SUM(CASE WHEN LEFT(AccNo,1)='3' THEN (Credit-Debit) ELSE (Debit-Credit) END) AS Amount FROM Vouchers
			WHERE VDate BETWEEN @DTFrom AND @DTTo AND LEFT(AccNo,2) IN('31','32','33','41','42','43','44','46') GROUP BY AccNo) T1 ON Accounts.AccNo=T1.AccNo
		WHERE LEFT(Accounts.AccNo,2) IN('31','32','33','41','42','43','44','46')
END

GO
