CREATE PROCEDURE [dbo].[IPOLotsPrinting_SP](@IPONo INT)
AS
BEGIN

CREATE TABLE #myTBL (RowNo CHAR(1),Lot1 INT,Lot2 INT,Lot3 INT,Lot4 INT,Lot5 INT,Lot6 INT,Lot7 INT,Lot8 INT,Lot9 INT,Lot10 INT,Lot11 INT,Lot12 INT,Lot13 INT,Lot14 INT,Lot15 INT,Lot16 INT,Lot17 INT,Lot18 INT,Lot19 INT,Lot20 INT,Lot21 INT,Lot22 INT,Lot23 INT,Lot24 INT,Lot25 INT,Lot26 INT,Lot27 INT,Lot28 INT,Lot29 INT,Lot30 INT)

DECLARE Cursor_Lots CURSOR FOR SELECT TOP 30 CompItemCode,IPOD_RefID,LotQty FROM InternalProductionOrderDetailLots INNER JOIN InternalProductionOrderDetail
	ON InternalProductionOrderDetailLots.IPOD_RefID=InternalProductionOrderDetail.EntryID INNER JOIN InternalProductionOrder ON InternalProductionOrder.EntryID=InternalProductionOrderDetail .RefID
	WHERE IPONo=@IPONo
	ORDER BY IPOD_RefID

OPEN Cursor_Lots

DECLARE @ItemID AS VARCHAR(255),@RefID AS INT,@LotQty AS INT,@RowNo AS INT,@PrevItemID AS VARCHAR(255),@ColNo AS INT
FETCH NEXT FROM Cursor_Lots INTO @ItemID,@RefID,@LotQty
DECLARE @myInsertSQL AS VARCHAR(1000)
DECLARE @myUpdateSQL AS VARCHAR(1000)
SET @RowNo=0
WHILE @@FETCH_STATUS=0
	BEGIN
		IF @ItemID<>@PrevItemID
			BEGIN
				IF @RowNo=0
					SET @RowNo=65
				ELSE
					BEGIN
						SET @RowNo=@RowNo+1
					END
				--SET @myInsertSQL='INSERT INTO #myTBL(RowNo) VALUES(''' + CHAR(@RowNo)  + '' + ')'
				INSERT INTO #myTBL(RowNo) VALUES(CHAR(@RowNo))
				SET @ColNo=1
			END
		ELSE
			BEGIN
				SET @ColNo=@ColNo+1
			END
		--SET @myInsertSQL='UPDATE #myTBL SET Date' + CAST(Day(@TempDT) AS VARCHAR(2)) +'=T1.InTime + CHAR(13) + T1.OutTime FROM #myTBL myTBL INNER JOIN (SELECT EmpID,MIN(InTime) AS InTime,MAX(OutTime) AS OutTime FROM EmpTimes WHERE DT=''' + CONVERT(VARCHAR(50),@TempDT,6) +  ''' GROUP BY EmpID) T1 ON myTBL.EmpID=T1.EmpID'

		SET @myUpdateSQL='UPDATE #myTBL SET Lot' + CAST(@ColNo AS VARCHAR(2)) + '=' + CAST(@LotQty AS VARCHAR(50)) + ' WHERE RowNo=''' + CHAR(@RowNo) + ''''
		--SELECT @LotQty,@ColNo,@myUpdateSQL
		EXEC(@myUpdateSQL)	--Execute Previous Update SQL
		SET @PrevItemID=@ItemID
		FETCH NEXT FROM Cursor_Lots INTO @ItemID,@RefID,@LotQty
	END

	CLOSE Cursor_Lots
	DEALLOCATE Cursor_Lots

	SELECT * FROM #myTBL
END
GO
