CREATE PROCEDURE [dbo].[IPOLotsReceiving_SP] (@ItemCode AS VARCHAR(50),@ProcessID AS INT) AS

DECLARE @ProcessSNo AS INT
SELECT @ProcessSNo=ItemSNo FROM VItemProcesses WHERE IsExist=@ItemCode AND ProcessID=@ProcessID
DECLARE @ScanProcessSNo AS INT,@NextToScanProcessSNo AS INT,@SNoToUse AS INT

SELECT @ScanProcessSNo=MIN(ItemSNo) FROM VItemProcesses WHERE IsExist=@ItemCode AND Scanning=1 AND ItemSNo>@ProcessSNo

SELECT @NextToScanProcessSNo=MIN(ItemSNo) FROM VItemProcesses WHERE IsExist=@ItemCode AND ItemSNo>@ScanProcessSNo

IF @NextToScanProcessSNo IS NULL
	SET @SNoToUse=@ScanProcessSNo
ELSE
	SET @SNoToUse=@NextToScanProcessSNo

SELECT Description,VenderName,VendAssItems.Rate,Makers.VendID,VItemProcesses.ProcessID,Operation,@NextToScanProcessSNo AS NextToProcessSNo,ItemSNo,@ScanProcessSNo AS ScanProcessSNo,InspectionProcess,Code FROM VItemProcesses
	LEFT OUTER JOIN Makers ON VItemProcesses.Fix_Maker_RefID=Makers.VendID
	LEFT OUTER JOIN VendAssItems ON VItemProcesses.Fix_Maker_RefID=VendAssItems.VendID AND VItemProcesses.IsExist=VendAssItems.ItemID --AND VItemProcesses.ProcessID=VendAssItems.ProcessID
	WHERE (ItemSNo>=@ProcessSNo AND (ItemSNo<=@SNoToUse OR @SNoToUse IS NULL)) AND IsExist=@ItemCode
	ORDER BY ItemSNo
GO
