CREATE PROCEDURE [dbo].[IssueItems_SP] (@ProcessID as Int=NULL,@ItemID AS VARCHAR(50)) AS

DECLARE @InitProcessID AS INT
SET @InitProcessID=(SELECT TOP 1 InitialProcessID FROM VItemProcessesExt WHERE IsExist=@ItemID)
/*
DECLARE @ReadyFinishProcessID AS INT,@SemiFinishProcessID AS INT,@FilingProcessID AS INT,@Filing2ProcessID AS INT
DECLARE @MakerPOProcess_I AS INT,@MakerPOProcess_II AS INT,@MakerPOProcess_III AS INT,@MakerPOProcess_IV AS INT,@MakerPOProcess_V AS INT
DECLARE @MakerPOProcess_VI AS INT,@MakerPOProcess_VII AS INT,@MakerPOProcess_VIII AS INT

SET @ReadyFinishProcessID=CAST(dbo.GetGeneralDataValue_F('ReadyFinishProcessID') AS INT)
SET @SemiFinishProcessID=CAST(dbo.GetGeneralDataValue_F('SemiFinishProcessID') AS INT)
SET @FilingProcessID=CAST(dbo.GetGeneralDataValue_F('FilingProcessID') AS INT)
SET @Filing2ProcessID=CAST(dbo.GetGeneralDataValue_F('Filing2ProcessID') AS INT)
SET @MakerPOProcess_I=CAST(dbo.GetGeneralDataValue_F('Maker_PO_Process_I') AS INT)
SET @MakerPOProcess_II=CAST(dbo.GetGeneralDataValue_F('Maker_PO_Process_II') AS INT)
SET @MakerPOProcess_III=CAST(dbo.GetGeneralDataValue_F('Maker_PO_Process_III') AS INT)
SET @MakerPOProcess_IV=CAST(dbo.GetGeneralDataValue_F('Maker_PO_Process_IV') AS INT)
SET @MakerPOProcess_V=CAST(dbo.GetGeneralDataValue_F('Maker_PO_Process_V') AS INT)

SET @MakerPOProcess_VI=CAST(dbo.GetGeneralDataValue_F('Maker_PO_Process_VI') AS INT)
SET @MakerPOProcess_VII=CAST(dbo.GetGeneralDataValue_F('Maker_PO_Process_VII') AS INT)
SET @MakerPOProcess_VIII=CAST(dbo.GetGeneralDataValue_F('Maker_PO_Process_VIII') AS INT)
*/
--IF @InitProcessID=@ProcessID OR @ProcessID IN(@ReadyFinishProcessID,@SemiFinishProcessID,@FilingProcessID,@Filing2ProcessID,@MakerPOProcess_I,@MakerPOProcess_II,@MakerPOProcess_III,@MakerPOProcess_IV,@MakerPOProcess_V,@MakerPOProcess_VI,@MakerPOProcess_VII,@MakerPOProcess_VIII)
IF @InitProcessID=@ProcessID OR @ProcessID IN(SELECT ProcessID FROM Processes_Purchase)

SELECT TOP 100 PERCENT @ProcessID AS ProcessID,VrptOrders.OrderNo,VrptOrders.ItemID,VrptOrders.Qty As OrderQty,F_Test.IssQty,VItemProcessesExt.InitialProcessID,VrptOrders.CompItemID,VrptOrders.ItemName,TabIssd.TotIssdProc
,VStockOrderAdjustments.Qty AS AdjustedQty,InternalRefNo
FROM VrptOrders_ForProduction VrptOrders
INNER JOIN VItemProcessesExt ON VrptOrders.CompItemID=VItemProcessesExt.IsExist AND VItemProcessesExt.ProcessID=@ProcessID
LEFT OUTER JOIN
dbo.F_Test(@ProcessID,@ItemID) F_Test ON VrptOrders.CompItemID=F_Test.ItemCode AND VrptOrders.OrderNo=F_Test.OrderNo
LEFT OUTER JOIN (SELECT OrderNo,SUM(CASE WHEN Closed=1 THEN RcvdQty ELSE IssQty END) AS TotIssdProc FROM VVendIssddetail WHERE ProcessID=@ProcessID AND ItemCode=@ItemID GROUP BY OrderNo) TabIssd ON VrptOrders.OrderNo=TabIssd.OrderNo
LEFT OUTER JOIN VStockOrderAdjustments ON VrptOrders.OrderNo=VStockOrderAdjustments.OrderNo AND VrptOrders.CompItemID=VStockOrderAdjustments.ItemID
WHERE VrptOrders.CompItemID=@ItemID AND VItemProcessesExt.ProcessID=@ProcessID AND VItemProcessesExt.IsExist=@ItemID
AND (VrptOrders.Qty-ISNULL(TotIssdProc,0)>0
AND VrptOrders.OrderNo NOT IN('Stock-Order') AND VrptOrders.OrderNo IN(SELECT OrderNo FROM VUnshippedOrderList) AND VrptOrders.Qty>ISNULL(ShippedQty,0))
OR (VrptOrders.OrderNo='Stock-OrderIss' AND VrptOrders.ItemCode=@ItemID)

ELSE

SELECT TOP 100 PERCENT @ProcessID AS ProcessID,VrptOrders.OrderNo,VrptOrders.ItemID,VrptOrders.Qty As OrderQty,F_Test.IssQty,VItemProcessesExt.InitialProcessID,VrptOrders.CompItemID,VrptOrders.ItemName,TabIssd.TotIssdProc
,0 AS AdjustedQty,InternalRefNo
FROM VrptOrders_ForProduction VrptOrders
INNER JOIN VItemProcessesExt ON VrptOrders.CompItemID=VItemProcessesExt.IsExist
LEFT OUTER JOIN
dbo.F_Test(@ProcessID,@ItemID) F_Test ON VrptOrders.CompItemID=F_Test.ItemCode AND VrptOrders.OrderNo=F_Test.OrderNo
LEFT OUTER JOIN (SELECT OrderNo,SUM(IssQty) AS TotIssdProc FROM VVendIssddetail WHERE ProcessID=@ProcessID AND ItemCode=@ItemID GROUP BY OrderNo) TabIssd ON VrptOrders.OrderNo=TabIssd.OrderNo
WHERE VrptOrders.CompItemID=@ItemID AND VItemProcessesExt.ProcessID=@ProcessID AND VItemProcessesExt.IsExist=@ItemID
AND F_Test.IssQty>0
AND VrptOrders.OrderNo NOT IN('Stock-Order') AND VrptOrders.OrderNo IN(SELECT OrderNo FROM VUnshippedOrderList) AND VrptOrders.Qty>ISNULL(ShippedQty,0)



--AND (F_Test.ProcessID = @ProcessID OR F_Test.ProcessID IS NULL) AND (VrptOrders.OrderNo=F_Test.Orderno OR F_Test.OrderNo IS NULL)
		/*SELECT     TOP 100 PERCENT FOrderItems.Qty As OrderQty,F_Test.ItemCode, F_Test.ProcessID, F_Test.IssQty, F_Test.LotNo, dbo.VFOrderItemsProcs.Description,
			dbo.VFOrderItemsProcs.SNO, dbo.VFOrderItemsProcs.ItemDescription, dbo.VFOrderItemsProcs.CompItemCode,LockedItems.ItemCode As LockedItemCode
		FROM         FOrderItems INNER JOIN dbo.F_Test(4,@OrderNo) F_Test ON FOrderItems.ItemCode=F_Test.ItemCode LEFT OUTER JOIN
			dbo.VFOrderItemsProcs ON F_Test.ItemCode = dbo.VFOrderItemsProcs.CompItemCode AND
			F_Test.ProcessID = dbo.VFOrderItemsProcs.ProcessID LEFT OUTER JOIN LockedItems ON F_Test.ItemCode=LockedItems.ItemCode AND F_Test.ProcessID=LockedItems.ProcessID
		WHERE     (F_Test.IssQty > 0) AND (F_Test.ProcessID = @ProcessID)
		ORDER BY F_Test.ProcessID, F_Test.ItemCode*/
GO
