CREATE PROCEDURE [dbo].[ItemDeliveryAnalysis_SP] (@CustCode AS VARCHAR(255)=NULL,@OrderNo AS VARCHAR(255)=NULL,@DTFrom AS DATETIME=NULL,@DTTo AS DATETIME=NULL) AS

BEGIN
SET @DTFrom=CONVERT(VARCHAR(50),@DTFrom,6)
SET @DTTo=CONVERT(VARCHAR(50),@DTTo,6)

SELECT CustCode,OrderNo,CompItemCode,Qty,ShippedQty,DeliveryDT,LastShipmentDate,CASE WHEN  ShippedQty=Qty THEN 1 ELSE 0 END AS Shipped,DATEDIFF(d,DeliveryDT,LastShipmentDate) AS LateDays  FROM VFOrderItemswithShippedQty
	WHERE (CustCode=@CustCode OR @CustCode IS NULL) AND (OrderNo=@OrderNo OR @OrderNo IS NULL)

END
