CREATE PROCEDURE [dbo].[ItemDemandSupply_SP] (@DTFrom AS DATETIME,@DTTo AS DATETIME) AS

DECLARE @myReturnTBL TABLE(ItemID VARCHAR(255),OrderQty INT,ExportQty INT)


INSERT INTO @myReturnTBL(ItemID,OrderQty,ExportQty)
	SELECT ItemID,ISNULL(TOrders.OrderQty,0),ISNULL(TExport.ExportQty,0) FROM Items
	LEFT OUTER JOIN(SELECT CompItemCode,SUM(Qty) AS OrderQty FROM FCustomerOrders INNER JOIN FOrderItems ON FCustomerOrders.OrderNo=FOrderItems.OrderNo WHERE DT BETWEEN @DTFrom AND @DTTo AND OrderType='Customer Order' GROUP BY CompItemCode) TOrders ON Items.ItemID=TOrders.CompItemCode
	LEFT OUTER JOIN(SELECT CompItemCode,SUM(Qty) AS ExportQty FROM VCustomInvoice WHERE DT BETWEEN @DTFrom AND @DTTo GROUP BY CompItemCode) TExport ON Items.ItemID=TExport.CompItemCode

DELETE FROM @myReturnTBL WHERE OrderQty=0 AND ExportQty=0
SELECT myReturnTBL.*,ItemGroups.Description AS MainGroup,MainGroupName AS SubGroupname,ItemName,GroupID,Items.MainGroupID FROM @myReturnTBL myReturnTBL INNER JOIN Items ON myReturnTBL.ItemID=Items.ItemID
	INNER JOIN ItemGroups ON Items.GroupID=ItemGroups.ID
	INNER JOIN ItemGroupsMain ON Items.MainGroupID=ItemGroupsMain.MainGroupID
GO
