CREATE PROCEDURE [dbo].[ItemsMisingParameters](@Running AS BIT=0)
AS

IF @Running=0

	SELECT     Items.ItemID, ItemName,CASE WHEN TechnicalDrawing IS NULL THEN 'Missing' ELSE 'Attached' END AS TechDrawing,CASE WHEN ItemPic IS NULL THEN 'Missing' ELSE 'Attached' END AS ItemPic,GroupID,
	CASE WHEN ProcessGroups.EntryID IS NULL THEN 'Missing' ELSE ProcessGroups.GroupName END AS GroupName,
	CASE WHEN ISNULL(ItemNameUrdu,'')='' THEN 'Missing' ELSE ItemNameUrdu END AS ItemNameUrdu,
	CASE WHEN ItemGroups.ID IS NULL THEN 'Missing' ELSE ItemGroups.Description END AS ItemGroup

	FROM Items
	LEFT OUTER JOIN ItemGroups ON ItemGroups.ID=Items.GroupID
	LEFT OUTER JOIN ItemProcessGroups ON Items.ItemID=ItemProcessGroups.ItemID
	LEFT OUTER JOIN ProcessGroups ON ProcessGroups.EntryID=ItemProcessGroups.PG_RefID
	WHERE ProcessGroups.EntryID IS NULL OR ItemGroups.ID IS NULL OR ItemPic IS NULL OR TechnicalDrawing IS NULL OR ISNULL(ItemNameUrdu,'')=''

ELSE

	SELECT     Items.ItemID, ItemName,CASE WHEN TechnicalDrawing IS NULL THEN 'Missing' ELSE 'Attached' END AS TechDrawing,CASE WHEN ItemPic IS NULL THEN 'Missing' ELSE 'Attached' END AS ItemPic,GroupID,ItemNameUrdu,
	CASE WHEN ProcessGroups.EntryID IS NULL THEN 'Missing' ELSE ProcessGroups.GroupName END AS GroupName,
	CASE WHEN ISNULL(ItemNameUrdu,'')='' THEN 'Missing' ELSE ItemNameUrdu END AS ItemNameUrdu,
	CASE WHEN ItemGroups.ID IS NULL THEN 'Missing' ELSE ItemGroups.Description END AS ItemGroup
	FROM Items
	LEFT OUTER JOIN ItemGroups ON ItemGroups.ID=Items.GroupID
	LEFT OUTER JOIN ItemProcessGroups ON Items.ItemID=ItemProcessGroups.ItemID
	LEFT OUTER JOIN ProcessGroups ON ProcessGroups.EntryID=ItemProcessGroups.PG_RefID
	WHERE (ProcessGroups.EntryID IS NULL OR ItemGroups.ID IS NULL OR ItemPic IS NULL OR TechnicalDrawing IS NULL OR ISNULL(ItemNameUrdu,'')='')
	AND Items.ItemID IN(SELECT CompItemCode FROM FOrderItems INNER JOIN VUnshippedOrderList ON FOrderItems.OrderNo=VUnShippedOrderList.OrderNo)
GO
/****** Object:  StoredProcedure [dbo].[ItemwiseAvgProcessDuration_SP]    Script Date: 6/29/2026 4:50:02 PM ******/
