GO



CREATE PROCEDURE [dbo].[ItemwiseAvgProcessDuration_SP] (@ItemID AS VARCHAR(255),@DTFrom AS DATETIME,@DTTo AS DATETIME)
AS
BEGIN

	SET @DTFrom=CAST(CONVERT(VARCHAR(50),@DTFrom,6) AS DATETIME)
	SET @DTTo=CAST(CONVERT(VARCHAR(50),@DTTo,6) AS DATETIME)

	SELECT T1.*,Processes.Description,ItemName,ItemProcesses.SNo,Code FROM Processes INNER JOIN (
	SELECT SUM(DATEDIFF(day,VendIssued.DT,VendReceived.DT)) AS Days,COUNT(*) AS Lots,SUM(VendRcvdDetail.RcvdQty) AS RcvdQty,VendIssued.ProcessID,VendIssdDetail.ItemCode FROM VendRcvdDetail
	INNER JOIN VendReceived ON VendReceived.EntryID=VendRcvdDetail.RefID
	INNER JOIN VendIssdDetail ON VendRcvdDetail.Issue_RefID=VendIssdDetail.EntryID
	INNER JOIN VendIssued ON VendIssdDetail.RefID=VendIssued.EntryID
	WHERE VendIssdDetail.LotNo<>'0' AND VendReceived.DT BETWEEN @DTFrom AND @DTTo AND VendIssdDetail.ItemCode=@ItemID
	--AND VendRcvdDetail.EntryID IN(SELECT MIN(EntryID) FROM VendRcvdDetail GROUP BY LotNo)
	GROUP BY VendIssued.ProcessID,VendIssdDetail.ItemCode) T1 ON Processes.ProcessID=T1.ProcessID INNER JOIN Items ON T1.ItemCode=Items.ItemID INNER JOIN ItemProcesses ON Items.ItemID=ItemProcesses.ItemID AND Processes.ProcessID=ItemProcesses.ProcessID



END
GO
