CREATE PROCEDURE [dbo].[JobOrderCosting_SP](@ItemID AS VARCHAR(50),@OrderNo AS VARCHAR(255))
AS
BEGIN

	DECLARE @BatchTBL TABLE(PORefNo VARCHAR(50),RMID INT,Qty REAL,Rate REAL,Type TINYINT)
	INSERT INTO @BatchTBL(PORefNo,RMID,Qty,Rate,Type)
		SELECT RawMaterialIssuanceDetail.PORefNo,RMID,Qty,VendRcvdDetailPO.Rate,Type FROM RawMaterialIssuanceDetail INNER JOIN RawMaterialIssuance ON RawMaterialIssuanceDetail.IssNo=RawMaterialIssuance.IssNo
			INNER JOIN VendIssued ON VendIssued.EntryID=RawMaterialIssuance.VI_RefID
			INNER JOIN RM ON RawMaterialIssuanceDetail.RMID1=RM.RMID1
			INNER JOIN RMGroups ON RM.GroupID=RMGroups.ID
			INNER JOIN VendRcvdDetailPO ON VendRcvdDetailPO.PORefNo=RawMaterialIssuanceDetail.PORefNo AND VendRcvdDetailPO.MaterialID=RM.RMID1
			WHERE RMGroups.Type IN(1,2) AND VendIssued.EntryID IN(SELECT RefID FROM VendIssdDetail WHERE OrderNo=@OrderNo AND ItemID=@ItemID AND ISNULL(LotNo,'0')='0')


	DECLARE @ReturnTBL TABLE(ItemID VARCHAR(255),ProcessID INT,Description VARCHAR(255),RcvdQty INT, VenderName VARCHAR(255),IssRate REAL,Operation INT,VendID INT,Rate REAL,JOCRRate REAL,SNO INT,StandardRate REAL,Rejection INT,ReWork INT,ReWorkLot BIT)

	INSERT INTO @ReturnTBL SELECT @ItemID,-2 AS ProcessID,'Forging',SUM(Qty),'Forging',SUM(Qty*Rate)/SUM(Qty),1,0,SUM(Qty*Rate)/SUM(Qty),SUM(Qty*Rate)/SUM(Qty),-2 AS SNo,0 AS StandardRate,0,0,0 FROM @BatchTBL WHERE Type=1 GROUP BY Type
	INSERT INTO @ReturnTBL SELECT @ItemID,-1 AS ProcessID,'Steel',SUM(Qty),'Steel',SUM(Qty*Rate)/SUM(Qty),1,0,SUM(Qty*Rate)/SUM(Qty),SUM(Qty*Rate)/SUM(Qty),-1 AS SNo,0 AS StandardRate,0,0,0 FROM @BatchTBL WHERE Type=2 GROUP BY Type

	INSERT INTO @ReturnTBL
	SELECT Items.ItemID,Processes.ProcessID,Processes.Description,TabRcvd.RcvdQty,VenderName,IssRate,Operation,Makers.VendID,JobOrderCostingRates.Rate,JOCR_2.Rate AS JOCRRate,ItemProcesses.SNo,ItemProcesses.Rate,Wastage,ReWork,ReWorkLot FROM Items INNER JOIN ItemProcesses
	ON Items.ItemID=ItemProcesses.ItemID INNER JOIN Processes ON ItemProcesses.ProcessID=Processes.ProcessID
	LEFT OUTER JOIN
	(SELECT VendID,OrderNo,ItemCode,ProcessID,IssRate,ReWorkLot,SUM(RcvdQty-ISNULL(ReWorkQty,0)-Wastage) AS RcvdQty,SUM(Wastage) AS Wastage,SUM(ISNULL(ReWorkQty,0)) AS ReWork FROM VVendRcvdDetail GROUP BY VendID,OrderNo,ItemCode,ProcessID,IssRate,ReWorkLot) TabRcvd ON
	ItemProcesses.ItemID=TabRcvd.ItemCode AND ItemProcesses.ProcessID=TabRcvd.ProcessID

	INNER JOIN Makers ON TabRcvd.VendID=Makers.VendID
	LEFT OUTER JOIN JobOrderCostingRates ON TabRcvd.OrderNo=JobOrderCostingRates.OrderNo AND TabRcvd.ItemCode=JobOrderCostingRates.ItemID AND TabRcvd.ProcessID=JobOrderCostingRates.ProcessID
	LEFT OUTER JOIN JobOrderCostingRates JOCR_2 ON TabRcvd.ItemCode=JOCR_2.ItemID AND TabRcvd.ProcessID=JOCR_2.ProcessID
	WHERE Items.ItemID=@ItemID AND TabRcvd.OrderNo=@OrderNo

	SELECT * FROM @ReturnTBL ORDER BY SNo

END
GO
