CREATE PROCEDURE [dbo].[MakerBilling_SP] (@MakerID AS INT)
AS
BEGIN

SELECT Makers.VendID,Makers.VendID1,Makers.VenderName,VendIssued.EntryID,RecieptID,DT,VendIssued.ItemID,TabIssd.IssQty,TabIssd.Value,TabIssd.Price,TabIssd.Rate,TempAdvance,RcvdQty,RcvdQtyUnAuth,RcvdWeight,RcvdWeightUnAuth,RcvdValue,
RcvdValueUnAuth,(RcvdQty+RcvdQtyUnAuth)/CAST(TabIssd.IssQty AS FLOAT) *100 AS PercentRcvd,TabRcvd.RepairAmt,ItemName,ItemNameUrdu,Wastage,Accounts.Balance As AccBalance,OrderNo,Issue_RefID
FROM VendIssued
--LEFT OUTER JOIN (SELECT RefID,SUM(IssQty) AS IssQty,SUM(IssValue) AS Value,SUM(Rate)/COUNT(*) AS Price,MAX(Rate) AS Rate FROM VVendIssdDetailWithValue GROUP BY RefID) TabIssd ON VendIssued.EntryID=TabIssd.RefID
LEFT OUTER JOIN (SELECT EntryID,RefID,SUM(IssQty) AS IssQty,SUM(IssValue) AS Value,SUM(Rate)/COUNT(*) AS Price,MAX(Rate) AS Rate FROM VVendIssdDetailWithValue GROUP BY EntryID,RefID) TabIssd ON VendIssued.EntryID=TabIssd.RefID
LEFT OUTER JOIN (SELECT Issuance_RefID,Issue_RefID,OrderNo,SUM(CASE WHEN ReqAuth=0 THEN RcvdQty ELSE 0 END) AS RcvdQty,SUM(CASE WHEN ReqAuth=1 THEN RcvdQty ELSE 0 END) AS RcvdQtyUnAuth,
					SUM(CASE WHEN ReqAuth=0 THEN RcvdWeight ELSE 0 END) AS RcvdWeight,SUM(CASE WHEN ReqAuth=1 THEN RcvdWeight ELSE 0 END) AS RcvdWeightUnAuth,
					SUM(CASE WHEN ReqAuth=0 THEN RcvdValue ELSE 0 END) AS RcvdValue,SUM(CASE WHEN ReqAuth=1 THEN RcvdValue ELSE 0 END) AS RcvdValueUnAuth,SUM(RepairAmt) AS RepairAmt
,SUM(Wastage) AS Wastage
FROM VVendRcvdDetail
			GROUP BY Issuance_RefID,Issue_RefID,OrderNo) TabRcvd ON VendIssued.EntryID=TabRcvd.Issuance_RefID AND TabIssd.EntryID=TabRcvd.Issue_RefID
LEFT OUTER JOIN (SELECT Issuance_RefID,SUM(Amount) AS TempAdvance FROM MakerTemporaryLoans WHERE ISNULL(GroupID,0)=0 OR GroupID IN(SELECT EntryID FROM MakerTemporaryLoansGroup WHERE Active=1)
																	GROUP BY Issuance_RefID) TabTemp ON VendIssued.EntryID=TabTemp.Issuance_RefID
INNER JOIN Items ON VendIssued.ItemID=Items.ItemID
INNER JOIN Makers ON VendIssued.VendID=Makers.VendID
INNER JOIN Accounts ON Makers.AccNo=Accounts.AccNo
WHERE VendIssued.VendID=@MakerID AND VchrNo IS NULL AND Issue_RefID IS NOT NULL
AND VendIssued.EntryID NOT IN(SELECT Iss_RefID FROM MakerBilling_Hidden)
ORDER BY (RcvdQty+RcvdQtyUnAuth)/CAST(TabIssd.IssQty AS FLOAT) *100 DESC
END
GO
