CREATE PROCEDURE [dbo].[MakerOrdersForTempLoan_SP] (@MakerID AS INT,@DTFrom AS DATETIME,@DTTo AS DATETIME)
AS
BEGIN

SELECT EntryID,RecieptID,DT,ItemID,TabIssd.IssQty,TabIssd.Value,TabIssd.Price,TempAdvance FROM VendIssued
LEFT OUTER JOIN (SELECT RefID,SUM(IssQty) AS IssQty,SUM(IssValue) AS Value,SUM(Rate)/COUNT(*) AS Price FROM VVendIssdDetailWithValue GROUP BY RefID) TabIssd ON VendIssued.EntryID=TabIssd.RefID
LEFT OUTER JOIN (SELECT Issuance_RefID,SUM(Amount) AS TempAdvance FROM MakerTemporaryLoans GROUP BY Issuance_RefID) Tab1 ON VendIssued.EntryID=Tab1.Issuance_RefID
WHERE VendID=@MakerID AND VchrNo IS NULL AND CAST(CONVERT(Varchar(50),DT,1) AS DATETIME) BETWEEN @DTFrom AND @DTTo AND Authorized=1

END
GO
