CREATE PROCEDURE [dbo].[MakerPaymentSheet_SP]
AS
BEGIN
DECLARE @PymtVchrs TABLE(SNo BigInt,AccNo Varchar(50),VchrNo Varchar(50),Balance FLOAT)
DECLARE @BillVchrs TABLE(AccNo Varchar(50),VchrNo Varchar(50),Credit FLOAT)
INSERT INTO @PymtVchrs SELECT SNo,AccNo,VchrNo,Balance FROM Vouchers WHERE SNo IN(SELECT MAX(SNo) FROM Vouchers
				WHERE LEFT(AccNo,10)='24-004-006' AND LEFT(VchrNo,3) IN('BPV','CPV') GROUP BY AccNo)

INSERT INTO @BillVchrs SELECT Vouchers.AccNo,Vouchers.VchrNo,Vouchers.Credit FROM Vouchers INNER JOIN @PymtVchrs PymtVchrs ON Vouchers.AccNo=PymtVchrs.AccNo AND Vouchers.SNo>PymtVchrs.SNo

SELECT Makers.VendID,VendID1,VenderName,MakerNameUrdu,Accounts.Balance AS ClosingBalance,Payments.Balance,Bills.TotalBillAmount,TotalTempAmt,TotalTempAmtPosted,RepairAmt,
UnAuthRcvingTotal,BalancePOValueTotal

FROM Makers
INNER JOIN Accounts ON Makers.AccNo=Accounts.AccNo
LEFT OUTER JOIN @PymtVchrs Payments ON Makers.AccNo=Payments.AccNo
LEFT OUTER JOIN (SELECT AccNo,SUM(Credit) AS TotalBillAmount FROM @BillVchrs GROUP BY AccNo) Bills ON Makers.AccNo=Bills.AccNo
LEFT OUTER JOIN (SELECT VendID,SUM(Amount) AS TotalTempAmt FROM VendIssued INNER JOIN MakerTemporaryLoans
		ON VendIssued.EntryID=MakerTemporaryLoans.Issuance_RefID WHERE VendIssued.VchrNo IS NULL GROUP BY VendID) TempLoans ON Makers.VendID=TempLoans.VendID
LEFT OUTER JOIN (SELECT VendID,SUM(Amount) AS TotalTempAmtPosted FROM VendIssued INNER JOIN MakerTemporaryLoans
		ON VendIssued.EntryID=MakerTemporaryLoans.Issuance_RefID WHERE VendIssued.VchrNo IN(SELECT VchrNo FROM @BillVchrs) GROUP BY VendID) TempLoanPosted
		ON Makers.VendID=TempLoanPosted.VendID
LEFT OUTER JOIN (SELECT BillVchrs.AccNo,SUM(Vouchers.Credit) AS RepairAmt FROM Vouchers INNER JOIN @BillVchrs BillVchrs ON Vouchers.VchrNo=BillVchrs.VchrNo WHERE Vouchers.AccNo='24-005-19001' GROUP BY BillVchrs.AccNo) TabDebits
		ON Makers.AccNo=TabDebits.AccNo
LEFT OUTER JOIN (SELECT VendID,SUM(RcvdValue) AS UnAuthRcvingTotal FROM VVendRcvdDetail WHERE ReqAuth=1 GROUP BY VendID) UnAuthRcvings ON Makers.VendID=UnAuthRcvings.VendID
LEFT OUTER JOIN (SELECT VendID,SUM(BalanceValue) AS BalancePOValueTotal FROM VVendIssdDetailWithValue GROUP BY VendID) BalancePO ON Makers.VendID=BalancePO.VendID
/*SELECT Makers.VendID,VendID1,VenderName,Accounts.Balance AS ClosingBalance,Payments.Balance,Bills.TotalBillAmount,TotalTempAmt FROM Makers INNER JOIN Accounts ON Makers.AccNo=Accounts.AccNo
LEFT OUTER JOIN @PymtVchrs Payments ON Makers.AccNo=Payments.AccNo LEFT OUTER JOIN
(SELECT AccNo, SNo, Credit AS TotalBillAmount FROM Vouchers WHERE LEFT(AccNo,10)='24-004-006') Bills ON Bills.AccNo=Makers.AccNo AND Bills.SNo>Payments.SNo
LEFT OUTER JOIN (SELECT VendID,SUM(Amount) AS TotalTempAmt FROM VendIssued INNER JOIN MakerTemporaryLoans
		ON VendIssued.EntryID=MakerTemporaryLoans.Issuance_RefID WHERE VendIssued.VchrNo IS NULL GROUP BY VendID) TempLoans ON Makers.VendID=TempLoans.VendID
*/
END
GO
