CREATE PROCEDURE [dbo].[MakersPayableReport_SP](@DTFrom DATETIME,@DTTo DATETIME,@CustCode VARCHAR(4000)='',@ItemGroups VARCHAR(4000)='',@Catagory AS VARCHAR(255)='0')
AS
BEGIN

SET @DTFrom=CAST(CONVERT(VARCHAR(50),@DTFrom,6) AS DATETIME)
SET @DTTo=CAST(CONVERT(VARCHAR(50),@DTTo,6) AS DATETIME)

/*CREATE TABLE #Customers(CustCode VARCHAR(50))
CREATE TABLE #ItemGroups(GroupID INT,GroupName VARCHAR(255))
DECLARE @myQuery AS VARCHAR(1000)
IF @CustCode=''
	SET @myQuery='INSERT INTO #Customers(CustCode) SELECT CustCode FROM ForeignCustomers'
ELSE
	SET @myQuery='INSERT INTO #Customers(CustCode) SELECT CustCode FROM ForeignCustomers WHERE CustCode IN(' + @CustCode +')'

EXEC(@myQuery)

IF @ItemGroups=''
	SET @myQuery='INSERT INTO #ItemGroups(GroupID,GroupName) SELECT ID,Description FROM ItemGroups'
ELSE
	SET @myQuery='INSERT INTO #ItemGroups(GroupID,GroupName) SELECT ID,Description FROM ItemGroups WHERE ID IN(' + @ItemGroups + ')'

EXEC(@myQuery)

CREATE TABLE #myTBL(RMID INT,AssignedProducts INT,TotalHits INT,OrderQty INT,Total_Item_MinLvl INT,FGPOQty INT,FGStock INT,MinQty INT,ToOrderQty INT,ItemID VARCHAR(50),ItemHits INT,ItemQty INT,Item_MinLvl INT)
*/
DECLARE @DTFromLast DATETIME,@DTToLast DATETIME
SET @DTFromLast=DATEADD(m,-3,getDate())
SET @DTFromLast=CAST(MONTH(@DTFromLast) AS VARCHAR(2)) + '/1/' + CAST(YEAR(@DTFromLast) AS VARCHAR(4))
SET @DTToLast=DATEADD(M,2,DATEADD(d,-1,DATEADD(m,1,@DTFromLast)))

DECLARE @BillingLastDT DATETIME
SET @BillingLastDT = DATEADD(yyyy,1,getDate())
CREATE TABLE #MakerBilling(VendID INT,VendID1 VARCHAR(255),VenderName VARCHAR(255),EntryID INT,RecieptID VARCHAR(50),DT DATETIME,ItemID VARCHAR(50),IssQty INT,Rate REAL,TempAdvance INT,RcvdQty INT,RcvdQtyUnAuth INT,RcvdWeight INT,RcvdWeightUnAuth INT,RcvdValue INT,RcvdValueUnAuth INT
	,PercentRcvd REAL,RepairAmt INT,ItemName VARCHAR(255),ItemNameUrdu NVARCHAR(255),Wastage INT,AccBalance INT,OrderNo VARCHAR(50),Issue_RefID INT,RcvDetailEntryID INT,RcvRecieptID VARCHAR(50)
	,LotNo VARCHAR(50),BillingProcRcvdQty INT,BillingProcAmount REAL,OnlyDT DATETIME
	,ProcessID INT,Description VARCHAR(255),CatID INT,MasterPONo VARCHAR(50),MasterRecieptID VARCHAR(50),MainIssuanceEntryID INT,LotClearDT DATETIME
	,WastageQtyFromRepair INT,WastageValueFromRepair INT,RcvDT DATETIME,ItemGroupName VARCHAR(50),Audited BIT,BillQtyDirect INT,BillQtyInDirect INT,CustCode VARCHAR(50))

	INSERT INTO #MakerBilling EXEC dbo.MakerBilling_RcvingWise_SP 0,@DTFrom,@DTTo,'0',0

--SELECT VendID,SUM(BillingProcAmount) AS BillAmt,SUM(BillingProcRcvdQty) AS BillQty
SELECT AMaster.AccTitle,Makers.VendID,Makers.VendID1,VenderName,TST.STAmt,(TLT.TotalAmountTaken-TLT.TotalAmountCleared) AS LTBalance,TLT.ActualDeductionAmount,PendingValue
	,RcvdQty--RcvdQty-ISNULL(BillQty,0) AS RcvdQty
	,RcvdValue--RcvdValue-ISNULL(BillAmt,0) AS RcvdValue
	,BillAmt,BillQty,ROUND(TRcvAvg.AvgRcvdValue/3,0) AS AvgBill,ROUND(TRcvAvg.AvgRcvdQty/3,0) AS AvgQty,MaterialDeduction
	,Accounts.Balance,TOpenPos.OpenPO_Value
	FROM Makers
	LEFT OUTER JOIN (SELECT AccNo,(Amount-AmountCleared) AS STAmt FROM VMakerAdvancesShortDeduction) TST ON Makers.AccNo=TST.AccNo
	LEFT OUTER JOIN (SELECT AccNO,TotalAmountTaken,TotalAmountCleared,ActualDeductionAmount FROM VMakerAdvancesDeduction) TLT ON Makers.AccNo=TLT.AccNo
	LEFT OUTER JOIN (SELECT VendID,SUM((IssQty-RcvdQty)*Rate) AS PendingValue FROM VVendIssdDetail_MakerDashBoard WHERE RcvdQty<IssQty AND Closed=0 GROUP BY VendID) TPV ON Makers.VendID=TPV.VendID
	/*LEFT OUTER JOIN (SELECT VendID,SUM(RcvdQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0)) AS RcvdQty,SUM((RcvdQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0))*Rate) AS RcvdValue FROM VVendReceivingList_Simple WHERE ISNULL(Opening_RefID,0)=0 AND (MPB_D_EntryID IS NULL) AND ProcessID NOT IN(SELECT ProcessID FROM Processes WHERE Operation=0) GROUP BY VendID) TRcv ON Makers.VendID=TRcv.VendID*/
	LEFT OUTER JOIN (SELECT VendID,SUM(RcvdQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0)) AS RcvdQty,SUM((RcvdQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0))*Rate) AS RcvdValue FROM VVendReceivingList_Simple WHERE VVendReceivingList_Simple.DT BETWEEN @DTFrom AND @DTTo GROUP BY VendID) TRcv ON Makers.VendID=TRcv.VendID
	LEFT OUTER JOIN (SELECT VendID,SUM(RcvdQty) AS AvgRcvdQty,SUM(RcvdQty*Rate) AS AvgRcvdValue FROM VVendReceivingList_Simple WHERE OnlyDT BETWEEN @DTFromLast AND @DTToLast GROUP BY VendID) TRcvAvg ON Makers.VendID=TRcvAvg.VendID
	LEFT OUTER JOIN (SELECT VendID,SUM(BillingProcAmount) AS BillAmt,SUM(BillingProcRcvdQty) AS BillQty	FROM #MakerBilling GROUP BY VendID) TBill ON Makers.VendID=TBill.VendID
	LEFT OUTER JOIN (SELECT VendID1,SUM(Qty*Rate) AS OpenPO_Value FROM VItemOpenPOs GROUP BY VendID1) TOpenPOs ON  Makers.VendID1=TOpenPOs.VendID1
	INNER JOIN Accounts ON Makers.AccNo=Accounts.AccNo
	INNER JOIN Accounts AMaster ON Accounts.SubAccOf=AMaster.AccNo
	LEFT JOIN (SELECT VendID,SUM(Qty*CASE WHEN ISNULL(Price,0)=0 THEN 0 ELSE Price END) AS MaterialDeduction FROM VRawMaterialIssuance WITH (NOLOCK) WHERE MasterEntryID NOT IN(SELECT RMI_RefID FROM MakerPostedBills_MaterialDeductions) AND EntryID NOT IN(SELECT RMID_RefID FROM MakerPostedBills_MaterialDeductions) GROUP BY VendID) TMD ON Makers.VendID=TMD.VendID
	WHERE (Accounts.SubAccOf=@Catagory OR @Catagory='0')
END


GO
