CREATE PROCEDURE [dbo].[MonthlyAttendanceStatus_SP] (@DTFrom AS DATETIME,@DTTo AS DATETIME,@DeptID AS VARCHAR(50)='0') AS

SET @DTFrom=CONVERT(varchar(50),@DTFrom,6)
/*IF @DTTo>getDate()
	SET @DTTo=getDate()*/
SET @DTTo=CONVERT(varchar(50),@DTTo,6)

DECLARE @TempDT AS DATETIME
DECLARE @myDTTBL TABLE(DT DATETIME)
DECLARE @myUpdateQry AS NVARCHAR(1000)
DECLARE @TotalSundays AS INT,@TotalHolidays AS INT
SELECT @TotalSundays=COUNT(*) FROM DateLookup WHERE WeekDayName='Sunday' AND DateFull BETWEEN @DTFrom AND @DTTo
SELECT @TotalHolidays=COUNT(*) FROM Holidays WHERE DT BETWEEN @DTFrom AND @DTTo
DECLARE @WorkingDays AS INT
SET @WorkingDays=DATEDIFF(day,@DTFrom,@DTTo)-@TotalSundays-@TotalHolidays

SELECT VEmp.EmpID,VEmp.Name,VEmp.FName,VEmp.DeptID,VEmp.DeptName,@TotalSundays AS TotalSundays,@TotalHolidays AS TotalHolidays,Leaves,Presents,@WorkingDays AS WorkingDays,OTHrs,JoinDate,DiscontinuedON FROM VEmp
	LEFT OUTER JOIN (SELECT EmpID,COUNT(EmpID) AS Leaves FROM Leaves WHERE DT BETWEEN @DTFrom AND @DTTo GROUP BY EmpID) T1 ON VEmp.EmpID=T1.EmpID
	LEFT OUTER JOIN (SELECT EmpID,COUNT(EmpID) AS Presents FROM AttendanceSheet WHERE DT BETWEEN @DTFrom AND @DTTo AND Attendance=1 GROUP BY EmpID) T2 ON VEmp.EmpID=T2.EmpID
	LEFT OUTER JOIN (SELECT EmpID,SUM(OTHrs) AS OTHrs FROM EmpOTHrs WHERE DT BETWEEN @DTFrom AND @DTTo GROUP BY EmpID) T3 ON VEmp.EmpID=T3.EmpID
	WHERE JoinDate <=@DTTo AND (DiscontinuedOn IS NULL OR DiscontinuedOn BETWEEN @DTFrom AND @DTTo) AND (DeptID=@DeptID OR @DeptID='0')

GO
