CREATE PROCEDURE [dbo].[MonthlyOverTimeRegister_SP] (@DTFrom AS DATETIME,@DTTo AS DATETIME,@AttGate AS Varchar(50)='',@ReportType AS TinyInt=0,@MainUnit AS Varchar(50),@DeptID AS VARCHAR(50)='',@EmpID AS VARCHAR(50)='') AS

SET @DTFrom=CAST(CONVERT(varchar(50),@DTFrom,6) AS DATETIME)
SET @DTTo=CAST(CONVERT(varchar(50),@DTTo,6) AS DATETIME)

DECLARE @TempDT AS DATETIME
DECLARE @myDTTBL TABLE(DT DATETIME)
DECLARE @myUpdateQry AS NVARCHAR(1000)
CREATE TABLE #myTBL (EmpID VARCHAR(50),Date1 Real,Date2 Real,Date3 Real,Date4 Real,Date5 Real,Date6 Real,Date7 Real,
				Date8 Real,Date9 Real,Date10 Real,Date11 Real,Date12 Real,Date13 Real,Date14 Real,Date15 Real,
				Date16 Real,Date17 Real,Date18 Real,Date19 Real,Date20 Real,Date21 Real,Date22 Real,Date23 Real,
				Date24 Real,Date25 Real,Date26 Real,Date27 Real,Date28 Real,Date29 Real,Date30 Real,Date31 Real)

--DECLARE @EmpSundays TABLE(EmpID VARCHAR(50),Sundays INT)

INSERT INTO #myTBL(EmpID) SELECT DISTINCT EmpID FROM EmpTimes WHERE OverTime=1 AND EmpID IN(SELECT EmpID FROM Employees WHERE (DeptID=@DeptID OR @DeptID='') AND (EmpID=@EmpID OR @EmpID='')) AND DT BETWEEN @DTFrom AND @DTTo --AND EmpID='00060'

SET @TempDT=@DTFrom

WHILE @TempDT<=@DTTo
	BEGIN
		INSERT INTO @myDTTBL(DT) VALUES(@TempDT)
		IF @ReportType=0 	--With Time
			SET @myUpdateQry='UPDATE #myTBL SET Date' + CAST(Day(@TempDT) AS VARCHAR(2)) +'=AppHrs FROM #myTBL myTBL INNER JOIN (SELECT EmpID,SUM(PayableHrs) AS AppHrs FROM EmpTimes WHERE OverTime=1 AND DT=''' + CONVERT(VARCHAR(50),@TempDT,6) +  ''' GROUP BY EmpID) T1 ON myTBL.EmpID=T1.EmpID'
		EXEC(@myUpdateQry)

		SET @TempDT=DATEADD(d,1,@TempDT)

	END

SELECT #myTBL.*,Name,Rel,FName,Designation,DOB,Religion,DeptID,DeptName FROM #myTBL INNER JOIN VEmp ON #myTBL.EmpID=VEmp.EmpID
	ORDER BY VEmp.EmpID

GO
