CREATE PROCEDURE [dbo].[MonthlyRejectionReportLotWise_SP](@DT AS DATETIME)
AS
BEGIN

CREATE TABLE #myTBL (LotNo INT,LotQty INT,Proc1 INT,Proc2 INT,Proc3 INT,Proc4 INT,Proc5 INT,Proc6 INT,Proc7 INT,Proc8 INT,Proc9 INT,Proc10 INT,Proc11 INT,Proc12 INT,Proc13 INT,Proc14 INT,Proc15 INT,Proc16 INT)

CREATE TABLE #myTBL1 (EntryID INT,ProcCode1 VARCHAR(50),ProcCode2 VARCHAR(50),ProcCode3 VARCHAR(50),ProcCode4 VARCHAR(50),ProcCode5 VARCHAR(50),ProcCode6 VARCHAR(50),ProcCode7 VARCHAR(50),ProcCode8 VARCHAR(50),ProcCode9 VARCHAR(50),ProcCode10 VARCHAR(50),ProcCode11 VARCHAR(50),ProcCode12 VARCHAR(50),ProcCode13 VARCHAR(50),ProcCode14 VARCHAR(50),ProcCode15 VARCHAR(50),ProcOther VARCHAR(50),ProcID1 INT,ProcID2 INT,ProcID3 INT,ProcID4 INT,ProcID5 INT,ProcID6 INT,ProcID7 INT,ProcID8 INT,ProcID9 INT,ProcID10 INT,ProcID11 INT,ProcID12 INT,ProcID13 INT,ProcID14 INT,ProcID15 INT,ProcIDOther INT)

DECLARE Cursor_Procs CURSOR FOR SELECT DISTINCT Code,ProcessNo FROM VRejectionReportLotwise WHERE MONTH(DT)=MONTH(@DT) AND YEAR(DT)=YEAR(@DT)
OPEN Cursor_Procs
DECLARE @ProcessCode AS VARCHAR(50),@ProcessNo AS INT
FETCH NEXT FROM Cursor_Procs INTO @ProcessCode,@ProcessNo
INSERT INTO #myTBL1(EntryID,ProcCode1,ProcCode2,ProcCode3,ProcCode4,ProcCode5,ProcCode6,ProcCode7,ProcCode8,ProcCode9,ProcCode10,ProcCode11,ProcCode12,ProcCode13,ProcCode14,ProcCode15,ProcOther) VALUES(1,'OS','OS','OS','OS','OS','OS','OS','OS','OS','OS','OS','OS','OS','OS','OS','Others')
DECLARE @myUpdateSQL AS VARCHAR(1000),@ColNo AS INT
SET @ColNo=0
DEClARE @Proc1 AS INT,@Proc2 AS INT,@Proc3 AS INT,@Proc4 AS INT,@Proc5 AS INT,@Proc6 AS INT,@Proc7 AS INT,@Proc8 AS INT,@Proc9 AS INT,@Proc10 AS INT,@Proc11 AS INT,@Proc12 AS INT,@Proc13 AS INT,@Proc14 AS INT,@Proc15 AS INT
WHILE @@FETCH_STATUS=0
	BEGIN
		SET @ColNo=1
		IF @ColNo=1
			SET @Proc1=@ProcessNo
		ELSE IF @ColNo=2
			SET @Proc2=@ProcessNo
		ELSE IF @ColNo=3
			SET @Proc3=@ProcessNo
		ELSE IF @ColNo=4
			SET @Proc4=@ProcessNo
		ELSE IF @ColNo=5
			SET @Proc5=@ProcessNo
		ELSE IF @ColNo=6
			SET @Proc6=@ProcessNo
		ELSE IF @ColNo=7
			SET @Proc7=@ProcessNo
		ELSE IF @ColNo=8
			SET @Proc8=@ProcessNo
		ELSE IF @ColNo=9
			SET @Proc9=@ProcessNo
		ELSE IF @ColNo=10
			SET @Proc10=@ProcessNo
		ELSE IF @ColNo=11
			SET @Proc11=@ProcessNo
		ELSE IF @ColNo=12
			SET @Proc12=@ProcessNo
		ELSE IF @ColNo=13
			SET @Proc13=@ProcessNo
		ELSE IF @ColNo=14
			SET @Proc14=@ProcessNo
		ELSE IF @ColNo=15
			SET @Proc15=@ProcessNo
		--SET @myUpdateSQL='UPDATE #myTBL SET Lot' + CAST(@ColNo AS VARCHAR(2)) + '=' + CAST(@LotQty AS VARCHAR(50)) + ' WHERE RowNo=''' + CHAR(@RowNo) + ''''
		SET @myUpdateSQL='UPDATE #myTBL1 SET ProcCode' + CAST(@ColNo AS VARCHAR(2)) + '=''' + 'OS' + CHAR(13) + @ProcessCode + ''',ProcID' + CAST(@ColNo AS VARCHAR(2)) + '=' + CAST(@ProcessNo AS VARCHAR(5))
		EXEC(@myUpdateSQL)
		FETCH NEXT FROM Cursor_Procs INTO @ProcessCode,@ProcessNo
	END

CLOSE Cursor_Procs
DEALLOCATE Cursor_Procs

DECLARE Cursor_Lots CURSOR FOR SELECT EntryID,LotQty,ProcessNo,RejectQty FROM VRejectionReportLotwise WHERE MONTH(DT)=MONTH(@DT) AND YEAR(DT)=YEAR(@DT)

OPEN Cursor_Lots

DECLARE @LotQty AS INT,@LotNo AS INT,@RejectQty AS INT
FETCH NEXT FROM Cursor_Lots INTO @LotNo,@LotQty,@ProcessNo,@RejectQty
DECLARE @myInsertSQL AS VARCHAR(1000)
DECLARE @RowNo AS INT,@ItemID AS VARCHAR(50),@PrevItemID AS VARCHAR(50)
SET @RowNo=0
DECLARE @ProcNo AS INT,@FieldName AS VARCHAR(50)
WHILE @@FETCH_STATUS=0
	BEGIN
		IF @ProcessNo=@Proc1
			SET @FieldName='Proc1'
		ELSE IF @ProcessNo=@Proc2
			SET @FieldName='Proc2'
		ELSE IF @ProcessNo=@Proc3
			SET @FieldName='Proc3'
		ELSE IF @ProcessNo=@Proc4
			SET @FieldName='Proc4'
		ELSE IF @ProcessNo=@Proc5
			SET @FieldName='Proc5'
		ELSE IF @ProcessNo=@Proc6
			SET @FieldName='Proc6'
		ELSE IF @ProcessNo=@Proc7
			SET @FieldName='Proc7'
		ELSE IF @ProcessNo=@Proc8
			SET @FieldName='Proc8'
		ELSE IF @ProcessNo=@Proc9
			SET @FieldName='Proc9'
		ELSE IF @ProcessNo=@Proc10
			SET @FieldName='Proc10'
		ELSE IF @ProcessNo=@Proc11
			SET @FieldName='Proc11'
		ELSE IF @ProcessNo=@Proc12
			SET @FieldName='Proc12'
		ELSE IF @ProcessNo=@Proc13
			SET @FieldName='Proc13'
		ELSE IF @ProcessNo=@Proc14
			SET @FieldName='Proc14'
		ELSE IF @ProcessNo=@Proc15
			SET @FieldName='Proc15'
		ELSE
			SET @FieldName='Proc16'
		--IF (SELECT COUNT(*) FROM #myTBL WHERE LotNo=@LotNo)>0
			--SET @myInsertSQL='UPDATE #myTBL SET ' + @FieldName + '=' + CAST(@LotQty AS VARCHAR(50)) + ' WHERE LotNo=' + CAST(@LotNo AS VARCHAR(50))
--		ELSE
			SET @myInsertSQL='INSERT INTO #myTBL(LotNo,LotQty,'+@FieldName+') VALUES(' + CAST(@LotNo AS VARCHAR(50)) + ',' + CAST(@LotQty AS VARCHAR(50)) + ',' + CAST(@RejectQty AS VARCHAR(50))+ ')'
		EXEC(@myInsertSQL)
		FETCH NEXT FROM Cursor_Lots INTO @LotNo,@LotQty,@ProcessNo,@RejectQty
	END

	CLOSE Cursor_Lots
	DEALLOCATE Cursor_Lots

	SELECT * FROM #myTBL1 CROSS JOIN #myTBL

END
GO
