CREATE PROCEDURE [dbo].[MonthWiseProductionReport_SP] (@DTFrom AS DATETIME,@DTTO AS DATETIME,@Summary AS BIT=0) AS


BEGIN

	SET @DTFrom=CAST(CONVERT(VARCHAR(50),@DTFrom,6) AS DATETIME)
	SET @DTTo=CAST(CONVERT(VARCHAR(50),@DTTo,6) AS DATETIME)

	DECLARE @QCProcessID AS INT,@PackingProcessID AS INT
	SELECT @QCProcessID=DataValue FROM GeneralData WHERE DataName='Q.CInspection100%'
	SELECT @PackingProcessID=DataValue FROM GeneralData WHERE DataName='PackingProcessID'
	SET @QCProcessID=198		--PHF

	DECLARE @myTBL TABLE(DateFull DATETIME,HolidayDescription VARCHAR(255),TotalRcvdQty INT,TotalRcvdItems INT,RcvdOnTime REAL,TotalQCItems INT,TotalQCQty INT,TotalPackItems INT,TotalPackQty INT,TotalOrderQty INT,TotalOrderItems INT,TotalInvoiceItems INT,TotalInvoiceQty INT)

		INSERT INTO @myTBL
		SELECT DateFull,Holidays.Description AS HolidayDescription,TotalRcvdQty,TotalRcvdItems,RcvdOnTime,TotalQCItems,TotalQCQty,TotalPackItems,TotalPackQty,TotalOrderQty,TotalOrderItems,TotalInvoiceItems,TotalInvoiceQty
		FROM DateLookup LEFT OUTER JOIN Holidays ON DateLookup.DateFull=Holidays.DT
		LEFT OUTER JOIN(SELECT CAST(CONVERT(varchar(50),VendReceived.DT,6) AS DATETIME) AS DT,SUM(VendRcvdDetail.RcvdQty) AS TotalRcvdQty,COUNT(VendRcvdDetail.ItemCode) AS TotalRcvdItems,
		SUM(CASE WHEN CAST(CONVERT(varchar(50),VendReceived.DT,6) AS DATETIME)<=VendIssdDetail_ReturnDTs.ReturnDT THEN 1 ELSE 0 END) AS RcvdOnTime FROM VendRcvdDetail INNER JOIN VendReceived ON VendReceived.EntryID=VendRcvdDetail.RefID

		INNER JOIN VendIssdDetail ON VendRcvdDetail.Issue_RefID=VendIssdDetail.EntryID
		INNER JOIN VendIssued ON VendIssdDetail.RefID=VendIssued.EntryID
		INNER JOIN VendIssdDetail_ReturnDTs ON VendIssdDetail.EntryID=VendIssdDetail_ReturnDTs.VIS_RefID
		WHERE MasterPONo IS NOT NULL AND CAST(CONVERT(varchar(50),VendReceived.DT,6) AS DATETIME) BETWEEN @DTFrom AND @DTTo
		GROUP BY CAST(CONVERT(varchar(50),VendReceived.DT,6) AS DATETIME)) TRcv ON DateLookup.DateFull=TRcv.DT

		LEFT OUTER JOIN(SELECT CAST(CONVERT(varchar(50),VendReceived.DT,6) AS DATETIME) AS DT,COUNT(VendRcvdDetail.ItemCode) AS TotalQCItems,SUM(VendRcvdDetail.RcvdQty) AS TotalQCQty FROM VendReceived
			INNER JOIN VendRcvdDetail ON VendReceived.EntryID=VendRcvdDetail.RefID WHERE VendRcvdDetail.ProcessID=@QCProcessID AND CAST(CONVERT(varchar(50),VendReceived.DT,6) AS DATETIME) BETWEEN @DTFrom AND @DTTo GROUP BY CAST(CONVERT(varchar(50),VendReceived.DT,6) AS DATETIME)) TQC ON DateLookup.DateFull=TQC.DT

		LEFT OUTER JOIN(SELECT CAST(CONVERT(varchar(50),VendReceived.DT,6) AS DATETIME) AS DT,COUNT(VendRcvdDetail.ItemCode) AS TotalPackItems,SUM(VendRcvdDetail.RcvdQty) AS TotalPackQty FROM VendReceived
			INNER JOIN VendRcvdDetail ON VendReceived.EntryID=VendRcvdDetail.RefID WHERE VendRcvdDetail.ProcessID=@PackingProcessID AND CAST(CONVERT(varchar(50),VendReceived.DT,6) AS DATETIME) BETWEEN @DTFrom AND @DTTo GROUP BY CAST(CONVERT(varchar(50),VendReceived.DT,6) AS DATETIME)) TPack ON DateLookup.DateFull=TPack.DT

		LEFT OUTER JOIN (SELECT DT,COUNT(FOrderItems.CompItemCode) AS TotalOrderItems,SUM(FOrderItems.Qty) AS TotalOrderQty FROM FCustomerOrders INNER JOIN FOrderItems ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
			WHERE DT BETWEEN @DTFrom AND @DTTo AND CustCode NOT IN('Stock') GROUP BY DT) TOrders ON DateLookup.DateFull=TOrders.DT

		LEFT OUTER JOIN (SELECT GatePassDT,COUNT(FOrderItems.CompItemCode) AS TotalInvoiceItems,SUM(CustomInvoiceItems.Qty) AS TotalInvoiceQty FROM CustomInvoice INNER JOIN CustomInvoiceItems ON CustomInvoice.CustomInvoice=CustomInvoiceItems.CustomInvoice
			INNER JOIN FProformaOrders ON CustomInvoiceItems.RefID=FProformaOrders.EntryID INNER JOIN FOrderItems ON FProformaOrders.OrderEntryID=FOrderItems.ID WHERE CustomInvoice.GatePassDT BETWEEN @DTFrom AND @DTTo AND CustCode NOT IN('Stock') GROUP BY GatePassDT) TInv ON DateLookup.DateFull=TInv.GatePassDT

		WHERE DateLookup.DateFull BETWEEN @DTFrom AND @DTTo

	IF @Summary=1
		SELECT RIGHT(CONVERT(VARCHAR(255),DateFull,6),6) AS DateFull,MAX(HolidayDescription) AS HolidayDescription,SUM(TotalRcvdQty) AS TotalRcvdQty,SUM(TotalRcvdItems) AS TotalRcvdItems,SUM(RcvdOnTime)/COUNT(*) AS RcvdOnTime,
			SUM(TotalQCItems) AS TotalQCItems,SUM(TotalQCQty) AS TotalQCQty,SUM(TotalPackItems) AS TotalPackItems,SUM(TotalPackQty) AS TotalPackQty,SUM(TotalOrderQty) AS TotalOrderQty,SUM(TotalOrderItems) AS TotalOrderItems
			,SUM(TotalInvoiceItems) AS TotalInvoiceItems,SUM(TotalInvoiceQty) AS TotalInvoiceQty FROM @myTBL GROUP BY RIGHT(CONVERT(VARCHAR(255),DateFull,6),6) ORDER BY MIN(MONTH(DateFull))
	ELSE
		SELECT * FROM @myTBL ORDER BY DateFull

	/*INNER JOIN @myTBL myTBL ON FCustomerOrders.OrderNo=myTBL.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(*) AS TotalOrderItems,SUM(Qty) AS TotalOrderQty FROM FOrderItems GROUP BY OrderNo) TOrd ON FCustomerOrders.OrderNo=TOrd.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPurItems,SUM(IssQty) AS TotalPurQty FROM VendIssued INNER JOIN VendIssdDetail ON VendIssued.EntryID=VendIssdDetail.RefID
		WHERE MasterPONo IS NOT NULL GROUP BY OrderNo) TPur ON FCustomerOrders.OrderNo=TPur.OrderNo
	LEFT OUTER JOIN(SELECT VendRcvdDetail.OrderNo,COUNT(DISTINCT VendRcvdDetail.ItemCode) AS TotalRcvItems,SUM(VendIssdDetail.IssQty-VendRcvdDetail.RcvdQty) AS TotalRcvQty FROM VendReceived INNER JOIN VendRcvdDetail ON VendReceived.EntryID=VendRcvdDetail.RefID  INNER JOIN VendIssdDetail ON VendRcvdDetail.Issue_RefID=VendIssdDetail.EntryID
		INNER JOIN VendIssued ON VendReceived.Issuance_RefID=VendIssued.EntryID  WHERE MasterPONo IS NOT NULL AND VendIssdDetail.IssQty-VendRcvdDetail.RcvdQty>0 GROUP BY VendRcvdDetail.OrderNo) TRcv ON FCustomerOrders.OrderNo=TRcv.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalProdItems,SUM(Qty) AS TotalProdQty FROM VRunningLots GROUP BY OrderNo) TProd ON FCustomerOrders.OrderNo=TProd.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPacItems,SUM(Qty)  AS TotalPacQty FROM VDispatchListDetail_Adv GROUP BY OrderNo) TPac ON FCustomerOrders.OrderNo=TPac.OrderNo*/

END
GO
