CREATE PROCEDURE [dbo].[NextProcessesForIssuance_SP] (@ProcessID AS INT,@VendID AS INT,@ItemID AS VARCHAR(50))
AS
BEGIN

DECLARE @MinSNo AS INT,@ItemSNo AS INT
SET @ItemSNo=(SELECT ITemSNo FROM VItemProcesses WHERE IsExist=@ItemID AND ProcessID=@ProcessID)

--****Get the Min Process of this Item which is not Assigned to Givend Maker....
SELECT @MinSNo=MIN(ItemSNO) FROM
(SELECT * FROM VItemProcesses WHERE IsExist=@ItemID) TabItem
LEFT OUTER JOIN (SELECT ProcessID FROM VendAssItems Where VendID=@VendID AND ItemID=@ItemID) TabVend ON TabItem.ProcessID=TabVend.ProcessID
WHERE TabVend.ProcessID IS NULL AND TabItem.ItemSNo>@ItemSNo

--****Now Select All the Processes of the Given Item that are Assigned to Given Vender BUT whose ItemSNo<ItemSno of Item which is not Assigned to this Maker
SELECT TabItem.ProcessID,TabVend.ProcessID,SNO,Description,TabVend.Rate,TabVend.Unit,ItemSNo
FROM
(SELECT * FROM VItemProcesses WHERE IsExist=@ItemID) TabItem
LEFT OUTER JOIN (SELECT ProcessID,Unit,Rate FROM VendAssItems Where VendID=@VendID AND ItemID=@ItemID) TabVend ON TabItem.ProcessID=TabVend.ProcessID
WHERE ((ItemSNo<@MinSNo AND ItemSNo>=@ItemSNo) OR (@MinSNo IS NULL AND ItemSNo>=@ItemSNo)) --AND TabVend.ProcessID>=@ProcessID
ORDER BY ItemSNo
END
GO
