CREATE PROCEDURE [dbo].[OrderPlanningPurchaseLog_SP] (@CustCode VARCHAR(255)='',@Country VARCHAR(255),@ShipStatus INT=4,@DTFrom DATETIME,@DTTo DATETIME) AS

--Status; 0=Unshipped;1=Shipped;2=Cancelled;3=Hold;4=All Orders

BEGIN
	DECLARE @myTBL TABLE(OrderNo VARCHAR(255),DeliveryDT DATETIME)
	IF @ShipStatus=0
		INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
			AND DT BETWEEN @DTFrom AND @DTTo
			AND (TotalShippedQty<TotalOrderQty AND Cancelled IS NULL)
	ELSE IF @ShipStatus=1
		INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
			AND DT BETWEEN @DTFrom AND @DTTo
			AND (TotalShippedQty=TotalOrderQty OR Cancelled=0)
	ELSE IF @ShipStatus=2
		INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
			AND DT BETWEEN @DTFrom AND @DTTo
			AND (Cancelled=1)
	ELSE IF @ShipStatus=3
		INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
			AND DT BETWEEN @DTFrom AND @DTTo
			AND (Cancelled=2)
	ELSE
		INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
			AND DT BETWEEN @DTFrom AND @DTTo


	SELECT CustCode,FCustomerOrders.OrderNo,FCustomerOrders.DeliveryDT,InternalRefNo,TotalOrderitems,TotalOrderQty,TotalPurItems,TotalPurQty,TotalRcvItems,TotalRcvQty,TotalProdItems,TotalProdQty,TotalPacItems,TotalPacQty,TotalTRFItems,TotalTRFQty,FCustomerOrders.DT FROM FCustomerOrders
	INNER JOIN @myTBL myTBL ON FCustomerOrders.OrderNo=myTBL.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(*) AS TotalOrderItems,SUM(Qty) AS TotalOrderQty FROM FOrderItems GROUP BY OrderNo) TOrd ON FCustomerOrders.OrderNo=TOrd.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPurItems,SUM(IssQty) AS TotalPurQty FROM VendIssued INNER JOIN VendIssdDetail ON VendIssued.EntryID=VendIssdDetail.RefID
		WHERE MasterPONo IS NOT NULL AND IssQty>RcvdQty GROUP BY OrderNo) TPur ON FCustomerOrders.OrderNo=TPur.OrderNo
	LEFT OUTER JOIN(SELECT VendRcvdDetail.OrderNo,COUNT(DISTINCT VendRcvdDetail.ItemCode) AS TotalRcvItems,SUM(VendIssdDetail.IssQty-VendRcvdDetail.RcvdQty) AS TotalRcvQty FROM VendReceived INNER JOIN VendRcvdDetail ON VendReceived.EntryID=VendRcvdDetail.RefID  INNER JOIN VendIssdDetail ON VendRcvdDetail.Issue_RefID=VendIssdDetail.EntryID
		INNER JOIN VendIssued ON VendReceived.Issuance_RefID=VendIssued.EntryID  WHERE MasterPONo IS NOT NULL GROUP BY VendRcvdDetail.OrderNo) TRcv ON FCustomerOrders.OrderNo=TRcv.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalProdItems,SUM(Qty) AS TotalProdQty FROM VRunningLots_Simple GROUP BY OrderNo) TProd ON FCustomerOrders.OrderNo=TProd.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPacItems,SUM(Qty)  AS TotalPacQty FROM VDispatchListDetail_Adv GROUP BY OrderNo) TPac ON FCustomerOrders.OrderNo=TPac.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DIsTINCT ItemCode) AS TotalTRFItems,SUM(Qty) AS TotalTRFQty FROM TransferredToReadyFinishLotsDetail INNER JOIN VendRcvdDetail
		ON VendRcvdDetail.EntryID=TransferredToReadyFinishLotsDetail.VRD_RefID GROUP BY OrderNo) TRF ON FCustomerOrders.OrderNo=TRF.OrderNo
END
GO
/****** Object:  StoredProcedure [dbo].[OrderPlanningReport_SP]    Script Date: 6/29/2026 4:50:02 PM ******/
SET ANSI_NULLS ON
GO
