CREATE PROCEDURE [dbo].[OrderPlanningReport_SP] (@OrderNo AS VARCHAR(255)=NULL,@FromItems AS BIT=0,@DTFrom AS DATETIME=NULL,@DTTo AS DATETIME=NULL,@CustCode AS VARCHAR(50)=NULL,@Country AS VARCHAR(50)=NULL,@NoDelivery AS BIT=0,@Both AS BIT=0,@ItemCode AS VARCHAR(4000)='0',@Urgent AS BIT=0,@GroupID AS INT=0,@templist_refid AS int=0) AS

BEGIN


SET ARITHABORT ON

DECLARE @myTBL TABLE(ItemID VARCHAR(255),ItemName VARCHAR(1000),Qty INT,OrderNo VARCHAR(255),CompItemCode VARCHAR(1000),InHand INT,SFQty INT,ForgingStock INT,QtyToRcv INT,TotalOrdersQty INT,MinLevel INT,InProcessLotsQty INT,InProcessLotsQtyB4 INT,OpenPOQty INT,RMID INT,Description VARCHAR(255),RMID1 VARCHAR(255),ItemFrequency INT,ItemCode VARCHAR(255),OrderDT DATETIME,OrderDeliveryDT DATETIME,OrderFinishing VARCHAR(255),SpecialInstructions VARCHAR(1000),TotalCurrentOrderQty INT,InternalRefNo VARCHAR(255),ItemQuality VARCHAR(255),CustItemCode VARCHAR(255),CustCode VARCHAR(255),DeliveryDTItem DATETIME,DeliveryStatus INT,ItemSize VARCHAR(255),SizeUnit VARCHAR(255),ItemGroup VARCHAR(255),Remarks VARCHAR(255),CustomerHits INT,CustomerQty INT,AllHits INT,AllQty INT,InProcessLotsQtyStock INT,InProcessLotsQtyB4Stock INT,OpenPOQtyStock INT,Plan_Qty INT,Plan_PONO VARCHAR(50),Plan_Vendor VARCHAR(255),Plan_Process VARCHAR(255),Plan_TargetDT DATETIME,Plan_Rate REAL,AdjQty INT,DispatchedQty INT,Forging_Multiple VARCHAR(1000),Item_Finishing_Type_Text VARCHAR(50))

IF @ItemCode<>'0'

	BEGIN
	CREATE TABLE #myTBL (ItemCode VARCHAR(50))
	DECLARE @myQuery AS VARCHAR(1000)
	SET @myQuery='INSERT INTO #myTBL(ItemCode) SELECT ItemID FROM Items WHERE ItemID IN(' + @ItemCode  +')'
	EXEC(@myQuery)
	INSERT INTO @myTBL

	SELECT VItems.ItemID,VItems.ItemName,Qty,VFOrderItems.OrderNo,VFOrderItems.CompItemCode,VItems.InHand,TabSF.SFQty,ForgingStock,QtyToRcv,TotalOrdersQty,MinLevel,InProcessLotsQty,InProcessLotsQtyB4,OpenPOQty,TabForgingStock.RMID,TabForgingStock.Description,RMID1,0,'' AS ItemCode,NULL AS OrderDT,NULL AS OrderDeliveryDT,'' AS FinQuality,'' AS Packaging,0,'' AS InternalRefNo,'' AS OrderFinishing,VFOrderItems.ItemCode,CustCode,DeliveryDT,DeliveryStatus,ItemSize,SizeUnit,ItemGroup,Remarks,0,0,0,0,0,0,0,0,'','','',NULL,0,0,0,'' AS Forging_Multiple,'' FROM VItems
		LEFT OUTER JOIN (SELECT VFOrderItems.CustCode,VFOrderItems.ItemCode,VFOrderItems.OrderNo,Qty,CompItemCode,ShippedQty,DeliveryDT,DeliveryStatus,Remarks FROM VFOrderItems INNER JOIN VUnshippedOrderList ON VFOrderItems.OrderNo=VUnshippedOrderList.OrderNo WHERE (Qty>ShippedQty)) VFOrderItems ON VItems.ItemID=VFOrderItems.CompItemCode
		LEFT OUTER JOIN (SELECT VStockOrderOpening.ItemID AS ItemCode,SUM(Qty-IssdQty) AS SFQty FROM VendRcvdDetail INNER JOIN VStockOrderOpening ON VendRcvdDetail.Opening_RefID=VStockOrderOpening.EntryID WHERE NextProcessID IS NOT NULL AND Opening_RefID IS NOT NULL AND Shelf_RefID<>0  AND Qty>IssdQty GROUP BY VStockOrderOpening.ItemID) TabSF ON VFOrderItems.CompItemCode=TabSF.ItemCode
		LEFT OUTER JOIN (SELECT ItemID,RMID,RMID1,Description,QtyInStock AS ForgingStock FROM VItemsRMComp WHERE EntryID IN(
			SELECT MAX(EntryID) FROM VItemsRMComp INNER JOIN (SELECT ItemID,MIN(QtyInStock) AS QtyInStock FROM VItemsRMComp INNER JOIN RMGroupIDsForForging ON GroupID=Group_ID GROUP BY ItemID) T1
			ON VItemsRMComp.ItemID=T1.ItemID AND VItemsRMComp.QtyInStock=T1.QtyInStock  GROUP BY VItemsRMComp.ItemID) ) TabForgingStock ON VFOrderItems.CompItemCode=TabForgingStock.ItemID

		LEFT OUTER JOIN (SELECT ItemID,RM.RMID,SUM(QtyToRcv) AS QtyToRcv FROM VVendOrdersToRcv INNER JOIN RM ON RM.RMID1=VVendOrdersToRcv.RMID1 INNER JOIN ItemsRMComp ON RM.RMID=ItemsRMComp.RMID GROUP BY RM.RMID,ItemID) TabPO
			ON VFOrderItems.CompItemCode=TabPO.ItemID AND TabForgingStock.RMID=TabPO.RMID
		LEFT OUTER JOIN
			(SELECT ItemCode,SUM(QtyB4) AS InProcessLotsQtyB4,SUM(Qty) AS InProcessLotsQty FROM
			(SELECT VVendIssdDetail.ItemCode,SUM(CASE WHEN SNo<=ISNULL(PolishingItemSNo,0) THEN IssQty-RcvdQty ELSE 0 END) AS QtyB4,SUM(CASE WHEN SNo>ISNULL(PolishingItemSNo,0) THEN IssQty-RcvdQty ELSE 0 END) AS Qty FROM VVendIssdDetail LEFT OUTER JOIN VItemPolishingProcessSNo ON VItemPolishingProcessSNo.ItemCode=VVendIssdDetail.ItemCode WHERE LotNo<>'0' AND IssQty-RcvdQty>0 AND EntryID NOT IN(SELECT Issue_RefID FROM VendRcvdDetail)  GROUP BY VVendIssdDetail.ItemCode					UNION ALL
			SELECT VVendRcvdDetail_Simple.ItemCode,SUM(CASE WHEN SNo<=ISNULL(PolishingItemSNo,0) THEN RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0) ELSE 0 END) AS QtyB4,SUM(CASE WHEN SNo>ISNULL(PolishingItemSNo,0) THEN RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0) ELSE 0 END) AS Qty FROM VVendRcvdDetail_Simple LEFT OUTER JOIN VItemPolishingProcessSNo ON VItemPolishingProcessSNo.ItemCode=VVendRcvdDetail_Simple.ItemCode WHERE LotNo<>'0' AND RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0)>0 AND EntryID NOT IN(SELECT Rcvd_RefID FROM VendIssdDetail) AND ISNULL(Opening_RefID,0)=0 GROUP BY VVendRcvdDetail_Simple.ItemCode) Tab1 GROUP BY ItemCode) TabLots ON VFOrderItems.CompItemCode=TabLots.ItemCode
		LEFT OUTER JOIN (SELECT ItemCode,SUM(CASE WHEN IssQty-RcvdQty>0 THEN IssQty-RcvdQty ELSE 0 END) AS OpenPOQty FROM VendIssdDetail WHERE ISNULL(LotNo,'')='' OR LotNo='0' GROUP BY ItemCode) TabOpenPO ON VFOrderItems.CompItemCode=TabOpenPO.ItemCode
		LEFT OUTER  JOIN (SELECT CompItemCode,SUM(Qty-ShippedQty) AS TotalOrdersQty FROM VFOrderItems WHERE OrderNo NOT IN('Stock-Order','Stock-OrderIss') AND OrderNo IN(SELECT OrderNo FROM VUnshippedOrderList) GROUP BY CompItemCode HAVING SUM(Qty-ShippedQty)>0) TabAllOrders ON VFOrderItems.CompItemCode=TabAllOrders.CompItemCode


	INNER JOIN #myTBL myTBL ON VFOrderItems.CompItemCode=myTBL.ItemCode

	ORDER BY VItems.ItemID

	END
ELSE IF @FromItems=0
	BEGIN

	DECLARE @OrderDT AS DATETIME,@MyCustCode AS VARCHAR(50)
	SELECT @OrderDT=DT FROM FCustomerOrders WHERE OrderNo=@OrderNo

	/*IF MONTH(@OrderDT)<7
		BEGIN
			SET @DTFrom='7/1/' + CAST(YEAR(@OrderDT)-1 AS VARCHAR)
			SET @DTTo='6/30/' + CAST(YEAR(@OrderDT) AS VARCHAR)
		END
	ELSE
		BEGIN
			SET @DTFrom='7/1/' + CAST(YEAR(@OrderDT) AS VARCHAR)
			SET @DTTo='6/30/' + CAST(YEAR(@OrderDT)+1 AS VARCHAR)
		END*/
	/*SET @DTFrom='1/1/' + CAST(YEAR(@OrderDT) AS VARCHAR)
	SET @DTTo='12/31/' + CAST(YEAR(@OrderDT) AS VARCHAR)*/
	SET @DTFrom=DATEADD(m,-12,@OrderDT)
	SET @DTTo=@OrderDT
	DECLARE @HistoryDTFrom AS DATETIME,@HistoryDTTo AS DATETIME
	SET @HistoryDTFrom=CAST('1/1/'+CAST(YEAR(@OrderDT)-1 AS VARCHAR(4)) AS DATETIME)
	SET @HistoryDTTo=CAST('12/31/'+CAST(YEAR(@OrderDT)-1 AS VARCHAR(4)) AS DATETIME)

	INSERT INTO @myTBL
	SELECT Items.ItemID,Items.ItemName,VFOrderItems.Qty,VFOrderItems.OrderNo,VFOrderItems.CompItemCode, Items.InHand,VItems_StockReport.SFStock AS SFQty,TabForgingStock.ForgingStock,QtyToRcv,TotalOrdersQty,Items.MinLevel,InProcessLotsQty,InProcessLotsQtyB4,OpenPOQty,TabForgingStock.RMID,TabForgingStock.Description,RMID1,ItemFrequency,VFOrderItems.ItemCode,DT AS OrderDT,OrderDeliveryDT,Quality,Packaging,TotalCurrentOrderQty,InternalRefNo,ItemQuality,VFOrderItems.ItemCode,CustCode,VFOrderItems.DeliveryDT,DeliveryStatus,VFOrderItems.ItemSize,VFOrderItems.SizeUnit,Items.ItemGroup,Remarks,CustomerHits,CustomerQty,AllHits,AllQty,InProcessLotsQtyStock,InProcessLotsQtyB4Stock,OpenPOQtyStock,TPlan.Qty,TPlan.PONo,TPlan.VenderName,TPlan.Description,TPlan.DeliveryDT,TPlan.Rate,TAdj.AdjQty,DispatchedQty,Forging_Multiple,VFOrderItems.Item_Finishing_Type_Text FROM VrptOrders_ForProduction_Reports AS VFOrderItems
		LEFT OUTER JOIN VItems_WithFinishedStock_Simple Items ON VFOrderItems.CompItemCode=Items.ItemID
		--LEFT OUTER JOIN (SELECT VStockOrderOpening.ItemID AS ItemCode,SUM(Qty-IssdQty) AS SFQty FROM VendRcvdDetail INNER JOIN VStockOrderOpening ON VendRcvdDetail.Opening_RefID=VStockOrderOpening.EntryID WHERE NextProcessID IS NOT NULL AND Opening_RefID IS NOT NULL AND Shelf_RefID<>0  AND Qty>IssdQty GROUP BY VStockOrderOpening.ItemID) TabSF ON VFOrderItems.CompItemCode=TabSF.ItemCode
		LEFT OUTER JOIN VItems_StockReport ON Items.ItemID=VItems_StockReport.ItemID
		--LEFT OUTER JOIN (SELECT ItemID,MIN(QtyInStock) AS ForgingStock FROM VRM INNER JOIN ItemsRMComp ON ItemsRMComp.RMID=VRM.RMID GROUP BY ItemID) TabForgingStock ON VFOrderItems.CompItemCode=TabForgingStock.ItemID
		LEFT OUTER JOIN (SELECT ItemID,RMID,RMID1,Description,QtyInStock AS ForgingStock FROM VItemsRMComp WHERE EntryID IN(
		SELECT MAX(EntryID) FROM VItemsRMComp INNER JOIN (SELECT ItemID,MIN(QtyInStock) AS QtyInStock FROM VItemsRMComp WHERE GroupID IN(SELECT Group_ID FROM RMGroupIDsForForging) GROUP BY ItemID) T1
		ON VItemsRMComp.ItemID=T1.ItemID AND VItemsRMComp.QtyInStock=T1.QtyInStock  GROUP BY VItemsRMComp.ItemID) ) TabForgingStock ON VFOrderItems.CompItemCode=TabForgingStock.ItemID
		LEFT OUTER JOIN (SELECT ItemID,RM.RMID,SUM(QtyToRcv) AS QtyToRcv FROM VVendOrdersToRcv INNER JOIN RM ON RM.RMID1=VVendOrdersToRcv.RMID1 INNER JOIN ItemsRMComp ON RM.RMID=ItemsRMComp.RMID GROUP BY RM.RMID,ItemID) TabPO
		ON VFOrderItems.CompItemCode=TabPO.ItemID AND TabForgingStock.RMID=TabPO.RMID
		LEFT OUTER JOIN
		(SELECT ItemCode
				--,SUM(CASE WHEN CustCode IN('Stock','PHF') THEN 0 ELSE QtyB4 END) AS InProcessLotsQtyB4
				,SUM(CASE WHEN OrderNo=@OrderNo THEN QtyB4 ELSE 0 END) AS InProcessLotsQtyB4
				,SUM(CASE WHEN CustCode NOT IN('Stock','PHF') THEN 0 ELSE QtyB4 END) AS InProcessLotsQtyB4Stock
				--,SUM(CASE WHEN CustCode IN('Stock','PHF') THEN 0 ELSE Qty END) AS InProcessLotsQty
				,SUM(CASE WHEN OrderNo=@OrderNo THEN Qty ELSE 0 END) AS InProcessLotsQty
				,SUM(CASE WHEN CustCode NOT IN('Stock','PHF') THEN 0 ELSE Qty END) AS InProcessLotsQtyStock


FROM
		(SELECT CustCode,VVendIssdDetail.ItemCode,VVendIssdDetail.OrderNo,SUM(CASE WHEN SNo<=ISNULL(PolishingItemSNo,0) THEN IssQty-RcvdQty ELSE 0 END) AS QtyB4,SUM(CASE WHEN SNo>ISNULL(PolishingItemSNo,0) THEN IssQty-RcvdQty ELSE 0 END) AS Qty FROM VVendIssdDetail LEFT OUTER JOIN VItemPolishingProcessSNo ON VItemPolishingProcessSNo.ItemCode=VVendIssdDetail.ItemCode WHERE LotNo<>'0' AND IssQty-RcvdQty>0 AND EntryID NOT IN(SELECT Issue_RefID FROM VendRcvdDetail)  GROUP BY VVendIssdDetail.ItemCode,CustCode,VVendIssdDetail.OrderNo
					UNION ALL
		SELECT CustCode,VVendRcvdDetail_Simple.ItemCode,VVendRcvdDetail_Simple.OrderNo,SUM(CASE WHEN SNo<=ISNULL(PolishingItemSNo,0) THEN RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0) ELSE 0 END) AS QtyB4,SUM(CASE WHEN SNo>ISNULL(PolishingItemSNo,0) THEN RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0) ELSE 0 END) AS Qty FROM VVendRcvdDetail_Simple LEFT OUTER JOIN VItemPolishingProcessSNo ON VItemPolishingProcessSNo.ItemCode=VVendRcvdDetail_Simple.ItemCode WHERE LotNo<>'0' AND RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0)>0 AND EntryID NOT IN(SELECT Rcvd_RefID FROM VendIssdDetail) AND ISNULL(Opening_RefID,0)=0 GROUP BY VVendRcvdDetail_Simple.ItemCode,CustCode,VVendRcvdDetail_Simple.OrderNo) Tab1 GROUP BY ItemCode) TabLots ON VFOrderItems.CompItemCode=TabLots.ItemCode

		LEFT OUTER JOIN (SELECT ItemCode,SUM(CASE WHEN IssQty-RcvdQty>0 AND CustCode NOT IN('Stock','PHF') THEN IssQty-RcvdQty ELSE 0 END) AS OpenPOQty,SUM(CASE WHEN IssQty-RcvdQty>0 AND CustCode IN('Stock','PHF') THEN IssQty-RcvdQty ELSE 0 END) AS OpenPOQtyStock FROM VendIssdDetail INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=VendIssdDetail.OrderNo WHERE ISNULL(LotNo,'')='' OR LotNo='0' GROUP BY ItemCode) TabOpenPO ON VFOrderItems.CompItemCode=TabOpenPO.ItemCode
		LEFT OUTER JOIN (SELECT CompItemCode,SUM(Qty-ShippedQty) AS TotalOrdersQty FROM VFOrderItems WHERE OrderNo NOT IN('Stock-Order','Stock-OrderIss') AND OrderNo IN(SELECT OrderNo FROM VUnshippedOrderList) GROUP BY CompItemCode HAVING SUM(Qty-ShippedQty)>0) TabAllOrders ON VFOrderItems.CompItemCode=TabAllOrders.CompItemCode
		LEFT OUTER JOIN (SELECT CompItemCode,COUNT(CompItemCode) ItemFrequency FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo WHERE FCustomerOrders.OrderNo NOT IN('Stock-Order','Stock-OrderIss') AND DT BETWEEN @DTFrom AND @DTTo GROUP BY FOrderItems.CompItemCode) TFrequency ON VFOrderItems.CompItemCode=TFrequency.CompItemCode
		LEFT OUTER JOIN(SELECT CompItemCode,COUNT(CompitemCode) CustomerHits,SUM(Qty) AS CustomerQty FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerORders.OrderNo=FOrderItems.OrderNo WHERE CustCode=@MyCustCode GROUP BY CompItemCode) TCustomerHits ON VFOrderItems.CompItemCode=TCustomerHits.CompItemCode
		LEFT OUTER JOIN(SELECT CompItemCode,COUNT(CompitemCode) AllHits,SUM(Qty) AS AllQty FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerORders.OrderNo=FOrderItems.OrderNo
			--WHERE DT BETWEEN @HistoryDTFrom AND @HistoryDTTo AND
			WHERE
			CustCode NOT IN('Stock','PHF','SAL') GROUP BY CompItemCode) TAllHits ON VFOrderItems.CompItemCode=TAllHits.CompItemCode
		LEFT OUTER JOIN (SELECT OrderNo AS TOrderNo,SUM(Qty) AS TotalCurrentOrderQty FROM FOrderItems GROUP BY OrderNo) TCurrentOrder ON VFOrderItems.OrderNo=TCurrentOrder.TOrderNo
		--LEFT OUTER JOIN(SELECT ItemID,SUM(NetQty) AS NetQty FROM VItemsWithShelfWiseStock GROUP BY ItemID) TFinishedStock ON Items.ItemID=TFinishedStock.ItemID
		LEFT JOIN (SELECT OrderNo,ItemID,VendID1,Qty,Description,Rate,DeliveryDT,'' AS PONo,VenderName  FROM VOrderPlanningDetails) TPlan ON VFOrderItems.OrderNo=TPlan.OrderNo AND VFOrderItems.CompItemCode=TPlan.ItemID
		LEFT JOIN (SELECT OrderNo,ItemID,SUM(Qty) AS AdjQty FROM StockOrderAdjustments GROUP BY OrderNo,ItemID) TAdj ON VFOrderItems.OrderNo=TAdj.OrderNo AND VFOrderItems.CompItemCode=TAdj.ItemID
		LEFT JOIN (SELECT OrderNo,ItemCode,SUM(DispatchListDetail_VRD.Qty) AS DispatchedQty FROM DispatchListDetail_VRD INNER JOIN VendRcvdDetail ON DispatchListDetail_VRD.VRD_RefID=VendRcvdDetail.EntryID GROUP BY OrderNo,ItemCode) TDis ON VFOrderItems.OrderNo=TDis.OrderNo AND VFOrderItems.CompItemCode=TDis.ItemCode
		LEFT JOIN (SELECT DISTINCT ItemID,
					(STUFF((SELECT CAST(QtyInStock AS VARCHAR(50)),CHAR(13)+CHAR(10) FROM VItemsRMComp T1
					WHERE GroupID IN(SELECT Group_ID FROM RMGroupIDsForForging)
					AND T1.ItemID=T2.ItemID
					FOR XML PATH(''),TYPE,ROOT).value('root[1]','varchar(max)'),1,0,'')) AS Forging_Multiple
					FROM VItemsRMComp T2) TForging_Multiple ON VFOrderItems.CompItemCode=TForging_Multiple.ItemID
	WHERE VFOrderItems.OrderNo=@OrderNo
	AND (VFOrderItems.Qty>ISNULL(ShippedQty,0))
	END

ELSE IF @Urgent=1

	INSERT INTO @myTBL
	SELECT Items.ItemID,Items.ItemName,Qty,OrderNo,VFOrderItems.CompItemCode,InHand,TabSF.SFQty,ForgingStock,QtyToRcv,TotalOrdersQty,MinLevel,InProcessLotsQty,InProcessLotsQtyB4,OpenPOQty,TabForgingStock.RMID,TabForgingStock.Description,RMID1,0,VFOrderItems.ItemCode,DT AS OrderDT,OrderDeliveryDT,Quality,Packaging,TotalCurrentOrderQty,InternalRefNo,ItemQuality,VFOrderItems.ItemCode,CustCode,DeliveryDT,DeliveryStatus,ItemSize,SizeUnit,ItemGroup,Remarks,0,0,0,0,0,0,0,0,'','','',NULL,0,0,0,'' AS Forging_Multiple,''     FROM VFOrderItems
		INNER JOIN VItems_WithFinishedStock_Simple Items ON VFOrderItems.CompItemCode=Items.ItemID
		LEFT OUTER JOIN (SELECT VStockOrderOpening.ItemID AS ItemCode,SUM(Qty-IssdQty) AS SFQty FROM VendRcvdDetail INNER JOIN VStockOrderOpening ON VendRcvdDetail.Opening_RefID=VStockOrderOpening.EntryID WHERE NextProcessID IS NOT NULL AND Opening_RefID IS NOT NULL AND Shelf_RefID<>0  AND Qty>IssdQty GROUP BY VStockOrderOpening.ItemID) TabSF ON VFOrderItems.CompItemCode=TabSF.ItemCode
		--LEFT OUTER JOIN (SELECT ItemID,MIN(QtyInStock) AS ForgingStock FROM VRM INNER JOIN ItemsRMComp ON ItemsRMComp.RMID=VRM.RMID GROUP BY ItemID) TabForgingStock ON VFOrderItems.CompItemCode=TabForgingStock.ItemID
		LEFT OUTER JOIN (SELECT ItemID,RMID,RMID1,Description,QtyInStock AS ForgingStock FROM VItemsRMComp WHERE EntryID IN(
		SELECT MAX(EntryID) FROM VItemsRMComp INNER JOIN (SELECT ItemID,MIN(QtyInStock) AS QtyInStock FROM VItemsRMComp WHERE GroupID IN(SELECT Group_ID FROM RMGroupIDsForForging) GROUP BY ItemID) T1
		ON VItemsRMComp.ItemID=T1.ItemID AND VItemsRMComp.QtyInStock=T1.QtyInStock  GROUP BY VItemsRMComp.ItemID) ) TabForgingStock ON VFOrderItems.CompItemCode=TabForgingStock.ItemID
		LEFT OUTER JOIN (SELECT ItemID,RM.RMID,SUM(QtyToRcv) AS QtyToRcv FROM VVendOrdersToRcv INNER JOIN RM ON RM.RMID1=VVendOrdersToRcv.RMID1 INNER JOIN ItemsRMComp ON RM.RMID=ItemsRMComp.RMID GROUP BY RM.RMID,ItemID) TabPO
		ON VFOrderItems.CompItemCode=TabPO.ItemID AND TabForgingStock.RMID=TabPO.RMID
		LEFT OUTER JOIN
		(SELECT ItemCode,SUM(QtyB4) AS InProcessLotsQtyB4,SUM(Qty) AS InProcessLotsQty FROM
		(SELECT VVendIssdDetail.ItemCode,SUM(CASE WHEN SNo<=ISNULL(PolishingItemSNo,0) THEN IssQty-RcvdQty ELSE 0 END) AS QtyB4,SUM(CASE WHEN SNo>ISNULL(PolishingItemSNo,0) THEN IssQty-RcvdQty ELSE 0 END) AS Qty FROM VVendIssdDetail LEFT OUTER JOIN VItemPolishingProcessSNo ON VItemPolishingProcessSNo.ItemCode=VVendIssdDetail.ItemCode WHERE LotNo<>'0' AND IssQty-RcvdQty>0 AND EntryID NOT IN(SELECT Issue_RefID FROM VendRcvdDetail)  GROUP BY VVendIssdDetail.ItemCode
					UNION ALL
		SELECT VVendRcvdDetail_Simple.ItemCode,SUM(CASE WHEN SNo<=ISNULL(PolishingItemSNo,0) THEN RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0) ELSE 0 END) AS QtyB4,SUM(CASE WHEN SNo>ISNULL(PolishingItemSNo,0) THEN RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0) ELSE 0 END) AS Qty FROM VVendRcvdDetail_Simple LEFT OUTER JOIN VItemPolishingProcessSNo ON VItemPolishingProcessSNo.ItemCode=VVendRcvdDetail_Simple.ItemCode WHERE LotNo<>'0' AND RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0)>0 AND EntryID NOT IN(SELECT Rcvd_RefID FROM VendIssdDetail) AND ISNULL(Opening_RefID,0)=0 GROUP BY VVendRcvdDetail_Simple.ItemCode) Tab1 GROUP BY ItemCode) TabLots ON VFOrderItems.CompItemCode=TabLots.ItemCode
		LEFT OUTER JOIN (SELECT ItemCode,SUM(CASE WHEN IssQty-RcvdQty>0 THEN IssQty-RcvdQty ELSE 0 END) AS OpenPOQty FROM VendIssdDetail WHERE ISNULL(LotNo,'')='' OR LotNo='0' GROUP BY ItemCode) TabOpenPO ON VFOrderItems.CompItemCode=TabOpenPO.ItemCode
		INNER JOIN (SELECT CompItemCode,SUM(Qty-ShippedQty) AS TotalOrdersQty FROM VFOrderItems WHERE OrderNo NOT IN('Stock-Order','Stock-OrderIss') AND OrderNo IN(SELECT OrderNo FROM VUnshippedOrderList) GROUP BY CompItemCode HAVING SUM(Qty-ShippedQty)>0) TabAllOrders ON VFOrderItems.CompItemCode=TabAllOrders.CompItemCode
		LEFT OUTER JOIN (SELECT OrderNo AS TOrderNo,SUM(Qty) AS TotalCurrentOrderQty FROM FOrderItems GROUP BY OrderNo) TCurrentOrder ON VFOrderItems.OrderNo=TCurrentOrder.TOrderNo
		--LEFT OUTER JOIN(SELECT ItemID,SUM(NetQty) AS NetQty FROM VItemsWithShelfWiseStock GROUP BY ItemID) TFinishedStock ON Items.ItemID=TFinishedStock.ItemID
	WHERE (DeliveryStatus=2 OR Remarks<>'')
	AND (CustCode=@CustCode OR @CustCode IS NULL) AND (Country=@Country OR @Country IS NULL)
	AND OrderNo IN(SELECT OrderNo FROM VUnshippedOrderList)  AND (Qty>ShippedQty)
	AND (Items.GroupID=@GroupID OR @GroupID=0)
	ORDER BY Items.ItemID

ELSE IF @Both=1
	INSERT INTO @myTBL
	SELECT Items.ItemID,Items.ItemName,Qty,OrderNo,VFOrderItems.CompItemCode,InHand,TabSF.SFQty,ForgingStock,QtyToRcv,TotalOrdersQty,MinLevel,InProcessLotsQty,InProcessLotsQtyB4,OpenPOQty,TabForgingStock.RMID,TabForgingStock.Description,RMID1,0,VFOrderItems.ItemCode,DT AS OrderDT,OrderDeliveryDT,Quality,Packaging,TotalCurrentOrderQty,InternalRefNo,ItemQuality,VFOrderItems.ItemCode,CustCode,DeliveryDT,DeliveryStatus,ItemSize,SizeUnit,ItemGroup,Remarks,0,0,0,0,0,0,0,0,'','','',NULL,0,0,0,'' AS Forging_Multiple,''    FROM VFOrderItems
		INNER JOIN VItems_WithFinishedStock_Simple Items ON VFOrderItems.CompItemCode=Items.ItemID
		LEFT OUTER JOIN (SELECT VStockOrderOpening.ItemID AS ItemCode,SUM(Qty-IssdQty) AS SFQty FROM VendRcvdDetail INNER JOIN VStockOrderOpening ON VendRcvdDetail.Opening_RefID=VStockOrderOpening.EntryID WHERE NextProcessID IS NOT NULL AND Opening_RefID IS NOT NULL AND Shelf_RefID<>0  AND Qty>IssdQty GROUP BY VStockOrderOpening.ItemID) TabSF ON VFOrderItems.CompItemCode=TabSF.ItemCode
		--LEFT OUTER JOIN (SELECT ItemID,MIN(QtyInStock) AS ForgingStock FROM VRM INNER JOIN ItemsRMComp ON ItemsRMComp.RMID=VRM.RMID GROUP BY ItemID) TabForgingStock ON VFOrderItems.CompItemCode=TabForgingStock.ItemID
		LEFT OUTER JOIN (SELECT ItemID,RMID,RMID1,Description,QtyInStock AS ForgingStock FROM VItemsRMComp WHERE EntryID IN(
		SELECT MAX(EntryID) FROM VItemsRMComp INNER JOIN (SELECT ItemID,MIN(QtyInStock) AS QtyInStock FROM VItemsRMComp WHERE GroupID IN(SELECT Group_ID FROM RMGroupIDsForForging) GROUP BY ItemID) T1
		ON VItemsRMComp.ItemID=T1.ItemID AND VItemsRMComp.QtyInStock=T1.QtyInStock  GROUP BY VItemsRMComp.ItemID) ) TabForgingStock ON VFOrderItems.CompItemCode=TabForgingStock.ItemID
		LEFT OUTER JOIN (SELECT ItemID,RM.RMID,SUM(QtyToRcv) AS QtyToRcv FROM VVendOrdersToRcv INNER JOIN RM ON RM.RMID1=VVendOrdersToRcv.RMID1 INNER JOIN ItemsRMComp ON RM.RMID=ItemsRMComp.RMID GROUP BY RM.RMID,ItemID) TabPO
		ON VFOrderItems.CompItemCode=TabPO.ItemID AND TabForgingStock.RMID=TabPO.RMID
		LEFT OUTER JOIN
		(SELECT ItemCode,SUM(QtyB4) AS InProcessLotsQtyB4,SUM(Qty) AS InProcessLotsQty FROM
		(SELECT VVendIssdDetail.ItemCode,SUM(CASE WHEN SNo<=ISNULL(PolishingItemSNo,0) THEN IssQty-RcvdQty ELSE 0 END) AS QtyB4,SUM(CASE WHEN SNo>ISNULL(PolishingItemSNo,0) THEN IssQty-RcvdQty ELSE 0 END) AS Qty FROM VVendIssdDetail LEFT OUTER JOIN VItemPolishingProcessSNo ON VItemPolishingProcessSNo.ItemCode=VVendIssdDetail.ItemCode WHERE LotNo<>'0' AND IssQty-RcvdQty>0 AND EntryID NOT IN(SELECT Issue_RefID FROM VendRcvdDetail)  GROUP BY VVendIssdDetail.ItemCode
					UNION ALL
		SELECT VVendRcvdDetail_Simple.ItemCode,SUM(CASE WHEN SNo<=ISNULL(PolishingItemSNo,0) THEN RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0) ELSE 0 END) AS QtyB4,SUM(CASE WHEN SNo>ISNULL(PolishingItemSNo,0) THEN RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0) ELSE 0 END) AS Qty FROM VVendRcvdDetail_Simple LEFT OUTER JOIN VItemPolishingProcessSNo ON VItemPolishingProcessSNo.ItemCode=VVendRcvdDetail_Simple.ItemCode WHERE LotNo<>'0' AND RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0)>0 AND EntryID NOT IN(SELECT Rcvd_RefID FROM VendIssdDetail) AND ISNULL(Opening_RefID,0)=0 GROUP BY VVendRcvdDetail_Simple.ItemCode) Tab1 GROUP BY ItemCode) TabLots ON VFOrderItems.CompItemCode=TabLots.ItemCode
		LEFT OUTER JOIN (SELECT ItemCode,SUM(CASE WHEN IssQty-RcvdQty>0 THEN IssQty-RcvdQty ELSE 0 END) AS OpenPOQty FROM VendIssdDetail WHERE ISNULL(LotNo,'')='' OR LotNo='0' GROUP BY ItemCode) TabOpenPO ON VFOrderItems.CompItemCode=TabOpenPO.ItemCode
		INNER JOIN (SELECT CompItemCode,SUM(Qty-ShippedQty) AS TotalOrdersQty FROM VFOrderItems WHERE OrderNo NOT IN('Stock-Order','Stock-OrderIss') AND OrderNo IN(SELECT OrderNo FROM VUnshippedOrderList) GROUP BY CompItemCode HAVING SUM(Qty-ShippedQty)>0) TabAllOrders ON VFOrderItems.CompItemCode=TabAllOrders.CompItemCode
		LEFT OUTER JOIN (SELECT OrderNo AS TOrderNo,SUM(Qty) AS TotalCurrentOrderQty FROM FOrderItems GROUP BY OrderNo) TCurrentOrder ON VFOrderItems.OrderNo=TCurrentOrder.TOrderNo
		--LEFT OUTER JOIN(SELECT ItemID,SUM(NetQty) AS NetQty FROM VItemsWithShelfWiseStock GROUP BY ItemID) TFinishedStock ON Items.ItemID=TFinishedStock.ItemID

	WHERE (VFOrderItems.DeliveryDT BETWEEN @DTFrom AND @DTTo OR DeliveryStatus=0)
	AND (CustCode=@CustCode OR @CustCode IS NULL) AND (Country=@Country OR @Country IS NULL)
	AND OrderNo IN(SELECT OrderNo FROM VUnshippedOrderList)   AND (Qty>ShippedQty)
	AND (Items.GroupID=@GroupID OR @GroupID=0)
	ORDER BY Items.ItemID

ELSE IF @NoDelivery=1
	INSERT INTO @myTBL
	SELECT Items.ItemID,Items.ItemName,Qty,OrderNo,VFOrderItems.CompItemCode, InHand,TabSF.SFQty,ForgingStock,QtyToRcv,TotalOrdersQty,MinLevel,InProcessLotsQty,InProcessLotsQtyB4,OpenPOQty,TabForgingStock.RMID,TabForgingStock.Description,RMID1,0,VFOrderItems.ItemCode,DT AS OrderDT,OrderDeliveryDT,Quality,Packaging,TotalCurrentOrderQty,InternalRefNo,ItemQuality,VFOrderItems.ItemCode,CustCode,DeliveryDT,DeliveryStatus,ItemSize,SizeUnit,ItemGroup,Remarks,0,0,0,0,0,0,0,0,'','','',NULL,0,0,0,'' AS Forging_Multiple,''     FROM VFOrderItems
		INNER JOIN VItems_WithFinishedStock_Simple Items ON VFOrderItems.CompItemCode=Items.ItemID
		LEFT OUTER JOIN (SELECT VStockOrderOpening.ItemID AS ItemCode,SUM(Qty-IssdQty) AS SFQty FROM VendRcvdDetail INNER JOIN VStockOrderOpening ON VendRcvdDetail.Opening_RefID=VStockOrderOpening.EntryID WHERE NextProcessID IS NOT NULL AND Opening_RefID IS NOT NULL AND Shelf_RefID<>0  AND Qty>IssdQty GROUP BY VStockOrderOpening.ItemID) TabSF ON VFOrderItems.CompItemCode=TabSF.ItemCode
		--LEFT OUTER JOIN (SELECT ItemID,MIN(QtyInStock) AS ForgingStock FROM VRM INNER JOIN ItemsRMComp ON ItemsRMComp.RMID=VRM.RMID GROUP BY ItemID) TabForgingStock ON VFOrderItems.CompItemCode=TabForgingStock.ItemID
		LEFT OUTER JOIN (SELECT ItemID,RMID,RMID1,Description,QtyInStock AS ForgingStock FROM VItemsRMComp WHERE EntryID IN(
		SELECT MAX(EntryID) FROM VItemsRMComp INNER JOIN (SELECT ItemID,MIN(QtyInStock) AS QtyInStock FROM VItemsRMComp WHERE GroupID IN(SELECT Group_ID FROM RMGroupIDsForForging) GROUP BY ItemID) T1
		ON VItemsRMComp.ItemID=T1.ItemID AND VItemsRMComp.QtyInStock=T1.QtyInStock  GROUP BY VItemsRMComp.ItemID) ) TabForgingStock ON VFOrderItems.CompItemCode=TabForgingStock.ItemID
		LEFT OUTER JOIN (SELECT ItemID,RM.RMID,SUM(QtyToRcv) AS QtyToRcv FROM VVendOrdersToRcv INNER JOIN RM ON RM.RMID1=VVendOrdersToRcv.RMID1 INNER JOIN ItemsRMComp ON RM.RMID=ItemsRMComp.RMID GROUP BY RM.RMID,ItemID) TabPO
		ON VFOrderItems.CompItemCode=TabPO.ItemID AND TabForgingStock.RMID=TabPO.RMID
		LEFT OUTER JOIN
		(SELECT ItemCode,SUM(QtyB4) AS InProcessLotsQtyB4,SUM(Qty) AS InProcessLotsQty FROM
		(SELECT VVendIssdDetail.ItemCode,SUM(CASE WHEN SNo<=ISNULL(PolishingItemSNo,0) THEN IssQty-RcvdQty ELSE 0 END) AS QtyB4,SUM(CASE WHEN SNo>ISNULL(PolishingItemSNo,0) THEN IssQty-RcvdQty ELSE 0 END) AS Qty FROM VVendIssdDetail LEFT OUTER JOIN VItemPolishingProcessSNo ON VItemPolishingProcessSNo.ItemCode=VVendIssdDetail.ItemCode WHERE LotNo<>'0' AND IssQty-RcvdQty>0 AND EntryID NOT IN(SELECT Issue_RefID FROM VendRcvdDetail)  GROUP BY VVendIssdDetail.ItemCode
					UNION ALL
		SELECT VVendRcvdDetail_Simple.ItemCode,SUM(CASE WHEN SNo<=ISNULL(PolishingItemSNo,0) THEN RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0) ELSE 0 END) AS QtyB4,SUM(CASE WHEN SNo>ISNULL(PolishingItemSNo,0) THEN RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0) ELSE 0 END) AS Qty FROM VVendRcvdDetail_Simple LEFT OUTER JOIN VItemPolishingProcessSNo ON VItemPolishingProcessSNo.ItemCode=VVendRcvdDetail_Simple.ItemCode WHERE LotNo<>'0' AND RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0)>0 AND EntryID NOT IN(SELECT Rcvd_RefID FROM VendIssdDetail) AND ISNULL(Opening_RefID,0)=0 GROUP BY VVendRcvdDetail_Simple.ItemCode) Tab1 GROUP BY ItemCode) TabLots ON VFOrderItems.CompItemCode=TabLots.ItemCode
		LEFT OUTER JOIN (SELECT ItemCode,SUM(CASE WHEN IssQty-RcvdQty>0 THEN IssQty-RcvdQty ELSE 0 END) AS OpenPOQty FROM VendIssdDetail WHERE ISNULL(LotNo,'')='' OR LotNo='0' GROUP BY ItemCode) TabOpenPO ON VFOrderItems.CompItemCode=TabOpenPO.ItemCode
		INNER JOIN (SELECT CompItemCode,SUM(Qty-ShippedQty) AS TotalOrdersQty FROM VFOrderItems WHERE OrderNo NOT IN('Stock-Order','Stock-OrderIss') AND OrderNo IN(SELECT OrderNo FROM VUnshippedOrderList) GROUP BY CompItemCode HAVING SUM(Qty-ShippedQty)>0) TabAllOrders ON VFOrderItems.CompItemCode=TabAllOrders.CompItemCode
		LEFT OUTER JOIN (SELECT OrderNo AS TOrderNo,SUM(Qty) AS TotalCurrentOrderQty FROM FOrderItems GROUP BY OrderNo) TCurrentOrder ON VFOrderItems.OrderNo=TCurrentOrder.TOrderNo
		--LEFT OUTER JOIN(SELECT ItemID,SUM(NetQty) AS NetQty FROM VItemsWithShelfWiseStock GROUP BY ItemID) TFinishedStock ON Items.ItemID=TFinishedStock.ItemID
	WHERE DeliveryStatus=0
	AND (CustCode=@CustCode OR @CustCode IS NULL) AND (Country=@Country OR @Country IS NULL)
	AND OrderNo IN(SELECT OrderNo FROM VUnshippedOrderList)  AND (Qty>ShippedQty)
	AND (Items.GroupID=@GroupID OR @GroupID=0)
	ORDER BY Items.ItemID



ELSE
	INSERT INTO @myTBL
	SELECT Items.ItemID,Items.ItemName,Qty,OrderNo,VFOrderItems.CompItemCode,InHand,TabSF.SFQty,ForgingStock,QtyToRcv,TotalOrdersQty,MinLevel,InProcessLotsQty,InProcessLotsQtyB4,OpenPOQty,TabForgingStock.RMID,TabForgingStock.Description,RMID1,0,VFOrderItems.ItemCode,DT AS OrderDT,OrderDeliveryDT,Quality,Packaging,TotalCurrentOrderQty,InternalRefNo,ItemQuality,VFOrderItems.ItemCode,CustCode,DeliveryDT,DeliveryStatus,ItemSize,SizeUnit,ItemGroup,Remarks,0,0,0,0,0,0,0,0,'','','',NULL,0,0,0,'' AS Forging_Multiple,''     FROM VFOrderItems
		INNER JOIN VItems_WithFinishedStock_Simple Items ON VFOrderItems.CompItemCode=Items.ItemID
		LEFT OUTER JOIN (SELECT VStockOrderOpening.ItemID AS ItemCode,SUM(Qty-IssdQty) AS SFQty FROM VendRcvdDetail INNER JOIN VStockOrderOpening ON VendRcvdDetail.Opening_RefID=VStockOrderOpening.EntryID WHERE NextProcessID IS NOT NULL AND Opening_RefID IS NOT NULL AND Shelf_RefID<>0  AND Qty>IssdQty GROUP BY VStockOrderOpening.ItemID) TabSF ON VFOrderItems.CompItemCode=TabSF.ItemCode
		--LEFT OUTER JOIN (SELECT ItemID,MIN(QtyInStock) AS ForgingStock FROM VRM INNER JOIN ItemsRMComp ON ItemsRMComp.RMID=VRM.RMID GROUP BY ItemID) TabForgingStock ON VFOrderItems.CompItemCode=TabForgingStock.ItemID
		LEFT OUTER JOIN (SELECT ItemID,RMID,RMID1,Description,QtyInStock AS ForgingStock FROM VItemsRMComp WHERE EntryID IN(
		SELECT MAX(EntryID) FROM VItemsRMComp INNER JOIN (SELECT ItemID,MIN(QtyInStock) AS QtyInStock FROM VItemsRMComp WHERE GroupID IN(SELECT Group_ID FROM RMGroupIDsForForging) GROUP BY ItemID) T1
		ON VItemsRMComp.ItemID=T1.ItemID AND VItemsRMComp.QtyInStock=T1.QtyInStock  GROUP BY VItemsRMComp.ItemID) ) TabForgingStock ON VFOrderItems.CompItemCode=TabForgingStock.ItemID
		LEFT OUTER JOIN (SELECT ItemID,RM.RMID,SUM(QtyToRcv) AS QtyToRcv FROM VVendOrdersToRcv INNER JOIN RM ON RM.RMID1=VVendOrdersToRcv.RMID1 INNER JOIN ItemsRMComp ON RM.RMID=ItemsRMComp.RMID GROUP BY RM.RMID,ItemID) TabPO
		ON VFOrderItems.CompItemCode=TabPO.ItemID AND TabForgingStock.RMID=TabPO.RMID
		LEFT OUTER JOIN
(SELECT ItemCode,SUM(QtyB4) AS InProcessLotsQtyB4,SUM(Qty) AS InProcessLotsQty FROM
		(SELECT VVendIssdDetail.ItemCode,SUM(CASE WHEN SNo<=ISNULL(PolishingItemSNo,0) THEN IssQty-RcvdQty ELSE 0 END) AS QtyB4,SUM(CASE WHEN SNo>ISNULL(PolishingItemSNo,0) THEN IssQty-RcvdQty ELSE 0 END) AS Qty FROM VVendIssdDetail LEFT OUTER JOIN VItemPolishingProcessSNo ON VItemPolishingProcessSNo.ItemCode=VVendIssdDetail.ItemCode WHERE LotNo<>'0' AND IssQty-RcvdQty>0 AND EntryID NOT IN(SELECT Issue_RefID FROM VendRcvdDetail)  GROUP BY VVendIssdDetail.ItemCode
					UNION ALL
		SELECT VVendRcvdDetail_Simple.ItemCode,SUM(CASE WHEN SNo<=ISNULL(PolishingItemSNo,0) THEN RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0) ELSE 0 END) AS QtyB4,SUM(CASE WHEN SNo>ISNULL(PolishingItemSNo,0) THEN RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0) ELSE 0 END) AS Qty FROM VVendRcvdDetail_Simple LEFT OUTER JOIN VItemPolishingProcessSNo ON VItemPolishingProcessSNo.ItemCode=VVendRcvdDetail_Simple.ItemCode WHERE LotNo<>'0' AND RcvdQty-IssQty-ISNULL(Wastage,0)-ISNULL(ReWorkQty,0)>0 AND EntryID NOT IN(SELECT Rcvd_RefID FROM VendIssdDetail) AND ISNULL(Opening_RefID,0)=0 GROUP BY VVendRcvdDetail_Simple.ItemCode) Tab1 GROUP BY ItemCode) TabLots ON VFOrderItems.CompItemCode=TabLots.ItemCode
		LEFT OUTER JOIN (SELECT ItemCode,SUM(CASE WHEN IssQty-RcvdQty>0 THEN IssQty-RcvdQty ELSE 0 END) AS OpenPOQty FROM VendIssdDetail WHERE ISNULL(LotNo,'')='' OR LotNo='0' GROUP BY ItemCode) TabOpenPO ON VFOrderItems.CompItemCode=TabOpenPO.ItemCode
		INNER JOIN (SELECT CompItemCode,SUM(Qty-ShippedQty) AS TotalOrdersQty FROM VFOrderItems WHERE OrderNo NOT IN('Stock-Order','Stock-OrderIss') AND OrderNo IN(SELECT OrderNo FROM VUnshippedOrderList) GROUP BY CompItemCode HAVING SUM(Qty-ShippedQty)>0) TabAllOrders ON VFOrderItems.CompItemCode=TabAllOrders.CompItemCode
		LEFT OUTER JOIN (SELECT OrderNo AS TOrderNo,SUM(Qty) AS TotalCurrentOrderQty FROM FOrderItems GROUP BY OrderNo) TCurrentOrder ON VFOrderItems.OrderNo=TCurrentOrder.TOrderNo
		--LEFT OUTER JOIN(SELECT ItemID,SUM(NetQty) AS NetQty FROM VItemsWithShelfWiseStock GROUP BY ItemID) TFinishedStock ON Items.ItemID=TFinishedStock.ItemID
	WHERE (VFOrderItems.DeliveryDT BETWEEN @DTFrom AND @DTTo)
	AND (CustCode=@CustCode OR @CustCode IS NULL) AND (Country=@Country OR @Country IS NULL)
	AND OrderNo IN(SELECT OrderNo FROM VUnshippedOrderList) AND (Qty>ShippedQty)
	AND (Items.GroupID=@GroupID OR @GroupID=0)
	ORDER BY Items.ItemID

--SELECT myTBL.*,T1.RMID,T1.Description,RMID1 FROM @myTBL myTBL LEFT OUTER JOIN (SELECT * FROM VItemsRMComp WHERE GroupID IN(SELECT Group_ID FROM RMGroupIDsForForging)) T1 ON myTBL.CompItemCode=T1.ItemID
SELECT myTBL.* FROM @myTBL myTBL

SET ANSI_WARNINGS ON
END


GO
/****** Object:  StoredProcedure [dbo].[OrderReceived_SP]    Script Date: 6/29/2026 4:50:02 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [dbo].[OrderReceived_SP](@DTFrom AS DATETIME,@DTTo AS DATETIME)
AS
BEGIN

SET @DTFrom=CAST(CONVERT(VARCHAR(50),@DTFrom,6) AS DATETIME)
SET @DTTo=CAST(CONVERT(VARCHAR(50),@DTTo,6) AS DATETIME)

DECLARE @myOrders TABLE(OrderNo VARCHAR(255))
DECLARE @myTBL TABLE (TROrders INT,TRItems INT,TRQty INT,FSOrders INT,FSItems INT,FSQty INT,FBOrders INT,FBItems INT,FBQty INT,PBOrders INT,PBItems INT,PBQty INT)
INSERT INTO @myOrders(OrderNo) SELECT OrderNo FROM FCustomerOrders WHERE DT BETWEEN @DTFrom AND @DTTo AND CustCode NOT IN('Stock')

INSERT INTO @myTBL(TROrders,TRItems,TRQty)
SELECT COUNT(DISTINCT FCustomerOrders.OrderNo) AS TotalOrders,COUNT(CompItemCode) AS TotalItems,SUM(Qty) AS TotalQty FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
	INNER JOIN @myOrders myOrders ON FCustomerOrders.OrderNo=myOrders.OrderNo


INSERT INTO @myTBL(FSOrders,FSItems,FSQty)
SELECT COUNT(DISTINCT FCustomerOrders.OrderNo) AS TotalOrders,COUNT(CompItemCode) AS TotalItems,SUM(Qty) AS TotalQty FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
	INNER JOIN @myOrders myOrders ON FCustomerOrders.OrderNo=myOrders.OrderNo AND FCustomerOrders.OrderNo NOT IN(SELECT OrderNo FROM VUnShippedOrderList)

--Fully Balance
INSERT INTO @myTBL(FBOrders,FBItems,FBQty)
SELECT COUNT(DISTINCT FCustomerOrders.OrderNo) AS TotalOrders,COUNT(CompItemCode) AS TotalItems,SUM(Qty) AS TotalQty FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
	INNER JOIN @myOrders myOrders ON FCustomerOrders.OrderNo=myOrders.OrderNo WHERE FCustomerOrders.OrderNo NOT IN(SELECT OrderNo FROM VFOrderItemsWIthShippedQty WHERE ShippedQty>0)

INSERT INTO @myTBL(PBOrders,PBItems,PBQty)
SELECT COUNT(DISTINCT FCustomerOrders.OrderNo) AS TotalOrders,COUNT(FOrderItems.CompItemCode) AS TotalItems,SUM(FOrderItems.Qty) AS TotalQty FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
	INNER JOIN @myOrders myOrders ON FCustomerOrders.OrderNo=myOrders.OrderNo INNER JOIN VUnShippedOrderList ON FCustomerOrders.OrderNo=VUnShippedOrderList.OrderNo
	WHERE FCustomerOrders.OrderNo IN(SELECT OrderNo FROM VFOrderItemsWIthShippedQty WHERE ShippedQty>0)


SELECT SUM(TROrders) AS TROrders,SUM(TRItems) AS TRItems,SUM(TRQty) AS TRQty,SUM(FSOrders) AS FSOrders,SUM(FSItems) AS FSItems,SUM(FSQty) AS FSQty,SUM(FBOrders) AS FBOrders,SUM(FBItems) AS FBItems,
	SUM(FBQty) AS FBQty,SUM(PBOrders) AS PBOrders,SUM(PBItems) AS PBItems,SUM(PBQty) AS PBQty
	FROM @myTBL
END
GO
