CREATE PROCEDURE [dbo].[Orders_Log_Sheet_SP] (@CustCode VARCHAR(255)='',@Country VARCHAR(255),@ShipStatus INT=4,@DTFrom DATETIME,@DTTo DATETIME,@DeliveryDTFilter AS BIT=0) AS

--Status; 0=Unshipped;1=Shipped;2=Cancelled;3=Hold;4=All Orders

BEGIN
	SET Ansi_Warnings OFF
	DECLARE @myTBL TABLE(OrderNo VARCHAR(255) UNIQUE,DeliveryDT DATETIME)
	IF @DeliveryDTFilter=0
		IF @ShipStatus=0
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DT BETWEEN @DTFrom AND @DTTo
				AND (TotalShippedQty<TotalOrderQty AND ISNULL(Cancelled,0)=0)
				AND OrderNo IN(SELECT OrderNo FROM VUnshippedOrderList)
		ELSE IF @ShipStatus=1
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DT BETWEEN @DTFrom AND @DTTo
				AND (TotalShippedQty=TotalOrderQty OR Cancelled=0)
		ELSE IF @ShipStatus=2
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DT BETWEEN @DTFrom AND @DTTo
				AND (Cancelled=1)
		ELSE IF @ShipStatus=3
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DT BETWEEN @DTFrom AND @DTTo
				AND (Cancelled=2)
		ELSE
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DT BETWEEN @DTFrom AND @DTTo
	ElSE
		IF @ShipStatus=0
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DeliveryDT BETWEEN @DTFrom AND @DTTo
				AND (TotalShippedQty<TotalOrderQty AND ISNULL(Cancelled,0)=0)
		ELSE IF @ShipStatus=1
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DeliveryDT BETWEEN @DTFrom AND @DTTo
				AND (TotalShippedQty=TotalOrderQty OR Cancelled=0)
		ELSE IF @ShipStatus=2
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DeliveryDT BETWEEN @DTFrom AND @DTTo
				AND (Cancelled=1)
		ELSE IF @ShipStatus=3
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DeliveryDT BETWEEN @DTFrom AND @DTTo
				AND (Cancelled=2)
		ELSE
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DeliveryDT BETWEEN @DTFrom AND @DTTo

	DELETE FROM @myTBL WHERE OrderNo IN(SELECT OrderNo FROM FCustomerOrders WHERE CustCode IN('PHF','SAL'))
	DELETE FROM @myTBL WHERE OrderNo NOT IN(SELECT OrderNo VUnshippedOrderList)

	SELECT CustCode,FCustomerOrders.OrderNo,FCustomerOrders.DT,FCustomerOrders.DeliveryDT,InternalRefNo,TotalOrderitems,TotalOrderQty,ISNULL(TotalPurItems,0) AS TotalPurItems,ISNULL(TotalPurQty,0) AS TotalPurQty,TotalRcvItems,ISNULL(TotalRcvQty,0) AS TotalRcvQty
	,TotalProdItems,TotalProdQty,TotalProdItems_Forceps ,TotalProdQty_Forceps,TotalProdItems_Scissors,TotalProdQty_Scissors,TotalProdItems_Dressing,TotalProdQty_Dressing,TotalProdItems_Others,TotalProdQty_Others
	,TotalPacItems,TotalPacQty,
	TotalTRFItems,TotalTRFQty,SOIQty,SOICount,SOAQty,SOACount,ISNULL(SOIQty,0)+ISNULL(SOAQty,0) AS SOQty,ISNULL(SOACount,0)+ISNULL(SOICount,0) AS SOCount,TotalTransferItems,TotalTransferQty,
	DT1,DT2,DT3,DT4,DT5,OriginalDelivery,PTCClosedItems,PTCClosedQty,ShippedQty,ShippedItems,ISNULL(WastageQty,0) AS WastageQty,ISNULL(ReWorkQty,0) AS ReWorkQty,MacItems,MacQty
	,Filing_Count,Filing_Qty,Polishing_Count,Polishing_Qty,EP_Count,EP_Qty,PS_Count,PS_Qty,Hardness_Count,Hardness_Qty,
	TTotalOrderItems_Forceps.TotalOrderItems_Forceps,TTotalOrderItems_Forceps.TotalOrderQty_Forceps,TTotalOrderItems_Scissors.TotalOrderItems_Scissors,TTotalOrderItems_Scissors.TotalOrderQty_Scissors,
	TTotalOrderItems_Dressing.TotalOrderItems_Dressing,TTotalOrderItems_Dressing.TotalOrderQty_Dressing,TTotalOrderItems_Others.TotalOrderItems_Others,TTotalOrderItems_Others.TotalOrderQty_Others,
	TPur_Forceps.TotalPurItems_Forceps,TPur_Forceps.TotalPurQty_Forceps,TPur_Forceps.LastReturnDT_Forceps,TPur_Scissors.TotalPurItems_Scissors,TPur_Scissors.TotalPurQty_Scissors,TPur_Scissors.LastReturnDT_Scissors,
	TPur_Dressing.TotalPurItems_Dressing,TPur_Dressing.TotalPurQty_Dressing,TPur_Dressing.LastReturnDT_Dressing,TPur_Others.TotalPurItems_Others,TPur_Others.TotalPurQty_Others,TPur_Others.LastReturnDT_Others
	,TotalPacItems_Forceps,TotalPacQty_Forceps,TotalPacItems_Scissors,TotalPacQty_Scissors,TotalPacItems_Dressing,TotalPacQty_Dressing,TotalPacItems_Others,TotalPacQty_Others
	FROM FCustomerOrders

	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT CompItemCode) AS TotalOrderItems_Forceps,SUM(Qty-ShippedQty) AS TotalOrderQty_Forceps FROM VFOrderItemsWithShippedQty INNER JOIN Items ON Items.ItemID=VFOrderItemsWithShippedQty.CompItemCode WHERE GroupID=60 GROUP BY OrderNo) TTotalOrderItems_Forceps ON FCustomerOrders.OrderNo=TTotalOrderItems_Forceps.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT CompItemCode) AS TotalOrderItems_Scissors,SUM(Qty-ShippedQty) AS TotalOrderQty_Scissors FROM VFOrderItemsWithShippedQty INNER JOIN Items ON Items.ItemID=VFOrderItemsWithShippedQty.CompItemCode WHERE GroupID=62 GROUP BY OrderNo) TTotalOrderItems_Scissors ON FCustomerOrders.OrderNo=TTotalOrderItems_Scissors.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT CompItemCode) AS TotalOrderItems_Dressing,SUM(Qty-ShippedQty) AS TotalOrderQty_Dressing FROM VFOrderItemsWithShippedQty INNER JOIN Items ON Items.ItemID=VFOrderItemsWithShippedQty.CompItemCode WHERE GroupID=63 GROUP BY OrderNo) TTotalOrderItems_Dressing ON FCustomerOrders.OrderNo=TTotalOrderItems_Dressing.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT CompItemCode) AS TotalOrderItems_Others,SUM(Qty-ShippedQty) AS TotalOrderQty_Others FROM VFOrderItemsWithShippedQty INNER JOIN Items ON Items.ItemID=VFOrderItemsWithShippedQty.CompItemCode WHERE GroupID NOT IN(60,62,63) GROUP BY OrderNo) TTotalOrderItems_Others ON FCustomerOrders.OrderNo=TTotalOrderItems_Others.OrderNo

	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPurItems_Forceps,SUM(IssQty-RcvdQty) AS TotalPurQty_Forceps,MAX(VendIssdDetail.ReturnDT) AS LastReturnDT_Forceps FROM VendIssued INNER JOIN VendIssdDetail ON VendIssued.EntryID=VendIssdDetail.RefID INNER JOIN Items ON VendIssdDetail.ItemCode=Items.ItemID
		WHERE GroupID=60 AND MasterPONo IS NOT NULL AND IssQty>RcvdQty AND VendID NOT IN(SELECT MakerID FROM FactoryMakers) AND Closed=0 GROUP BY OrderNo) TPur_Forceps ON FCustomerOrders.OrderNo=TPur_Forceps.OrderNo

	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPurItems_Scissors,SUM(IssQty-RcvdQty) AS TotalPurQty_Scissors,MAX(VendIssdDetail.ReturnDT) AS LastReturnDT_Scissors FROM VendIssued INNER JOIN VendIssdDetail ON VendIssued.EntryID=VendIssdDetail.RefID INNER JOIN Items ON VendIssdDetail.ItemCode=Items.ItemID
		WHERE GroupID=62 AND MasterPONo IS NOT NULL AND IssQty>RcvdQty AND VendID NOT IN(SELECT MakerID FROM FactoryMakers) AND Closed=0 GROUP BY OrderNo) TPur_Scissors ON FCustomerOrders.OrderNo=TPur_Scissors.OrderNo

	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPurItems_Dressing,SUM(IssQty-RcvdQty) AS TotalPurQty_Dressing,MAX(VendIssdDetail.ReturnDT) AS LastReturnDT_Dressing FROM VendIssued INNER JOIN VendIssdDetail ON VendIssued.EntryID=VendIssdDetail.RefID INNER JOIN Items ON VendIssdDetail.ItemCode=Items.ItemID
		WHERE GroupID=63 AND MasterPONo IS NOT NULL AND IssQty>RcvdQty AND VendID NOT IN(SELECT MakerID FROM FactoryMakers) AND Closed=0 GROUP BY OrderNo) TPur_Dressing ON FCustomerOrders.OrderNo=TPur_Dressing.OrderNo

	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPurItems_Others,SUM(IssQty-RcvdQty) AS TotalPurQty_Others,MAX(VendIssdDetail.ReturnDT) AS LastReturnDT_Others FROM VendIssued INNER JOIN VendIssdDetail ON VendIssued.EntryID=VendIssdDetail.RefID INNER JOIN Items ON VendIssdDetail.ItemCode=Items.ItemID
		WHERE GroupID NOT IN(60,62,63) AND MasterPONo IS NOT NULL AND IssQty>RcvdQty AND VendID NOT IN(SELECT MakerID FROM FactoryMakers) AND Closed=0 GROUP BY OrderNo) TPur_Others ON FCustomerOrders.OrderNo=TPur_Others.OrderNo

	INNER JOIN @myTBL myTBL ON FCustomerOrders.OrderNo=myTBL.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(*) AS TotalOrderItems,SUM(Qty) AS TotalOrderQty FROM FOrderItems GROUP BY OrderNo) TOrd ON FCustomerOrders.OrderNo=TOrd.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPurItems,SUM(IssQty-RcvdQty) AS TotalPurQty FROM VendIssued INNER JOIN VendIssdDetail ON VendIssued.EntryID=VendIssdDetail.RefID
		WHERE MasterPONo IS NOT NULL AND IssQty>RcvdQty AND VendID NOT IN(SELECT MakerID FROM FactoryMakers) AND Closed=0 GROUP BY OrderNo) TPur ON FCustomerOrders.OrderNo=TPur.OrderNo
	LEFT OUTER JOIN(SELECT VendRcvdDetail.OrderNo,COUNT(DISTINCT VendRcvdDetail.ItemCode) AS TotalRcvItems,SUM(VendRcvdDetail.RcvdQty) AS TotalRcvQty,SUM(ReWorkQty) AS ReWorkQty FROM VendReceived INNER JOIN VendRcvdDetail ON VendReceived.EntryID=VendRcvdDetail.RefID  INNER JOIN VendIssdDetail ON VendRcvdDetail.Issue_RefID=VendIssdDetail.EntryID
		INNER JOIN VendIssued ON VendReceived.Issuance_RefID=VendIssued.EntryID  WHERE MasterPONo IS NOT NULL GROUP BY VendRcvdDetail.OrderNo) TRcv ON FCustomerOrders.OrderNo=TRcv.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalProdItems,SUM(Qty) AS TotalProdQty FROM VRunningLots_Simple_PHF WHERE ProcessID<>206 GROUP BY OrderNo) TProd ON FCustomerOrders.OrderNo=TProd.OrderNo
	LEFT OUTER JOIN(SELECT VRunningLots_Simple_PHF.OrderNo,COUNT(DISTINCT VRunningLots_Simple_PHF.ItemCode) AS TotalProdItems_Forceps,SUM(VRunningLots_Simple_PHF.Qty) AS TotalProdQty_Forceps FROM VRunningLots_Simple_PHF INNER JOIN Items ON Items.ItemID=VRunningLots_Simple_PHF.ItemCode LEFT JOIN VFOrderItemswithShippedQty ON VRunningLots_Simple_PHF.OrderNo=VFOrderItemswithShippedQty.OrderNo AND VRunningLots_Simple_PHF.ItemCode=VFOrderItemswithShippedQty.CompItemCode WHERE ProcessID<>206 AND GroupID=60 AND VFOrderItemswithShippedQty.ShippedQty<VFOrderItemswithShippedQty.Qty GROUP BY VRunningLots_Simple_PHF.OrderNo) TProd_Forceps ON FCustomerOrders.OrderNo=TProd_Forceps.OrderNo
	LEFT OUTER JOIN(SELECT VRunningLots_Simple_PHF.OrderNo,COUNT(DISTINCT VRunningLots_Simple_PHF.ItemCode) AS TotalProdItems_Scissors,SUM(VRunningLots_Simple_PHF.Qty) AS TotalProdQty_Scissors FROM VRunningLots_Simple_PHF INNER JOIN Items ON Items.ItemID=VRunningLots_Simple_PHF.ItemCode LEFT JOIN VFOrderItemswithShippedQty ON VRunningLots_Simple_PHF.OrderNo=VFOrderItemswithShippedQty.OrderNo AND VRunningLots_Simple_PHF.ItemCode=VFOrderItemswithShippedQty.CompItemCode WHERE ProcessID<>206 AND GroupID=62 AND VFOrderItemswithShippedQty.ShippedQty<VFOrderItemswithShippedQty.Qty GROUP BY VRunningLots_Simple_PHF.OrderNo) TProd_Scissors ON FCustomerOrders.OrderNo=TProd_Scissors.OrderNo
	LEFT OUTER JOIN(SELECT VRunningLots_Simple_PHF.OrderNo,COUNT(DISTINCT VRunningLots_Simple_PHF.ItemCode) AS TotalProdItems_Dressing,SUM(VRunningLots_Simple_PHF.Qty) AS TotalProdQty_Dressing FROM VRunningLots_Simple_PHF INNER JOIN Items ON Items.ItemID=VRunningLots_Simple_PHF.ItemCode LEFT JOIN VFOrderItemswithShippedQty ON VRunningLots_Simple_PHF.OrderNo=VFOrderItemswithShippedQty.OrderNo AND VRunningLots_Simple_PHF.ItemCode=VFOrderItemswithShippedQty.CompItemCode WHERE ProcessID<>206 AND GroupID=63 AND VFOrderItemswithShippedQty.ShippedQty<VFOrderItemswithShippedQty.Qty GROUP BY VRunningLots_Simple_PHF.OrderNo) TProd_Dressing ON FCustomerOrders.OrderNo=TProd_Dressing.OrderNo
	LEFT OUTER JOIN(SELECT VRunningLots_Simple_PHF.OrderNo,COUNT(DISTINCT VRunningLots_Simple_PHF.ItemCode) AS TotalProdItems_Others,SUM(VRunningLots_Simple_PHF.Qty) AS TotalProdQty_Others FROM VRunningLots_Simple_PHF INNER JOIN Items ON Items.ItemID=VRunningLots_Simple_PHF.ItemCode LEFT JOIN VFOrderItemswithShippedQty ON VRunningLots_Simple_PHF.OrderNo=VFOrderItemswithShippedQty.OrderNo AND VRunningLots_Simple_PHF.ItemCode=VFOrderItemswithShippedQty.CompItemCode WHERE ProcessID<>206 AND GroupID NOT IN(60,62,63) AND VFOrderItemswithShippedQty.ShippedQty<VFOrderItemswithShippedQty.Qty GROUP BY VRunningLots_Simple_PHF.OrderNo) TProd_Others ON FCustomerOrders.OrderNo=TProd_Others.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,SUM(CASE WHEN EPEntry=1 THEN 1 ELSE 0 END) AS EP_Count,SUM(CASE WHEN EPEntry=1 THEN Qty ELSE 0 END) AS EP_Qty
	,SUM(CASE WHEN PolishingEntry=1 THEN 1 ELSE 0 END) AS Polishing_Count,SUM(CASE WHEN PolishingEntry=1 THEN Qty ELSE 0 END) AS Polishing_Qty
	,SUM(CASE WHEN FilingEntry=1 THEN 1 ELSE 0 END) AS Filing_Count,SUM(CASE WHEN FilingEntry=1 THEN Qty ELSE 0 END) AS Filing_Qty
	,SUM(CASE WHEN PSEntry=1 THEN 1 ELSE 0 END) AS PS_Count,SUM(CASE WHEN PSEntry=1 THEN Qty ELSE 0 END) AS PS_Qty
	,SUM(CASE WHEN HardnessEntry=1 THEN 1 ELSE 0 END) AS Hardness_Count,SUM(CASE WHEN HardnessEntry=1 THEN Qty ELSE 0 END) AS Hardness_Qty
	FROM (SELECT OrderNo,VRunningLots_Simple_PHF.ItemCode,Qty
	,CASE WHEN SNO<=VItemWithEtchingPackingProcessSNo.EPItemSNo AND SNO>VItemWithFinalPolishingProcessSNo.FinalPolishingItemSNo THEN 1 ELSE 0 END AS EPEntry
	,CASE WHEN SNO<=VItemWithFinalPolishingProcessSNo.FinalPolishingItemSNo AND SNO>VItemWithFilingQCProcessSNo.FilingQCItemSNo THEN 1 ELSE 0 END AS PolishingEntry
	,CASE WHEN SNO<=VItemWithFilingQCProcessSNo.FilingQCItemSNo THEN 1 ELSE 0 END AS FilingEntry
	,CASE WHEN SNO=VItemWithPinScrewsProcessSNo.PSItemSNo THEN 1 ELSE 0 END AS PSEntry
	,CASE WHEN SNO=VItemWithHardnessProcessSNo.HardnessItemSNo THEN 1 ELSE 0 END AS HardnessEntry
	FROM VRunningLots_Simple_PHF
	INNER JOIN VItemWithFilingQCProcessSNo ON VRunningLots_Simple_PHF.ItemCode=VItemWithFilingQCProcessSNo.ItemCode
	INNER JOIN VItemWithFinalPolishingProcessSNo ON VRunningLots_Simple_PHF.ItemCode=VItemWithFinalPolishingProcessSNo.ItemCode
	INNER JOIN VItemWithEtchingPackingProcessSNo ON VRunningLots_Simple_PHF.ItemCode=VItemWithEtchingPackingProcessSNo.ItemCode
	INNER JOIN VItemWithPinScrewsProcessSNo ON VRunningLots_Simple_PHF.ItemCode=VItemWithPinScrewsProcessSNo.ItemCode
	INNER JOIN VItemWithHardnessProcessSNo ON VRunningLots_Simple_PHF.ItemCode=VItemWithHardnessProcessSNo.ItemCode
	) TINNER
	GROUP BY OrderNo) TProcWiseData ON FCustomerOrders.OrderNo=TProcWiseData.OrderNo

	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS PTCClosedItems,SUM(Qty) AS PTCClosedQty FROM VRunningLots_Simple WHERE ProcessID=206 GROUP BY OrderNo) TPTCClosed ON FCustomerOrders.OrderNo=TPTCClosed.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPacItems,SUM(Qty)  AS TotalPacQty FROM VDispatchListDetail_Adv GROUP BY OrderNo) TPac ON FCustomerOrders.OrderNo=TPac.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPacItems_Forceps,SUM(Qty)  AS TotalPacQty_Forceps FROM VDispatchListDetail_Adv WHERE GroupID=60 GROUP BY OrderNo) TPac_Forceps ON FCustomerOrders.OrderNo=TPac_Forceps.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPacItems_Scissors,SUM(Qty)  AS TotalPacQty_Scissors FROM VDispatchListDetail_Adv WHERE GroupID=62 GROUP BY OrderNo) TPac_Scissors ON FCustomerOrders.OrderNo=TPac_Scissors.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPacItems_Dressing,SUM(Qty)  AS TotalPacQty_Dressing FROM VDispatchListDetail_Adv WHERE GroupID=63 GROUP BY OrderNo) TPac_Dressing ON FCustomerOrders.OrderNo=TPac_Dressing.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPacItems_Others,SUM(Qty)  AS TotalPacQty_Others FROM VDispatchListDetail_Adv WHERE GroupID NOT IN(60,62,63) GROUP BY OrderNo) TPac_Others ON FCustomerOrders.OrderNo=TPac_Others.OrderNo

	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalTRFItems,SUM(Qty) AS TotalTRFQty FROM TransferredToReadyFinishLotsDetail INNER JOIN VendRcvdDetail
		ON VendRcvdDetail.EntryID=TransferredToReadyFinishLotsDetail.VRD_RefID GROUP BY OrderNo) TRF ON FCustomerOrders.OrderNo=TRF.OrderNo

	LEFT OUTER JOIN(SELECT OrderNo,SUM(StockOrderOpening_Issuance.QtyIssd) AS SOIQty,COUNT(DISTINCT ItemCode) AS SOICount FROM StockOrderOpening_Issuance
				INNER JOIN VendIssdDetail ON StockOrderOpening_Issuance.VID_RefID=VendIssdDetail.EntryID INNER JOIN VendIssued ON VendIssued.EntryID=VendIssdDetail.RefID
				GROUP BY OrderNo) TSOI ON FCustomerOrders.OrderNo=TSOI.OrderNo

	LEFT OUTER JOIN(SELECT OrderNo,SUM(Qty) AS SOAQty,COUNT(DISTINCT ItemID) AS SOACount FROM StockOrderAdjustments GROUP BY OrderNo) TSOA ON FCustomerOrders.OrderNo=TSOA.OrderNo
	LEFT OUTER JOIN(SELECT ToOrderNo,COUNT(DISTINCT ToItemCode) AS TotalTransferItems,SUM(Qty) AS TotalTransferQty FROM LotTransferDetails WHERE Type=0 GROUP BY ToOrderNo) TTR ON FCustomerOrders.OrderNo=TTR.ToOrderNo
	LEFT OUTER JOIN FCustomerOrders_ShippingDates ON FCustomerOrders.OrderNo=FCustomerOrders_ShippingDates.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemID) AS MacItems,SUM(IssQty) AS MacQty FROM VendIssdDetail INNER JOIN Vendissued ON VendIssued.EntryID=VendIssdDetail.RefID WHERE VendID IN(959,1038) AND ProcessID=169 GROUP BY OrderNo) TMac ON FCustomerOrders.OrderNo=TMac.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,SUM(CustomInvoiceItems.Qty) AS ShippedQty,COUNT(DISTINCT FOrderItems.ID) AS ShippedItems FROM CustomInvoiceItems INNER JOIN FProformaOrders ON FProformaOrders.EntryID=CustomInvoiceItems.RefID
		 INNER JOIN FOrderItems ON FOrderItems.ID=FProformaOrders.OrderEntryID INNER JOIN CustomInvoice ON CustomInvoice.CustomInvoice=CustomInvoiceItems.CustomInvoice WHERE ISNULL(GatePassNo,'')<>'' GROUP BY OrderNo) TShipped ON FCustomerOrders.OrderNo=TShipped.OrderNo
	LEFT OUTER JOIN (SELECT VendIssdDetail.OrderNo,SUM(MakerRepair.Qty) AS WastageQty FROM MakerRepair
			INNER JOIN VendRcvdDetail ON VendRcvdDetail.EntryID=MakerRepair.VRD_RefID_ChargeTo
			INNER JOIN VendIssdDetail ON VendRcvdDetail.Issue_RefID=VendIssdDetail.EntryID
			INNER JOIN VendIssued ON VendIssued.EntryID=VendIssdDetail.RefID


			WHERE MasterPONo IS NOT NULL AND VendIssued.VendID NOT IN(SELECT MakerID FROM FactoryMakers) GROUP BY VendIssdDetail.OrderNo) TRej ON TOrd.OrderNo=TRej.OrderNo
END

GO
/****** Object:  StoredProcedure [dbo].[OrderStatusLog_Ex_SP]    Script Date: 6/29/2026 4:50:02 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [dbo].[OrderStatusLog_Ex_SP] (@CustCode VARCHAR(255)='',@Country VARCHAR(255),@ShipStatus INT=4,@DTFrom DATETIME,@DTTo DATETIME,@DeliveryDTFilter AS BIT=0) AS

--Status; 0=Unshipped;1=Shipped;2=Cancelled;3=Hold;4=All Orders

BEGIN
	SET Ansi_Warnings OFF
	DECLARE @myTBL TABLE(OrderNo VARCHAR(255) UNIQUE,DeliveryDT DATETIME)
	IF @DeliveryDTFilter=0
		IF @ShipStatus=0
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DT BETWEEN @DTFrom AND @DTTo
				AND (TotalShippedQty<TotalOrderQty AND ISNULL(Cancelled,0)=0)
		ELSE IF @ShipStatus=1
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DT BETWEEN @DTFrom AND @DTTo
				AND (TotalShippedQty=TotalOrderQty OR Cancelled=0)
		ELSE IF @ShipStatus=2
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DT BETWEEN @DTFrom AND @DTTo
				AND (Cancelled=1)
		ELSE IF @ShipStatus=3
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DT BETWEEN @DTFrom AND @DTTo
				AND (Cancelled=2)
		ELSE
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DT BETWEEN @DTFrom AND @DTTo
	ElSE
		IF @ShipStatus=0
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DeliveryDT BETWEEN @DTFrom AND @DTTo
				AND (TotalShippedQty<TotalOrderQty AND ISNULL(Cancelled,0)=0)
		ELSE IF @ShipStatus=1
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DeliveryDT BETWEEN @DTFrom AND @DTTo
				AND (TotalShippedQty=TotalOrderQty OR Cancelled=0)
		ELSE IF @ShipStatus=2
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DeliveryDT BETWEEN @DTFrom AND @DTTo
				AND (Cancelled=1)
		ELSE IF @ShipStatus=3
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DeliveryDT BETWEEN @DTFrom AND @DTTo
				AND (Cancelled=2)
		ELSE
			INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
				AND DeliveryDT BETWEEN @DTFrom AND @DTTo


	SELECT CustCode,FCustomerOrders.OrderNo,FCustomerOrders.DT,FCustomerOrders.DeliveryDT,InternalRefNo,TotalOrderitems,TotalOrderQty,ISNULL(TotalPurItems,0) AS TotalPurItems,ISNULL(TotalPurQty,0) AS TotalPurQty,TotalRcvItems,ISNULL(TotalRcvQty,0) AS TotalRcvQty
	,TotalProdItems,TotalProdQty,TotalProdItems_Forceps ,TotalProdQty_Forceps,TotalProdItems_Scissors,TotalProdQty_Scissors,TotalProdItems_Dressing,TotalProdQty_Dressing,TotalProdItems_Others,TotalProdQty_Others
	,TotalPacItems,TotalPacQty,
	TotalTRFItems,TotalTRFQty,SOIQty,SOICount,SOAQty,SOACount,ISNULL(SOIQty,0)+ISNULL(SOAQty,0) AS SOQty,ISNULL(SOACount,0)+ISNULL(SOICount,0) AS SOCount,TotalTransferItems,TotalTransferQty,
	DT1,DT2,DT3,DT4,DT5,OriginalDelivery,PTCClosedItems,PTCClosedQty,ShippedQty,ShippedItems,ISNULL(WastageQty,0) AS WastageQty,ISNULL(ReWorkQty,0) AS ReWorkQty,MacItems,MacQty
	,Filing_Count,Filing_Qty,Polishing_Count,Polishing_Qty,EP_Count,EP_Qty,PS_Count,PS_Qty,Hardness_Count,Hardness_Qty
	FROM FCustomerOrders
	INNER JOIN @myTBL myTBL ON FCustomerOrders.OrderNo=myTBL.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(*) AS TotalOrderItems,SUM(Qty) AS TotalOrderQty FROM FOrderItems GROUP BY OrderNo) TOrd ON FCustomerOrders.OrderNo=TOrd.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPurItems,SUM(IssQty-RcvdQty) AS TotalPurQty FROM VendIssued INNER JOIN VendIssdDetail ON VendIssued.EntryID=VendIssdDetail.RefID
		WHERE MasterPONo IS NOT NULL AND IssQty>RcvdQty AND VendID NOT IN(SELECT MakerID FROM FactoryMakers) AND Closed=0 GROUP BY OrderNo) TPur ON FCustomerOrders.OrderNo=TPur.OrderNo
	LEFT OUTER JOIN(SELECT VendRcvdDetail.OrderNo,COUNT(DISTINCT VendRcvdDetail.ItemCode) AS TotalRcvItems,SUM(VendRcvdDetail.RcvdQty) AS TotalRcvQty,SUM(ReWorkQty) AS ReWorkQty FROM VendReceived INNER JOIN VendRcvdDetail ON VendReceived.EntryID=VendRcvdDetail.RefID  INNER JOIN VendIssdDetail ON VendRcvdDetail.Issue_RefID=VendIssdDetail.EntryID
		INNER JOIN VendIssued ON VendReceived.Issuance_RefID=VendIssued.EntryID  WHERE MasterPONo IS NOT NULL GROUP BY VendRcvdDetail.OrderNo) TRcv ON FCustomerOrders.OrderNo=TRcv.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalProdItems,SUM(Qty) AS TotalProdQty FROM VRunningLots_Simple_PHF WHERE ProcessID<>206 GROUP BY OrderNo) TProd ON FCustomerOrders.OrderNo=TProd.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalProdItems_Forceps,SUM(Qty) AS TotalProdQty_Forceps FROM VRunningLots_Simple_PHF INNER JOIN Items ON Items.ItemID=VRunningLots_Simple_PHF.ItemCode WHERE ProcessID<>206 AND GroupID=60 GROUP BY OrderNo) TProd_Forceps ON FCustomerOrders.OrderNo=TProd_Forceps.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalProdItems_Scissors,SUM(Qty) AS TotalProdQty_Scissors FROM VRunningLots_Simple_PHF INNER JOIN Items ON Items.ItemID=VRunningLots_Simple_PHF.ItemCode WHERE ProcessID<>206 AND GroupID=62 GROUP BY OrderNo) TProd_Scissors ON FCustomerOrders.OrderNo=TProd_Scissors.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalProdItems_Dressing,SUM(Qty) AS TotalProdQty_Dressing FROM VRunningLots_Simple_PHF INNER JOIN Items ON Items.ItemID=VRunningLots_Simple_PHF.ItemCode WHERE ProcessID<>206 AND GroupID=63 GROUP BY OrderNo) TProd_Dressing ON FCustomerOrders.OrderNo=TProd_Dressing.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalProdItems_Others,SUM(Qty) AS TotalProdQty_Others FROM VRunningLots_Simple_PHF INNER JOIN Items ON Items.ItemID=VRunningLots_Simple_PHF.ItemCode WHERE ProcessID<>206 AND GroupID NOT IN(60,62,63) GROUP BY OrderNo) TProd_Others ON FCustomerOrders.OrderNo=TProd_Others.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,SUM(CASE WHEN EPEntry=1 THEN 1 ELSE 0 END) AS EP_Count,SUM(CASE WHEN EPEntry=1 THEN Qty ELSE 0 END) AS EP_Qty
	,SUM(CASE WHEN PolishingEntry=1 THEN 1 ELSE 0 END) AS Polishing_Count,SUM(CASE WHEN PolishingEntry=1 THEN Qty ELSE 0 END) AS Polishing_Qty
	,SUM(CASE WHEN FilingEntry=1 THEN 1 ELSE 0 END) AS Filing_Count,SUM(CASE WHEN FilingEntry=1 THEN Qty ELSE 0 END) AS Filing_Qty
	,SUM(CASE WHEN PSEntry=1 THEN 1 ELSE 0 END) AS PS_Count,SUM(CASE WHEN PSEntry=1 THEN Qty ELSE 0 END) AS PS_Qty
	,SUM(CASE WHEN HardnessEntry=1 THEN 1 ELSE 0 END) AS Hardness_Count,SUM(CASE WHEN HardnessEntry=1 THEN Qty ELSE 0 END) AS Hardness_Qty
	FROM (SELECT OrderNo,VRunningLots_Simple_PHF.ItemCode,Qty
	,CASE WHEN SNO<=VItemWithEtchingPackingProcessSNo.EPItemSNo AND SNO>VItemWithFinalPolishingProcessSNo.FinalPolishingItemSNo THEN 1 ELSE 0 END AS EPEntry
	,CASE WHEN SNO<=VItemWithFinalPolishingProcessSNo.FinalPolishingItemSNo AND SNO>VItemWithFilingQCProcessSNo.FilingQCItemSNo THEN 1 ELSE 0 END AS PolishingEntry
	,CASE WHEN SNO<=VItemWithFilingQCProcessSNo.FilingQCItemSNo THEN 1 ELSE 0 END AS FilingEntry
	,CASE WHEN SNO=VItemWithPinScrewsProcessSNo.PSItemSNo THEN 1 ELSE 0 END AS PSEntry
	,CASE WHEN SNO=VItemWithHardnessProcessSNo.HardnessItemSNo THEN 1 ELSE 0 END AS HardnessEntry
	FROM VRunningLots_Simple_PHF
	INNER JOIN VItemWithFilingQCProcessSNo ON VRunningLots_Simple_PHF.ItemCode=VItemWithFilingQCProcessSNo.ItemCode
	INNER JOIN VItemWithFinalPolishingProcessSNo ON VRunningLots_Simple_PHF.ItemCode=VItemWithFinalPolishingProcessSNo.ItemCode
	INNER JOIN VItemWithEtchingPackingProcessSNo ON VRunningLots_Simple_PHF.ItemCode=VItemWithEtchingPackingProcessSNo.ItemCode
	INNER JOIN VItemWithPinScrewsProcessSNo ON VRunningLots_Simple_PHF.ItemCode=VItemWithPinScrewsProcessSNo.ItemCode
	INNER JOIN VItemWithHardnessProcessSNo ON VRunningLots_Simple_PHF.ItemCode=VItemWithHardnessProcessSNo.ItemCode
	) TINNER
	GROUP BY OrderNo) TProcWiseData ON FCustomerOrders.OrderNo=TProcWiseData.OrderNo

	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS PTCClosedItems,SUM(Qty) AS PTCClosedQty FROM VRunningLots_Simple WHERE ProcessID=206 GROUP BY OrderNo) TPTCClosed ON FCustomerOrders.OrderNo=TPTCClosed.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPacItems,SUM(Qty)  AS TotalPacQty FROM VDispatchListDetail_Adv GROUP BY OrderNo) TPac ON FCustomerOrders.OrderNo=TPac.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalTRFItems,SUM(Qty) AS TotalTRFQty FROM TransferredToReadyFinishLotsDetail INNER JOIN VendRcvdDetail
		ON VendRcvdDetail.EntryID=TransferredToReadyFinishLotsDetail.VRD_RefID GROUP BY OrderNo) TRF ON FCustomerOrders.OrderNo=TRF.OrderNo

	LEFT OUTER JOIN(SELECT OrderNo,SUM(StockOrderOpening_Issuance.QtyIssd) AS SOIQty,COUNT(DISTINCT ItemCode) AS SOICount FROM StockOrderOpening_Issuance
				INNER JOIN VendIssdDetail ON StockOrderOpening_Issuance.VID_RefID=VendIssdDetail.EntryID INNER JOIN VendIssued ON VendIssued.EntryID=VendIssdDetail.RefID
				GROUP BY OrderNo) TSOI ON FCustomerOrders.OrderNo=TSOI.OrderNo

	LEFT OUTER JOIN(SELECT OrderNo,SUM(Qty) AS SOAQty,COUNT(DISTINCT ItemID) AS SOACount FROM StockOrderAdjustments GROUP BY OrderNo) TSOA ON FCustomerOrders.OrderNo=TSOA.OrderNo
	LEFT OUTER JOIN(SELECT ToOrderNo,COUNT(DISTINCT ToItemCode) AS TotalTransferItems,SUM(Qty) AS TotalTransferQty FROM LotTransferDetails WHERE Type=0 GROUP BY ToOrderNo) TTR ON FCustomerOrders.OrderNo=TTR.ToOrderNo
	LEFT OUTER JOIN FCustomerOrders_ShippingDates ON FCustomerOrders.OrderNo=FCustomerOrders_ShippingDates.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemID) AS MacItems,SUM(IssQty) AS MacQty FROM VendIssdDetail INNER JOIN Vendissued ON VendIssued.EntryID=VendIssdDetail.RefID WHERE VendID IN(959,1038) AND ProcessID=169 GROUP BY OrderNo) TMac ON FCustomerOrders.OrderNo=TMac.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,SUM(CustomInvoiceItems.Qty) AS ShippedQty,COUNT(DISTINCT FOrderItems.ID) AS ShippedItems FROM CustomInvoiceItems INNER JOIN FProformaOrders ON FProformaOrders.EntryID=CustomInvoiceItems.RefID
		 INNER JOIN FOrderItems ON FOrderItems.ID=FProformaOrders.OrderEntryID INNER JOIN CustomInvoice ON CustomInvoice.CustomInvoice=CustomInvoiceItems.CustomInvoice WHERE ISNULL(GatePassNo,'')<>'' GROUP BY OrderNo) TShipped ON FCustomerOrders.OrderNo=TShipped.OrderNo
	LEFT OUTER JOIN (SELECT VendIssdDetail.OrderNo,SUM(MakerRepair.Qty) AS WastageQty FROM MakerRepair
			INNER JOIN VendRcvdDetail ON VendRcvdDetail.EntryID=MakerRepair.VRD_RefID_ChargeTo
			INNER JOIN VendIssdDetail ON VendRcvdDetail.Issue_RefID=VendIssdDetail.EntryID
			INNER JOIN VendIssued ON VendIssued.EntryID=VendIssdDetail.RefID


			WHERE MasterPONo IS NOT NULL AND VendIssued.VendID NOT IN(SELECT MakerID FROM FactoryMakers) GROUP BY VendIssdDetail.OrderNo) TRej ON TOrd.OrderNo=TRej.OrderNo
END
GO
