CREATE PROCEDURE [dbo].[OrderStatusReport_SP] (@DTFrom AS DATETIME=NULL,@DTTo AS DATETIME=NULL,@CustCode AS VARCHAR(50)=NULL,@Country AS VARCHAR(50)=NULL,@OrderNo AS VARCHAR(4000)='0',@CatID AS INT=0,@FOI_IDs AS VARCHAR(4000)='0') AS

BEGIN
SET ANSI_WARNINGS OFF
DECLARE @myQuery AS VARCHAR(4000)
--DECLARE @myTBL TABLE(ItemID VARCHAR(255),ItemName VARCHAR(1000),Qty INT,OrderNo VARCHAR(255),CompItemCode VARCHAR(1000),InHand INT,SFQty INT,ForgingStock INT,QtyToRcv INT,TotalOrdersQty INT,MinLevel INT,InProcessLotsQty INT,InProcessLotsQtyB4 INT,OpenPOQty INT,RMID INT,Description VARCHAR(255),RMID1 VARCHAR(255))
	IF @FOI_IDs='0'
		BEGIN
		CREATE TABLE #myTBL (OrderNo VARCHAR(50))

		SET @myQuery='INSERT INTO #myTBL(OrderNo) SELECT OrderNo FROM FCustomerOrders WHERE OrderNo IN(' + @OrderNo +')'
		EXEC(@myQuery)


		SELECT TOrders.OrderNo,Items.ItemID,ItemName,TOrders.Qty AS OrderQty,StockQty,TStockSF.SFIssQty,POQty,PODT,ForgingQty,MachiningQty,FilingQty,TemperQty
			,PolishingIssQty,PolishingRcvQty,SettingQty,FinalPolQty,FinalInspQty,PackingQty
			,ShippedQty,DPQty,BookmarkQty,TradeTerms,LastShipmentDate,TOrders.ItemCode,TOrders.Price
			,TOrders.DeliveryDT,DeliveryStatus,InternalRefNo,FCustomerOrders.DT,FCustomerOrders.CustCode,PInvoice
			,TAnnealingIss.Annealing_IssDT,TAnnealingIss.AnnealingIssQty,TAnnealing.AnnealingRcvdQty
			,TMasterPOIss.MasterPO_IssDT,TMasterPOIss.MasterPOIssQty,TMasterPORcv.MasterPORcvdQty
			,TMillingIss.MillingIssQty,TMillingRcv.MillingRcvQty
			,TFilingIss.FilingIssQty,TFilingRcv.FilingRcvQty
			FROM Items INNER JOIN   FOrderItems  TOrders ON Items.ItemID=TOrders.CompItemCode
			INNER JOIN  #myTBL myTBL ON TOrders.OrderNo=myTBL.OrderNo
			INNER JOIN FCustomerOrders ON TOrders.OrderNo=FCustomerOrders.OrderNo
			INNER JOIN FProformaOrders ON TOrders.ID=FProformaOrders.OrderEntryID
			LEFT OUTER JOIN (SELECT OrderNo,ItemID,SUM(Qty) AS StockQty FROM StockOrderAdjustments GROUP BY OrderNo,ItemID) TStock ON TOrders.CompItemCode=TStock.ItemID AND TOrders.OrderNo=TStock.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(IssQty) AS SFIssQty FROM StockOrderOpening_Issuance INNER JOIN VendIssdDetail ON StockOrderOpening_Issuance.VID_RefID=VendIssdDetail.EntryID GROUP BY OrderNo,ItemCode) TStockSF ON TOrders.CompItemCode=TStockSF.ItemCode AND TOrders.OrderNo=TStockSF.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,MAX(DT) AS PODT,SUM(IssQty) AS POQty FROM VendIssued INNER JOIN VendIssdDetail ON VendIssued.EntryID=VendIssdDetail.RefID
										WHERE MasterPONo IS NOT NULL GROUP BY OrderNo,ItemCode) TPO ON TOrders.CompItemCode=TPO.ItemCode AND TOrders.OrderNo=TPO.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS ForgingQty FROM VVendRcvdDetail_Simple WHERE ProcessID=88 GROUP BY OrderNo,ItemCode) TForging ON TOrders.CompItemCode=TForging.ItemCode AND TOrders.OrderNo=TForging.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS MachiningQty FROM VVendRcvdDetail_Simple WHERE ProcessID=90 GROUP BY OrderNo,ItemCode) TMachining ON TOrders.CompItemCode=TMachining.ItemCode AND TOrders.OrderNo=TMachining.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS FilingQty FROM VVendRcvdDetail_Simple WHERE ProcessID=92 GROUP BY OrderNo,ItemCode) TFiling ON TOrders.CompItemCode=TFiling.ItemCode AND TOrders.OrderNo=TFiling.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS TemperQty FROM VVendRcvdDetail_Simple WHERE ProcessID=95 GROUP BY OrderNo,ItemCode) TTemper ON TOrders.CompItemCode=TTemper.ItemCode AND TOrders.OrderNo=TTemper.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(IssQty) AS PolishingIssQty FROM VendIssdDetail INNER JOIN VendIssued ON VendIssued.EntryID=VendIssdDetail.RefID WHERE ProcessID=99 GROUP BY OrderNo,ItemCode) TPolishingIss ON TOrders.CompItemCode=TPolishingIss.ItemCode AND TOrders.OrderNo=TPolishingIss.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS PolishingRcvQty FROM VVendRcvdDetail_Simple WHERE ProcessID=99  GROUP BY OrderNo,ItemCode) TPolishingRcv ON TOrders.CompItemCode=TPolishingRcv.ItemCode AND TOrders.OrderNo=TPolishingRcv.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS SettingQty FROM VVendRcvdDetail_Simple WHERE ProcessID=119 GROUP BY OrderNo,ItemCode) TSetting ON TOrders.CompItemCode=TSetting.ItemCode AND TOrders.OrderNo=TSetting.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS FinalPolQty FROM VVendRcvdDetail_Simple WHERE ProcessID=32 GROUP BY OrderNo,ItemCode) FinalPol ON TOrders.CompItemCode=FinalPol.ItemCode AND TOrders.OrderNo=FinalPol.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS FinalInspQty FROM VVendRcvdDetail_Simple WHERE ProcessID=74 GROUP BY OrderNo,ItemCode) FinalInsp ON TOrders.CompItemCode=FinalInsp.ItemCode AND TOrders.OrderNo=FinalInsp.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS PackingQty FROM VVendRcvdDetail_Simple WHERE ProcessID=100 GROUP BY OrderNo,ItemCode) TPacking ON TOrders.CompItemCode=TPacking.ItemCode AND TOrders.OrderNo=TPacking.OrderNo

			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,MAX(VendIssued.DT) AS Annealing_IssDT,SUM(IssQty) AS AnnealingIssQty FROM VendIssdDetail INNER JOIN VendIssued ON VendIssued.EntryID=VendIssdDetail.RefID WHERE ProcessID=141 GROUP BY OrderNo,ItemCode) TAnnealingIss ON TOrders.CompItemCode=TAnnealingIss.ItemCode AND TOrders.OrderNo=TAnnealingIss.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS AnnealingRcvdQty FROM VVendRcvdDetail_Simple WHERE ProcessID=141 GROUP BY OrderNo,ItemCode) TAnnealing ON TOrders.CompItemCode=TAnnealing.ItemCode AND TOrders.OrderNo=TAnnealing.OrderNo

			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(IssQty) AS MillingIssQty FROM VendIssdDetail INNER JOIN VendIssued ON VendIssued.EntryID=VendIssdDetail.RefID WHERE ProcessID=88 GROUP BY OrderNo,ItemCode) TMillingIss ON TOrders.CompItemCode=TMillingIss.ItemCode AND TOrders.OrderNo=TMillingIss.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS MillingRcvQty FROM VVendRcvdDetail_Simple WHERE ProcessID=88 GROUP BY OrderNo,ItemCode) TMillingRcv ON TOrders.CompItemCode=TMillingRcv.ItemCode AND TOrders.OrderNo=TMillingRcv.OrderNo

			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(IssQty) AS FilingIssQty FROM VendIssdDetail INNER JOIN VendIssued ON VendIssued.EntryID=VendIssdDetail.RefID WHERE ProcessID=90 GROUP BY OrderNo,ItemCode) TFilingIss ON TOrders.CompItemCode=TFilingIss.ItemCode AND TOrders.OrderNo=TFilingIss.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS FilingRcvQty FROM VVendRcvdDetail_Simple WHERE ProcessID=90 GROUP BY OrderNo,ItemCode) TFilingRcv ON TOrders.CompItemCode=TFilingRcv.ItemCode AND TOrders.OrderNo=TFilingRcv.OrderNo

			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,MAX(VendIssued.DT) AS MasterPO_IssDT,SUM(IssQty) AS MasterPOIssQty FROM VendIssdDetail INNER JOIN VendIssued ON VendIssued.EntryID=VendIssdDetail.RefID WHERE MasterPONo IS NOT NULL GROUP BY OrderNo,ItemCode) TMasterPOIss ON TOrders.CompItemCode=TMasterPOIss.ItemCode AND TOrders.OrderNo=TMasterPOIss.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS MasterPORcvdQty FROM VVendRcvdDetail_Simple INNER JOIN VendIssued ON VVendRcvdDetail_Simple.Issuance_RefID=VendIssued.EntryID WHERE MasterPONo IS NOT NULL GROUP BY OrderNo,ItemCode) TMasterPORcv ON TOrders.CompItemCode=TMasterPORcv.ItemCode AND TOrders.OrderNo=TMasterPORcv.OrderNo

			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(Qty) AS DPQty FROM VDispatchListDetail_Adv  GROUP BY OrderNo,ItemCode) TDP ON TOrders.CompItemCode=TDP.ItemCode AND TOrders.OrderNo=TDP.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemID,SUM(Qty) AS BookmarkQty FROM VID_Bookmarks WHERE ViewDone=0 GROUP BY OrderNo,ItemID) TBookMarks ON TOrders.CompItemCode=TBookMarks.ItemID AND TOrders.OrderNo=TBookMarks.OrderNo


			INNER JOIN VUnshippedOrderItemList ON TOrders.OrderNo=VUnshippedOrderItemList.OrderNo AND TOrders.CompItemCode=VUnshippedOrderItemList.CompItemCode

		END
	ELSE
		BEGIN

		CREATE TABLE #myTBLOrders(OrderNo VARCHAR(50),ItemID VARCHAR(50))

		SET @myQuery='INSERT INTO #myTBLOrders(OrderNo,ItemID) SELECT OrderNo,CompItemCode FROM FOrderItems WHERE ID  IN(' + @FOI_IDs +')'
		EXEC(@myQuery)

		SELECT TOrders.OrderNo,Items.ItemID,ItemName,TOrders.Qty AS OrderQty,StockQty,SFIssQty,POQty,PODT,ForgingQty,MachiningQty,FilingQty,TemperQty,PolishingIssQty,PolishingRcvQty,SettingQty,FinalPolQty,FinalInspQty,PackingQty,ShippedQty,DPQty,BookmarkQty,TradeTerms,LastShipmentDate,TOrders.ItemCode
		,TOrders.Price,TOrders.DeliveryDT,DeliveryStatus,InternalRefNo,FCustomerOrders.DT,FCustomerOrders.CustCode,'' AS PInvoice
		,TAnnealingIss.Annealing_IssDT,TAnnealingIss.AnnealingIssQty,TAnnealing.AnnealingRcvdQty
		,TMasterPOIss.MasterPO_IssDT,TMasterPOIss.MasterPOIssQty,TMasterPORcv.MasterPORcvdQty
		,TMillingIss.MillingIssQty,TMillingRcv.MillingRcvQty
		,TFilingIss.FilingIssQty,TFilingRcv.FilingRcvQty
		FROM Items
		INNER JOIN FOrderItems TOrders ON Items.ItemID=TOrders.CompItemCode INNER JOIN #myTBLOrders myTBL ON TOrders.OrderNo=myTBL.OrderNo
		INNER JOIN FCustomerOrders ON TOrders.OrderNo=FCustomerOrders.OrderNo
		INNER JOIN FProformaOrders ON TOrders.ID=FProformaOrders.OrderEntryID
			LEFT OUTER JOIN (SELECT OrderNo,ItemID,SUM(Qty) AS StockQty FROM StockOrderAdjustments GROUP BY OrderNo,ItemID) TStock ON TOrders.CompItemCode=TStock.ItemID AND TOrders.OrderNo=TStock.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(IssQty) AS SFIssQty FROM StockOrderOpening_Issuance INNER JOIN VendIssdDetail ON StockOrderOpening_Issuance.VID_RefID=VendIssdDetail.EntryID GROUP BY OrderNo,ItemCode) TStockSF ON TOrders.CompItemCode=TStockSF.ItemCode AND TOrders.OrderNo=TStockSF.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,MAX(DT) AS PODT,SUM(IssQty) AS POQty FROM VendIssued INNER JOIN VendIssdDetail ON VendIssued.EntryID=VendIssdDetail.RefID
										WHERE MasterPONo IS NOT NULL GROUP BY OrderNo,ItemCode) TPO ON TOrders.CompItemCode=TPO.ItemCode AND TOrders.OrderNo=TPO.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS ForgingQty FROM VVendRcvdDetail_Simple WHERE ProcessID=88 GROUP BY OrderNo,ItemCode) TForging ON TOrders.CompItemCode=TForging.ItemCode AND TOrders.OrderNo=TForging.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS MachiningQty FROM VVendRcvdDetail_Simple WHERE ProcessID=90 GROUP BY OrderNo,ItemCode) TMachining ON TOrders.CompItemCode=TMachining.ItemCode AND TOrders.OrderNo=TMachining.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS FilingQty FROM VVendRcvdDetail_Simple WHERE ProcessID=92 GROUP BY OrderNo,ItemCode) TFiling ON TOrders.CompItemCode=TFiling.ItemCode AND TOrders.OrderNo=TFiling.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS TemperQty FROM VVendRcvdDetail_Simple WHERE ProcessID=95 GROUP BY OrderNo,ItemCode) TTemper ON TOrders.CompItemCode=TTemper.ItemCode AND TOrders.OrderNo=TTemper.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(IssQty) AS PolishingIssQty FROM VendIssdDetail INNER JOIN VendIssued ON VendIssued.EntryID=VendIssdDetail.RefID WHERE ProcessID=99 GROUP BY OrderNo,ItemCode) TPolishingIss ON TOrders.CompItemCode=TPolishingIss.ItemCode AND TOrders.OrderNo=TPolishingIss.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS PolishingRcvQty FROM VVendRcvdDetail_Simple WHERE ProcessID=99  GROUP BY OrderNo,ItemCode) TPolishingRcv ON TOrders.CompItemCode=TPolishingRcv.ItemCode AND TOrders.OrderNo=TPolishingRcv.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS SettingQty FROM VVendRcvdDetail_Simple WHERE ProcessID=119 GROUP BY OrderNo,ItemCode) TSetting ON TOrders.CompItemCode=TSetting.ItemCode AND TOrders.OrderNo=TSetting.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS FinalPolQty FROM VVendRcvdDetail_Simple WHERE ProcessID=32 GROUP BY OrderNo,ItemCode) FinalPol ON TOrders.CompItemCode=FinalPol.ItemCode AND TOrders.OrderNo=FinalPol.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS FinalInspQty FROM VVendRcvdDetail_Simple WHERE ProcessID=74 GROUP BY OrderNo,ItemCode) FinalInsp ON TOrders.CompItemCode=FinalInsp.ItemCode AND TOrders.OrderNo=FinalInsp.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS PackingQty FROM VVendRcvdDetail_Simple WHERE ProcessID=100 GROUP BY OrderNo,ItemCode) TPacking ON TOrders.CompItemCode=TPacking.ItemCode AND TOrders.OrderNo=TPacking.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,MAX(VendIssued.DT) AS Annealing_IssDT,SUM(IssQty) AS AnnealingIssQty FROM VendIssdDetail INNER JOIN VendIssued ON VendIssued.EntryID=VendIssdDetail.RefID WHERE ProcessID=141 GROUP BY OrderNo,ItemCode) TAnnealingIss ON TOrders.CompItemCode=TAnnealingIss.ItemCode AND TOrders.OrderNo=TAnnealingIss.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS AnnealingRcvdQty FROM VVendRcvdDetail_Simple WHERE ProcessID=141 GROUP BY OrderNo,ItemCode) TAnnealing ON TOrders.CompItemCode=TAnnealing.ItemCode AND TOrders.OrderNo=TAnnealing.OrderNo

			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(IssQty) AS MillingIssQty FROM VendIssdDetail INNER JOIN VendIssued ON VendIssued.EntryID=VendIssdDetail.RefID WHERE ProcessID=88 GROUP BY OrderNo,ItemCode) TMillingIss ON TOrders.CompItemCode=TMillingIss.ItemCode AND TOrders.OrderNo=TMillingIss.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS MillingRcvQty FROM VVendRcvdDetail_Simple WHERE ProcessID=88 GROUP BY OrderNo,ItemCode) TMillingRcv ON TOrders.CompItemCode=TMillingRcv.ItemCode AND TOrders.OrderNo=TMillingRcv.OrderNo

			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(IssQty) AS FilingIssQty FROM VendIssdDetail INNER JOIN VendIssued ON VendIssued.EntryID=VendIssdDetail.RefID WHERE ProcessID=90 GROUP BY OrderNo,ItemCode) TFilingIss ON TOrders.CompItemCode=TFilingIss.ItemCode AND TOrders.OrderNo=TFilingIss.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS FilingRcvQty FROM VVendRcvdDetail_Simple WHERE ProcessID=90 GROUP BY OrderNo,ItemCode) TFilingRcv ON TOrders.CompItemCode=TFilingRcv.ItemCode AND TOrders.OrderNo=TFilingRcv.OrderNo

