			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS MasterPORcvdQty FROM VVendRcvdDetail_Simple INNER JOIN VendIssued ON VVendRcvdDetail_Simple.Issuance_RefID=VendIssued.EntryID WHERE MasterPONo IS NOT NULL GROUP BY OrderNo,ItemCode) TMasterPORcv ON TOrders.CompItemCode=TMasterPORcv.ItemCode AND TOrders.OrderNo=TMasterPORcv.OrderNo


