CREATE PROCEDURE [dbo].[OrderStatusReport_SP_Old] (@DTFrom AS DATETIME=NULL,@DTTo AS DATETIME=NULL,@CustCode AS VARCHAR(50)=NULL,@Country AS VARCHAR(50)=NULL,@OrderNo AS VARCHAR(4000)='0',@CatID AS INT=0,@FOI_IDs AS VARCHAR(4000)='0') AS

BEGIN
