			LEFT OUTER JOIN (SELECT OrderNo,ItemID,SUM(Qty) AS StockQty FROM StockOrderAdjustments GROUP BY OrderNo,ItemID) TStock ON TOrders.CompItemCode=TStock.ItemID AND TOrders.OrderNo=TStock.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(IssQty) AS SFIssQty FROM StockOrderOpening_Issuance INNER JOIN VendIssdDetail ON StockOrderOpening_Issuance.VID_RefID=VendIssdDetail.EntryID GROUP BY OrderNo,ItemCode) TStockSF ON TOrders.CompItemCode=TStockSF.ItemCode AND TOrders.OrderNo=TStockSF.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,MAX(DT) AS PODT,SUM(IssQty) AS POQty FROM VendIssued INNER JOIN VendIssdDetail ON VendIssued.EntryID=VendIssdDetail.RefID
										WHERE MasterPONo IS NOT NULL GROUP BY OrderNo,ItemCode) TPO ON TOrders.CompItemCode=TPO.ItemCode AND TOrders.OrderNo=TPO.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS ForgingQty FROM VVendRcvdDetail_Simple WHERE ProcessID=88 GROUP BY OrderNo,ItemCode) TForging ON TOrders.CompItemCode=TForging.ItemCode AND TOrders.OrderNo=TForging.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS MachiningQty FROM VVendRcvdDetail_Simple WHERE ProcessID=90 GROUP BY OrderNo,ItemCode) TMachining ON TOrders.CompItemCode=TMachining.ItemCode AND TOrders.OrderNo=TMachining.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS FilingQty FROM VVendRcvdDetail_Simple WHERE ProcessID=92 GROUP BY OrderNo,ItemCode) TFiling ON TOrders.CompItemCode=TFiling.ItemCode AND TOrders.OrderNo=TFiling.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS TemperQty FROM VVendRcvdDetail_Simple WHERE ProcessID=95 GROUP BY OrderNo,ItemCode) TTemper ON TOrders.CompItemCode=TTemper.ItemCode AND TOrders.OrderNo=TTemper.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(IssQty) AS PolishingIssQty FROM VendIssdDetail INNER JOIN VendIssued ON VendIssued.EntryID=VendIssdDetail.RefID WHERE ProcessID=99 GROUP BY OrderNo,ItemCode) TPolishingIss ON TOrders.CompItemCode=TPolishingIss.ItemCode AND TOrders.OrderNo=TPolishingIss.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS PolishingRcvQty FROM VVendRcvdDetail_Simple WHERE ProcessID=99  GROUP BY OrderNo,ItemCode) TPolishingRcv ON TOrders.CompItemCode=TPolishingRcv.ItemCode AND TOrders.OrderNo=TPolishingRcv.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS SettingQty FROM VVendRcvdDetail_Simple WHERE ProcessID=119 GROUP BY OrderNo,ItemCode) TSetting ON TOrders.CompItemCode=TSetting.ItemCode AND TOrders.OrderNo=TSetting.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS FinalPolQty FROM VVendRcvdDetail_Simple WHERE ProcessID=32 GROUP BY OrderNo,ItemCode) FinalPol ON TOrders.CompItemCode=FinalPol.ItemCode AND TOrders.OrderNo=FinalPol.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS FinalInspQty FROM VVendRcvdDetail_Simple WHERE ProcessID=74 GROUP BY OrderNo,ItemCode) FinalInsp ON TOrders.CompItemCode=FinalInsp.ItemCode AND TOrders.OrderNo=FinalInsp.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS PackingQty FROM VVendRcvdDetail_Simple WHERE ProcessID=100 GROUP BY OrderNo,ItemCode) TPacking ON TOrders.CompItemCode=TPacking.ItemCode AND TOrders.OrderNo=TPacking.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(Qty) AS DPQty FROM VDispatchListDetail_Adv  GROUP BY OrderNo,ItemCode) TDP ON TOrders.CompItemCode=TDP.ItemCode AND TOrders.OrderNo=TDP.OrderNo
			LEFT OUTER JOIN (SELECT OrderNo,ItemID,SUM(Qty) AS BookmarkQty FROM VID_Bookmarks WHERE ViewDone=0 GROUP BY OrderNo,ItemID) TBookMarks ON TOrders.CompItemCode=TBookMarks.ItemID AND TOrders.OrderNo=TBookMarks.OrderNo
			INNER JOIN VUnshippedOrderItemList ON TOrders.OrderNo=VUnshippedOrderItemList.OrderNo AND TOrders.CompItemCode=VUnshippedOrderItemList.CompItemCode

		--CREATE TABLE #myTBLOrders(OrderNo VARCHAR(50),ItemID VARCHAR(50))

		--SET @myQuery='INSERT INTO #myTBLOrders(OrderNo,ItemID) SELECT OrderNo,CompItemCode FROM FOrderItems WHERE ID  IN(' + @FOI_IDs +')'
		--EXEC(@myQuery)

		--SELECT TOrders.OrderNo,Items.ItemID,ItemName,TOrders.Qty AS OrderQty,StockQty,SFIssQty,POQty,PODT,TForging.ForgingQty,TMachining.MachiningQty,
		--TTemper.TemperQty,TPolishing.PolishingQty,SettingQty,FinalPolQty,FinalInspQty,PackingQty,ShippedQty,DPQty,BookmarkQty,TradeTerms,LastShipmentDate,TOrders.ItemCode,TOrders.Price,TOrders.DeliveryDT,DeliveryStatus,InternalRefNo,FCustomerOrders.DT,FCustomerOrders.CustCode,FProformaOrders.PInvoice  FROM Items
		--INNER JOIN FOrderItems TOrders ON Items.ItemID=TOrders.CompItemCode INNER JOIN #myTBLOrders myTBL ON TOrders.OrderNo=myTBL.OrderNo
		--INNER JOIN FCustomerOrders ON TOrders.OrderNo=FCustomerOrders.OrderNo
		--INNER JOIN FProformaOrders ON TOrders.ID=FProformaOrders.OrderEntryID
		--	LEFT OUTER JOIN (SELECT OrderNo,ItemID,SUM(Qty) AS StockQty FROM StockOrderAdjustments GROUP BY OrderNo,ItemID) TStock ON TOrders.CompItemCode=TStock.ItemID AND TOrders.OrderNo=TStock.OrderNo
		--	LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(IssQty) AS SFIssQty FROM StockOrderOpening_Issuance INNER JOIN VendIssdDetail ON StockOrderOpening_Issuance.VID_RefID=VendIssdDetail.EntryID GROUP BY OrderNo,ItemCode) TStockSF ON TOrders.CompItemCode=TStockSF.ItemCode AND TOrders.OrderNo=TStockSF.OrderNo
		--	LEFT OUTER JOIN (SELECT OrderNo,ItemCode,MAX(DT) AS PODT,SUM(IssQty) AS POQty FROM VendIssued INNER JOIN VendIssdDetail ON VendIssued.EntryID=VendIssdDetail.RefID
		--								WHERE MasterPONo IS NOT NULL GROUP BY OrderNo,ItemCode) TPO ON TOrders.CompItemCode=TPO.ItemCode AND TOrders.OrderNo=TPO.OrderNo

		--	LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS ForgingQty FROM VVendRcvdDetail_Simple WHERE ProcessID=88 GROUP BY OrderNo,ItemCode) TForging ON TOrders.CompItemCode=TForging.ItemCode AND TOrders.OrderNo=TForging.OrderNo

		--	LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS MachiningQty FROM VVendRcvdDetail_Simple WHERE ProcessID=90 GROUP BY OrderNo,ItemCode) TMachining ON TOrders.CompItemCode=TMachining.ItemCode AND TOrders.OrderNo=TMachining.OrderNo

		--	LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS FilingQty FROM VVendRcvdDetail_Simple WHERE ProcessID=92 GROUP BY OrderNo,ItemCode) TFiling ON TOrders.CompItemCode=TFiling.ItemCode AND TOrders.OrderNo=TFiling.OrderNo

		--	LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS TemperQty FROM VVendRcvdDetail_Simple WHERE ProcessID=95 GROUP BY OrderNo,ItemCode) TTemper ON TOrders.CompItemCode=TTemper.ItemCode AND TOrders.OrderNo=TTemper.OrderNo

		--	LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS PolishingQty FROM VVendRcvdDetail_Simple WHERE ProcessID=99 GROUP BY OrderNo,ItemCode) TPolishing ON TOrders.CompItemCode=TPolishing.ItemCode AND TOrders.OrderNo=TPolishing.OrderNo

		--	LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS SettingQty FROM VVendRcvdDetail_Simple WHERE ProcessID=119 GROUP BY OrderNo,ItemCode) TSetting ON TOrders.CompItemCode=TSetting.ItemCode AND TOrders.OrderNo=TSetting.OrderNo

		--	LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS FinalPolQty FROM VVendRcvdDetail_Simple WHERE ProcessID=32 GROUP BY OrderNo,ItemCode) FinalPol ON TOrders.CompItemCode=FinalPol.ItemCode AND TOrders.OrderNo=FinalPol.OrderNo

		--	LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS FinalInspQty FROM VVendRcvdDetail_Simple WHERE ProcessID=74 GROUP BY OrderNo,ItemCode) FinalInsp ON TOrders.CompItemCode=FinalInsp.ItemCode AND TOrders.OrderNo=FinalInsp.OrderNo

		--	LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(RcvdQty) AS PackingQty FROM VVendRcvdDetail_Simple WHERE ProcessID=130 GROUP BY OrderNo,ItemCode) TPacking ON TOrders.CompItemCode=TPacking.ItemCode AND TOrders.OrderNo=TPacking.OrderNo

		--	LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(Qty) AS DPQty FROM VDispatchListDetail_Adv  GROUP BY OrderNo,ItemCode) TDP ON TOrders.CompItemCode=TDP.ItemCode AND TOrders.OrderNo=TDP.OrderNo

		--	LEFT OUTER JOIN (SELECT OrderNo,ItemID,SUM(Qty) AS BookmarkQty FROM VID_Bookmarks WHERE ViewDone=0 GROUP BY OrderNo,ItemID) TBookMarks ON TOrders.CompItemCode=TBookMarks.ItemID AND TOrders.OrderNo=TBookMarks.OrderNo

		--	INNER JOIN VUnshippedOrderItemList ON TOrders.OrderNo=VUnshippedOrderItemList.OrderNo AND TOrders.CompItemCode=VUnshippedOrderItemList.CompItemCode

