CREATE PROCEDURE [dbo].[OverTimeIndividualReport_SP] (@EmpID VARCHAR(50),@DTFrom DATETIME,@DTTo DATETIME) AS

SET @DTFrom=CONVERT(varchar(50),@DTFrom,6)
SET @DTTo=CONVERT(varchar(50),@DTTo,6)

DECLARE @myDT DATETIME
DECLARE @myDTTBL TABLE(myDT  DATETIME,myMonth VARCHAR(50))
SET @myDT=@DTFrom
WHILE @myDT<=@DTTo
	BEGIN
		INSERT INTO @myDTTBL(myDT,myMonth) VALUES(@myDT,LEFT(CONVERT(Varchar(50),@myDT,11),5))
		SET @myDT=DATEADD(m,1,@myDT)
	END

SELECT VEmp.EmpID,VEmp.Name,Rel,FName,JoinDate,VEmp.DeptID,DeptName,myDTTBL.myDT,myDTTBL.myMonth,Balance,TotalHrs,TotalFrequency,StartingSalary,OAmt FROM VEmp
	CROSS JOIN @myDTTBL myDTTBL
	LEFT OUTER JOIN (SELECT EmpID,LEFT(CONVERT(Varchar(50),DT,11),5) AS myMonth,Balance,Total,OAmt FROM MonthlySalaries WHERE EmpID=@EmpID AND DT BETWEEN @DTFrom AND @DTTo) Tab1
	ON VEmp.EmpID=Tab1.EmpID AND myDTTBL.myMonth=Tab1.myMonth
	LEFT OUTER JOIN (SELECT EmpiD,LEFT(CONVERT(Varchar(50),DT,11),5) AS myMonth,SUM(PayableHrs) AS TotalHrs,COUNT(EmpID) AS TotalFrequency FROM EmpTimes WHERE OverTime=1 AND EmpID=@EmpID AND DT BETWEEN @DTFrom AND @DTTo GROUP BY EmpID,LEFT(CONVERT(Varchar(50),DT,11),5)) TabOT
	ON VEmp.EmpID=TabOT.EmpID AND myDTTBL.myMonth=TabOT.myMonth
	WHERE VEmp.EmpID=@EmpID
GO
