CREATE PROCEDURE [dbo].[OverTimeYearlyReport_SP] (@DTFrom DATETIME,@DTTo DATETIME) AS

SET @DTFrom=CONVERT(varchar(50),@DTFrom,6)
SET @DTTo=CONVERT(varchar(50),@DTTo,6)

DECLARE @DTFrom1 AS DATETIME,@DTTo1 AS DATETIME
DECLARE @DTFrom2 AS DATETIME,@DTTo2 AS DATETIME
DECLARE @DTFrom3 AS DATETIME,@DTTo3 AS DATETIME
DECLARE @DTFrom4 AS DATETIME,@DTTo4 AS DATETIME
DECLARE @DTFrom5 AS DATETIME,@DTTo5 AS DATETIME
DECLARE @DTFrom6 AS DATETIME,@DTTo6 AS DATETIME
DECLARE @DTFrom7 AS DATETIME,@DTTo7 AS DATETIME
DECLARE @DTFrom8 AS DATETIME,@DTTo8 AS DATETIME
DECLARE @DTFrom9 AS DATETIME,@DTTo9 AS DATETIME
DECLARE @DTFrom10 AS DATETIME,@DTTo10 AS DATETIME
DECLARE @DTFrom11 AS DATETIME,@DTTo11 AS DATETIME
DECLARE @DTFrom12 AS DATETIME,@DTTo12 AS DATETIME

SET @DTFrom1=@DTFrom;SET @DTFrom2=DateAdd(m,1,@DTFrom);SET @DTFrom3=DateAdd(m,2,@DTFrom);SET @DTFrom4=DateAdd(m,3,@DTFrom)
SET @DTFrom5=DateAdd(m,4,@DTFrom);SET @DTFrom6=DateAdd(m,5,@DTFrom);SET @DTFrom7=DateAdd(m,6,@DTFrom);SET @DTFrom8=DateAdd(m,7,@DTFrom)
SET @DTFrom9=DateAdd(m,8,@DTFrom);SET @DTFrom10=DateAdd(m,9,@DTFrom);SET @DTFrom11=DateAdd(m,10,@DTFrom);SET @DTFrom12=DateAdd(m,11,@DTFrom)

SET @DTTo1=DateAdd(d,-1,DateAdd(m,1,@DTFrom1));SET @DTTo2=DateAdd(d,-1,DateAdd(m,1,@DTFrom2));SET @DTTo3=DateAdd(d,-1,DateAdd(m,1,@DTFrom3))
SET @DTTo4=DateAdd(d,-1,DateAdd(m,1,@DTFrom4));SET @DTTo5=DateAdd(d,-1,DateAdd(m,1,@DTFrom5));SET @DTTo6=DateAdd(d,-1,DateAdd(m,1,@DTFrom6))
SET @DTTo7=DateAdd(d,-1,DateAdd(m,1,@DTFrom7));SET @DTTo8=DateAdd(d,-1,DateAdd(m,1,@DTFrom8));SET @DTTo9=DateAdd(d,-1,DateAdd(m,1,@DTFrom9))
SET @DTTo10=DateAdd(d,-1,DateAdd(m,1,@DTFrom10));SET @DTTo11=DateAdd(d,-1,DateAdd(m,1,@DTFrom11));SET @DTTo12=DateAdd(d,-1,DateAdd(m,1,@DTFrom12))

DECLARE @myReturnTBL TABLE(EmpID VARCHAR(50),Month1 REAL,Month2 REAL,Month3 REAL,Month4 REAL,Month5 REAL,Month6 REAL,Month7 REAL,Month8 REAL,Month9 REAL,Month10 REAL,Month11 REAL,Month12 REAL)
INSERT INTO @myReturnTBL (EmpID) SELECT Distinct EmpID FROM EmpTimes WHERE OverTime=1 AND DT BETWEEN @DTFrom AND @DTTo

UPDATE @myReturnTBL SET Month1=Month1.TotalHrs
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,SUM(PayableHrs) AS TotalHrs FROM EmpTimes WHERE OverTime=1 AND DT BETWEEN @DTFrom1 AND @DTTo1 GROUP BY EmpID) Month1  ON myReturnTBL.EmpID=Month1.EmpID

UPDATE @myReturnTBL SET Month2=Month2.TotalHrs
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,SUM(PayableHrs) AS TotalHrs FROM EmpTimes WHERE OverTime=1 AND DT BETWEEN @DTFrom2 AND @DTTo2 GROUP BY EmpID) Month2  ON myReturnTBL.EmpID=Month2.EmpID

UPDATE @myReturnTBL SET Month3=Month3.TotalHrs
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,SUM(PayableHrs) AS TotalHrs FROM EmpTimes WHERE OverTime=1 AND DT BETWEEN @DTFrom3 AND @DTTo3 GROUP BY EmpID) Month3  ON myReturnTBL.EmpID=Month3.EmpID

UPDATE @myReturnTBL SET Month4=Month4.TotalHrs
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,SUM(PayableHrs) AS TotalHrs FROM EmpTimes WHERE OverTime=1 AND DT BETWEEN @DTFrom4 AND @DTTo4 GROUP BY EmpID) Month4  ON myReturnTBL.EmpID=Month4.EmpID

UPDATE @myReturnTBL SET Month5=Month5.TotalHrs
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,SUM(PayableHrs) AS TotalHrs FROM EmpTimes WHERE OverTime=1 AND DT BETWEEN @DTFrom5 AND @DTTo5 GROUP BY EmpID) Month5  ON myReturnTBL.EmpID=Month5.EmpID

UPDATE @myReturnTBL SET Month6=Month6.TotalHrs
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,SUM(PayableHrs) AS TotalHrs FROM EmpTimes WHERE OverTime=1 AND DT BETWEEN @DTFrom6 AND @DTTo6 GROUP BY EmpID) Month6  ON myReturnTBL.EmpID=Month6.EmpID

UPDATE @myReturnTBL SET Month7=Month7.TotalHrs
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,SUM(PayableHrs) AS TotalHrs FROM EmpTimes WHERE OverTime=1 AND DT BETWEEN @DTFrom7 AND @DTTo7 GROUP BY EmpID) Month7  ON myReturnTBL.EmpID=Month7.EmpID

UPDATE @myReturnTBL SET Month8=Month8.TotalHrs
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,SUM(PayableHrs) AS TotalHrs FROM EmpTimes WHERE OverTime=1 AND DT BETWEEN @DTFrom8 AND @DTTo8 GROUP BY EmpID) Month8  ON myReturnTBL.EmpID=Month8.EmpID

UPDATE @myReturnTBL SET Month9=Month9.TotalHrs
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,SUM(PayableHrs) AS TotalHrs FROM EmpTimes WHERE OverTime=1 AND DT BETWEEN @DTFrom9 AND @DTTo9 GROUP BY EmpID) Month9  ON myReturnTBL.EmpID=Month9.EmpID

UPDATE @myReturnTBL SET Month10=Month10.TotalHrs
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,SUM(PayableHrs) AS TotalHrs FROM EmpTimes WHERE OverTime=1 AND DT BETWEEN @DTFrom10 AND @DTTo10 GROUP BY EmpID) Month10  ON myReturnTBL.EmpID=Month10.EmpID

UPDATE @myReturnTBL SET Month11=Month11.TotalHrs
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,SUM(PayableHrs) AS TotalHrs FROM EmpTimes WHERE OverTime=1 AND DT BETWEEN @DTFrom11 AND @DTTo11 GROUP BY EmpID) Month11  ON myReturnTBL.EmpID=Month11.EmpID

UPDATE @myReturnTBL SET Month12=Month12.TotalHrs
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT EmpID,SUM(PayableHrs) AS TotalHrs FROM EmpTimes WHERE OverTime=1 AND DT BETWEEN @DTFrom12 AND @DTTo12 GROUP BY EmpID) Month12  ON myReturnTBL.EmpID=Month12.EmpID

--We can add Salaries of each month from monthly salaries to get the exact rates here...

SELECT VEmp.EmpID,VEmp.Name,Rel,FName,JoinDate,VEmp.DeptID,DeptName,StartingSalary
	,Month1,Month2,Month3,Month4,Month5,Month6,Month7,Month8,Month9,Month10,Month11,Month12
	FROM VEmp
	INNER JOIN @myReturnTBL myReturnTBL ON VEmp.EmpID=myReturnTBL.EmpID
GO
