CREATE PROCEDURE [dbo].[PaymentStatusNew_SP]  AS

/*
Null Entry Means <All Customers> Or <All Countries>
@Status
0=Unpaid
1=Paid
2=All
*/

	 BEGIN

		SELECT VPaymentStatus.*
		FROM VPaymentStatus INNER JOIN ForeignCustomers ON VPaymentStatus.CustCode=ForeignCustomers.CustCode AND VPaymentStatus.Country=ForeignCustomers.Country
		WHERE CustomPayment<>0
		AND VPaymentStatus.CustomInvoice IN(SELECT CustomInvoice FROM VCustomInvoiceAmtStatus WHERE ROUND(TotalAmt-TotalAmtRcvd,0)>0) ORDER BY VPaymentStatus.CustCode,AWBNoDT

	END
GO
/****** Object:  StoredProcedure [dbo].[PiecesReport_SP]    Script Date: 6/29/2026 4:50:02 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[PiecesReport_SP] (@CustCode AS VARCHAR(4000)=NULL,@ItemGroups AS VARCHAR(4000)=NULL) AS

BEGIN
SET ANSI_WARNINGS OFF
DECLARE @myQuery AS VARCHAR(4000)

		BEGIN
		CREATE TABLE #Customers (CustCode VARCHAR(50))
		CREATE TABLE #ItemGroups(GroupID INT)
		CREATE TABLE #OrderItems(OrderNo VARCHAR(50),ItemID VARCHAR(255),GroupID INT)
		IF @CustCode='0'
			SET @myQuery='INSERT INTO #Customers(CustCode) SELECT DISTINCT CustCode FROM FCustomerOrders'
		ELSE
			SET @myQuery='INSERT INTO #Customers(CustCode) SELECT DISTINCT CustCode FROM FCustomerOrders WHERE CustCode IN(' + @CustCode +')'
		EXEC(@myQuery)

		IF @ItemGroups='0'
			SET @myQuery='INSERT INTO #ItemGroups(GroupID) SELECT ID FROM ItemGroups'
		ELSE
			SET @myQuery='INSERT INTO #ItemGroups(GroupID) SELECT ID FROM ItemGroups WHERE ID IN(' + @ItemGroups +')'

		EXEC(@myQuery)

		INSERT INTO #OrderItems(OrderNo,ItemID,GroupID)
			SELECT FOrderItems.OrderNo,Items.ItemID,Items.GroupID FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
				INNER JOIN #Customers ON FCustomerOrders.CustCode=#Customers.CustCode
				INNER JOIN Items ON FOrderItems.CompItemCode=Items.ItemID
				INNER JOIN ItemGroups ON Items.GroupID=ItemGroups.ID

		SELECT ItemGroups.Description,ItemGroups.ID,PendingOrders,PendingQty,PendingValue,ShippedOrders,ShippedQty,ShippedValue,
			ForgingQty,MachiningQty,FilingQty,TemperQty,PolishingQty,UltraQty,TuckQty,SettingQty,PassivationQty,FinalPolQty,FinalChkQty,PackQty
		 FROM ItemGroups
			LEFT OUTER JOIN (SELECT #OrderItems.GroupID,COUNT(DISTINCT VFOrderItemswithShippedQty.OrderNo) AS PendingOrders,SUM(Qty-ShippedQty) AS PendingQty,SUM(Price*(Qty-ShippedQty)) AS PendingValue FROM VFOrderItemswithShippedQty
							INNER JOIN #OrderItems ON VFOrderItemswithShippedQty.OrderNo=#OrderItems.OrderNo AND VFOrderItemswithShippedQty.CompItemCode=#OrderItems.ItemID
							WHERE (Qty-ShippedQty)>0
							GROUP BY #OrderItems.GroupID) TPendingOrders ON ItemGroups.ID=TPendingOrders.GroupID

			LEFT OUTER JOIN (SELECT #OrderItems.GroupID,COUNT(DISTINCT VFOrderItemswithShippedQty.OrderNo) AS ShippedOrders,SUM(ShippedQty) AS ShippedQty,SUM(ShippedQty*Price) AS ShippedValue FROM VFOrderItemswithShippedQty
							INNER JOIN #OrderItems ON VFOrderItemswithShippedQty.OrderNo=#OrderItems.OrderNo AND VFOrderItemswithShippedQty.CompItemCode=#OrderItems.ItemID
							WHERE (Qty-ShippedQty)<=0
							GROUP BY #OrderItems.GroupID) TShippedOrders ON ItemGroups.ID=TShippedOrders.GroupID


			LEFT OUTER JOIN (SELECT #OrderItems.GroupID,SUM(RcvdQty-IssQty) AS ForgingQty FROM VVendRcvdDetail_Simple INNER JOIN #OrderItems ON VVendRcvdDetail_Simple.OrderNo=#OrderItems.OrderNo AND VVendRcvdDetail_Simple.ItemCode=#OrderItems.ItemID WHERE ProcessID=1 GROUP BY #OrderItems.GroupID) TForging ON ItemGroups.ID=TForging.GroupID
			LEFT OUTER JOIN (SELECT #OrderItems.GroupID,SUM(RcvdQty-IssQty) AS MachiningQty FROM VVendRcvdDetail_Simple INNER JOIN #OrderItems ON VVendRcvdDetail_Simple.OrderNo=#OrderItems.OrderNo AND VVendRcvdDetail_Simple.ItemCode=#OrderItems.ItemID WHERE ProcessID=4 GROUP BY #OrderItems.GroupID) TMachining ON ItemGroups.ID=TMachining.GroupID
			LEFT OUTER JOIN (SELECT #OrderItems.GroupID,SUM(RcvdQty-IssQty) AS FilingQty FROM VVendRcvdDetail_Simple INNER JOIN #OrderItems ON VVendRcvdDetail_Simple.OrderNo=#OrderItems.OrderNo AND VVendRcvdDetail_Simple.ItemCode=#OrderItems.ItemID WHERE ProcessID=6 GROUP BY #OrderItems.GroupID) TFiling ON ItemGroups.ID=TFiling.GroupID
			LEFT OUTER JOIN (SELECT #OrderItems.GroupID,SUM(RcvdQty-IssQty) AS TemperQty FROM VVendRcvdDetail_Simple INNER JOIN #OrderItems ON VVendRcvdDetail_Simple.OrderNo=#OrderItems.OrderNo AND VVendRcvdDetail_Simple.ItemCode=#OrderItems.ItemID WHERE ProcessID=10 GROUP BY #OrderItems.GroupID) TTemper ON ItemGroups.ID=TTemper.GroupID
			LEFT OUTER JOIN (SELECT #OrderItems.GroupID,SUM(RcvdQty-IssQty) AS PolishingQty FROM VVendRcvdDetail_Simple INNER JOIN #OrderItems ON VVendRcvdDetail_Simple.OrderNo=#OrderItems.OrderNo AND VVendRcvdDetail_Simple.ItemCode=#OrderItems.ItemID WHERE ProcessID=27 GROUP BY #OrderItems.GroupID) TPolishing ON ItemGroups.ID=TPolishing.GroupID
			LEFT OUTER JOIN (SELECT #OrderItems.GroupID,SUM(RcvdQty-IssQty) AS UltraQty FROM VVendRcvdDetail_Simple INNER JOIN #OrderItems ON VVendRcvdDetail_Simple.OrderNo=#OrderItems.OrderNo AND VVendRcvdDetail_Simple.ItemCode=#OrderItems.ItemID WHERE ProcessID=34 GROUP BY #OrderItems.GroupID) TUltra ON ItemGroups.ID=TUltra.GroupID
			LEFT OUTER JOIN (SELECT #OrderItems.GroupID,SUM(RcvdQty-IssQty) AS TuckQty FROM VVendRcvdDetail_Simple INNER JOIN #OrderItems ON VVendRcvdDetail_Simple.OrderNo=#OrderItems.OrderNo AND VVendRcvdDetail_Simple.ItemCode=#OrderItems.ItemID WHERE ProcessID=68 GROUP BY #OrderItems.GroupID) TTuck ON ItemGroups.ID=TTuck.GroupID
			LEFT OUTER JOIN (SELECT #OrderItems.GroupID,SUM(RcvdQty-IssQty) AS SettingQty FROM VVendRcvdDetail_Simple INNER JOIN #OrderItems ON VVendRcvdDetail_Simple.OrderNo=#OrderItems.OrderNo AND VVendRcvdDetail_Simple.ItemCode=#OrderItems.ItemID WHERE ProcessID=21 GROUP BY #OrderItems.GroupID) TSetting ON ItemGroups.ID=TSetting.GroupID
			LEFT OUTER JOIN (SELECT #OrderItems.GroupID,SUM(RcvdQty-IssQty) AS PassivationQty FROM VVendRcvdDetail_Simple INNER JOIN #OrderItems ON VVendRcvdDetail_Simple.OrderNo=#OrderItems.OrderNo AND VVendRcvdDetail_Simple.ItemCode=#OrderItems.ItemID WHERE ProcessID=24 GROUP BY #OrderItems.GroupID) TPassivation ON ItemGroups.ID=TPassivation.GroupID
			LEFT OUTER JOIN (SELECT #OrderItems.GroupID,SUM(RcvdQty-IssQty) AS FinalPolQty FROM VVendRcvdDetail_Simple INNER JOIN #OrderItems ON VVendRcvdDetail_Simple.OrderNo=#OrderItems.OrderNo AND VVendRcvdDetail_Simple.ItemCode=#OrderItems.ItemID WHERE ProcessID=32 GROUP BY #OrderItems.GroupID) TFinalPol ON ItemGroups.ID=TFinalPol.GroupID
			LEFT OUTER JOIN (SELECT #OrderItems.GroupID,SUM(RcvdQty-IssQty) AS FinalChkQty FROM VVendRcvdDetail_Simple INNER JOIN #OrderItems ON VVendRcvdDetail_Simple.OrderNo=#OrderItems.OrderNo AND VVendRcvdDetail_Simple.ItemCode=#OrderItems.ItemID WHERE ProcessID=73 GROUP BY #OrderItems.GroupID) TFinalChk ON ItemGroups.ID=TFinalChk.GroupID
			LEFT OUTER JOIN (SELECT #OrderItems.GroupID,SUM(RcvdQty-IssQty) AS PackQty FROM VVendRcvdDetail_Simple INNER JOIN #OrderItems ON VVendRcvdDetail_Simple.OrderNo=#OrderItems.OrderNo AND VVendRcvdDetail_Simple.ItemCode=#OrderItems.ItemID WHERE ProcessID=88 GROUP BY #OrderItems.GroupID) TPack ON ItemGroups.ID=TPack.GroupID

			INNER JOIN #ItemGroups ON ItemGroups.ID=#ItemGroups.GroupID

			WHERE NOT (ISNULL(PackQty,0)=0 AND ISNULL(FinalChkQty,0)=0 AND ISNULL(FinalPolQty,0)=0 AND ISNULL(PassivationQty,0)=0 AND ISNULL(SettingQty,0)=0 AND ISNULL(TuckQty,0)=0 AND ISNULL(UltraQty,0)=0
			AND ISNULL(PolishingQty,0)=0 AND ISNULL(TemperQty,0)=0 AND ISNULL(FilingQty,0)=0 AND ISNULL(MachiningQty,0)=0 AND ISNULL(ForgingQty,0)=0 AND ISNULL(PendingQty,0)=0)
		END

SET ANSI_WARNINGS ON
END

GO
