CREATE PROCEDURE [dbo].[PlanningReport_SP](@DTFrom DATETIME,@DTTo DATETIME,@CustCode VARCHAR(4000)='',@ItemGroups VARCHAR(4000)='')
AS
BEGIN

SET @DTFrom=CAST(CONVERT(VARCHAR(50),@DTFrom,6) AS DATETIME)
SET @DTTo=CAST(CONVERT(VARCHAR(50),@DTTo,6) AS DATETIME)

CREATE TABLE #Customers(CustCode VARCHAR(50))
CREATE TABLE #ItemGroups(GroupID INT,GroupName VARCHAR(255))
DECLARE @myQuery AS VARCHAR(1000)
IF @CustCode=''
	SET @myQuery='INSERT INTO #Customers(CustCode) SELECT CustCode FROM ForeignCustomers'
ELSE
	SET @myQuery='INSERT INTO #Customers(CustCode) SELECT CustCode FROM ForeignCustomers WHERE CustCode IN(' + @CustCode +')'

EXEC(@myQuery)

IF @ItemGroups=''
	SET @myQuery='INSERT INTO #ItemGroups(GroupID,GroupName) SELECT ID,Description FROM ItemGroups'
ELSE
	SET @myQuery='INSERT INTO #ItemGroups(GroupID,GroupName) SELECT ID,Description FROM ItemGroups WHERE ID IN(' + @ItemGroups + ')'

EXEC(@myQuery)

CREATE TABLE #myTBL(ItemCode VARCHAR(255),Hits INT,OrderQty INT,BalanceQty INT,RunningQty INT,POQty INT,ForgingQty INT,StockQty INT,SFStockQty INT,MinQty INT,ROLvlQty INT,MaxQty INT,Remarks VARCHAR(50),ToOrderQty INT,AvgQty INT)



INSERT INTO #myTBL(ItemCode,Hits,OrderQty)
	SELECT Items.ItemID,Hits,Qty FROM Items
	INNER JOIN #ItemGroups ON Items.GroupID=#ItemGroups.GroupID

	LEFT OUTER JOIN(SELECT CompItemCode,COUNT(CompItemCode) AS Hits,SUM(Qty) AS Qty FROM FOrderItems
						INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
						WHERE FCustomerOrders.DT BETWEEN @DTFrom AND @DTTo AND FCustomerOrders.CustCode<>'Stock' AND FCustomerOrders.OrderNo IN(SELECT OrderNo FROM VUnshippedOrderList) GROUP BY CompItemCode) T1 ON Items.ItemID=T1.CompItemCode





UPDATE #myTBL SET BalanceQty=TBal.BalanceQty FROM #myTBL INNER JOIN
	(SELECT CompItemCode,SUM(Qty-ShippedQty) AS BalanceQty FROM VFOrderItemswithShippedQty WHERE Qty-ShippedQty>0 AND CustCode<>'Stock'
			GROUP BY CompItemCode) TBal ON #myTBL.ItemCode=TBal.CompItemCode

UPDATE #myTBL SET RunningQty=TRunning.Qty FROM #myTBL INNER JOIN
	(SELECT ItemCode,SUM(Qty) AS Qty FROM VRunningLots_Simple GROUP BY ItemCode) TRunning ON #myTBL.ItemCode=TRunning.ItemCode

UPDATE #myTBL SET POQty=TOpen.Qty FROM #myTBL INNER JOIN
	(SELECT ItemCode,SUM(Qty) AS Qty FROM VItemOpenPOs GROUP BY ItemCode) TOpen ON #myTBL.ItemCode=TOpen.ItemCode

UPDATE #myTBL SET SFStockQty=TStock.Qty FROM #myTBL INNER JOIN
	(SELECT VStockOrderOpening.ItemID,SUM(Qty-IssdQty) AS Qty FROM VStockOrderOpening INNER JOIN (SELECT Opening_RefID FROM VendRcvdDetail GROUP BY Opening_RefID) T1 ON T1.Opening_RefID=VStockOrderOpening.EntryID
		WHERE Qty>IssdQty GROUP BY VStockOrderOpening.ItemID) TStock ON #myTBL.ItemCode=TStock.ItemID

UPDATE #myTBL SET StockQty=TStock.Qty FROM #myTBL INNER JOIN
	(SELECT ItemID,SUM(NetQty) AS Qty FROM VItemsWithShelfWiseStock WHERE NetQty>0 GROUP BY ItemID) TStock ON #myTBL.ItemCode=TStock.ItemID

UPDATE #myTBL SET AvgQty=OrderQty/Hits

UPDATE #myTBL SET MinQty=CASE WHEN Hits>3 THEN AvgQty*2 ELSE AvgQty END
UPDATE #myTBL SET ROLvlQty=MinQty*1.2
UPDATE #myTBL SET MaxQty=CASE WHEN Hits=1 THEN MinQty*1.2 ELSE MinQty*2 END

--UPDATE #myTBL SET ToOrderQty=ISNULL(BalanceQty,0)-ISNULL(RunningQty,0)-ISNULL(POQty,0)-ISNULL(ForgingQty,0)-ISNULL(StockQty,0)+ISNULL(MinQty,0)
UPDATE #myTBL SET ToOrderQty=ISNULL(MinQty,0)+ISNULL(BalanceQty,0)-ISNULL(RunningQty,0)-ISNULL(POQty,0)-ISNULL(ForgingQty,0)-ISNULL(StockQty,0)

SELECT #myTBL.*,Items.ItemName,Items.GroupID,#ItemGroups.GroupName FROM #myTBL
	INNER JOIN Items ON #myTBL.ItemCode=Items.ItemID
	INNER JOIN #ItemGroups ON Items.GroupID=#ItemGroups.GroupID
	WHERE Hits>0

END
GO
