CREATE PROCEDURE [dbo].[PreparePlanningReport_SP] (@OrderNo VARCHAR(255)='0',@R1 AS BIT=1,@ItemCodes AS VARCHAR(8000)='0') AS

SET ANSI_WARNINGS OFF

DECLARE @FactoryMakerID AS INT
SET @FactoryMakerID=CAST(dbo.GetGeneralDataValue_F('FactoryMaker') AS INT)

DECLARE @myItems TABLE(ItemID VARCHAR(50))
IF @ItemCodes<>'0'

	BEGIN
		CREATE TABLE #myTBL (ItemCode VARCHAR(50))
		DECLARE @myQuery AS VARCHAR(1000)
		SET @myQuery='INSERT INTO #myTBL(ItemCode) SELECT DISTINCT CompItemCode FROM VFOrderItems ' + @ItemCodes --SELECT ItemID FROM Items WHERE ItemID IN(' + @ItemCodes  +')'
		EXEC(@myQuery)
		INSERT INTO @myItems(ItemID) SELECT DISTINCT ItemCode FROM #myTBL
	END

ELSE
	INSERT INTO @myItems(ItemID) SELECT DISTINCT CompItemCode FROM FOrderItems WHERE OrderNo=@OrderNo

-----Customer Orders
DELETE FROM CustomerOrders_ForR1 WHERE ForOrderNo=@OrderNo
INSERT INTO CustomerOrders_ForR1(OrderNo,ItemID,Qty,Remarks,DeliveryStatus,ForOrderNo,DT)
	SELECT VUnshippedOrderList.OrderNo,CompItemCode,Qty-ShippedQty,Remarks,DeliveryStatus,@OrderNo,DT FROM VFOrderItemsWithShippedQty INNER JOIN VUnshippedOrderList ON VFOrderItemsWithShippedQty.OrderNo=VUnshippedOrderList.OrderNo
	WHERE Qty>ShippedQty AND CompItemCode IN(SELECT ItemID FROM @myItems)

IF @R1=1
	BEGIN
	-----Running Lots
	DELETE FROM RunningLots_ForR1 WHERE ForOrderNo=@OrderNo

	INSERT INTO RunningLots_ForR1(ItemID,LotNo,Description,OrderNo,Qty,ProcessID,ForOrderNo,Bold,Italic)
		SELECT DISTINCT ItemCode,LotNo,Description,OrderNo,Qty,ProcessID,@OrderNo,CASE WHEN VendID=@FactoryMakerID THEN 1 ELSE 0 END,ReWorkLot FROM VRunningLots_Simple INNER JOIN @myItems myItems ON VRunningLots_Simple.ItemCode=myItems.ItemID WHERE SNo<=PolishingItemSNo


	-----Forging Status
	DELETE FROM ForgingStatus_ForR1 WHERE ForOrderNo=@OrderNo

	INSERT INTO ForgingStatus_ForR1(RMID1,RMName,QtyInStock,QtyToRcv,RMID,ItemID,ForOrderNo)
		SELECT RMID1,RMName,QtyInStock,QtyToRcv,RMID,VItemForgingStatus.ItemID,@OrderNo FROM VItemForgingStatus INNER JOIN @myItems myItems ON VItemForgingStatus.ItemID=myItems.ItemID

	-----Open POs
	DELETE FROM OpenPOs_ForR1 WHERE ForOrderNo=@OrderNo

	INSERT INTO OpenPOs_ForR1(VendID1,OrderNo,Qty,ItemID,ForOrderNo)
		SELECT VendID1,OrderNo,Qty,ItemCode,@OrderNo FROM VItemOpenPOs INNER JOIN @myItems myItems ON VItemOpenPOs.ItemCode=myItems.ItemID

	END


IF @R1=0
	BEGIN
		-----Packed Stock
		DELETE FROM Packed_ForR2 WHERE ForOrderNo=@OrderNo

		INSERT INTO Packed_ForR2(Qty,ItemID,Remarks,ForOrderNo,StoreName)
		SELECT NetQty,VItemsWithShelfWiseStock.ItemID,Remarks,@OrderNo,StoreName FROM VItemsWithShelfWiseStock INNER JOIN @myItems myItems ON VItemsWithShelfWiseStock.ItemID=myItems.ItemID
			WHERE NetQty>0

		-----Running Lots
		DELETE FROM RunningLots_ForR1 WHERE ForOrderNo=@OrderNo

		INSERT INTO RunningLots_ForR1(ItemID,LotNo,Description,OrderNo,Qty,ProcessID,ForOrderNo,Bold,Italic)
			SELECT DISTINCT ItemCode,LotNo,Description,OrderNo,Qty,ProcessID,@OrderNo,CASE WHEN VendID=@FactoryMakerID THEN 1 ELSE 0 END,ReWorkLot FROM VRunningLots_Simple INNER JOIN @myItems myItems ON VRunningLots_Simple.ItemCode=myItems.ItemID WHERE SNo>PolishingItemSNo
	END

----SF Stock
		DELETE FROM SFStock_ForR2 WHERE ForOrderNo=@OrderNo

		INSERT INTO SFStock_ForR2(Qty,ItemID,Remarks,ForOrderNo,StoreName)
		SELECT Qty-IssdQty,VStockOrderOpening.ItemID,Remarks,@OrderNo,StoreName FROM VStockOrderOpening INNER JOIN (SELECT Opening_RefID FROM VendRcvdDetail GROUP BY Opening_RefID) T1 ON  VStockOrderOpening.EntryID=T1.Opening_RefID INNER JOIN @myItems myItems ON VStockOrderOpening.ItemID=myItems.ItemID WHERE Qty>IssdQty
GO
