CREATE PROCEDURE [dbo].[PrintInnerLabels_SP] (@DLDA_RefID AS INT) AS
BEGIN
	DECLARE @TempTB TABLE(AutoEntryID INT IDENTITY (1, 1),EntryID INT,Labels INT,Qty INT,DLDA_RefID INT,ItemID VARCHAR(50),LabelNo INT)
	DECLARE @myCursor CURSOR
	SET @myCursor=CURSOR FORWARD_ONLY FOR SELECT EntryID,Labels,Qty,DLDA_RefID,ItemID FROM DispatchListInnerLabelPrinting WHERE DLDA_RefID=@DLDA_RefID


	DECLARE @EntryID AS INT,@Labels AS INT,@Qty AS INT,@ItemID AS VARCHAR(255)
	OPEN @myCursor
	FETCH NEXT FROM @myCursor INTO @EntryID,@Labels,@Qty,@DLDA_RefID,@ItemID
	DECLARE @iCounter AS INT
	WHILE @@FETCH_STATUS = 0
		BEGIN
			SET @iCounter=1
			WHILE @iCounter<=@Labels
				BEGIN
					INSERT INTO @TempTB(EntryID,Labels,Qty,DLDA_RefID,ItemID,LabelNo) VALUES(@EntryID,@Labels,@Qty,@DLDA_RefID,@ItemID,@iCounter)
					SET @iCounter=@iCounter+1
				END
			FETCH NEXT FROM @myCursor INTO @EntryID,@Labels,@Qty,@DLDA_RefID,@ItemID
		END

END
CLOSE @myCursor
DEALLOCATE @myCursor

SELECT TempTB.*,ItemName FROM @TempTB TempTB INNER JOIN Items ON Items.ItemID=TempTB.ItemID
--SELECT * FROM @TempTB
GO
