CREATE PROCEDURE [dbo].[PrintItemLabels_SP] (@InvoiceNo AS VARCHAR(255)) AS
BEGIN
	DECLARE @TempTB TABLE(AutoEntryID INT IDENTITY (1, 1),ItemNo INT,InvoiceNo VARCHAR(50),ItemID VARCHAR(255))
	DECLARE @myCursor CURSOR
	SET @myCursor=CURSOR FORWARD_ONLY FOR SELECT ItemID,SUM(Qty) AS Qty FROM VrptCustomInvoiceDetail WHERE CustomInvoice=@InvoiceNo GROUP BY ItemID ORDER BY ItemID

	DECLARE @ItemNo AS INT,@ItemID AS VARCHAR(255),@Qty AS INT
	OPEN @myCursor
	FETCH NEXT FROM @myCursor INTO @ItemID,@Qty
	DECLARE @iCounter AS INT
	WHILE @@FETCH_STATUS = 0
		BEGIN
			SET @iCounter=1
			WHILE @iCounter<=@Qty
				BEGIN
					INSERT INTO @TempTB(ItemNo,InvoiceNo,ItemID) VALUES(@iCounter,@InvoiceNo,@ItemID)
					SET @iCounter=@iCounter+1
				END
			FETCH NEXT FROM @myCursor INTO @ItemID,@Qty
		END

END
CLOSE @myCursor
DEALLOCATE @myCursor

SELECT TempTB.*,ItemName FROM @TempTB TempTB INNER JOIN Items ON Items.ItemID=TempTB.ItemID
--SELECT * FROM @TempTB
GO
