CREATE PROCEDURE [dbo].[ProcessWiseProductionReport_SP] (@DTFrom AS DATETIME,@DTTo AS DATETIME,@GroupIDs AS VARCHAR(4000)='0') AS

BEGIN
SET ANSI_WARNINGS OFF

	CREATE TABLE #myTBL (GroupID INT)
	DECLARE @myQuery AS VARCHAR(1000)

	IF @GroupIDs='0'
		SET @myQuery='INSERT INTO #myTBL(GroupID) SELECT ID FROM ItemGroups'
	ELSE
		SET @myQuery='INSERT INTO #myTBL(GroupID) SELECT ID FROM ItemGroups WHERE ID IN(' +@GroupIDs +')'

	EXEC(@myQuery)

SELECT ItemGroups.ID,ItemGroups.Description,DateFull,UltraIssQty,UltraRcvQty,UltraIssLots,UltraRcvLots
	,TuckIssQty,TuckIssLots,TuckRcvQty,TuckRcvLots,TuckRWQty
	,SettingIssQty,SettingIssLots,SettingRcvQty,SettingRcvLots,SettingRWQty,Ultra2IssQty,Ultra2IssLots,Ultra2RcvQty,Ultra2RcvLots,FCIssQty,FCIssLots,FCRcvQty,FCRcvLots,FCRWQty,PackRcvLots,
	UltraBalQty,TuckBalQty,SettingBalQty,Ultra2BalQty,FCBalQty
FROM ItemGroups
INNER JOIN #myTBL myTBL ON ItemGroups.ID=myTBL.GroupID
CROSS JOIN DateLookup


	LEFT OUTER JOIN (SELECT GroupID,DT,SUM(IssQty) AS UltraIssQty,COUNT(LotNo) AS UltraIssLots FROM VVendIssdDetail WHERE DT BETWEEN @DTFrom AND @DTTo AND ProcessID=4 GROUP BY GroupID,DT) TUltraIss ON DateLookup.DateFull=TUltraIss.DT AND ItemGroups.ID=TUltraIss.GroupID
	LEFT OUTER JOIN (SELECT GroupID,DT,SUM(RcvdQty) AS UltraRcvQty,COUNT(LotNo) AS UltraRcvLots FROM VVendRcvdDetail_Simple WHERE DT BETWEEN @DTFrom AND @DTTo AND ProcessID=4 AND ISNULL(Opening_RefID,0)=0 GROUP BY GroupID,DT) TUltraRcv ON DateLookup.DateFull=TUltraRcv.DT AND ItemGroups.ID=TUltraRcv.GroupID

	LEFT OUTER JOIN (SELECT GroupID,DT,SUM(IssQty) AS TuckIssQty,COUNT(LotNo) AS TuckIssLots FROM VVendIssdDetail WHERE DT BETWEEN @DTFrom AND @DTTo AND ProcessID=6 GROUP BY GroupID,DT) TTuckIss ON DateLookup.DateFull=TTuckIss.DT AND ItemGroups.ID=TTuckIss.GroupID
	LEFT OUTER JOIN (SELECT GroupID,DT,SUM(RcvdQty) AS TuckRcvQty,COUNT(LotNo) AS TuckRcvLots,SUM(ReWorkQty) AS TuckRWQty FROM VVendRcvdDetail_Simple WHERE DT BETWEEN @DTFrom AND @DTTo AND ProcessID=6 AND ISNULL(Opening_RefID,0)=0  GROUP BY GroupID,DT) TTuckRcv ON DateLookup.DateFull=TTuckRcv.DT AND ItemGroups.ID=TTuckRcv.GroupID

	LEFT OUTER JOIN (SELECT GroupID,DT,SUM(IssQty) AS SettingIssQty,COUNT(LotNo) AS SettingIssLots FROM VVendIssdDetail WHERE DT BETWEEN @DTFrom AND @DTTo AND ProcessID=17 GROUP BY GroupID,DT) TSettingIss ON DateLookup.DateFull=TSettingIss.DT AND ItemGroups.ID=TSettingIss.GroupID
	LEFT OUTER JOIN (SELECT GroupID,DT,SUM(RcvdQty) AS SettingRcvQty,COUNT(LotNo) AS SettingRcvLots,SUM(ReWorkQty) AS SettingRWQty FROM VVendRcvdDetail_Simple WHERE DT BETWEEN @DTFrom AND @DTTo AND ProcessID=17 AND ISNULL(Opening_RefID,0)=0 GROUP BY GroupID,DT) TSettingRcv ON DateLookup.DateFull=TSettingRcv.DT AND ItemGroups.ID=TSettingRcv.GroupID

	LEFT OUTER JOIN (SELECT GroupID,DT,SUM(IssQty) AS Ultra2IssQty,COUNT(LotNo) AS Ultra2IssLots FROM VVendIssdDetail WHERE DT BETWEEN @DTFrom AND @DTTo AND ProcessID=22 GROUP BY GroupID,DT) TUltra2Iss ON DateLookup.DateFull=TUltra2Iss.DT AND ItemGroups.ID=TUltra2Iss.GroupID
	LEFT OUTER JOIN (SELECT GroupID,DT,SUM(RcvdQty) AS Ultra2RcvQty,COUNT(LotNo) AS Ultra2RcvLots FROM VVendRcvdDetail_Simple WHERE DT BETWEEN @DTFrom AND @DTTo AND ProcessID=22 AND ISNULL(Opening_RefID,0)=0 GROUP BY GroupID,DT) TUltra2Rcv ON DateLookup.DateFull=TUltra2Rcv.DT AND ItemGroups.ID=TUltra2Rcv.GroupID

	LEFT OUTER JOIN (SELECT GroupID,DT,SUM(IssQty) AS FCIssQty,COUNT(LotNo) AS FCIssLots FROM VVendIssdDetail WHERE DT BETWEEN @DTFrom AND @DTTo AND ProcessID=39 GROUP BY GroupID,DT) TFCIss ON DateLookup.DateFull=TFCIss.DT AND ItemGroups.ID=TFCIss.GroupID
	LEFT OUTER JOIN (SELECT GroupID,DT,SUM(RcvdQty) AS FCRcvQty,COUNT(LotNo) AS FCRcvLots,SUM(ReWorkQty) AS FCRWQty FROM VVendRcvdDetail_Simple WHERE DT BETWEEN @DTFrom AND @DTTo AND ProcessID=39 AND ISNULL(Opening_RefID,0)=0 GROUP BY GroupID,DT) TFCRcv ON DateLookup.DateFull=TFCRcv.DT AND ItemGroups.ID=TFCRcv.GroupID

	LEFT OUTER JOIN (SELECT GroupID,DT,SUM(RcvdQty) AS PackRcvQty,COUNT(LotNo) AS PackRcvLots FROM VVendRcvdDetail_Simple WHERE DT BETWEEN @DTFrom AND @DTTo AND ProcessID=28 AND ISNULL(Opening_RefID,0)=0 GROUP BY GroupID,DT) TPackRcv ON DateLookup.DateFull=TPackRcv.DT AND ItemGroups.ID=TPackRcv.GroupID

	LEFT OUTER JOIN (SELECT GroupID,SUM(IssQty-RcvdQty) AS UltraBalQty FROM VVendIssdDetail WHERE DT<@DTFrom AND ProcessID=4 GROUP BY GroupID) TUltraBal ON ItemGroups.ID=TUltraBal.GroupID
	LEFT OUTER JOIN (SELECT GroupID,SUM(IssQty-RcvdQty) AS TuckBalQty FROM VVendIssdDetail WHERE DT<@DTFrom AND ProcessID=6 GROUP BY GroupID) TTcukBal ON ItemGroups.ID=TTcukBal.GroupID
	LEFT OUTER JOIN (SELECT GroupID,SUM(IssQty-RcvdQty) AS SettingBalQty FROM VVendIssdDetail WHERE DT<@DTFrom AND ProcessID=17 GROUP BY GroupID) TSettingBal ON ItemGroups.ID=TSettingBal.GroupID
	LEFT OUTER JOIN (SELECT GroupID,SUM(IssQty-RcvdQty) AS Ultra2BalQty FROM VVendIssdDetail WHERE DT<@DTFrom AND ProcessID=22 GROUP BY GroupID) TUltra2Bal ON ItemGroups.ID=TUltra2Bal.GroupID
	LEFT OUTER JOIN (SELECT GroupID,SUM(IssQty-RcvdQty) AS FCBalQty FROM VVendIssdDetail WHERE DT<@DTFrom AND ProcessID=39 GROUP BY GroupID) TFCBal ON ItemGroups.ID=TFCBal.GroupID

WHERE DateFull BETWEEN @DTFrom AND @DTTo

END
GO
