CREATE PROCEDURE [dbo].[ProductionTimeline_Monthly_SP] (@DTFrom DATETIME,@DTTo DATETIME) AS

--Status; 0=Unshipped;1=Shipped;2=Cancelled;3=Hold;4=All Orders
SET @DTFrom=CAST(CONVERT(VARCHAR(50),@DTFrom,6) AS DATETIME)
SET @DTTo=CAST(CONVERT(VARCHAR(50),@DTTo,6) AS DATETIME)

BEGIN
	/*
	IF @ShipStatus=0
		INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
			AND DT BETWEEN @DTFrom AND @DTTo
			AND (TotalShippedQty<TotalOrderQty AND Cancelled IS NULL)
	ELSE IF @ShipStatus=1
		INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
			AND DT BETWEEN @DTFrom AND @DTTo
			AND (TotalShippedQty=TotalOrderQty OR Cancelled=0)
	ELSE IF @ShipStatus=2
		INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
			AND DT BETWEEN @DTFrom AND @DTTo
			AND (Cancelled=1)
	ELSE IF @ShipStatus=3
		INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
			AND DT BETWEEN @DTFrom AND @DTTo
			AND (Cancelled=2)
	ELSE
		INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
			AND DT BETWEEN @DTFrom AND @DTTo*/

	SELECT DateFull,TotalRcvItems,TotalRcvQty,HubRcvCount,HubRcvQty,HubIssCount,HubIssQty,PolRcvCount,PolRcvQty,
		PolIssCount,PolIssQty,QCRcvCount,QCRcvQty,QCIssCount,QCIssQty,PackRcvCount,PackRcvQty,PackIssCount,PackIssQty FROM DateLookup

	LEFT OUTER JOIN(SELECT CAST(CONVERT(VARCHAR(50),VendReceived.DT,6) AS DATETIME) AS DT,COUNT(DISTINCT VendRcvdDetail.ItemCode) AS TotalRcvItems,SUM(VendIssdDetail.IssQty-VendRcvdDetail.RcvdQty) AS TotalRcvQty FROM VendReceived INNER JOIN VendRcvdDetail ON VendReceived.EntryID=VendRcvdDetail.RefID  INNER JOIN VendIssdDetail ON VendRcvdDetail.Issue_RefID=VendIssdDetail.EntryID
		INNER JOIN VendIssued ON VendReceived.Issuance_RefID=VendIssued.EntryID  WHERE MasterPONo IS NOT NULL GROUP BY CAST(CONVERT(VARCHAR(50),VendReceived.DT,6) AS DATETIME)) TRcv ON DateLookup.DateFull=TRcv.DT
	LEFT OUTER JOIN (SELECT DT,COUNT(DISTINCT ItemCode) AS HubRcvCount,SUM(RcvdQty) AS HubRcvQty FROM VVendRcvdDetail_Simple WHERE ProcessID=174 AND DT BETWEEN @DTFrom AND @DTTo GROUP BY DT) THubRcv ON DateLookup.DateFull=THubRcv.DT
	LEFT OUTER JOIN (SELECT DT,COUNT(DISTINCT ItemCode) AS HubIssCount,SUM(RcvdQty) AS HubIssQty FROM VVendRcvdDetail_Simple WHERE ProcessID=176 AND DT BETWEEN @DTFrom AND @DTTo GROUP BY DT) THubIss ON DateLookup.DateFull=THubIss.DT
	LEFT OUTER JOIN (SELECT DT,COUNT(DISTINCT ItemCode) AS PolRcvCount,SUM(RcvdQty) AS PolRcvQty FROM VVendRcvdDetail_Simple WHERE ProcessID=179 AND DT BETWEEN @DTFrom AND @DTTo  GROUP BY DT) TPolRcv ON DateLookup.DateFull=TPolRcv.DT
	LEFT OUTER JOIN (SELECT DT,COUNT(DISTINCT ItemCode) AS PolIssCount,SUM(RcvdQty) AS PolIssQty FROM VVendRcvdDetail_Simple WHERE ProcessID=176 AND DT BETWEEN @DTFrom AND @DTTo  GROUP BY DT) TPolIss ON DateLookup.DateFull=TPolIss.DT
	LEFT OUTER JOIN (SELECT DT,COUNT(DISTINCT ItemCode) AS QCRcvCount,SUM(RcvdQty) AS QCRcvQty FROM VVendRcvdDetail_Simple WHERE ProcessID=194 AND DT BETWEEN @DTFrom AND @DTTo  GROUP BY DT) TQCRcv ON DateLookup.DateFull=TQCRcv.DT
	LEFT OUTER JOIN (SELECT DT,COUNT(DISTINCT ItemCode) AS QCIssCount,SUM(RcvdQty) AS QCIssQty FROM VVendRcvdDetail_Simple WHERE ProcessID=214 AND DT BETWEEN @DTFrom AND @DTTo  GROUP BY DT) TQCIss ON DateLookup.DateFull=TQCIss.DT
	LEFT OUTER JOIN (SELECT DT,COUNT(DISTINCT ItemCode) AS PackRcvCount,SUM(RcvdQty) AS PackRcvQty FROM VVendRcvdDetail_Simple WHERE ProcessID=203 AND DT BETWEEN @DTFrom AND @DTTo  GROUP BY DT) TPackRcv ON DateLookup.DateFull=TPackRcv.DT
	LEFT OUTER JOIN (SELECT DT,COUNT(DISTINCT ItemCode) AS PackIssCount,SUM(RcvdQty) AS PackIssQty FROM VVendRcvdDetail_Simple WHERE ProcessID=205 AND DT BETWEEN @DTFrom AND @DTTo  GROUP BY DT) TPackIss ON DateLookup.DateFull=TPackIss.DT
	WHERE DateFull BETWEEN @DTFrom AND @DTTo
	ORDER BY DateFull
END
GO
