CREATE PROCEDURE [dbo].[ProductionTimeline_SP] (@CustCode VARCHAR(255)='',@Country VARCHAR(255),@ShipStatus INT=4,@DTFrom DATETIME,@DTTo DATETIME) AS

--Status; 0=Unshipped;1=Shipped;2=Cancelled;3=Hold;4=All Orders

BEGIN
	DECLARE @myTBL TABLE(OrderNo VARCHAR(255),DeliveryDT DATETIME)
	IF @ShipStatus=0
		INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
			AND DT BETWEEN @DTFrom AND @DTTo
			AND (TotalShippedQty<TotalOrderQty AND Cancelled IS NULL)
	ELSE IF @ShipStatus=1
		INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
			AND DT BETWEEN @DTFrom AND @DTTo
			AND (TotalShippedQty=TotalOrderQty OR Cancelled=0)
	ELSE IF @ShipStatus=2
		INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
			AND DT BETWEEN @DTFrom AND @DTTo
			AND (Cancelled=1)
	ELSE IF @ShipStatus=3
		INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
			AND DT BETWEEN @DTFrom AND @DTTo
			AND (Cancelled=2)
	ELSE
		INSERT INTO @myTBL(OrderNo,DeliveryDT) SELECT OrderNo,DeliveryDT FROM VFOrderList WHERE (CustCode=@CustCode OR @CustCode='') AND (Country=@Country OR @Country='')
			AND DT BETWEEN @DTFrom AND @DTTo


	SELECT CustCode,FCustomerOrders.OrderNo,FCustomerOrders.DeliveryDT,InternalRefNo,TotalOrderitems,TotalOrderQty,TotalRcvItems,TotalRcvQty,HubRcvCount,HubRcvQty,HubIssCount,HubIssQty,PolRcvCount,PolRcvQty,
	PolIssCount,PolIssQty,QCRcvCount,QCRcvQty,QCIssCount,QCIssQty,PackRcvCount,PackRcvQty,PackIssCount,PackIssQty,DT FROM FCustomerOrders
	INNER JOIN @myTBL myTBL ON FCustomerOrders.OrderNo=myTBL.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(*) AS TotalOrderItems,SUM(Qty) AS TotalOrderQty FROM FOrderItems GROUP BY OrderNo) TOrd ON FCustomerOrders.OrderNo=TOrd.OrderNo

	LEFT OUTER JOIN(SELECT VendRcvdDetail.OrderNo,COUNT(DISTINCT VendRcvdDetail.ItemCode) AS TotalRcvItems,SUM(VendIssdDetail.IssQty-VendRcvdDetail.RcvdQty) AS TotalRcvQty FROM VendReceived INNER JOIN VendRcvdDetail ON VendReceived.EntryID=VendRcvdDetail.RefID  INNER JOIN VendIssdDetail ON VendRcvdDetail.Issue_RefID=VendIssdDetail.EntryID
		INNER JOIN VendIssued ON VendReceived.Issuance_RefID=VendIssued.EntryID  WHERE MasterPONo IS NOT NULL GROUP BY VendRcvdDetail.OrderNo) TRcv ON FCustomerOrders.OrderNo=TRcv.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS HubRcvCount,SUM(RcvdQty) AS HubRcvQty FROM VVendRcvdDetail_Simple WHERE ProcessID=174 GROUP BY OrderNo) THubRcv ON FCustomerOrders.OrderNo=THubRcv.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS HubIssCount,SUM(RcvdQty) AS HubIssQty FROM VVendRcvdDetail_Simple WHERE ProcessID=176 GROUP BY OrderNo) THubIss ON FCustomerOrders.OrderNo=THubIss.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS PolRcvCount,SUM(RcvdQty) AS PolRcvQty FROM VVendRcvdDetail_Simple WHERE ProcessID=179 GROUP BY OrderNo) TPolRcv ON FCustomerOrders.OrderNo=TPolRcv.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS PolIssCount,SUM(RcvdQty) AS PolIssQty FROM VVendRcvdDetail_Simple WHERE ProcessID=176 GROUP BY OrderNo) TPolIss ON FCustomerOrders.OrderNo=TPolIss.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS QCRcvCount,SUM(RcvdQty) AS QCRcvQty FROM VVendRcvdDetail_Simple WHERE ProcessID=194 GROUP BY OrderNo) TQCRcv ON FCustomerOrders.OrderNo=TQCRcv.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS QCIssCount,SUM(RcvdQty) AS QCIssQty FROM VVendRcvdDetail_Simple WHERE ProcessID=214 GROUP BY OrderNo) TQCIss ON FCustomerOrders.OrderNo=TQCIss.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS PackRcvCount,SUM(RcvdQty) AS PackRcvQty FROM VVendRcvdDetail_Simple WHERE ProcessID=203 GROUP BY OrderNo) TPackRcv ON FCustomerOrders.OrderNo=TPackRcv.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS PackIssCount,SUM(RcvdQty) AS PackIssQty FROM VVendRcvdDetail_Simple WHERE ProcessID=205 GROUP BY OrderNo) TPackIss ON FCustomerOrders.OrderNo=TPackIss.OrderNo
END
GO
