-- =============================================
-- Author:		<solecoder@outlook.com>
-- Create date: <05-MAR-2015>
-- Description:	<>
-- =============================================
CREATE PROCEDURE [dbo].[Purchaserwise_PurchasePlan_SP] (@DTFrom DATETIME,@DTTo DATETIME,@PurchaserID VARCHAR(50)='')

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	CREATE TABLE #RevisionDTs(VIS_RD_RefID INT,RevCount INT,Rev1DT DATETIME,Rev1EntryID INT,Rev2DT DATETIME,Rev2EntryID INT,Rev3DT DATETIME,Rev3EntryID INT)
	INSERT INTO #RevisionDTs(VIS_RD_RefID,RevCount)
		SELECT VIS_RD_RefID,COUNT(*) FROM VendIssdDetail_ReturnDTs_Revisions  GROUP BY VIS_RD_RefID

	UPDATE #RevisionDTs SET Rev1EntryID=MinEntryID FROM #RevisionDTs
		INNER JOIN (SELECT VIS_RD_RefID,MIN(EntryID) AS MinEntryID FROM VendIssdDetail_ReturnDTs_Revisions GROUP BY VIS_RD_RefID) T1 ON #RevisionDTs.VIS_RD_RefID=T1.VIS_RD_RefID

	UPDATE #RevisionDTs SET Rev2EntryID=MinEntryID FROM #RevisionDTs
		INNER JOIN (SELECT VIS_RD_RefID,MIN(EntryID) AS MinEntryID FROM VendIssdDetail_ReturnDTs_Revisions WHERE EntryID NOT IN(SELECT Rev1EntryID FROM #RevisionDTs) GROUP BY VIS_RD_RefID) T1 ON #RevisionDTs.VIS_RD_RefID=T1.VIS_RD_RefID

	UPDATE #RevisionDTs SET Rev2EntryID=MinEntryID FROM #RevisionDTs
		INNER JOIN (SELECT VIS_RD_RefID,MIN(EntryID) AS MinEntryID FROM VendIssdDetail_ReturnDTs_Revisions WHERE EntryID NOT IN(SELECT Rev1EntryID FROM #RevisionDTs) AND EntryID NOT IN(SELECT Rev2EntryID FROM #RevisionDTs) GROUP BY VIS_RD_RefID) T1 ON #RevisionDTs.VIS_RD_RefID=T1.VIS_RD_RefID

	UPDATE #RevisionDTs SET Rev1DT=ReturnDT FROM #RevisionDTs INNER JOIN VendIssdDetail_ReturnDTs_Revisions ON VendIssdDetail_ReturnDTs_Revisions.EntryID=#RevisionDTs.Rev1EntryID
	UPDATE #RevisionDTs SET Rev2DT=ReturnDT FROM #RevisionDTs INNER JOIN VendIssdDetail_ReturnDTs_Revisions ON VendIssdDetail_ReturnDTs_Revisions.EntryID=#RevisionDTs.Rev2EntryID
	UPDATE #RevisionDTs SET Rev3DT=ReturnDT FROM #RevisionDTs INNER JOIN VendIssdDetail_ReturnDTs_Revisions ON VendIssdDetail_ReturnDTs_Revisions.EntryID=#RevisionDTs.Rev3EntryID

	SELECT VendIssdDetail.VID_EmpID,Employees.Name AS Purchaser,VendIssdDetail.ItemCode,Items.ItemName,VendIssdDetail.OrderNo,FCustomerOrders.InternalRefNo,VendIssdDetail.IssQty,VendIssued.MasterPONo,VendIssued.DT,FOrderItems.Qty,Makers.VenderName,Makers.VendID1,VendIssdDetail.ReturnDT,LastRcvDT,TotalRcvdQty,FCustomerOrders.CustCode,TotalRejectQty,TotalReWorkQty
		,CASE RevCount WHEN 1 THEN TDTs.ReturnDT ELSE Rev2DT END AS Revision1DT
		,CASE RevCount WHEN 2 THEN TDTs.ReturnDT ELSE Rev3DT END AS Revision2DT
		,CASE RevCount WHEN 3 THEN TDTs.ReturnDT ELSE NULL END AS Revision3DT
		FROM VendIssued INNER JOIN VendIssdDetail ON VendIssued.EntryID=VendIssdDetail.RefID
		INNER JOIN Makers ON VendIssued.VendID=Makers.VendID
		INNER JOIN Items ON VendIssdDetail.ItemCode=Items.ItemID
		INNER JOIN FCustomerOrders ON VendIssdDetail.OrderNo=FCustomerOrders.OrderNo
		INNER JOIN FOrderItems ON FCustomerOrders.OrderNo=FOrderItems.OrderNo AND Items.ItemID=FOrderItems.CompItemCode
		INNER JOIN Employees ON VendIssdDetail.VID_EmpID=Employees.EmpID
		LEFT JOIN (SELECT VendRcvdDetail.Issue_RefID,MAX(VendReceived.DT) AS LastRcvDT,SUM(VendRcvdDetail.RcvdQty) AS TotalRcvdQty,SUM(VendRcvdDetail.Wastage) AS TotalRejectQty,SUM(VendRcvdDetail.ReWorkQty) AS TotalReWorkQty FROM VendRcvdDetail INNER JOIN VendReceived ON VendReceived.EntryID=VendRcvdDetail.RefID GROUP BY VendRcvdDetail.Issue_RefID) TRcv ON VendIssdDetail.EntryID=TRcv.Issue_RefID
		LEFT JOIN (SELECT VIS_RefID,ReturnDT,RevCount,Rev1DT,Rev2DT,Rev3DT FROM VendIssdDetail_ReturnDTs INNER JOIN #RevisionDTs ON VendIssdDetail_ReturnDTs.EntryID=#RevisionDTs.VIS_RD_RefID) TDTs ON VendIssdDetail.EntryID=TDTs.VIS_RefID
		WHERE ((VendIssdDetail.ReturnDT BETWEEN @DTFrom AND @DTTo)
			OR (CASE RevCount WHEN 1 THEN TDTs.ReturnDT ELSE Rev2DT END BETWEEN @DTFrom AND @DTTo)
			OR (CASE RevCount WHEN 2 THEN TDTs.ReturnDT ELSE Rev3DT END BETWEEN @DTFrom AND @DTTo)
			OR (CASE RevCount WHEN 3 THEN TDTs.ReturnDT ELSE NULL END BETWEEN @DTFrom AND @DTTo))
			AND (VendIssdDetail.VID_EmpID=@PurchaserID OR @PurchaserID='')
			AND VendIssdDetail.IssQty>VendIssdDetail.RcvdQty
			AND VendIssued.Closed=0
	DROP TABLE #RevisionDTs

END

GO
