CREATE PROCEDURE [dbo].[R2OutlookReport_SP] (@CustCode AS VARCHAR(4000)='',@ItemGroup AS VARCHAR(4000)='',@ItemCats AS VARCHAR(4000)='',@Type AS VARCHAR(50)) AS

BEGIN
SET ANSI_WARNINGS OFF
		DECLARE @myQuery AS VARCHAR(4000)
		CREATE TABLE #Customers(CustCode VARCHAR(50))
		CREATE TABLE #ItemGroups(GroupID INT)
		CREATE TABLE #ItemCatagories(CatID VARCHAR(50))
		CREATE TABLE #Processes(ProcessID INT)

		DECLARE @Processes AS VARCHAR(1000)
		IF @CustCode=''
			SET @myQuery='INSERT INTO #Customers(CustCode) SELECT CustCode FROM ForeignCustomers'
		ELSE
			SET @myQuery='INSERT INTO #Customers(CustCode) SELECT CustCode FROM ForeignCustomers WHERE CustCode IN(' + @CustCode +')'
		EXEC(@myQuery)

		IF @ItemGroup=''
			SET @myQuery='INSERT INTO #ItemGroups(GroupID) SELECT ID FROM ItemGroups'
		ELSE
			SET @myQuery='INSERT INTO #ItemGroups(GroupID) SELECT ID FROM ItemGroups WHERE ID IN(' + @ItemGroup + ')'

		EXEC(@myQuery)

		IF @ItemCats=''
			SET @myQuery='INSERT INTO #ItemCatagories(CatID) SELECT CatID FROM ItemCatagories'
		ELSE
			SET @myQuery='INSERT INTO #ItemCatagories(CatID) SELECT CatID FROM ItemCatagories WHERE CatID IN(' + @ItemCats + ')'
		EXEC(@myQuery)

		SET @Processes=''
		IF @Type='QAInspection'
			SET @Processes='66,67,133'
		ELSE IF @Type='Ultra'
			--SET @Processes='34,35,36,37,38,39,106'
			SET @Processes='34,35,36,37,38,39'
		ELSE IF @Type='Setting'
			--SET @Processes='21,22,23,48'
			SET @Processes='21,22,23,113'
		/*ELSE IF @Type='Jurai'
			SET @Processes='113'*/
		ELSE IF @Type='FunctionalChecking'
			SET @Processes='63,73'
		ELSE IF @Type='Polishing'
			--SET @Processes='32,118,122'
			--SET @Processes='27,28,29,30,31,32,48,122,146,118,52,81'
			SET @Processes='28,29,30,31,32,48,122,146,118,52,81'
		ELSE IF @Type='SandBlasting'
			SET @Processes='25,26'
		ELSE IF @Type='Tuck'
			SET @Processes='68,69,110'
		ELSE IF @Type='Passevation'
			SET @Processes='24,134'
		ELSE IF @Type='Etching'
			SET @Processes='85'
		ELSE IF @Type='Cleaning&Packing'
			SET @Processes='87,88'


		IF @Processes=''
			INSERT INTO #Processes SELECT ProcessID FROM Processes
		ELSE
			BEGIN
				SET @myQuery='INSERT INTO #Processes(ProcessID) SELECT ProcessID FROM Processes WHERE ProcessID IN(' + @Processes + ')'
				EXEC(@myQuery)
			END
		SELECT     ItemCode, ProcessID, SUM(Qty) AS Qty FROM (
			/*SELECT dbo.VendIssdDetail.ItemCode,
			dbo.VendIssued.ProcessID, SUM(dbo.VendIssdDetail.IssQty - dbo.VendIssdDetail.RcvdQty) AS Qty
			FROM dbo.VendIssued INNER JOIN dbo.VendIssdDetail ON dbo.VendIssued.EntryID = dbo.VendIssdDetail.RefID
			INNER JOIN Items ON VendIssdDetail.ItemCode=Items.ItemID
			INNER JOIN FCustomerOrders ON VendIssdDetail.OrderNo=FCustomerOrders.OrderNo
			INNER JOIN #Customers ON FCustomerOrders.CustCode=#Customers.CustCode
			INNER JOIN #ItemGroups ON Items.GroupID=#ItemGroups.GroupID
			INNER JOIN #ItemCatagories ON Items.CatID=#ItemCatagories.CatID
			INNER JOIN #Processes ON VendIssued.ProcessID=#Processes.ProcessID

			WHERE     (dbo.VendIssdDetail.IssQty > dbo.VendIssdDetail.RcvdQty)
            GROUP BY dbo.VendIssdDetail.ItemCode, dbo.VendIssued.ProcessID

			UNION ALL*/

            SELECT     ItemCode, VRunningLots_Simple.ProcessID AS ProcessID, SUM(Qty) AS Qty
            FROM         VRunningLots_Simple
            INNER JOIN Items ON VRunningLots_Simple.ItemCode=Items.ItemID
			INNER JOIN FCustomerOrders ON VRunningLots_Simple.OrderNo=FCustomerOrders.OrderNo
			INNER JOIN #Customers ON FCustomerOrders.CustCode=#Customers.CustCode
			INNER JOIN #ItemGroups ON Items.GroupID=#ItemGroups.GroupID
			INNER JOIN #ItemCatagories ON Items.CatID=#ItemCatagories.CatID
			INNER JOIN #Processes ON VRunningLots_Simple.ProcessID=#Processes.ProcessID
            GROUP BY ItemCode, VRunningLots_Simple.ProcessID) AS TInner
		GROUP BY ItemCode, ProcessID

SET ANSI_WARNINGS ON
END




GO
