CREATE PROCEDURE [dbo].[ReIssueItems_Lotwise_SP] (@ProcessID as Int=0,@LotNo AS VARCHAR(50)='',@ReWorkLot AS BIT=0,@ItemID VARCHAR(255)='') AS


	IF @ReWorkLot=1

		/*SELECT TOP 100 PERCENT @ProcessID AS ProcessID,VrptOrders.OrderNo,VrptOrders.ItemID,VrptOrders.Qty As OrderQty,F_Test.VendID,F_Test.IssQty,VrptOrders.CompItemID,VrptOrders.ItemName,TabIssd.TotIssdProc,Makers.VendID1,Makers.VenderName,F_Test.Rcvd_RefID,0 AS InitialProcessID
			FROM VrptOrders_GroupedItems AS VrptOrders LEFT OUTER JOIN
			dbo.F_TestNew(@ProcessID,@ItemID) F_Test ON VrptOrders.CompItemID=F_Test.ItemCode AND VrptOrders.OrderNo=F_Test.OrderNo
			LEFT OUTER JOIN (SELECT Rcvd_RefID,VendID,OrderNo,ItemCode,LotNo,SUM(IssQty) AS TotIssdProc FROM VVendIssddetail WHERE ProcessID=@ProcessID
			GROUP BY Rcvd_RefID,VendID,OrderNo,ItemCode,LotNo) TabIssd ON VrptOrders.OrderNo=TabIssd.OrderNo AND VrptOrders.CompItemID=TabIssd.ItemCode AND F_Test.Rcvd_RefID=TabIssd.Rcvd_RefID
			INNER JOIN Makers ON F_Test.VendID=Makers.VendID
			WHERE F_Test.IssQty>0 AND F_Test.LotNo=@LotNo*/
		SELECT TOP 100 PERCENT @ProcessID AS ProcessID,VrptOrders.OrderNo,VrptOrders.ItemID,VrptOrders.Qty As OrderQty,TabIssd.VendID,F_Test.IssQty,0 AS InitialProcessID
				,VrptOrders.CompItemID,VrptOrders.ItemName,TabIssd.TotIssdProc,Makers.VendID1,Makers.VenderName,TabIssd.Rcvd_RefID
				,VrptOrders.InternalRefNo
			FROM VrptOrders_ForProduction AS VrptOrders
			LEFT OUTER JOIN (SELECT LotNo,OrderNo,ItemCode,VendRcvdDetail.EntryID AS Rcvd_RefID,VendID,RcvdQty AS TotIssdProc,Repair_RefID FROM VendReceived INNER JOIN VendRcvdDetail ON VendReceived.EntryID=VendRcvdDetail.RefID
			WHERE LotNo=@LotNo AND NextProcessID=@ProcessID AND RcvdQty>IssQty) TabIssd ON VrptOrders.OrderNo=TabIssd.OrderNo AND VrptOrders.CompItemID=TabIssd.ItemCode
			LEFT OUTER JOIN dbo.F_IssuanceByLot(@ProcessID,@LotNo) F_Test ON TabIssd.LotNo=F_Test.LotNo
			INNER JOIN Makers ON TabIssd.VendID=Makers.VendID
			INNER JOIN VRepairTypeProcesses ON TabIssd.Repair_RefID=VRepairTypeProcesses.EntryID
			WHERE VRepairTypeProcesses.ProcessID=@ProcessID
	ELSE
		SELECT TOP 100 PERCENT @ProcessID AS ProcessID,VrptOrders.OrderNo,VrptOrders.ItemID,VrptOrders.Qty As OrderQty,TabIssd.VendID,F_Test.IssQty,VItemProcessesExt.InitialProcessID
			,VrptOrders.CompItemID,VrptOrders.ItemName,TabIssd.TotIssdProc,Makers.VendID1,Makers.VenderName,TabIssd.Rcvd_RefID
			,VrptOrders.InternalRefNo
			FROM VrptOrders_ForProduction AS VrptOrders INNER JOIN VItemProcessesExt ON VrptOrders.CompItemID=VItemProcessesExt.IsExist

			LEFT OUTER JOIN (SELECT LotNo,OrderNo,ItemCode,VendRcvdDetail.EntryID AS Rcvd_RefID,VendID,RcvdQty AS TotIssdProc FROM VendReceived INNER JOIN VendRcvdDetail ON VendReceived.EntryID=VendRcvdDetail.RefID
			WHERE LotNo=@LotNo AND NextProcessID=@ProcessID AND RcvdQty>IssQty) TabIssd ON VrptOrders.OrderNo=TabIssd.OrderNo AND VrptOrders.CompItemID=TabIssd.ItemCode
			LEFT OUTER JOIN dbo.F_IssuanceByLot(@ProcessID,@LotNo) F_Test ON TabIssd.LotNo=F_Test.LotNo
			LEFT JOIN Makers ON TabIssd.VendID=Makers.VendID
			WHERE VItemProcessesExt.ProcessID=@ProcessID --AND F_Test.IssQty>0
			AND F_Test.LotNo=@LotNo
GO
