CREATE PROCEDURE [dbo].[ReIssueItems_SP] (@ProcessID as Int=0,@MakerID AS INT=0,@ItemID AS VARCHAR(50)='') AS

IF @MakerID=0	--Selection based on Process Only

	SELECT TOP 100 PERCENT @ProcessID AS ProcessID,VrptOrders.OrderNo,VrptOrders.ItemID,VrptOrders.Qty As OrderQty,F_Test.IssQty,VItemProcessesExt.InitialProcessID,VrptOrders.CompItemID,VrptOrders.ItemName,TabIssd.TotIssdProc ,InternalRefNo
		FROM VrptOrders INNER JOIN VItemProcessesExt ON VrptOrders.CompItemID=VItemProcessesExt.IsExist LEFT OUTER JOIN
		dbo.F_Test(@ProcessID,@ItemID) F_Test ON VrptOrders.CompItemID=F_Test.ItemCode AND VrptOrders.OrderNo=F_Test.OrderNo
		LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(IssQty) AS TotIssdProc FROM VVendIssddetail WHERE ProcessID=@ProcessID
		GROUP BY OrderNo,ItemCode) TabIssd ON VrptOrders.OrderNo=TabIssd.OrderNo AND VrptOrders.CompItemID=TabIssd.ItemCode
		WHERE VItemProcessesExt.ProcessID=@ProcessID AND F_Test.IssQty>0

ELSE IF @ItemID=''
	SELECT TOP 100 PERCENT @ProcessID AS ProcessID,VrptOrders.OrderNo,VrptOrders.ItemID,VrptOrders.Qty As OrderQty,F_Test.IssQty,VItemProcessesExt.InitialProcessID,VrptOrders.CompItemID,VrptOrders.ItemName,TabIssd.TotIssdProc  ,InternalRefNo
		FROM VrptOrders INNER JOIN VItemProcessesExt ON VrptOrders.CompItemID=VItemProcessesExt.IsExist LEFT OUTER JOIN
		dbo.F_Test(@ProcessID,@ItemID) F_Test ON VrptOrders.CompItemID=F_Test.ItemCode AND VrptOrders.OrderNo=F_Test.OrderNo
		LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(IssQty) AS TotIssdProc FROM VVendIssddetail WHERE ProcessID=@ProcessID
		GROUP BY OrderNo,ItemCode) TabIssd ON VrptOrders.OrderNo=TabIssd.OrderNo AND VrptOrders.CompItemID=TabIssd.ItemCode
		WHERE VItemProcessesExt.ProcessID=@ProcessID AND F_Test.IssQty>0 --AND VrptOrders.CompItemID IN(SELECT ItemID FROM VendAssItems WHERE ProcessID=@ProcessID AND VendID=@MakerID)

ELSE
	SELECT TOP 100 PERCENT @ProcessID AS ProcessID,VrptOrders.OrderNo,VrptOrders.ItemID,VrptOrders.Qty As OrderQty,F_Test.IssQty,VItemProcessesExt.InitialProcessID,VrptOrders.CompItemID,VrptOrders.ItemName,TabIssd.TotIssdProc  ,InternalRefNo
		FROM VrptOrders INNER JOIN VItemProcessesExt ON VrptOrders.CompItemID=VItemProcessesExt.IsExist LEFT OUTER JOIN
		dbo.F_Test(@ProcessID,@ItemID) F_Test ON VrptOrders.CompItemID=F_Test.ItemCode AND VrptOrders.OrderNo=F_Test.OrderNo
		LEFT OUTER JOIN (SELECT OrderNo,ItemCode,SUM(IssQty) AS TotIssdProc FROM VVendIssddetail WHERE ProcessID=@ProcessID
		GROUP BY OrderNo,ItemCode) TabIssd ON VrptOrders.OrderNo=TabIssd.OrderNo AND VrptOrders.CompItemID=TabIssd.ItemCode
		WHERE VItemProcessesExt.ProcessID=@ProcessID AND F_Test.IssQty>0 AND VrptOrders.CompItemID IN(SELECT ItemID FROM VendAssItems WHERE ProcessID=@ProcessID AND VendID=@MakerID AND ItemID=@ItemID)
GO
