CREATE PROCEDURE [dbo].[ReIssueItemsNew_SP] (@ProcessID as Int=0,@MakerID AS INT=0,@ItemID AS VARCHAR(50)='',@LotNo AS VARCHAR(50)='',@ReWorkLot AS BIT=0) AS

IF @MakerID=0	--Selection based on Process Only

	IF @ReWorkLot=1

		SELECT TOP 100 PERCENT @ProcessID AS ProcessID,VrptOrders.OrderNo,VrptOrders.ItemID,VrptOrders.Qty As OrderQty,F_Test.VendID,F_Test.IssQty,VrptOrders.CompItemID,VrptOrders.ItemName,TabIssd.TotIssdProc,Makers.VendID1,Makers.VenderName,F_Test.Rcvd_RefID,0 AS InitialProcessID
			FROM VrptOrders_GroupedItems AS VrptOrders LEFT OUTER JOIN
			dbo.F_TestNew(@ProcessID,@ItemID) F_Test ON VrptOrders.CompItemID=F_Test.ItemCode AND VrptOrders.OrderNo=F_Test.OrderNo
			LEFT OUTER JOIN (SELECT Rcvd_RefID,VendID,OrderNo,ItemCode,LotNo,SUM(IssQty) AS TotIssdProc FROM VVendIssddetail WHERE ProcessID=@ProcessID
			GROUP BY Rcvd_RefID,VendID,OrderNo,ItemCode,LotNo) TabIssd ON VrptOrders.OrderNo=TabIssd.OrderNo AND VrptOrders.CompItemID=TabIssd.ItemCode AND F_Test.Rcvd_RefID=TabIssd.Rcvd_RefID
			INNER JOIN Makers ON F_Test.VendID=Makers.VendID
			WHERE F_Test.IssQty>0 AND F_Test.LotNo=@LotNo

	ELSE
		SELECT TOP 100 PERCENT @ProcessID AS ProcessID,VrptOrders.OrderNo,VrptOrders.ItemID,VrptOrders.Qty As OrderQty,F_Test.VendID,F_Test.IssQty,VItemProcessesExt.InitialProcessID,VrptOrders.CompItemID,VrptOrders.ItemName,TabIssd.TotIssdProc,Makers.VendID1,Makers.VenderName,F_Test.Rcvd_RefID
			FROM VrptOrders_GroupedItems AS VrptOrders INNER JOIN VItemProcessesExt ON VrptOrders.CompItemID=VItemProcessesExt.IsExist LEFT OUTER JOIN
			dbo.F_TestNew(@ProcessID,@ItemID) F_Test ON VrptOrders.CompItemID=F_Test.ItemCode AND VrptOrders.OrderNo=F_Test.OrderNo
			LEFT OUTER JOIN (SELECT Rcvd_RefID,VendID,OrderNo,ItemCode,LotNo,SUM(IssQty) AS TotIssdProc FROM VVendIssddetail WHERE ProcessID=@ProcessID
			GROUP BY Rcvd_RefID,VendID,OrderNo,ItemCode,LotNo) TabIssd ON VrptOrders.OrderNo=TabIssd.OrderNo AND VrptOrders.CompItemID=TabIssd.ItemCode AND F_Test.Rcvd_RefID=TabIssd.Rcvd_RefID
			INNER JOIN Makers ON F_Test.VendID=Makers.VendID
			WHERE VItemProcessesExt.ProcessID=@ProcessID AND F_Test.IssQty>0 AND F_Test.LotNo=@LotNo

ELSE IF @ItemID=''
	SELECT TOP 100 PERCENT @ProcessID AS ProcessID,VrptOrders.OrderNo,VrptOrders.ItemID,VrptOrders.Qty As OrderQty,F_Test.VendID,F_Test.IssQty,VItemProcessesExt.InitialProcessID,VrptOrders.CompItemID,VrptOrders.ItemName,TabIssd.TotIssdProc,Makers.VendID1,Makers.VenderName,F_Test.Rcvd_RefID
		FROM VrptOrders_GroupedItems AS VrptOrders INNER JOIN VItemProcessesExt ON VrptOrders.CompItemID=VItemProcessesExt.IsExist LEFT OUTER JOIN
		dbo.F_TestNew(@ProcessID,@ItemID) F_Test ON VrptOrders.CompItemID=F_Test.ItemCode AND VrptOrders.OrderNo=F_Test.OrderNo
		LEFT OUTER JOIN (SELECT Rcvd_RefID,VendID,OrderNo,ItemCode,LotNo,SUM(IssQty) AS TotIssdProc FROM VVendIssddetail WHERE ProcessID=@ProcessID
		GROUP BY Rcvd_RefID,VendID,OrderNo,ItemCode,LotNo) TabIssd ON VrptOrders.OrderNo=TabIssd.OrderNo AND VrptOrders.CompItemID=TabIssd.ItemCode AND F_Test.Rcvd_RefID=TabIssd.Rcvd_RefID
		INNER JOIN Makers ON F_Test.VendID=Makers.VendID
		INNER JOIN (SELECT ItemID FROM VendAssItems WHERE ProcessID=@ProcessID AND VendID=@MakerID) TabVend ON VrptOrders.CompItemID=TabVend.ItemID
		WHERE VItemProcessesExt.ProcessID=@ProcessID AND F_Test.IssQty>0 AND F_Test.LotNo=@LotNo
		--AND VrptOrders.CompItemID IN(SELECT ItemID FROM VendAssItems WHERE ProcessID=@ProcessID AND VendID=@MakerID)

ELSE
	IF @ReWorkLot=1
		SELECT TOP 100 PERCENT @ProcessID AS ProcessID,VrptOrders.OrderNo,VrptOrders.ItemID,VrptOrders.Qty As OrderQty,F_Test.VendID,F_Test.IssQty,0 AS InitialProcessID,VrptOrders.CompItemID,VrptOrders.ItemName,TabIssd.TotIssdProc,Makers.VendID1,Makers.VenderName,F_Test.Rcvd_RefID
			FROM VrptOrders_GroupedItems AS VrptOrders LEFT OUTER JOIN
			dbo.F_TestNew(@ProcessID,@ItemID) F_Test ON VrptOrders.CompItemID=F_Test.ItemCode AND VrptOrders.OrderNo=F_Test.OrderNo
			LEFT OUTER JOIN (SELECT Rcvd_RefID,VendID,OrderNo,ItemCode,LotNo,SUM(IssQty) AS TotIssdProc FROM VVendIssddetail WHERE ProcessID=@ProcessID
			GROUP BY Rcvd_RefID,VendID,OrderNo,ItemCode,LotNo) TabIssd ON VrptOrders.OrderNo=TabIssd.OrderNo AND VrptOrders.CompItemID=TabIssd.ItemCode AND F_Test.Rcvd_RefID=TabIssd.Rcvd_RefID
			INNER JOIN Makers ON F_Test.VendID=Makers.VendID
			INNER JOIN (SELECT VendID,ProcessID FROM MakerProcesses WHERE ProcessID=@ProcessID AND VendID=@MakerID) TabVend ON TabVend.ProcessID=@ProcessID
			WHERE F_Test.IssQty>0 AND F_Test.LotNo=@LotNo --AND Makers.VendID IN(SELECT VendID FROM MakerProcesses WHERE ProcessID=@ProcessID)
	ELSE
		SELECT TOP 100 PERCENT @ProcessID AS ProcessID,VrptOrders.OrderNo,VrptOrders.ItemID,VrptOrders.Qty As OrderQty,F_Test.VendID,F_Test.IssQty,VItemProcessesExt.InitialProcessID,VrptOrders.CompItemID,VrptOrders.ItemName,TabIssd.TotIssdProc,Makers.VendID1,Makers.VenderName,F_Test.Rcvd_RefID
			FROM VrptOrders_GroupedItems AS VrptOrders INNER JOIN VItemProcessesExt ON VrptOrders.CompItemID=VItemProcessesExt.IsExist LEFT OUTER JOIN
			dbo.F_TestNew(@ProcessID,@ItemID) F_Test ON VrptOrders.CompItemID=F_Test.ItemCode AND VrptOrders.OrderNo=F_Test.OrderNo
			LEFT OUTER JOIN (SELECT Rcvd_RefID,VendID,OrderNo,ItemCode,LotNo,SUM(IssQty) AS TotIssdProc FROM VVendIssddetail WHERE ProcessID=@ProcessID
			GROUP BY Rcvd_RefID,VendID,OrderNo,ItemCode,LotNo) TabIssd ON VrptOrders.OrderNo=TabIssd.OrderNo AND VrptOrders.CompItemID=TabIssd.ItemCode AND F_Test.Rcvd_RefID=TabIssd.Rcvd_RefID
			INNER JOIN Makers ON F_Test.VendID=Makers.VendID
			INNER JOIN (SELECT ItemID FROM VendAssItems WHERE ProcessID=@ProcessID AND VendID=@MakerID AND ItemID=@ItemID) TabVend ON VrptOrders.CompItemID=TabVend.ItemID
			WHERE VItemProcessesExt.ProcessID=@ProcessID AND F_Test.IssQty>0 AND F_Test.LotNo=@LotNo
		--AND VrptOrders.CompItemID IN(SELECT ItemID FROM VendAssItems WHERE ProcessID=@ProcessID AND VendID=@MakerID AND ItemID=@ItemID)
GO
/****** Object:  StoredProcedure [dbo].[Running_Lots_Summary_Hubwise]    Script Date: 6/29/2026 4:50:02 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[Running_Lots_Summary_Hubwise](@DTFrom DATETIME,@DTTo DATETIME,@OrderNo VARCHAR(50)='0')

AS
BEGIN

	SET NOCOUNT ON;

    SELECT
	COUNT(DISTINCT (CASE WHEN Hub_Name='H1' THEN ItemCode ELSE NULL END)) AS H1_Items
	,COUNT(DISTINCT (CASE WHEN Hub_Name='H2' THEN ItemCode ELSE NULL END)) AS H2_Items
	,COUNT(DISTINCT (CASE WHEN Hub_Name='H3' THEN ItemCode ELSE NULL END)) AS H3_Items
	,COUNT(DISTINCT (CASE WHEN Hub_Name='H4' THEN ItemCode ELSE NULL END)) AS H4_Items
	,COUNT(DISTINCT (CASE WHEN Hub_Name='H5' THEN ItemCode ELSE NULL END)) AS H5_Items
	,COUNT(DISTINCT (CASE WHEN Hub_Name='H6' THEN ItemCode ELSE NULL END)) AS H6_Items
	,SUM(CASE WHEN Hub_Name='H1' THEN Qty ELSE 0 END) AS H1_Qty
	,SUM(CASE WHEN Hub_Name='H2' THEN Qty ELSE 0 END) AS H2_Qty
	,SUM(CASE WHEN Hub_Name='H3' THEN Qty ELSE 0 END) AS H3_Qty
	,SUM(CASE WHEN Hub_Name='H4' THEN Qty ELSE 0 END) AS H4_Qty
	,SUM(CASE WHEN Hub_Name='H5' THEN Qty ELSE 0 END) AS H5_Qty
	,SUM(CASE WHEN Hub_Name='H6' THEN Qty ELSE 0 END) AS H6_Qty
	FROM VRunningLots
	INNER JOIN ItemProcessGroups ON VRunningLots.ItemCode=ItemProcessGroups.ItemID
	INNER JOIN ProcessGroupsProcesses ON ItemProcessGroups.PG_RefID=ProcessGroupsProcesses.Group_RefID AND VRunningLots.ProcessID=ProcessGroupsProcesses.Process_RefID
	WHERE VRunningLots.DT BETWEEN @DTFrom AND @DTTo
	AND (VRunningLots.OrderNo=@OrderNo OR @OrderNo IN('0',''))
	GROUP BY Hub_Name

END
GO
