CREATE PROCEDURE [dbo].[ScoreBoard_SP] (@OrderNo VARCHAR(255)) AS

BEGIN
	SET ANSI_WARNINGS OFF

	SELECT CustCode,FCustomerOrders.OrderNo,FCustomerOrders.DT,FCustomerOrders.DeliveryDT,InternalRefNo,TotalOrderitems,TotalOrderQty,ISNULL(TotalPurItems,0) AS TotalPurItems,ISNULL(TotalPurQty,0) AS TotalPurQty,LastPurReturnDT,TotalRcvItems,ISNULL(TotalRcvQty,0) AS TotalRcvQty
	,TotalProdItems,TotalProdQty,TotalPacItems,TotalPacQty,
	TotalTRFItems,TotalTRFQty,SOIQty,SOICount,SOAQty,SOACount,ISNULL(SOIQty,0)+ISNULL(SOAQty,0) AS SOQty,ISNULL(SOACount,0)+ISNULL(SOICount,0) AS SOCount,TotalTransferItems,TotalTransferQty,
	DT1,DT2,DT3,DT4,DT5,OriginalDelivery,PTCClosedItems,PTCClosedQty,ShippedQty,ShippedItems,ISNULL(WastageQty,0) AS WastageQty,ISNULL(ReWorkQty,0) AS ReWorkQty,MacItems,MacQty
	,Filing_Count,Filing_Qty,Polishing_Count,Polishing_Qty,EP_Count,EP_Qty,PS_Count,PS_Qty,Hardness_Count,Hardness_Qty
	,TOrd_Group.ItemGroup,TotalProdItems_Group,TotalProdQty_Group,TotalOrderItems_Group,TotalOrderQty_Group
	,TotalPurItems_Group,TotalPurQty_Group
	,TotalRcvItems_Group,TotalRcvQty_Group
	,PTCClosedItems_Group,PTCClosedQty_Group
	FROM FCustomerOrders
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(*) AS TotalOrderItems,SUM(Qty) AS TotalOrderQty FROM FOrderItems WHERE OrderNo=@OrderNo GROUP BY OrderNo) TOrd ON FCustomerOrders.OrderNo=TOrd.OrderNo

	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPurItems,SUM(IssQty-RcvdQty) AS TotalPurQty,MAX(ReturnDT) AS LastPurReturnDT FROM VendIssued INNER JOIN VendIssdDetail ON VendIssued.EntryID=VendIssdDetail.RefID WHERE  OrderNo=@OrderNo AND MasterPONo IS NOT NULL AND IssQty>RcvdQty AND VendID NOT IN(SELECT MakerID FROM FactoryMakers) AND Closed=0 GROUP BY OrderNo) TPur ON FCustomerOrders.OrderNo=TPur.OrderNo

	LEFT OUTER JOIN(SELECT VendRcvdDetail.OrderNo,COUNT(DISTINCT VendRcvdDetail.ItemCode) AS TotalRcvItems,SUM(VendRcvdDetail.RcvdQty) AS TotalRcvQty,SUM(ReWorkQty) AS ReWorkQty FROM VendReceived INNER JOIN VendRcvdDetail ON VendReceived.EntryID=VendRcvdDetail.RefID  INNER JOIN VendIssdDetail ON VendRcvdDetail.Issue_RefID=VendIssdDetail.EntryID INNER JOIN VendIssued ON VendReceived.Issuance_RefID=VendIssued.EntryID  WHERE VendRcvdDetail.OrderNo=@OrderNo AND MasterPONo IS NOT NULL GROUP BY VendRcvdDetail.OrderNo) TRcv ON FCustomerOrders.OrderNo=TRcv.OrderNo


	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalProdItems,SUM(Qty) AS TotalProdQty FROM VRunningLots_Simple_PHF WHERE ProcessID<>206 AND OrderNo=@OrderNo GROUP BY OrderNo) TProd ON FCustomerOrders.OrderNo=TProd.OrderNo

	LEFT OUTER JOIN (SELECT OrderNo,SUM(CASE WHEN EPEntry=1 THEN 1 ELSE 0 END) AS EP_Count,SUM(CASE WHEN EPEntry=1 THEN Qty ELSE 0 END) AS EP_Qty
	,SUM(CASE WHEN PolishingEntry=1 THEN 1 ELSE 0 END) AS Polishing_Count,SUM(CASE WHEN PolishingEntry=1 THEN Qty ELSE 0 END) AS Polishing_Qty
	,SUM(CASE WHEN FilingEntry=1 THEN 1 ELSE 0 END) AS Filing_Count,SUM(CASE WHEN FilingEntry=1 THEN Qty ELSE 0 END) AS Filing_Qty
	,SUM(CASE WHEN PSEntry=1 THEN 1 ELSE 0 END) AS PS_Count,SUM(CASE WHEN PSEntry=1 THEN Qty ELSE 0 END) AS PS_Qty
	,SUM(CASE WHEN HardnessEntry=1 THEN 1 ELSE 0 END) AS Hardness_Count,SUM(CASE WHEN HardnessEntry=1 THEN Qty ELSE 0 END) AS Hardness_Qty
	FROM (SELECT OrderNo,VRunningLots_Simple_PHF.ItemCode,Qty
	,CASE WHEN SNO<=VItemWithEtchingPackingProcessSNo.EPItemSNo AND SNO>VItemWithFinalPolishingProcessSNo.FinalPolishingItemSNo THEN 1 ELSE 0 END AS EPEntry
	,CASE WHEN SNO<=VItemWithFinalPolishingProcessSNo.FinalPolishingItemSNo AND SNO>VItemWithFilingQCProcessSNo.FilingQCItemSNo THEN 1 ELSE 0 END AS PolishingEntry
	,CASE WHEN SNO<=VItemWithFilingQCProcessSNo.FilingQCItemSNo THEN 1 ELSE 0 END AS FilingEntry
	,CASE WHEN SNO=VItemWithPinScrewsProcessSNo.PSItemSNo THEN 1 ELSE 0 END AS PSEntry
	,CASE WHEN SNO=VItemWithHardnessProcessSNo.HardnessItemSNo THEN 1 ELSE 0 END AS HardnessEntry
	FROM VRunningLots_Simple_PHF
	INNER JOIN VItemWithFilingQCProcessSNo ON VRunningLots_Simple_PHF.ItemCode=VItemWithFilingQCProcessSNo.ItemCode
	INNER JOIN VItemWithFinalPolishingProcessSNo ON VRunningLots_Simple_PHF.ItemCode=VItemWithFinalPolishingProcessSNo.ItemCode
	INNER JOIN VItemWithEtchingPackingProcessSNo ON VRunningLots_Simple_PHF.ItemCode=VItemWithEtchingPackingProcessSNo.ItemCode
	INNER JOIN VItemWithPinScrewsProcessSNo ON VRunningLots_Simple_PHF.ItemCode=VItemWithPinScrewsProcessSNo.ItemCode
	INNER JOIN VItemWithHardnessProcessSNo ON VRunningLots_Simple_PHF.ItemCode=VItemWithHardnessProcessSNo.ItemCode
	) TINNER WHERE OrderNo=@OrderNo
	GROUP BY OrderNo) TProcWiseData ON FCustomerOrders.OrderNo=TProcWiseData.OrderNo

	LEFT OUTER JOIN(SELECT OrderNo,COUNT(DISTINCT ItemCode) AS PTCClosedItems,SUM(Qty) AS PTCClosedQty FROM VRunningLots_Simple WHERE OrderNo=@OrderNo AND ProcessID=206 GROUP BY OrderNo) TPTCClosed ON FCustomerOrders.OrderNo=TPTCClosed.OrderNo

	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalPacItems,SUM(Qty)  AS TotalPacQty FROM VDispatchListDetail_Adv WHERE OrderNo=@OrderNo GROUP BY OrderNo) TPac ON FCustomerOrders.OrderNo=TPac.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemCode) AS TotalTRFItems,SUM(Qty) AS TotalTRFQty FROM TransferredToReadyFinishLotsDetail INNER JOIN VendRcvdDetail
		ON VendRcvdDetail.EntryID=TransferredToReadyFinishLotsDetail.VRD_RefID WHERE OrderNo=@OrderNo GROUP BY OrderNo) TRF ON FCustomerOrders.OrderNo=TRF.OrderNo

	LEFT OUTER JOIN(SELECT OrderNo,SUM(StockOrderOpening_Issuance.QtyIssd) AS SOIQty,COUNT(DISTINCT ItemCode) AS SOICount FROM StockOrderOpening_Issuance
				INNER JOIN VendIssdDetail ON StockOrderOpening_Issuance.VID_RefID=VendIssdDetail.EntryID INNER JOIN VendIssued ON VendIssued.EntryID=VendIssdDetail.RefID
				WHERE OrderNo=@OrderNo GROUP BY OrderNo) TSOI ON FCustomerOrders.OrderNo=TSOI.OrderNo

	LEFT OUTER JOIN(SELECT OrderNo,SUM(Qty) AS SOAQty,COUNT(DISTINCT ItemID) AS SOACount FROM StockOrderAdjustments WHERE OrderNo=@OrderNo GROUP BY OrderNo) TSOA ON FCustomerOrders.OrderNo=TSOA.OrderNo
	LEFT OUTER JOIN(SELECT ToOrderNo,COUNT(DISTINCT ToItemCode) AS TotalTransferItems,SUM(Qty) AS TotalTransferQty FROM LotTransferDetails WHERE ToOrderNo=@OrderNo AND Type=0 GROUP BY ToOrderNo) TTR ON FCustomerOrders.OrderNo=TTR.ToOrderNo
	LEFT OUTER JOIN FCustomerOrders_ShippingDates ON FCustomerOrders.OrderNo=FCustomerOrders_ShippingDates.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,COUNT(DISTINCT ItemID) AS MacItems,SUM(IssQty) AS MacQty FROM VendIssdDetail INNER JOIN Vendissued ON VendIssued.EntryID=VendIssdDetail.RefID WHERE OrderNo=@OrderNo AND VendID IN(959,1038) AND ProcessID=169 GROUP BY OrderNo) TMac ON FCustomerOrders.OrderNo=TMac.OrderNo
	LEFT OUTER JOIN (SELECT OrderNo,SUM(CustomInvoiceItems.Qty) AS ShippedQty,COUNT(DISTINCT FOrderItems.ID) AS ShippedItems FROM CustomInvoiceItems INNER JOIN FProformaOrders ON FProformaOrders.EntryID=CustomInvoiceItems.RefID
		 INNER JOIN FOrderItems ON FOrderItems.ID=FProformaOrders.OrderEntryID INNER JOIN CustomInvoice ON CustomInvoice.CustomInvoice=CustomInvoiceItems.CustomInvoice WHERE OrderNo=@OrderNo AND ISNULL(GatePassNo,'')<>'' GROUP BY OrderNo) TShipped ON FCustomerOrders.OrderNo=TShipped.OrderNo
	LEFT OUTER JOIN (SELECT VendIssdDetail.OrderNo,SUM(MakerRepair.Qty) AS WastageQty FROM MakerRepair
			INNER JOIN VendRcvdDetail ON VendRcvdDetail.EntryID=MakerRepair.VRD_RefID_ChargeTo
			INNER JOIN VendIssdDetail ON VendRcvdDetail.Issue_RefID=VendIssdDetail.EntryID
			INNER JOIN VendIssued ON VendIssued.EntryID=VendIssdDetail.RefID



	WHERE VendIssdDetail.OrderNo=@OrderNo AND MasterPONo IS NOT NULL AND VendIssued.VendID NOT IN(SELECT MakerID FROM FactoryMakers) GROUP BY VendIssdDetail.OrderNo) TRej ON TOrd.OrderNo=TRej.OrderNo



	LEFT OUTER JOIN (SELECT OrderNo,ItemGroup,COUNT(*) AS TotalOrderItems_Group,SUM(Qty) AS TotalOrderQty_Group FROM FOrderItems INNER JOIN VItems ON FOrderItems.CompItemCode=VItems.ItemID WHERE OrderNo=@OrderNo GROUP BY ItemGroup,OrderNo) TOrd_Group ON FCustomerOrders.OrderNo=TOrd_Group.OrderNo
	LEFT OUTER JOIN(SELECT OrderNo,ItemGroup,COUNT(DISTINCT ItemCode) AS TotalPurItems_Group,SUM(IssQty-RcvdQty) AS TotalPurQty_Group FROM VendIssued INNER JOIN VendIssdDetail ON VendIssued.EntryID=VendIssdDetail.RefID INNER JOIN VItems ON VendIssdDetail.ItemCode=VItems.ItemID WHERE OrderNo=@OrderNo AND MasterPONo IS NOT NULL AND IssQty>RcvdQty AND VendID NOT IN(SELECT MakerID FROM FactoryMakers) AND Closed=0 GROUP BY ItemGroup,OrderNo) TPur_Group ON FCustomerOrders.OrderNo=TPur_Group.OrderNo AND TOrd_Group.ItemGroup=TPur_Group.ItemGroup
	LEFT OUTER JOIN(SELECT VendRcvdDetail.OrderNo,ItemGroup,COUNT(DISTINCT VendRcvdDetail.ItemCode) AS TotalRcvItems_Group,SUM(VendRcvdDetail.RcvdQty) AS TotalRcvQty_Group,SUM(ReWorkQty) AS ReWorkQty_Forceps FROM VendReceived INNER JOIN VendRcvdDetail ON VendReceived.EntryID=VendRcvdDetail.RefID  INNER JOIN VendIssdDetail ON VendRcvdDetail.Issue_RefID=VendIssdDetail.EntryID INNER JOIN VendIssued ON VendReceived.Issuance_RefID=VendIssued.EntryID INNER JOIN VItems ON VendRcvdDetail.ItemCode=VItems.ItemID WHERE VendRcvdDetail.OrderNo=@OrderNo AND MasterPONo IS NOT NULL GROUP BY ItemGroup,VendRcvdDetail.OrderNo) TRcv_Group ON FCustomerOrders.OrderNo=TRcv_Group.OrderNo AND TOrd_Group.ItemGroup=TRcv_Group.ItemGroup
	LEFT OUTER JOIN(SELECT OrderNo,ItemGroup,COUNT(DISTINCT ItemCode) AS TotalProdItems_Group,SUM(Qty) AS TotalProdQty_Group FROM VRunningLots_Simple_PHF INNER JOIN VItems ON VItems.ItemID=VRunningLots_Simple_PHF.ItemCode WHERE OrderNo=@OrderNo AND ProcessID<>206 GROUP BY OrderNo,ItemGroup) TProd_Group ON FCustomerOrders.OrderNo=TProd_Group.OrderNo AND TOrd_Group.ItemGroup=TProd_Group.ItemGroup
	LEFT OUTER JOIN(SELECT OrderNo,ItemGroup,COUNT(DISTINCT ItemCode) AS PTCClosedItems_Group,SUM(Qty) AS PTCClosedQty_Group FROM VRunningLots_Simple INNER JOIN VItems ON VRunningLots_Simple.ItemCode=VItems.ItemID  WHERE OrderNo=@OrderNo AND ProcessID=206 GROUP BY ItemGroup,OrderNo) TPTCClosed_Group ON FCustomerOrders.OrderNo=TPTCClosed_Group.OrderNo AND TOrd_Group.ItemGroup=TPTCClosed_Group.ItemGroup

	WHERE FCustomerOrders.OrderNo=@OrderNo
END

GO
/****** Object:  StoredProcedure [dbo].[SFLedger]    Script Date: 6/29/2026 4:50:02 PM ******/
SET ANSI_NULLS OFF
GO
