CREATE PROCEDURE [dbo].[SFLedger](@ItemID AS VARCHAR(50))
AS
BEGIN

	DECLARE @OpeningQty AS INT
	--SELECT @OpeningQty=SUM(Qty) FROM StockOrderOpening INNER JOIN VendRcvdDetail ON VendRcvdDetail.Opening_RefID=StockOrderOpening.EntryID
	--	WHERE ItemID=@ItemID GROUP BY ItemID

	SELECT ItemName,Unit,ItemID,TInner.*,@OpeningQty AS Opening,StoreName,RackNo,ShelfNo,FCustomerOrders.InternalRefNo FROM Items LEFT OUTER JOIN
	(SELECT T1.ItemCode,DT,QtyIssd AS QtyOut,0 AS QtyIn,1 AS Type,Processes.Description,Shelf_RefID,OrderNo,VendIssdDetail.LotNo,Lots_List.Batch_No,Lots_List.Mill_Certificate_No FROM VendIssdDetail
		INNER JOIN VendIssued ON VendIssued.EntryID=VendissdDetail.RefID
		LEFT JOIN Lots_List ON VendIssdDetail.LotNo=Lots_List.LotNo
		INNER JOIN (SELECT StockOrderOpening.ItemID AS ItemCode,StockOrderOpening.Shelf_RefID,VID_RefID,SUM(QtyIssd) AS QtyIssd FROM StockOrderOpening_Issuance INNER JOIN StockOrderOpening ON StockOrderOpening.EntryID=StockOrderOpening_Issuance.SOO_RefID WHERE ItemID=@ItemID GROUP BY StockOrderOpening.Shelf_RefID,VID_RefID,ItemID) T1  ON VendIssdDetail.EntryID=T1.VID_RefID INNER JOIN Processes ON VendIssued.ProcessID=Processes.ProcessID WHERE T1.ItemCode=@ItemID

	UNION ALL

	SELECT StockOrderOpening.ItemID AS ItemCode,CAST(CONVERT(Varchar(50),DTEntry,6) AS DATETIME),0 AS QtyOut,StockOrderOpening.Qty AS QtyIn,0 AS Type
		,Processes.Description,Shelf_RefID,LotTransferDetails.FromOrderNo,StockOrderOpening.LotNo_Manual,Lots_List.Batch_No,Lots_List.Mill_Certificate_No
		FROM StockOrderOpening
		INNER JOIN Processes ON StockOrderOpening.ProcessID=Processes.ProcessID
		LEFT JOIN VendRcvdDetail ON VendRcvdDetail.Opening_RefID=StockOrderOpening.EntryID
		LEFT JOIN LotTransferDetails ON VendRcvdDetail.EntryID=LotTransferDetails.VRD_To_RefID
		LEFT JOIN Lots_List ON StockOrderOpening.LotNo_Manual=Lots_List.LotNo
		WHERE StockOrderOpening.ItemID=@ItemID) TInner ON Items.ItemID=TInner.ItemCode

		INNER JOIN VStoreShelfs ON TInner.Shelf_RefID=VStoreShelfs.EntryID
		LEFT JOIN FCustomerOrders ON TInner.OrderNo=FCustomerOrders.OrderNo

		WHERE ItemID=@ItemID
END
GO
