CREATE PROCEDURE [dbo].[SP_AddStock] (@ItemCode Varchar(50),@ProcessID As Int,@RecID As Varchar(50),@Qty as int,@iRefID as int,@VendID as int,@ReqAuth as bit,@AuthorizeEntry as bit=0,@LotNo As Int) AS

Declare @NextProcessID as int

Declare @Bal as float
Declare @ItemRate as real

Declare @EntryID as int
Declare @DT as DateTime

Exec SP_GetNextProcID @ItemCode,@ProcessID,@NextProcID=@NextProcessID OUTPUT

		--Get Rate Of The Rcvd Item...
		If @VendID<>0
			Set @ItemRate=(Select Rate From VendAssItems Where VendID=@VendID and ItemID=@ItemCode)
		Else
			Set @ItemRate=0 --For Now

		--Save To RcvdItems...
		If @AuthorizeEntry =0
			If @ProcessID>=7
				Insert Into VendRcvdDetail(RefID,ItemCode,RecieptID,RcvdQty,Rate,ReqAuth,NextProcessID,LotNo)
				 Values(@iRefID,@ItemCode,@RecID, @Qty,@ItemRate,@ReqAuth,@NextProcessID,@LotNo)
			else
				Insert Into VendRcvdDetail(RefID,ItemCode,RecieptID,RcvdQty,Rate,ReqAuth,NextProcessID)
				 Values(@iRefID,@ItemCode,@RecID, @Qty,@ItemRate,@ReqAuth,@NextProcessID)



	/*If @VendID<>0 and @ReqAuth=0
		Begin

			--If It's Polishing Then Check For Sub Vender's For This Vender
			--If Sub Venders are present Then Insert Into VenderLedger...
			Declare @Rate as float
			Select @Rate=Rate From VendAssItems Where VendID=@VendID and ItemID=@ItemCode

			Insert Into VenderLedger(RefID,VendID,ItemCode,Qty,Rate) Values(@iRefID,@VendID,@ItemCode,@Qty,@Rate)

		End*/
