CREATE PROCEDURE [dbo].[SP_AdjRcvdOrdQty] (@ItemCode Varchar(50)) AS

SELECT     dbo.FOrderItems.OrderNo, dbo.FOrderItems.CompItemCode, dbo.F_PerIncrease(dbo.FOrderItems.Qty) - ISNULL(dbo.VTotRcvdByOrder.TotQty, 0)
                      AS RemQty, dbo.FCustomerOrders.DT, dbo.FCustomerOrders.DeliveryDT
FROM         dbo.FOrderItems INNER JOIN
                      dbo.FCustomerOrders ON dbo.FOrderItems.OrderNo = dbo.FCustomerOrders.OrderNo LEFT OUTER JOIN
                      dbo.VTotRcvdByOrder ON dbo.FOrderItems.OrderNo = dbo.VTotRcvdByOrder.OrderNo AND
                      dbo.FOrderItems.CompItemCode = dbo.VTotRcvdByOrder.ItemCode
Where dbo.FOrderItems.CompItemCode =@ItemCode
Order By dbo.FCustomerOrders.DeliveryDT,dbo.FCustomerOrders.DT
GO
