CREATE PROCEDURE [dbo].[SP_CalcDHR] (@PInvoice As Varchar(50),@OrderNo As Varchar(50),@ManStartDT As DateTime ,@ManFinishDT As DateTime,@ItemID As Varchar(50)=Null)
AS

Declare @DT as DateTime
Declare @DeliveryDT as DateTime
Declare @TotDays As int

Declare @StartDT as Datetime
Declare @EndDT as dateTime

Declare @ItemCode as Varchar(50)
Declare @Qty as int,@ExtraQty as int,@ExtraQty1 as int
Declare @TotProcs as int

Declare @TotSuns as int
Declare @TotHolidays as int

Set @DT=@ManStartDT
Set @DeliveryDT=@ManFinishDT
--Select @TotDays=DateDiff(day,DT,DeliveryDT),@DT=DT,@DeliveryDT=DeliveryDT From FCustomerOrders Where OrderNo=@OrderNo
Set @TotDays=DateDiff(day,@DT,@DeliveryDT)

Set @TotSuns=IsNull((Select dbo.F_TotalSundays(@DT,@DeliveryDT)),0)

Set @TotHolidays=IsNull((Select Count(DT) From Holidays Where DT Between @StartDT and @DeliveryDT),0)

If @TotDays>10
	Set @TotDays=@TotDays-5           --Manufact. start after one day of order and will end before 4 days of delivery date...

--Set @TotDays=@TotDays-(@TotHolidays+@TotSuns)


Set @StartDT=DateAdd(day,1,@DT)
Set @EndDT=DateAdd(day,@TotDays,@StartDT)

--DECLARE CustomHolidays CURSOR
--	FOR
--		Select DT From Holidays Where DT Between @StartDT and @EndDT Order By DT

IF @ItemID Is Null
	DECLARE OrderDetail CURSOR
	FOR
		Select ItemCode,Sum(Qty),dbo.F_PerIncrease(Sum(Qty))-Sum(Qty) From VProformaItems
		Where PInvoice=@PInvoice
		Group By PInvoice,OrderNo,ItemCode
		--Order By ID
ELSE
	DECLARE OrderDetail CURSOR
	FOR
		Select ItemCode,Sum(Qty),dbo.F_PerIncrease(Sum(Qty))-Sum(Qty) From VProformaItems
		Where PInvoice=@PInvoice And OrderNo=@OrderNo And ItemCode=@ItemID
		Group By PInvoice,OrderNo,ItemCode
		--Order By ID


OPEN OrderDetail


FETCH NEXT FROM OrderDetail into @ItemCode,@Qty,@ExtraQty1

Declare @ProcID as int
Declare @WastePer as float
Declare @Wastage as int
Declare @75Rem as int
Declare @25 as int
----------------------------------------------
Declare @AvgDays as int
Declare @PStartDT as DateTime
Declare @PEndDT as DateTime
Declare @DTIncr as int
Declare @ProcNo as int

Declare @ExtraDays as int
Declare @ExtraDaysH as int

Declare @TempDT as DateTime
Declare @DaysAdj as int
Declare @UseQty as int

Declare @ExtTemp as int
Declare @Repeating as int

Declare @LessPer As Float
Declare @WasteF As Float
Declare @Temp As int

DECLARE @iDays as int
DECLARE @iWaste as int
----------------------------
DECLARE @TempTable TABLE (ItemCode Varchar(50),ProcessID int,iDays int,iWaste int)
-----------------------------

DECLARE @ItemProcs CURSOR
--Set @ItemProcs
--FOR
--	Select ProcessID,WastePer From VItemFDAProcesses Where IsExist=@ItemCode Order By SNo

	Set @WasteF=0
WHILE @@FETCH_STATUS = 0



	--Repeat:

	BEGIN
		--/\\/\/\\/\/\/\/\/\/\/\/\/\/\/\\/\/\/\//\\//\
		DECLARE @fProcID as int
		DECLARE @fMinDays as int
		DECLARE @fMaxDays as int
		DECLARE @fMinWaste as int
		DECLARE @fMaxWaste as int

		DECLARE @fiDays as int
		DECLARE @fiWaste as int
		Set @Repeating=0
		Repeat:

		DECLARE Procs CURSOR
		FOR
		Select ProcessID,MinDays,MaxDays,MinWastePer,MaxWastePer From VItemFDAProcesses Where IsExist=@ItemCode Order By SNO
		Open Procs
		Fetch Next From Procs Into @fProcID,@fMinDays,@fMaxDays,@fMinWaste,@fMaxWaste


		Delete From @TempTable
		WHILE @@FETCH_STATUS=0
			Begin
				If @Repeating>=2
					Set @fiDays=@fMinDays
				Else
					Set @fiDays=Floor(Rand()*((@fMaxDays)-(@fMinDays-1))+@fMinDays)


				Set @fiWaste=Floor(Rand()*((@fMaxWaste)-(@fMinWaste-1))+@fMinWaste)

				Insert Into @TempTable Values(@ItemCode,@fProcID,@fiDays,@fiWaste)
				Fetch Next From Procs Into @fProcID,@fMinDays,@fMaxDays,@fMinWaste,@fMaxWaste
			End
		Close Procs
		Deallocate Procs
		--/\\/\/\\/\/\/\/\/\/\/\/\/\/\/\\/\/\/\//\\//\

		--Set @ItemProcs=Cursor For Select ProcessID,MinDays,MaxDays,MinWastePer,MaxWastePer From VItemFDAProcesses Where IsExist=@ItemCode Order By SNo
		Set @ItemProcs=Cursor For Select ProcessID,iDays,iWaste From @TempTable



		Set @ProcNo=0
		Set @ExtraQty=@ExtraQty1-Floor(Rand()*(3-(1-1))+1)   -- 1to3


				Set @TotProcs=(Select Count(ProcessID) From ItemProcessesFDA Where ItemID=@ItemCode)
				--Set @LessPer=100-(Select Sum(WastePer) From VItemFDAProcesses Where IsExist=@ItemCode)
				Set @AvgDays=Floor(@TotDays/@TotProcs)
				Set @ExtraDays=@TotDays % @TotProcs
				If (@ExtraDays-@TotSuns-@TotHolidays)>0
					Set @ExtTemp=CEILING(@TotProcs/(@ExtraDays-@TotSuns-@TotHolidays))
				Else
					Set @ExtTemp=0

				Set @ExtraDaysH=@ExtraDays/2

				Open @ItemProcs
				Fetch Next From @ItemProcs Into @ProcID,@iDays,@iWaste

				Set @75Rem=@ExtraQty*75/100
				Set @25=@ExtraQty-@75Rem


				WHILE @@FETCH_STATUS=0

					BEGIN
						--If @75Rem<=0
							--Break
						Set @ProcNo=@ProcNo+1



						If @ProcNo=1
							Set @PStartDT=@StartDT
						Else
							Set @PStartDT=DateAdd(Day,1,@PEndDT)

						----Now Check For Holiday on this date...

						Set @TempDT=(Select dbo.F_CheckHoliday(@PStartDT,@StartDT,@EndDT))

						Set @DaysAdj=DateDiff(Day,@TempDT,@PStartDT)

						Set @PStartDT=@TempDT

						If @DaysAdj>=@AvgDays
							Begin
								Set @DTIncr=1
							End
						Else
							Set @DTIncr=Floor(Rand()*((@AvgDays)-(0-1))+0)

						If @DTIncr>=1 and @Repeating>=2
							Set @DTIncr=@DTIncr-1

						If @ExtraDays>0 and @Repeating<2
							Begin
								Set @DTIncr=@DTIncr+@ExtTemp
								Set @ExtraDays=@ExtraDays-@ExtTemp
							End

						If @DTIncr>@AvgDays
							Set @ExtraDays=@ExtraDays-(@DTIncr-@AvgDays)

						If @ProcID=16 and @Repeating<2
							Set @DTIncr=@DTIncr+@ExtraDays

						Set @PEndDT=DateAdd(Day,@iDays,@PStartDT)      --Set @PEndDT=DateAdd(Day,@,@PStartDT)

						Set @PEndDT=(Select dbo.F_CheckHoliday(@PEndDT,@StartDT,@EndDT))

						set @Wastage=@iWaste
						-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
						Insert Into DHR (PInvoice,OrderNo,ItemCode,ProcID,WasteQty,DTIn,DTOut,NotApplicable) Values(@PInvoice,@OrderNo,@ItemCode,@ProcID,@Wastage,@PStartDT,@PEndDT,0)

						--Floor(Rand()*(Max-(Min-1))+Min)
						Fetch Next From @ItemProcs Into @ProcID,@iDays,@iWaste
						-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
					END

				CLOSE @ItemProcs

		If @PEndDT>@ManFinishDT
			Begin
				Delete From DHR Where PInvoice=@PInvoice and ItemCode=@ItemCode
				--Print 'PEnd DT=' + Cast(@PEndDT as Varchar)--
--				--Print 'End DT=' + Cast(@EndDT as Varchar)
--				--Print 'Avg=' + Cast(@AvgDays	as Varchar)
--				--Print 'Start DT=' + Cast(@StartDT as Varchar)
				Set @Repeating=@Repeating+1
				GoTo Repeat
			End

		Insert Into DHR (PInvoice,OrderNo,ItemCode,ProcID,NotApplicable)
		Select @PInvoice,@OrderNo,@ItemCode,ProcessID,1 From FDAProcesses Where ProcessID Not In
		(Select ProcessID From ItemProcessesFDA Where ItemID=@ItemCode)

		DEALLOCATE @ItemProcs

		FETCH NEXT FROM OrderDetail into @ItemCode,@Qty,@ExtraQty1
	END
	--Print @EndDT
CLOSE OrderDetail

DEALLOCATE OrderDetail
GO
