CREATE PROCEDURE [dbo].[SP_CreatePList] (@CustomInvoice  as Varchar(50)) AS

DECLARE @PInvoiceID As Int
DECLARE @OrderItemID As Int
DECLARE @PQty As Int
DECLARE @RemQty As Int
DECLARE @CartonFrom As Int
DECLARE @CartonTo As Int
DECLARE @TempQty As Int

DECLARE @PackingMode As Int

DECLARE TempTable CURSOR
FOR SELECT CustomInvoiceItemsEntryID,CustomInvoice,Qty,PackingMode FROM VrptCUstomInvoiceDetail WHERE CustomInvoice=@CustomInvoice Order By Qty Desc
OPEN TempTable

FETCH NEXT FROM TempTable INTO @OrderItemID,@CustomInvoice,@PQty,@PackingMode

Delete From CustomPList Where CustomInvoice=@CustomInvoice
Set @CartonFrom=0
Set @CartonTo=0
DECLARE @CartonQty As Int
WHILE @@FETCH_STATUS = 0

	BEGIN

		SET @TempQty=0
		SET @RemQty=@PQty

		While @RemQty>0
			Begin
				Set @CartonFrom=@CartonTo+1
				If @RemQty>@PackingMode
					BEGIN
						SET @TempQty=@PackingMode
						SET @CartonQty=@PackingMode
						SET @CartonTo=@CartonFrom + (@RemQty/@PackingMode) -1
						SET @TempQty=(@CartonTo-@CartonFrom+1)*@PackingMode
					END
				Else
					BEGIN
						SET @TempQty=@RemQty
						SET @CartonQty=@RemQty
						SET @CartonTo=@CartonFrom
					END



				INSERT INTO CustomPList(CustomInvoice,OrderItemID,CartonFrom,CartonTo,Qty) VALUES(@CustomInvoice,@OrderItemID,@CartonFrom,@CartonTo,@CartonQty)

				SET @RemQty=@RemQty-@TempQty

			End

		FETCH NEXT FROM TempTable INTO @OrderItemID,@CustomInvoice,@PQty,@PackingMode
	END


CLOSE TempTable
DEALLOCATE TempTable
GO
