CREATE PROCEDURE [dbo].[SP_DeptSettings] (@DT As DateTime,@DeptID As Varchar(50)=Null)
As

Declare  @TempTable1   Table (DeptID Varchar(50),TotalEmps Int,TotalAbs Int)
Declare  @TempTable9  Table (DeptID Varchar(50),EmpID Varchar(50),LateComing Int,ShortTimes Int,ExcessTimes Int)
Declare  @TempTable2  Table (DeptID Varchar(50),LateComing Int,ShortTimes Int,ExcessTimes Int)

INSERT INTO @TempTable1 SELECT Departments.DeptID,COUNT(DISTINCT EmpID) AS TotalEmps,
SUM(CASE WHEN InTime IS NULL THEN 1 ELSE 0 END) AS TotalAbsents
FROM F_EmpTimes(@DT) VEmpTimes
RIGHT OUTER JOIN Departments ON Departments.DeptID=VEmpTimes.DeptID
GROUP BY ALL Departments.DeptID

INSERT INTO @TempTable9 SELECT Tab1.DeptID,EmpID,
CASE WHEN DateDiff(n,@DT + ' ' + GeneralSettings.EnterTime,EmpInTime)>0 Then 1 Else 0 End As LateComing,
CASE WHEN EmpWorkingHrs-1<WorkingHrs THEN 1 ELSE 0 END AS ShortTimes,
CASE WHEN EmpWorkingHrs-1>WorkingHrs THEN 1 ELSE 0 END AS ExcessTimes
FROM GeneralSettings INNER JOIN (SELECT DeptID,EmpID,DT,MIN(CAST(DT + ' ' + InTime AS DATETIME)) AS EmpInTime,SUM(Hrs) AS EmpWorkingHrs
FROM VEmpTimes WHERE DT=@DT GROUP BY DeptID,EmpID,DT) Tab1 ON GeneralSettings.DeptID=Tab1.DeptID
ORDER BY Tab1.EmpID

INSERT INTO @TempTable2 SELECT DeptID,SUM(LateComing) As TotalLateComings,SUM(ShortTimes) As TotalShortTimes,SUM(ExcessTimes) AS TotalExcessTimes FROM @TempTable9 GROUP BY DeptID
IF @DeptID IS NULL
	SELECT VMain.DeptID,VMain.Name,VMain.TotalActiveEmps As TotalEmps,VMain.EnterTime,VMain.ExitTime,VMain.WorkingHrs,VMain.Color,Sub1.TotalAbs,Sub2.LateComing,Sub2.ShortTimes,Sub2.ExcessTimes
	FROM VDeptSettings VMain LEFT OUTER JOIN @TempTable1 Sub1 On VMain.DeptID=Sub1.DeptID LEFT OUTER JOIN @TempTable2 Sub2
	ON VMain.DeptID=Sub2.DeptID
	WHERe TotalEmps>0
	ORDER BY VMain.SNo
ELSE
	SELECT VMain.DeptID,VMain.Name,VMain.TotalActiveEmps As TotalEmps,VMain.EnterTime,VMain.ExitTime,VMain.WorkingHrs,VMain.Color,Sub1.TotalAbs,Sub2.LateComing,Sub2.ShortTimes,Sub2.ExcessTimes
	FROM VDeptSettings VMain LEFT OUTER JOIN @TempTable1 Sub1 On VMain.DeptID=Sub1.DeptID LEFT OUTER JOIN @TempTable2 Sub2
	ON VMain.DeptID=Sub2.DeptID
	WHERE VMain.deptID=@DeptID
	AND TotalEmps>0
	ORDER BY VMain.SNo
GO
