CREATE PROCEDURE [dbo].[SP_EmpLeaveBalances] (@DT As DateTime) As

Declare @TempTable1  Table (EmpID Varchar(50),CL Int,SL Int,AL Int,CPL Int,LWP Int,ML Int)
Declare @TempTable2  Table (EmpID Varchar(50),CL Int,SL Int,AL Int,CPL Int,LWP Int,ML Int)
Declare @FinalDT As DateTime
Set @FinalDT=DateAdd(m,1,@DT)

Declare @StartDT As SmallDateTime

/*if Month(@DT)<7
	Set @StartDT='7/1/' + Cast(Year(@DT)-1 As Varchar)
Else
	Set @StartDT='7/1/' + Cast(Year(@DT) As Varchar)*/

SET @StartDT='1/1/' + Cast(Year(@DT) As Varchar)

Begin
	--Insert Into @TempTable1 Select EmpID,Sum(IsNull(CL,0)) As CL,Sum(IsNull(SL,0)) As SL,Sum(Isnull(AL,0)) As AL,Sum(IsNull(CPL,0)) As CPL,Sum(IsNull(LWP,0)) As LWP,Sum(IsNull(ML,0)) As ML From Leaves Where DT<@DT Group By EmpID
	Insert Into @TempTable1 Select EmpID,Sum(IsNull(CL,0)) As CL,Sum(IsNull(SL,0)) As SL,Sum(Isnull(AL,0)) As AL,Sum(IsNull(CPL,0)) As CPL,Sum(IsNull(LWP,0)) As LWP,Sum(IsNull(ML,0)) As ML From Leaves Where DT<@DT AND (DT Between @StartDT AND @DT) Group By EmpID
	Insert Into @TempTable2 Select EmpID,Sum(IsNull(CL,0)) As CL,Sum(IsNull(SL,0)) As SL,Sum(Isnull(AL,0)) As AL,Sum(IsNull(CPL,0)) As CPL,Sum(IsNull(LWP,0)) As LWP,Sum(IsNull(ML,0)) As ML From Leaves Where Month(DT)=Month(@DT) AND Year(DT)=Year(@DT) Group By EmpID

	Delete From PrintEmpLeavesDetail
	Insert Into  PrintEmpLeavesDetail Select t3.EmpID,@DT As DT,t1.CL As BalCL,t2.CL As CL
	,t1.SL As BalSL,t2.SL As SL,t1.AL As BalAL,t2.AL As AL,t1.CPL As BalCPL,t2.CPL As CPL,t1.LWP As BalLWP,t2.LWP As LWP,t1.ML As BalML,t2.ML As ML
	From Employees t3 LEFT OUTER JOIN @TempTable1 t1 ON t1.EmpID=t3.EmpID LEFT OUTER JOIN @TempTable2 t2 ON t2.EmpID=t3.EmpID
	Where t3.JoinDate<@FinalDT AND (t3.DiscontinuedOn Is Null OR t3.DiscontinuedOn>=@DT)
End




GO
