CREATE PROCEDURE [dbo].[SP_GetNextProcID] (@ItemCode as Varchar(50),@ProcID as int,@ReWorkLot AS BIT=0,@RepairType AS INT=0,@NextProcID as int OutPut) As
DECLARE @ReadyFinishProcessID AS INT,@SemiFinishProcessID AS INT
SET @ReadyFinishProcessID=0--CAST(dbo.GetGeneralDataValue_F('ReadyFinishProcessID') AS INT)
SET @SemiFinishProcessID=0--CAST(dbo.GetGeneralDataValue_F('SemiFinishProcessID') AS INT)

DECLARE @SNo AS INT
IF @ReWorkLot=0
	BEGIN
		SET @SNo=(SELECT ItemSNo FROM VItemProcesses WHERE IsExist=@ItemCode AND ProcessID=@ProcID)
		SET @NextProcID=(SELECT TOP 1 ProcessID FROM VItemProcesses WHERE IsExist=@ItemCode AND ItemSNo>@SNo AND ProcessID NOT IN(@ReadyFinishProcessID,@SemiFinishProcessID) ORDER BY ItemSNo)
	END
ELSE
	BEGIN
		SET @SNo=(SELECT SeqNo FROM RepairTypeProcesses WHERE Repair_RefID=@RepairType AND ProcessID=@ProcID)
		SET @NextProcID=(SELECT TOP 1 ProcessID FROM RepairTypeProcesses WHERE Repair_RefID=@RepairType AND SeqNo>@SNo  ORDER BY SeqNo)
	END
GO
