CREATE PROCEDURE [dbo].[SP_GetPackingList] (@Customer as Varchar(100),@CustomPackingList As Bit) as

If @CustomPackingList=1
	SELECT DISTINCT dbo.CustomPList.CustomInvoice,  dbo.VrptCustomInvoice.PackingListL
	FROM         dbo.CustomPList INNER JOIN
			dbo.VrptCustomInvoice ON dbo.CustomPList.CustomInvoice = dbo.VrptCustomInvoice.CustomInvoice
	WHERE (CustCode+Country=@Customer) --AND dbo.VrptCustomInvoice.PackingListH=0
	ORDER BY dbo.CustomPList.CustomInvoice
Else
	SELECT DISTINCT dbo.CustomPList.CustomInvoice, dbo.VrptCustomInvoice.CPackingListL
	FROM         dbo.CustomPList INNER  JOIN
			dbo.VrptCustomInvoice ON dbo.CustomPList.CustomInvoice = dbo.VrptCustomInvoice.CustomInvoice
	WHERE (CustCode+Country=@Customer) --AND dbo.VrptCustomInvoice.CPackingListH=0
	ORDER BY dbo.CustomPList.CustomInvoice
GO
