CREATE PROCEDURE [dbo].[SP_GetPrevProcID] (@ItemCode as Varchar(50),@ProcID as int,@PrevProcID as int OutPut) As
DECLARE @ReadyFinishProcessID AS INT,@SemiFinishProcessID AS INT
SET @ReadyFinishProcessID=CAST(dbo.GetGeneralDataValue_F('ReadyFinishProcessID') AS INT)
SET @SemiFinishProcessID=CAST(dbo.GetGeneralDataValue_F('SemiFinishProcessID') AS INT)

DECLARE @SNo AS INT
SET @SNo=(SELECT ItemSNo FROM VItemProcesses WHERE IsExist=@ItemCode and ProcessID=@ProcID)
SET @PrevProcID=(SELECT TOP 1 ProcessID FROM VItemProcesses WHERE IsExist=@ItemCode AND ItemSNo<@SNo AND ProcessID NOT IN(@ReadyFinishProcessID,@SemiFinishProcessID) ORDER BY ItemSNo DESC)
GO
