CREATE PROCEDURE [dbo].[SP_InsertVendRcvdILP] (@ItemCode as Varchar(50),@ProcessID as int,@Qty as int,@RefID as int,@VendID as int,@LotNo as int,@RecID as Varchar(50),@ReqAuth as bit,@AuthorizeEntry as bit=0,@AddLedger As Bit=1) AS

Declare @TempQty as int
Declare @TempTot as int
Declare @CurrQty as int
Declare @EntryID as int


Declare @ItemRate as float

Set @TempTot=0

Declare @NextProcessID as int

Declare @TempCount As TinyInt

Exec SP_GetNextProcID @ItemCode,@ProcessID,@NextProcID=@NextProcessID OUTPUT

Declare @TotalRate As Float
Declare @RepairVend As Bit
If @VendID<>0
	If @ProcessID=7
		Begin
			Declare @Planter as int,@Snaffer as int,@Stamper as int
				Select @RepairVend=RepairVend From Venders Where VendID=@VendID
				Select @Planter=Planter,@Snaffer=Snaffer,@Stamper=Stamper From Venders Where VendID=@VendID
				Declare @PlantRate as float,@SnaffRate as float,@StampRate as float,@Rate as float
				Select @PlantRate=PlantRate,@SnaffRate=SnaffRate,@StampRate=StampRate,@Rate=Rate From VendAssItems Where VendID=@VendID and ItemID=@ItemCode
				Set @TotalRate=@Rate

				If IsNull(@RepairVend,0)=0
				Begin
					If IsNull(@Planter,0)=0
						Set @TotalRate=@TotalRate+@PlantRate
					If IsNull(@Snaffer,0)=0
						Set @TotalRate=@TotalRate+@SnaffRate
				End
		End
	Else
		Set @TotalRate=(Select Rate From VendAssItems Where VendID=@VendID and ItemID=@ItemCode)
Else
	Set @TotalRate=0 --For Now

	If @AuthorizeEntry =0
		Insert Into VendRcvdDetail(RefID,RecieptID,ItemCode,NextProcessID,RcvdQty,Wastage,Rate,LotNo,ReqAuth)
		 Values(@RefID,@RecID,@ItemCode,@NextProcessID, @Qty,0,@TotalRate,@LotNo,@ReqAuth)

	/*If @OrderNo='Repair'
		Begin
			--Insert Into FOrderItems
			Set @TempCount=(Select Count(*) From FOrderItems Where OrderNo=@OrderNo And ItemCode=@ItemCode)
			If @TempCount=0
				Insert Into ForderItems(OrderNo,ItemCode,CompItemCode,Price,Qty) Values(@OrderNo,@ItemCode,@ItemCode,0,0)
		End*/
	If @ReqAuth=0
		Exec SP_UpdateIssued @ItemCode,@ProcessID,@VendID,@Qty
	--Update VendIssdDetail Set RcvdQty=IssQty Where LotNo=@LotNo and ProcessID=@ProcessID

If @VendID<>0 and @ReqAuth=0 And @AddLedger=1
	Begin

		--If It's Polishing Then Check For Sub Vender's For This Vender
		--If Sub Venders are present Then Insert Into VenderLedger...
		If @ProcessID=7
			Begin

				Insert Into VenderLedger(RefID,VendID,ItemCode,Qty,Rate) Values(@RefID,@VendID,@ItemCode,@Qty,@TotalRate)

				If IsNull(@Planter,0)<>0 and IsNull(@PlantRate,0)<>0
					Insert Into VenderLedger(RefID,VendID,ItemCode,Qty,Rate) Values(@RefID,@Planter,@ItemCode,@Qty,@PlantRate)
				If IsNull(@Snaffer,0)<>0 and IsNull(@SnaffRate,0)<>0
					Insert Into VenderLedger(RefID,VendID,ItemCode,Qty,Rate) Values(@RefID,@Snaffer,@ItemCode,@Qty,@SnaffRate)
				If IsNull(@Stamper,0)<>0 and IsNull(@StampRate,0)<>0
					Insert Into VenderLedger(RefID,VendID,ItemCode,Qty,Rate) Values(@RefID,@Stamper,@ItemCode,@Qty,@StampRate)
			End


		--Save To VenderLedger
		--Insert Into VenderLedger(VendID,DT,Amt,RefID,Balance) Values(@VendID,@DT,-@ItemRate*@TempQty,@EntryID,@Bal-(@ItemRate*@TempQty))
	End
GO
