CREATE PROCEDURE [dbo].[SP_InsertVendRcvdLost] (@ItemCode Varchar(50),@ProcessID as int,@Qty as int,@WasteQty as int,@iRefID as int,@VendID as int,@LotNo as int,@RecID as Varchar(50),@RcvDT as DateTime,@Rate As float,@ReqAuth as bit,@UserID As Int,@AuthorizeEntry as bit=0) AS

Declare @NextProcessID as int

Declare @Bal as float
Declare @ItemRate as real

Declare @EntryID as int
Declare @DT as DateTime

Exec SP_GetNextProcID @ItemCode,@ProcessID,@NextProcID=@NextProcessID OUTPUT

Declare @lQty As int, @TotQty As int
Set @lQty=0
Declare @TempQty As int, @TempWasteQty As int
Declare @TempTot as int

--To Fetch Records...
Declare @FQty as int
Declare @FOrderNo as varchar(50)
Declare @FItemCode as Varchar(50)

Declare @TotalQty as int
Set @TempTot=0
Set @TempQty=0
Set @TotQty=@Qty+@WasteQty

--Declare Cursor

DECLARE TempTable CURSOR
FOR Select ItemCode,TotQty From VTotIssdByOrder Where ItemCode=@ItemCode and ProcessID=@ProcessID and VendID=@VendID
OPEN TempTable
FETCH NEXT FROM TempTable into @FItemCode,@FQty

--WHILE @@FETCH_STATUS = 0

Print cast(@FQty as Varchar) +  ' ,  ' + Cast(@TotQty as nvarchar)
--Paste Here
While  @lQty < @TotQty
	BEGIN
		Set @TempQty = @TotQty - @lQty
		Set @TempWasteQty = 0
		If @TempQty > @FQty
			Set @TempQty = @FQty
		If @WasteQty > 0
			Begin
					If @TempQty > @WasteQty
					Begin
						Set @TempQty = @TempQty - @WasteQty
						Set @TempWasteQty = @WasteQty
						Set @WasteQty = 0
					End
				Else
					Begin
						Set @TempWasteQty = @WasteQty
						Set @TempQty = 0
						Set @WasteQty = @WasteQty - @TempQty
					End
			End
				--Print 'Order No=' + @ForderNo
		--Get Rate Of The Rcvd Item...
		/*If @VendID<>0
			Set @ItemRate=(Select Rate From VendAssItems Where VendID=@VendID and ItemID=@FItemCode)
		Else
			Set @ItemRate=0 --For Now*/

		--Save To RcvdItems...
		If @LotNo=0
			Set @LotNo=null
		If @AuthorizeEntry =0
			Insert Into VendRcvdDetail(RefID,RecieptID,ItemCode,NextProcessID,RcvdQty,LostQty,Rate,LotNo,ReqAuth)
			Values(@iRefID,@RecID,@FItemCode,@NextProcessID, @TempQty,@TempWasteQty,@Rate,@LotNo,@ReqAuth)

		--Get The EntryID
		--(Select @EntryID=EntryID,@DT=DT From VVendRcvdItems  Where EntryID=(Select Max(EntryID) From VendRcvdDetail))


		Set @TotalQty=@TempQty+@TempWasteQty
		--Print Cast(@TotalQty as nvarchar)
		If @ReqAuth=0
			Exec SP_UpdateIssued  @FItemCode,@ProcessID,@VendID,@TotalQty
			Print @TotalQty
		Set @lQty = @lQty + @TempQty + @TempWasteQty

		FETCH NEXT FROM TempTable into @FItemCode,@FQty

	END

	If @VendID<>0 and @ReqAuth=0
		Begin

			--If It's Polishing Then Check For Sub Vender's For This Vender
			--If Sub Venders are present Then Insert Into VenderLedger...
			/*Declare @Rate as float
			Select @Rate=Rate From VendAssItems Where VendID=@VendID and ItemID=@ItemCode*/

			Insert Into VenderLedger(RefID,VendID,ItemCode,Qty,Rate) Values(@iRefID,@VendID,@ItemCode,@WasteQty,-@Rate)

		End


	CLOSE TempTable
	DEALLOCATE TempTable
GO
