CREATE PROCEDURE [dbo].[SP_InsertVendRcvdLots] (@ProcessID as int,@Qty as int,@RefID as int,@VendID as int,@LotNo as int,@RecID as Varchar(50),@ReqAuth as bit,@AuthorizeEntry as bit=0) AS

Declare @TempQty as int
Declare @TempTot as int
Declare @CurrQty as int
Declare @EntryID as int
Declare @UEntryID as Int
Declare @ItemCode as Varchar(50)
Declare @ItemRate as float

Declare @TRefID As Int
Set @TempTot=0

Declare @NextProcessID as int

DECLARE TempTable1 CURSOR

FOR
	Select EntryID,ItemCode,(IssQty-RcvdQty) As IssQty From VendIssdDetail
	 Where  LotNo=@LotNo And (IssQty-RcvdQty)>0 Order By EntryID

OPEN TempTable1
FETCH NEXT FROM TempTable1 into @UEntryID,@ItemCode,@CurrQty

Exec SP_GetNextProcID @ItemCode,@ProcessID,@NextProcID=@NextProcessID OUTPUT


If @VendID<>0
	Set @ItemRate=(Select Rate From VendAssItems Where VendID=@VendID and ItemID=@ItemCode)
Else
	Set @ItemRate=0 --For Now

WHILE @@FETCH_STATUS = 0
	BEGIN
		If (@CurrQty>@Qty-@TempTot)   --For Remaining
			Begin
				Set @TempQty=@Qty-@TempTot
			End
		Else
			Begin
				Set @TempQty=@CurrQty
			End

		--Update VendRcvdDetail Set IssQty=IssQty+@TempQty Where EntryID=@EntryID


		If @AuthorizeEntry =0
			Begin
				Insert Into VendRcvdDetail(RefID,RecieptID,ItemCode,NextProcessID,RcvdQty,Wastage,Rate,LotNo,ReqAuth)
				Values(@RefID,@RecID,@ItemCode,@NextProcessID, @TempQty,0,@ItemRate,@LotNo,@ReqAuth)
				Set @TRefID=(Select Max(EntryID) From VendRcvdDetail)
			End

		Set @TempTot=@TempTot+@TempQty
		FETCH NEXT FROM TempTable1 into @UEntryID,@ItemCode,@CurrQty

	END

	If @ReqAuth=0
		Update VendIssdDetail Set RcvdQty=IssQty Where EntryID=@UEntryID

	If @VendID<> 0 and @ReqAuth=0
		Begin

			--If It's Polishing Then Check For Sub Vender's For This Vender
			--If Sub Venders are present Then Insert Into VenderLedger...
			Declare @Rate as float
			Select @Rate=Rate From VendAssItems Where VendID=@VendID and ItemID=@ItemCode

			Insert Into VenderLedger(RefID,VendID,ItemCode,Qty,Rate,RefID1) Values(@RefID,@VendID,@ItemCode,@Qty,@Rate,@TRefID)

		End

	CLOSE TempTable1
	DEALLOCATE TempTable1
GO
