CREATE PROCEDURE [dbo].[SP_InsertVendRcvdLotsP] (@ProcessID as int,@Qty as int,@Wastage as int,@Repair as int,@RefID as int,@VendID as int,@LotNo as int,@RecID as Varchar(50),@ReqAuth as bit,@AuthorizeEntry as bit=0) AS

Declare @TempQty as int
Declare @TempTot as int
Declare @CurrQty as int
Declare @EntryID as int
Declare @OrderNo as Varchar(50)
Declare @ItemCode as Varchar(50)
Declare @ItemRate as float
------------------------------------------------
Declare @InQty As Int
Declare @NewRefID As Int
Declare @TRefID As Int
Declare @FreeQty As Int
Declare @InOrderItems As Int
------------------------------------------------

Set @TempTot=0

Select @NewRefID=EntryID,@ItemCode=ItemCode from VendIssdDetail Where  LotNo=@LotNo And (IssQty-RcvdQty)>0 Order By EntryID

Declare @NextProcessID As Int


Exec SP_GetNextProcID @ItemCode,@ProcessID,@NextProcID=@NextProcessID OUTPUT

If @VendID<>0
	Set @ItemRate=(Select Rate From VendAssItems Where VendID=@VendID and ItemID=@ItemCode)
Else
	Set @ItemRate=0 --For Now

		--Update VendRcvdDetail Set IssQty=IssQty+@TempQty Where EntryID=@EntryID


	If @AuthorizeEntry =0
		/*If Left(@OrderNo,10)='HICO Order' Or @OrderNo='Repair'
			Begin
				Insert Into VendRcvdDetail(RefID,RecieptID,OrderNo,ItemCode,NextProcessID,ProcessID,RcvdQty,Wastage,Rate,LotNo,ReqAuth,RcvRepairQty,IssRepairQty)
				Values(@RefID,@RecID,@OrderNo,@ItemCode,@NextProcessID,@ProcessID, @Qty,@Wastage,@ItemRate,@LotNo,@ReqAuth,@Repair,0)
				GoTo ComeThere
			End*/
		--First Check Whether there is an Entry for this Order And Item Against This ProcessID....
		--If It is Then Just Update The Quantities And If It's Not Then Insert Row...

		Begin
			--Set @OrderQty=(Select Qty From FOrderItems Where OrderNo=@OrderNo And ItemCode=@ItemCode)

				Begin
					Insert Into VendRcvdDetail(RefID,RecieptID,ItemCode,NextProcessID,RcvdQty,Wastage,Rate,LotNo,ReqAuth,RcvRepairQty,IssRepairQty)
					Values(@RefID,@RecID,@ItemCode,@NextProcessID, @Qty,@Wastage,@ItemRate,@LotNo,@ReqAuth,@Repair,0)
					Set @TRefID=(Select Max(EntryID) From VendRcvdDetail)
				End

		End
ComeThere:
	If @ReqAuth=0
		Update VendIssdDetail Set RcvdQty=IssQty Where EntryID=@NewRefID

	If @VendID<>0 and @ReqAuth=0
		Begin

			--If It's Polishing Then Check For Sub Vender's For This Vender
			--If Sub Venders are present Then Insert Into VenderLedger...
			Declare @Rate as float

			Select @Rate=Rate From VendAssItems Where VendID=@VendID and ItemID=@ItemCode

			Insert Into VenderLedger(RefID,VendID,ItemCode,Qty,Rate,RcvingRepair) Values(@RefID,@VendID,@ItemCode,@Qty,@Rate,0)

			--Repair Deductions From The Vender from whom we received this Lot @ Polishing
			Declare @DedVendID As Int
			Declare @OwnRepair As Bit
			Declare @DedRepair As Float

			Select @OwnRepair=OwnRepair,@DedRepair=RepairDedRate  From Venders Where VendID=@VendID

			If @OwnRepair=0
				Begin
					Select @DedVendID=VendID From VVendRcvdDetail Where ProcessID=7 AND RecieptID=@RecID
					Select @DedRepair=RepairRate From GeneralSettings1		--Repair Rate
					Insert Into VenderLedger(RefID,VendID,ItemCode,Qty,Rate,RcvingRepair,RefID1) Values(@RefID,@DedVendID,@ItemCode,@Repair,@DedRepair,1,@TRefID)
					--Insert Into VenderLedger(RefID,VendID,ItemCode,Qty,Rate,RcvingRepair) Values(@RefID,@VendID,@ItemCode,@Repair,@DedRepair,1)
				End

		End
GO
