CREATE PROCEDURE [dbo].[SP_InsertVendRcvdNew] (@ItemCode Varchar(50),@ProcessID as int,@Qty as int,@WasteQty AS INT,@RepairQty AS INT=0,@LostQty AS INT=0,@iRefID as int,@VendID as int,@LotNo AS VARCHAR(50),@RecID as Varchar(50),@RcvDT as DateTime,@ReqAuth as bit,@UserID As Int,@AuthorizeEntry as bit=0,@OrderNo AS Varchar(50),@DeliveryRefID AS INT,@CountedBy AS VARCHAR(50),@Issue_RefID AS INT,@Weight AS FLOAT,@ReWorkQty AS INT=0,@ReWorkLot AS BIT=0,@RepairType AS INT=0,@VRD_EntryID AS INT=0) AS

DECLARE @NetQty AS INT
SET @NetQty=@Qty-@WasteQty-@RepairQty-@LostQty-@ReWorkQty

DECLARE @NextProcessID AS INT

DECLARE @Bal AS FLOAT
DECLARE @ItemRate AS REAL

DECLARE @EntryID AS INT
DECLARE @DT AS DATETIME

EXEC SP_GetNextProcID @ItemCode,@ProcessID,@ReWorkLot,@RepairType,@NextProcID=@NextProcessID OUTPUT

DECLARE @lQty AS INT, @TotQty AS INT
SET @lQty=0
DECLARE @TempQty AS INT, @TempWasteQty AS INT
DECLARE @TempTot AS INT
--To Fetch Records...
Declare @FQty as int
Declare @FOrderNo as varchar(50)
Declare @FItemCode as Varchar(50)

Declare @TotalQty as int
Set @TempTot=0
Set @TempQty=0

Set @TotQty=@Qty--@Qty-@WasteQty-@LostQty-@ReWorkQty


/*DECLARE TempTable CURSOR
FOR SELECT ItemCode,TotQty From VTotIssuedByEntryID Where ItemCode=@ItemCode and ProcessID=@ProcessID AND VendID=@VendID AND OrderNo=@OrderNo AND EntryID=@DeliveryRefID
OPEN TempTable
FETCH NEXT FROM TempTable INTO @FItemCode,@FQty


While  @lQty < @TotQty
	BEGIN
		Set @TempQty = @TotQty - @lQty
		Set @TempWasteQty = 0
		If @TempQty > @FQty
			Set @TempQty = @FQty

		If @VendID<>0
			SET @ItemRate=(SELECT Rate FROM VendIssdDetail WHERE EntryID=@Issue_RefID)
		Else
			Set @ItemRate=0 --For Now

		--Save To RcvdItems...
		If @LotNo=0
			Set @LotNo=null

		Set @TotalQty=@TempQty
		IF @ReqAuth=0
			EXEC SP_UpdateIssuedNew  @FItemCode,@ProcessID,@VendID,@TotalQty,@OrderNo,@DeliveryRefID

		SET @lQty = @lQty + @TempQty + @TempWasteQty

		FETCH NEXT FROM TempTable into @FItemCode,@FQty

	END*/
	If @VendID<>0
		SET @ItemRate=(SELECT Rate FROM VendIssdDetail WHERE EntryID=@Issue_RefID)
	Else
		Set @ItemRate=0 --For Now

	IF @AuthorizeEntry =0
		BEGIN
			INSERT INTO  VendRcvdDetail(RefID,RecieptID,ItemCode,NextProcessID,RcvdQty,Wastage,Rate,LotNo,ReqAuth,OrderNo,CountedBy,Issue_RefID,ProcessID,RcvdWeight,ReWorkLot,Repair_RefID)
			VALUES(@iRefID,@RecID,@ItemCode,@NextProcessID, @Qty,@WasteQty,@ItemRate,@LotNo,@ReqAuth,@OrderNo,@CountedBy,@Issue_RefID,@ProcessID,@Weight,@ReWorkLot,@RepairType)

			SET @VRD_EntryID=(SELECT MAX(EntryID) FROM VendRcvdDetail)
		END
	IF @ReqAuth=0
			EXEC SP_UpdateIssuedNew @ItemCode,@ProcessID,@VendID,@TotQty,@OrderNo,@DeliveryRefID,@VRD_EntryID

	IF @VendID<>0 and @ReqAuth=0
		BEGIN

			--If It's Polishing Then Check For Sub Vender's For This Vender
			--If Sub Venders are present Then Insert Into VenderLedger...
			DECLARE @Rate AS FLOAT
			SELECT @Rate=Rate FROM VendAssItems WHERE VendID=@VendID and ItemID=@ItemCode AND ProcessID=@ProcessID
			INSERT INTO VenderLedger(RefID,VendID,ItemCode,Qty,Rate) VALUES(@iRefID,@VendID,@ItemCode,@NetQty,@Rate)

		END


	--CLOSE TempTable
	--DEALLOCATE TempTable
GO
