CREATE PROCEDURE [dbo].[SP_IssueItems1] (@OrderNo as varchar(50) =null,@ProcessID as Int=null,@VendID as int=null,@CustCode as varchar(50)=null,@ItemCode as Varchar(50)) AS

if @VendID is null
	SELECT     TOP 100 PERCENT F_ProcQtyToIssue.OrderNo,F_ProcQtyToIssue.ItemCode, F_ProcQtyToIssue.ProcessID, F_ProcQtyToIssue.IssQty,
                      dbo.VFOrderItemsProcs.Description, dbo.VFOrderItemsProcs.SNO,
                      dbo.VFOrderItemsProcs.ItemDescription, dbo.VFOrderItemsProcs.CompItemCode, dbo.VFOrderItemQty.Qty, dbo.VFOrderItemQty.FreeStock,dbo.VFOrderItemQty.CustCode
	FROM         dbo.VFOrderItemQty INNER JOIN
                      dbo.F_ProcQtyToIssue(@OrderNo) F_ProcQtyToIssue ON dbo.VFOrderItemQty.OrderNo = F_ProcQtyToIssue.OrderNo AND
                      dbo.VFOrderItemQty.CompItemCode = F_ProcQtyToIssue.ItemCode LEFT OUTER JOIN
                      dbo.VFOrderItemsProcs ON F_ProcQtyToIssue.ItemCode = dbo.VFOrderItemsProcs.CompItemCode AND
                      F_ProcQtyToIssue.OrderNo = dbo.VFOrderItemsProcs.OrderNo AND F_ProcQtyToIssue.ProcessID = dbo.VFOrderItemsProcs.ProcessID

	WHERE     dbo.VFOrderItemQty.CompItemCode=@ItemCode and (F_ProcQtyToIssue.IssQty > 0) AND (F_ProcQtyToIssue.ProcessID = @ProcessID Or @ProcessID is null)
		AND (dbo.VFOrderItemQty.CustCode = @CustCode Or @CustCode is null)
	ORDER BY F_ProcQtyToIssue.ProcessID, F_ProcQtyToIssue.ItemCode
Else
	SELECT     TOP 100 PERCENT F_ProcQtyToIssue.OrderNo, F_ProcQtyToIssue.ItemCode, F_ProcQtyToIssue.ProcessID, F_ProcQtyToIssue.IssQty,
                      dbo.VFOrderItemsProcs.Description, dbo.VFOrderItemsProcs.SNO, dbo.VFOrderItemsProcs.ItemDescription, dbo.VFOrderItemsProcs.CompItemCode,
                      dbo.VendAssItems.VendID, dbo.VendAssItems.Rate, dbo.VVenders.VenderName AS VendName,
                      dbo.VFOrderItemQty.Qty, dbo.VFOrderItemQty.FreeStock
	FROM         dbo.VFOrderItemsProcs INNER JOIN
                      dbo.F_ProcQtyToIssue(@OrderNo) F_ProcQtyToIssue ON dbo.VFOrderItemsProcs.OrderNo = F_ProcQtyToIssue.OrderNo AND
                      dbo.VFOrderItemsProcs.ItemID = F_ProcQtyToIssue.ItemCode AND dbo.VFOrderItemsProcs.ProcessID = F_ProcQtyToIssue.ProcessID INNER JOIN
                      dbo.VendAssItems ON dbo.VFOrderItemsProcs.CompItemCode = dbo.VendAssItems.ItemID INNER JOIN
                      dbo.VVenders ON dbo.VendAssItems.VendID = dbo.VVenders.VendID AND F_ProcQtyToIssue.ProcessID = dbo.VVenders.PhaseID INNER JOIN
                      dbo.VFOrderItemQty ON dbo.VFOrderItemsProcs.OrderNo = dbo.VFOrderItemQty.OrderNo AND
                      dbo.VFOrderItemsProcs.CompItemCode = dbo.VFOrderItemQty.CompItemCode
	WHERE     dbo.VFOrderItemQty.CompItemCode=@ItemCode and (F_ProcQtyToIssue.IssQty > 0) and (F_ProcQtyToIssue.ProcessID=@ProcessID Or @ProcessID is null) and (dbo.VendAssItems.VendID=@VendID)
	ORDER BY F_ProcQtyToIssue.ProcessID, F_ProcQtyToIssue.ItemCode
GO
