CREATE PROCEDURE [dbo].[SP_IssueItemsLots] (@OrderNo as varchar(50) =null,@ProcessID as Int=null,@VendID as int=null,@CustCode as varchar(50)=null) AS

if @VendID is null

		SELECT TOP 100 PERCENT F_ProcQtyToIssueLots.ItemCode, F_ProcQtyToIssueLots.ProcessID, F_ProcQtyToIssueLots.IssQty, F_ProcQtyToIssueLots.LotNo,
			F_ProcQtyToIssueLots.RecieptID, dbo.Processes.Description, dbo.Processes.SNO, dbo.Items.ItemName AS ItemDescription,
			dbo.Items.ItemID AS CompItemCode,LockedItems.ItemCode As LockedItemCode
		FROM         dbo.F_ProcQtyToIssueLots() F_ProcQtyToIssueLots INNER JOIN
			dbo.Processes ON F_ProcQtyToIssueLots.ProcessID = dbo.Processes.ProcessID INNER JOIN
			dbo.Items ON F_ProcQtyToIssueLots.ItemCode = dbo.Items.ItemID LEFT OUTER JOIN LockedItems ON F_ProcQtyToIssueLots.ItemCode=LockedItems.ItemCode
		WHERE     (F_ProcQtyToIssueLots.IssQty > 0) AND (F_ProcQtyToIssueLots.ProcessID = @ProcessID)
		ORDER BY F_ProcQtyToIssueLots.ProcessID, F_ProcQtyToIssueLots.ItemCode

/*Else
	SELECT     TOP 100 PERCENT F_ProcQtyToIssue.OrderNo, F_ProcQtyToIssue.ItemCode, F_ProcQtyToIssue.ProcessID, F_ProcQtyToIssue.IssQty,
                      dbo.VFOrderItemsProcs.Description, dbo.VFOrderItemsProcs.SNO, dbo.VFOrderItemsProcs.ItemDescription, dbo.VFOrderItemsProcs.CompItemCode,
                      dbo.VendAssItems.VendID, dbo.VendAssItems.Rate, dbo.VVenders.VenderName AS VendName,
                      dbo.VFOrderItemQty.Qty, dbo.VFOrderItemQty.FreeStock,dbo.VFOrderItemQty.PackingMode
	FROM         dbo.VFOrderItemsProcs INNER JOIN
                      dbo.F_ProcQtyToIssue(@OrderNo) F_ProcQtyToIssue ON dbo.VFOrderItemsProcs.OrderNo = F_ProcQtyToIssue.OrderNo AND
                      dbo.VFOrderItemsProcs.ItemID = F_ProcQtyToIssue.ItemCode AND dbo.VFOrderItemsProcs.ProcessID = F_ProcQtyToIssue.ProcessID INNER JOIN
                      dbo.VendAssItems ON dbo.VFOrderItemsProcs.CompItemCode = dbo.VendAssItems.ItemID INNER JOIN
                      dbo.VVenders ON dbo.VendAssItems.VendID = dbo.VVenders.VendID AND F_ProcQtyToIssue.ProcessID = dbo.VVenders.PhaseID INNER JOIN
                      dbo.VFOrderItemQty ON dbo.VFOrderItemsProcs.OrderNo = dbo.VFOrderItemQty.OrderNo AND
                      dbo.VFOrderItemsProcs.CompItemCode = dbo.VFOrderItemQty.CompItemCode
	WHERE     (F_ProcQtyToIssue.IssQty > 0) and (F_ProcQtyToIssue.ProcessID=@ProcessID Or @ProcessID is null) and (dbo.VendAssItems.VendID=@VendID)
	ORDER BY F_ProcQtyToIssue.ProcessID, F_ProcQtyToIssue.ItemCode*/
GO
