CREATE PROCEDURE [dbo].[SP_IssueRepair]  (@VendID as int,@ProcessID as int,@ItemCode Varchar(50),@Qty as int,@iRefID as int) AS

Declare @TempQty as int
Declare @TempTot as int
Declare @CurrQty as int

Set @TempTot=0

Declare @OrderNo as varchar(50)
DECLARE TempTable1 CURSOR

FOR
	Select OrderNo,ForRepair From VVendIssRepairByOrder
	Where ForRepair>0 and ItemCode=@ItemCode and ProcessID=@ProcessID and VendID=@VendID


OPEN TempTable1
FETCH NEXT FROM TempTable1 into @OrderNo,@CurrQty

WHILE @@FETCH_STATUS = 0
	BEGIN
		If (@CurrQty>@Qty-@TempTot)   --For Remaining
			Begin
				Set @TempQty=@Qty-@TempTot
			End
		Else
			Begin
				Set @TempQty=@CurrQty
			End


		If @TempQty=0
			Break
		--Update VendRcvdDetail Set IssQty=IssQty+@TempQty Where EntryID=@EntryID

		Insert Into VendRepairIssDetail(RefID,OrderNo,ItemCode,ProcessID,IssQty)
		Values(@iRefID,@OrderNo,@ItemCode,@ProcessID,@TempQty)


		Set @TempTot=@TempTot+@TempQty
		FETCH NEXT FROM TempTable1 into @OrderNo,@CurrQty

	END

CLOSE TempTable1
DEALLOCATE TempTable1
GO
