CREATE PROCEDURE [dbo].[SP_OldAgeMonthly](
@ParDate as DateTime,@DeptID as varchar(50)=null) as
SELECT VEmp.*,MonthlySalaries.FakeSalary As EmpSalary, MonthlySalaries.FakeWorkingHrs As SalDays,MonthlySalaries.Total As SalAmt ,
Case When (MonthlySalaries.Total-MonthlySalaries.OAmt) <4000  Then (MonthlySalaries.Total-MonthlySalaries.OAmt ) * 6/100 Else 240 End  As EOBIAmt,CASE WHEN DATEDIFF(dd, dbo.VEmp.JoinDate, dbo.VCurDT.CurDT)
                      > 90 THEN 'Permanent' ELSE 'Temporary' END AS EmpStatus
From VEmp Inner Join MonthlySalaries On VEmp.EmpID=Monthlysalaries.EMPID Cross Join VCurDT
WHERE month(MonthlySalaries.Dt)=month(@ParDate) AND year(MonthlySalaries.DT) =Year(@ParDate) and (VEmp.DeptID=@DeptID or @DeptID is null )
and IsForSA=1 AND MonthlySalaries.EOBI>0
GO
