CREATE PROCEDURE [dbo].[SP_PaymentStatus] (@CustCode VARCHAR(50)=NULL,@Status INT=2,@CustomPayments BIT=0) AS

/*
@Status
0=Unpaid
1=Paid
2=All
*/
IF @CustomPayments=1
	BEGIN
	IF @Status=0
		SELECT * FROM VPaymentStatus WHERE FreeSamples=0 AND GatePassNo<>'' AND (CustCode=@CustCode OR @CustCode IS NULL) And CustomPayment<>0  And CustomInvoice In(SELECT CustomInvoice FROM VrptCustomInvoice WHERE TotalCustomAmtToRcv>0) ORDER BY CustomInvoice,EntryType,DT,EntryID
	ELSE IF @Status=1
		SELECT * FROM VPaymentStatus WHERE FreeSamples=0 AND GatePassNo<>'' AND  (CustCode=@CustCode OR @CustCode IS NULL) And CustomPayment<>0  And CustomInvoice In(SELECT CustomInvoice FROM VrptCustomInvoice WHERE TotalCustomAmtToRcv<=0) ORDER BY CustomInvoice,EntryType,DT,EntryID
	ELSE IF @Status=2
		SELECT * FROM VPaymentStatus WHERE FreeSamples=0 AND GatePassNo<>'' AND  (CustCode=@CustCode OR @CustCode IS NULL) And CustomPayment<>0   ORDER BY CustomInvoice,EntryType,DT,EntryID
	END
ELSE
	BEGIN
	IF @Status=0
		SELECT * FROM VPaymentStatus WHERE FreeSamples=0 AND GatePassNo<>'' AND  (CustCode=@CustCode OR @CustCode IS NULL) And CustomPayment<>1  And CustomInvoice In(SELECT CustomInvoice FROM VrptCustomInvoice WHERE TotalCommercialAmtToRcv>0) ORDER BY CustomInvoice,EntryType,DT,EntryID
	ELSE IF @Status=1
		SELECT * FROM VPaymentStatus WHERE FreeSamples=0 AND GatePassNo<>'' AND  (CustCode=@CustCode OR @CustCode IS NULL) And CustomPayment<>1 And CustomInvoice In(SELECT CustomInvoice FROM VrptCustomInvoice WHERE TotalCommercialAmtToRcv<=0) ORDER BY CustomInvoice,EntryType,DT,EntryID
	ELSE IF @Status=2
		SELECT * FROM VPaymentStatus WHERE FreeSamples=0 AND GatePassNo<>'' AND  (CustCode=@CustCode OR @CustCode IS NULL) And CustomPayment<>1   ORDER BY CustomInvoice,EntryType,DT,EntryID
	END
GO
