CREATE PROCEDURE [dbo].[SP_PrintDailyAbsentLeaveDetail](@DT As DateTime) AS

Begin
	Declare @EmpID As Varchar(50)
	Declare @FullLeave As Bit,@HalfLeave As Bit
	Declare @Absent As Bit,@Present As Bit
	Declare @LateComing As Bit
	Declare @LateHours As Float
	Declare @StartDate As DateTime
	Declare @EndDate As DateTime,@EndDate1 As DateTime
	Declare @TotDays As Int
	DECLARE @myDT As DateTime
	SET @myDT=dbo.GetLastWorkingDate(@DT)

	Set @EndDate=@DT
	Set @EndDate1=DateAdd(d,-1,@DT)--GetDate()
	If Month(@EndDate)<7
		Set @StartDate=Cast(7 As Char(1)) + '/1/' + Cast(Year(@EndDate)-1 As Varchar)
	Else
		Set @StartDate=Cast(7 As Char(1)) + '/1/' + Cast(Year(@EndDate) As Varchar)

	Delete From PrintDailyAbsentLeaveDetail
	Insert Into PrintDailyAbsentLeaveDetail(DT,EmpID,Absents,Present,PrevDT) SELECT @DT As DT,EmpID,Case When JoinDate>@StartDate Then DateDiff(d,JoinDate,@EndDate) Else DateDiff(d,@StartDate,@EndDate) END As TotDays,0 As Present,@myDT From Employees
	Where Active=1

	UPDATE PrintDailyAbsentLeaveDetail SET PrintDailyAbsentLeaveDetail.FullLeave=Leaves.FullLeaves,PrintDailyAbsentLeaveDetail.HalfLeave=ABS(1-Leaves.FullLeaves)
	FROM PrintDailyAbsentLeaveDetail,(Select EmpID,[Full] As FullLeaves  From VLeaves Where DT=@DT) Leaves WHERE PrintDailyAbsentLeaveDetail.EmpID=Leaves.EmpID

	UPDATE PrintDailyAbsentLeaveDetail SET PrintDailyAbsentLeaveDetail.Present=Att.Present,PrintDailyAbsentLeaveDetail.Absent=Att.Absent,PrintDailyAbsentLeaveDetail.LateComing=Att.LateComing,PrintDailyAbsentLeaveDetail.LateTime=Att.LateHours
	FROM PrintDailyAbsentLeaveDetail,(Select EmpID,Case When Attendance=3 Then 1 Else 0 End As Absent,Case When IsNull(LateHours,0)>0 Then  1 Else 0 End As LateComing,LateHours,
	 Case When Attendance=1 Then 1 Else 0 End As Present From AttendanceSheet Where DT=@DT) Att WHERE PrintDailyAbsentLeaveDetail.EmpID=Att.EmpID


	UPDATE PrintDailyAbsentLeaveDetail SET Absent=1 WHERE EmpID Not In(SELECT EmpID FROM AttendanceSheet WHERE DT=@DT)

	UPDATE PrintDailyAbsentLeaveDetail SET HalfLeaves=TotalHalfLeaves,FullLeaves=TotalFullLeaves,CasualLeaves=TotalCL,SickLeaves=TotalSL,AnnLeaves=TotalAL,CPLLeaves=TotalCPL,LWPLeaves=TotalLWP,MatLeaves=TotalML
	FROM PrintDailyAbsentLeaveDetail,(Select EmpID,Sum(Case When [Full]=0 Then 1 Else 0 End) As TotalHalfLeaves,Sum(Case When [Full]=1 Then 1 Else 0 End) As TotalFullLeaves,
	 SUM(CL) As TotalCL,SUM(SL) As TotalSL,SUM(AL) As TotalAL,SUM(CPL) As TotalCPL,SUM(LWP) As TotalLWP,SUM(ML) As TotalML
	 From Leaves Where DT Between @StartDate AND @EndDate1 Group By EmpID) Leaves WHERE PrintDailyAbsentLeaveDetail.EmpID=Leaves.EmpID


	UPDATE PrintDailyAbsentLeaveDetail SET LateComings=TotalLateComings
	FROM PrintDailyAbsentLeaveDetail,(Select EmpID,Sum(Case When IsNull(LateHours,0)>0 Then 1 Else 0 End) As TotalLateComings
	 FROM AttendanceSheet Where DT Between @StartDate AND @EndDate1 Group By EmpID) Att WHERE PrintDailyAbsentLeaveDetail.EmpID=Att.EmpID


	DECLARE @TotInDays As Int,@TotPresents As Int
	DECLARE @TotSuns As Int,@TotHolidays As Int

	Set @TotSuns=dbo.FTotalSundays(@StartDate,@EndDate)
	SELECT @TotHolidays=Count(DT) From Holidays Where DT Between @StartDate AND @EndDate

	UPDATE PrintDailyAbsentLeaveDetail SET Absents=Absents-@TotSuns-@TotHolidays-TotPresents
	FROM PrintDailyAbsentLeaveDetail,(Select EmpID,Count(EmpID) As TotPresents From AttendanceSheet Where Attendance<>3 AND DT Between @StartDate AND @EndDate Group By EmpID) Att WHERE PrintDailyAbsentLeaveDetail.EmpID=Att.EmpID


	UPDATE PrintDailyAbsentLeaveDetail SET PrintDailyAbsentLeaveDetail.InTime=a.InTime
	From PrintDailyAbsentLeaveDetail,(Select EmpID,MIN(InTime) InTime From EmpTimes Where DT=@DT GROUP BY EMPID) a
	Where PrintDailyAbsentLeaveDetail.EmpID=a.EmpID

	DECLARE @myTable TABLE(EmpID VARCHAR(50),FirstInTime CHAR(5),FirstOutTime CHAR(5),SecondInTime CHAR(5),SecondOutTime CHAR(5),OTInTime CHAR(5),OTOutTime CHAR(5),PayableHrs REAL)
	INSERT INTO @myTable SELECT EmpID,FirstInTime,FirstOutTime,SecondInTime,SecondOutTime,OTInTime,OTOutTime,PayableHrs From VEmpTimes2 Where DT=@myDT

	UPDATE PrintDailyAbsentLeaveDetail SET PrevFirstIn=FirstInTime,PrevFirstOut=FirstOutTime,PrevSecondIn=SecondInTime,PrevSecondOut=SecondOutTime,PrevOTIn=OTInTime,PrevOTOut=OTOutTime,PrevPayableHrs=a.PayableHrs
	From PrintDailyAbsentLeaveDetail,@myTable a
	WHERE PrintDailyAbsentLeaveDetail.EmpID=a.EmpID
	/*UPDATE PrintDailyAbsentLeaveDetail SET PrevFirstIn=FirstInTime,PrevFirstOut=FirstOutTime,PrevSecondIn=SecondInTime,PrevSecondOut=SecondOutTime,PrevOTIn=OTInTime,PrevOTOut=OTOutTime,PrevPayableHrs=a.PayableHrs
	From PrintDailyAbsentLeaveDetail,(Select EmpID,FirstInTime,FirstOutTime,SecondInTime,SecondOutTime,OTInTime,OTOutTime,PayableHrs From VEmpTimes2 Where DT=@myDT ) a
	WHERE PrintDailyAbsentLeaveDetail.EmpID=a.EmpID*/

End
GO
