CREATE PROCEDURE [dbo].[SP_PrintEmpAbsentList](@DTFrom As DateTime,@DTTo As DateTime,@DeptID AS VARCHAR(50)=NULL) AS

BEGIN
DECLARE @dt AS DATETIME
SET @dt=@DTFrom
DELETE FROM PrintEmpAbsentList
DELETE FROM PrintEmpAbsentList_Summary
WHILE @dt<=@DTTo
	BEGIN
		IF DATENAME(dw,@dt)<>'Sunday'

			INSERT INTO PrintEmpAbsentList(DT,EmpID) SELECT  @dt,Employees.EmpID FROM Employees LEFT OUTER JOIN VEmpLastInActiveDate ON  Employees.EmpID=VEmpLastInActiveDate.EmpID WHERE Employees.EmpID Not In(SELECT EmpID FROM
			 AttendanceSheet WHERE DT=@DT) AND Employees.EmpID NOT IN (SELECT EmpID FROM Leaves WHERE DT=@DT)
			 AND JoinDate<=@dt AND DeptID In(SELECT DeptID FROM Departments WHERE TempDept=0)
			 AND @DT NOT IN(SELECT DT FROM Holidays) AND (DiscontinuedOn IS NULL OR DiscontinuedOn>@dt)
			 AND (DeptID=@DeptID OR @DeptID IS NULL)
			 AND (InActiveDT IS NULL OR InActiveDT>@DT)
			 AND Employees.Active=1

		SET @dt=DATEADD(d,1,@dt)
	END

	INSERT INTO PrintEmpAbsentList_Summary(EmpID,Total_Absents) SELECT EmpID,COUNT(*) FROM PrintEmpAbsentList GROUP BY EmpID
END
GO
