CREATE PROCEDURE [dbo].[SP_PrintIssRcvRpts]
(@FromDate datetime,@ToDate as DateTime=Null,@RcvRpt as bit=0,@DailyRpt as bit=0,@ProcessID As Int=0)
as
	Declare @InitLotProc as int
	Set @InitLotProc=(Select ProcessID From InitialLotProcess)
--Removed  (Wastage=0)  from where condition for VVendRcvItemsrpt
	Delete From PrintIssRcvRpts
	If @RcvRpt=1
		If @ToDate Is Null
			Insert Into PrintIssRcvRpts Select CompItemDesc,DT,RecieptID,ItemCode,VenderName,VendID1,ProcessID,Process,RcvdQty,Wastage,LostQty,UserID,AuthUserID,AuthDT,0 As IssEntry From VVendRcvItemsrpt
			 Where (Convert(Varchar,DT,6)=Convert(Varchar,@FromDate,6))
			 and (ReqAuth=0) and (ProcessID<=@InitLotProc)  and (ProcessID Like IsNull(@ProcessID,ProcessID))
		Else
			Insert Into PrintIssRcvRpts Select CompItemDesc,DT,RecieptID,ItemCode,VenderName,VendID1,ProcessID,Process,RcvdQty,Wastage,LostQty,UserID,AuthUserID,AuthDT,0 As IssEntry From VVendRcvItemsrpt
			 Where ((Cast(Convert(Varchar(11),DT,6) as DateTime) Between @FromDate and @ToDate)  and (ReqAuth=0) and (ProcessID<=@InitLotProc))
			and (ProcessID Like IsNull(@ProcessID,ProcessID))
			 --Or (Convert(Varchar,DT,6)=Convert(Varchar,@FromDate,6))
	Else
		If @ToDate Is Null
			Insert Into PrintIssRcvRpts Select CompItemDesc,DT,RecieptID,ItemCode,VenderName,VendID1,ProcessID,Process,IssQty,0 As Wastage,0 As LostQty,UserID,AuthUserID,AuthDT,1 As IssEntry From VVendIssItemsrpt
			 Where (Convert(Varchar,DT,6)=Convert(Varchar,@FromDate,6))
			 and (ReqAuth=0 and ProcessID<=@InitLotProc)  and (ProcessID Like IsNull(@ProcessID,ProcessID))
		Else
			Insert Into PrintIssRcvRpts  Select CompItemDesc,DT,RecieptID,ItemCode,VenderName,VendID1,ProcessID,Process,IssQty,0 As Wastage,0 As LostQty,UserID,AuthUserID,AuthDT,1 As IssEntry From VVendIssItemsrpt
			 Where ((Cast(Convert(Varchar(11),DT,6) as DateTime) Between @FromDate and @ToDate) and (IsNull(ReqAuth,0)=0 and ProcessID<=@InitLotProc))
			 and (ProcessID Like IsNull(@ProcessID,ProcessID))
			 --Or (Convert(Varchar,DT,6)=Convert(Varchar,@FromDate,6))
GO
