CREATE PROCEDURE [dbo].[SP_RebateStatus] (@Status Int=2) AS

/*
@Status
0=Unpaid
1=Paid
2=All
*/

If @Status=0
	Select * From VRebateStatus Where CustomInvoice In(Select CustomInvoice From VRebateBalance Where Round(Balance,1)>0) Order By CustomInvoice,EntryType,DT,EntryID
Else If @Status=1
	Select * From VRebateStatus Where CustomInvoice In(Select CustomInvoice From VRebateBalance Where Round(Balance,1)=0) Order By CustomInvoice,EntryType,DT,EntryID
Else If @Status=2
	Select * From VRebateStatus Where CustomInvoice Is Null Order By CInvoice
Else If @Status=3
	Select * From VRebateStatus Order By CInvoice,EntryType,DT,EntryID
GO
