GO

CREATE PROCEDURE [dbo].[SP_ReturnIssEntry]  (@RecieptID As Varchar(50),@ItemCode Varchar(50),@ProcessID as int,@Qty as int) AS

Declare @TempQty as int
Declare @TempTot as int
Declare @CurrQty as int
Declare @EntryID as int
Set @TempTot=0

DECLARE TempTable1 CURSOR

FOR
	Select EntryID,IssQty From VVendRcvdDetail
	Where IssQty>0 AND ItemCode=@ItemCode and NextProcessID=@ProcessID AND ReqAuth=0 Order By EntryID

OPEN TempTable1
FETCH NEXT FROM TempTable1 into @EntryID,@CurrQty

WHILE @@FETCH_STATUS = 0
	BEGIN
		If (@CurrQty>@Qty-@TempTot)   --For Remaining
			Begin
				Set @TempQty=@Qty-@TempTot
			End
		Else
			Begin
				Set @TempQty=@CurrQty
			End

		Update VendRcvdDetail Set IssQty=IssQty-@TempQty Where EntryID=@EntryID

		Set @TempTot=@TempTot+@TempQty
		FETCH NEXT FROM TempTable1 into @EntryID,@CurrQty
		If @TempTot=@Qty
			GoTo OUT_OF_LOOP
	END
OUT_OF_LOOP:
	Delete From VendIssdDetail Where RecieptID=@RecieptID

CLOSE TempTable1
DEALLOCATE TempTable1
GO
