CREATE PROCEDURE [dbo].[SP_SSMonthly](
@ParDate as DateTime,@DeptID as varchar(50)=null) as
SELECT VSSEmployees.*,MonthlySalaries.FakeSalary As EmpSalary, MonthlySalaries.FakeWorkingHrs As SDays,
--Round((MonthlySalaries.Rate*MonthlySalaries.SDays),-1) as SalAmt ,
MonthlySalaries.Total as SalAmt,
Case When  MonthlySalaries.Total>5000 Then  350 Else (MonthlySalaries.Total)* 7/100 END as SocialAmt
 From VSSEmployees Inner Join MonthlySalaries On VSSEmployees.EmpID=Monthlysalaries.EMPID
WHERE month(MonthlySalaries.Dt)=month(@ParDate) AND year(MonthlySalaries.DT) =Year(@ParDate) and
(VSSEmployees.DeptID=@DeptID or @DeptID is null ) and IsForSA=1 AND VSSEmployees.Social=1
GO
