CREATE PROCEDURE [dbo].[SP_TBBase]
(@FromDate datetime)
as
SELECT     Accno, balance + Credit - Debit AS TheBalance
FROM         dbo.Vouchers
WHERE     (SNo IN
                          (SELECT     MAX(Sno)
                            FROM          Vouchers
                            WHERE      VDATE <= @FromDate
                            GROUP BY Accno))
GO
