CREATE PROCEDURE [dbo].[SP_TBHeads] (@FromDate as datetime)
AS
SELECT     dbo.Heads.code, dbo.Heads.Head, ISNULL(H1.H1OBal, H2.H2OBal) AS OpeningBalance
FROM         dbo.Heads LEFT OUTER JOIN
                          (SELECT     LEFT(VTB.AccNo, 2) AS AccType, SUM(TheBalance) AS H1OBal
                            FROM          F_TBase(@FromDate) AS VTB
                            GROUP BY LEFT(VTB.AccNo, 2)) H1 ON dbo.Heads.code = H1.AccType LEFT OUTER JOIN
                          (SELECT     Accounts.Type AS AccType, SUM(OpenBal) AS H2OBal
                            FROM          Accounts
                            GROUP BY Accounts.Type) H2 ON dbo.Heads.code = H2.AccType
GO
