CREATE PROCEDURE [dbo].[SP_UpdateForIARLots]  (@ProcessID as int,@Qty as int,@LotNo as int,@RefID as int,@Rate as float,@RecID as Varchar(50),@ReqAuth as bit) AS

Declare @TempQty as int
Declare @TempTot as int
Declare @CurrQty as int
Declare @EntryID as int
Declare @OrderNo as Varchar(50)
Declare @ItemCode as Varchar(50)


Set @TempTot=0

DECLARE TempTable1 CURSOR

FOR
	Select ItemCode,RcvdQty From VendRcvdDetail
	Where NextProcessID=@ProcessID and LotNo=@LotNo Order By EntryID

OPEN TempTable1
FETCH NEXT FROM TempTable1 into @ItemCode,@CurrQty

WHILE @@FETCH_STATUS = 0
	BEGIN
		If (@CurrQty>@Qty-@TempTot)   --For Remaining
			Begin
				Set @TempQty=@Qty-@TempTot
			End
		Else
			Begin
				Set @TempQty=@CurrQty
			End

		--Update VendRcvdDetail Set IssQty=IssQty+@TempQty Where EntryID=@EntryID
		Insert Into VendIssdDetail(RefID,RecieptID,ItemCode,Rate,IssQty,LotNo,ReqAuth)
		 Values(@RefID,@RecID,@ItemCode,@Rate,@CurrQty,@LotNo,@ReqAuth)

		Set @TempTot=@TempTot+@TempQty
		FETCH NEXT FROM TempTable1 into @ItemCode,@CurrQty

	END

CLOSE TempTable1
DEALLOCATE TempTable1
GO
