CREATE PROCEDURE [dbo].[SP_UpdateIssued] (@ItemCode Varchar(50),@ProcessID as int,@VendID as int,@Qty as int,@OrderNo AS Varchar(50)) AS

Declare @TempQty as int
Declare @TempTot as int
Declare @CurrQty as int
Declare @EntryID as int
Set @TempTot=0

DECLARE Cursor_UpdateIssued CURSOR

FOR
	Select EntryID,IssQty-RcvdQty From VMakerIssItems
	Where IssQty-RcvdQty>0 and ItemCode=@ItemCode and RcvProcessID=@ProcessID and VendID=@VendID AND ReqAuth=0 AND OrderNo=@OrderNo--Order By EntryID

OPEN Cursor_UpdateIssued
FETCH NEXT FROM Cursor_UpdateIssued into @EntryID,@CurrQty

WHILE @@FETCH_STATUS = 0
	BEGIN
		If (@CurrQty>@Qty-@TempTot)   --For Remaining
			Begin
					Set @TempQty=@Qty-@TempTot
			End
		Else
			Begin
				Set @TempQty=@CurrQty
			End

		Update VendIssdDetail Set RcvdQty=RcvdQty+@TempQty Where EntryID=@EntryID
		Set @TempTot=@TempTot+@TempQty
		FETCH NEXT FROM Cursor_UpdateIssued into @EntryID,@CurrQty
	END

CLOSE Cursor_UpdateIssued
DEALLOCATE Cursor_UpdateIssued
GO
