CREATE PROCEDURE [dbo].[SP_UpdateIssuedNew] (@ItemCode Varchar(50),@ProcessID as int,@VendID as int,@Qty as int,@OrderNo AS Varchar(50),@DeliveryRefID AS INT,@VRD_EntryID AS INT) AS

Declare @TempQty as int
Declare @TempTot as int
Declare @CurrQty as int
Declare @EntryID as int
Set @TempTot=0

UPDATE VendIssdDetail SET RcvdQty=RcvdQty+@Qty WHERE OrderNo=@OrderNo AND RefID=@DeliveryRefID AND ItemCode=@ItemCode AND RcvProcessID=@ProcessID
DECLARE Cursor_UpdateIssued CURSOR

FOR
	SELECT  EntryID,IssQty-RcvQty From VendIssdDetail_ReturnDTs
		WHERE VIS_RefID IN(SELECT EntryID FROM VendIssdDetail WHERE OrderNo=@OrderNo AND RefID=@DeliveryRefID AND ItemCode=@ItemCode AND RcvProcessID=@ProcessID) ORDER BY ReturnDT--(IssQty-RcvQty) DESC

OPEN Cursor_UpdateIssued
FETCH NEXT FROM Cursor_UpdateIssued into @EntryID,@CurrQty

WHILE @@FETCH_STATUS = 0
	BEGIN
		If (@CurrQty>@Qty-@TempTot)   --For Remaining
			Begin
					Set @TempQty=@Qty-@TempTot
			End
		Else
			Begin
				Set @TempQty=@CurrQty
			End

		UPDATE VendIssdDetail_ReturnDTs  SET RcvQty=RcvQty+@TempQty WHERE EntryID=@EntryID
		INSERT INTO VendRcvdDetail_VID_RDTs(VID_RDTs_RefID,VRD_RefID,Qty) VALUES(@EntryID,@VRD_EntryID,@TempQty)
		SET @TempTot=@TempTot+@TempQty
		FETCH NEXT FROM Cursor_UpdateIssued INTO @EntryID,@CurrQty
	END

CLOSE Cursor_UpdateIssued
DEALLOCATE Cursor_UpdateIssued

IF (@Qty-@TempTot)>0 --Update Last Row, Even if It goes in minus.
	Update VendIssdDetail_ReturnDTs SET RcvQty=RcvQty+(@Qty-@TempTot) WHERE EntryID=@EntryID

GO
