CREATE PROCEDURE [dbo].[SP_UpdateRepair]  (@VendID as int,@ItemCode Varchar(50),@Qty as int) AS

Declare @TempQty as int
Declare @TempTot as int
Declare @CurrQty as int

Set @TempTot=0

Declare @EntryID as int
DECLARE @TempTable1 CURSOR

Declare @RepairVend As Bit
Select @RepairVend=RepairVend From Venders Where VendID=@VendID

If @RepairVend=1
	Set @TempTable1 = CURSOR FOR
	Select EntryID,RepairQty From VUpdateRepair
	 Where ItemCode=@ItemCode And ForVendID In(Select VendID From Venders Where OwnRepair=0)
Else
	Set @TempTable1 = CURSOR FOR
	Select EntryID,RepairQty From VUpdateRepair
	 Where ItemCode=@ItemCode  and ForVendID=@VendID


OPEN @TempTable1
FETCH NEXT FROM @TempTable1 into @EntryID,@CurrQty

WHILE @@FETCH_STATUS = 0
	BEGIN
		If (@CurrQty>@Qty-@TempTot)   --For Remaining
			Begin
				Set @TempQty=@Qty-@TempTot
			End
		Else
			Begin
				Set @TempQty=@CurrQty
			End


		If @TempQty=0
			Break
		--Update VendRcvdDetail Set IssQty=IssQty+@TempQty Where EntryID=@EntryID

		Update VendRcvdDetail Set IssRepairQty=IssRepairQty+@TempQty Where EntryID=@EntryID

		Set @TempTot=@TempTot+@TempQty
		FETCH NEXT FROM @TempTable1 into @EntryID,@CurrQty

	END

CLOSE @TempTable1
DEALLOCATE @TempTable1
GO
