CREATE PROCEDURE [dbo].[SP_VendAdvSalary]( @ParDate Datetime,@VendID int,@ProcessID as int,@TotMonDays as int) AS
Begin
	IF @VendID<>0
		SELECT     dbo.Venders.VendID, dbo.Venders.VendID1, dbo.Venders.VenderName, dbo.Venders.PhaseID, F_VendLongDeduct.DedAmt, F_VendLongDeduct.TotAmt,
		                      F_VendLongDeduct.ClsAmt, F_VendPayed.Payed, F_VendAdvSal.AdvSalPaid, F_VendWorkDone.Total, F_VendResDed.TotalResDeduction,GeneralSettings.AdvSalPer
				,F_VendPlantBill.TotAmt As PlantBill,F_VendSnaffBill.TotAmt As SnaffBill,F_VendRepairDeduction.RepairDeduction As RepairDeduction
		FROM         dbo.Venders LEFT OUTER JOIN
		                      dbo.F_VendResDed(@ParDate,@TotMonDays) F_VendResDed ON dbo.Venders.VendID = F_VendResDed.VendID LEFT OUTER JOIN
		                      dbo.F_VendWorkDone(@ParDate) F_VendWorkDone ON dbo.Venders.VendID = F_VendWorkDone.VendID LEFT OUTER JOIN
		                      dbo.F_VendAdvSal(@ParDate) F_VendAdvSal ON dbo.Venders.VendID = F_VendAdvSal.VendID LEFT OUTER JOIN
		                      dbo.F_VendPayed(@ParDate) F_VendPayed ON dbo.Venders.VendID = F_VendPayed.VendID LEFT OUTER JOIN
		                      dbo.F_VendLongDeduct(@ParDate) F_VendLongDeduct ON dbo.Venders.VendID = F_VendLongDeduct.VendID LEFT OUTER JOIN
			        dbo.GeneralSettings ON dbo.Venders.PhaseID=GeneralSettings.ProcessID LEFT OUTER JOIN
				dbo.F_VendPlantBill(@ParDate) F_VendPlantBill ON dbo.Venders.VendID=F_VendPlantBill.VendID LEFT OUTER JOIN
				dbo.F_VendSnaffBill(@ParDate) F_VendSnaffBill ON dbo.Venders.VendID=F_VendSnaffBill.VendID LEFT OUTER JOIN
				dbo.F_VendRepairDeduction(@ParDate) F_VendRepairDeduction ON dbo.Venders.VendID=F_VendRepairDeduction.VendID
			--WHERE (VOnlyEmps.JoinDate<=@Pardate) and VOnlyEmps.EmpID like @EmpID+'%')
		Where Venders.VendID=@VendID AND Venders.VendID<>129  AND F_VendWorkDone.Total>0 --AND IsNull(GeneralSettings.AdvSalPer,0)>0
	Else If @ProcessID<>0
		SELECT     dbo.Venders.VendID, dbo.Venders.VendID1, dbo.Venders.VenderName, dbo.Venders.PhaseID, F_VendLongDeduct.DedAmt, F_VendLongDeduct.TotAmt,
		                      F_VendLongDeduct.ClsAmt, F_VendPayed.Payed, F_VendAdvSal.AdvSalPaid, F_VendWorkDone.Total, F_VendResDed.TotalResDeduction,GeneralSettings.AdvSalPer
				,F_VendPlantBill.TotAmt As PlantBill,F_VendSnaffBill.TotAmt As SnaffBill,F_VendRepairDeduction.RepairDeduction As RepairDeduction
		FROM         dbo.Venders LEFT OUTER JOIN
		                      dbo.F_VendResDed(@ParDate,@TotMonDays) F_VendResDed ON dbo.Venders.VendID = F_VendResDed.VendID LEFT OUTER JOIN
		                      dbo.F_VendWorkDone(@ParDate) F_VendWorkDone ON dbo.Venders.VendID = F_VendWorkDone.VendID LEFT OUTER JOIN
		                      dbo.F_VendAdvSal(@ParDate) F_VendAdvSal ON dbo.Venders.VendID = F_VendAdvSal.VendID LEFT OUTER JOIN
		                      dbo.F_VendPayed(@ParDate) F_VendPayed ON dbo.Venders.VendID = F_VendPayed.VendID LEFT OUTER JOIN
		                      dbo.F_VendLongDeduct(@ParDate) F_VendLongDeduct ON dbo.Venders.VendID = F_VendLongDeduct.VendID LEFT OUTER JOIN
			        dbo.GeneralSettings ON dbo.Venders.PhaseID=GeneralSettings.ProcessID LEFT OUTER JOIN
				dbo.F_VendPlantBill(@ParDate) F_VendPlantBill ON dbo.Venders.VendID=F_VendPlantBill.VendID LEFT OUTER JOIN
				dbo.F_VendSnaffBill(@ParDate) F_VendSnaffBill ON dbo.Venders.VendID=F_VendSnaffBill.VendID LEFT OUTER JOIN
				dbo.F_VendRepairDeduction(@ParDate) F_VendRepairDeduction ON dbo.Venders.VendID=F_VendRepairDeduction.VendID
		Where Venders.PhaseID=@ProcessID AND Venders.VendID<>129 AND F_VendWorkDone.Total>0 AND IsNull(GeneralSettings.AdvSalPer,0)>0
	Else
		SELECT     dbo.Venders.VendID, dbo.Venders.VendID1, dbo.Venders.VenderName, dbo.Venders.PhaseID, F_VendLongDeduct.DedAmt, F_VendLongDeduct.TotAmt,
		                      F_VendLongDeduct.ClsAmt, F_VendPayed.Payed, F_VendAdvSal.AdvSalPaid, F_VendWorkDone.Total, F_VendResDed.TotalResDeduction,
				F_VendAdvSal.CashPaid,F_VendAdvSal.ChequeNo,GeneralSettings.AdvSalPer,F_VendPlantBill.TotAmt As PlantBill,F_VendSnaffBill.TotAmt As SnaffBill,F_VendRepairDeduction.RepairDeduction As RepairDeduction
		FROM         dbo.Venders LEFT OUTER JOIN
		                      dbo.F_VendResDed(@ParDate,@TotMonDays) F_VendResDed ON dbo.Venders.VendID = F_VendResDed.VendID LEFT OUTER JOIN
		                      dbo.F_VendWorkDone(@ParDate) F_VendWorkDone ON dbo.Venders.VendID = F_VendWorkDone.VendID LEFT OUTER JOIN
		                      dbo.F_VendAdvSal(@ParDate) F_VendAdvSal ON dbo.Venders.VendID = F_VendAdvSal.VendID LEFT OUTER JOIN
		                      dbo.F_VendPayed(@ParDate) F_VendPayed ON dbo.Venders.VendID = F_VendPayed.VendID LEFT OUTER JOIN
		                      dbo.F_VendLongDeduct(@ParDate) F_VendLongDeduct ON dbo.Venders.VendID = F_VendLongDeduct.VendID LEFT OUTER JOIN
			        dbo.GeneralSettings ON dbo.Venders.PhaseID=GeneralSettings.ProcessID LEFT OUTER JOIN
				dbo.F_VendPlantBill(@ParDate) F_VendPlantBill ON dbo.Venders.VendID=F_VendPlantBill.VendID LEFT OUTER JOIN
				dbo.F_VendSnaffBill(@ParDate) F_VendSnaffBill ON dbo.Venders.VendID=F_VendSnaffBill.VendID LEFT OUTER JOIN
				dbo.F_VendRepairDeduction(@ParDate) F_VendRepairDeduction ON dbo.Venders.VendID=F_VendRepairDeduction.VendID
			         Where Venders.VendID<>129 AND F_VendWorkDone.Total>0 AND IsNull(GeneralSettings.AdvSalPer,0)>0
End
GO
