CREATE PROCEDURE [dbo].[SP_VendAssItem] @VendID AS INT,@ItemID AS VARCHAR(50)='0',@ProcessID AS INT,@Rate AS REAL
AS

DECLARE @PlantRate AS FLOAT
DECLARE @StampRate AS FLOAT
DECLARE @SnaffRate AS FLOAT
DECLARE @Unit AS VARCHAR(50)
IF @ItemID<>'0'
	BEGIN
		SELECT @PlantRate=PlantRate,@StampRate=StampRate,@SnaffRate=SnaffRate,@Unit=Unit From Items Where ItemID=@ItemID
		--Print @ItemID
		INSERT INTO VendAssItems(VendID,ProcessID,ItemID,Rate,PlantRate,StampRate,SnaffRate,Unit)
		VALUES(@VendID,@ProcessID,@ItemID,@Rate,@PlantRate,@StampRate,@SnaffRate,@Unit)
	END
ELSE
	INSERT INTO VendAssItems(VendID,ProcessID,ItemID,PlantRate,StampRate,SnaffRate)
	SELECT *
	FROM F_VendAssItems(@VendID,@ProcessID)
GO
