CREATE PROCEDURE [dbo].[SP_VendSalarySettings] (@ParDate Datetime,@VendID int,@AdvSalary bit)
as

If @VendID=0
	SELECT VendMonthlyPayments.*
	FROM VendMonthlyPayments
	WHERE (month(dt) = Month(@ParDate) AND year(DT) = Year(@ParDate) AND DT <=@ParDATE )
		and AdvSalary=@advsalary;
Else
	SELECT VendMonthlyPayments.*
	FROM VendMonthlyPayments
	WHERE (month(dt) = Month(@ParDate) AND year(DT) = Year(@ParDate) AND DT <=@ParDATE )
		and VendID=@VendID and AdvSalary=@advsalary

GO
