CREATE PROCEDURE [dbo].[StockReport_SP]

	@DTFrom AS DATETIME,
	@DTTo AS DATETIME,
	@GroupID AS INT=0
AS
BEGIN
	SET @DTFrom=CAST(CONVERT(VARCHAR(50),@DTFrom,6) AS DATETIME)
	SET @DTTo=CAST(CONVERT(VARCHAR(50),@DTTo,6) AS DATETIME)
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	--SET NOCOUNT ON;

    -- Insert statements for procedure here
	SELECT RM.GroupID,RM.RMID1,RMName,OpeningStock+ISNULL(OpeningQtyCalc,0) AS OpeningStock,(OpeningStock+OpeningQtyCalc)*ISNULL(LastRate,Rate) AS OpeningValue,RMGroups.Description,ISNULL(QtyRcvd,0) AS QtyRcvd,ValueRcvd,ISNULL(QtyIssd,0) AS QtyIssd,ValueIssd FROM RM
INNER JOIN RMGroups ON RM.GroupID=RMGroups.ID

LEFT OUTER JOIN(SELECT MaterialID,SUM(QtyRcvd+ExtraQtyRcvd-ISNULL(QtyReturned,0)) AS QtyRcvd,SUM(Rate*(QtyRcvd+ExtraQtyRcvd-ISNULL(QtyReturned,0))) AS ValueRcvd FROM VendRcvdDetailPO INNER JOIN
	VendRcvd ON VendRcvd.RcvID=VendRcvdDetailPO.RcvID WHERE RcvDate BETWEEN @DTFrom AND @DTTo GROUP BY MaterialID) TRcvd
	ON RM.RMID1=TRcvd.MaterialID

LEFT OUTER JOIN(SELECT RM.RMID1,SUM(Qty) AS QtyIssd,SUM(Rate*Qty) AS ValueIssd FROM RawMaterialIssuance INNER JOIN
	RawMaterialIssuanceDetail ON RawMaterialIssuance.IssNo=RawMaterialIssuanceDetail.IssNo INNER JOIN RM ON RM.RMID1=RawMaterialIssuanceDetail.RMID1 WHERE DT BETWEEN @DTFrom AND @DTTo GROUP BY RM.RMID1) TIssd
	ON RM.RMID1=TIssd.RMID1

LEFT OUTER JOIN(
SELECT MaterialID,SUM(Qty) AS OpeningQtyCalc,SUM(Value) AS OpeningValueCalc FROM(
SELECT MaterialID,SUM(QtyRcvd+ExtraQtyRcvd-ISNULL(QtyReturned,0)) AS Qty,SUM(Rate*(QtyRcvd+ExtraQtyRcvd-ISNULL(QtyReturned,0))) AS Value FROM VendRcvdDetailPO INNER JOIN
	VendRcvd ON VendRcvd.RcvID=VendRcvdDetailPO.RcvID WHERE RcvDate<@DTFrom GROUP BY MaterialID
UNION ALL
SELECT RM.RMID1 AS MaterialID,-SUM(Qty) AS Qty,-SUM(Qty*Rate) AS Value FROM RawMaterialIssuanceDetail INNER JOIN
	RawMaterialIssuance ON RawMaterialIssuance.IssNo=RawMaterialIssuanceDetail.IssNo INNER JOIN RM ON RawMaterialIssuanceDetail.RMID1=RM.RMID1 WHERE DT<@DTFrom GROUP BY RM.RMID1) T1
	GROUP BY MaterialID) TOpening ON RM.RMID1=TOpening.MaterialID

LEFT OUTER JOIN(
SELECT MaterialID,Rate AS LastRate FROM VendRcvdDetailPO
	WHERE EntryID IN(SELECT MAX(EntryID) FROM VendRcvdDetailPO INNER JOIN VendRcvd ON VendRcvd.RcvID=VendRcvdDetailPO.RcvID WHERE RcvDate<@DTFrom GROUP BY MaterialID)) TLastRate ON RM.RMID1=TLastRate.MaterialID

WHERE InActive=0 AND (GroupID=@GroupID OR @GroupID=0)
AND (ISNULL(OpeningStock,0)>0 OR ISNULL(QtyRcvd,0)>0 OR ISNULL(QtyIssd,0)>0)
END

GO
