CREATE PROCEDURE [dbo].[TBBase]
(@FromDate datetime,@Code As Varchar(50)=NULL,@Summary As Bit=0)
AS
DECLARE @CodeLength AS INT
IF @Code IS NULL
	SET @CodeLength=0
ELSE
	SET @CodeLength=LEN(@Code)

IF @Summary=1
	SELECT     dbo.Accounts.*, ISNULL(TBase.TheBalance, dbo.Accounts.openbal) AS OpeningBalance,
	CASE WHEN ISNULL(TBase.TheBalance, dbo.Accounts.openbal)>=0 THEN ISNULL(TBase.TheBalance, dbo.Accounts.openbal) ELSE 0 END AS OpeningBalanceDr,
	CASE WHEN ISNULL(TBase.TheBalance, dbo.Accounts.openbal)<0 THEN ABS(ISNULL(TBase.TheBalance, dbo.Accounts.openbal)) ELSE 0 END AS OpeningBalanceCr
	FROM         dbo.Accounts LEFT OUTER JOIN
	(SELECT     Accno, balance  AS TheBalance FROM dbo.Vouchers  WHERE (SNo IN (SELECT MAX(Sno) FROM Vouchers WHERE VDATE<@FromDate GROUP BY Accno))) TBase
	ON dbo.Accounts.AccNo = TBase.Accno
	WHERE ((dbo.Accounts.Parent <> 0) OR (ISNULL(dbo.Accounts.SubAccOf,'')= ''))
	AND (LEFT(Accounts.AccNo,@CodeLength)=@Code OR @Code IS NULL)
ELSE
	SELECT     dbo.Accounts.*, ISNULL(TBase.TheBalance, dbo.Accounts.openbal) AS OpeningBalance,
	CASE WHEN ISNULL(TBase.TheBalance, dbo.Accounts.openbal)>=0 THEN ISNULL(TBase.TheBalance, dbo.Accounts.openbal) ELSE 0 END AS OpeningBalanceDr,
	CASE WHEN ISNULL(TBase.TheBalance, dbo.Accounts.openbal)<0 THEN ABS(ISNULL(TBase.TheBalance, dbo.Accounts.openbal)) ELSE 0 END AS OpeningBalanceCr
	FROM         dbo.Accounts LEFT OUTER JOIN
	(SELECT     Accno, balance  AS TheBalance
	FROM        dbo.Vouchers
	WHERE     (SNo IN (SELECT MAX(Sno) FROM Vouchers WHERE VDATE<@FromDate GROUP BY Accno))) TBase
	ON dbo.Accounts.AccNo = TBase.Accno
	WHERE (LEFT(Accounts.AccNo,@CodeLength)=@Code OR @Code IS NULL)
GO
