CREATE PROCEDURE [dbo].[TBHeadsNewWithCrDr] (@FromDate As DateTime,@Code As Varchar(50)='0',@ToDate As DateTime)
AS

DECLARE @CodeLength AS INT
IF @Code='0'
	SET @CodeLength=0
ELSE
	SET @CodeLength=LEN(@Code)

IF @Code='0'
	SELECT Heads.Code,Heads.Head,dbo.Accounts.Type,SUM(ISNULL(TBase.TheBalance, dbo.Accounts.openbal)) AS OpeningBalance,
	SUM(CASE WHEN ISNULL(TBase.TheBalance, dbo.Accounts.openbal)>=0 THEN ISNULL(TBase.TheBalance, dbo.Accounts.openbal) ELSE 0 END) AS OpeningBalanceDr,
	SUM(CASE WHEN ISNULL(TBase.TheBalance, dbo.Accounts.openbal)<0 THEN ABS(ISNULL(TBase.TheBalance, dbo.Accounts.openbal)) ELSE 0 END) AS OpeningBalanceCr,
	SUM(CASE WHEN ISNULL(TBaseBal.TheBalance, dbo.Accounts.openbal)>=0 THEN ISNULL(TBaseBal.TheBalance, dbo.Accounts.openbal) ELSE 0 END) AS LastBalanceBalanceDr,
	SUM(CASE WHEN ISNULL(TBaseBal.TheBalance, dbo.Accounts.openbal)<0 THEN ABS(ISNULL(TBaseBal.TheBalance, dbo.Accounts.openbal)) ELSE 0 END) AS LastBalanceBalanceCr,
	SUM(Vchr.DebitTotal) As TotalDebit,SUM(Vchr.CreditTotal) As TotalCredit
	FROM         dbo.Accounts INNER JOIN Heads ON Heads.Code=Accounts.Type LEFT OUTER JOIN
	(SELECT     Accno, balance  AS TheBalance
	FROM        dbo.Vouchers
	WHERE     (SNo IN (SELECT MAX(Sno) FROM Vouchers WHERE VDATE<@FromDate GROUP BY Accno))) TBase
	ON dbo.Accounts.AccNo = TBase.Accno LEFT OUTER JOIN
	(SELECT Accno,balance AS TheBalance From dbo.Vouchers
	WHERE (SNo IN (SELECT MAX(Sno) FROM Vouchers WHERE VDATE<=@ToDate GROUP BY Accno)))
	TBaseBal ON dbo.Accounts.AccNo = TBaseBal.Accno
	LEFT OUTER JOIN (Select AccNo,SUM(DEBIT) As DebitTotal,SUM(CREDIT) As CreditTotal From Vouchers Where VDate Between @FromDate AND @ToDate GROUP BY AccNo) VCHR
	ON Accounts.AccNo=VCHR.AccNo
	GROUP BY Accounts.Type,Heads.Code,Heads.Head
Else
	SELECT Heads.Code,Heads.Head,dbo.Accounts.Type,SUM(ISNULL(TBase.TheBalance, dbo.Accounts.openbal)) AS OpeningBalance,
	SUM(CASE WHEN ISNULL(TBase.TheBalance, dbo.Accounts.openbal)>=0 THEN ISNULL(TBase.TheBalance, dbo.Accounts.openbal) ELSE 0 END) AS OpeningBalanceDr,
	SUM(CASE WHEN ISNULL(TBase.TheBalance, dbo.Accounts.openbal)<0 THEN ABS(ISNULL(TBase.TheBalance, dbo.Accounts.openbal)) ELSE 0 END) AS OpeningBalanceCr,
	SUM(CASE WHEN ISNULL(TBaseBal.TheBalance, dbo.Accounts.openbal)>=0 THEN ISNULL(TBaseBal.TheBalance, dbo.Accounts.openbal) ELSE 0 END) AS LastBalanceBalanceDr,
	SUM(CASE WHEN ISNULL(TBaseBal.TheBalance, dbo.Accounts.openbal)<0 THEN ABS(ISNULL(TBaseBal.TheBalance, dbo.Accounts.openbal)) ELSE 0 END) AS LastBalanceBalanceCr,
	SUM(Vchr.DebitTotal) As TotalDebit,SUM(Vchr.CreditTotal) As TotalCredit
	FROM         dbo.Accounts INNER JOIN Heads ON Heads.Code=Accounts.Type LEFT OUTER JOIN
	(SELECT     Accno, balance  AS TheBalance
	FROM        dbo.Vouchers
	WHERE     (SNo IN (SELECT MAX(Sno) FROM Vouchers WHERE VDATE<@FromDate GROUP BY Accno))) TBase
	ON dbo.Accounts.AccNo = TBase.Accno LEFT OUTER JOIN
	(SELECT Accno,balance AS TheBalance From dbo.Vouchers
	WHERE (SNo IN (SELECT MAX(Sno) FROM Vouchers WHERE VDATE<=@ToDate GROUP BY Accno)))
	TBaseBal ON dbo.Accounts.AccNo = TBaseBal.Accno
	LEFT OUTER JOIN (Select AccNo,SUM(DEBIT) As DebitTotal,SUM(CREDIT) As CreditTotal From Vouchers Where VDate Between @FromDate AND @ToDate GROUP BY AccNo) VCHR
	ON Accounts.AccNo=VCHR.AccNo
	WHERE LEFT(Accounts.AccNo,@CodeLength)=@Code
	GROUP BY Accounts.Type,Heads.Code,Heads.Head
GO
