SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE PROCEDURE [dbo].[TrafficDashBoard_SP] (@DTFrom AS DATETIME,@DTTo AS DATETIME,@CustCode AS VARCHAR(4000)='',@Country AS VARCHAR(50)='',@OrderNo AS VARCHAR(50)='',@GroupID AS INT=0,@NoDelivery AS BIT=0,@Both AS BIT=0,@Urgent AS BIT=0,@R1R2 AS TINYINT=0) AS

BEGIN
SET ANSI_WARNINGS OFF

		DECLARE @PackingProcessID AS INT
		SET @PackingProcessID=CAST(dbo.GetGeneralDataValue_F('PackingProcessID') AS INT)

		DECLARE @myQuery AS VARCHAR(4000)

		CREATE TABLE #Customers(CustCode VARCHAR(50))

		IF @CustCode=''
			SET @myQuery='INSERT INTO #Customers(CustCode) SELECT CustCode FROM ForeignCustomers'
		ELSE
			SET @myQuery='INSERT INTO #Customers(CustCode) SELECT CustCode FROM ForeignCustomers WHERE CustCode IN(' + @CustCode +')'

		EXEC(@myQuery)

		CREATE TABLE #myTBL(CustCode VARCHAR(50),Country VARCHAR(50),ID INT,GroupID INT,DeliveryDT DATETIME,DeliveryStatus TINYINT,Remarks VARCHAR(255),CompItemCode VARCHAR(255),OrderNo VARCHAR(255),Qty INT)
		CREATE TABLE #RunningLots(ItemCode VARCHAR(50),LotNo VARCHAR(50),OrderNo VARCHAR(50),Qty INT,ProcessID INT,VendID INT,DT DATETIME)
		CREATE TABLE #OpenPOs(OrderNo VARCHAR(50),ItemCode VARCHAR(50),ReturnDT DATETIME)

		CREATE TABLE #myReturnTBL(CompItemCode VARCHAR(255),OrderNo VARCHAR(255),Qty INT,Color VARCHAR(10),Criteria VARCHAR(3))
		CREATE TABLE #RedItems(OrderNo VARCHAR(50),CompItemCode VARCHAR(50))
		CREATE TABLE #YellowItems(OrderNo VARCHAR(50),CompItemCode VARCHAR(50))

		INSERT INTO #myTBL SELECT CustCode,Country,ID,GroupID,DeliveryDT,DeliveryStatus,Remarks,CompItemCode,OrderNo,(Qty-ShippedQty) AS Qty FROM VFOrderItems
			WHERE (Qty>ShippedQty) AND OrderNo IN (SELECT OrderNo FROM VUnshippedOrderList) --AND CustCode NOT IN('Stock')

		IF @OrderNo<>''
			DELETE FROM #myTBL WHERE OrderNo<>@OrderNo
		ELSE
			BEGIN

			DELETE FROM #myTBL WHERE CustCode NOT IN(SELECT CustCode FROM #Customers)

			IF @Country<>''
				DELETE FROM #myTBL WHERE Country<>@Country

			IF @GroupID<>0
				DELETE FROM #myTBL WHERE GroupID<>@GroupID

			IF @Urgent=1
				DELETE FROM #myTBL WHERE NOT (DeliveryStatus=2 OR Remarks<>'')
			ELSE
				BEGIN
					IF @Both=1
						DELETE FROM #myTBL WHERE NOT (DeliveryStatus=0 OR (DeliveryDT BETWEEN @DTFrom AND @DTTo))
					ELSE
						BEGIN
							--Since We have blocked No-Delivery Check box on Traffic Dashboard Form, this Parameter is not
							--longer valid, So We'll have to adjust Items of No Delivery Date in Else part...
							IF @NoDelivery=1
								DELETE FROM #myTBL WHERE DeliveryStatus<>0
							ELSE
								DELETE FROM #myTBL WHERE NOT (DeliveryDT BETWEEN @DTFrom AND @DTTo OR DeliveryStatus=0)
						END
				END
			END
		---------------------------------------------------------------
		INSERT INTO #myReturnTBL(CompItemCode,OrderNo,Qty) SELECT CompItemCode,OrderNo,SUM(Qty) FROM #myTBL GROUP BY CompItemCode,OrderNo
		----------------------------------------------------------------
		DELETE FROM #RunningLots
		IF @R1R2=0
			INSERT INTO #RunningLots SELECT T1.ItemCode,T1.LotNo,T1.OrderNo,T1.Qty,T1.ProcessID,T1.VendID,T1.DT FROM
				VRunningLots_Simple T1 INNER JOIN #myReturnTBL T2 ON T1.OrderNo=T2.OrderNo AND T1.ItemCode=T2.CompItemCode
		ELSE IF @R1R2=1
			INSERT INTO #RunningLots SELECT T1.ItemCode,T1.LotNo,T1.OrderNo,T1.Qty,T1.ProcessID,T1.VendID,T1.DT FROM
				VRunningLots_Simple T1 INNER JOIN #myReturnTBL T2 ON T1.OrderNo=T2.OrderNo AND T1.ItemCode=T2.CompItemCode WHERE (SNO<=PolishingItemSNo)
		ELSE IF @R1R2=2
			INSERT INTO #RunningLots SELECT T1.ItemCode,T1.LotNo,T1.OrderNo,T1.Qty,T1.ProcessID,T1.VendID,T1.DT FROM
				VRunningLots_Simple T1 INNER JOIN #myReturnTBL T2 ON T1.OrderNo=T2.OrderNo AND T1.ItemCode=T2.CompItemCode WHERE (SNO>PolishingItemSNo)

		INSERT INTO #OpenPOs SELECT T1.OrderNo,T1.ItemCode,T1.ReturnDT FROM VItemOpenPOs T1 INNER JOIN #myReturnTBL T2 ON T1.OrderNo=T2.OrderNo AND T1.ItemCode=T2.CompItemCode
		----------------------------------------------------------------
		--------RED CRITERIA--------------
		----------------------------------------------------------------
		--Sub.Criteria # 1 .. Running Lots & Open POs < Customer Order Qty...
		UPDATE #myReturnTBL SET Color='Red',Criteria='1-1' FROM #myReturnTBL myTBL
			LEFT OUTER JOIN(SELECT OrderNo,ItemCode,SUM(Qty) AS Qty FROM #RunningLots GROUP BY OrderNo,ItemCode) T1 ON myTBL.OrderNo=T1.OrderNo AND myTBL.CompItemCode=T1.ItemCode
			LEFT OUTER JOIN(SELECT OrderNo,ItemCode,SUM(Qty) AS Qty FROM VItemOpenPOs GROUP BY OrderNo,ItemCode) T2 ON myTBL.OrderNo=T2.OrderNo AND myTBL.CompItemCode=T2.ItemCode
			WHERE myTBL.Qty>(ISNULL(T1.Qty,0)+ISNULL(T2.Qty,0))

		--Sub.Criteria # 2 .. Maker PO is Delayed by 2 or More Days...
		UPDATE #myReturnTBL SET Color='White',Criteria='1-2' FROM #myReturnTBL myTBL
			INNER JOIN (SELECT OrderNo,ItemCode FROM #OpenPOs WHERE DATEADD(day,2,ReturnDT)<GETDATE() ) T2 ON myTBL.OrderNo=T2.OrderNo AND myTBL.CompItemCode=T2.ItemCode

		--Sub.Criteria # 3 .. Lot is Struck for 5 or More Days
		UPDATE #myReturnTBL SET Color='Red',Criteria='1-3' FROM #myReturnTBL myTBL
			INNER JOIN (SELECT OrderNo,ItemCode FROM #RunningLots WHERE DATEADD(day,5,DT)<GETDATE() ) T2 ON myTBL.OrderNo=T2.OrderNo AND myTBL.CompItemCode=T2.ItemCode

		----------------------------------------------------------------
		--------YELLOW CRITERIA--------------
		----------------------------------------------------------------
		--Sub.Criteria # 1 .. Lot is Struck for 2-4 or More Days
		UPDATE #myReturnTBL SET Color='Yellow',Criteria='2-1' FROM #myReturnTBL myTBL
			INNER JOIN (SELECT OrderNo,ItemCode FROM #RunningLots WHERE DATEDIFF(day,DT,GetDate()) BETWEEN 2 AND 4) T2 ON myTBL.OrderNo=T2.OrderNo AND myTBL.CompItemCode=T2.ItemCode

		--Sub.Criteria # 2 .. Repair Not Issued....
		UPDATE #myReturnTBL SET Color='Yellow',Criteria='2-2' FROM #myReturnTBL myTBL
			INNER JOIN (SELECT OrderNo,ItemCode FROM VVendRcvdDetailReWorkDetail WHERE Qty>IssQty) T1 ON myTBL.OrderNo=T1.OrderNo AND myTBL.CompItemCode=T1.ItemCode

		--Sub.Criteria # 3 .. Maker PO's Delivery Date is Yet to Come
		UPDATE #myReturnTBL SET Color='White',Criteria='2-3' FROM #myReturnTBL myTBL
			INNER JOIN (SELECT OrderNo,ItemCode FROM #OpenPOs WHERE ReturnDT>GETDATE()) T2 ON myTBL.OrderNo=T2.OrderNo AND myTBL.CompItemCode=T2.ItemCode
		----------------------------------------------------------------

		--------GREEN CRITERIA-------------- All of the Rest
		UPDATE #myReturnTBL SET Color='Green',Criteria='3' WHERE Color IS NULL



		--Apply R-1,R-2 Filters...
		IF @R1R2=1			--R1 Only
			BEGIN
				DELETE FROM #myReturnTBL WHERE Criteria NOT IN('1-1','1-2','2-3','1-3','2-1','2-2')
			END
		ELSE IF @R1R2=2		--R2 Only
			BEGIN
				DELETE FROM #myReturnTBL WHERE Criteria NOT IN('1-3','2-1','2-2')
			END

		SELECT FCustomerOrders.CustCode,FCustomerOrders.Country,myTBL.OrderNo,myTBL.CompItemCode,myTBL.Qty,myTBL.Color,Items.ItemName,ItemGroups.Description,Criteria,InternalRefNo FROM #myReturnTBL myTBL
			INNER JOIN FCustomerOrders ON myTBL.OrderNo=FCustomerOrders.OrderNo
			INNER JOIN Items ON myTBL.CompItemCode=Items.ItemID
			INNER JOIN ItemGroups ON Items.GroupID=ItemGroups.ID

SET ANSI_WARNINGS ON
END

GO
