CREATE PROCEDURE [dbo].[UpdateItemProcessesFromProcessGroups_SP] (@PG_RefID INT)
AS
BEGIN

	DELETE FROM ItemProcesses WHERE ItemID IN(SELECT ItemID FROM ItemProcessGroups WHERE PG_RefID=@PG_RefID)
	INSERT INTO ItemProcesses(ProcessID,ItemID,Rate,SNo,Scanning) SELECT Process_RefID,ItemID,0,SeqNo,Scanning FROM ItemProcessGroups
		INNER JOIN ProcessGroupsProcesses ON ItemProcessGroups.PG_RefID=ProcessGroupsProcesses.Group_RefID WHERE PG_RefID=@PG_RefID
		ORDER BY SeqNo
END
