CREATE PROCEDURE [dbo].[UpdateMaterialLocation](@MaterialID VARCHAR(50),@LocationID INT,@Qty REAL,@Access AS BIT=0,@NewLocationID AS INT=0,@UserName AS VARCHAR(50)='',@MachineName AS VARCHAR(50)='',@Sheets AS INT,@PORefNo AS VARCHAR(50)='',@DetailEntryID AS INT,@BatchNo VARCHAR(50)='',@LotNo VARCHAR(50)='') AS

DECLARE @TempQty AS REAL,@TempTot AS REAL
DECLARE @EntryID AS INT,@CurrQty AS REAL
DECLARE @Rcvd_RefID AS INT,@RefID AS INT
DECLARE @Cursor_UpdateLocation CURSOR
--IF @PORefNo=''
IF @BatchNo='' AND @LotNo=''
	SET @Cursor_UpdateLocation=CURSOR FOR
		SELECT EntryID,QtyPlaced-QtyIssued,Rcvd_RefID From VMaterialLocationwiseStatus
		WHERE QtyPlaced-QtyIssued>0 AND MaterialID=@MaterialID AND Shelf_RefID=@LocationID
ELSE
	SET @Cursor_UpdateLocation=CURSOR FOR
		SELECT EntryID,QtyPlaced-QtyIssued,Rcvd_RefID FROM VMaterialLocationANDPOWiseStatus
		WHERE QtyPlaced-QtyIssued>0 AND MaterialID=@MaterialID AND Shelf_RefID=@LocationID AND ISNULL(BatchNo,'')=@BatchNo AND ISNULL(LotNo,'')=@LotNo

OPEN @Cursor_UpdateLocation
FETCH NEXT FROM @Cursor_UpdateLocation INTO @EntryID,@CurrQty,@Rcvd_RefID

SET @TempTot=0
SET @TempQty=0
WHILE @@FETCH_STATUS = 0
	BEGIN
		IF (@CurrQty>@Qty-@TempTot)   --For Remaining
			SET @TempQty=@Qty-@TempTot
		ELSE
			SET @TempQty=@CurrQty


		UPDATE MaterialLocationwiseStatus SET QtyIssued=QtyIssued+@TempQty WHERE EntryID=@EntryID
		IF @DetailEntryID>0
			INSERT INTO RMID_MLS_Details(RMID_RefID,MLS_RefID,Qty) VALUES(@DetailEntryID,@EntryID,@TempQty)
		IF @Access=1
			BEGIN
				INSERT INTO MaterialLocationwiseStatus(Rcvd_RefID,Shelf_RefID,QtyPlaced,UserName,MachineName) VALUES(@Rcvd_RefID,@NewLocationID,@TempQty,@UserName,@MachineName)
				SET @RefID=(SELECT MAX(EntryID) FROM MaterialLocationwiseStatus WHERE MachineName=@MachineName)
				INSERT INTO MaterialMovements(MLS_From_RefID,MLS_To_RefID,UserName,MachineName) VALUES(@EntryID,@RefID,@UserName,@MachineName)
			END
		SET @TempTot=@TempTot+@TempQty
		FETCH NEXT FROM @Cursor_UpdateLocation INTO @EntryID,@CurrQty,@Rcvd_RefID
	END

CLOSE @Cursor_UpdateLocation
DEALLOCATE @Cursor_UpdateLocation

IF @Sheets>0
	BEGIN
		DECLARE @Cursor_UpdateLocationSheets CURSOR
		IF @PORefNo=''
			SET @Cursor_UpdateLocationSheets=CURSOR FOR
				SELECT EntryID,SheetsPlaced-ISNULL(SheetsIssued,0),Rcvd_RefID From VMaterialLocationwiseStatus
				WHERE SheetsPlaced-ISNULL(SheetsIssued,0)>0 AND MaterialID=@MaterialID AND Shelf_RefID=@LocationID
		ELSE
			SET @Cursor_UpdateLocationSheets=CURSOR FOR
				SELECT EntryID,SheetsPlaced-ISNULL(SheetsIssued,0),Rcvd_RefID From VMaterialLocationANDPOWiseStatus
				WHERE SheetsPlaced-ISNULL(SheetsIssued,0)>0 AND MaterialID=@MaterialID AND Shelf_RefID=@LocationID AND PORefNo=@PORefNo

		OPEN @Cursor_UpdateLocationSheets
		FETCH NEXT FROM @Cursor_UpdateLocationSheets INTO @EntryID,@CurrQty,@Rcvd_RefID

		SET @TempTot=0
		SET @TempQty=0
		WHILE @@FETCH_STATUS = 0
			BEGIN
				IF (@CurrQty>@Sheets-@TempTot)   --For Remaining
					SET @TempQty=@Sheets-@TempTot
				ELSE
					SET @TempQty=@CurrQty


				UPDATE MaterialLocationwiseStatus SET SheetsIssued=ISNULL(SheetsIssued,0)+@TempQty WHERE EntryID=@EntryID
				IF @DetailEntryID>0
					INSERT INTO RMID_MLS_Sheets_Details(RMID_RefID,MLS_RefID,Sheets) VALUES(@DetailEntryID,@EntryID,@TempQty)
				IF @Access=1
					BEGIN
						INSERT INTO MaterialLocationwiseStatus(Rcvd_RefID,Shelf_RefID,SheetsPlaced,UserName,MachineName) VALUES(@Rcvd_RefID,@NewLocationID,@TempQty,@UserName,@MachineName)
						SET @RefID=(SELECT MAX(EntryID) FROM MaterialLocationwiseStatus WHERE MachineName=@MachineName)
						INSERT INTO MaterialMovements(MLS_From_RefID,MLS_To_RefID,UserName,MachineName) VALUES(@EntryID,@RefID,@UserName,@MachineName)
					END
				SET @TempTot=@TempTot+@TempQty
				FETCH NEXT FROM @Cursor_UpdateLocationSheets INTO @EntryID,@CurrQty,@Rcvd_RefID
			END

		CLOSE @Cursor_UpdateLocationSheets
		DEALLOCATE @Cursor_UpdateLocationSheets
	END
GO
/****** Object:  StoredProcedure [dbo].[UpdateMaterialLocation_Deletion_SP]    Script Date: 6/29/2026 4:50:02 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[UpdateMaterialLocation_Deletion_SP](@IssNo AS VARCHAR(255)) AS

--Update MaterialLocationWiseStatus Qty...
UPDATE MaterialLocationWiseStatus SET MaterialLocationWiseStatus.QtyIssued=MaterialLocationWiseStatus.QtyIssued-RMID_MLS_Details.Qty
	FROM MaterialLocationWiseStatus INNER JOIN RMID_MLS_Details ON MaterialLocationWiseStatus.EntryID=RMID_MLS_Details.MLS_RefID
	INNER JOIN RawMaterialIssuanceDetail ON RMID_MLS_Details.RMID_RefID=RawMaterialIssuanceDetail.EntryID
	WHERE RawMaterialIssuanceDetail.IssNo=@IssNo


--Update MaterialLocationWiseStatus Sheets...
UPDATE MaterialLocationWiseStatus SET MaterialLocationWiseStatus.SheetsIssued=MaterialLocationWiseStatus.SheetsIssued-RMID_MLS_Sheets_Details.Sheets
	FROM MaterialLocationWiseStatus INNER JOIN RMID_MLS_Sheets_Details ON MaterialLocationWiseStatus.EntryID=RMID_MLS_Sheets_Details.MLS_RefID
	INNER JOIN RawMaterialIssuanceDetail ON RMID_MLS_Sheets_Details.RMID_RefID=RawMaterialIssuanceDetail.EntryID
	WHERE RawMaterialIssuanceDetail.IssNo=@IssNo


UPDATE RM SET QtyInStock=QtyInStock-Qty FROM RM INNER JOIN RawMaterialIssuanceDetail ON RM.RMID1=RawMaterialIssuanceDetail.RMID1
	WHERE RawMaterialIssuanceDetail.IssNo=@IssNo


DELETE FROM RMID_MLS_Details WHERE RMID_RefID IN(SELECT EntryID FROM RawMaterialIssuanceDetail WHERE IssNo=@IssNo)
DELETE FROM RMID_MLS_Sheets_Details WHERE RMID_RefID IN(SELECT EntryID FROM RawMaterialIssuanceDetail WHERE IssNo=@IssNo)

DELETE FROM RawMaterialIssuanceDetail WHERE IssNo=@IssNo
DELETE FROM RawMaterialIssuance WHERE IssNo=@IssNo
GO
/****** Object:  StoredProcedure [dbo].[User_Activity_Report_SP]    Script Date: 6/29/2026 4:50:02 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[User_Activity_Report_SP] (@UserName VARCHAR(50),@DTFrom DATETIME,@DTTO DATETIME)

AS
BEGIN

	SET @DTFrom=CAST(CONVERT(VARCHAR(50),@DTFrom,6) AS DATETIME)
	SET @DTTo=CAST(CONVERT(VARCHAR(50),@DTTo,6) AS DATETIME)
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	SELECT T1.UserName,T1.DT,T1.ItemCode,T1.Qty,T1.ProcessID,T1.EntryType,Items.ItemName,
		   Processes.Description AS Process_Description,DTEntry,MachineName
	 FROM (
		SELECT VI.UserName,VI.DT,VID.ItemCode,VID.IssQty AS Qty,VI.ProcessID,
		CASE WHEN MasterPONo IS NULL THEN 'Process Issuance' ELSE 'Purcahse Order' END AS EntryType ,
		VI.DTEntry,VI.MachineName
		FROM VendIssued VI
		INNER JOIN VendIssdDetail VID ON VI.EntryID=VID.RefID
		INNER JOIN Makers ON VI.VendID=Makers.VendID
		WHERE VI.DT BETWEEN @DTFrom AND @DTTo
		AND VI.UserName=@UserName

	UNION ALL


	SELECT VR.UserName,VR.DT,VRD.ItemCode,VRD.RcvdQty,VRD.ProcessID,CASE WHEN VI.MasterPONo IS NULL THEN 'Process Receiving' ELSE 'Receiving' END AS EntryType,
		 VR.EntryDT,VR.MachineName
	FROM VendReceived VR
		INNER JOIN VendRcvdDetail VRD ON VR.EntryID=VRD.RefID
		INNER JOIN VendIssued VI ON VR.Issuance_RefID=VI.EntryID
		WHERE VR.DT BETWEEN @DTFrom AND @DTTo
		AND VR.UserName=@UserName
		) T1

		INNER JOIN Items ON T1.ItemCode=Items.ItemID
		INNER JOIN Processes ON T1.ProcessID=Processes.ProcessID

END


SELECT * FROM VendIssued
GO
