CREATE PROCEDURE [dbo].[UserSettings_SP](@UserID int,@ModuleName varchar(255)) AS

SELECT     dbo.MenuOptions.*, ISNULL(UserPermissions.UserID, 0) AS UserID
FROM         dbo.MenuOptions LEFT OUTER JOIN
                      (Select * from dbo.UserMenuOptions Where UserID=@UserID)  UserPermissions ON dbo.MenuOptions.OptionID = UserPermissions.OptionID
Where ModuleName=@ModuleName and (UserPermissions.UserID=@UserID or UserPermissions.UserID is null)
