CREATE PROCEDURE [dbo].[VAdvanceSalaryDeptWise]( @ParDate Datetime,@DeptID varchar(255)) AS
(
SELECT VAbsentDays.AbsentDays, VLateHours.Hours, VOverTime.OverTimeHours,VOverTime.SAOverTimeHours,VSalariedEmps.*,
 VPresentDays.PresentDays, VPayed.Payed, VLongDeduct.DedAmt, VLongDeduct.TotAmt,
VLongDeduct.ClsAmt,0 as AdvSalPaid, VLeaves.Leaves, ApprovedLeaves,VFine.TotalFine, VBonus.TotalBonus,VLongDeduct.CurrentLong,
CasualLeaves, SickLeaves, CompensatoryLeaves, AnnualLeaves, WPLeaves, MaternityLeaves,FOTByQty.OTQtyWorked,VScholorships.ScholorshipAmt
--,IsNull(LunchAmt,0) as LunchAmt
,0 AS LunchAmt
,HrsWorked,isnull(LeaveHours,0) as ShortLeaveHrs,SundayOTHrs,SPAbsentDays,DeductionSpecialAbsents,HoldAmt
,AmtToDeduct,LateComingHrs,AmtPaid,GPHrs,DinnerCount,ExtraHrsToDeduct,HalfLeaves,VLeaves.HL,LateComingHrs_Adjusted
,VOverTIme.OTHrs_Actual,LateComingHrs_Actual
,VOverTime.Food_Allowance
FROM VSalariedEmps
LEFT JOIN FAbsentDays(@ParDATE) as VAbsentDays ON VSalariedEmps.empid = VAbsentDays.EmpID
LEFT JOIN FLateHours(@pardate) as VLateHours ON VSalariedEmps.empid = VLateHours.EmpID
LEFT JOIN FOverTime(@pardate) as VOverTime ON VSalariedEmps.empid = VOverTime.EmpID
LEFT JOIN FPresentDays(@pardate) as VPresentDays ON VSalariedEmps.empid = VPresentDays.EmpID
LEFT JOIN FPayed(@parDate) as VPayed ON VSalariedEmps.empid = VPayed.EmpID
LEFT JOIN FLongDeduct(@ParDate) as VLongDeduct ON VSalariedEmps.empid = VLongDeduct.EmpID
LEFT JOIN FLeaves(@ParDate) as VLeaves ON VSalariedEmps.empid = VLeaves.EmpID
LEFT JOIN FFine(@ParDate) as VFine ON VSalariedEmps.empid = VFine.EmpID
LEFT JOIN FBonus(@ParDate) as VBonus ON VSalariedEmps.empid = VBonus.EmpID
LEFT JOIN FScholorships(@ParDate) as VScholorships ON VSalariedEmps.empid = VScholorships.EmpID
LEFT JOIN FOverTimeByQty(@ParDate) as FOTByQty ON VSalariedEmps.empid = FOTByQty.EmpID
LEFT JOIN FEmpLunchAmt(@ParDate) as VEmpLunchAmt ON VSalariedEmps.empid = VEmpLunchAmt.EmpID
LEFT JOIN FHrsWorked(@ParDate) as VHrsWorked ON VSalariedEmps.empid = VHrsWorked.EmpID
LEFT JOIN FShortLeavesAmt(@ParDate) as VShortLeavesAmt ON VSalariedEmps.empid = VShortLeavesAmt.EmpID
LEFT JOIN FSundayOTHrs(@ParDate) as VSundayOTHrs ON VSalariedEmps.empid = VSundayOTHrs.EmpID
LEFT JOIN FExtraDeduction(@ParDate) AS FExtraDeduction ON VSalariedEmps.empid = FExtraDeduction.EmpID
LEFT JOIN FHoldedSalaries(@ParDate) AS VHoldedSalaries ON VSalariedEmps.empid = VHoldedSalaries.EmpID
LEFT JOIN FLateComingHrs(@ParDate) AS VLateComingHrs ON VSalariedEmps.EmpID=VLateComingHrs.EmpID
LEFT JOIN (SELECT EmpID,AmtToDeduct FROM LongTermDeductionsMonthly WHERE MONTH(DedMonth)=MONTH(@ParDate) AND YEAR(DedMonth)=YEAR(@ParDate)) Tab1 ON VSalariedEmps.EmpID=Tab1.EmpID
LEFT JOIN (SELECT EmpID,AmtPaid FROM SalaryAlreadyPaid WHERE MONTH(ForMonth)=MONTH(@ParDate) AND YEAR(ForMonth)=YEAR(@ParDate)) Tab2 ON VSalariedEmps.EmpID=Tab2.EmpID
LEFT JOIN GPHrs_F(@ParDate) AS VGPHrs ON VSalariedEmps.EmpID=VGPHrs.EmpID
LEFT JOIN FOverTimeDinnerCount(@ParDate) AS VOTDinnerCount ON VSalariedEmps.EmpID=VOTDinnerCount.EmpID
LEFT JOIN SpecialHoursDeduction_Fn(@ParDate) AS VSpecialHourDeduction ON VSalariedEmps.EmpID=VSpecialHourDeduction.EmpID
WHERE (VSalariedEmps.JoinDate<=@Pardate AND VHrsWorked.HrsWorked>0 OR (VSalariedEmps.Pay_Full_Salary=1 AND VSalariedEmps.Active=1) ) AND (VSalariedEmps.DeptID=@DeptID)
AND (VSalariedEmps.EmpID Not In(Select EmpID From EmpSettlements Where Month(DT)=Month(@ParDate)  AND Year(DT)=Year(@ParDate))))
--OR (VSalariedEmps.DeptID='VDRS'))
GO
