CREATE PROCEDURE [dbo].[VEmpAttendance] (@ParMonth numeric) as
SELECT     att.EmpID,Day(att.Dt) as AttDay,
case (select sub1.Attendance from AttendanceSheet Sub1 Where sub1.Dt=Att.dt and Shift like '%First%' and sub1.EmpID=Att.empid)
When 1 then 'P'
when 0 then 'A'
else null end
as FirstAtt,
case (select sub2.Attendance from AttendanceSheet sub2 Where sub2.Dt=Att.dt and Shift like '%Second%' and sub2.EmpID=Att.empid)
When 1 then 'P'
when 0 then 'A'
else null end
as SecondAtt
FROM         AttendanceSheet Att
WHERE     month(dt) = @ParMonth

GO
