CREATE PROCEDURE [dbo].[VExternalSalary] (@ParDate Datetime,@EmpID as varchar(255),@AdvSalary as bit)
as
SELECT VMonthlySalaries.*, VAdvSalary.AdvSalPaid
FROM(VMonthlySalaries LEFT JOIN FAdvSal(@ParDate) AS VAdvSalary ON VMonthlySalaries.EmpID=VAdvSalary.EmpID)
WHERE (month(dt) = Month(@ParDate) AND year(DT) = Year(@ParDate) AND DT <=@ParDATE )
	 and VMonthlySalaries.EmpID like @EmpID+ '%' and AdvSalary=@advsalary AND Social=1  ORDER BY VMonthlySalaries.EmpID;

