CREATE PROCEDURE [dbo].[VLHours](@ParLTime numeric,
@ParDate datetime,@ParNTime numeric) AS
SELECT empid, case
	when (Select Sum(LateHours) from AttendanceSheet as sub1 Where sub1.EmpID=sub.EmpID  and LateHours<=@ParLTime and (month(dt) = Month(@ParDate) AND year(DT) = Year(@ParDate) AND DT <=@ParDATE ) )
	  <=@ParNTime then (Select Sum(LateHours) from AttendanceSheet as sub2 Where sub2.EmpID=sub.EmpID and LateHours>@ParLTime and (month(dt) = Month(@ParDate) AND year(DT) = Year(@ParDate) AND DT <=@ParDATE ) )
	else	(Select Sum(LateHours) from AttendanceSheet  as sub3 Where  sub3.EmpID=sub.EmpID and (month(dt) = Month(@ParDate) AND year(DT) = Year(@ParDate) AND DT <=@ParDATE )  )
	end
AS LHrs
FROM AttendanceSheet AS sub
GROUP BY empid

GO
