CREATE PROCEDURE [dbo].[VTakeAtt]
@AttDate dateTime ,
@TheShift Varchar(10)
as
SELECT Employees.empid, Employees.deptid, Employees.name, Employees.fname, Employees.dob, Employees.Religion, Employees.age, Employees.sex, Employees.address, Employees.JoinDate, Employees.retirement, Employees.Active, Att.DT, Att.Shift, Att.Attendance, Att.LateHours
FROM Employees LEFT JOIN (SELECT *
