CREATE PROCEDURE [dbo].[YearlyOrderDemandReport_ItemWise_MulitpleYears_SP] (@DTFrom AS DATETIME,@DTTo AS DATETIME,@YearlyReport AS BIT=0,@X2Only AS BIT=0,@ItemGroups AS VARCHAR(4000)='',@AdditionalGroups AS VARCHAR(4000)='') AS

/*DECLARE @DTFrom AS DATETIME
DECLARE @DTTo AS DATETIME

IF @YearlyReport=0
	BEGIN
		SET @DTFrom='1/1/' + CAST(YEAR(@DTFrom) AS VARCHAR(4))
		SET @DTTo='12/31/' + CAST(YEAR(@DTFrom) AS VARCHAR(4))
	END
ELSE
	BEGIN
		SET @DTFrom='1/1/' + CAST(YEAR(@DTFrom) AS VARCHAR(4))
		SET @DTTo='12/31/' + CAST(YEAR(@DTFrom)+11 AS VARCHAR(4))
	END
*/

DECLARE @DTFrom1 AS DATETIME,@DTTo1 AS DATETIME
DECLARE @DTFrom2 AS DATETIME,@DTTo2 AS DATETIME
DECLARE @DTFrom3 AS DATETIME,@DTTo3 AS DATETIME
DECLARE @DTFrom4 AS DATETIME,@DTTo4 AS DATETIME
DECLARE @DTFrom5 AS DATETIME,@DTTo5 AS DATETIME
DECLARE @DTFrom6 AS DATETIME,@DTTo6 AS DATETIME
DECLARE @DTFrom7 AS DATETIME,@DTTo7 AS DATETIME
DECLARE @DTFrom8 AS DATETIME,@DTTo8 AS DATETIME
DECLARE @DTFrom9 AS DATETIME,@DTTo9 AS DATETIME
DECLARE @DTFrom10 AS DATETIME,@DTTo10 AS DATETIME
DECLARE @DTFrom11 AS DATETIME,@DTTo11 AS DATETIME
DECLARE @DTFrom12 AS DATETIME,@DTTo12 AS DATETIME

/*IF @YearlyReport=0
	BEGIN
		SET @DTFrom1=@DTFrom;SET @DTFrom2=DateAdd(m,1,@DTFrom);SET @DTFrom3=DateAdd(m,2,@DTFrom);SET @DTFrom4=DateAdd(m,3,@DTFrom)
		SET @DTFrom5=DateAdd(m,4,@DTFrom);SET @DTFrom6=DateAdd(m,5,@DTFrom);SET @DTFrom7=DateAdd(m,6,@DTFrom);SET @DTFrom8=DateAdd(m,7,@DTFrom)
		SET @DTFrom9=DateAdd(m,8,@DTFrom);SET @DTFrom10=DateAdd(m,9,@DTFrom);SET @DTFrom11=DateAdd(m,10,@DTFrom);SET @DTFrom12=DateAdd(m,11,@DTFrom)

		SET @DTTo1=DateAdd(d,-1,DateAdd(m,1,@DTFrom1));SET @DTTo2=DateAdd(d,-1,DateAdd(m,1,@DTFrom2));SET @DTTo3=DateAdd(d,-1,DateAdd(m,1,@DTFrom3))
		SET @DTTo4=DateAdd(d,-1,DateAdd(m,1,@DTFrom4));SET @DTTo5=DateAdd(d,-1,DateAdd(m,1,@DTFrom5));SET @DTTo6=DateAdd(d,-1,DateAdd(m,1,@DTFrom6))
		SET @DTTo7=DateAdd(d,-1,DateAdd(m,1,@DTFrom7));SET @DTTo8=DateAdd(d,-1,DateAdd(m,1,@DTFrom8));SET @DTTo9=DateAdd(d,-1,DateAdd(m,1,@DTFrom9))
		SET @DTTo10=DateAdd(d,-1,DateAdd(m,1,@DTFrom10));SET @DTTo11=DateAdd(d,-1,DateAdd(m,1,@DTFrom11));SET @DTTo12=DateAdd(d,-1,DateAdd(m,1,@DTFrom12))
	END
ELSE
	BEGIN
		SET @DTFrom1=@DTFrom;SET @DTFrom2=DateAdd(yyyy,1,@DTFrom);SET @DTFrom3=DateAdd(yyyy,2,@DTFrom);SET @DTFrom4=DateAdd(yyyy,3,@DTFrom)
		SET @DTFrom5=DateAdd(yyyy,4,@DTFrom);SET @DTFrom6=DateAdd(yyyy,5,@DTFrom);SET @DTFrom7=DateAdd(yyyy,6,@DTFrom);SET @DTFrom8=DateAdd(yyyy,7,@DTFrom)
		SET @DTFrom9=DateAdd(yyyy,8,@DTFrom);SET @DTFrom10=DateAdd(yyyy,9,@DTFrom);SET @DTFrom11=DateAdd(yyyy,10,@DTFrom);SET @DTFrom12=DateAdd(yyyy,11,@DTFrom)

		SET @DTTo1=DateAdd(d,-1,DateAdd(yyyy,1,@DTFrom1));SET @DTTo2=DateAdd(d,-1,DateAdd(yyyy,1,@DTFrom2));SET @DTTo3=DateAdd(d,-1,DateAdd(yyyy,1,@DTFrom3))
		SET @DTTo4=DateAdd(d,-1,DateAdd(yyyy,1,@DTFrom4));SET @DTTo5=DateAdd(d,-1,DateAdd(yyyy,1,@DTFrom5));SET @DTTo6=DateAdd(d,-1,DateAdd(yyyy,1,@DTFrom6))
		SET @DTTo7=DateAdd(d,-1,DateAdd(yyyy,1,@DTFrom7));SET @DTTo8=DateAdd(d,-1,DateAdd(yyyy,1,@DTFrom8));SET @DTTo9=DateAdd(d,-1,DateAdd(yyyy,1,@DTFrom9))
		SET @DTTo10=DateAdd(d,-1,DateAdd(yyyy,1,@DTFrom10));SET @DTTo11=DateAdd(d,-1,DateAdd(yyyy,1,@DTFrom11));SET @DTTo12=DateAdd(d,-1,DateAdd(yyyy,1,@DTFrom12))
	END
*/

DECLARE @DTTemp AS DATETIME
DECLARE @myReturnTBL TABLE(Trans_Year INT,ItemCode VARCHAR(50),Month1 REAL,Month2 REAL,Month3 REAL,Month4 REAL,Month5 REAL,Month6 REAL,Month7 REAL,Month8 REAL,Month9 REAL,Month10 REAL,Month11 REAL,Month12 REAL,Month1Value REAL,Month2Value REAL,Month3Value REAL,Month4Value REAL,Month5Value REAL,Month6Value REAL,Month7Value REAL,Month8Value REAL,Month9Value REAL,Month10Value REAL,Month11Value REAL,Month12Value REAL,Month1Hits REAL,Month2Hits REAL,Month3Hits REAL,Month4Hits REAL,Month5Hits REAL,Month6Hits REAL,Month7Hits REAL,Month8Hits REAL,Month9Hits REAL,Month10Hits REAL,Month11Hits REAL,Month12Hits REAL,X2Qty REAL,X2Value REAL,X2Hits REAL)

CREATE TABLE #Customers(CustCode VARCHAR(50))

IF @X2Only=1
	INSERT INTO #Customers(CustCode) VALUES('X2')
ELSE
	INSERT INTO #Customers(CustCode) SELECT CustCode FROM ForeignCustomers WHERE CustCode NOT IN('Stock','PHF','SAL')

SET @DTTemp=@DTFrom

DECLARE @iYEAR AS INT

WHILE @DTTemp<@DTTo

	BEGIN
		SET @DTFrom1=@DTFrom;SET @DTFrom2=DateAdd(m,1,@DTFrom);SET @DTFrom3=DateAdd(m,2,@DTFrom);SET @DTFrom4=DateAdd(m,3,@DTFrom)
		SET @DTFrom5=DateAdd(m,4,@DTFrom);SET @DTFrom6=DateAdd(m,5,@DTFrom);SET @DTFrom7=DateAdd(m,6,@DTFrom);SET @DTFrom8=DateAdd(m,7,@DTFrom)
		SET @DTFrom9=DateAdd(m,8,@DTFrom);SET @DTFrom10=DateAdd(m,9,@DTFrom);SET @DTFrom11=DateAdd(m,10,@DTFrom);SET @DTFrom12=DateAdd(m,11,@DTFrom)

		SET @DTTo1=DateAdd(d,-1,DateAdd(m,1,@DTFrom1));SET @DTTo2=DateAdd(d,-1,DateAdd(m,1,@DTFrom2));SET @DTTo3=DateAdd(d,-1,DateAdd(m,1,@DTFrom3))
		SET @DTTo4=DateAdd(d,-1,DateAdd(m,1,@DTFrom4));SET @DTTo5=DateAdd(d,-1,DateAdd(m,1,@DTFrom5));SET @DTTo6=DateAdd(d,-1,DateAdd(m,1,@DTFrom6))
		SET @DTTo7=DateAdd(d,-1,DateAdd(m,1,@DTFrom7));SET @DTTo8=DateAdd(d,-1,DateAdd(m,1,@DTFrom8));SET @DTTo9=DateAdd(d,-1,DateAdd(m,1,@DTFrom9))
		SET @DTTo10=DateAdd(d,-1,DateAdd(m,1,@DTFrom10));SET @DTTo11=DateAdd(d,-1,DateAdd(m,1,@DTFrom11));SET @DTTo12=DateAdd(d,-1,DateAdd(m,1,@DTFrom12))

		SET @iYEAR=YEAR(@DTFrom1)
		INSERT INTO @myReturnTBL(Trans_Year,ItemCode) SELECT DISTINCT @iYEAR,CompItemCode FROM FCustomerOrders INNER JOIN FOrderItems ON FCustomerOrders.OrderNo=FOrderItems.OrderNo
			WHERE OrderType='Customer Order' AND DT BETWEEN @DTFrom AND @DTTo AND FCustomerOrders.OrderNo NOT IN(SELECT OrderNo FROM FCustomerFinalOrders WHERE Cancelled=1) AND CustCode IN(SELECT CustCode FROM #Customers) AND Qty>0


		UPDATE @myReturnTBL SET Trans_YEAR=@iYear,Month1=Month1.TotalQty,Month1Value=Month1.TotalValue,Month1Hits=Month1.Hits
			FROM @myReturnTBL myReturnTBL INNER JOIN
			(SELECT CompItemCode,SUM(Qty) AS TotalQty,SUM(Qty*Price) AS TotalValue,COUNT(DISTINCT FCustomerOrders.OrderNo) AS Hits FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo WHERE OrderType='Customer Order' AND DT BETWEEN @DTFrom1 AND @DTTo1 AND FCustomerOrders.OrderNo NOT IN(SELECT OrderNo FROM FCustomerFinalOrders WHERE Cancelled=1) AND CustCode IN(SELECT CustCode FROM #Customers) AND Qty>0 GROUP BY CompItemCode) Month1  ON myReturnTBL.ItemCode=Month1.CompItemCode AND myReturnTBL.Trans_Year=@iYEAR

		UPDATE @myReturnTBL SET Trans_YEAR=@iYear,Month2=Month2.TotalQty,Month2Value=Month2.TotalValue,Month2Hits=Month2.Hits
			FROM @myReturnTBL myReturnTBL INNER JOIN
