CREATE TABLE #myGroups(GroupID INT)
CREATE TABLE #myAdditionalGroups(GroupID INT)
DECLARE @myQuery AS VARCHAR(4000)
IF @ItemGroups=''
	INSERT INTO #myGroups(GroupID) SELECT ID FROM ItemGroups
ELSE
	BEGIN
		SET @myQuery='INSERT INTO #myGroups(GroupID) SELECT ID FROM ItemGroups WHERE ID IN('+@ItemGroups+')'
		EXEC(@myQuery)
	END

IF @AdditionalGroups=''
	INSERT INTO #myAdditionalGroups(GroupID) SELECT MainGroupID FROM ItemGroupsMain
ELSE
	BEGIN

		SET @myQuery='INSERT INTO #myAdditionalGroups(GroupID) SELECT MainGroupID FROM ItemGroupsMain WHERE MainGroupID IN('+@AdditionalGroups+')'
		EXEC(@myQuery)
	END

