CREATE PROCEDURE [dbo].[YearlyOrderDemandReport_ItemWise_SP] (@DT AS DATETIME,@YearlyReport AS BIT=0,@X2Only AS BIT=0) AS

DECLARE @DTFrom AS DATETIME
DECLARE @DTTo AS DATETIME

IF @YearlyReport=0
	BEGIN
		SET @DTFrom='1/1/' + CAST(YEAR(@DT) AS VARCHAR(4))
		SET @DTTo='12/31/' + CAST(YEAR(@DT) AS VARCHAR(4))
	END
ELSE
	BEGIN
		SET @DTFrom='1/1/' + CAST(YEAR(@DT) AS VARCHAR(4))
		SET @DTTo='12/31/' + CAST(YEAR(@DT)+11 AS VARCHAR(4))
	END

DECLARE @DTFrom1 AS DATETIME,@DTTo1 AS DATETIME
