		SET @DTFrom5=DateAdd(yyyy,4,@DTFrom);SET @DTFrom6=DateAdd(yyyy,5,@DTFrom);SET @DTFrom7=DateAdd(yyyy,6,@DTFrom);SET @DTFrom8=DateAdd(yyyy,7,@DTFrom)
