	(SELECT CompItemCode,SUM(Qty) AS TotalQty,SUM(Qty*Price) AS TotalValue,COUNT(DISTINCT FCustomerOrders.OrderNo) AS Hits  FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo WHERE OrderType='Customer Order' AND DT BETWEEN @DTFrom12 AND @DTTo12 AND FCustomerOrders.OrderNo NOT IN(SELECT OrderNo FROM FCustomerFinalOrders WHERE Cancelled=1) AND CustCode IN(SELECT CustCode FROM #Customers) AND Qty>0  GROUP BY CompItemCode) Month12  ON myReturnTBL.ItemCode=Month12.CompItemCode


UPDATE @myReturnTBL SET X2Qty=T1.TotalQty,X2Value=T1.TotalValue,X2Hits=T1.Hits
	FROM @myReturnTBL myReturnTBL INNER JOIN
	(SELECT CompItemCode,SUM(Qty) AS TotalQty,SUM(Qty*Price) AS TotalValue,COUNT(DISTINCT FCustomerOrders.OrderNo) AS Hits FROM FOrderItems INNER JOIN FCustomerOrders ON FCustomerOrders.OrderNo=FOrderItems.OrderNo WHERE OrderType='Customer Order' AND DT BETWEEN @DTFrom1 AND @DTTo12 AND FCustomerOrders.OrderNo NOT IN(SELECT OrderNo FROM FCustomerFinalOrders WHERE Cancelled=1) AND CustCode='X2' AND Qty>0  GROUP BY CompItemCode) T1  ON myReturnTBL.ItemCode=T1.CompItemCode

SELECT ItemCode
	,Month1,Month2,Month3,Month4,Month5,Month6,Month7,Month8,Month9,Month10,Month11,Month12
	,Month1Value,Month2Value,Month3Value,Month4Value,Month5Value,Month6Value,Month7Value,Month8Value,Month9Value,Month10Value,Month11Value,Month12Value
	,Month1Hits,Month2Hits,Month3Hits,Month4Hits,Month5Hits,Month6Hits,Month7Hits,Month8Hits,Month9Hits,Month10Hits,Month11Hits,Month12Hits,
	X2Qty,X2Value,X2Hits
	,@DTFrom1 AS DT1,@DTFrom2 AS DT2,@DTFrom3 AS DT3,@DTFrom4 AS DT4,@DTFrom5 AS DT5,@DTFrom6 AS DT6,@DTFrom7 AS DT7,@DTFrom8 AS DT8,@DTFrom9 AS DT9,@DTFrom10 AS DT10,@DTFrom11 AS DT11,@DTFrom12 AS DT12,VItems.ItemName FROM
	@myReturnTBL myTBL INNER JOIN VItems ON myTBL.ItemCode=VItems.ITemID

